function T(key)
    return I18N[key] and I18N[key][cfg.lng] or key
end

-- Helper to open URLs safely (fallback if SWS not installed)
local UTILS = {}

--- Escape non-ASCII characters to \uXXXX for safe storage in .ini
function UTILS.unicode_escape(s)
    if type(s) ~= "string" then return s end
    local result = {}
    for p, c in utf8.codes(s) do
        if c > 127 or c < 32 or c == 92 then
            table.insert(result, string.format("\\u%04x", c))
        else
            table.insert(result, string.char(c))
        end
    end
    return table.concat(result)
end

--- Unescape \uXXXX sequences back to UTF-8
function UTILS.unicode_unescape(s)
    if type(s) ~= "string" then return s end
    return s:gsub("\\u(%x%x%x%x)", function(hex)
        local code = tonumber(hex, 16)
        if code then return utf8.char(code) end
        return "\\u" .. hex
    end)
end

--- Format number with thousands separator (e.g. 1,000,000)
function UTILS.format_number(amount)
    if not amount or type(amount) ~= "number" then return tostring(amount or 0) end
    local formatted = tostring(math.floor(amount))
    while true do  
        formatted, k = string.gsub(formatted, "^(-?%d+)(%d%d%d)", '%1,%2')
        if (k == 0) then break end
    end
    return formatted
end

-- Global Scale Helper
local function S(val)
    return math.floor(val * cfg.gui_scale)
end

