--- Simple JSON encoder (handles basic types: string, number, boolean, table)
function STATS.json_encode(val, indent)
    local t = type(val)
    
    if t == "string" then
        return '"' .. val:gsub('\\', '\\\\'):gsub('"', '\\"'):gsub('\n', '\\n'):gsub('\r', '\\r') .. '"'
    elseif t == "number" or t == "boolean" then
        return tostring(val)
    elseif t == "table" then
        local is_array = true
        local max_idx = 0
        local count = 0
        for k, v in pairs(val) do
            count = count + 1
            if type(k) ~= "number" or k < 1 or k ~= math.floor(k) then
                is_array = false
            else
                max_idx = math.max(max_idx, k)
            end
        end
        if is_array and count ~= max_idx then is_array = false end
        if count == 0 then
            return "[]"
        end
        
        local nl = indent and "\n" or ""
        local spacing = indent and string.rep("  ", indent) or ""
        local inner_spacing = indent and string.rep("  ", indent + 1) or ""
        local next_indent = indent and (indent + 1) or nil
        
        if is_array then
            local parts = {}
            for i = 1, max_idx do
                table.insert(parts, inner_spacing .. STATS.json_encode(val[i], next_indent))
            end
            return "[" .. nl .. table.concat(parts, "," .. nl) .. nl .. spacing .. "]"
        else
            local parts = {}
            local keys = {}
            for k in pairs(val) do table.insert(keys, tostring(k)) end
            table.sort(keys)
            
            for _, k_str in ipairs(keys) do
                local k = k_str
                if val[tonumber(k_str)] ~= nil then k = tonumber(k_str) end
                if val[k_str] == nil and val[k] == nil then k = k_str end 

                local v = val[k]
                local key_part = '"' .. tostring(k):gsub('\\', '\\\\'):gsub('"', '\\"') .. '"'
                table.insert(parts, inner_spacing .. key_part .. (indent and ": " or ":") .. STATS.json_encode(v, next_indent))
            end
            return "{" .. nl .. table.concat(parts, "," .. nl) .. nl .. spacing .. "}"
        end
    else
        return "null"
    end
end

--- Simple JSON decoder (handles basic JSON structures)
function STATS.json_decode(str)
    if not str or str == "" then return nil end
    
    local pos = 1
    
    local function skip_whitespace()
        while pos <= #str and str:sub(pos, pos):match("%s") do
            pos = pos + 1
        end
    end
    
    local decode_value -- forward declaration
    
    local function decode_string()
        pos = pos + 1 -- skip opening "
        local res = ""
        while pos <= #str do
            local char = str:sub(pos, pos)
            if char == '"' then
                pos = pos + 1
                return res
            elseif char == '\\' then
                local next_char = str:sub(pos + 1, pos + 1)
                if next_char == 'n' then res = res .. "\n"
                elseif next_char == 'r' then res = res .. "\r"
                elseif next_char == 't' then res = res .. "\t"
                else res = res .. next_char end
                pos = pos + 2
            else
                res = res .. char
                pos = pos + 1
            end
        end
        return res
    end
    
    local function decode_number()
        local start = pos
        while pos <= #str and str:sub(pos, pos):match("[%d%.%-%+eE]") do
            pos = pos + 1
        end
        local num_str = str:sub(start, pos - 1)
        return tonumber(num_str) or 0
    end
    
    local function decode_array()
        pos = pos + 1 -- [
        local res = {}
        skip_whitespace()
        if str:sub(pos, pos) == "]" then
            pos = pos + 1
            return res
        end
        while pos <= #str do
            table.insert(res, decode_value())
            skip_whitespace()
            local char = str:sub(pos, pos)
            if char == "]" then
                pos = pos + 1
                return res
            elseif char == "," then
                pos = pos + 1
            end
        end
        return res
    end
    
    local function decode_object()
        pos = pos + 1 -- {
        local res = {}
        skip_whitespace()
        if str:sub(pos, pos) == "}" then
            pos = pos + 1
            return res
        end
        while pos <= #str do
            skip_whitespace()
            local key = decode_value()
            if key == nil then break end -- Robustness: stop if key is invalid
            
            skip_whitespace()
            if str:sub(pos, pos) == ":" then
                pos = pos + 1
            end
            skip_whitespace()
            res[tostring(key)] = decode_value()
            
            skip_whitespace()
            local char = str:sub(pos, pos)
            if char == "}" then
                pos = pos + 1
                return res
            elseif char == "," then
                pos = pos + 1
            else
                break -- Something is wrong, stop to avoid infinite loop
            end
        end
        return res
    end
    
    decode_value = function()
        skip_whitespace()
        local char = str:sub(pos, pos)
        if char == "{" then
            return decode_object()
        elseif char == "[" then
            return decode_array()
        elseif char == '"' then
            return decode_string()
        elseif char == "t" and str:sub(pos, pos+3) == "true" then
            pos = pos + 4
            return true
        elseif char == "f" and str:sub(pos, pos+4) == "false" then
            pos = pos + 5
            return false
        elseif char == "n" and str:sub(pos, pos+3) == "null" then
            pos = pos + 4
            return nil
        else
            return decode_number()
        end
    end
    
    local ok, res = pcall(decode_value)
    if not ok then
        reaper.ShowConsoleMsg("JSON Decode Error: " .. tostring(res) .. " at pos " .. pos .. "\n")
        return {}
    end
    return res
end

function OTHER.load_other_exts()
    -- Load presets now that STATS is ready
    local raw_presets = reaper.GetExtState(section_name, "fmt_presets_ext")
    if raw_presets ~= "" then
        cfg.fmt_presets = STATS.json_decode(UTILS.unicode_unescape(raw_presets)) or {}
    else
        cfg.fmt_presets = {}
    end

    local raw_dir_presets = reaper.GetExtState(section_name, "dir_presets_ext")
    if raw_dir_presets ~= "" then
        cfg.director_presets = STATS.json_decode(UTILS.unicode_unescape(raw_dir_presets)) or {}
    else
        cfg.director_presets = {
            {label = "ЗВУ", val = "Пропуск звуку"},
            {label = "ДИК", val = "Погана дикція, чіткіше "},
            {label = "ПРЕ", val = "Пропуск репліки"},
            {label = "ТЩЧ", val = "Твердішу Щ/Ч"},
            {label = "ЛОГ", val = "Логіка мови, дивно звучить"},
            {label = "ФЕВ", val = "Чую Ф замість В"},
            {label = "ЕНР", val = "Додай енергії, мляво звучить"},
            {label = "ЛІП", val = "Ліпсінк, уважніше!"},
            {label = "НАГ", val = "Неправильний наголос: "},
            {label = "АНС", val = "Акцент на слові: "},
            {label = "ПЗД", val = "Потрібно завершити думку, поставити крапку."},
        }
    end

    local raw_rules = reaper.GetExtState(section_name, "dict_auto_rules")
    if raw_rules ~= "" then
        cfg.dict_auto_rules = STATS.json_decode(UTILS.unicode_unescape(raw_rules)) or {}
    else
        cfg.dict_auto_rules = {}
    end

    local raw_dubber_rules = reaper.GetExtState(section_name, "dubber_char_rules")
    if raw_dubber_rules ~= "" then
        cfg.dubber_char_rules = STATS.json_decode(UTILS.unicode_unescape(raw_dubber_rules)) or {}
    else
        cfg.dubber_char_rules = {}
    end

    -- Legacy migration check: if cfg.dubber_char_rules is a flat array, wrap it in a default project
    local is_old_format = false
    if type(cfg.dubber_char_rules) == "table" and #cfg.dubber_char_rules > 0 then
        local first = cfg.dubber_char_rules[1]
        if type(first) == "table" and (first.dubber_name or first.chars) then
            is_old_format = true
        end
    end
    
    if is_old_format then
        local old_rules = cfg.dubber_char_rules
        cfg.dubber_char_rules = {}
        cfg.dubber_char_rules["Проєкт 1"] = old_rules
        cfg.dubber_project_selected = "Проєкт 1"
    else
        -- Load selected project name
        local sel_p = UTILS.unicode_unescape(reaper.GetExtState(section_name, "dubber_project_selected"))
        if sel_p ~= "" then
            cfg.dubber_project_selected = sel_p
        end
    end

    -- Ensure we have a selected project if projects exist
    if type(cfg.dubber_char_rules) == "table" then
        local has_projects = false
        local first_proj = nil
        for p_name in pairs(cfg.dubber_char_rules) do
            has_projects = true
            if not first_proj or p_name < first_proj then
                first_proj = p_name
            end
        end
        if has_projects then
            if not cfg.dubber_project_selected or not cfg.dubber_char_rules[cfg.dubber_project_selected] then
                cfg.dubber_project_selected = first_proj
            end
        else
            cfg.dubber_project_selected = nil
        end
    else
        cfg.dubber_char_rules = {}
        cfg.dubber_project_selected = nil
    end
end

