--- Perform a global audit of all projects in the registry to count unique deadline failures
function ACHIEVEMENTS.global_deadline_sweep()
    local global_data = DEADLINE.load_global()
    local now = os.time()
    local failed_list = reaper.GetExtState(section_ach_name, "ach_6_idx_list")
    local initial_count = tonumber(reaper.GetExtState(section_ach_name, "ach_6_failed_count")) or 0
    local registry_changed = false
    
    -- Load counter once to avoid race conditions inside the loop
    local last_global_idx = tonumber(reaper.GetExtState(section_ach_name, "global_project_counter")) or 0
    local start_global_idx = last_global_idx

    for norm_path, proj in pairs(global_data) do
        if proj.deadline and now > proj.deadline then
            -- Assign index if missing (Legacy migration)
            if not proj.idx or not tonumber(proj.idx) then
                last_global_idx = last_global_idx + 1
                proj.idx = last_global_idx
                registry_changed = true
            end

            local idx_str = tostring(proj.idx)
            -- Only count numeric/valid indices for unique achievements
            if tonumber(idx_str) then
                local search_pattern = "|" .. idx_str .. "|"
                local wrapped_list = "|" .. failed_list .. "|"
                
                if not wrapped_list:find(search_pattern, 1, true) then
                    failed_list = failed_list == "" and idx_str or (failed_list .. "|" .. idx_str)
                end
            end
        end
    end

    -- Save counter once if it was incremented
    if last_global_idx ~= start_global_idx then
        reaper.SetExtState(section_ach_name, "global_project_counter", tostring(last_global_idx), true)
    end

    -- Count unique IDs and self-correct the achievement stat
    local count = 0
    if failed_list ~= "" then
        for _ in failed_list:gmatch("[^|]+") do count = count + 1 end
    end
    
    local current_stat = ACHIEVEMENTS.get_stat("ach_6_failed_count")
    if count ~= current_stat then
        ACHIEVEMENTS.add_stat("ach_6_failed_count", count - current_stat)
    end
    reaper.SetExtState(section_ach_name, "ach_6_idx_list", failed_list, true)

    if registry_changed then
        local json_str = STATS.json_encode(global_data)
        reaper.SetExtState(section_name, "new_project_deadlines", json_str, true)
    end
end

--- Generate unique project ID from project path
function STATS.get_project_id()
    local proj_path = reaper.GetProjectPath("") .. "/" .. reaper.GetProjectName(0, "")
    if proj_path == "/" then return nil end -- No project loaded
    
    -- Simple hash: sum of character codes
    local hash = 0
    for i = 1, #proj_path do
        hash = (hash * 31 + string.byte(proj_path, i)) % 0xFFFFFFFF
    end
    return string.format("%08x", hash)
end

--- Get current date string (YYYY-MM-DD)
function STATS.get_date_string()
    return os.date("%Y-%m-%d")
end

--- Get file path for current project (creates new file with date if needed)
function STATS.get_project_file_path()
    local proj_id = STATS.get_project_id()
    if not proj_id then return nil end
    
    -- Check if we already have a file path for this project
    if STATS.current_project_id == proj_id and STATS.file_path then
        return STATS.file_path
    end
    
    -- Look for existing file for this project
    local pattern = "stats_" .. proj_id .. "_*.json"
    local files = {}
    
    -- Scan stats directory for matching files
    local i = 0
    repeat
        local file = reaper.EnumerateFiles(STATS.stats_dir, i)
        if file and file:match("^stats_" .. proj_id .. "_") then
            table.insert(files, file)
        end
        i = i + 1
    until not file
    
    -- Use existing file or create new one with current date
    local filename
    if #files > 0 then
        -- Use the first (oldest) file found
        table.sort(files)
        filename = files[1]
    else
        -- Create new file with current date
        filename = "stats_" .. proj_id .. "_" .. STATS.get_date_string() .. ".json"
    end
    
    STATS.current_project_id = proj_id
    STATS.file_path = STATS.stats_dir .. filename
    return STATS.file_path
end

--- Load statistics from file
function STATS.load()
    local file_path = STATS.get_project_file_path()
    if not file_path then
        STATS.data = nil
        return
    end
    
    local file = io.open(file_path, "r")
    if not file then
        -- Initialize default structure for this project
        STATS.data = {
            meta_version = 1,
            project_id = STATS.get_project_id(),
            project_name = reaper.GetProjectName(0, ""),
            project_path = reaper.GetProjectPath("") .. "/" .. reaper.GetProjectName(0, ""),
            created_date = STATS.get_date_string(),
            last_updated = os.time(),
            metadata = {
                total_lines_in_script = 0,
                total_words = 0,
                edits_count = 0
            },
            total = {
                lines_recorded = 0
            },
            duration = {},
            daily_stats = {}
        }
        STATS.dirty = true
        return
    end
    
    local content = file:read("*all")
    file:close()
    
    local decoded = STATS.json_decode(content)
    if type(decoded) == "table" and decoded.project_id then
        STATS.data = decoded
        -- Ensure critical sub-tables always exist
        if not STATS.data.metadata then STATS.data.metadata = {} end
        if not STATS.data.total then STATS.data.total = {} end
        if not STATS.data.duration then STATS.data.duration = {} end
        if not STATS.data.daily_stats then STATS.data.daily_stats = {} end
        
        STATS.update_cache()
    else
        -- Fallback: initialize default structure
        STATS.data = {
            meta_version = 1,
            project_id = STATS.get_project_id(),
            project_name = reaper.GetProjectName(0, ""),
            project_path = reaper.GetProjectPath("") .. "/" .. reaper.GetProjectName(0, ""),
            created_date = STATS.get_date_string(),
            last_updated = os.time(),
            metadata = {
                total_lines_in_script = 0,
                total_words = 0,
                edits_count = 0
            },
            total = {
                lines_recorded = 0
            },
            duration = {},
            daily_stats = {}
        }
        STATS.dirty = true
    end
end

--- Save statistics to file
function STATS.save()
    if not STATS.data or not STATS.dirty then return end
    
    local file_path = STATS.get_project_file_path()
    if not file_path then return end
    
    -- Ensure directory exists
    local dir = STATS.file_path:match("^(.+[/\\])")
    if dir then
        reaper.RecursiveCreateDirectory(dir, 0)
    end
    
    -- Check for Project Veteran Achievement (ach_14: > 12 hours)
    ACHIEVEMENTS.check_project_veteran_ach_14()
    
    local file = io.open(file_path, "w")
    if not file then return end
    
    file:write(STATS.json_encode(STATS.data))
    file:close()
    
    STATS.dirty = false
    STATS.last_save_time = reaper.time_precise()
end

--- Get or create project entry (now returns the main data object)
function STATS.get_project()
    if not STATS.data then
        STATS.load()
    end
    
    -- Reload if project changed
    local current_proj_id = STATS.get_project_id()
    if current_proj_id ~= STATS.current_project_id then
        STATS.load()
    end
    
    return STATS.data
end

--- Increment outside recordings counter
function STATS.increment_outside()
    local proj = STATS.get_project()
    if not proj then return end
    
    local date = STATS.get_date_string()
    
    -- Ensure daily stats entry exists
    if not proj.daily_stats[date] then
        proj.daily_stats[date] = {
            lines = 0,
            actors = {}
        }
    end
    
    -- Initialize outside counter if missing
    if not proj.total.lines_recorded_outside then
        proj.total.lines_recorded_outside = 0
    end
    if not proj.daily_stats[date].lines_outside then
        proj.daily_stats[date].lines_outside = 0
    end
    
    -- Increment counters
    proj.total.lines_recorded_outside = proj.total.lines_recorded_outside + 1
    proj.daily_stats[date].lines_outside = proj.daily_stats[date].lines_outside + 1
    
    proj.last_updated = os.time()
    STATS.dirty = true
end

--- Increment recorded lines counter
function STATS.increment_recorded(actor_name)
    local proj = STATS.get_project()
    if not proj then return end
    
    local date = STATS.get_date_string()
    
    -- Ensure daily stats entry exists
    if not proj.daily_stats[date] then
        proj.daily_stats[date] = {
            lines = 0,
            actors = {}
        }
    end
    
    -- Increment counters
    proj.total.lines_recorded = proj.total.lines_recorded + 1
    proj.daily_stats[date].lines = proj.daily_stats[date].lines + 1
    
    -- Track per-actor
    if actor_name then
        if not proj.daily_stats[date].actors[actor_name] then
            proj.daily_stats[date].actors[actor_name] = { lines = 0 }
        end
        proj.daily_stats[date].actors[actor_name].lines = proj.daily_stats[date].actors[actor_name].lines + 1
    end
    
    proj.last_updated = os.time()
    STATS.dirty = true
end

--- Increment edits counter
function STATS.increment_edit()
    local proj = STATS.get_project()
    if not proj then return end
    
    proj.metadata.edits_count = proj.metadata.edits_count + 1
    proj.last_updated = os.time()
    STATS.dirty = true
end

--- Recalculate duration cache (call only when data changes)
function STATS.update_cache()
    local proj = STATS.get_project()
    if not proj or not proj.duration then 
        STATS.duration_cache = 0
        return 
    end
    
    local total = 0
    for _, s in ipairs(proj.duration) do
        if s["end"] and s.start then
            total = total + (s["end"] - s.start)
        end
    end
    STATS.duration_cache = total
end

--- Clear statistics
function STATS.clear_stats()
    local res = reaper.MB(T("REMOVE_STATS_1"), T("REMOVE_STATS_2"), 4)
    if res == 6 then -- Yes (6)
        STATS.data = {
            meta_version = 1,
            project_id = STATS.get_project_id(),
            project_name = reaper.GetProjectName(0, ""),
            project_path = reaper.GetProjectPath("") .. "/" .. reaper.GetProjectName(0, ""),
            created_date = STATS.get_date_string(),
            last_updated = os.time(),
            metadata = {
                total_lines_in_script = 0,
                total_words = 0,
                edits_count = 0
            },
            total = {
                lines_recorded = 0
            },
            duration = {},
            daily_stats = {}
        }
        STATS.dirty = true
        STATS.update_cache()
        STATS.save()
    end
end

--- Get session summary for display
function STATS.get_session_summary()
    local proj = STATS.get_project()
    if not proj then return 0, 0 end
    
    local takes = (proj.total.lines_recorded or 0) + (proj.total.lines_recorded_outside or 0)
    local duration = STATS.duration_cache or 0
    
    -- Add currently active recording time if playing
    local play_state = reaper.GetPlayState()
    if (play_state & 4) == 4 and #proj.duration > 0 then
        local last = proj.duration[#proj.duration]
        if last and last.start then
            local now = os.time()
            duration = duration + (now - last.start)
        end
    end
    
    return takes, duration
end

--- Format duration in Ukrainian (HH год MM хв or MM хв SS с)
function STATS.format_hms(s)
    if not s or s <= 0 then return T("HMS_F_0_S") end
    local h = math.floor(s / 3600)
    local m = math.floor((s % 3600) / 60)
    local sec = math.floor(s % 60)
    
    if h > 0 then
        if m > 0 then
            return string.format(T("HMS_F_H_M"), h, m)
        else
            return string.format(T("HMS_F_H"), h)
        end
    elseif m > 0 then
        if sec > 0 then
            return string.format(T("HMS_F_M_S"), m, sec)
        else
            return string.format(T("HMS_F_M"), m)
        end
    else
        return string.format(T("HMS_F_S"), sec)
    end
end

--- Initialize stats on script load
STATS.load()

--- Check if the current project has failed its deadline and track it uniquely
function ACHIEVEMENTS.check_deadline_failure()
    local idx = ACHIEVEMENTS.get_project_idx()
    if idx == "unsaved" then return end

    -- Get deadline for the active project
    local proj_path, _ = DEADLINE.get_project_info()
    if not proj_path then return end
    
    local global_data = DEADLINE.load_global()
    local norm_path = DEADLINE.normalize_path(proj_path)
    local deadline = global_data[norm_path] and global_data[norm_path].deadline
    
    if not deadline then
        -- Check local backup
        local retval, val = reaper.GetProjExtState(0, section_name, "project_deadline")
        if retval and val ~= "" then deadline = tonumber(val) end
    end

    if deadline and os.time() > deadline then
        local failed_list = reaper.GetExtState(section_ach_name, "ach_6_idx_list")
        local idx_str = tostring(idx)
        
        -- Back-sync project index to global registry if missing
        local registry_updated = false
        if global_data[norm_path] and not global_data[norm_path].idx and tonumber(idx) then
            global_data[norm_path].idx = tonumber(idx)
            registry_updated = true
        end
        if registry_updated then
            local json_str = STATS.json_encode(global_data)
            reaper.SetExtState(section_name, "new_project_deadlines", json_str, true)
        end

        -- Unique failure tracking (only for numeric IDs)
        if tonumber(idx_str) then
            local search_pattern = "|" .. idx_str .. "|"
            local wrapped_list = "|" .. failed_list .. "|"
            if not wrapped_list:find(search_pattern, 1, true) then
                local new_list = failed_list == "" and idx_str or (failed_list .. "|" .. idx_str)
                reaper.SetExtState(section_ach_name, "ach_6_idx_list", new_list, true)
                
                -- Recalculate total unique count to ensure accuracy
                local count = 0
                for _ in new_list:gmatch("[^|]+") do count = count + 1 end
                local current_stat = ACHIEVEMENTS.get_stat("ach_6_failed_count")
                ACHIEVEMENTS.add_stat("ach_6_failed_count", count - current_stat)
            end
        end
    end
end

function ACHIEVEMENTS.format_long_duration(s)
    if not s or s <= 0 then return "0" .. T("DUR_MIN") end
    
    local months = math.floor(s / 2592000) -- 30 days
    s = s % 2592000
    local days = math.floor(s / 86400)
    s = s % 86400
    local hours = math.floor(s / 3600)
    s = s % 3600
    local minutes = math.floor(s / 60)
    
    local parts = {}
    if months > 0 then table.insert(parts, months .. T("DUR_MONTH")) end
    if days > 0 then table.insert(parts, days .. T("DUR_DAY")) end
    if hours > 0 then table.insert(parts, hours .. T("DUR_HOUR")) end
    if minutes > 0 or #parts == 0 then table.insert(parts, minutes .. T("DUR_MIN")) end
    
    return table.concat(parts, " ")
end

--- Check if the current project has earned the 'Architect' achievement uniquely
function ACHIEVEMENTS.check_project_architect_ach_10()
    local _, filename = reaper.EnumProjects(-1)
    
    -- If project is unsaved but has the "earned" flag, it's likely from a template.
    -- We clear it so it can be re-earned once this project is saved.
    if not filename or filename == "" then
        local retval, earned = reaper.GetProjExtState(0, section_name, "earned_ach_10")
        if retval > 0 and earned == "1" then
            reaper.SetProjExtState(0, section_name, "earned_ach_10", "")
        end
        return 
    end
    
    local retval, earned = reaper.GetProjExtState(0, section_name, "earned_ach_10")
    if retval == 0 or earned ~= "1" then
        ACHIEVEMENTS.add_stat("ach_10_count", 1)
        reaper.SetProjExtState(0, section_name, "earned_ach_10", "1")
        reaper.MarkProjectDirty(0)
    end
end

--- Check if the current project has earned the 'Polyphonic Vortex' achievement (ach_16: 15+ tracks)
function ACHIEVEMENTS.check_big_track_count_ach_16()
    local retval, earned = reaper.GetProjExtState(0, section_name, "earned_ach_16")
    if retval == 0 or earned ~= "1" then
        if reaper.CountTracks(0) >= 15 then
            ACHIEVEMENTS.add_stat("ach_16_count", 1)
            reaper.SetProjExtState(0, section_name, "earned_ach_16", "1")
            reaper.MarkProjectDirty(0)
        end
    end
end

--- Check if the current project has earned the 'Legion' achievement (ach_17: 50+ actors)
function ACHIEVEMENTS.check_high_actor_count_ach_17()
    local retval, earned = reaper.GetProjExtState(0, section_name, "earned_ach_17")
    if retval == 0 or earned ~= "1" then
        local count = 0
        if ass_actors then
            for _ in pairs(ass_actors) do count = count + 1 end
        end
        if count >= 50 then
            ACHIEVEMENTS.add_stat("ach_17_count", 1)
            reaper.SetProjExtState(0, section_name, "earned_ach_17", "1")
            reaper.MarkProjectDirty(0)
        end
    end
end

