--- Check if the requirements for 'Midnight Vigil' (ach_22) are met
-- Must be recorded between 00:00 and 04:00, only once per day globally.
function ACHIEVEMENTS.check_midnight_vigil_ach_22()
    local time_t = os.date("*t")
    -- Check if it's between 00:00 and 04:00
    if time_t.hour >= 0 and time_t.hour < 4 then
        local today_str = os.date("%Y-%m-%d")
        -- Check if we already earned it today (persistent global tracking)
        if ACHIEVEMENTS.get_stat_string("ach_22_last_date") ~= today_str then
            ACHIEVEMENTS.add_stat("ach_22_count", 1)
            ACHIEVEMENTS.set_stat_string("ach_22_last_date", today_str)
            return true -- Earned today
        end
    end
    return false
end

--- Check if the current project has earned 'Blessing of Artemis' (ach_23: accuracy >= 50 lines, ratio <= 1.1)
function ACHIEVEMENTS.check_perfect_accuracy_ach_23()
    local retval, earned = reaper.GetProjExtState(0, section_name, "earned_ach_23")
    if retval == 0 or earned ~= "1" then
        local _, recorded_count, _ = UTILS.get_recording_progress()

        if recorded_count >= 50 then
            local takes_count, _ = STATS.get_session_summary()
            local attempts = takes_count / recorded_count

            if attempts <= 1.1 and takes_count > 30 and attempts > 0.5 then
                ACHIEVEMENTS.add_stat("ach_23_count", 1)
                reaper.SetProjExtState(0, section_name, "earned_ach_23", "1")
                reaper.MarkProjectDirty(0)
            end
        end
    end
end

--- Check if the recorded take is 'absolute silence' for 'Lightness of a Feather' (ach_24)
-- Requires take length >= 5.0s and Peak < -60 dB (0.001 linear)
function ACHIEVEMENTS.check_feather_silence_ach_24(item, length)
    if not item or not length or length < 5.0 then return false end
    local take = reaper.GetActiveTake(item)
    if not take or reaper.TakeIsMIDI(take) then return false end
    
    local source = reaper.GetMediaItemTake_Source(take)
    if not source then return false end
    local n_chans = reaper.GetMediaSourceNumChannels(source)
    if not n_chans or n_chans == 0 then return false end
    
    local accessor = reaper.CreateTakeAudioAccessor(take)
    if not accessor then return false end
    
    -- Optimized: Use low sample rate (1000Hz) for ultra-fast light analysis
    local check_srate = 1000 
    local total_samples = math.floor(length * check_srate)
    local ts_chs = total_samples * n_chans

    if total_samples <= 0 or ts_chs <= 0 then 
        reaper.DestroyAudioAccessor(accessor)
        return false 
    end

    local buffer = reaper.new_array(ts_chs)
    local retval = reaper.GetAudioAccessorSamples(accessor, check_srate, n_chans, 0, total_samples, buffer)
    reaper.DestroyAudioAccessor(accessor)
    
    if retval > 0 then
        local sum_sq = 0
        
        for i = 1, ts_chs do
            local val = buffer[i] or 0
            sum_sq = sum_sq + (val * val)
        end
        
        local mean_sq = sum_sq / ts_chs
        -- -60 dB threshold (square of 0.001 linear) is 0.000001
        if mean_sq < 0.000001 then
            ACHIEVEMENTS.add_stat("ach_24_count", 1)
            return true
        end
    end
    
    return false
end

