-- Global Actor Color Registry
OTHER.global_actor_colors_limit = 100
OTHER.global_actor_colors = {}
OTHER.global_actor_color_names = {} -- Track order for LRU (Least Recently Used) pruning

function OTHER.save_global_actor_colors()
    local dump = {}
    for i = 1, math.min(#OTHER.global_actor_color_names, OTHER.global_actor_colors_limit) do
        local name = OTHER.global_actor_color_names[i]
        local col = OTHER.global_actor_colors[name]
        if col then
            table.insert(dump, name .. ":" .. tostring(col))
        end
    end
    reaper.SetExtState(section_name, "global_actor_colors", table.concat(dump, "⟊"), true)
end

function OTHER.update_global_actor_color(name, col)
    if not name or name == "" then return end
    
    -- Update value
    OTHER.global_actor_colors[name] = col
    
    -- Update order (Move to front)
    for i, existing_name in ipairs(OTHER.global_actor_color_names) do
        if existing_name == name then
            table.remove(OTHER.global_actor_color_names, i)
            break
        end
    end
    table.insert(OTHER.global_actor_color_names, 1, name)
    
    -- Prune list
    if #OTHER.global_actor_color_names > OTHER.global_actor_colors_limit then
        local removed = table.remove(OTHER.global_actor_color_names)
        OTHER.global_actor_colors[removed] = nil
    end
    
    OTHER.save_global_actor_colors()
end

function OTHER.load_global_actor_colors()
    local str = reaper.GetExtState(section_name, "global_actor_colors")
    OTHER.global_actor_colors = {}
    OTHER.global_actor_color_names = {}
    if str ~= "" then
        -- Add trailing ⟊ for easy matching if not present
        if not str:match("⟊$") then str = str .. "⟊" end 
        for entry in str:gmatch("(.-)⟊") do
            local name, col = entry:match("^(.-):(%d+)$")
            if name and col and not OTHER.global_actor_colors[name] then
                OTHER.global_actor_colors[name] = tonumber(col)
                table.insert(OTHER.global_actor_color_names, name)
            end
        end
    end
end

-- Initialize Registry
OTHER.load_global_actor_colors()

--- Update project metadata (total lines, words)
function STATS.update_metadata()
    local proj = STATS.get_project()
    if not proj then return end

    local total_lines = 0
    local total_words = 0
    local selected_lines = 0
    local selected_words = 0
    local actor_stats = {}
    
    -- Iterate ass_lines directly (defined locally above)
    if ass_lines then
        for _, line in ipairs(ass_lines) do
            -- Count every line (we want total lines in script)
            total_lines = total_lines + 1
            
            -- Word count logic matching line 10094 (strip tags, convert breaks, count non-whitespace)
            local clean = (line.text or ""):gsub("{{+.-}}+", ""):gsub("{.-}", ""):gsub("\\[Nnh]", " ")
            local _, count = clean:gsub("%S+", "")
            total_words = total_words + count
            
            -- Count selected/enabled lines
            if line.enabled ~= false then
                selected_lines = selected_lines + 1
                selected_words = selected_words + count
            end
            
            -- Track per-actor stats (total in script)
            local actor = line.actor
            if actor and actor ~= "" then
                if not actor_stats[actor] then
                    -- Check selection status from ass_actors global table
                    -- ass_actors[name] is true if selected/visible, nil/false if hidden
                    local is_selected = false
                    if ass_actors and ass_actors[actor] == true then
                        is_selected = true
                    end

                    actor_stats[actor] = {
                        lines = 0,
                        words = 0,
                        id = actor,
                        selected = is_selected
                    }
                end
                actor_stats[actor].lines = actor_stats[actor].lines + 1
                actor_stats[actor].words = actor_stats[actor].words + count
            end
        end
    end
    
    -- Always update metadata if values differ
    -- We'll assume if total counts changed, actor stats might have too, so we update the actors table
    if proj.metadata.total_lines_in_script ~= total_lines or 
       proj.metadata.total_words ~= total_words or
       proj.metadata.selected_lines_count ~= selected_lines or
       proj.metadata.selected_words_count ~= selected_words or
       not proj.metadata.actors or
       (total_lines > 0 and proj.metadata.total_lines_in_script == 0) then
        proj.metadata.total_lines_in_script = total_lines
        proj.metadata.total_words = total_words
        proj.metadata.selected_lines_count = selected_lines
        proj.metadata.selected_words_count = selected_words
        proj.metadata.actors = actor_stats
        proj.last_updated = os.time()
        STATS.dirty = true
    end
end

