function UI.apply_ui_theme(theme_name)    
    local theme = UI.UI_THEMES[theme_name] or UI.UI_THEMES["Titanium"]
    for k, v in pairs(theme) do
        UI[k] = v
    end
    cfg.ui_theme = theme_name
end

-- Apply initial theme
UI.apply_ui_theme(cfg.ui_theme)

