-- SHARED OVERLAY SYNC
-- UTILITY FUNCTIONS
-- =============================================================================

-- Proximity helper for marker detection
function UTILS.is_near(t1, t2) return math.abs(t1-t2) < 0.001 end

--- Serialize and send Prompter data to ExtState for the satellite Overlay script
function UTILS.find_satellite_window(title_pattern)
    if not reaper.JS_Window_ArrayAllChild then return nil end
    
    local function find_recursively(parent_hwnd)
        local arr = reaper.new_array({}, 1024)
        reaper.JS_Window_ArrayAllChild(parent_hwnd, arr)
        local children = arr.table()
        for _, ptr in ipairs(children) do
            local child = reaper.JS_Window_HandleFromAddress(ptr)
            local title = reaper.JS_Window_GetTitle(child)
            if title:find(title_pattern, 1, true) then
                return child
            end
            local found = find_recursively(child)
            if found then return found end
        end
        return nil
    end

    local found_hwnd = find_recursively(reaper.GetMainHwnd())
    if not found_hwnd and reaper.JS_Window_ArrayAllTop then
        local arr = reaper.new_array({}, 1024)
        reaper.JS_Window_ArrayAllTop(arr)
        for _, ptr in ipairs(arr.table()) do
            local hwnd = reaper.JS_Window_HandleFromAddress(ptr)
            if reaper.JS_Window_GetTitle(hwnd):find(title_pattern, 1, true) then
                found_hwnd = hwnd
                break
            end
        end
    end
    return found_hwnd
end

function UTILS.run_satellite_script(folder, filename, label)
    local sep = package.config:sub(1, 1)
    local script_path = debug.getinfo(1,'S').source:match([[^@?(.*[\/])]])
    local full_path = script_path .. folder .. sep .. filename
    
    -- Check if file exists
    local f_check = io.open(full_path, "r")
    if not f_check then
        reaper.MB(T("NEED_IM_GUI_NO_FILE") .. full_path, T("ERROR"), 0)
        return
    end
    f_check:close()

    -- Dependency Check: ReaImGui
    local has_reapack = reaper.ReaPack_GetOwner ~= nil
    local has_imgui = reaper.ImGui_CreateContext ~= nil

    if not has_imgui then
        local msg = T("NEED_IM_GUI_1") .. label .. T("NEED_IM_GUI_2")
        if not has_reapack then
            msg = msg .. T("NEED_IM_GUI_3")
        else
            msg = msg .. T("NEED_IM_GUI_4")
        end
        reaper.MB(msg, T("MISSIBG_COMPONENTS"), 0)
        return
    end

    -- Clear the close signal before running any script
    reaper.SetExtState("Subass_Global", "ForceCloseComplementary", "0", false)

    -- Check if script is already running
    local titles = {
        ["Lionzz_SubOverlay_Subass.lua"] = "SubOverlay",
        ["Subass_Dictionary.lua"] = "Subass Dictionary",
        ["imnotbad_Notepad.lua"] = "Notepad",
        ["Subass_PDF.lua"] = "Subass PDF Reader",
        ["imnotbad_MP4_MKV_Extract.lua"] = "MKV/MP4 Extract"
    }
    
    local window_title = titles[filename]
    if window_title then
        local hwnd = UTILS.find_satellite_window(window_title)
        if hwnd then
            local choice = reaper.MB(label .. T("SATELLITE_1"), 
                label .. T("SATELLITE_2"), 3)
            
            if choice == 6 then -- Yes: Focus
                reaper.DockWindowActivate(hwnd)
                reaper.JS_Window_SetFocus(hwnd)
                reaper.JS_Window_SetForeground(hwnd)
                return
            elseif choice == 7 then -- No: Close
                -- Signal the script to close itself gracefully
                reaper.SetExtState("Subass_Global", "ForceCloseComplementary", filename, false)
                return
            else -- Cancel or other
                return
            end
        end
    end

    -- Try to find the Command ID in reaper-kb.ini
    local kb_path = reaper.GetResourcePath() .. "/reaper-kb.ini"
    local f = io.open(kb_path, "r")
    local cmd_id = nil
    if f then
        local pattern = folder .. "[\\/]" .. filename
        for line in f:lines() do
            if line:find(pattern) then
                local rs_part = line:match("RS([%a%d]+)")
                if rs_part then
                    cmd_id = "_RS" .. rs_part
                    break
                end
            end
        end
        f:close()
    end

    -- If found, run it. If not, ask the user to register it once.
    if cmd_id and reaper.NamedCommandLookup(cmd_id) ~= 0 then
        reaper.Main_OnCommand(reaper.NamedCommandLookup(cmd_id), 0)
    else
        reaper.MB(T("SATELLITE_3") .. filename .. T("SATELLITE_4") .. folder .. T("SATELLITE_5"), R("SATELLITE_6"), 0)
    end
end

function UTILS.invalidate_prompter_cache()
    if draw_prompter_cache then
        draw_prompter_cache.last_text = nil
        draw_prompter_cache.last_next_text = nil
        draw_prompter_cache.next_cache = {}
    end
    if prompter_slider_cache then
        prompter_slider_cache.state_count = -1
    end
end

--- Split text into words and separators for interaction
--- @param text string Input text
--- @return table List of segments {text, is_word}
function UTILS.get_words_and_separators(text)
    local result = {}
    local pos = 1
    -- Includes Cyrillic, Latin, apostrophes, and hyphens for compound words
    local pattern = "[%a\128-\255\'%-]+[\128-\255]*"
    
    while pos <= #text do
        local s, e = text:find(pattern, pos)
        if s then
            if s > pos then
                table.insert(result, {text = text:sub(pos, s-1), is_word = false})
            end
            table.insert(result, {text = text:sub(s, e), is_word = true})
            pos = e + 1
        else
            table.insert(result, {text = text:sub(pos), is_word = false})
            break
        end
    end
    return result
end

