        [224] = "\208\176", [225] = "\208\177", [226] = "\208\178", [227] = "\208\179", [228] = "\208\180", [229] = "\208\181", [230] = "\208\182", [231] = "\208\183",
        [232] = "\208\184", [233] = "\208\185", [234] = "\208\186", [235] = "\208\187", [236] = "\208\188", [237] = "\208\189", [238] = "\208\190", [239] = "\208\191",
        [240] = "\209\128", [241] = "\209\129", [242] = "\209\130", [243] = "\209\131", [244] = "\209\132", [245] = "\209\133", [246] = "\209\134", [247] = "\209\135",
        [248] = "\209\136", [249] = "\209\137", [250] = "\209\138", [251] = "\209\139", [252] = "\209\140", [253] = "\209\141", [254] = "\209\142", [255] = "\209\143"
    }
    
    local res = {}
    for i = 1, #str do
        local b = str:byte(i)
        if b < 128 then
            table.insert(res, string.char(b))
        else
            if cfg.fix_CP1251 then
                table.insert(res, cp1251_map[b] or "?")
            else
                -- Sanitization: replace non-UTF8 bytes with '?' if conversion is disabled
                table.insert(res, "?")
            end
        end
    end
    return table.concat(res)
end

--- Parse ASS timestamp format (H:MM:SS.cs) to seconds
--- @param str string Timestamp string
--- @return number Time in seconds or 0 if invalid
local function parse_ass_timestamp(str)
    local h, m, s, cs = str:match("(%d+):(%d+):(%d+)%.(%d+)")
    if not h then return 0 end
    return (tonumber(h) * 3600) + (tonumber(m) * 60) + tonumber(s) + (tonumber(cs) / 100)
end

local sws_alert_shown = false

--- Set system clipboard text
--- @param text string Text to copy to clipboard
local function set_clipboard(text)
    if not text then return end
    text = text:match("^%s*(.-)%s*$")
    if text == "" then return end
    
    if reaper.CF_SetClipboard then 
        reaper.CF_SetClipboard(text)
        return
    end
    
    if not sws_alert_shown then
        reaper.MB(T("NEED_SWS_FOR_COPY_F"), "Subass", 0)
        sws_alert_shown = true
    end
    
    local os_name = reaper.GetOS()
    if os_name:match("OSX") or os_name:match("macOS") then
        -- Use pbcopy
        local escaped = text:gsub("'", "'\\''") -- escape single quotes
        io.popen("printf '"..escaped.."' | pbcopy", "w")
    else
        -- Windows clip
        -- Note: 'clip' reads from stdin, but io.popen("clip", "w") might not work as easily with pure Lua write.
        -- Echoing is easier but restricted length. 
        -- Try PowerShell Set-Clipboard
        local escaped = text:gsub('"', '\\"')
        io.popen('powershell.exe -command "Set-Clipboard -Value \\"' .. escaped .. '\\""', "w")
    end
end

local function draw_loader()
    if not UI_STATE.script_loading_state.active then 
        UI_STATE.script_loading_state.loader_idx = nil
        UI_STATE.script_loading_state.start_time = nil
        return 
    end
    
    -- Overlay
    gfx.set(0, 0, 0, 0.7)
    gfx.rect(0, 0, gfx.w, gfx.h, 1)
    
    -- Loading Text
    gfx.setfont(F.bld)
    set_color(UI.C_TXT)
    
    local str = UI_STATE.script_loading_state.text or T("LOADING_ELLIPSIS")
    local sw, sh = gfx.measurestr(str)
    
    local cx, cy = gfx.w / 2, gfx.h / 2
    
    gfx.x = cx - sw / 2
    gfx.y = cy - sh / 2 + 50 -- Nudge text down slightly
    gfx.drawstr(str)
    
    -- Animated Loader Image
    if not UI_STATE.script_loading_state.loader_idx then
        -- Count how many loaders actually loaded and their weights
        local available_loaders = {}
        local total_weight = 0
        for i, cfg in ipairs(OTHER.LOADERS_CFG) do
            local w, h = gfx.getimgdim(cfg.buf)
            if w > 0 then 
                table.insert(available_loaders, i) 
                total_weight = total_weight + (cfg.weight or 1)
            end
        end
        
        if #available_loaders > 0 then
            math.randomseed(os.time())
            local rnd = math.random() * total_weight
            local current_weight = 0
            for _, idx in ipairs(available_loaders) do
                local cfg = OTHER.LOADERS_CFG[idx]
                current_weight = current_weight + (cfg.weight or 1)
                if rnd <= current_weight then
                    UI_STATE.script_loading_state.loader_idx = idx
                    
                    -- Easter Egg Achievement for Itachi
                    if cfg.is_itachi then
                        ACHIEVEMENTS.add_stat("ach_7_itachi_uchiha", 1)
                    end
                    
                    break
                end
            end
            -- Fallback
            UI_STATE.script_loading_state.loader_idx = UI_STATE.script_loading_state.loader_idx or available_loaders[1]
        end
    end
    
    local l_idx = UI_STATE.script_loading_state.loader_idx
    local image_drawn = false
    
    if l_idx and OTHER.LOADERS_CFG[l_idx] then
        local l_cfg = OTHER.LOADERS_CFG[l_idx]
        local buf = l_cfg.buf
        local num_frames = l_cfg.frames
        local frame_w_orig = l_cfg.frame_w
        
        local img_w, img_h = gfx.getimgdim(buf)
        if img_w > 0 then
            local frame_w = frame_w_orig or (img_w / num_frames)
            local frame_h = img_h
            if not UI_STATE.script_loading_state.start_time then
                UI_STATE.script_loading_state.start_time = reaper.time_precise()
            end
            local elapsed = reaper.time_precise() - UI_STATE.script_loading_state.start_time
            
            local fps = l_cfg.fps or 12
            local frame_idx = math.floor(elapsed * fps) % num_frames
            local zoom = l_cfg.zoom or 1
            
            -- Scaling to fit UI
            local dest_h = S(100) * zoom -- Base size 100px scaled
            local dest_w = (frame_w / frame_h) * dest_h
            
            local dx = cx - dest_w / 2
            local dy = cy - sh - dest_h / 2 - 20
            
            gfx.blit(buf, 1, 0, frame_idx * frame_w, 0, frame_w, frame_h, dx, dy, dest_w, dest_h)
            image_drawn = true
        end
    end
    
    if not image_drawn then
        -- Fallback to Simple Spinner if image not found
        local radius = 20
        local spinner_y = cy - sh - 30
        local time = reaper.time_precise() * 10
        
        for i = 0, 7 do
            local angle = i * (math.pi / 4) + time
            local px = cx + math.cos(angle) * radius
            local py = spinner_y + math.sin(angle) * radius
            
            local alpha = (math.sin(i / 8 * math.pi * 2 + time) + 1) / 2
            gfx.set(1, 1, 1, alpha)
            gfx.circle(px, py, 3, 1)
        end
    end
    
    -- Force update to animate
    reaper.defer(function() end) 
end

-- =============================================================================
-- MOUSE INPUT HELPERS
-- =============================================================================

--- Check if mouse was just clicked (left button down this frame)
--- @return boolean True if clicked this frame
local function is_mouse_clicked(btn)
    local cap = btn or 1
    -- Check specific bit for the requested button (1=L, 2=R)
    -- Cap 1 is bit 0, Cap 2 is bit 1. 
    -- But gfx.mouse_cap usually returns 1 for Left, 2 for Right.
    -- Strict check: 
    return (gfx.mouse_cap & cap == cap) and (UI_STATE.last_mouse_cap & cap == 0)
end

--- Check if mouse right button was just clicked
--- @return boolean True if clicked this frame
local function is_right_mouse_clicked()
    return gfx.mouse_cap == 2 and UI_STATE.last_mouse_cap == 0
end

