--- Підготовка даних для експорту субтитрів (фільтрація, сортування, генерація імені файлу)
--- @param ext string Розширення файлу (напр. ".srt", ".ass")
--- @return table|nil, string|nil Список реплік та запропоноване ім'я файлу (або nil у разі переривання)
function UTILS.prepare_export_data(ext)
    if not reaper.JS_Dialog_BrowseForSaveFile then
        local msg = T("NEED_JS_REA_1")
        if not has_reapack then
            msg = msg .. T("NEED_JS_REA_2")
        else
            msg = msg .. T("NEED_JS_REA_3")
        end
        reaper.MB(msg, T("MISSIBG_COMPONENTS"), 0)
        return nil, nil
    end

    -- Filter enabled lines
    local out_lines = {}
    local selected_actors = {}
    
    for _, l in ipairs(ass_lines) do
        if l.enabled then
            table.insert(out_lines, l)
            if l.actor and l.actor ~= "" then
                selected_actors[l.actor] = true
            end
        end
    end
    -- Strict sort by index to preserve original file order and layering
    table.sort(out_lines, function(a, b) return (a.index or 0) < (b.index or 0) end)

    if #out_lines == 0 then
        show_snackbar(T("NO_ACTIVE_1"), "info")
        return nil, nil
    end

    -- Construct filename
    local _, proj_path = reaper.EnumProjects(-1)
    local proj_name = "Project"
    if proj_path and proj_path ~= "" then
        proj_name = proj_path:match("([^/\\%s]+)%.[Rr][Pp][Pp]$") or proj_name
    end

    local actors_list = {}
    for act in pairs(selected_actors) do
        table.insert(actors_list, act)
    end
    table.sort(actors_list)
    
    local total_actors = 0
    for _ in pairs(ass_actors) do total_actors = total_actors + 1 end
    
    local suffix = ""
    if #actors_list > 0 and #actors_list < total_actors then
        -- Limit to first 100 actors to avoid super long filenames
        local limit = 100
        local parts = {}
        for i = 1, math.min(#actors_list, limit) do
            table.insert(parts, actors_list[i])
        end
        suffix = "_" .. table.concat(parts, "_")
        if #actors_list > limit then
            suffix = suffix .. "_etc"
        end
    else
        suffix = "_All"
    end
    
    -- Clean filename chars (Sanitize illegal chars, allow unicode)
    suffix = suffix:gsub("[<>:\"/\\|?*]", "_")
    
    local total_replicas, total_words = UTILS.calculate_lines_stats(out_lines)
    local stats_suffix = string.format(T("EXPORT_SUB_STAT_POSTFIX"), total_replicas, total_words)
    
    local default_filename = proj_name .. suffix .. stats_suffix .. ext
    
    return out_lines, default_filename
end

-- ═══════════════════════════════════════════════════════════════
-- DEADLINE MODULE - Methods
-- ═══════════════════════════════════════════════════════════════

--- Get project-wide deadline
--- @return number|nil Project deadline as Unix timestamp
function DEADLINE.get()
    local proj_path, _ = DEADLINE.get_project_info()
    if proj_path then
        local global_data = DEADLINE.load_global()
        local norm_path = DEADLINE.normalize_path(proj_path)
        if global_data[norm_path] and global_data[norm_path].deadline then
            return global_data[norm_path].deadline
        end
    end

    local retval, val = reaper.GetProjExtState(0, section_name, "project_deadline")
    if retval and val ~= "" then
        return tonumber(val)
    end
    return nil
end

--- Set project-wide deadline
--- @param timestamp number|nil Unix timestamp or nil to clear
function DEADLINE.set(timestamp)
    reaper.SetProjExtState(0, section_name, "project_deadline", timestamp and tostring(timestamp) or "")
    reaper.MarkProjectDirty(0)
    DEADLINE.project_deadline = timestamp
    
    -- Update global storage
    local proj_path, proj_name = DEADLINE.get_project_info()
    if proj_path then
        local idx = ACHIEVEMENTS.get_project_idx()
        DEADLINE.save_global(proj_path, proj_name, timestamp, idx)
    end

    -- Trigger immediate achievement update for the new deadline
    ACHIEVEMENTS.check_deadline_failure()
end

--- Get current project path and name
--- @return string|nil, string|nil Project path and name, or nil if unsaved
function DEADLINE.get_project_info()
    local proj, full_path = reaper.EnumProjects(-1)
    if not full_path or full_path == "" then
        -- Return project pointer as a stable ID for unsaved tabs
        local ptr_id = "PTR:" .. tostring(proj)
        return ptr_id, T("UNTITLED_UNSEVED")
    end
    
    local proj_name = reaper.GetProjectName(0)
    if not proj_name or proj_name == "" then
        proj_name = "Untitled"
    end
    
    return full_path, proj_name
end

--- Normalize path for comparison (lower case, separators)
--- @param path string
--- @return string
function DEADLINE.normalize_path(path)
    if not path then return "" end
    path = path:lower()
    path = path:gsub("\\", "/")
    path = path:gsub("^%s*(.-)%s*$", "%1") -- trim
    return path
end

--- Smartly open a project: switch if open, else new tab.
--- Handles missing files by asking user to locate them.
--- @param proj_data table {path, name, deadline}
function DEADLINE.open_project_smart(proj_data)
    if not proj_data or not proj_data.path then return end
    local target_path = proj_data.path
    
    -- PASS 0: Project Pointer Match (for unsaved projects)
    if target_path:match("^PTR:") then
        local target_ptr = target_path:gsub("^PTR:", "")
        local i = 0
        while true do
            local proj = reaper.EnumProjects(i, "")
            if not proj then break end
            if tostring(proj) == target_ptr then
                reaper.SelectProjectInstance(proj)
                return
            end
            i = i + 1
        end
        -- If we are here, the unsaved project tab was closed
        reaper.MB(T("ERR_DEADLINE_NO_OPEN_TEMP"), T("ERROR"), 0)
        return
    end

    -- Normalize target path for comparison
    local norm_target = DEADLINE.normalize_path(target_path)
    local target_filename = norm_target:match("([^/]+)$")
    
    -- PASS 1: Exact Path Match
    local i = 0
    while true do
        local proj = reaper.EnumProjects(i, "")
        if not proj then break end
        
        local _, path = reaper.EnumProjects(i, "")
        if path and path ~= "" then
            local norm_path = DEADLINE.normalize_path(path)
            if norm_path == norm_target then
                reaper.SelectProjectInstance(proj)
                return
            end
        end
        i = i + 1
    end

    -- PASS 2: Filename Match (Fallback)
    if target_filename then
        i = 0
        while true do
            local proj = reaper.EnumProjects(i, "")
            if not proj then break end
            
            local _, path = reaper.EnumProjects(i, "")
            if path and path ~= "" then
                local norm_path = DEADLINE.normalize_path(path)
                local filename = norm_path:match("([^/]+)$")
                
                if filename == target_filename then
                    reaper.SelectProjectInstance(proj)
                    return
                end
            end
            i = i + 1
        end
    end
    
    -- PASS 3: Open New Tab (or Recover)
    if reaper.file_exists(target_path) then
        reaper.Main_OnCommand(40859, 0) -- New project tab
        reaper.Main_openProject(target_path)
    else
        -- Smart Recovery: File not found
        local result = reaper.MB(T("SRC_I_NF_1") .. target_path .. T("SRC_I_NF_2"), T("SRC_I_NF_3"), 4)
        if result == 6 then -- 6 = Yes
            local retval, new_path = reaper.GetUserFileNameForRead(target_path, T("FIND_A_PROJ_UF") .. " " .. (proj_data.name or ""), "rpp")
            if retval and new_path then
                -- Open found file
                reaper.Main_OnCommand(40859, 0)
                reaper.Main_openProject(new_path)
                
                -- Update Database
                DEADLINE.save_global(target_path, proj_data.name, nil) -- Delete old
                DEADLINE.save_global(new_path, proj_data.name, proj_data.deadline) -- Save new
                show_snackbar(T("DEADLINE_SAVE_UPDATE_PATH"), "success")
            end
        end
    end
end

--- Save deadline to global storage
--- @param project_path string Full path to project file
--- @param project_name string Project name
--- @param deadline_ts number|nil Unix timestamp or nil to remove
function DEADLINE.save_global(project_path, project_name, deadline_ts, idx)
    if not project_path then return end
    local norm_path = DEADLINE.normalize_path(project_path)

    local data = DEADLINE.load_global()
    
    if deadline_ts then
        -- Add or update deadline
        data[norm_path] = {
            name = project_name,
            deadline = deadline_ts,
            path = project_path, -- Store original raw path with casing
            idx = idx or (data[norm_path] and data[norm_path].idx) -- Preserve existing index if updated
        }
    else
        -- Remove deadline
        data[norm_path] = nil
    end
    
    -- Save as JSON
    local json_str = STATS.json_encode(data)
    reaper.SetExtState(section_name, "new_project_deadlines", json_str, true)
    
    -- Invalidate urgency cache for immediate update
    DEADLINE.urgency_cache.last_check = 0
end

--- Load all project deadlines from global storage
--- @return table Map of project_path -> {name, deadline}
function DEADLINE.load_global()
    local json_str = reaper.GetExtState(section_name, "new_project_deadlines")
    if not json_str or json_str == "" then
        return {}
    end
    
    -- Simple JSON decode (assumes valid format)
    local data = {}
    local success, result = pcall(function()
        return STATS.json_decode(json_str)
    end)
    
    if success and type(result) == "table" then
        return result
    end
    
    return {}
end

--- Get overall urgency color for dashboard button
--- @return number color constant
DEADLINE.urgency_cache = {
    color = nil,
    last_check = 0
}

function DEADLINE.get_overall_urgency()
    local now = reaper.time_precise()
    -- Return cached value if less than 3 second passed
    if DEADLINE.urgency_cache.color and (now - DEADLINE.urgency_cache.last_check < 3.0) then
        return DEADLINE.urgency_cache.color
    end

    local data = DEADLINE.load_global()
    local highest_urgency = 0 -- 0: none, 1: orange, 2: red
    local ts_now = os.time()
    
    for _, proj in pairs(data) do
        if proj.deadline then
            local days = math.ceil((proj.deadline - ts_now) / 86400)
            if days <= 0 then
                highest_urgency = 2
            elseif days == 1 and highest_urgency < 1 then
                highest_urgency = 1
            end
        end
    end
    
    local final_col = UI.C_TAB_INA
    if highest_urgency == 2 then final_col = UI.C_RED end
    if highest_urgency == 1 then final_col = UI.C_ORANGE end
    
    DEADLINE.urgency_cache.color = final_col
    DEADLINE.urgency_cache.last_check = now
    
    return final_col
end

--- Sync local project deadline with global storage on load
function DEADLINE.sync_project()
    local proj_path, proj_name = DEADLINE.get_project_info()
    if not proj_path then return end

    -- Normalize path for consistent key lookup
    proj_path = DEADLINE.normalize_path(proj_path)

    -- Load and sync
    local global_data = DEADLINE.load_global()
    local changed = false

    -- MIGRATION: Check if we have an entry for this project as "unsaved" (via pointer)
    local proj_ptr, _ = reaper.EnumProjects(-1)
    local ptr_id = DEADLINE.normalize_path("PTR:" .. tostring(proj_ptr))
    local ptr_entry = global_data[ptr_id]
    
    if ptr_entry and not proj_path:match("^ptr:") then
        -- Move deadline from temporary pointer ID to the real project path
        local norm_proj_path = DEADLINE.normalize_path(proj_path)
        global_data[norm_proj_path] = {
            name = proj_name or "Untitled",
            deadline = ptr_entry.deadline,
            path = proj_path -- Store original raw path with casing
        }
        global_data[ptr_id] = nil
        changed = true
    end

    local global_entry = global_data[proj_path]

    if global_entry then
        -- Sync local with global (Global is source of truth)
        if DEADLINE.project_deadline ~= global_entry.deadline then
            reaper.SetProjExtState(0, section_name, "project_deadline", tostring(global_entry.deadline))
            DEADLINE.project_deadline = global_entry.deadline
        end
    else
        -- If project is NOT in global registry, it means it has no deadline (or it was deleted)
        -- We MUST clear the local state to stay in sync with the global truth
        reaper.SetProjExtState(0, section_name, "project_deadline", "")
        DEADLINE.project_deadline = nil
    end

    if changed then
        local json_str = STATS.json_encode(global_data)
        reaper.SetExtState(section_name, "new_project_deadlines", json_str, true)
    end
end
-- Run sync on script start
DEADLINE.sync_project()
ACHIEVEMENTS.check_deadline_failure()

--- Sort projects by urgency: Passed -> Today -> Soon -> Later
local function sort_deadlines(a, b)
    local now = os.time()
    
    -- Helper to get days remaining
    local function get_days(ts)
        return math.ceil((ts - now) / 86400)
    end
    
    local days_a = get_days(a.deadline)
    local days_b = get_days(b.deadline)
    
    -- Priority 1: Passed deadlines (negative days)
    if days_a < 0 and days_b >= 0 then return true end
    if days_b < 0 and days_a >= 0 then return false end
    
    -- Priority 2: Today (0 days)
    if days_a == 0 and days_b ~= 0 then return true end
    if days_b == 0 and days_a ~= 0 then return false end
    
    -- Priority 3: Ascending order (sooner first)
    return a.deadline < b.deadline
end

--- Draw Deadline Dashboard
function DEADLINE.draw_dashboard(input_queue)
    local pad = S(20)
    
    -- Background overlay
    set_color(UI.C_BG, 0.98)
    gfx.rect(0, 0, gfx.w, gfx.h, 1)
    
    -- Header measuring (for list_y)
    gfx.setfont(F.title)
    local title = T("MY_DEADLINES")
    local tw, th = gfx.measurestr(title)
    local is_narrow = gfx.w < S(450)
    local list_y = pad + th + S(12)

    -- Load and Sort Data
    local all_deadlines = DEADLINE.load_global()
    local sorted_projects = {}
    for path_key, data in pairs(all_deadlines) do
        if data.deadline then
            table.insert(sorted_projects, {
                path = data.path or path_key, -- Use original path if stored, else fallback to key
                name = data.name,
                deadline = data.deadline
            })
        end
    end
    table.sort(sorted_projects, sort_deadlines)
    
    -- Scroll Configuration
    local row_h = is_narrow and S(100) or S(60)
    local avail_h = gfx.h - list_y - pad
    local content_h = #sorted_projects * row_h
    local max_scroll = math.max(0, content_h - avail_h)
    
    -- Mouse Wheel Handling
    if gfx.mouse_wheel ~= 0 then
        UI_STATE.dash_target_scroll_y = UI_STATE.dash_target_scroll_y - (gfx.mouse_wheel * 0.25)
        gfx.mouse_wheel = 0
    end
    
    -- Bound & Smooth Scroll
    UI_STATE.dash_target_scroll_y = math.max(0, math.min(UI_STATE.dash_target_scroll_y, max_scroll))
    local diff = UI_STATE.dash_target_scroll_y - UI_STATE.dash_scroll_y
    if math.abs(diff) > 0.5 then
        UI_STATE.dash_scroll_y = UI_STATE.dash_scroll_y + (diff * 0.8)
    else
        UI_STATE.dash_scroll_y = UI_STATE.dash_target_scroll_y
    end

    local function get_y(offset)
        return list_y + offset - math.floor(UI_STATE.dash_scroll_y)
    end

    -- Column Config
    local status_col_w = S(100)
    local btn_col_w = S(150)
    
    local status_x = pad + S(5)
    local btn_x = gfx.w - pad - btn_col_w
    local name_x = status_x + status_col_w + S(2)
    local name_col_w = btn_x - name_x - S(10)
    
    if is_narrow then
        btn_col_w = (gfx.w - pad * 2 - S(10)) / 2
        btn_x = pad
    end
    
    -- Empty State
    if #sorted_projects == 0 then
        set_color(UI.C_TXT, 0.5)
        gfx.setfont(F.std)
        local msg = T("NO_ACTIVE_DEADLINES")
        local mw, mh = gfx.measurestr(msg)
        gfx.x, gfx.y = (gfx.w - mw)/2, list_y + S(50)
        gfx.drawstr(msg)
    else
        -- Draw List
        for i, proj in ipairs(sorted_projects) do
            local y_offset = (i-1) * row_h
            local row_y = get_y(y_offset)
            
            -- Only draw if visible
            if row_y + row_h > list_y and row_y < gfx.h then
                -- Separator line
                set_color(UI.C_TAB_INA, 0.2)
                gfx.line(pad, row_y + row_h - 1, gfx.w - pad, row_y + row_h - 1)
                
                -- Calculations
                local days = math.ceil((proj.deadline - os.time()) / 86400)
                local date_txt = os.date("%d.%m.%Y", proj.deadline)
                local status_txt, status_col = "", UI.C_TXT
                
                if days < 0 then
                    status_txt, status_col = T("DEADLINE_PASSED"), UI.C_SNACK_ERROR
                elseif days == 0 then
                    status_txt, status_col = T("DEADLINE_TODAY"), UI.C_RED
                elseif days == 1 then
                    status_txt, status_col = T("TOMORROW"), UI.C_ORANGE
                else
                    status_txt, status_col = T("ACTIVE"), UI.C_SNACK_SUCCESS
                end
                
                -- --- COLUMN 1: Status & Date ---
                gfx.setfont(F.std)
                local cur_y = row_y + S(10)
                
                local br_w = status_col_w - S(15)
                if days <= 1 then
                    local sw, sh = gfx.measurestr(status_txt)
                    local dw, dh = gfx.measurestr(date_txt)
                    local bh = sh + dh + S(6)
                    
                    set_color(status_col)
                    gfx.rect(status_x - S(5), cur_y - S(2), br_w, bh, 1)
                    
                    local txt_col = UI.C_TXT
                    if days < 0 and cfg.ui_theme == "Quartz" then txt_col = UI.C_WHITE end
                    set_color(txt_col)
                    
                    gfx.x, gfx.y = status_x, cur_y
                    gfx.drawstr(status_txt)
                    gfx.x, gfx.y = status_x, cur_y + sh + S(2)
                    gfx.drawstr(date_txt)
                else
                    set_color(status_col)
                    gfx.x, gfx.y = status_x, cur_y
                    gfx.drawstr(status_txt)
                    set_color(UI.C_TXT, 0.7)
                    gfx.x, gfx.y = status_x, cur_y + S(16)
                    gfx.drawstr(date_txt)
                end
                
                -- --- COLUMN 2: Name & Path ---
                local nx = is_narrow and (status_x + br_w + S(10)) or name_x
                local ny = cur_y
                local nw = is_narrow and (gfx.w - nx - pad) or name_col_w
                
                set_color(UI.C_TXT)
                gfx.setfont(F.bld)
                gfx.x, gfx.y = nx, ny
                local trunk_name = fit_text_width(proj.name, nw)
                gfx.drawstr(trunk_name)
                
                set_color(UI.C_TXT, 0.5)
                gfx.setfont(F.tip)
                gfx.x, gfx.y = nx, ny + S(18)
                local trunk_path = fit_text_width(proj.path, nw)
                gfx.drawstr(trunk_path)
                
                -- --- COLUMN 3: Actions ---
                local btn_w = is_narrow and btn_col_w or (btn_col_w / 2 - S(5))
                local btn_h = S(28)
                local bx = is_narrow and pad or btn_x
                local by = is_narrow and (row_y + S(55)) or (row_y + (row_h - btn_h)/2)
                
                if btn(bx, by, btn_w, btn_h, T("CHANGE"), UI.C_BTN, UI.C_TXT) and gfx.mouse_y > list_y then
                    DEADLINE.open_picker(proj.deadline, function(new_ts)
                        DEADLINE.save_global(proj.path, proj.name, new_ts)
                        ACHIEVEMENTS.global_deadline_sweep() -- Trigger immediate achievement sync
                        local cp_path, _ = DEADLINE.get_project_info()
                        if cp_path and proj.path and DEADLINE.normalize_path(cp_path) == DEADLINE.normalize_path(proj.path) then
                            DEADLINE.set(new_ts)
                        end
                    end)
                end
                
                if btn(bx + btn_w + S(10), by, btn_w, btn_h, T("OPEN"), UI.C_ROW, UI.C_TXT) and gfx.mouse_y > list_y then
                    DEADLINE.open_project_smart(proj)
                end
            end
        end
        
        -- Draw Interactive Scrollbar
        if max_scroll > 0 then
            UI_STATE.dash_target_scroll_y = draw_scrollbar(gfx.w - S(10), list_y, S(10), avail_h, content_h, avail_h, UI_STATE.dash_target_scroll_y)
        end
    end

    -- --- HEADER OVERLAY (Mask scrolling rows) ---
    set_color(UI.C_BG, 1.0)
    gfx.rect(0, 0, gfx.w, list_y, 1)

    -- Close button (Top Right)
    local close_sz = S(24)
    local cx = gfx.w - pad - close_sz
    local cy = pad

    -- --- HEADER CONTENTS ---
    gfx.setfont(F.title)
    set_color(UI.C_TXT)
    gfx.x, gfx.y = pad, pad

    -- Setup Notifications Button
    local s_btn_w = cfg.lng == "ua" and S(170) or S(117)
    
    -- Truncate title if it gets too close to the close button
    local avail_tw = cx - pad - s_btn_w - S(10)
    local draw_title = fit_text_width(title, avail_tw)
    gfx.drawstr(draw_title)
    
    local function close_dash()
        DEADLINE.dashboard_show = false
    end
    
    if btn(cx, cy, close_sz, close_sz, "X", UI.C_BTN, UI.C_TXT) then
        close_dash()
    end

    local s_btn_x = cx - s_btn_w - S(10)
    if btn(s_btn_x, cy, s_btn_w, close_sz, T("SET_UP_NOTIFY"), UI.C_ROW, UI.C_TXT) then
        local retval, ret_time = reaper.GetUserInputs(T("NOTIFY_SETTINGS"), 1, T("NOTIFY_SETTINGS_TIME"), cfg.notify_time)
        if retval then
            cfg.notify_time = ret_time
            reaper.SetExtState(section_name, "notify_time", ret_time, true)
            
            local source = debug.getinfo(1,'S').source
            local script_path = source:match([[^@?(.*[\\/])]]) or ""
            if script_path ~= "" then
                local py_script = script_path .. "stats/subass_notifier.py"
                local cmd_args = ' --setup --time "' .. ret_time .. '"'
                
                if reaper.GetOS():match("Win") then
                    py_script = py_script:gsub("/", "\\")
                    local py_exe = UTILS.get_win_py_exe((OTHER and OTHER.rec_state and OTHER.rec_state.python and OTHER.rec_state.python.executable) or "pythonw.exe")
                    local cmd = string.format('cmd.exe /C start /B "" %s "%s" %s', py_exe, py_script, cmd_args)
                    reaper.ExecProcess(cmd, 0)
                else
                    -- macOS/Linux: simple background execution with nohup for complete detachment
                    local cmd = string.format('nohup python3 "%s" %s > /dev/null 2>&1 &', py_script, cmd_args)
                    os.execute(cmd)
                end
                ACHIEVEMENTS.add_stat("ach_30_count", 1)
                show_snackbar(T("NOTIFY_REQUEST_SENT") .. ret_time, "info")
            end
        end
    end
    
    -- Escape key check
    if input_queue then
        for _, c in ipairs(input_queue) do
            if c == 27 then -- ESC
                close_dash()
                break
            end
        end
    end
end

--- Helper: Is leap year?
function DEADLINE.is_leap_year(y)
    return (y % 4 == 0 and y % 100 ~= 0) or (y % 400 == 0)
end

--- Helper: Get days in month
function DEADLINE.get_days_in_month(m, y)
    local days = {31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31}
    if m == 2 and DEADLINE.is_leap_year(y) then return 29 end
    return days[m] or 31
end

--- Open the date picker modal
--- @param initial_ts number|nil Initial timestamp
--- @param callback function Function to call on select(timestamp)
function DEADLINE.open_picker(initial_ts, callback)
    local now = os.date("*t")
    local t = initial_ts and os.date("*t", initial_ts) or now
    
    DEADLINE.modal.year = t.year
    DEADLINE.modal.month = t.month
    DEADLINE.modal.selected_day = t.day
    DEADLINE.modal.initial_date = initial_ts and os.date("*t", initial_ts) or nil
    DEADLINE.modal.callback = callback
    DEADLINE.modal.show = true
end

--- Draw the Date Picker Modal
function DEADLINE.draw_picker(input_queue)
    if not DEADLINE.modal.show then return end
    
    UI_STATE.mouse_handled = true -- Block interaction with background
    
    local w, h = S(DEADLINE.modal.w), S(DEADLINE.modal.h)
    local x, y = (gfx.w - w) / 2, (gfx.h - h) / 2

    -- Dim background
    set_color({0, 0, 0, 0.5})
    gfx.rect(0, 0, gfx.w, gfx.h, 1)
    
    -- Modal Background
    set_color(UI.C_BG)
    gfx.rect(x, y, w, h, 1)
    set_color(UI.C_MEDIUM_GREY)
    gfx.rect(x, y, w, h, 0)
    
    -- Header (Month Year)
    local month_names = {"Січень", "Лютий", "Березень", "Квітень", "Травень", "Червень", 
                         "Липень", "Серпень", "Вересень", "Жовтень", "Листопад", "Грудень"}

    -- Weekdays Header
    local wd_names = {"Пн", "Вт", "Ср", "Чт", "Пт", "Сб", "Нд"}

    if cfg.lng == "en" then
        month_names = {"January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"}
        wd_names = {"Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"}
    end

    local title = month_names[DEADLINE.modal.month] .. " " .. DEADLINE.modal.year
    gfx.setfont(F.dict_bld)
    set_color(UI.C_TXT)
    local tw, th = gfx.measurestr(title)
    gfx.x, gfx.y = x + (w - tw) / 2, y + S(15)
    gfx.drawstr(title)
    
    -- Month Navigation
    if btn(x + S(10), y + S(12), S(30), S(25), "<", UI.C_ROW) then
        DEADLINE.modal.month = DEADLINE.modal.month - 1
        if DEADLINE.modal.month < 1 then
            DEADLINE.modal.month = 12
            DEADLINE.modal.year = DEADLINE.modal.year - 1
        end
    end
    
    if btn(x + w - S(40), y + S(12), S(30), S(25), ">", UI.C_ROW) then
        DEADLINE.modal.month = DEADLINE.modal.month + 1
        if DEADLINE.modal.month > 12 then
            DEADLINE.modal.month = 1
            DEADLINE.modal.year = DEADLINE.modal.year + 1
        end
    end
    
    gfx.setfont(F.dict_std_sm)
    local cell_w = (w - S(20)) / 7
    for i, wd in ipairs(wd_names) do
        set_color(i > 5 and UI.C_RED or UI.C_MEDIUM_GREY)
        local wdw = gfx.measurestr(wd)
        gfx.x = x + S(10) + (i - 1) * cell_w + (cell_w - wdw) / 2
        gfx.y = y + S(50)
        gfx.drawstr(wd)
    end
    
    -- Calendar Grid
    local first_day_t = os.time({year=DEADLINE.modal.year, month=DEADLINE.modal.month, day=1})
    local first_wd = tonumber(os.date("%w", first_day_t)) -- 0=Sun
    first_wd = (first_wd == 0) and 7 or first_wd -- Map to 1=Mon...7=Sun
    
    local days_in_month = DEADLINE.get_days_in_month(DEADLINE.modal.month, DEADLINE.modal.year)
    local day_cursor = 1
    local row = 0
    local now = os.date("*t")
    
    while day_cursor <= days_in_month do
        for col = 1, 7 do
            local current_wd_idx = row * 7 + col
            if current_wd_idx >= first_wd and day_cursor <= days_in_month then
                local cx = x + S(10) + (col - 1) * cell_w
                local cy = y + S(75) + row * S(30)
                
                -- Highlight if it matches the current set deadline
                local cur_dl = DEADLINE.modal.initial_date
                local is_highlighted = cur_dl and cur_dl.day == day_cursor and cur_dl.month == DEADLINE.modal.month and cur_dl.year == DEADLINE.modal.year
                
                local is_today = (day_cursor == now.day and DEADLINE.modal.month == now.month and DEADLINE.modal.year == now.year)
                
                -- Cell Background
                if is_highlighted then
                    set_color(UI.C_GREEN)
                    gfx.rect(cx + 2, cy + 2, cell_w - 4, S(26), 1)
                elseif is_today then
                    set_color(UI.C_RED) -- Use a distinct color for today
                    gfx.rect(cx + 2, cy + 2, cell_w - 4, S(26), 0) -- Outline
                end
                
                -- Click
                if is_mouse_clicked() and gfx.mouse_x >= cx and gfx.mouse_x < cx + cell_w and
                   gfx.mouse_y >= cy and gfx.mouse_y < cy + S(30) then
                    local new_ts = os.time({year=DEADLINE.modal.year, month=DEADLINE.modal.month, day=day_cursor, hour=0, min=0, sec=0})
                    if DEADLINE.modal.callback then DEADLINE.modal.callback(new_ts) end
                    DEADLINE.modal.show = false
                end
                
                -- Day Number
                set_color(is_highlighted and UI.C_BLACK or UI.C_TXT)
                local ds = tostring(day_cursor)
                local dw, dh = gfx.measurestr(ds)
                gfx.x = cx + (cell_w - dw) / 2
                gfx.y = cy + (S(30) - dh) / 2
                gfx.drawstr(ds)
                
                day_cursor = day_cursor + 1
            end
        end
        row = row + 1
    end
    
    -- Bottom Buttons
    local b_w = (w - S(30)) / 2
    local b_y = y + h - S(45)
    
    if btn(x + S(10), b_y, b_w, S(30), T("REMOVE_DEADLINE")) then
        if DEADLINE.modal.callback then DEADLINE.modal.callback(nil) end
        DEADLINE.modal.show = false
    end
    
    if btn(x + S(20) + b_w, b_y, b_w, S(30), T("CLOSE"), UI.C_ROW) then
        DEADLINE.modal.show = false
    end

    -- Escape key check
    if input_queue then
        for _, c in ipairs(input_queue) do
            if c == 27 then -- ESC
                DEADLINE.modal.show = false
                break
            end
        end
    end
end

--- Parse deadline from name (e.g. [15.02.2026] or [15.02])
--- @param name string Text to parse
--- @return number|nil Unix timestamp of start of day
function DEADLINE.parse_from_name(name)
    -- Pattern: [DD.MM.YYYY] or [DD.MM]
    local d, m, y = name:match("%[(%d%d)%.(%d%d)%.?(%d?%d?%d?%d?)%]")
    if d and m then
        d, m = tonumber(d), tonumber(m)
        y = tonumber(y)
        local now = os.date("*t")
        if not y or y == 0 then
            y = now.year
        elseif y < 100 then
            y = 2000 + y
        end
        
        -- Return start of day (00:00:00)
        local success, res = pcall(os.time, {day=d, month=m, year=y, hour=0, min=0, sec=0})
        if success then return res end
    end
    return nil
end

function UTILS.get_tracks_to_check()
    local tracks_to_check = {}
    local processed_tracks = {}
    local guids = ""
    local sel_tracks_count = reaper.CountSelectedTracks(0)
    
    if sel_tracks_count > 0 then
        for i = 0, sel_tracks_count - 1 do
            local tr = reaper.GetSelectedTrack(0, i)
            local guid = reaper.GetTrackGUID(tr)
            guids = guids .. guid
            
            if not processed_tracks[tr] then
                processed_tracks[tr] = true
                table.insert(tracks_to_check, tr)
                
                -- Check if it's a folder (I_FOLDERDEPTH > 0)
                if reaper.GetMediaTrackInfo_Value(tr, "I_FOLDERDEPTH") > 0 then
                    local tr_idx = math.floor(reaper.GetMediaTrackInfo_Value(tr, "IP_TRACKNUMBER")) -- 1-based
                    local parent_depth = reaper.GetTrackDepth(tr)
                    local total_tracks = reaper.CountTracks(0)
                    
                    for j = tr_idx, total_tracks - 1 do
                        local child_tr = reaper.GetTrack(0, j)
                        if reaper.GetTrackDepth(child_tr) > parent_depth then
                            if not processed_tracks[child_tr] then
                                processed_tracks[child_tr] = true
                                table.insert(tracks_to_check, child_tr)
                            end
                        else
                            break -- End of folder
                        end
                    end
                end
            end
        end
    end
    return tracks_to_check, guids
end

function UTILS.get_recording_progress()
    if not regions or #regions == 0 then return 0, 0, 0 end
    
    -- Freeze progress during active recording to save resources
    local play_state = reaper.GetPlayState()
    if (play_state & 4) == 4 then 
        return OTHER.progress_cache.percent, OTHER.progress_cache.recorded or 0, OTHER.progress_cache.regions_count or 0
    end
    
    -- Throttle: don't recalculate more than once per 0.5s.
    -- The triple-nested regions×tracks×items loop is very expensive in large projects.
    local now = reaper.time_precise()
    if OTHER.progress_cache.last_calc_time and (now - OTHER.progress_cache.last_calc_time) < 0.5 then
        return OTHER.progress_cache.percent or 0, OTHER.progress_cache.recorded or 0, OTHER.progress_cache.regions_count or #regions
    end
    OTHER.progress_cache.last_calc_time = now
    
    local cur_state = reaper.GetProjectStateChangeCount(0)
    
    -- Invalidate whole track cache if project state or regions count changes
    if OTHER.progress_cache.state_count ~= cur_state or OTHER.progress_cache.regions_count ~= #regions then
        OTHER.progress_cache.state_count = cur_state
        OTHER.progress_cache.regions_count = #regions
        OTHER.progress_cache.data = {} -- Reset per-track map
        OTHER.progress_cache.data_rec = {}
    end

    local tracks_to_check, guids = UTILS.get_tracks_to_check()
    if guids == "" then return 0, 0, #regions end

    -- Check if we have this track combo in cache
    if OTHER.progress_cache.data[guids] then
        OTHER.progress_cache.percent = OTHER.progress_cache.data[guids] -- Store for playhead freeze use
        OTHER.progress_cache.recorded = OTHER.progress_cache.data_rec[guids] or 0
        return OTHER.progress_cache.percent, OTHER.progress_cache.recorded, #regions
    end
    
    -- OPTIMIZATION: Collect all item ranges ONCE to avoid thousands of API calls in the nested loop
    local items_ranges = {}
    local proj_len = reaper.GetProjectLength(0)
    for _, tr in ipairs(tracks_to_check) do
        local item_count = reaper.CountTrackMediaItems(tr)
        for i = 0, item_count - 1 do
            local item = reaper.GetTrackMediaItem(tr, i)
            if item and reaper.GetMediaItemInfo_Value(item, "B_MUTE") == 0 then
                local i_pos = reaper.GetMediaItemInfo_Value(item, "D_POSITION")
                local i_len = reaper.GetMediaItemInfo_Value(item, "D_LENGTH")
                
                -- Check if it is a video file
                local is_video = false
                local take = reaper.GetActiveTake(item)
                if take then
                    local source = reaper.GetMediaItemTake_Source(take)
                    if source then
                        local src_type = reaper.GetMediaSourceType(source, "")
                        if src_type == "VIDEO" then
                            is_video = true
                        end
                    end
                end
                
                -- Ignore items that occupy the entire project duration, are videos, or exceed 10 minutes (600s)
                local is_full_proj = (proj_len > 15 and i_len >= proj_len - 2.0)
                local is_too_long = (i_len > 600)
                
                if not is_full_proj and not is_video and not is_too_long then
                    table.insert(items_ranges, {s = i_pos, e = i_pos + i_len})
                end
            end
        end
    end

    local recorded_count = 0
    for _, rgn in ipairs(regions) do
        local rgn_recorded = false
        -- Efficient check against pre-collected ranges
        for _, it in ipairs(items_ranges) do
            if it.s < rgn.rgnend and it.e > rgn.pos then
                rgn_recorded = true
                break
            end
        end
        if rgn_recorded then recorded_count = recorded_count + 1 end
    end
    
    local percent = math.floor((recorded_count / #regions) * 100)
    
    -- Update cache
    OTHER.progress_cache.data[guids] = percent
    OTHER.progress_cache.data_rec[guids] = recorded_count
    OTHER.progress_cache.percent = percent
    OTHER.progress_cache.recorded = recorded_count
    
    return percent, recorded_count, #regions
end

--- Get ETC strings for context menu (Needs UTILS scope)
function STATS.get_etc_strings()
    local buf = STATS.etc.buffer
    if not buf or #buf < 2 then
        return T("PROMPT_MENU_R_MORE_SPEED"), T("PROMPT_MENU_R_MORE_FORECAST")
    end
    
    local first = buf[1]
    local last = buf[#buf]

    local time_since_last = os.time() - STATS.etc.last_activity_time
    local effective_last_time
    if time_since_last < STATS.etc.PAUSE_THRESHOLD then
        effective_last_time = math.max(last.time, os.time())
    else
        effective_last_time = last.time
    end
    
    local diff_time = effective_last_time - first.time
    local diff_count = last.count - first.count
    
    if diff_time <= 0 or diff_count <= 0 then
        return T("PROMPT_MENU_R_MORE_SPEED"), T("PROMPT_MENU_R_MORE_FORECAST")
    end
    
    -- Speed in replicas per minute
    local speed = diff_count / (diff_time / 60)
    
    -- Format speed string: if slow (< 1 replica/min), show as "1 репл. / ~N хв" for clarity
    local speed_str
    if speed >= 1 then
        speed_str = string.format(T("PROMPT_MENU_CL_1"), speed)
    else
        local mins_per_replica = math.ceil(1 / speed)
        speed_str = string.format(T("PROMPT_MENU_CL_2"), mins_per_replica)
    end

    local _, current_count, total_count = UTILS.get_recording_progress()
    local work_left = (total_count or 0) - (current_count or 0)
    
    if work_left <= 0 then
        return T("PROMPT_MENU_CL_4") .. speed_str, T("PROMPT_MENU_CL_3")
    end
    
    local minutes_left = work_left / speed
    local hours = math.floor(minutes_left / 60)
    local mins = math.floor(minutes_left % 60)
    
    local time_str = ""
    if hours > 0 then
        time_str = string.format(T("PROMPT_MENU_CL_5"), hours, mins)
    elseif mins > 0 then
        time_str = string.format(T("PROMPT_MENU_CL_6"), mins)
    else
        time_str = T("PROMPT_MENU_CL_7")
    end
    
    return T("PROMPT_MENU_CL_4") .. speed_str, T("PROMPT_MENU_CL_8") .. time_str
end

function UTILS.jump_to_first_unrecorded_region()
    if not regions or #regions == 0 then return end
    
    local tracks_to_check = UTILS.get_tracks_to_check()
    if #tracks_to_check == 0 then 
        show_snackbar(T("PROMPT_MENU_SELECT_T_TO_C"), "warning")
        return 
    end
    
    -- OPTIMIZATION: Collect all item ranges ONCE to avoid API calls in the nested loop
    local items_ranges = {}
    for _, tr in ipairs(tracks_to_check) do
        local item_count = reaper.CountTrackMediaItems(tr)
        for i = 0, item_count - 1 do
            local item = reaper.GetTrackMediaItem(tr, i)
            if item and reaper.GetMediaItemInfo_Value(item, "B_MUTE") == 0 then
                local i_pos = reaper.GetMediaItemInfo_Value(item, "D_POSITION")
                local i_len = reaper.GetMediaItemInfo_Value(item, "D_LENGTH")
                table.insert(items_ranges, {s = i_pos, e = i_pos + i_len})
            end
        end
    end
    
    for _, rgn in ipairs(regions) do
        local rgn_recorded = false
        -- Efficient check against pre-collected ranges
        for _, it in ipairs(items_ranges) do
            if it.s < rgn.rgnend and it.e > rgn.pos then
                rgn_recorded = true
                break
            end
        end
        
        if not rgn_recorded then
            reaper.SetEditCurPos(rgn.pos, true, false)
            show_snackbar(T("PROMPT_MENU_SKIP_TO_F_ER"), "info")
            return
        end
    end
    
    show_snackbar(T("PROMPT_MENU_ALL_RECORDED"), "info")
end

-- =============================================================================
-- UTF-8 TEXT PROCESSING
-- =============================================================================

--- Convert UTF-8 string to lowercase (supports Cyrillic)
--- @param s string Input string
--- @return string Lowercase string
local function utf8_lower(s)
    if not s then return "" end
    local res = {}
    local len = #s
    local i = 1
    while i <= len do
        local b = s:byte(i)
        if b < 128 then
            -- ASCII A-Z
            if b >= 65 and b <= 90 then
                table.insert(res, string.char(b + 32))
            else
                table.insert(res, string.char(b))
            end
            i = i + 1
        else
            -- Multibyte
            local seq_len = 0
            if b >= 240 then seq_len = 4
            elseif b >= 224 then seq_len = 3
            elseif b >= 192 then seq_len = 2
            end
            
            if seq_len > 0 and i + seq_len - 1 <= len then
                -- Valid length, try to decode
                local codepoint = 0
                if seq_len == 2 then
                    codepoint = ((b & 31) << 6) | (s:byte(i+1) & 63)
                elseif seq_len == 3 then
                    codepoint = ((b & 15) << 12) | ((s:byte(i+1) & 63) << 6) | (s:byte(i+2) & 63)
                elseif seq_len == 4 then
                    codepoint = ((b & 7) << 18) | ((s:byte(i+1) & 63) << 12) | ((s:byte(i+2) & 63) << 6) | (s:byte(i+3) & 63)
                end
                
                -- Cyrillic Case Mapping
                -- Basic: 0x0410(1040) - 0x042F(1071) -> +32
                if codepoint >= 1040 and codepoint <= 1071 then codepoint = codepoint + 32 
                -- Special mappings
                elseif codepoint == 1025 then codepoint = 1105 -- Yo
                elseif codepoint == 1028 then codepoint = 1108 -- Ye
                elseif codepoint == 1030 then codepoint = 1110 -- I
                elseif codepoint == 1031 then codepoint = 1111 -- Yi
                elseif codepoint == 1168 then codepoint = 1169 -- Ghe
                end
                
                table.insert(res, utf8.char(codepoint))
                i = i + seq_len
            else
                -- Invalid start byte or truncated: just copy the byte
                table.insert(res, string.char(b))
                i = i + 1
            end
        end
    end
    return table.concat(res)
end

--- Remove combining acute accents (stress marks) from a UTF-8 string
--- @param s string Input string
--- @return string Clean string
local function strip_accents(s)
    if not s then return "" end
    return s:gsub(acute, "")
end

-- Helper: UTF-8 safe uppercase
--- Convert UTF-8 string to uppercase (supports Cyrillic)
--- @param s string Input string
--- @return string Uppercase string
local function utf8_upper(s)
    if not s then return "" end
    local res = {}
    local len = #s
    local i = 1
    while i <= len do
        local b = s:byte(i)
        if b < 128 then
            if b >= 97 and b <= 122 then
                table.insert(res, string.char(b - 32))
            else
                table.insert(res, string.char(b))
            end
            i = i + 1
        else
            local seq_len = 0
            if b >= 240 then seq_len = 4
            elseif b >= 224 then seq_len = 3
            elseif b >= 192 then seq_len = 2
            end
            
            if seq_len > 0 and i + seq_len - 1 <= len then
                local codepoint = 0
                if seq_len == 2 then
                    codepoint = ((b & 31) << 6) | (s:byte(i+1) & 63)
                elseif seq_len == 3 then
                    codepoint = ((b & 15) << 12) | ((s:byte(i+1) & 63) << 6) | (s:byte(i+2) & 63)
                elseif seq_len == 4 then
                    codepoint = ((b & 7) << 18) | ((s:byte(i+1) & 63) << 12) | ((s:byte(i+2) & 63) << 6) | (s:byte(i+3) & 63)
                end
                
                -- Cyrillic Upper Mapping
                if codepoint >= 1072 and codepoint <= 1103 then codepoint = codepoint - 32
                elseif codepoint == 1105 then codepoint = 1025
                elseif codepoint == 1108 then codepoint = 1028
                elseif codepoint == 1110 then codepoint = 1030
                elseif codepoint == 1111 then codepoint = 1031
                elseif codepoint == 1169 then codepoint = 1168
                end
                
                table.insert(res, utf8.char(codepoint))
                i = i + seq_len
            else
                table.insert(res, string.char(b))
                i = i + 1
            end
        end
    end
    return table.concat(res)
end

--- Find substring in a UTF-8 string ignoring case and stress marks
--- Returns the START and END byte indices in the ORIGINAL string
--- @param s string Source string
--- @param query string Query string (unnormalized)
--- @return number, number Start and End indices
local function utf8_find_accent_blind(s, query)
    if not s or not query or query == "" then return nil end
    local q_clean = strip_accents(utf8_lower(query))
    if q_clean == "" then return nil end
    
    local s_lower = utf8_lower(s)
    local s_clean = strip_accents(s_lower)
    
    local start_c, end_c = s_clean:find(q_clean, 1, true)
    if not start_c then return nil end
    
    -- Map byte positions from s_clean back to s_lower
    local byte_map = {} 
    local clean_byte_idx = 1
    local i = 1
    local len = #s_lower
    
    while i <= len do
        local b = s_lower:byte(i)
        if b == 204 and (i < len and s_lower:byte(i+1) == 129) then
            i = i + 2 -- skip acute in mapping
        else
            local clen = 1
            if b >= 240 then clen = 4
            elseif b >= 224 then clen = 3
            elseif b >= 192 then clen = 2
            end
            
            for k = 0, clen - 1 do
                byte_map[clean_byte_idx + k] = i + k
            end
            
            i = i + clen
            clean_byte_idx = clean_byte_idx + clen
        end
    end
    
    local start_orig = byte_map[start_c]
    local end_orig = byte_map[end_c]
    
    if not start_orig or not end_orig then return nil end
    
    -- Include trailing stress marks in the final range
    while end_orig + 2 <= #s_lower do
        if s_lower:byte(end_orig + 1) == 204 and s_lower:byte(end_orig + 2) == 129 then
            end_orig = end_orig + 2
        else
            break
        end
    end
    
    return start_orig, end_orig
end

--- Capitalize first character of UTF-8 string
--- @param s string Input string
--- @return string String with first character capitalized
local function utf8_capitalize(s)
    if not s or s == "" then return "" end
    local b = s:byte(1)
    local seq_len = 1
    if b >= 240 then seq_len = 4
    elseif b >= 224 then seq_len = 3
    elseif b >= 192 then seq_len = 2
    end
    
    return utf8_upper(s:sub(1, seq_len)) .. s:sub(seq_len + 1)
end

--- Convert codepoint to UTF-8 string
local function utf8_char(cp)
    if not cp then return "" end
    if cp <= 127 then return string.char(cp) end
    local res = ""
    if cp <= 2047 then
        res = string.char(192 + math.floor(cp / 64)) .. string.char(128 + (cp % 64))
    elseif cp <= 65535 then
        res = string.char(224 + math.floor(cp / 4096)) .. string.char(128 + (math.floor(cp / 64) % 64)) .. string.char(128 + (cp % 64))
    elseif cp <= 1114111 then
        res = string.char(240 + math.floor(cp / 262144)) .. string.char(128 + (math.floor(cp / 4096) % 64)) .. string.char(128 + (math.floor(cp / 64) % 64)) .. string.char(128 + (cp % 64))
    end
    return res
end

--- Drawing primitive for acute accent (stress mark)
--- @param base_x number X position of character
--- @param base_y number Y position of character (top)
--- @param char_width number Width of character
--- @param char_height number Height of font
--- @param is_uppercase boolean Whether character is uppercase (for adaptive positioning)
function DRAW_WINDOW.draw_acute_accent_primitive(base_x, base_y, char_width, char_height, is_uppercase)
    -- Acute accent: two tilted lines side by side, right one is red
    local accent_height = char_height * 0.22 
    local left_line_thickness = 3 
    local right_line_thickness = 1 
    
    local center_x = base_x + (char_width / 2)
    
    local top_y
    if is_uppercase then
        top_y = base_y - (char_height * 0.20)
    else
        top_y = base_y - (char_height * 0.05)
    end
    
    local tilt_offset = char_width * 0.08 
    local bottom_y = top_y + accent_height
    local top_y_pos = top_y
    
    local orig_r, orig_g, orig_b, orig_a = gfx.r, gfx.g, gfx.b, gfx.a
    
    -- Left line (text color)
    local left_x_bottom = center_x - right_line_thickness
    local left_x_top = left_x_bottom + tilt_offset
    
    gfx.set(orig_r, orig_g, orig_b, orig_a)
    for t = 0, left_line_thickness - 1 do
        gfx.line(left_x_bottom + t, bottom_y, left_x_top + t, top_y_pos)
    end
    
    -- Right line (red)
    local right_x_bottom = center_x + 1.5
    local right_x_top = right_x_bottom + tilt_offset
    local right_bottom_y = bottom_y - (accent_height / 2)
    
    gfx.set(1.0, 0.0, 0.0, orig_a) -- red color for accent mark (obeying alpha)
    for t = 0, right_line_thickness - 1 do
        gfx.line(right_x_bottom + t, right_bottom_y, right_x_top + t, top_y_pos)
    end
    
    gfx.set(orig_r, orig_g, orig_b, orig_a)
end

--- Draw text string, automatically rendering manual stress marks where the combining acute accent (U+0301) is found.
--- @param text string The string to draw
--- @param use_all_caps boolean? Whether to force uppercase
local function draw_text_with_stress_marks(text, use_all_caps, use_stress_caps)
    if not text or text == "" then return end
    
    local d_text = text
    if use_all_caps then
        d_text = utf8_upper(text)
    end
    
    if not d_text:find(acute) then
        gfx.drawstr(d_text)
        return
    end
    
    local i = 1
    local len = #d_text
    while i <= len do
        local b = d_text:byte(i)
        local char_len = 1
        if b >= 240 then char_len = 4
        elseif b >= 224 then char_len = 3
        elseif b >= 192 then char_len = 2
        end
        
        local char_end = i + char_len - 1
        local next_char_start = char_end + 1
        
        local has_stress = false
        if next_char_start <= len then
            if d_text:byte(next_char_start) == 204 and d_text:byte(next_char_start+1) == 129 then
                has_stress = true
            end
        end
        
        local char_str = d_text:sub(i, char_end)
        if has_stress then
            if use_stress_caps and not use_all_caps then
                char_str = utf8_upper(char_str)
            end
            
            local w_base = gfx.measurestr(char_str)
            local h_base = gfx.texth
            local char_start_x = gfx.x
            local char_y = gfx.y
            
            gfx.drawstr(char_str)
            
            local is_uppercase = (char_str == utf8_upper(char_str))
            DRAW_WINDOW.draw_acute_accent_primitive(char_start_x, char_y, w_base, h_base, is_uppercase)
            
            i = next_char_start + 2
        else
            gfx.drawstr(char_str)
            i = next_char_start
        end
    end
end

local function apply_accent_caps(text)
    if not text or not text:find(acute) then return text end
    
    local d_text = text
    local i = 1
    local res = {}
    local len = #d_text
    while i <= len do
        local b = d_text:byte(i)
        local char_len = 1
        if b >= 240 then char_len = 4
        elseif b >= 224 then char_len = 3
        elseif b >= 192 then char_len = 2
        end
        
        local char_str = d_text:sub(i, i + char_len - 1)
        local next_char_start = i + char_len
        
        local has_stress = false
        if next_char_start <= len then
            if d_text:byte(next_char_start) == 204 and d_text:byte(next_char_start+1) == 129 then
                has_stress = true
            end
        end
        
        if has_stress then
            table.insert(res, utf8_upper(char_str))
            table.insert(res, acute)
            i = next_char_start + 2
        else
            table.insert(res, char_str)
            i = next_char_start
        end
    end
    return table.concat(res)
end

-- =============================================================================
-- DICT: User Dictionary module (reads from Subass_Dictionary data)
-- =============================================================================
local DICT = {
    selected_ids = {}, -- set: { [id] = true }
    dicts = {},        -- {id, name}
    cached_lookup = nil,
    last_update_ts = ""
}

-- Load persisted selection from project ExtState
function DICT.dict_load_selection()
    DICT.selected_ids = {}
    local _, raw = reaper.GetProjExtState(0, section_name, "selected_dict_ids")
    if raw and raw ~= "" then
        local decoded = STATS.json_decode(raw)
        if type(decoded) == "table" then
            for _, id in ipairs(decoded) do
                DICT.selected_ids[id] = true
            end
        end
    end
end
DICT.dict_load_selection()

function DICT.reload_if_project_changed()
    -- Detect project switch (state change count resets on new project)
    local current_proj_id = STATS.get_project_id and STATS.get_project_id() or reaper.GetProjectPath("")
    if DICT._proj_id ~= current_proj_id then
        DICT._proj_id = current_proj_id
        DICT.dict_load_selection()
        DICT.load() -- refresh dict list for this project
    end
end
DICT._proj_id = STATS.get_project_id and STATS.get_project_id() or reaper.GetProjectPath("")

function DICT.save_selected()
    local ids = {}
    for id in pairs(DICT.selected_ids) do table.insert(ids, id) end
    local ts = tostring(reaper.time_precise())
    reaper.SetProjExtState(0, section_name, "selected_dict_ids", STATS.json_encode(ids))
    reaper.SetProjExtState(0, section_name, "dict_last_update", ts)
    reaper.MarkProjectDirty(0)
    DICT.last_update_ts = ts
    -- Invalidate lookup cache
    DICT.cached_lookup = nil
    UTILS.invalidate_prompter_cache()
end

function DICT.is_selected(id)
    return DICT.selected_ids[id] == true
end

function DICT.toggle(id)
    if DICT.selected_ids[id] then
        DICT.selected_ids[id] = nil
    else
        DICT.selected_ids[id] = true
    end
    DICT.save_selected()
end

function DICT.auto_toggle_by_rules(filename)
    if not cfg.dict_auto_rules or #cfg.dict_auto_rules == 0 or not filename then return end
    local file_name = filename:match("[^\\/]+$") or filename
    file_name = utf8_lower(file_name)
    
    local changed = false
    for _, rule in ipairs(cfg.dict_auto_rules) do
        if rule.dict_id and rule.dict_id ~= "" and rule.terms and rule.terms ~= "" then
            -- Split terms by comma
            for term in rule.terms:gmatch("[^,]+") do
                -- Trim spaces
                term = term:match("^%s*(.-)%s*$")
                if term and term ~= "" then
                    if file_name:find(utf8_lower(term), 1, true) then
                        if not DICT.selected_ids[rule.dict_id] then
                            DICT.selected_ids[rule.dict_id] = true
                            changed = true
                        end
                    end
                end
            end
        end
    end
    if changed then
        DICT.save_selected()
    end
end

function DICT.load(dont_push)
    -- Resolve path relative to this script's location
    local script_path = ({reaper.get_action_context()})[2]
    local base_dir = script_path:match("^(.*[\\/])") or ""
    local dict_file = base_dir .. "dictionary/data/user_dictionaries.json"

    local f = io.open(dict_file, "r")
    if not f then DICT.dicts = {} return end
    local content = f:read("*a")
    f:close()

    DICT.dicts = {}
    local decoded = STATS.json_decode(content)
    if type(decoded) == "table" and type(decoded.dictionaries) == "table" then
        for _, d in ipairs(decoded.dictionaries) do
            if d.id and d.name then
                table.insert(DICT.dicts, { id = d.id, name = d.name, entries = d.entries or {} })
            end
        end
    end
    
    if not dont_push then
        local ts = tostring(reaper.time_precise())
        reaper.SetProjExtState(0, section_name, "dict_last_update", ts)
        DICT.last_update_ts = ts
    else
        DICT.last_update_ts = reaper.GetProjExtState(0, section_name, "dict_last_update")
    end
    -- Invalidate lookup cache
    DICT.cached_lookup = nil
    UTILS.invalidate_prompter_cache()
end

function DICT.check_sync()
    local external_ts = reaper.GetProjExtState(0, section_name, "dict_last_update")
    if external_ts ~= "" and external_ts ~= DICT.last_update_ts then
        DICT.load(true)
    end
end

DICT.load() -- populate dicts at startup

-- Build a flat lookup: { [word_lowercase] = {replacement, comment} } from all active dicts
function DICT.get_lookup_table()
    local current_ts = reaper.GetProjExtState(0, section_name, "dict_last_update")
    if DICT.cached_lookup and DICT.last_update_ts == current_ts then
        return DICT.cached_lookup
    end

    local lookup = {}
    DICT.max_words = 1
    for _, d in ipairs(DICT.dicts) do
        if DICT.is_selected(d.id) then
            for _, entry in ipairs(d.entries or {}) do
                local w = entry.word
                if w and w ~= "" then
                    local raw_comment = entry.comment and entry.comment:gsub("[\r\n]", ""):match("^%s*(.-)%s*$") or ""
                    local comment = (raw_comment ~= "")
                        and raw_comment
                        or (T("DICT_COMMENT_PROM_1") .. d.name .. T("DICT_COMMENT_PROM_2") .. w)
                    local repl = (entry.replacement and entry.replacement ~= "") and entry.replacement or w
                    local key = utf8_lower(w):gsub(acute, "")
                    lookup[key] = { replacement = repl, comment = comment }

                    local spaces = 0
                    for _ in key:gmatch(" ") do spaces = spaces + 1 end
                    if spaces + 1 > DICT.max_words then 
                        DICT.max_words = spaces + 1 
                    end
                end
            end
        end
    end
    
    DICT.cached_lookup = lookup
    DICT.last_update_ts = current_ts
    return lookup
end

function UTILS.apply_text_transforms(line_spans, no_assimilation)
    if not line_spans or line_spans.transformed then return line_spans end
    local current_spans = line_spans

    local function clone_span(span, overrides)
        local n = {}
        for k, v in pairs(span) do n[k] = v end
        if overrides then
            for k, v in pairs(overrides) do n[k] = v end
        end
        return n
    end

    -- 1. ASSIMILATION
    if cfg.text_assimilations and not no_assimilation then
        -- Правила асиміляції. Кожен запис: {паттерн, заміна [, умови]}
        -- Умови (необов'язковий 3-й елемент):
        --   not_word_start  = true  →  НЕ застосовувати якщо паттерн на самому початку слова
        --   word_start_only = true  →  застосовувати ЛИШЕ якщо паттерн на самому початку слова
        local rules = {
            -- 1. Найдовші ланцюжки та специфічні спрощення (4 та 3 літери)
            {"ться", "цця"},           -- робиться → робицця
            {"стськ", "сськ"},         -- туристський → туриський
            {"нтськ", "нськ"},         -- студентський → студенський
            {"нтст", "нст"},           -- студентство → студенство
            {"стці", "сці"},           -- хустці → хусці
            {"стч", "шч"},             -- (рідко: хвостчик)
            {"стд", "зд"},             -- шістдесят → шіздесят
            {"стс", "сс"},             -- шістсот → шіссот

            -- 2. Специфічні випадки дієслів та відмінювання (3 літери)
            {"шся", "сся"},            -- вмиваєшся → вмиваєсся
            {"чся", "цся"},            -- мучся → муцся
            {"шці", "сці"},            -- дошці → досці  [ш+ц' → с'ц']

            -- 3. Подвійні приголосні на межі (2 літери)
            {"жці", "зці"},            -- книжці → книзці  [ж+ц' → з'ц']
            {"чці", "цці"},            -- качці → кацці  [ч+ц' → ц':]
            {"тці", "цці"},            -- тітці → тіцці  [т+ц' → ц':]
            {"зж", "жж"},              -- зжати → жжати

            -- зш: позиційно залежне (правило УМ)
            --   початок слова: зш → шш  (зшити → шшити)  [ж → ш перед глухим ш]
            --   середина слова: зш → жш  (безшумний → бежшумний)
            {"зш", "шш", {word_start_only = true}},
            {"зш", "жш", {not_word_start = true}},

            {"сш", "шш", {not_word_start = true}},              -- сш → шш

            -- зч: позиційно залежне (правило УМ)
            --   початок слова: зч → шч  (зчепити → шчепити)  [з оглушується перед ч → с, + с→ш]
            --   середина слова: зч → жч  (безчинство → бежчинство)
            {"зч", "шч", {word_start_only = true}},
            {"зч", "жч", {not_word_start = true}},

            {"сч", "щ"},               -- сч → щ [шч]: козащина; Борищенко
            {"тч", "чч"},              -- вотчина → воччина  [т+ч → ч:]
            {"тш", "чш"},              -- багатший → багачший  [т+ш → чш]
            {"тц", "цц"},              -- коритце → корицце, братця → брацця  [т+ц → ц:]
            {"дч", "чч"},              -- відчепити → віч**ч**епити  (д→т→ч)
            {"дш", "чш"},              -- підшити → піч**ш**ити  [д→т→ч перед ш]
            {"тс", "ц"}               -- братство → брацтво  [т+с → ц]
        }
        local new_spans = {}
        local function process_text(text, span, orig_word)
            if text == "" then return end
            local b_pos, b_rule = nil, nil
            local l_text = utf8_lower(text)
            for _, r in ipairs(rules) do
                local p = l_text:find(r[1], 1, true)
                if p then
                    local skip = false
                    local guard = r[3]
                    if guard then
                        -- not_word_start: блокувати якщо паттерн на самому початку слова
                        if guard.not_word_start  and p == 1 then skip = true end
                        -- word_start_only: блокувати якщо паттерн НЕ на початку слова
                        if guard.word_start_only and p ~= 1 then skip = true end
                    end
                    if not skip and (not b_pos or p < b_pos) then b_pos, b_rule = p, r end
                end
            end
            if b_pos then
                local before = text:sub(1, b_pos - 1)
                local m_len = #b_rule[1]
                local original_match = text:sub(b_pos, b_pos + m_len - 1)
                local remainder = text:sub(b_pos + m_len)
                local repl = b_rule[2]
                if original_match == utf8_upper(original_match) then repl = utf8_upper(repl)
                elseif original_match == utf8_capitalize(utf8_lower(original_match)) then repl = utf8_capitalize(repl) end
                
                if before ~= "" then table.insert(new_spans, clone_span(span, {text=before, orig_word=orig_word})) end
                table.insert(new_spans, clone_span(span, {text = repl, u=false, u_wave=true, orig_word=orig_word}))
                process_text(remainder, span, orig_word)
            else
                table.insert(new_spans, clone_span(span, {text=text, orig_word=orig_word}))
            end
        end
        for _, span in ipairs(current_spans) do
            local segments = UTILS.get_words_and_separators(span.text)
            for _, seg in ipairs(segments) do
                if seg.is_word and (not dict_modal.show) then process_text(seg.text, span, seg.text:gsub(acute, ""))
                else table.insert(new_spans, clone_span(span, {text=seg.text})) end
            end
        end
        current_spans = new_spans
    end

    -- 2. EUPHONICS (в/у та й/і чергування)
    if cfg.text_euphonics and not no_assimilation then
        local vowels_uk = {
            ["а"] = true, ["е"] = true, ["є"] = true, ["и"] = true, ["і"] = true,
            ["ї"] = true, ["о"] = true, ["у"] = true, ["ю"] = true, ["я"] = true,
            ["А"] = true, ["Е"] = true, ["Є"] = true, ["И"] = true, ["І"] = true,
            ["Ї"] = true, ["О"] = true, ["У"] = true, ["Ю"] = true, ["Я"] = true
        }
        -- 7th vowel apostrophe is not a letter, skip
        -- Helpers to get last / first visible char, ignoring spaces
        local function last_char(s)
            if not s or s == "" then return nil end
            local trimmed = s:match("^(.-)%s*$")
            if not trimmed or trimmed == "" then return nil end
            local offset = utf8.offset(trimmed, -1)
            if not offset then return nil end
            return trimmed:sub(offset)
        end

        local euph_spans = {}
        -- Pre-tokenize all spans into a flat list of segments to allow look-ahead
        local all_segments = {}
        for _, span in ipairs(current_spans) do
            local segs = UTILS.get_words_and_separators(span.text)
            for _, seg in ipairs(segs) do
                seg.span = span -- Keep reference for cloning properties
                table.insert(all_segments, seg)
            end
        end

        local function is_vowel(char)
            if not char then return false end
            local low_char = utf8_lower(char)
            return vowels_uk[low_char] == true or low_char:match("[aeiouy]") ~= nil
        end

        local function get_first_char(s)
            if not s or s == "" then return nil end
            local trimmed = s:match("^%s*(.-)$")
            if not trimmed or trimmed == "" then return nil end
            local off = utf8.offset(trimmed, 2)
            if off then return trimmed:sub(1, off - 1) end
            return trimmed
        end

        local prev_char = nil
        local has_pause = true -- Start of subtitle is a pause
        local has_hard_pause = true -- Start of subtitle is a hard pause
        local prev_after_vowel = false

        for i, seg in ipairs(all_segments) do
            if seg.is_word then
                local w = seg.text
                local low = utf8_lower(w)
                local changed = nil

                -- Look ahead for the next word's first character
                local next_char = nil
                local next_word_low = nil
                local followed_by_hard_pause = false
                for j = i + 1, #all_segments do
                    local s = all_segments[j]
                    local c = get_first_char(s.text)
                    if c then 
                        next_char = utf8_lower(c)
                        next_word_low = utf8_lower(s.text)
                        -- Detect if this next thing is a hard pause (before any word)
                        if next_char:match("[%.'!%?%+=%*#]") or next_char == "—" or next_char == ":" then
                            followed_by_hard_pause = true
                        end
                        break 
                    end
                end

                local prev_is_vowel = is_vowel(prev_char)
                local next_is_vowel = is_vowel(next_char)
                local next_is_consonant = next_char and not next_is_vowel
                
                local is_heavy_cluster = false
                if next_word_low and next_char then
                    if next_word_low:match("^в") or next_word_low:match("^ф") or 
                       next_word_low:match("^льв") or next_word_low:match("^св") or 
                       next_word_low:match("^тв") or next_word_low:match("^зв") or 
                       next_word_low:match("^хв") or next_word_low:match("^ст") or
                       next_word_low:match("^сх") or next_word_low:match("^сп") or
                       next_word_low:match("^ск") or
                       next_word_low:match("^v") or next_word_low:match("^w") then
                        is_heavy_cluster = true
                    end
                    -- General: any 2-consonant cluster at start (тр, кр, пр, гр, бр, etc.)
                    if not is_heavy_cluster and next_is_consonant then
                        local c2 = get_first_char(next_word_low:sub(#next_char + 1))
                        if c2 and not is_vowel(c2) then is_heavy_cluster = true end
                    end
                end

                -- Ukrainian Euphonics Rules (Refined Phonetic Awareness)
                if low == "в" then
                    -- MANDATORY 'у' before heavy clusters (в, ф, льв, св, зв, хв, тв, ст)
                    -- OR standard rule: between consonants / start of sentence
                    if is_heavy_cluster then
                        changed = "у"
                    elseif next_is_consonant and (not prev_is_vowel or has_hard_pause) and not followed_by_hard_pause then
                        changed = "у"
                    end
                elseif low == "у" then
                    -- Use 'в' between vowels or after vowel before consonant
                    -- BUT block it before heavy clusters
                    if prev_is_vowel and not has_hard_pause and (next_is_vowel or next_is_consonant) then
                        if is_heavy_cluster then
                            -- Block
                        else
                            changed = "в"
                        end
                    end
                elseif low == "і" or low == "й" then
                    -- Use 'й' after vowel or vowel-like [w] sound (trailing 'в' after vowel)
                    -- BUT avoid 'й' before і, я, ю, є, ї, й.
                    -- AND avoid triple 'і' by using 'та'.
                    local prev_is_vowel_like = prev_is_vowel or (prev_char == "в" and prev_after_vowel)
                    local next_is_glide = next_char and string.find("іяюєїй", utf8_lower(next_char), 1, true)
                    
                    if prev_char == "і" and next_char == "і" then
                        changed = "та"
                    elseif low == "і" then
                        if prev_is_vowel_like and not has_hard_pause and (next_is_vowel or next_is_consonant) and not next_is_glide then
                            changed = "й"
                        end
                    elseif low == "й" then
                        if not prev_is_vowel_like or has_hard_pause or next_is_glide then
                            changed = "і"
                        end
                    end
                elseif low == "з" or low == "із" or low == "зі" then
                    local next_is_vowel = is_vowel(next_char)
                    local next_is_sibilant = next_char and string.find("сзшжчщц", utf8_lower(next_char), 1, true)
                    local prev_is_vowel_like = (is_vowel(prev_char) or (prev_char == "в" and prev_after_vowel)) and not has_hard_pause
                    
                    local next_starts_with_cluster = false
                    if next_word_low then
                        local first = get_first_char(next_word_low)
                        if first then
                            local second = get_first_char(next_word_low:sub(#first + 1))
                            if second and not is_vowel(first) and not is_vowel(second) then
                                next_starts_with_cluster = true
                            end
                        end
                    end

                    local next_is_sibilant_cluster = next_starts_with_cluster and next_is_sibilant
                    local next_is_manual_cluster = next_word_low and (
                        (next_char == "м" and next_starts_with_cluster) or
                        next_word_low:match("^льв") or 
                        next_word_low:match("^вс")
                    )
                    
                    if next_is_sibilant_cluster or next_is_manual_cluster then
                        changed = "зі"
                    elseif next_is_sibilant or (not prev_is_vowel_like and not next_is_vowel and next_char) then
                        changed = "із"
                    else
                        changed = "з"
                    end
                elseif low == "б" or low == "би" then
                    local prev_is_vowel_like = (is_vowel(prev_char) or (prev_char == "в" and prev_after_vowel)) and not has_hard_pause
                    -- Avoid 'б' before labials (б, п, в, ф, м) for easier pronunciation
                    local next_is_labial = next_char and string.find("бпвфм", utf8_lower(next_char), 1, true)
                    if prev_is_vowel_like and not next_is_labial then
                        changed = "б"
                    else
                        changed = "би"
                    end
                end

                if changed and changed ~= low then
                    if w == utf8_upper(w) then changed = utf8_upper(changed) end
                    table.insert(euph_spans, clone_span(seg.span, {text = changed, orig_word = w, u = false, u_wave = true}))
                else
                    table.insert(euph_spans, clone_span(seg.span, {text = w}))
                end
                
                -- Update context from the word (phonetic and pause)
                local last_was_vowel = false
                for _, cp in utf8.codes(w) do
                    local c = utf8.char(cp)
                    local low_c = utf8_lower(c)
                    if low_c:match("[%a\128-\255]") then
                        prev_after_vowel = (low_c == "в" and last_was_vowel)
                        prev_char = low_c
                        last_was_vowel = is_vowel(low_c)
                        has_pause = false
                        has_hard_pause = false
                    elseif low_c:match("[%.,;!%?%(%)%-\"%+=%*#%[%]]") or low_c == "—" or low_c == ":" then
                        has_pause = true
                        if low_c:match("[%.'!%?%+=%*#%[%]]") or low_c == "—" or low_c == ":" then
                            has_hard_pause = true
                        end
                    end
                end
            else
                -- Separator (spaces, punctuation)
                table.insert(euph_spans, clone_span(seg.span, {text = seg.text}))
                for _, cp in utf8.codes(seg.text) do
                    local c = utf8.char(cp)
                    local low_c = utf8_lower(c)
                    if low_c:match("[%.,;!%?%(%)%-\"%+=%*#%[%]]") or low_c == "—" or low_c == ":" then
                        has_pause = true
                        if low_c:match("[%.'!%?%+=%*#%[%]]") or low_c == "—" or low_c == ":" then
                            has_hard_pause = true
                        end
                    elseif not low_c:match("%s") then
                        prev_after_vowel = false
                        prev_char = low_c
                        has_pause = false
                        has_hard_pause = false
                    end
                end
            end
            
            if seg.is_newline then
                has_pause = false
                has_hard_pause = false
            end
        end
        current_spans = euph_spans
    end

    -- 3. DICTIONARY
    local dict_lookup = DICT.get_lookup_table()
    local has_dict = next(dict_lookup) ~= nil
    if has_dict then
        local max_dict_words = DICT.max_words or 1
        
        -- Build a flat word list across all spans
        local word_list = {}
        for i, span in ipairs(current_spans) do
            span.segments = UTILS.get_words_and_separators(span.text)
            for j, seg in ipairs(span.segments) do
                if seg.is_word then
                    table.insert(word_list, {
                        span = span,
                        span_idx = i,
                        seg = seg,
                        lower = utf8_lower(seg.text):gsub(acute, "")
                    })
                end
            end
        end

        local w_idx = 1
        while w_idx <= #word_list do
            local matched = false
            for len = math.min(max_dict_words, #word_list - w_idx + 1), 1, -1 do
                local phrase = {}
                for k = 0, len - 1 do
                    table.insert(phrase, word_list[w_idx + k].lower)
                end
                local key = table.concat(phrase, " ")
                local entry = dict_lookup[key]

                if entry then
                    local first_w = word_list[w_idx]
                    first_w.seg.replaced_with = entry.replacement or ""
                    first_w.seg.replaced_comment = entry.comment

                    local original_names = {}
                    for k = 0, len - 1 do
                        local item = word_list[w_idx + k].seg
                        table.insert(original_names, item.text)
                        if k > 0 then item.replaced_empty = true end
                    end
                    first_w.seg.orig_phrase = table.concat(original_names, " ")

                    w_idx = w_idx + len
                    matched = true
                    break
                end
            end
            if not matched then
                w_idx = w_idx + 1
            end
        end

        -- Reconstruct spans
        local dict_spans = {}
        for _, span in ipairs(current_spans) do
            local current_span_text = ""
            if span.segments then
                for _, seg in ipairs(span.segments) do
                    if seg.replaced_with then
                        if current_span_text ~= "" then
                            table.insert(dict_spans, clone_span(span, {text = current_span_text}))
                            current_span_text = ""
                        end
                        table.insert(dict_spans, clone_span(span, {
                            text = seg.replaced_with,
                            orig_word = seg.orig_phrase or seg.text,
                            comment = seg.replaced_comment,
                            u = false, u_wave = true
                        }))
                    elseif seg.replaced_empty then
                        if current_span_text ~= "" then
                            table.insert(dict_spans, clone_span(span, {text = current_span_text}))
                            current_span_text = ""
                        end
                    else
                        current_span_text = current_span_text .. seg.text
                    end
                end
            else
                current_span_text = span.text
            end

            if current_span_text ~= "" then
                table.insert(dict_spans, clone_span(span, {text = current_span_text}))
            elseif #dict_spans == 0 and span.is_link then
                -- Keep empty links if any (though usually segments handle this)
                table.insert(dict_spans, clone_span(span, {text = ""}))
            end
            span.segments = nil
        end
        current_spans = dict_spans
    end
    current_spans.transformed = true
    return current_spans
end

--- Strip HTML tags and entities
local function clean_html(html)
    if not html then return "" end
    -- Remove script and style blocks
    html = html:gsub("<script.-/script>", "")
    html = html:gsub("<style.-/style>", "")
    -- Simplest tag removal
    html = html:gsub("<[^>]+>", "")
    -- Common entities
    html = html:gsub("&nbsp;", " ")
    html = html:gsub("&quot;", "\"")
    html = html:gsub("&amp;", "&")
    html = html:gsub("&lt;", "<")
    html = html:gsub("&gt;", ">")
    -- Handle decimal entities &#1234;
    html = html:gsub("&#(%d+)%s*;", function(d) return utf8_char(tonumber(d)) end)
    -- Handle hex entities &#xABCD;
    html = html:gsub("&#x(%x+)%s*;", function(h) return utf8_char(tonumber(h, 16)) end)
    return html
end

--- Parse mixed text with <a> tags into segments
local function hex_to_rgb(hex)
    local h = hex:lower()
    -- Remap dark blues to lighter shades for dark background
    if h == "#000080" then return {0.4, 0.7, 1.0, 1} end -- Was Navy, now Light Blue
    if h == "#333399" then return {0.6, 0.7, 1.0, 1} end -- Was Dark Periwinkle, now Lighter
    
    hex = hex:gsub("#","")
    if #hex == 3 then
        local r = tonumber("0x"..hex:sub(1,1)..hex:sub(1,1))
        local g = tonumber("0x"..hex:sub(2,2)..hex:sub(2,2))
        local b = tonumber("0x"..hex:sub(3,3)..hex:sub(3,3))
        return {r/255, g/255, b/255, 1}
    elseif #hex == 6 then
        local r = tonumber("0x"..hex:sub(1,2))
        local g = tonumber("0x"..hex:sub(3,4))
        local b = tonumber("0x"..hex:sub(5,6))
        return {r/255, g/255, b/255, 1}
    end
    return nil
end

local function parse_html_to_spans(html, inherited)
    local segments = {}
    local remaining = html:gsub("%s+", " ")
    inherited = inherited or {}
    
    local tags = {
        { tag = "a",      pattern = "<a%s+([^>]-)>([^\0]-)</a>" },
        { tag = "span",   pattern = "<span%s+([^>]-)>([^\0]-)</span>" },
        { tag = "b",      pattern = "<b([^>]-)>([^\0]-)</b>" },
        { tag = "strong", pattern = "<strong([^>]-)>([^\0]-)</strong>" },
        { tag = "i",      pattern = "<i([^>]-)>([^\0]-)</i>" },
        { tag = "em",     pattern = "<em([^>]-)>([^\0]-)</em>" }
    }
    
    -- Fallback for tags without any attributes/spaces
    local tags_fallback = {
        { tag = "a",      pattern = "<a()>([^\0]-)</a>" },
        { tag = "span",   pattern = "<span()>([^\0]-)</span>" }
    }
    
    while #remaining > 0 do
        local best_start = 1000000
        local best_end = 0
        local chosen_tag = nil
        local chosen_attr = ""
        local chosen_text = ""
        
        for _, t in ipairs(tags) do
            local s, e, a, txt = remaining:find(t.pattern)
            if s and s < best_start then
                best_start = s
                best_end = e
                chosen_tag = t.tag
                chosen_attr = a or ""
                chosen_text = txt or ""
            end
        end
        
        for _, t in ipairs(tags_fallback) do
            local s, e, a, txt = remaining:find(t.pattern)
            if s and s < best_start then
                best_start = s
                best_end = e
                chosen_tag = t.tag
                chosen_attr = ""
                chosen_text = txt or ""
            end
        end
        
        if chosen_tag then
            -- Prefix
            local prefix = remaining:sub(1, best_start - 1)
            if #prefix > 0 then
                table.insert(segments, {
                    text = clean_html(prefix),
                    is_bold = inherited.is_bold,
                    is_italic = inherited.is_italic,
                    is_plain = inherited.is_plain,
                    color = inherited.color,
                    is_link = inherited.is_link,
                    word = inherited.word
                })
            end
            
            local next_inherited = {
                is_bold = inherited.is_bold,
                is_italic = inherited.is_italic,
                is_plain = inherited.is_plain,
                color = inherited.color,
                is_link = inherited.is_link,
                word = inherited.word
            }
            
            if chosen_tag == "a" then
                local word = chosen_attr:match('href=".-/([^/"]+)"') or chosen_text
                word = UTILS.url_decode(clean_html(word)):gsub("^%s+", ""):gsub("%s+$", "")
                next_inherited.is_link = true
                next_inherited.word = word
            elseif chosen_tag == "span" then
                local attr_lower = chosen_attr:lower()
                local is_plain_class = attr_lower:find('short%-interpret') or attr_lower:find('interpret') or 
                    attr_lower:find('remark') or attr_lower:find('gram') or 
                    attr_lower:find('info') or attr_lower:find('description') or
                    attr_lower:find('term') or attr_lower:find('note') or
                    attr_lower:find('interpret%-formula')
                
                if is_plain_class then next_inherited.is_plain = true end
                
                -- Extract color
                local color_hex = chosen_attr:match("[Cc][Oo][Ll][Oo][Rr]%s*:%s*(#[0-9a-fA-F]+)")
                if color_hex then
                    next_inherited.color = hex_to_rgb(color_hex)
                end
            elseif chosen_tag == "b" or chosen_tag == "strong" then
                next_inherited.is_bold = true
            elseif chosen_tag == "i" or chosen_tag == "em" then
                next_inherited.is_italic = true
                next_inherited.is_plain = true
            end
            
            local inner = parse_html_to_spans(chosen_text, next_inherited)
            for _, s in ipairs(inner) do table.insert(segments, s) end
            
            remaining = remaining:sub(best_end + 1)
        else
            table.insert(segments, {
                text = clean_html(remaining),
                is_bold = inherited.is_bold,
                is_italic = inherited.is_italic,
                is_plain = inherited.is_plain,
                color = inherited.color,
                is_link = inherited.is_link,
                word = inherited.word
            })
            remaining = ""
        end
    end
    
    -- Cleanup whitespace across segments and merge identical formats
    local merged = {}
    for _, seg in ipairs(segments) do
        -- Normalize fields
        seg.is_link = seg.is_link or false
        seg.is_plain = (seg.is_plain == true) -- Force boolean
        seg.is_bold = seg.is_bold or false
        seg.is_italic = seg.is_italic or false
        seg.word = seg.word or ""
        -- Color comparison logic needs to be careful with tables
        
        if #seg.text > 0 or seg.is_link then
            local last = merged[#merged]
            
            -- Helper to compare colors
            local colors_match = false
            if not last then
                 -- No last segment
            elseif not last.color and not seg.color then
                colors_match = true
            elseif last.color and seg.color then
                colors_match = (last.color[1] == seg.color[1] and 
                                last.color[2] == seg.color[2] and 
                                last.color[3] == seg.color[3])
            end

            local can_merge = last and 
                (last.is_link == seg.is_link) and 
                (last.is_plain == seg.is_plain) and 
                (last.is_bold == seg.is_bold) and
                (last.is_italic == seg.is_italic) and
                colors_match and
                (not seg.is_link or (last.word == seg.word))
           
            if can_merge then
                last.text = last.text .. seg.text
            else
                table.insert(merged, {
                    text = seg.text,
                    is_link = seg.is_link,
                    is_plain = seg.is_plain,
                    is_bold = seg.is_bold,
                    is_italic = seg.is_italic,
                    word = seg.word,
                    color = seg.color
                })
            end
        end
    end
    
    return merged
end

--- Parse a <table> HTML string into a grid object
local function parse_dictionary_table_html(table_html)
    local grid = {is_table = true, rows = {}}
    for row_attr, row_content in table_html:gmatch('<tr%s*([^>]-)>([^\0]-)</tr>') do
        local row_data = {
            cells = {},
            is_header = row_attr:find('column%-header') or row_attr:find('subgroup%-header')
        }
        for cell_attr, cell_html in row_content:gmatch('<t[dh]%s*([^>]-)>([^\0]-)</t[dh]>') do
            local colspan = tonumber(cell_attr:match('colspan="?(%d+)"?')) or 1
            local rowspan = tonumber(cell_attr:match('rowspan="?(%d+)"?')) or 1
            local is_cell_header = cell_attr:find('class="[^"]*header[^"]*"')
            
            -- Use rich text parsing for cell content to support colors/styles
            local segments = parse_html_to_spans(cell_html)
            
            -- Also keep a plain text version for debugging or fallback if needed
            local cleaned = clean_html(cell_html)
            cleaned = cleaned:gsub("%s+", " "):gsub("^%s+", ""):gsub("%s+$", "")
            
            table.insert(row_data.cells, {
                text = cleaned,
                segments = segments,
                colspan = colspan,
                rowspan = rowspan,
                is_cell_header = is_cell_header
            })
        end
        if #row_data.cells > 0 then 
            table.insert(grid.rows, row_data) 
        end
    end
    
    -- Calculate max logical columns
    local max_cols = 0
    if #grid.rows > 0 then
        for _, cell in ipairs(grid.rows[1].cells) do
            max_cols = max_cols + (cell.colspan or 1)
        end
        grid.cols = max_cols
        return grid
    end
    return nil
end

--- Parse dictionary definition from HTML
local function parse_dictionary_definition(html, category)
    if not html or html == "" then return nil end
    
    -- Detect "Word not found" page pattern
    if html:find("Словник%s+«.-»%s+не%s+містить%s+слова") or 
       html:find("відсутнє%s+для%s+цього%s+словника") then
        return {}
    end
    -- Clean up raw HTML from sidebar and ads globally
    html = html:gsub('<aside[^>]-class="column_sidebar"[^>]->.-</aside>', "")
    html = html:gsub('<div[^>]-class="ad%-wrapper.-"[^>]->.-</div>%s-</div>', "")
    html = html:gsub('<div[^>]-class="ad%-wrapper.-"[^>]->.-</div>', "")

    local lines = {}

    -- Helper to split by article-block
    local blocks = {}
    local last_pos = 1
    while true do
        local b_start, b_end = html:find('<div[^>]-class="article%-block"[^>]->', last_pos)
        if not b_start then break end
        
        local next_b_start = html:find('<div[^>]-class="article%-block"[^>]->', b_end + 1)
        local block_content
        if next_b_start then
            block_content = html:sub(b_start, next_b_start - 1)
            last_pos = next_b_start
        else
            block_content = html:sub(b_start)
            table.insert(blocks, block_content)
            break
        end
        table.insert(blocks, block_content)
    end
    
    if #blocks == 0 then
        -- Fallback: use whole HTML as one block if no article-block found (might happen for some pages)
        blocks = { html }
    end
    for _, block in ipairs(blocks) do
        if category == "Тлумачення" then
            -- Add separator BEFORE subsequent blocks
            if _ > 1 and #lines > 0 then table.insert(lines, { is_separator = true }) end
            
            -- 1. Header (Word + remarks)
            local header_html = block:match('<h2 [^>]-class="page__sub%-header"[^>]->([^\0]-)</h2>')
            if header_html then
                local rich = parse_html_to_spans(header_html)
                if #rich > 0 then
                   table.insert(lines, { segments = rich, indent = 0, is_header = true })
                end
            end

            -- Interpretation body: extract the entire article-block__body content
            local body = block:match('<div class="article%-block__body">([^\0]-)<footer') 
                      or block:match('<div class="article%-block__body">([^\0]-)</div>%s-</div>') -- More robust for nested divs
                      or block:match('<div class="article%-block__body">([^\0]-)$')
                      or block
            
            -- Remove "Приклади" button text which clutters the view
            body = body:gsub('<span[^>]-class="show%-examples_btn"[^>]->.-</span>', "")

            -- Aggressive Cleanup: Remove source info and additional blocks from body 
            -- to prevent them from leaking into the definitions as messy text.
            body = body:gsub("<div[^>]*class=['\"][^'\"]*source%-info[^'\"]*['\"][^>]*>[^\0]-</div>", "")
            body = body:gsub("<span[^>]*class=['\"][^'\"]*source%-info[^'\"]*['\"][^>]*>[^\0]-</span>", "")
            body = body:gsub("<a[^>]*class=['\"][^'\"]*source%-info[^'\"]*['\"][^>]*>[^\0]-</a>", "")
            body = body:gsub('<div[^>]-class="page__additional%-block"[^>]->.-</div>%s-</div>', "")
            body = body:gsub('<div[^>]-class="[^"]*section_watch%-also[^"]*"[^>]->.-</div>', "")

            -- SPLIT BODY BY INTERPRET BLOCKS robustly (to handle nested divs like examples)
            local items = {}
            local last_search_pos = 1
            while true do
                local s, e = body:find('<div [^>]-class="interpret.-"[^>]->', last_search_pos)
                if not s then break end
                
                local next_s = body:find('<div [^>]-class="interpret.-"[^>]->', e + 1)
                local content
                if next_s then
                    content = body:sub(e + 1, next_s - 1)
                    last_search_pos = next_s
                else
                    content = body:sub(e + 1)
                    table.insert(items, content)
                    break
                end
                table.insert(items, content)
            end

            for _, item in ipairs(items) do
               local rich = parse_html_to_spans(item)
                if #rich > 0 then
                    rich[1].text = "• " .. rich[1].text
                    table.insert(lines, { segments = rich, indent = 1, is_header = false }) 
                end
            end
        elseif category == "Словозміна" then
            -- 1. Header (Word + short interpret)
            local header_html = block:match('<h2 [^>]-class="page__sub%-header"[^>]->([^\0]-)</h2>')
            if header_html then
                -- Add " - " prefix to short-interpret span
                header_html = header_html:gsub('(<span[^>]-class="short%-interpret"[^>]->)', '%1 — ')
                local rich = parse_html_to_spans(header_html)

                if #rich > 0 then
                    table.insert(lines, { segments = rich, indent = 0, is_header = true })
                end
            end
           
            -- 3. All Tables in this block
            for table_html in block:gmatch('<table class="table">([^\0]-)</table>') do
                local grid = parse_dictionary_table_html(table_html)
                if grid then
                    table.insert(lines, grid)
                end
            end
        elseif category == "Синонімія" or category == "Фразеологія" then
            -- Add separator BEFORE subsequent blocks (if any lines were added in previous blocks)
            if _ > 1 and #lines > 0 then
                table.insert(lines, { is_separator = true })
            end
            
            -- 1. Header (Word + short interpret)
            local header_html = block:match('<h2 [^>]-class="page__sub%-header"[^>]->([^\0]-)</h2>')
            if header_html then
                -- Add "- " prefix to short-interpret span
                header_html = header_html:gsub('%s*(<span[^>]-class="short%-interpret"[^>]->)', '%1 — ')
                local rich = parse_html_to_spans(header_html)

                if #rich > 0 then
                    table.insert(lines, { segments = rich, indent = 0, is_header = true, block_idx = _ })
                end
            end
            -- 2. Indented items (synonyms or phrase interprets)
            for item in block:gmatch('<div [^>]-class="interpret.-"[^>]->([^\0]-)</div>') do
                local rich = parse_html_to_spans(item)
                if #rich > 0 then
                    rich[1].text = "• " .. rich[1].text
                    table.insert(lines, { segments = rich, indent = 1, is_header = false })
                end
            end
            
            for item in block:gmatch('<div [^>]-class="list%-item.-">([^\0]-)</div>') do
                local rich = parse_html_to_spans(item)
                if #rich > 0 then
                    rich[1].text = "• " .. rich[1].text
                    table.insert(lines, { segments = rich, indent = 1, is_header = false })
                end
            end
        elseif category == "Слововживання" then
            -- 1. Header (Word + short interpret)
            local header_html = block:match('<h2 [^>]-class="page__sub%-header"[^>]->([^\0]-)</h2>')
            if header_html then
                local rich = parse_html_to_spans(header_html)
                if #rich > 0 then
                   table.insert(lines, { segments = rich, indent = 0, is_header = true })
                end
            end

            -- Clean up source info manually on the whole block first
            -- Remove divs with source-info
            block = block:gsub("<div[^>]*class=['\"][^'\"]*source%-info[^'\"]*['\"][^>]*>[^\0]-</div>", "")
            -- Remove spans with source-info
            block = block:gsub("<span[^>]*class=['\"][^'\"]*source%-info[^'\"]*['\"][^>]*>[^\0]-</span>", "")
            -- Remove links with source-info (including source-info__link)
            block = block:gsub("<a[^>]*class=['\"][^'\"]*source%-info[^'\"]*['\"][^>]*>[^\0]-</a>", "")
            
            -- 2. Body (Content with colored spans)
            -- Use match to extract the body content
            local body = block:match('<div class="article%-block__body">([^\0]-)</div>%s-</div>') 
                      or block:match('<div class="article%-block__body">([^\0]-)</div>')
            if body then
                local pos = 1
                while true do
                    local t_start, t_end = body:find('<table.-</table>', pos)
                    if not t_start then
                        -- Remaining text
                        local rem = body:sub(pos)
                        if #rem > 0 then
                            -- Clean up extra newlines/spaces
                            local rich = parse_html_to_spans(rem)
                            if #rich > 0 then 
                                table.insert(lines, { segments = rich, indent = 1 }) 
                            end
                        end
                        break
                    end
                    
                    -- Text before table
                    if t_start > pos then
                        local pre = body:sub(pos, t_start - 1)
                        if pre:match("%S") then -- Only if meaningful text
                             local rich = parse_html_to_spans(pre)
                             if #rich > 0 then 
                                table.insert(lines, { segments = rich, indent = 1 }) 
                             end
                        end
                    end
                    
                    -- Table
                    local table_html = body:sub(t_start, t_end)
                    local grid = parse_dictionary_table_html(table_html)
                    if grid then
                        table.insert(lines, grid)
                        table.insert(lines, { segments = "" }) -- Spacing after table
                    end
                    
                    pos = t_end + 1
                end
            end

            if _ < #blocks then
                table.insert(lines, { is_separator = true })
            else
                table.insert(lines, { segments = "" })
            end
        end
    end
    
    -- Cleanup: Limit consecutive empty lines to max 2
    local cleaned_lines = {}
    local empty_count = 0
    
    local function is_item_empty(item)
        if type(item) ~= "table" then return false end
        if item.is_table then return false end -- Tables are content
        
        local segs = item.segments
        if not segs then return true end
        
        if type(segs) == "string" then 
            -- Remove NBSP (\194\160) and standard whitespace
            local s = segs:gsub("\194\160", ""):gsub("%s+", "")
            return s == ""
        end
        
        if type(segs) == "table" then
            if #segs == 0 then return true end
            for _, s in ipairs(segs) do
                if s.text then
                     -- Check for content after removing NBSP
                    local txt = s.text:gsub("\194\160", " ")
                    if txt:match("%S") then return false end
                end
            end
            return true
        end
        
        return false
    end
    
    -- Cleanup Phase
    for _, line in ipairs(lines) do
        -- Trim segments if it's a paragraph
        if type(line) == "table" and not line.is_table then
            if type(line.segments) == "string" then
                line.segments = line.segments:gsub("^%s+", ""):gsub("%s+$", "")
            elseif type(line.segments) == "table" then
                -- Trim start of first segment and end of last segment
                if #line.segments > 0 then
                    line.segments[1].text = line.segments[1].text:gsub("^%s+", "")
                    line.segments[#line.segments].text = line.segments[#line.segments].text:gsub("%s+$", "")
                end
            end
        end

        if is_item_empty(line) then
            if empty_count < 1 then -- Reduced to max 1 empty line
                table.insert(cleaned_lines, line)
                empty_count = empty_count + 1
            end
        else
            table.insert(cleaned_lines, line)
            empty_count = 0
        end
    end
    
    -- Remove trailing/leading empty lines
    while #cleaned_lines > 0 and is_item_empty(cleaned_lines[1]) do
        table.remove(cleaned_lines, 1)
    end
    while #cleaned_lines > 0 and is_item_empty(cleaned_lines[#cleaned_lines]) do
        table.remove(cleaned_lines)
    end
    
    -- 2. Handle "Watch Also" section (usually at the bottom of the page)
    -- This section is only relevant for Interpretation
    if category == "Тлумачення" then
        local watch_also = html:match('<div[^>]-class="[^"]*section_watch%-also[^"]*"[^>]->(.-)</div>%s-</div>')
                        or html:match('<div[^>]-class="[^"]*section_watch%-also[^"]*"[^>]->(.-)</div>%s-</div>%s-</div>') -- Handle potential wrapper depth
        if watch_also then
            -- Add separator if we already have content
            if #cleaned_lines > 0 then table.insert(cleaned_lines, { is_separator = true }) end
            
            -- Extract title (e.g. "Усталені словосполучення")
            local title = watch_also:match('<div[^>]-class="section%-header__title"[^>]->%s*(.-)%s*</div>') or "Дивіться також:"
            table.insert(cleaned_lines, { segments = parse_html_to_spans("<b>" .. title .. "</b>"), indent = 0, is_header = true })
            
            -- Extract list items from <li> tags
            for item in watch_also:gmatch('<li[^>]->(.-)</li>') do
                local rich = parse_html_to_spans(item)
                if #rich > 0 then
                    rich[1].text = "• " .. rich[1].text
                    table.insert(cleaned_lines, { segments = rich, indent = 1, is_header = false })
                end
            end
        end
    end

    if category == "Тлумачення" then
        ACHIEVEMENTS.add_stat("ach_3_definition", 1)
    elseif category == "Словозміна" then
        ACHIEVEMENTS.add_stat("ach_3_conjugation", 1)
    elseif category == "Синонімія" then
        ACHIEVEMENTS.add_stat("ach_3_synonyms", 1)
    elseif category == "Фразеологія" then
        ACHIEVEMENTS.add_stat("ach_3_idioms", 1)
    elseif category == "Слововживання" then
        ACHIEVEMENTS.add_stat("ach_3_word_usage", 1)
    end
    
    return cleaned_lines
end

--- Fetch combined dictionary data
--- Fetch a specific dictionary category (Lazy loading)
local function fetch_dictionary_category(word, display_name)
    local categories = {
        [T("GD_Interpretation")] = "Тлумачення",
        [T("GD_Conjugation")] = "Словозміна",
        [T("GD_Synonyms")] = "Синонімія",
        [T("GD_Idioms")] = "Фразеологія",
        [T("GD_Word_usage")] = "Слововживання"
    }
    
    local url_part = categories[display_name]
    if not url_part then return nil end
    
    local encoded = word
    if not word:find("%%") then encoded = UTILS.url_encode(word) end
    
    local url = "https://goroh.pp.ua/" .. UTILS.url_encode(url_part) .. "/" .. encoded
    
    -- Construct curl command
    -- Add User Agent to avoid 403 blocks
    -- Add --ssl-no-revoke for Windows compatibility
    -- Production: -s (silent) -S (show errors)
    local cmd = "curl -s -S -L --ssl-no-revoke -A \"Mozilla/5.0\" \"" .. url .. "\""
    -- Note: run_async_command handles OS specific wrapping / redirects
    
    run_async_command(cmd, function(html)
        -- Defensive check: Verify state integrity before indexing
        if type(dict_modal) ~= "table" or type(dict_modal.content) ~= "table" then
            if not dict_modal then reaper.ShowConsoleMsg("SUBASS_DICT_DEBUG: dict_modal is nil\n")
            elseif type(dict_modal.content) ~= "table" then reaper.ShowConsoleMsg("SUBASS_DICT_DEBUG: dict_modal.content is " .. type(dict_modal.content) .. "\n") end
            return 
        end
        
        -- Safe to proceed if types match
        if not display_name or type(display_name) ~= "string" then return end
        
        if html and html ~= "" then
            -- Detection of Cloudflare / Dictionary site errors (500, 502, 504 etc)
            if html:find("<title>goroh.pp.ua | 50") then
                if dict_modal.show then
                    dict_modal.content[display_name] = "ERR:SERVER_DOWN"
                end
                return
            end

            local parsed = parse_dictionary_definition(html, url_part)
            -- Update Modal Content via Closure
            if dict_modal.show then
                dict_modal.content[display_name] = parsed
            end
        else
            if dict_modal.show then
                dict_modal.content[display_name] = T("DICT_UNABLE_TO_LOAD_1")
            end
        end
    end)
    
    return T("LOADING_ELLIPSIS") -- Placeholder
end

--- Call AI API Asynchronously (delegates to subass_ai.py)
--- @param provider string AI Provider ("gemini" or "mistral")
--- @param key string API Key
--- @param prompt string Prompt text
--- @param final_callback function(status, body)
--- @param use_json_schema boolean|nil Use structured JSON output
local function ai_api_call_async(provider, key, prompt, final_callback, use_json_schema)
    if not key or key == "" then
        final_callback(0, "No API Key")
        return
    end

    -- Write prompt and key to temp files (avoids all shell-quoting issues)
    local is_win = reaper.GetOS():match("Win")
    local res_path = reaper.GetResourcePath()
    local temp_prompt = res_path .. "/subass_gemini_prompt.txt"
    local temp_key    = res_path .. "/subass_gemini_key.txt"
    if is_win then
        temp_prompt = temp_prompt:gsub("/", "\\")
        temp_key    = temp_key:gsub("/", "\\")
    end

    local fp = io.open(temp_prompt, "w")
    if fp then fp:write(prompt); fp:close()
    else final_callback(0, "Failed to write prompt file"); return end

    local fk = io.open(temp_key, "w")
    if fk then fk:write(key); fk:close()
    else final_callback(0, "Failed to write key file"); return end

    local source = debug.getinfo(1, 'S').source
    local script_dir = source:match([[^@?(.*[\\/])]]) or ""
    local py_script = script_dir .. "stats/subass_ai.py"
    local schema_flag = use_json_schema and " --json-schema" or ""

    local cmd
    if is_win then
        py_script = py_script:gsub("/", "\\")
        local py_exe = (OTHER.rec_state and OTHER.rec_state.python and OTHER.rec_state.python.executable) or "py -3"
        cmd = py_exe .. ' "' .. py_script .. '" --provider ' .. provider .. ' --key-file "' .. temp_key .. '" --prompt-file "' .. temp_prompt .. '"' .. schema_flag
    else
        cmd = 'python3 "' .. py_script .. '" --provider ' .. provider .. ' --key-file "' .. temp_key .. '" --prompt-file "' .. temp_prompt .. '"' .. schema_flag
    end

    run_async_command(cmd, function(output)
        os.remove(temp_prompt)
        os.remove(temp_key)
        if output and output ~= "" then
            local trimmed = output:gsub("^%s+", ""):gsub("%s+$", "")
            -- Catch: our "Error: ...", argparse "path: error: ...", and "usage: ..."
            if trimmed:match("^Error:") or trimmed:match(": error:") or trimmed:match("^usage:") or trimmed:match("subass_ai.py") then
                final_callback(0, trimmed)
            else
                -- Wrap in minimal Gemini JSON so gemini_extract_text works unchanged
                local escaped = trimmed:gsub("\\", "\\\\"):gsub('"', '\\"'):gsub("\n", "\\n"):gsub("\r", "")
                local wrapped = '{"candidates":[{"content":{"parts":[{"text":"' .. escaped .. '"}]}}]}'
                final_callback(200, wrapped)
            end
        else
            final_callback(0, "No output from subass_ai.py")
        end
    end)
end

--- Asynchronous call to ElevenLabs API to check key validity
--- @param key string API Key
--- @param callback function Callback function(status, body)
local function eleven_api_call_async(key, callback)
    if not key or key == "" then 
        callback(0, "No API Key")
        return 
    end

    local url = "https://api.elevenlabs.io/v1/user"
    local cmd
    if reaper.GetOS():match("Win") then
        cmd = 'curl -s -k --ssl-no-revoke -w "\\n%{http_code}" -X GET "' .. url .. '" -H "xi-api-key: ' .. key .. '"'
    else
        cmd = "curl -s -w '\\n%{http_code}' -X GET '" .. url .. "' -H 'xi-api-key: " .. key .. "'"
    end
    
    run_async_command(cmd, function(output)
        if output and output ~= "" then
            local lines = {}
            for line in output:gmatch("[^\r\n]+") do table.insert(lines, line) end
            local status = tonumber(lines[#lines]) or 0
            local body = ""
            for i = 1, #lines - 1 do body = body .. lines[i] .. "\n" end
            callback(status, body)
        else
            callback(0, "No output")
        end
    end)
end

--- Extract text from Gemini JSON response using patterns (Robust)
--- @param json string JSON response body
--- @return string|nil Parsed text content
local function gemini_extract_text(json)
    if not json then return nil end
    
    -- Find "text": "
    local start_pattern = '"text"%s*:%s*"'
    local s, e = json:find(start_pattern)
    if not e then return nil end
    
    local start_index = e + 1
    local len = #json
    local end_index = nil
    
    -- Scan for closing quote, ignoring escaped ones
    local i = start_index
    while i <= len do
        local char = json:sub(i, i)
        if char == '"' then
            -- Check if escaped by counting preceding backslashes
            local backslashes = 0
            local j = i - 1
            while j >= start_index and json:sub(j, j) == '\\' do
                backslashes = backslashes + 1
                j = j - 1
            end
            
            if backslashes % 2 == 0 then
                -- Even backslashes -> Not escaped -> Found end!
                end_index = i - 1
                break
            end
        end
        i = i + 1
    end
    
    if end_index then
        local content = json:sub(start_index, end_index)
        -- Unescape JSON string
        content = content:gsub('\\"', '"'):gsub('\\n', '\n'):gsub('\\r', ''):gsub('\\t', '\t'):gsub('\\\\', '\\')
        return content
    end
    
    return nil
end

--- Parse simple JSON array of strings: ["a", "b"]
--- Handles escaped quotes inside strings
local function parse_json_string_array(json_str)
    local results = {}
    if not json_str then return results end
    
    -- Simple state machine parser
    local pos = 1
    local len = #json_str
    
    while pos <= len do
        -- Find start of string
        local start_quote = json_str:find('"', pos)
        if not start_quote then break end
        
        -- Find end of string, skipping escaped quotes
        local current = start_quote + 1
        local str_content = nil
        while current <= len do
            local end_quote = json_str:find('"', current)
            if not end_quote then break end
            
            -- Check if escaped
            local preceding_backslashes = 0
            local check_idx = end_quote - 1
            while check_idx >= current and json_str:sub(check_idx, check_idx) == "\\" do
                preceding_backslashes = preceding_backslashes + 1
                check_idx = check_idx - 1
            end
            
            if preceding_backslashes % 2 == 0 then
                -- Even backslashes means the quote is NOT escaped (it terminates the string)
                str_content = json_str:sub(start_quote + 1, end_quote - 1)
                pos = end_quote + 1
                break
            else
                -- Odd backslashes means quote IS escaped, continue searching
                current = end_quote + 1
            end
        end
        
        if str_content then
            -- Unescape JSON string
            str_content = str_content:gsub('\\"', '"'):gsub('\\\\', '\\'):gsub('\\n', '\n'):gsub('\\r', ''):gsub('\\t', '\t')
            table.insert(results, str_content)
        else
            pos = start_quote + 1 -- Should not happen in valid JSON
        end
    end
    return results
end

--- Parse 1. 2. 3. format into a table (Legacy fallback)
--- @param text string Multiline text
--- @return table List of suggestions
local function parse_ai_suggestions(text)
    local results = {}
    for line in text:gmatch("[^\r\n]+") do
        local cleaned = line:match("^%d+%.%s*(.+)$") or line:match("^[^%d]+%s*(.+)$") or line
        cleaned = cleaned:gsub("^%s+", ""):gsub("%s+$", "")
        if #cleaned > 0 then
            table.insert(results, cleaned)
        end
    end
    return results
end

