--- Get text from system clipboard
--- @return string|nil Clipboard content or nil if unavailable
local function get_clipboard()
    if reaper.CF_GetClipboard then return reaper.CF_GetClipboard("") end

    if not sws_alert_shown then
        reaper.MB(T("NEED_SWS_FOR_COPY_F"), "Subass", 0)
        sws_alert_shown = true
    end
    local os_name = reaper.GetOS()
    if os_name:match("OSX") or os_name:match("macOS") then
        local f = io.popen("pbpaste", "r")
        if f then local c = f:read("*a"); f:close(); return c end
    else
        local f = io.popen('powershell.exe -command "Get-Clipboard"', "r")
        if f then local c = f:read("*a"); f:close(); return c end
    end
    return nil
end

--- Format seconds to timestamp string (HH:MM:SS.mmm or MM:SS.mmm)
--- @param seconds number Time in seconds
--- @return string Formatted timestamp
local function format_timestamp(seconds)
    local s = math.floor(seconds)
    local ms = math.floor((seconds - s) * 1000)
    
    local hours = math.floor(s / 3600)
    local minutes = math.floor((s % 3600) / 60)
    local secs = s % 60
    
    if hours > 0 then
        return string.format("%d:%02d:%02d.%03d", hours, minutes, secs, ms)
    else
        return string.format("%02d:%02d.%03d", minutes, secs, ms)
    end
end

--- Format seconds to simple timestamp string (HH:MM:SS or MM:SS) without milliseconds
--- @param seconds number Time in seconds
--- @return string Formatted timestamp
local function format_time_hms(seconds)
    local s = math.floor(seconds)
    local hours = math.floor(s / 3600)
    local minutes = math.floor((s % 3600) / 60)
    local secs = s % 60
    
    if hours > 0 then
        return string.format("%d:%02d:%02d", hours, minutes, secs)
    else
        return string.format("%02d:%02d", minutes, secs)
    end
end

-- =============================================================================
-- RICH TEXT PARSING
-- =============================================================================
-- Format: { {text="foo", b=true, i=false, u=false, s=false}, ... }
-- Supports splitting lines by \N or \n

--- Smart text wrapping at natural break points (with cache)
--- @param text string Text to wrap
--- @param max_length number Maximum line length
--- @return string Wrapped text
local wrap_cache = {}
local function wrap_long_text(text, max_length)
    if not text or text == "" then return "" end
    
    -- Check cache
    local cache_key = text .. "|" .. max_length
    if wrap_cache[cache_key] then return wrap_cache[cache_key] end

    -- Normalize existing newlines to \N for uniform processing
    local normalized_text = text:gsub("\n", "\\N"):gsub("\\n", "\\N")
    
    -- Tokenizer: tags, newlines, spaces, words
    local tokens = {}
    local cursor = 1
    while cursor <= #normalized_text do
        local token
        local nl_s, nl_e = normalized_text:find("^\\N", cursor)
        if nl_s then
            token = "\\N"
            cursor = nl_e + 1
        else
            local tag_s, tag_e = normalized_text:find("^{.-}", cursor)
            if tag_s == cursor then
                token = normalized_text:sub(tag_s, tag_e)
                cursor = tag_e + 1
            else
                local htm_s, htm_e = normalized_text:find("^<.->", cursor)
                if htm_s == cursor then
                    token = normalized_text:sub(htm_s, htm_e)
                    cursor = htm_e + 1
                else
                    local sp_s, sp_e = normalized_text:find("^%s+", cursor)
                    if sp_s == cursor then
                        token = normalized_text:sub(sp_s, sp_e)
                        cursor = sp_e + 1
                    else
                        -- Find word until next special char or space
                        local wd_s, wd_e = normalized_text:find("^[^%s{}<\\]+", cursor)
                        if wd_s then
                            token = normalized_text:sub(wd_s, wd_e)
                            cursor = wd_e + 1
                        else
                            -- Fallback for backslash or single special char
                            token = normalized_text:sub(cursor, cursor)
                            cursor = cursor + 1
                        end
                    end
                end
            end
        end
        if token then table.insert(tokens, token) end
    end

    local result = ""
    local current_line = ""
    local current_line_len = 0
    
    for _, t in ipairs(tokens) do
        if t == "\\N" then
            result = result .. (result == "" and "" or "\\N") .. current_line:gsub("%s+$", "")
            current_line = ""
            current_line_len = 0
        elseif t:find("^{") or t:find("^<") then
            -- Tags/Comments don't add to layout length
            current_line = current_line .. t
        elseif t:find("^%s+$") then
            -- Only count spaces if they aren't at the start of a line
            if current_line_len > 0 then
                current_line = current_line .. t
                current_line_len = current_line_len + (utf8.len(t) or #t)
            end
        else
            -- Word
            local w_len = utf8.len(t) or #t
            if current_line_len + w_len > max_length and current_line_len > 0 then
                -- Wrap
                result = result .. (result == "" and "" or "\\N") .. current_line:gsub("%s+$", "")
                current_line = t
                current_line_len = w_len
            else
                current_line = current_line .. t
                current_line_len = current_line_len + w_len
            end
        end
    end
    
    if current_line ~= "" then
        result = result .. (result == "" and "" or "\\N") .. current_line:gsub("%s+$", "")
    end

    if #wrap_cache > 100 then wrap_cache = {} end
    wrap_cache[cache_key] = result
    
    return result
end

--- Merge two comments with dash prefixes and newline separation
--- @param old string|nil Previous comment
--- @param new string Current comment
--- @return string Merged comment
local function merge_comments(old, new)
    if not new or new == "" then return old end
    local s2 = new:gsub("^%s+", ""):gsub("%s+$", "")
    if s2 == "" then return old end
    
    if not old or old == "" then return s2 end
    local s1 = old:gsub("^%s+", ""):gsub("%s+$", "")
    
    if not s1:match("^%-") then s1 = "-" .. s1 end
    if not s2:match("^%-") then s2 = "-" .. s2 end
    
    return s1 .. "\n" .. s2
end

local function parse_prompter_to_lines(str, skip_transforms)
    -- Remove double-brace comments {{...}} completely from display
    if str:find("{{") then
        str = str:gsub("{{", "\1"):gsub("}}", "\2")
        str = str:gsub("%b\1\2", "\3") -- Use \3 as placeholder for removed comment
        
        -- Remove lines that ONLY contain placeholders and whitespace to avoid empty lines
        str = str:gsub("\n[\3%s]*\3[\3%s]*\n", "\n")
        str = str:gsub("^[\3%s]*\3[\3%s]*\n", "")
        str = str:gsub("\n[\3%s]*\3[\3%s]*$", "")
        str = str:gsub("^[\3%s]*\3[\3%s]*$", "")
        
        -- Remove any remaining placeholders and restore unmatched braces
        str = str:gsub("\3", "")
        str = str:gsub("\1", "{{"):gsub("\2", "}}")
    end

    local all_spans = {}
    
    local state = {b=false, i=false, u=false, s=false}
    local cursor = 1
    local pending_comment = nil
    local global_comment = nil
    local has_text = false
    
    -- Normalize/Flatten newlines before wrapping if soft mode is enabled
    if cfg.p_soft_n then
        str = str:gsub("\\n", " "):gsub("\n", " "):gsub("\\N", " ")
    end

    -- Wrap long text (configurable max length)
    str = wrap_long_text(str, cfg.wrap_length)
    
    -- Final normalization for non-soft mode or any remaining \n
    if not cfg.p_soft_n then
        str = str:gsub("\\n", "\\N"):gsub("\n", "\\N")
    end
    
    while cursor <= #str do
        -- Check for tag start '{', HTML '<', or newline '\N'
        local tag_start = str:find("[{<\\]", cursor)
        
        if not tag_start then
            -- Rest is text
            local remainder = str:sub(cursor)
            if remainder ~= "" then
                if pending_comment or global_comment then
                    local word_end = remainder:find("%s")
                    if word_end and word_end < #remainder then
                        local word = remainder:sub(1, word_end - 1)
                        local rest = remainder:sub(word_end)
                        table.insert(all_spans, {text=word, b=state.b, i=state.i, u=state.u, s=state.s, comment=pending_comment or global_comment})
                        table.insert(all_spans, {text=rest, b=state.b, i=state.i, u=state.u, s=state.s, comment=global_comment})
                    else
                        table.insert(all_spans, {text=remainder, b=state.b, i=state.i, u=state.u, s=state.s, comment=pending_comment or global_comment})
                    end
                    pending_comment = nil
                else
                    table.insert(all_spans, {text=remainder, b=state.b, i=state.i, u=state.u, s=state.s})
                end
                has_text = true
            end
            break
        end
        
        -- Append text before tag
        if tag_start > cursor then
            local segment = str:sub(cursor, tag_start - 1)
            if pending_comment or global_comment then
                local word_end = segment:find("%s")
                if word_end and word_end < #segment then
                    local word = segment:sub(1, word_end - 1)
                    local rest = segment:sub(word_end)
                    table.insert(all_spans, {text=word, b=state.b, i=state.i, u=state.u, s=state.s, comment=pending_comment or global_comment})
                    table.insert(all_spans, {text=rest, b=state.b, i=state.i, u=state.u, s=state.s, comment=global_comment})
                else
                    table.insert(all_spans, {text=segment, b=state.b, i=state.i, u=state.u, s=state.s, comment=pending_comment or global_comment})
                end
                pending_comment = nil
            else
                table.insert(all_spans, {text=segment, b=state.b, i=state.i, u=state.u, s=state.s})
            end
            if segment:find("%S") then has_text = true end
        end
        
        -- Handle Newline
        if str:sub(tag_start, tag_start+1) == "\\N" then
            table.insert(all_spans, {text=" ", is_newline = true, b=state.b, i=state.i, u=state.u, s=state.s})
            cursor = tag_start + 2
            
        elseif str:sub(tag_start, tag_start) == "{" then
            -- Handle ASS Tag or Comment
            local tag_end = str:find("}", tag_start)
            if tag_end then
                local content = str:sub(tag_start+1, tag_end-1)
                
                local is_formatting = false
                -- Parse supported tags: \b1, \b0, \i1, \u1, \s1
                for tag in content:gmatch("\\[bius]%d") do
                    local t = tag:sub(2,2)
                    local v = (tag:sub(3,3) == "1")
                    if t == "b" then state.b = v
                    elseif t == "i" then state.i = v
                    elseif t == "u" then state.u = v
                    elseif t == "s" then state.s = v
                    end
                    is_formatting = true
                end
                
                -- Check for other formatting tags (starting with backslash)
                if not is_formatting and content:find("^\\") then
                    is_formatting = true
                end
                
                if not is_formatting and content ~= "" then
                    content = content:gsub("^%s+", ""):gsub("%s+$", "") -- Trim
                    
                    -- Rule: If preceded by a newline, make it global. Otherwise, word-specific.
                    local is_after_newline = (#all_spans > 0 and all_spans[#all_spans].is_newline)
                    
                    if not has_text or is_after_newline then
                        global_comment = merge_comments(global_comment, content)
                    elseif #all_spans > 0 then
                        -- Word-specific (attach to last word only)
                        local last_span = all_spans[#all_spans]
                        if last_span.comment then
                            last_span.comment = merge_comments(last_span.comment, content)
                        else
                            local text = last_span.text
                            local word_start = text:find("[^%s]+%s*$")
                            if word_start and word_start > 1 then
                                local prefix = text:sub(1, word_start - 1)
                                local word = text:sub(word_start)
                                last_span.text = prefix
                                table.insert(all_spans, {
                                    text = word, b=last_span.b, i=last_span.i, u=last_span.u, s=last_span.s, 
                                    comment = content
                                })
                            else
                                last_span.comment = content
                            end
                        end
                    else
                        pending_comment = merge_comments(pending_comment, content)
                    end
                end
                
                cursor = tag_end + 1
            else
                -- Broken tag
                table.insert(all_spans, {text="{", b=state.b, i=state.i, u=state.u, s=state.s})
                cursor = tag_start + 1
            end
            
        elseif str:sub(tag_start, tag_start) == "<" then
            -- Handle HTML Tag
            local tag_end = str:find(">", tag_start)
            if tag_end then
                local content = str:sub(tag_start+1, tag_end-1):lower()
                local tag_found = true
                if content == "b" then state.b = true
                elseif content == "/b" then state.b = false
                elseif content == "i" then state.i = true
                elseif content == "/i" then state.i = false
                elseif content == "u" then state.u = true
                elseif content == "/u" then state.u = false
                elseif content == "s" then state.s = true
                elseif content == "/s" then state.s = false
                else
                    tag_found = false
                end
                
                if tag_found then
                    cursor = tag_end + 1
                else
                    -- Treat as text
                    local segment = str:sub(tag_start, tag_end)
                    table.insert(all_spans, {text=segment, b=state.b, i=state.i, u=state.u, s=state.s})
                    if segment:find("%S") then has_text = true end
                    cursor = tag_end + 1
                end
            else
                -- Broken tag, treat as text
                table.insert(all_spans, {text="<", b=state.b, i=state.i, u=state.u, s=state.s})
                cursor = tag_start + 1
            end
        else
            -- Should not happen unless pattern matches backslash alone not followed by N?
            -- Treat as text
            table.insert(all_spans, {text=str:sub(tag_start, tag_start), b=state.b, i=state.i, u=state.u, s=state.s})
            cursor = tag_start + 1
        end
    end
    
    -- Final loop result check is now handled by the split-back-into-lines block
    
    -- Final Pass: Apply global_comment to all spans that don't have a specific comment
    if global_comment then
        for _, span in ipairs(all_spans) do
            if not span.comment then
                span.comment = global_comment
            end
        end
    end
    
    -- Apply block-level transformations (euphonics/assimilation)
    all_spans = UTILS.apply_text_transforms(all_spans, skip_transforms)
    
    -- Split back into lines based on is_newline markers
    local lines = {}
    local current_line = {}
    for _, span in ipairs(all_spans) do
        if span.is_newline then
            table.insert(lines, current_line)
            current_line = {}
        else
            table.insert(current_line, span)
        end
    end
    table.insert(lines, current_line)
    
    -- Mark all lines as already transformed
    for _, line in ipairs(lines) do
        line.transformed = true
    end
    
    return lines
end

-- Serialization Helpers
local function serialize_table(val, name, skipnewlines, depth)
    skipnewlines = skipnewlines or false
    depth = depth or 0
    local tmp = string.rep(" ", depth)
    if name then tmp = tmp .. name .. " = " end
    if type(val) == "table" then
        tmp = tmp .. "{" .. (not skipnewlines and "\n" or "")
        for k, v in pairs(val) do
            tmp =  tmp .. serialize_table(v, k, skipnewlines, depth + 1) .. "," .. (not skipnewlines and "\n" or "")
        end
        tmp = tmp .. string.rep(" ", depth) .. "}"
    elseif type(val) == "number" then
        tmp = tmp .. tostring(val)
    elseif type(val) == "string" then
        tmp = tmp .. string.format("%q", val)
    elseif type(val) == "boolean" then
        tmp = tmp .. (val and "true" or "false")
    else
        tmp = tmp .. "\"[inserializeable datatype:" .. type(val) .. "]\""
    end
    return tmp
end

-- =============================================================================
-- PROJECT DATA PERSISTENCE
-- =============================================================================

--- Save subtitle data to project extended state
local function save_project_data()
    -- CRITICAL SAFETY: Never save data while a project is being loaded or switched.
    -- This prevents race conditions from overwriting valid project state with empty/interim data.
    if UI_STATE.is_loading then return end

    -- Chunked saving to avoid project state limits (usually ~64KB per key)
    -- We use a safer limit of 16KB to prevent truncation in some REAPER versions
    local CHUNK_SIZE = 16000 
    
    local function save_chunked(base_key, data_tbl)
        local full_str = table.concat(data_tbl)
        local len = #full_str
        local chunks = math.ceil(len / CHUNK_SIZE)
        
        -- Store total chunk count
        reaper.SetProjExtState(0, section_name, base_key .. "_count", tostring(chunks))
        
        for i = 1, chunks do
            local start_p = (i - 1) * CHUNK_SIZE + 1
            local end_p = math.min(i * CHUNK_SIZE, len)
            local chunk = full_str:sub(start_p, end_p)
            reaper.SetProjExtState(0, section_name, base_key .. "_chunk_" .. i, chunk)
        end
        
        -- Legacy fallback (first chunk only)
        reaper.SetProjExtState(0, section_name, base_key, full_str:sub(1, CHUNK_SIZE))
    end

    -- Prepare lines data
    local dump_tbl = {}
    for i, l in ipairs(ass_lines) do
        local en = (l.enabled == nil or l.enabled) and "1" or "0"
        local r_idx = l.rgn_idx or -1
        local index = l.index or i
        local meta_json = l.metadata and STATS.json_encode(l.metadata):gsub("\n", "") or ""
        -- Escape | as !ђ∆! to prevent column misalignment and conflict with ASS tags like \pos
        local escaped_text = l.text:gsub("|", "!ђ∆!"):gsub("\n","\\n")
        table.insert(dump_tbl, string.format("%.3f|%.3f|%s|%s|%d|%d|%s|%s\n", l.t1, l.t2, l.actor, en, r_idx, index, escaped_text, meta_json))
    end
    save_chunked("ass_lines", dump_tbl)
    
    local act_tbl = {}
    for k,v in pairs(ass_actors) do
        table.insert(act_tbl, k .. "|" .. (v and "1" or "0") .. "\n")
    end
    reaper.SetProjExtState(0, section_name, "ass_actors", table.concat(act_tbl))
    
    reaper.SetProjExtState(0, section_name, "dir_actors", table.concat(director_actors, "|"))
    
    if director_state.region_actor_to_dubber then
        local json_m = STATS.json_encode(director_state.region_actor_to_dubber):gsub("\n", "")
        reaper.SetProjExtState(0, section_name, "dir_actors_region_mapping", json_m)
    end
    
    local col_tbl = {}
    for k,v in pairs(ASS.actor_colors) do
        table.insert(col_tbl, k .. "|" .. tostring(v) .. "\n")
    end
    reaper.SetProjExtState(0, section_name, "actor_colors", table.concat(col_tbl))

    reaper.SetProjExtState(0, section_name, "ass_loaded", UI_STATE.ass_file_loaded and "1" or "0")
    if UI_STATE.current_file_name then
        reaper.SetProjExtState(0, section_name, "ass_fname", UI_STATE.current_file_name)
    end

    -- Save ASS Headers/Styles
    if ASS.ass_header_order and #ASS.ass_header_order > 0 then
        local header_data = {
            order = ASS.ass_header_order,
            sections = ASS.ass_header_sections,
            events_header = ASS.ass_events_header_lines,
            format_order = ASS.ass_format_order
        }
        local json_h = STATS.json_encode(header_data)
        save_chunked("ass_headers", {json_h})
    else
        reaper.SetProjExtState(0, section_name, "ass_headers_count", "0")
    end
    
    -- Track edit in statistics
    STATS.increment_edit()

    local mark_tbl = {}
    for _, m in ipairs(ass_markers) do
        table.insert(mark_tbl, string.format("%.3f|%s|%d|%d\n", m.pos, m.name:gsub("\n", "\\n"), m.markindex, m.color))
    end
    save_chunked("ass_markers", mark_tbl)
    
    -- Signal change to external scripts (Overlay)
    reaper.gmem_write(101, (reaper.gmem_read(101) or 0) + 1)
end

--- Ensure all ass_lines have unique numeric indices
local function sanitize_indices()
    if not ass_lines then return end
    local used = {}
    local next_id = 1
    
    -- First pass: find max used numeric index to avoid collisions
    for _, l in ipairs(ass_lines) do
        if type(l.index) == "number" and l.index >= next_id then
            next_id = l.index + 1
        end
    end
    
    -- Second pass: fix missing or duplicate indices
    for _, l in ipairs(ass_lines) do
        if not l.index or type(l.index) ~= "number" or used[l.index] then
            l.index = next_id
            next_id = next_id + 1
        end
        used[l.index] = true
    end
end

--- Load director actors from ProjectExtState
local function load_director_actors_from_state()
    local okD, d_dump = reaper.GetProjExtState(0, section_name, "dir_actors")
    if okD and d_dump ~= "" then
        director_actors = {}
        for act in d_dump:gmatch("([^|]+)") do
            table.insert(director_actors, act)
        end
    else
        director_actors = {}
    end
end

--- Add actors to director_actors list if not already present
--- @param new_actors table|string Table of actor names or string containing [Actor] prefix
local function ensure_director_actors(new_actors)
    if not new_actors then return end
    local actors_to_add = {}
    
    if type(new_actors) == "string" then
        -- Extract from [Name] or [Name 1, Name 2] at the start of string
        local bracket_content = new_actors:match("^%[([^%]]+)%]")
        if bracket_content then
            for name in bracket_content:gmatch("[^,]+") do
                name = name:match("^%s*(.-)%s*$") -- Trim
                if name ~= "" then table.insert(actors_to_add, name) end
            end
        end
    elseif type(new_actors) == "table" then
        actors_to_add = new_actors
    end
    
    local changed = false
    local existing = {}
    for _, a in ipairs(director_actors) do existing[a] = true end
    
    for _, name in ipairs(actors_to_add) do
        if name and name ~= "" and not existing[name] then
            table.insert(director_actors, name)
            existing[name] = true
            changed = true
        end
    end
    
    if changed then
        -- Sort actors alphabetically for better UI
        table.sort(director_actors)
        save_project_data()
    end
end

--- Load project data from ProjectExtState
local function load_project_data()
    UI_STATE.is_loading = true
    -- ALWAYS reset state first
    ass_lines = {}
    
    -- Reset temporary session takes for ach_12 (King of the Hill)
    if STATS and STATS.etc then STATS.etc.replica_takes = {} end
    ass_actors = {}
    ASS.actor_colors = {}
    ass_markers = {} -- Added explicit reset
    ASS.ass_header_sections = {}
    ASS.ass_header_order = {}
    ASS.ass_events_header_lines = {}
    ASS.ass_format_order = {}
    UI_STATE.ass_file_loaded = false
    UI_STATE.current_file_name = nil
    
    local ok, loaded = reaper.GetProjExtState(0, section_name, "ass_loaded")
    
    if not ok or loaded ~= "1" then
        -- NEW PROJECT: No data loaded -> Switch to File tab
        UI_STATE.current_tab = 1
    end

    if ok and loaded == "1" then
        UI_STATE.ass_file_loaded = true
        
        local okF, fname = reaper.GetProjExtState(0, section_name, "ass_fname")
        if okF then UI_STATE.current_file_name = fname end
        
        -- Load chunked lines
        local l_dump = ""
        local okC, count_str = reaper.GetProjExtState(0, section_name, "ass_lines_count")
        if okC and count_str ~= "" then
            local count = tonumber(count_str) or 0
            for i = 1, count do
                local okX, chunk = reaper.GetProjExtState(0, section_name, "ass_lines_chunk_" .. i)
                if okX then l_dump = l_dump .. chunk end
            end
        else
            -- Legacy fallback
            local okL, legacy_dump = reaper.GetProjExtState(0, section_name, "ass_lines")
            if okL then l_dump = legacy_dump end
        end

        if l_dump ~= "" then
            for line in l_dump:gmatch("([^\n]*)\n?") do
                if line ~= "" then
                    local matched = false
                    
                    -- 1. Try metadata format (8 fields): t1|t2|actor|enabled|rgn_idx|index|text|metadata
                    local t1, t2, act, en, r_idx, idx, txt, meta = line:match("^(.-)|(.-)|(.-)|(.-)|(.-)|(.-)|(.-)|(.*)$")
                    if t1 and meta then
                        table.insert(ass_lines, {
                            t1 = tonumber(t1),
                            t2 = tonumber(t2),
                            actor = act,
                            enabled = (en == "1"),
                            rgn_idx = tonumber(r_idx),
                            index = tonumber(idx),
                            text = txt:gsub("!ђ∆!", "|"):gsub("\\n", "\n"),
                            metadata = (meta ~= "" and STATS.json_decode(meta) or nil)
                        })
                        matched = true
                    end

                    -- 2. Try intermediate format (7 fields): t1|t2|actor|enabled|rgn_idx|index|text
                    if not matched then
                        local t1, t2, act, en, r_idx, idx, txt = line:match("^(.-)|(.-)|(.-)|(.-)|(.-)|(.-)|(.*)$")
                        if t1 and idx then
                            table.insert(ass_lines, {
                                t1 = tonumber(t1),
                                t2 = tonumber(t2),
                                actor = act,
                                enabled = (en == "1"),
                                rgn_idx = tonumber(r_idx),
                                index = tonumber(idx),
                                text = txt:gsub("!ђ∆!", "|"):gsub("\\n", "\n")
                            })
                            matched = true
                        end
                    end

                    -- 3. Try previous sync format (6 fields): t1|t2|actor|enabled|rgn_idx|text
                    if not matched then
                        local t1, t2, act, en, r_idx, txt = line:match("^(.-)|(.-)|(.-)|(.-)|(.-)|(.*)$")
                        if t1 and r_idx then
                            table.insert(ass_lines, {
                                t1 = tonumber(t1),
                                t2 = tonumber(t2),
                                actor = act,
                                enabled = (en == "1"),
                                rgn_idx = tonumber(r_idx),
                                text = txt:gsub("!ђ∆!", "|"):gsub("\\n", "\n")
                            })
                            matched = true
                        end
                    end

                    -- 4. Try older format (5 fields): t1|t2|actor|enabled|text
                    if not matched then
                        local t1, t2, act, en, txt = line:match("^(.-)|(.-)|(.-)|(.-)|(.*)$")
                        if t1 and en then
                            table.insert(ass_lines, {
                                t1 = tonumber(t1),
                                t2 = tonumber(t2),
                                actor = act,
                                enabled = (en == "1"),
                                text = txt:gsub("!ђ∆!", "|"):gsub("\\n", "\n")
                            })
                            matched = true
                        end
                    end

                    -- 5. Fallback: very old format (4 fields): t1|t2|actor|text
                    if not matched then
                        local t1, t2, act, txt = line:match("^(.-)|(.-)|(.-)|(.*)$")
                        if t1 then
                            table.insert(ass_lines, {
                                t1 = tonumber(t1),
                                t2 = tonumber(t2),
                                actor = act,
                                enabled = true,
                                text = txt:gsub("\\n", "\n")
                            })
                        end
                    end
                end
            end
        end

        local ok3, a_dump = reaper.GetProjExtState(0, section_name, "ass_actors")
        if ok3 then
            for line in a_dump:gmatch("([^\n]*)\n?") do
                if line ~= "" then
                    local act, val = line:match("^(.-)|(.*)$")
                    if act then
                        ass_actors[act] = (val == "1")
                    end
                end
            end
        end
        
        -- Load chunked markers
        local m_dump = ""
        local okMC, m_count_str = reaper.GetProjExtState(0, section_name, "ass_markers_count")
        if okMC and m_count_str ~= "" then
            local count = tonumber(m_count_str) or 0
            for i = 1, count do
                local okX, chunk = reaper.GetProjExtState(0, section_name, "ass_markers_chunk_" .. i)
                if okX then m_dump = m_dump .. chunk end
            end
        else
            local okML, m_legacy = reaper.GetProjExtState(0, section_name, "ass_markers")
            if okML then m_dump = m_legacy end
        end

        if m_dump ~= "" then
            ass_markers = {} -- Reset before populating
            for line in m_dump:gmatch("([^\n]*)\n?") do
                if line ~= "" then
                    local pos, name, midx, col = line:match("^(.-)|(.-)|(.-)|(.*)$")
                    if pos and name then
                        table.insert(ass_markers, {
                            pos = tonumber(pos),
                            name = name:gsub("\\n", "\n"),
                            markindex = tonumber(midx) or 0,
                            color = tonumber(col) or 0
                        })
                    end
                end
            end
        end
        
        load_director_actors_from_state()
        
        local okM, m_dump = reaper.GetProjExtState(0, section_name, "dir_actors_region_mapping")
        if okM and m_dump ~= "" then
            local success, result = pcall(function() return STATS.json_decode(m_dump) end)
            if success and type(result) == "table" then
                director_state.region_actor_to_dubber = result
            end
        end
        
        local ok4, c_dump = reaper.GetProjExtState(0, section_name, "actor_colors")
        if ok4 then
            for line in c_dump:gmatch("([^\n]*)\n?") do
                if line ~= "" then
                    local act, col_str = line:match("^(.-)|(.*)$")
                    if act and col_str then
                      ASS.actor_colors[act] = tonumber(col_str)
                    end
                end
            end
        end
    end
    
    -- Load ASS Headers
    local h_dump = ""
    local okHC, h_count_str = reaper.GetProjExtState(0, section_name, "ass_headers_count")
    if okHC and h_count_str ~= "" then
        local count = tonumber(h_count_str) or 0
        for i = 1, count do
            local okX, chunk = reaper.GetProjExtState(0, section_name, "ass_headers_chunk_" .. i)
            if okX then h_dump = h_dump .. chunk end
        end
    end
    if h_dump ~= "" then
        local success, h_data = pcall(function() return STATS.json_decode(h_dump) end)
        if success and type(h_data) == "table" then
            ASS.ass_header_order = h_data.order or {}
            ASS.ass_header_sections = h_data.sections or {}
            ASS.ass_events_header_lines = h_data.events_header or {}
            ASS.ass_format_order = h_data.format_order or {}
        end
    end

    STATS.update_metadata()
    UI_STATE.is_loading = false
end

-- LOAD DATA ON STARTUP
load_project_data()
sanitize_indices()

-- =============================================================================
-- REAPER REGIONS MANAGEMENT
-- =============================================================================

-- Helper: Unique Random Color per Actor
--- Get consistent color for an actor. Uses a batch assignment strategy:
--- on first call for an unknown actor, assigns colors to ALL actors at once
--- in alphabetical order from a curated 16-color palette + golden-ratio fallback.
--- @param actor string Actor name
--- @return number Native color integer
local function get_actor_color(actor)
    if not actor or actor == "" or not cfg.random_color_actors then return 0 end

    -- 1. Fast path: already has a color
    if ASS.actor_colors[actor] then
        return ASS.actor_colors[actor]
    end

    -- 2. Apply global user-defined colors first
    if OTHER.global_actor_colors[actor] then
        ASS.actor_colors[actor] = OTHER.global_actor_colors[actor]
        return ASS.actor_colors[actor]
    end

    -- 3. Batch assign colors to ALL unknown actors at once
    local need_color = {}
    local need_set = {}
    local function check_actor(a)
        if OTHER.global_actor_colors[a] then
            ASS.actor_colors[a] = OTHER.global_actor_colors[a]
        elseif not ASS.actor_colors[a] and not need_set[a] then
            table.insert(need_color, a)
            need_set[a] = true
        end
    end

    if ass_actors then
        for a in pairs(ass_actors) do check_actor(a) end
    end
    check_actor(actor)
    table.sort(need_color) -- alphabetical for determinism

    -- Curated palette: 16 vivid hues ~22.5° apart
    local PALETTE = {
        {220,  60,  60},  -- 1  red        0°
        {220, 140,  50},  -- 2  orange    30°
        {210, 200,  50},  -- 3  yellow    55°
        {130, 210,  50},  -- 4  lime      90°
        { 50, 200,  80},  -- 5  green    112°
        { 50, 210, 160},  -- 6  mint     160°
        { 50, 200, 210},  -- 7  cyan     185°
        { 50, 140, 220},  -- 8  sky      210°
        { 60,  70, 220},  -- 9  blue     240°
        {110,  60, 220},  -- 10 indigo   263°
        {175,  60, 220},  -- 11 violet   285°
        {220,  60, 200},  -- 12 magenta  308°
        {220,  60, 130},  -- 13 rose     332°
        {180, 120,  60},  -- 14 tan      27°
        { 90, 180, 210},  -- 15 sky-blue 197°
        {210, 170, 100},  -- 16 gold     38°
    }

    -- Helpers (circular hue distance, RGB→hue, hue via native round-trip)
    local function hue_dist(a, b)
        local d = math.abs(a - b); return d > 0.5 and (1.0 - d) or d
    end
    local function rgb_to_hue(r, g, b)
        r, g, b = r/255, g/255, b/255
        local mx = math.max(r,g,b); local mn = math.min(r,g,b); local d = mx-mn
        if d < 0.001 then return 0 end
        local h
        if     mx == r then h = ((g-b)/d) % 6
        elseif mx == g then h = (b-r)/d + 2
        else                h = (r-g)/d + 4
        end
        return h/6
    end
    -- HSL → RGB (standard formula, h in 0-1)
    local function hsl_to_rgb(h, s, l)
        local function f(n)
            local k = (n + h*12) % 12
            return l - s*math.max(-1, math.min(k-3, 9-k, 1)) * math.min(l, 1-l)
        end
        return math.floor(f(0)*255+0.5), math.floor(f(8)*255+0.5), math.floor(f(4)*255+0.5)
    end

    local HUE_THRESHOLD = 0.08  -- ~29° — enough spacing between 16 slots

    -- Assign colors one by one in alphabetical order
    for _, a in ipairs(need_color) do
        if ASS.actor_colors[a] then goto continue end  -- assigned by earlier batch step

        -- Collect true visual hues already in use
        local used_hues = {}
        for _, col in pairs(ASS.actor_colors) do
            local cr, cg, cb = reaper.ColorFromNative(col & 0xFFFFFF)
            table.insert(used_hues, rgb_to_hue(cr, cg, cb))
        end

        -- Try palette in order
        local br, bg, bb
        for _, rgb in ipairs(PALETTE) do
            local ph = rgb_to_hue(rgb[1], rgb[2], rgb[3])
            local taken = false
            for _, uh in ipairs(used_hues) do
                if hue_dist(ph, uh) < HUE_THRESHOLD then taken = true; break end
            end
            if not taken then br, bg, bb = rgb[1], rgb[2], rgb[3]; break end
        end

        -- Fallback: golden-ratio gap-fill
        if not br then
            local best_hue, best_dist = 0, -1
            local offset = (#used_hues * 0.6180339887) % 1.0
            for i = 0, 127 do
                local h = (offset + i * 0.6180339887) % 1.0
                local md = 1.0
                for _, uh in ipairs(used_hues) do
                    local d = hue_dist(h, uh); if d < md then md = d end
                end
                if md > best_dist then best_dist = md; best_hue = h end
            end
            local s = 0.72; local l = 0.50
            br, bg, bb = hsl_to_rgb(best_hue, s, l)
        end

        br = math.max(40, math.min(220, br))
        bg = math.max(40, math.min(220, bg))
        bb = math.max(40, math.min(220, bb))
        ASS.actor_colors[a] = reaper.ColorToNative(br, bg, bb) | 0x1000000

        ::continue::
    end

    return ASS.actor_colors[actor] or (reaper.ColorToNative(128,128,128) | 0x1000000)
end

--- Sync ass_actors with current ass_lines (Remove actors with 0 replicas)
--- Identify used actors and remove unused ones from list
local function cleanup_actors()
    if not ass_lines then return end
    
    if editor_state and editor_state.sort_cache then
        editor_state.sort_cache.valid = false
    end
    
    local current_actors = {}
    for _, line in ipairs(ass_lines) do
        if line.actor then
            current_actors[line.actor] = true
            -- Ensure it exists in ass_actors
            if ass_actors[line.actor] == nil then
                ass_actors[line.actor] = true
            end
        end
    end
    
    -- Remove actors from ass_actors if they are no longer in any line
    -- AND remove from actor_colors if needed
    for act in pairs(ass_actors) do
        if not current_actors[act] then
            ass_actors[act] = nil
            if ASS.actor_colors then ASS.actor_colors[act] = nil end
        end
    end

    ACHIEVEMENTS.check_high_actor_count_ach_17()
end

--- Find the highest current region index and return next available
local function get_next_line_index()
    if not ass_lines then return 1 end
    local max_idx = 0
    for _, l in ipairs(ass_lines) do
        if l.index and l.index > max_idx then max_idx = l.index end
    end
    return max_idx + 1
end

--- Check if a replica with same actor, timing and text already exists
--- @param actor string Actor name
--- @param t1 number Start time
--- @param t2 number End time
--- @param text string Replica text
--- @param metadata table|nil Metadata table (optional)
--- @return boolean True if duplicate found
local function is_duplicate_replica(actor, t1, t2, text, metadata)
    if not ass_lines then return false end
    for _, l in ipairs(ass_lines) do
        -- Compare with small epsilon for timing
        if l.actor == actor and 
           math.abs(l.t1 - t1) < 0.005 and 
           math.abs(l.t2 - t2) < 0.005 and 
           l.text == text then
            
            -- If metadata is provided, all fields must match
            if metadata and l.metadata then
                local all_match = true
                -- Check all fields in incoming metadata
                for k, v in pairs(metadata) do
                    if l.metadata[k] ~= v then
                        all_match = false
                        break
                    end
                end
                -- Also check if existing line has extra fields
                if all_match then
                    for k, v in pairs(l.metadata) do
                        if metadata[k] ~= v then
                            all_match = false
                            break
                        end
                    end
                end
                
                if all_match then return true end
            elseif not metadata and not (l.metadata and next(l.metadata)) then
                -- Both lack metadata (or existing as an empty table)
                return true
            elseif not metadata or not (l.metadata and next(l.metadata)) then
                -- One has metadata and the other doesn't -> not a duplicate
                -- (We allow empty metadata tables to count as "no metadata")
            end
        end
    end
    return false
end

local function capture_project_markers()
    local markers = {}
    local i = 0
    while true do
        local retval, isrgn, pos, rgnend, name, markindex, color = reaper.EnumProjectMarkers3(0, i)
        if retval == 0 then break end
        if not isrgn then
            table.insert(markers, {
                pos = pos,
                name = name,
                markindex = markindex,
                color = color
            })
        end
        i = i + 1
    end
    return markers
end

local function update_regions_cache()
    regions = {}
    local retval, num_markers, num_regions = reaper.CountProjectMarkers(0)
    local i = 0
    local rgn_map = {}
    while true do
        local retval, isrgn, pos, rgnend, name, idx, color = reaper.EnumProjectMarkers3(0, i)
        if retval == 0 then break end
        if isrgn then
            local rgn_obj = {idx = idx, pos = pos, rgnend = rgnend, name = name, rgn_index = i, actor = "", color = color}
            table.insert(regions, rgn_obj)
            rgn_map[idx] = rgn_obj
        end
        i = i + 1
    end
    
    -- Sync internal ass_lines with actual project regions
    if ass_lines and #ass_lines >= 0 then
        local changed = false
        local tracked_rgn_idxs = {}
        local lines_to_remove = {}
        
        -- 1. Sync existing tracked lines and check for deletions
        for i, line in ipairs(ass_lines) do
            if line.enabled == false then goto skip_sync end
            if line.rgn_idx then
                if tracked_rgn_idxs[line.rgn_idx] then
                    -- DUPLICATE ID: Another line already uses this region ID. 
                    -- Unlink this one so it can find its own region in orphan pass.
                    line.rgn_idx = nil
                    changed = true
                else
                    local rgn = rgn_map[line.rgn_idx]
                    if rgn then
                        rgn.actor = line.actor
                        -- Update times if changed in REAPER
                        if math.abs(line.t1 - rgn.pos) > 0.0001 or math.abs(line.t2 - rgn.rgnend) > 0.0001 or (line.text ~= rgn.name and rgn.name ~= T("EMPTY")) then
                            line.t1 = rgn.pos
                            line.t2 = rgn.rgnend
                            line.text = rgn.name
                            changed = true
                        end
                        tracked_rgn_idxs[line.rgn_idx] = true
                    else
                        -- Region ID is gone from project.
                        -- UNLINK instead of DELETE to prevent data loss on transient ID issues.
                        line.rgn_idx = nil
                        changed = true
                    end
                end
            end
            ::skip_sync::
        end
        
        -- 1.5. Try to RE-BIND orphans to available regions match by Time AND TEXT
        for i, line in ipairs(ass_lines) do
            if not line.rgn_idx and line.enabled ~= false then
                for idx, rgn in pairs(rgn_map) do
                    if not tracked_rgn_idxs[idx] then
                        -- Strict Time Match (approx 1ms tolerance)
                        if math.abs(line.t1 - rgn.pos) < 0.001 and math.abs(line.t2 - rgn.rgnend) < 0.001 then
                            -- Also check text to minimize wrong actor binding if times are identical
                            if UTILS.compare_sub_text(line.text, rgn.name) then 
                                line.rgn_idx = idx
                                rgn.actor = line.actor
                                tracked_rgn_idxs[idx] = true
                                changed = true
                                break 
                            end
                        end
                    end
                end
            end
        end
        
        -- 2. Adopt "foreign" regions (created manually in REAPER)
        local is_empty_project = (#ass_lines == 0)
        
        -- SAFETY LOCK: If still loading project data, skip adoption logic to prevent overwriting correct state
        -- with 'REAPER' actor names in case of a race condition or transient failure.
        if is_empty_project and UI_STATE.is_loading then
            return
        end
        
        for idx, rgn in pairs(rgn_map) do
            if not tracked_rgn_idxs[idx] then
                -- This is a new region! Adopt it.
                if not UI_STATE.ass_file_loaded then UI_STATE.ass_file_loaded = true end
                
                -- Determine Actor name based on color, OR just "REAPER" if lines already exist
                local actor_name = "REAPER"
                
                -- Only assign color-based names if we are importing a fresh project (ass_lines is empty)
                -- Otherwise, any new / restored regions just go to a default "REAPER" actor to avoid hex scatter on Ctrl+Z
                if is_empty_project and rgn.color and rgn.color ~= 0 then
                    -- Extract RGB from BGR color (REAPER uses 0x1BBGGRR format where 1 is a flag)
                    -- For EnumProjectMarkers3, color is native (BGR)
                    local r = (rgn.color & 0xFF)
                    local g = (rgn.color >> 8) & 0xFF
                    local b = (rgn.color >> 16) & 0xFF
                    actor_name = string.format("REAPER_%02X%02X%02X", r, g, b)
                end

                local new_line = {
                    t1 = rgn.pos,
                    t2 = rgn.rgnend,
                    text = rgn.name,
                    actor = actor_name,
                    enabled = true,
                    index = get_next_line_index(),
                    rgn_idx = rgn.idx
                }
                table.insert(ass_lines, new_line)
                if ass_actors[actor_name] == nil then 
                    ass_actors[actor_name] = true 
                    -- Register color in global actor_colors
                    local color_to_save = rgn.color
                    if not color_to_save or color_to_save == 0 then
                        color_to_save = reaper.GetThemeColor("region", 0)
                    end
                    
                    if color_to_save then
                        -- Ensure 0x1000000 bit is set for consistency with get_actor_color
                        if (color_to_save & 0x1000000) == 0 then
                            color_to_save = color_to_save | 0x1000000
                        end
                        -- Only pre-seed if we don't already have a color for this actor.
                        -- This prevents overwriting a palette color that was just generated.
                        if not ASS.actor_colors[actor_name] then
                            ASS.actor_colors[actor_name] = color_to_save
                        end
                    end
                end
                changed = true
                tracked_rgn_idxs[idx] = true -- Don't adopt twice
                rgn.actor = actor_name
            end
        end
        
        if changed then
            UI_STATE._markers_is_dirty = true
            cleanup_actors()
            save_project_data()
        end

        -- Sync markers (non-regions)
        ass_markers = capture_project_markers()
    end
end

-- --- INTERNAL UNDO HISTORY ---
local undo_stack = {}
local redo_stack = {}
local max_undo_depth = 20

local function deep_copy_table(t)
    if type(t) ~= 'table' then return t end
    local res = {}
    for k, v in pairs(t) do
        res[deep_copy_table(k)] = deep_copy_table(v)
    end
    return res
end

local function rebuild_regions()
    reaper.PreventUIRefresh(1)
    reaper.Undo_BeginBlock()
    
    -- Clear all tracked region indices for ass_lines before rebuild
    if ass_lines then
        for _, line in ipairs(ass_lines) do
            line.rgn_idx = nil
        end
    end
    
    -- Fast Delete: Repeatedly delete the first marker until none remain.
    local safety_cnt = 0
    local max_markers = reaper.CountProjectMarkers(0) + 10 -- Add Buffer
    while true do
        local retval, isrgn, pos, rgnend, name, idx = reaper.EnumProjectMarkers(0)
        if not retval or retval == 0 then break end
        reaper.DeleteProjectMarker(0, idx, isrgn)
        
        safety_cnt = safety_cnt + 1
        if safety_cnt > max_markers then 
            -- ERROR: Something is not being deleted. Break to prevent freeze.
            break 
        end 
    end
    
    -- Add from ass_lines if line is enabled
    local count = 0
    local last_t1, last_t2, last_text = -1, -1, ""
    for i, line in ipairs(ass_lines) do
        if line.enabled ~= false then -- Default true if nil
            local col = get_actor_color(line.actor)
            if col == 0 and cfg.random_color_actors then
                col = get_actor_color(line.actor) 
            end
            
            -- Force uniqueness for REAPER by adding a 10ms epsilon to identical overlapping regions
            local t1, t2 = line.t1, line.t2
            if math.abs(t1 - last_t1) < 0.001 and math.abs(t2 - last_t2) < 0.001 and line.text == last_text then
                t2 = t2 + 0.001
            end
            
            local rgn_idx = reaper.AddProjectMarker2(0, true, t1, t2, line.text, -1, col)
            line.rgn_idx = rgn_idx
            
            last_t1, last_t2, last_text = t1, t2, line.text
            count = count + 1
        end
    end
    
    -- Sync back markers (non-regions) from ass_markers
    for _, m in ipairs(ass_markers) do
        reaper.AddProjectMarker2(0, false, m.pos, 0, m.name, m.markindex, m.color)
    end
    
    reaper.Undo_EndBlock("Update Synced Regions", -1)
    reaper.PreventUIRefresh(-1)
    reaper.UpdateArrange()

    update_regions_cache() -- Update cache immediately execution
    save_project_data() -- SAVE ON CHANGE
    STATS.update_metadata()
end

local function push_undo(label)
    if not ass_lines then return end
    
    -- Capture markers from project
    ass_markers = capture_project_markers()
    
    -- Capture state
    local state = {
        lines = deep_copy_table(ass_lines),
        actors = deep_copy_table(ass_actors),
        dubbers = deep_copy_table(DUBBERS.data),
        dir_actors = deep_copy_table(director_actors),
        markers = deep_copy_table(ass_markers),
        label = label or "Action"
    }
    
    table.insert(undo_stack, state)
    if #undo_stack > max_undo_depth then
        table.remove(undo_stack, 1)
    end
    
    -- Clear redo stack on new action
    redo_stack = {}
end

local function undo_action()
    if #undo_stack == 0 then return end
    
    -- Capture current state to redo stack before restoring
    local current_state = {
        lines = deep_copy_table(ass_lines),
        actors = deep_copy_table(ass_actors),
        dubbers = deep_copy_table(DUBBERS.data),
        dir_actors = deep_copy_table(director_actors),
        markers = capture_project_markers(),
        label = undo_stack[#undo_stack].label
    }
    
    local last_state = table.remove(undo_stack)
    
    table.insert(redo_stack, current_state)
    if #redo_stack > max_undo_depth then
        table.remove(redo_stack, 1)
    end

    ass_lines = last_state.lines
    ass_actors = last_state.actors
    ass_markers = last_state.markers
    if last_state.dubbers then DUBBERS.data = last_state.dubbers end
    if last_state.dir_actors then director_actors = last_state.dir_actors end

    if editor_state.last_region_id ~= nil then
        local _, isrgn, _, _, name, _ = reaper.EnumProjectMarkers3(0, editor_state.last_region_id)
        if isrgn then
            editor_state.original_text = name
        end

        for _, line in ipairs(ass_lines) do
            if line.rgn_idx and line.rgn_idx == editor_state.last_region_id then
                editor_state.current_actor = line.actor
                break
            end
        end
    end
    
    DUBBERS.save()
    cleanup_actors()
    rebuild_regions()
    save_project_data(UI_STATE.last_project_id) -- Sync to metadata
    show_snackbar(T("UNDO_SNC") .. last_state.label, "info")
end

local function redo_action()
    if #redo_stack == 0 then return end
    
    local next_state = table.remove(redo_stack)
    
    -- Save current state back to undo stack
    local current_state = {
        lines = deep_copy_table(ass_lines),
        actors = deep_copy_table(ass_actors),
        dubbers = deep_copy_table(DUBBERS.data),
        dir_actors = deep_copy_table(director_actors),
        markers = capture_project_markers(),
        label = next_state.label
    }
    
    table.insert(undo_stack, current_state)
    if #undo_stack > max_undo_depth then
        table.remove(undo_stack, 1)
    end

    ass_lines = next_state.lines
    ass_actors = next_state.actors
    ass_markers = next_state.markers
    if next_state.dubbers then DUBBERS.data = next_state.dubbers end
    if next_state.dir_actors then director_actors = next_state.dir_actors end

    if editor_state.last_region_id ~= nil then
        local _, isrgn, _, _, name, _ = reaper.EnumProjectMarkers3(0, editor_state.last_region_id)
        if isrgn then
            editor_state.original_text = name
        end

        for _, line in ipairs(ass_lines) do
            if line.rgn_idx and line.rgn_idx == editor_state.last_region_id then
                editor_state.current_actor = line.actor
                break
            end
        end
    end
    
    DUBBERS.save()
    cleanup_actors()
    rebuild_regions()
    save_project_data(UI_STATE.last_project_id) -- Sync to metadata
    show_snackbar(T("REDO_SNC") .. next_state.label, "info")
end

local function apply_item_coloring(reset)
    local items = {}
    local item_count = reaper.CountSelectedMediaItems(0)
    
    if item_count > 0 then
        for i = 0, item_count - 1 do
            table.insert(items, reaper.GetSelectedMediaItem(0, i))
        end
    else
        local track_count = reaper.CountSelectedTracks(0)
        if track_count > 0 then
            local processed_tracks = {}
            for i = 0, track_count - 1 do
                local track = reaper.GetSelectedTrack(0, i)
                if not processed_tracks[track] then
                    processed_tracks[track] = true
                    local depth = reaper.GetTrackDepth(track)
                    local track_idx = reaper.GetMediaTrackInfo_Value(track, "IP_TRACKNUMBER")
                    local total_tracks = reaper.CountTracks(0)
                    for j = track_idx, total_tracks - 1 do
                        local child = reaper.GetTrack(0, j)
                        if child and reaper.GetTrackDepth(child) > depth then
                            processed_tracks[child] = true
                        else break end
                    end
                end
            end
            for tr in pairs(processed_tracks) do
                local track_item_count = reaper.CountTrackMediaItems(tr)
                for j = 0, track_item_count - 1 do
                    table.insert(items, reaper.GetTrackMediaItem(tr, j))
                end
            end
        end
    end

    if #items == 0 then
        show_snackbar(T("EBU_SELECT_M_ITEMS_T"), "info")
        return
    end

    if not reset then
        local msg = T("COLOR_CODER_ITEM_INFO")
        local res = reaper.MB(msg, T("TABLE_MENU_COLOR_BY_ACTOR"), 1) -- 1 = OK/Cancel
        if res ~= 1 then return end
    end

    local colored = 0
    for _, item in ipairs(items) do
        if item then
            if reset then
                reaper.SetMediaItemInfo_Value(item, "I_CUSTOMCOLOR", 0)
                colored = colored + 1
            else
                local item_start = reaper.GetMediaItemInfo_Value(item, "D_POSITION")
                local item_end = item_start + reaper.GetMediaItemInfo_Value(item, "D_LENGTH")
                
                local max_overlap = 0
                local best_color = nil
                
                -- Efficiently find overlapping regions
                local _, num_markers, num_regions = reaper.CountProjectMarkers(0)
                local total = num_markers + num_regions
                
                for j = 0, total - 1 do
                    local _, isrgn, r_start, r_end, _, _, color = reaper.EnumProjectMarkers3(0, j)
                    if isrgn and color ~= 0 then
                        -- Calculate intersection
                        local overlap_start = math.max(item_start, r_start)
                        local overlap_end = math.min(item_end, r_end)
                        local overlap = overlap_end - overlap_start
                        
                        if overlap > max_overlap then
                            max_overlap = overlap
                            best_color = color
                        end
                    end
                end
                
                local item_len = item_end - item_start
                if best_color and max_overlap > 0 then
                    -- Higher precision thresholds:
                    -- At least 0.8s (substantial chunk) OR more than 50% of the item
                    if max_overlap > 0.8 or (max_overlap / item_len) > 0.5 then
                        -- For Media Items, we need the 0x1000000 flag for custom colors
                        reaper.SetMediaItemInfo_Value(item, "I_CUSTOMCOLOR", best_color | 0x1000000)
                        colored = colored + 1
                    end
                end
            end
        end
    end
    
    reaper.UpdateArrange()
    if not reset then
        show_snackbar(T("COLOR_CODER_S_1") .. colored .. T("COLOR_CODER_S_2"), "success")
    else
        show_snackbar(T("COLOR_CODER_REMOVE_1") .. colored .. ")", "success")
    end
end

--- Remove all accent marks for selected actors
function UTILS.remove_all_acute_for_selected_actors()
    if not ass_lines or not ass_actors then return end
    
    local lines_to_change = {}
    for _, line in ipairs(ass_lines) do
        if line.actor and ass_actors[line.actor] == true then
            if (line.text or ""):find(acute, 1, true) then
                table.insert(lines_to_change, line)
            end
        end
    end
    
    if #lines_to_change > 0 then
        push_undo(T("ACCENTS_REMOVED_N_1") .. #lines_to_change .. ")")
        for _, line in ipairs(lines_to_change) do
            line.text = line.text:gsub(acute, "")
        end
        rebuild_regions()
        show_snackbar(T("ACCENTS_REMOVED_N_1") .. #lines_to_change .. ")", "success")
    else
        show_snackbar(T("NO_ACCENTS_WERE_FOUND_FOR_A"), "info")
    end
end

-- Save Text Items styles to ExtState
function UTILS.save_text_items_styles()
    if not UI_STATE.text_items_style or not UI_STATE.text_items_style.params then
        return
    end

    local params = UI_STATE.text_items_style.params
    local data = {}

    for key, idx in pairs(OTHER.TEXT_ITEMS_PARAM_INDICES) do
        if params[key] ~= nil then
            data[key] = tostring(params[key])
        end
    end

    -- Also save custom font name
    if UI_STATE.text_items_style.custom_font_name then
        data["custom_font_name"] = UI_STATE.text_items_style.custom_font_name
    end

    local json_str = STATS.json_encode(data)
    reaper.SetExtState(section_name, "text_items_styles", json_str, true)
end

-- Load Text Items styles from ExtState
function UTILS.load_text_items_styles()
    local json_str = reaper.GetExtState(section_name, "text_items_styles")
    if not json_str or json_str == "" then
        return nil
    end

    local success, data = pcall(function() return STATS.json_decode(json_str) end)
    if not success or type(data) ~= "table" then
        return nil
    end

    local params = {}
    for key, idx in pairs(OTHER.TEXT_ITEMS_PARAM_INDICES) do
        if data[key] then
            params[key] = tonumber(data[key])
        end
    end

    local custom_font_name = data["custom_font_name"]

    return { params = params, custom_font_name = custom_font_name }
end

--- Creates empty "Text Items" on a dedicated SUBASS_ITEMS track from all project regions.
--- If the track already exists its items are cleared first.
function UTILS.create_text_items_from_regions()
    -- Simplified robust helper to set FX code (Track or Take)
    local function set_fx_code_simple(target, fx_idx, code_str, is_take)
        -- Try API first
        local setter = is_take and reaper.TakeFX_SetNamedConfigParm or reaper.TrackFX_SetNamedConfigParm
        if setter then
            if setter(target, fx_idx, "code", code_str) then return true end
        end

        -- Fallback to chunk hacking (target is track or take)
        local encoded = "|" .. code_str:gsub("\n", "\n|")
        local ret, chunk
        local item = is_take and reaper.GetMediaItemTake_Item(target) or nil

        if is_take then
            ret, chunk = reaper.GetItemStateChunk(item, "", false)
        else
            ret, chunk = reaper.GetTrackStateChunk(target, "", false)
        end

        if ret then
            -- Find the fx_idx-th VIDEO_EFFECT block (0-indexed)
            local current_idx = -1
            local s_idx = 1
            while true do
                local s, e = chunk:find("<VIDEO_EFFECT", s_idx)
                if not s then break end
                current_idx = current_idx + 1

                if current_idx == fx_idx then
                    local b_end = chunk:find("\n>", e)
                    if b_end then
                        local code_s, code_e = chunk:find("<CODE.-%s>", s)
                        local new_chunk
                        if code_s and code_s < b_end then
                            new_chunk = chunk:sub(1, code_s - 1) ..
                            "<CODE\n" .. encoded .. "\n>" .. chunk:sub(code_e + 1)
                        else
                            -- Find first newline after VIDEO_EFFECT to insert NI and CODE
                            local head_end = chunk:find("\n", e) or e
                            new_chunk = chunk:sub(1, head_end) ..
                            "\n<CODE\n" .. encoded .. "\n>" .. chunk:sub(head_end + 1)
                        end

                        if is_take then
                            reaper.SetItemStateChunk(item, new_chunk, false)
                        else
                            reaper.SetTrackStateChunk(target, new_chunk, false)
                        end
                        return true
                    end
                end
                s_idx = e + 1
            end
        end
        return false
    end

    -- Collect all regions from project
    local rgns = {}
    local time_points = {}
    local i = 0
    while true do
        local retval, isrgn, pos, rgnend, name = reaper.EnumProjectMarkers3(0, i)
        if retval == 0 then break end
        if isrgn then
            table.insert(rgns, { pos = pos, rgnend = rgnend, name = name })
            table.insert(time_points, pos)
            table.insert(time_points, rgnend)
        end
        i = i + 1
    end

    if #rgns == 0 then
        show_snackbar(T("NO_REGIONS_IN_PROJ"), "warning")
        return
    end

    -- Find or create SUBASS_ITEMS track
    local track_name = "SUBASS_ITEMS"
    local target_track = nil
    local tc = reaper.CountTracks(0)
    for t = 0, tc - 1 do
        local tr = reaper.GetTrack(0, t)
        local _, tn = reaper.GetTrackName(tr)
        if tn == track_name then
            target_track = tr
            break
        end
    end

    reaper.PreventUIRefresh(1)
    reaper.Undo_BeginBlock()

    if not target_track then
        reaper.InsertTrackAtIndex(0, true)
        target_track = reaper.GetTrack(0, 0)
        reaper.GetSetMediaTrackInfo_String(target_track, "P_NAME", track_name, true)
    else
        -- Clear all existing items from this track
        local item_count = reaper.CountTrackMediaItems(target_track)
        for k = item_count - 1, 0, -1 do
            local it = reaper.GetTrackMediaItem(target_track, k)
            reaper.DeleteTrackMediaItem(target_track, it)
        end
    end

    -- Add FX to the track (if not present)
    local track_fx_code = [=[// TEXT OVER VIDEO (Direct Screen Render Fix)
#text="";
font="Arial";
#custom_font = "";

//@param1:size 'Size' 0.05 0.01 0.2 0.1 0.001
//@param4:fontselect 'Font' 0 0 12 6 1
//@param5:fontstyle 'Style' 0 0 3 1.5 1
//@param6:underline 'Underline' 0 0 1 0.5 1
//@param7:xpos 'Text X position' 0.5 0 1 0.5 0.01
//@param8:ypos 'Text Y position' 0.5 0 1 0.5 0.01
//@param9:fgc_r 'Red text' 1.0 0 1 0.5 0.01
//@param10:fgc_g 'Green text' 1.0 0 1 0.5 0.01
//@param11:fgc_b 'Blue text' 1.0 0 1 0.5 0.01
//@param12:align 'Text align' 1 0 2 1 1
//@param13:fga 'Alpha text' 1.0 0 1 0.5 0.01
//@param14:bg_on 'BG enabled' 0 0 1 0.5 1
//@param15:bgypos 'BG Y offset' 0.5 0 1 0.5 0.01
//@param16:bgxpos 'BG X offset' 0.5 0 1 0.5 0.01

//@param18:bgwidth 'BG width' 1.0 0.0 10.0 1.0 0.01
//@param19:bgheight 'BG height' 1.0 0.0 10.0 1.0 0.01
//@param20:bgc_r 'Red BG' 0.0 0 1 0.5 0.01
//@param21:bgc_g 'Green BG' 0.0 0 1 0.5 0.01
//@param22:bgc_b 'Blue BG' 0.0 0 1 0.5 0.01
//@param23:bga 'Alpha BG' 1 0.001 1 0.5 0.001

//@param27:ol_on 'Outline enabled' 0 0 1 0.5 1
//@param28:outline_w 'Outline width' 2 0 10 2 1
//@param29:outl_r 'Red outline' 0.0 0 1 0.5 0.01
//@param30:outl_g 'Green outline' 0.0 0 1 0.5 0.01
//@param31:outl_b 'Blue outline' 0.0 0 1 0.5 0.01
//@param32:outl_a 'Alpha outline' 1.0 0 1 0.5 0.01
//@param34:sh_x 'Shadow X offset' 5 -100 100 0 1
//@param35:sh_y 'Shadow Y offset' 5 -100 100 0 1
//@param36:sh_a 'Shadow alpha' 0.5 0 1 0.5 0.01
//@param37:sh_on 'Shadow enabled' 1 0 1 0.5 1

input_info(0, w, h);
w == 0 ? (
  gfx_clear = 0;
  return;
);

// 1. Обов'язково малюємо відео на екран
gfx_blit(0, 1);

project_w <= 0 ? input_info(0, project_w, project_h);
(project_w <= 0 || project_h <= 0) ? (project_w = 1920; project_h = 1080;);

is_active = gmem[0];
gmem[0] = 0;

#text = "";

// 2. Зчитування назви айтема
is_active == 1 ? (
  input_get_name(0, #text);
  strcmp(#text, "SUBASS_ITEMS") == 0 ? #text = "";
) : (
  #text = "";
);

// 3. Малювання тексту напряму на екран проекту
strlen(#text) > 0 ? (
  fontselect == 0  ? font = "Arial";
  fontselect == 1  ? font = "Calibri";
  fontselect == 2  ? font = "Roboto";
  fontselect == 3  ? font = "Segoe UI";
  fontselect == 4  ? font = "Trebuchet MS";
  fontselect == 5  ? font = "Verdana";
  fontselect == 6  ? font = "Cambria";
  fontselect == 7  ? font = "Impact";
  fontselect == 8  ? font = "Georgia";
  fontselect == 9  ? font = "Times New Roman";
  fontselect == 10 ? font = "Consolas";
  fontselect == 11 ? font = "Courier New";
  fontselect == 12 ? font = #custom_font;

  style_flag = 0;
  fontstyle == 1 ? style_flag = 'b';
  fontstyle == 2 ? style_flag = 'i';
  fontstyle == 3 ? style_flag = 256 * 'i' + 'b';
  underline > 0.5 ? style_flag = (style_flag > 0) ? (256 * style_flag + 'u') : 'u';

  colorspace = 'RGBA';
  gfx_setfont(size * project_h, font, style_flag);

  // Вимірюємо текст
  line_count = 0; max_line_w = 0; total_line_h = 0; src_len = strlen(#text); i = 0; line_start = 0;
  loop(src_len + 1,
    ch = (i < src_len) ? str_getchar(#text, i) : 10;
    (ch == 10 || ch == 13) ? (
      #line = ""; copy_len = i - line_start;
      copy_len > 0 ? ( j = 0; loop(copy_len, str_setchar(#line, j, str_getchar(#text, line_start + j)); j += 1; ); str_setchar(#line, copy_len, 0); );
      gfx_str_measure(#line, lw, lh);
      lw > max_line_w ? max_line_w = lw;
      total_line_h += lh; line_h_single = lh; line_count += 1;
      (ch == 13 && i + 1 < src_len && str_getchar(#text, i + 1) == 10) ? ( i += 1; );
      line_start = i + 1;
    );
    i += 1;
  );
  line_count == 0 ? ( gfx_str_measure(#text, max_line_w, total_line_h); line_h_single = total_line_h; line_count = 1; );
  txtw = max_line_w; txth = total_line_h;

  ty = ((project_h - txth) * ypos) | 0; xp = (xpos * (project_w - txtw)) | 0;
  bgw = bg_on ? txtw * bgwidth : project_w * bgwidth; bgh = bg_on ? txth * bgheight : project_h * bgheight;
  bgx = xp - (bgw - txtw) / 2 + (bgxpos - 0.5) * project_w; bgy = ty  - (bgh - txth) / 2 + (bgypos - 0.5) * project_h;

  img_bg = gfx_img_alloc(bgw, bgh, 1);
  gfx_dest = img_bg;
  gfx_set(0, 0, 0, 0); gfx_clear = 1; // Очистка в прозорість

  gfx_dest = -1; // ПРЯМЕ МАЛЮВАННЯ БЕЗ БУФЕРІВ

  // А. ПІД КЛАДКА
  (bg_on > 0.5 && bga > 0) ? (
    gfx_set(bgc_r, bgc_g, bgc_b, bga, 0);
    gfx_fillrect(bgx, bgy, bgw, bgh);
  );

  // Б. МАЛЮЄМО ТЕКСТ ТА ОБВОДКУ
  cur_ly = ty; i = 0; line_start = 0;
  loop(src_len + 1,
    ch = (i < src_len) ? str_getchar(#text, i) : 10;
    (ch == 10 || ch == 13) ? (
      #line = ""; copy_len = i - line_start;
      copy_len > 0 ? ( j = 0; loop(copy_len, str_setchar(#line, j, str_getchar(#text, line_start + j)); j += 1; ); str_setchar(#line, copy_len, 0); );
      gfx_str_measure(#line, line_w, line_h);

      align == 0 ? cur_lx = xp;
      align == 1 ? cur_lx = xp + (txtw - line_w) / 2;
      align == 2 ? cur_lx = xp + (txtw - line_w);

      // 1. Тінь
      (sh_on > 0.5 && sh_a > 0) ? (
        gfx_set(0, 0, 0, sh_a * fga, 0);
        gfx_str_draw(#line, cur_lx + sh_x, cur_ly + sh_y);
      );

      // 2. Обводка
      (ol_on > 0.5 && outline_w > 0) ? (
        gfx_set(outl_r, outl_g, outl_b, outl_a, 0);
        oi = -outline_w;
        while(oi <= outline_w) (
          oj = -outline_w;
          while(oj <= outline_w) (
            (oi != 0 || oj != 0) ? gfx_str_draw(#line, cur_lx + oi, cur_ly + oj);
            oj += outline_w;
          );
          oi += outline_w;
        );
      );

      // 3. ОСНОВНИЙ ТЕКСТ (Фікс альфа-каналу)
      // Ми малюємо текст двічі: перший раз з альфою 0 для заповнення,
      // а другий раз — як нормальний колір.
      gfx_set(fgc_r, fgc_g, fgc_b, fga, 0);
      gfx_str_draw(#line, cur_lx, cur_ly);
      // Якщо він все ще прозорий, додаємо "штамп":
      gfx_set(fgc_r, fgc_g, fgc_b, fga, 1);
      gfx_str_draw(#line, cur_lx, cur_ly);

      cur_ly += line_h;
      (ch == 13 && i + 1 < src_len && str_getchar(#text, i + 1) == 10) ? ( i += 1; );
      line_start = i + 1;
    );
    i += 1;
  );
);]=]

    -- Find if the track already has a Video Processor FX
    local track_fx_idx = -1
    local num_fx = reaper.TrackFX_GetCount(target_track)
    for f = 0, num_fx - 1 do
        local retval, fx_name = reaper.TrackFX_GetFXName(target_track, f, "")
        if retval and (fx_name:lower():find("video processor") or fx_name:lower():find("video_processor")) then
            track_fx_idx = f
            break
        end
    end

    if track_fx_idx < 0 then
        track_fx_idx = reaper.TrackFX_AddByName(target_track, "Video processor", false, 1) -- add
        if track_fx_idx >= 0 then
            set_fx_code_simple(target_track, track_fx_idx, track_fx_code, false)
            reaper.SetOnlyTrackSelected(target_track)
            reaper.Main_OnCommand(8, 0)

            -- Завантажуємо збережені стилі
            local saved_styles = UTILS.load_text_items_styles()

            if saved_styles and saved_styles.params then
                -- Застосовуємо збережені параметри до FX
                for key, idx in pairs(OTHER.TEXT_ITEMS_PARAM_INDICES) do
                    local val = saved_styles.params[key]
                    if val ~= nil then
                        reaper.TrackFX_SetParam(target_track, track_fx_idx, idx, val)
                    end
                end

                -- Відновлюємо custom font name
                if saved_styles.custom_font_name then
                    local function set_custom_font_to_track(track, fx_idx, font_name)
                        local ret, chunk = reaper.GetTrackStateChunk(track, "", false)
                        if not ret then return false end

                        local fx_start = nil
                        local fx_end = nil
                        local current_idx = -1
                        local s_idx = 1

                        while true do
                            local s, e = chunk:find("<VIDEO_EFFECT", s_idx)
                            if not s then break end
                            current_idx = current_idx + 1

                            if current_idx == fx_idx then
                                fx_start = s
                                local b_end = chunk:find("\n>", e)
                                if b_end then
                                    fx_end = b_end
                                end
                                break
                            end
                            s_idx = e + 1
                        end

                        if not fx_start or not fx_end then return false end

                        local fx_chunk = chunk:sub(fx_start, fx_end)
                        local new_fx_chunk = fx_chunk:gsub('#custom_font = "[^"]*"',
                            '#custom_font = "' .. font_name .. '"')

                        if new_fx_chunk == fx_chunk then
                            new_fx_chunk = fx_chunk:gsub('font="Arial";',
                                'font="Arial";\n#custom_font = "' .. font_name .. '";')
                        end

                        local new_chunk = chunk:sub(1, fx_start - 1) .. new_fx_chunk .. chunk:sub(fx_end + 1)
                        reaper.SetTrackStateChunk(track, new_chunk, false)
                        return true
                    end

                    set_custom_font_to_track(target_track, track_fx_idx, saved_styles.custom_font_name)
                end
            else
                -- Якщо немає збережених стилів, використовуємо стандартні значення
                reaper.TrackFX_SetParam(target_track, track_fx_idx, 0, 0.065)
                reaper.TrackFX_SetParam(target_track, track_fx_idx, 6, 0.5)
                reaper.TrackFX_SetParam(target_track, track_fx_idx, 7, 0.98)
                reaper.TrackFX_SetParam(target_track, track_fx_idx, 8, 1.0)
                reaper.TrackFX_SetParam(target_track, track_fx_idx, 9, 1.0)
                reaper.TrackFX_SetParam(target_track, track_fx_idx, 10, 1.0)
                reaper.TrackFX_SetParam(target_track, track_fx_idx, 11, 1.0)
                reaper.TrackFX_SetParam(target_track, track_fx_idx, 12, 1.0)
                reaper.TrackFX_SetParam(target_track, track_fx_idx, 13, 0.0)

                reaper.TrackFX_SetParam(target_track, track_fx_idx, 14, 0.5)
                reaper.TrackFX_SetParam(target_track, track_fx_idx, 15, 0.5)
                reaper.TrackFX_SetParam(target_track, track_fx_idx, 17, 1.1)
                reaper.TrackFX_SetParam(target_track, track_fx_idx, 18, 1.1)
                reaper.TrackFX_SetParam(target_track, track_fx_idx, 22, 0.5)

                reaper.TrackFX_SetParam(target_track, track_fx_idx, 26, 1.0)
                reaper.TrackFX_SetParam(target_track, track_fx_idx, 27, 2.0)
                reaper.TrackFX_SetParam(target_track, track_fx_idx, 31, 0.15)

                reaper.TrackFX_SetParam(target_track, track_fx_idx, 33, 3.0)
                reaper.TrackFX_SetParam(target_track, track_fx_idx, 34, 3.0)
                reaper.TrackFX_SetParam(target_track, track_fx_idx, 35, 0.6)
                reaper.TrackFX_SetParam(target_track, track_fx_idx, 36, 1.0)
            end
        end
    end

    local function format_text(in_text, limit)
        text = in_text:gsub("{{+.-}}+", ""):gsub("{.-}", "")

        local lines = {}
        -- Розбиваємо вхідний текст на існуючі рядки
        for line in text:gmatch("[^\r\n]+") do
            -- Якщо рядок короткий, додаємо як є
            if #line <= limit then
                table.insert(lines, line)
            else
                -- Якщо рядок задовгий, розбиваємо його на підрядки
                local current_line = ""
                for word in line:gmatch("%S+") do
                    if #current_line + #word + 1 > limit then
                        table.insert(lines, current_line)
                        current_line = word
                    else
                        current_line = (current_line == "" and "" or current_line .. " ") .. word
                    end
                end
                table.insert(lines, current_line)
            end
        end

        -- Збираємо все назад у один текст
        return table.concat(lines, "\n")
    end

    table.sort(time_points)
    local unique_points = {}
    for i = 1, #time_points do
        if i == 1 or time_points[i] ~= time_points[i - 1] then
            table.insert(unique_points, time_points[i])
        end
    end

    for i = 1, #unique_points - 1 do
        local start_t = unique_points[i]
        local end_t = unique_points[i + 1]

        -- Знаходимо всі регіони, які активні в цьому сегменті
        local active_names = {}
        for _, rgn in ipairs(rgns) do
            if rgn.pos <= start_t and rgn.rgnend >= end_t then
                table.insert(active_names, rgn.name)
            end
        end

        -- Якщо в цьому сегменті щось є — створюємо айтем
        if #active_names > 0 then
            local item = reaper.AddMediaItemToTrack(target_track)
            reaper.SetMediaItemInfo_Value(item, "D_POSITION", start_t)
            reaper.SetMediaItemInfo_Value(item, "D_LENGTH", math.max(end_t - start_t, 0.001))

            local take = reaper.AddTakeToMediaItem(item)
            if take then
                -- Об'єднуємо назви через перенос рядка
                local combined_text = table.concat(active_names, "\n")
                local formatted_name = format_text(combined_text, 80)

                reaper.GetSetMediaItemTakeInfo_String(take, "P_NAME", formatted_name, true)
                reaper.GetSetMediaItemInfo_String(item, "P_NOTES", formatted_name, true)

                local take_fx = reaper.TakeFX_AddByName(take, "Video processor", 1)
                if take_fx >= 0 then
                    local item_code = "gfx_blit(0, 1);\ngmem[0] = 1;"
                    set_fx_code_simple(take, take_fx, item_code, true)
                end
            end
        end
    end

    reaper.PreventUIRefresh(-1)
    reaper.UpdateArrange()
    reaper.Undo_EndBlock("Create text items from regions", -1)
    show_snackbar(string.format(T("IN_TEXT_I_SUCC"), #rgns, track_name), "success")
end


--- Open modal window to edit text item styles
function UTILS.open_text_items_style_editor()
    -- Знаходимо трек SUBASS_ITEMS
    local track_name = "SUBASS_ITEMS"
    local target_track = nil
    local tc = reaper.CountTracks(0)
    for t = 0, tc - 1 do
        local tr = reaper.GetTrack(0, t)
        local _, tn = reaper.GetTrackName(tr)
        if tn == track_name then
            target_track = tr
            break
        end
    end

    -- Завантажуємо збережені стилі
    local saved_styles = UTILS.load_text_items_styles()

    local current_params = {}

    -- БЕРЕМО ПАРАМЕТРИ ТІЛЬКИ З DEFAULT АБО EXTSTATE
    for key, default_val in pairs(OTHER.TEXT_ITEMS_DEFAULT_PARAMS) do
        if saved_styles and saved_styles.params and saved_styles.params[key] ~= nil then
            current_params[key] = saved_styles.params[key]
        else
            current_params[key] = default_val
        end
    end

    local fx_idx = -1
    local custom_font_name = saved_styles and saved_styles.custom_font_name or nil

    if target_track then
        local num_fx = reaper.TrackFX_GetCount(target_track)
        for f = 0, num_fx - 1 do
            local retval, fx_name = reaper.TrackFX_GetFXName(target_track, f, "")
            if retval and (fx_name:lower():find("video processor") or fx_name:lower():find("video_processor")) then
                fx_idx = f
                break
            end
        end
    end

    -- Створюємо стан
    UI_STATE.text_items_style = {
        track = target_track,
        fx_idx = fx_idx,
        params = current_params,
        default_params = OTHER.TEXT_ITEMS_DEFAULT_PARAMS,
        show = true,
        scroll_y = 0,
        target_scroll_y = 0,
        custom_font_name = custom_font_name,
        subass_items_editor_mode = false,
    }
end

--- Apply current styles to all selected items
function UTILS.apply_styles_to_selected_items()
    local track_name = "SUBASS_ITEMS"
    local target_track = nil
    local tc = reaper.CountTracks(0)
    for t = 0, tc - 1 do
        local tr = reaper.GetTrack(0, t)
        local _, tn = reaper.GetTrackName(tr)
        if tn == track_name then
            target_track = tr
            break
        end
    end
    
    if not target_track then
        show_snackbar(T("NO_SUBASS_TRACK"), "warning")
        return false
    end
    
    if not UI_STATE.text_items_style or not UI_STATE.text_items_style.params then
        show_snackbar(T("NO_STYLES_TO_APPLY"), "warning")
        return false
    end
    
    -- Отримуємо тільки виділені items на треку
    local selected_items = {}
    local item_count = reaper.CountTrackMediaItems(target_track)
    
    for i = 0, item_count - 1 do
        local item = reaper.GetTrackMediaItem(target_track, i)
        if reaper.IsMediaItemSelected(item) then
            local take = reaper.GetActiveTake(item)
            if take then
                table.insert(selected_items, {item = item, take = take})
            end
        end
    end
    
    if #selected_items == 0 then
        show_snackbar(T("NO_ITEM_SELECTED"), "warning")
        return false
    end
    
    -- Prepare styles data
    local styles_data = {
        params = {},
        custom_font_name = UI_STATE.text_items_style.custom_font_name or ""
    }
    
    for key, val in pairs(UI_STATE.text_items_style.params) do
        styles_data.params[key] = val
    end
    
    -- Generate full Video Processor code
    local full_code = UTILS.generate_full_video_processor_code(styles_data)
    
    -- Вставляємо custom_font у код якщо є
    local custom_font = styles_data.custom_font_name or ""
    if custom_font ~= "" then
        full_code = full_code:gsub('#custom_font = "[^"]*"', '#custom_font = "' .. custom_font .. '"')
    end
    
    -- Застосовуємо стилі до кожного виділеного item
    local success_count = 0
    for _, selected in ipairs(selected_items) do
        local take = selected.take
        
        -- Find and remove existing Video Processor FX on take
        local num_fx = reaper.TakeFX_GetCount(take)
        for f = num_fx - 1, 0, -1 do
            local retval, fx_name = reaper.TakeFX_GetFXName(take, f, "")
            if retval and (fx_name:lower():find("video processor") or fx_name:lower():find("video_processor")) then
                reaper.TakeFX_Delete(take, f)
            end
        end
        
        -- Add new Video Processor FX
        local fx_idx = reaper.TakeFX_AddByName(take, "Video processor", 1)
        
        if fx_idx >= 0 then
            -- Try to set code via SetNamedConfigParm
            local success = reaper.TakeFX_SetNamedConfigParm(take, fx_idx, "code", full_code)
            
            if not success then
                -- Fallback: try via chunk
                success = UTILS.set_take_code_via_chunk(take, fx_idx, full_code)
            end
            
            if success then
                -- Set parameters
                for key, idx in pairs(OTHER.TEXT_ITEMS_PARAM_INDICES) do
                    local val = styles_data.params[key]
                    if val ~= nil then
                        reaper.TakeFX_SetParam(take, fx_idx, idx, val)
                    end
                end
                
                -- Apply custom font if exists
                if custom_font ~= "" then
                    local item = reaper.GetMediaItemTake_Item(take)
                    if item then
                        local ret, chunk = reaper.GetItemStateChunk(item, "", false)
                        if ret then
                            local new_chunk = chunk:gsub('#custom_font = "[^"]*"', '#custom_font = "' .. custom_font .. '"')
                            if new_chunk ~= chunk then
                                reaper.SetItemStateChunk(item, new_chunk, false)
                            end
                        end
                    end
                end
                
                success_count = success_count + 1
            end
        end
    end
    
    if success_count > 0 then
        show_snackbar(string.format(T("STYLES_APPLIED_TO_ITEMS"), success_count), "success")
        reaper.UpdateArrange()
    else
        show_snackbar(T("FAILED_TO_APPLY_STYLES"), "error")
    end
    
    return success_count > 0
end

--- Set take code via item chunk (more reliable method)
function UTILS.set_take_code_via_chunk(take, fx_idx, code)
    local item = reaper.GetMediaItemTake_Item(take)
    if not item then return false end

    -- Get item chunk
    local ret, chunk = reaper.GetItemStateChunk(item, "", false)
    if not ret then return false end

    -- Find which take number this is
    local take_num = -1
    local tc = reaper.CountTakes(item)
    for t = 0, tc - 1 do
        if reaper.GetTake(item, t) == take then
            take_num = t
            break
        end
    end

    if take_num < 0 then return false end

    -- Find the take block
    local take_start = 1
    for t = 0, take_num do
        take_start = chunk:find("<TAKE", take_start)
        if not take_start then return false end
        if t < take_num then
            take_start = chunk:find(">", take_start) + 1
        end
    end

    local take_end = chunk:find(">", take_start)
    if not take_end then return false end

    local take_chunk = chunk:sub(take_start, take_end)

    -- Find VIDEO_EFFECT blocks
    local fx_start = 1
    local current_fx = -1
    local fx_pos_start = nil
    local fx_pos_end = nil

    while true do
        local s, e = take_chunk:find("<VIDEO_EFFECT", fx_start)
        if not s then break end
        current_fx = current_fx + 1

        if current_fx == fx_idx then
            fx_pos_start = s
            local b_end = take_chunk:find("\n>", e)
            if b_end then
                fx_pos_end = b_end
            end
            break
        end
        fx_start = e + 1
    end

    if not fx_pos_start or not fx_pos_end then return false end

    -- Encode code with pipe characters at line starts
    local encoded_code = ""
    for line in code:gmatch("[^\r\n]*") do
        encoded_code = encoded_code .. "|" .. line .. "\n"
    end

    -- Build new FX chunk with CODE section
    local fx_chunk = take_chunk:sub(fx_pos_start, fx_pos_end)

    -- Remove existing CODE section if any
    local code_start, code_end = fx_chunk:find("<CODE.-%s>")
    if code_start then
        fx_chunk = fx_chunk:sub(1, code_start - 1) .. fx_chunk:sub(code_end + 1)
    end

    -- Insert new CODE section
    local insert_pos = fx_chunk:find("\n") or 1
    if insert_pos then
        fx_chunk = fx_chunk:sub(1, insert_pos) .. "<CODE\n" .. encoded_code .. ">\n" .. fx_chunk:sub(insert_pos + 1)
    end

    -- Reconstruct chunks
    local new_take_chunk = take_chunk:sub(1, fx_pos_start - 1) .. fx_chunk .. take_chunk:sub(fx_pos_end + 1)
    local new_chunk = chunk:sub(1, take_start - 1) .. new_take_chunk .. chunk:sub(take_end + 1)

    return reaper.SetItemStateChunk(item, new_chunk, false)
end

function UTILS.generate_full_video_processor_code(styles_data)
    local p = styles_data.params
    local custom_font = styles_data.custom_font_name or ""

    return string.format([=[// Text
        #text="";

        #colortext="";  // Колір тексту в форматі RRGGBB або RRGGBBAA

        #colorBG="";    // Колір фону в форматі RRGGBB або RRGGBBAA

        font="";
        #custom_font = "";

        //@param1:size 'Size' 0.05 0.01 0.2 0.1 0.001
        //@param2:rotate 'Rotation' 0 -360 360 0 0.1

        //@param4:fontselect 'Font' 0 0 12 6 1
        //@param5:fontstyle 'Style' 0 0 3 1.5 1
        //@param6:underline 'Underline' 0 0 1 0.5 1
        //@param7:xpos 'Text X position' 0.5 0 1 0.5 0.01
        //@param8:ypos 'Text Y position' 0.5 0 1 0.5 0.01
        //@param9:fgc_r 'Red text' 1.0 0 1 0.5 0.01
        //@param10:fgc_g 'Green text' 1.0 0 1 0.5 0.01
        //@param11:fgc_b 'Blue text' 1.0 0 1 0.5 0.01
        //@param12:align 'Text align' 1 0 2 1 1
        //@param13:fga 'Alpha text' 1.0 0 1 0.5 0.01

        //@param14:bg_on 'BG enabled' 0 0 1 0.5 1
        //@param15:bgypos 'BG Y offset' 0.5 0 1 0.5 0.01
        //@param16:bgxpos 'BG X offset' 0.5 0 1 0.5 0.01
        //@param17:bg_rot 'BG rotation (deg)' 0 -360 360 0 0.1
        //@param18:bgwidth 'BG width' 1.0 0.0 10.0 1.0 0.01
        //@param19:bgheight 'BG height' 1.0 0.0 10.0 1.0 0.01
        //@param20:bgc_r 'Red BG' 0.0 0 1 0.5 0.01
        //@param21:bgc_g 'Green BG' 0.0 0 1 0.5 0.01
        //@param22:bgc_b 'Blue BG' 0.0 0 1 0.5 0.01
        //@param23:bga 'Alpha BG' 1 0.001 1 0.5 0.001
        //@param24:bg_corner 'BG border radius' 0 0 0.5 0.1 0.01
        //@param25:bg_fade 'BG fade' 0 0 0.5 0 0

        //@param27:ol_on 'Outline enabled' 0 0 1 0.5 1
        //@param28:outline_w 'Outline width' 2 0 10 2 1
        //@param29:outl_r 'Red outline' 0.0 0 1 0.5 0.01
        //@param30:outl_g 'Green outline' 0.0 0 1 0.5 0.01
        //@param31:outl_b 'Blue outline' 0.0 0 1 0.5 0.01
        //@param32:outl_a 'Alpha outline' 1.0 0 1 0.5 0.01

        //@param34:sh_x 'Shadow X offset' 5 -100 100 0 1
        //@param35:sh_y 'Shadow Y offset' 5 -100 100 0 1
        //@param36:sh_a 'Shadow alpha' 0.5 0 1 0.5 0.01
        //@param37:sh_on 'Shadow enabled' 1 0 1 0.5 1

        //@param39:ignoreinput 'Ignore input' 0 0 1 0.5 1

        input = ignoreinput ? -2 : 0;
        project_wh_valid === 0 ? input_info(input, project_w, project_h);

        // 1. Вибір шрифту
        fontselect == 0  ? font = "Arial";
        fontselect == 1  ? font = "Calibri";
        fontselect == 2  ? font = "Roboto";
        fontselect == 3  ? font = "Segoe UI";
        fontselect == 4  ? font = "Trebuchet MS";
        fontselect == 5  ? font = "Verdana";
        fontselect == 6  ? font = "Cambria";
        fontselect == 7  ? font = "Impact";
        fontselect == 8  ? font = "Georgia";
        fontselect == 9  ? font = "Times New Roman";
        fontselect == 10 ? font = "Consolas";
        fontselect == 11 ? font = "Courier New";
        fontselect == 12 ? font = #custom_font;

        // 2. Парсинг кольору тексту з #colortext
        strlen(#colortext) >= 6 ? (
            h1 = str_getchar(#colortext, 0);
            h2 = str_getchar(#colortext, 1);
            h3 = str_getchar(#colortext, 2);
            h4 = str_getchar(#colortext, 3);
            h5 = str_getchar(#colortext, 4);
            h6 = str_getchar(#colortext, 5);

            v1 = (h1 >= 48 && h1 <= 57) ? h1 - 48 : (h1 >= 65 && h1 <= 70) ? h1 - 55 : (h1 >= 97 && h1 <= 102) ? h1 - 87 : 0;
            v2 = (h2 >= 48 && h2 <= 57) ? h2 - 48 : (h2 >= 65 && h2 <= 70) ? h2 - 55 : (h2 >= 97 && h2 <= 102) ? h2 - 87 : 0;
            v3 = (h3 >= 48 && h3 <= 57) ? h3 - 48 : (h3 >= 65 && h3 <= 70) ? h3 - 55 : (h3 >= 97 && h3 <= 102) ? h3 - 87 : 0;
            v4 = (h4 >= 48 && h4 <= 57) ? h4 - 48 : (h4 >= 65 && h4 <= 70) ? h4 - 55 : (h4 >= 97 && h4 <= 102) ? h4 - 87 : 0;
            v5 = (h5 >= 48 && h5 <= 57) ? h5 - 48 : (h5 >= 65 && h5 <= 70) ? h5 - 55 : (h5 >= 97 && h5 <= 102) ? h5 - 87 : 0;
            v6 = (h6 >= 48 && h6 <= 57) ? h6 - 48 : (h6 >= 65 && h6 <= 70) ? h6 - 55 : (h6 >= 97 && h6 <= 102) ? h6 - 87 : 0;

            fgc_r = (v1 * 16 + v2) / 255;
            fgc_g = (v3 * 16 + v4) / 255;
            fgc_b = (v5 * 16 + v6) / 255;

            strlen(#colortext) >= 8 ? (
                h7 = str_getchar(#colortext, 6);
                h8 = str_getchar(#colortext, 7);
                v7 = (h7 >= 48 && h7 <= 57) ? h7 - 48 : (h7 >= 65 && h7 <= 70) ? h7 - 55 : (h7 >= 97 && h7 <= 102) ? h7 - 87 : 0;
                v8 = (h8 >= 48 && h8 <= 57) ? h8 - 48 : (h8 >= 65 && h8 <= 70) ? h8 - 55 : (h8 >= 97 && h8 <= 102) ? h8 - 87 : 0;
                fga = (v7 * 16 + v8) / 255;
            );
        );

        // 3. Парсинг кольору фону з #colorBG
        strlen(#colorBG) >= 6 ? (
            h1 = str_getchar(#colorBG, 0);
            h2 = str_getchar(#colorBG, 1);
            h3 = str_getchar(#colorBG, 2);
            h4 = str_getchar(#colorBG, 3);
            h5 = str_getchar(#colorBG, 4);
            h6 = str_getchar(#colorBG, 5);

            v1 = (h1 >= 48 && h1 <= 57) ? h1 - 48 : (h1 >= 65 && h1 <= 70) ? h1 - 55 : (h1 >= 97 && h1 <= 102) ? h1 - 87 : 0;
            v2 = (h2 >= 48 && h2 <= 57) ? h2 - 48 : (h2 >= 65 && h2 <= 70) ? h2 - 55 : (h2 >= 97 && h2 <= 102) ? h2 - 87 : 0;
            v3 = (h3 >= 48 && h3 <= 57) ? h3 - 48 : (h3 >= 65 && h3 <= 70) ? h3 - 55 : (h3 >= 97 && h3 <= 102) ? h3 - 87 : 0;
            v4 = (h4 >= 48 && h4 <= 57) ? h4 - 48 : (h4 >= 65 && h4 <= 70) ? h4 - 55 : (h4 >= 97 && h4 <= 102) ? h4 - 87 : 0;
            v5 = (h5 >= 48 && h5 <= 57) ? h5 - 48 : (h5 >= 65 && h5 <= 70) ? h5 - 55 : (h5 >= 97 && h5 <= 102) ? h5 - 87 : 0;
            v6 = (h6 >= 48 && h6 <= 57) ? h6 - 48 : (h6 >= 65 && h6 <= 70) ? h6 - 55 : (h6 >= 97 && h6 <= 102) ? h6 - 87 : 0;

            bgc_r = (v1 * 16 + v2) / 255;
            bgc_g = (v3 * 16 + v4) / 255;
            bgc_b = (v5 * 16 + v6) / 255;

            strlen(#colorBG) >= 8 ? (
                h7 = str_getchar(#colorBG, 6);
                h8 = str_getchar(#colorBG, 7);
                v7 = (h7 >= 48 && h7 <= 57) ? h7 - 48 : (h7 >= 65 && h7 <= 70) ? h7 - 55 : (h7 >= 97 && h7 <= 102) ? h7 - 87 : 0;
                v8 = (h8 >= 48 && h8 <= 57) ? h8 - 48 : (h8 >= 65 && h8 <= 70) ? h8 - 55 : (h8 >= 97 && h8 <= 102) ? h8 - 87 : 0;
                bga = (v7 * 16 + v8) / 255;
            );
            bg_on = 1;
        );

        // 4. Стилі
        style_flag = 0;
        fontstyle == 1 ? style_flag = 'b';
        fontstyle == 2 ? style_flag = 'i';
        fontstyle == 3 ? style_flag = 256 * 'i' + 'b';
        underline > 0.5 ? style_flag = (style_flag > 0) ? (256 * style_flag + 'u') : 'u';
        gfx_a2 = 0;
        gfx_blit(input, 1);
        colorspace = 'RGBA';
        gfx_setfont(size * project_h, font, style_flag);

        // 5. Читаємо текст
        strcmp(#text, "") == 0 ? input_get_name(-1, #text);

        // 6. Розбиваємо на рядки через str_getchar (шукаємо код 10 = \n)
        // Підраховуємо кількість рядків і максимальну ширину блоку
        line_count = 0;
        max_line_w = 0;
        total_line_h = 0;
        src_len = strlen(#text);

        // Перший прохід: міряємо
        i = 0;
        line_start = 0;
        loop(src_len + 1,
          ch = (i < src_len) ? str_getchar(#text, i) : 10;
          (ch == 10 || ch == 13) ? (
            // Витягуємо рядок [line_start .. i-1]
            #line = "";
            copy_len = i - line_start;
            copy_len > 0 ? (
              j = 0;
              loop(copy_len,
                str_setchar(#line, j, str_getchar(#text, line_start + j));
                j += 1;
              );
              str_setchar(#line, copy_len, 0);
            );
            gfx_str_measure(#line, lw, lh);
            lw > max_line_w ? max_line_w = lw;
            total_line_h += lh;
            line_h_single = lh;
            line_count += 1;
            // Пропускаємо \r\n як одне
            (ch == 13 && i + 1 < src_len && str_getchar(#text, i + 1) == 10) ? (
              i += 1;
            );
            line_start = i + 1;
          );
          i += 1;
        );

        // Якщо рядків не знайдено (немає \n взагалі) — весь текст один рядок
        line_count == 0 ? (
          gfx_str_measure(#text, max_line_w, total_line_h);
          line_h_single = total_line_h;
          line_count = 1;
        );

        txtw = max_line_w;
        txth = total_line_h;

        // 7. Позиція текстового блоку
        ty = ((project_h - txth) * ypos) | 0;
        xp = (xpos * (project_w - txtw)) | 0;

        // 8. Розміри та позиція фону
        // Фон прив'язаний до тексту; bgxpos/bgypos — додатковий зсув
        bgw = bg_on ? txtw * bgwidth : project_w * bgwidth;
        bgh = bg_on ? txth * bgheight : project_h * bgheight;
        bgx = xp - (bgw - txtw) / 2 + (bgxpos - 0.5) * project_w;
        bgy = ty  - (bgh - txth) / 2 + (bgypos - 0.5) * project_h;

        // 9. Межі всього об'єкта
        obj_x1 = min(xp - outline_w - abs(sh_x), bgx);
        obj_y1 = min(ty - outline_w - abs(sh_y), bgy);
        obj_x2 = max(xp + txtw + outline_w + abs(sh_x), bgx + bgw);
        obj_y2 = max(ty + txth + outline_w + abs(sh_y), bgy + bgh);
        obj_w = obj_x2 - obj_x1;
        obj_h = obj_y2 - obj_y1;
        obj_diag = ceil(sqrt(obj_w * obj_w + obj_h * obj_h)) + 32;

        // 10. Створення прозорого буфера
        img_obj = gfx_img_alloc(obj_diag, obj_diag, 1);
        gfx_dest = img_obj;
        gfx_clear = 0;

        // 11. Локальні координати в буфері
        buf_x = (obj_diag - obj_w) / 2;
        buf_y = (obj_diag - obj_h) / 2;
        lx  = buf_x + (xp  - obj_x1);
        ly  = buf_y + (ty  - obj_y1);
        lbgx = buf_x + (bgx - obj_x1);
        lbgy = buf_y + (bgy - obj_y1);

        // 12. Малювання фону з fade (виправлено: краї прозорі, не чорні)
        (bg_on > 0.5 && bga > 0) ? (
          bg_diag = ceil(sqrt(bgw * bgw + bgh * bgh));
          img_bg = gfx_img_alloc(bg_diag, bg_diag, 1);
          gfx_dest = img_bg;
          // Спочатку очищаємо в повністю прозорий стан
          gfx_set(0, 0, 0, 0);
          gfx_clear = 1;
          gfx_a2 = 1;

          bg_cx = (bg_diag - bgw) / 2;
          bg_cy = (bg_diag - bgh) / 2;

          fade_px  = floor(min(bgw, bgh) * bg_fade);
          corner_px = floor(min(bgw, bgh) * bg_corner);
          corner_px < fade_px ? corner_px = fade_px;

          // Центральні суцільні прямокутники
          gfx_set(bgc_r, bgc_g, bgc_b, bga);
          gfx_fillrect(bg_cx + fade_px,   bg_cy + corner_px, bgw - fade_px * 2,   bgh - corner_px * 2);
          gfx_fillrect(bg_cx + corner_px, bg_cy + fade_px,   bgw - corner_px * 2, bgh - fade_px * 2);

          // Верхня межа (fade: прозоро вгорі → повна альфа знизу)
          y = 0;
          loop(fade_px,
            alpha = bga * (y / max(fade_px, 1));
            gfx_set(bgc_r, bgc_g, bgc_b, alpha);
            gfx_fillrect(bg_cx + corner_px, bg_cy + y, bgw - corner_px * 2, 1);
            y += 1;
          );

          // Нижня межа
          y = 0;
          loop(fade_px,
            alpha = bga * (y / max(fade_px, 1));
            gfx_set(bgc_r, bgc_g, bgc_b, alpha);
            gfx_fillrect(bg_cx + corner_px, bg_cy + bgh - 1 - y, bgw - corner_px * 2, 1);
            y += 1;
          );

          // Ліва межа
          x = 0;
          loop(fade_px,
            alpha = bga * (x / max(fade_px, 1));
            gfx_set(bgc_r, bgc_g, bgc_b, alpha);
            gfx_fillrect(bg_cx + x, bg_cy + corner_px, 1, bgh - corner_px * 2);
            x += 1;
          );

          // Права межа
          x = 0;
          loop(fade_px,
            alpha = bga * (x / max(fade_px, 1));
            gfx_set(bgc_r, bgc_g, bgc_b, alpha);
            gfx_fillrect(bg_cx + bgw - 1 - x, bg_cy + corner_px, 1, bgh - corner_px * 2);
            x += 1;
          );

          // Кути: d > corner_px — не малюємо (вже прозорі після gfx_clear)
          y = 0;
          loop(corner_px,
            x = 0;
            loop(corner_px,
              dx = corner_px - x;
              dy = corner_px - y;
              d = sqrt(dx * dx + dy * dy);
              d <= corner_px ? (
                d <= corner_px - fade_px ? (
                  alpha = bga;
                ) : (
                  alpha = bga * (1 - (d - (corner_px - fade_px)) / max(fade_px, 1));
                );
                alpha < 0 ? alpha = 0;
                gfx_set(bgc_r, bgc_g, bgc_b, alpha);
                gfx_fillrect(bg_cx + x,           bg_cy + y,           1, 1);
                gfx_fillrect(bg_cx + bgw - 1 - x, bg_cy + y,           1, 1);
                gfx_fillrect(bg_cx + x,           bg_cy + bgh - 1 - y, 1, 1);
                gfx_fillrect(bg_cx + bgw - 1 - x, bg_cy + bgh - 1 - y, 1, 1);
              );
              x += 1;
            );
            y += 1;
          );

          gfx_dest = img_obj;
          blit_x = lbgx + bgw / 2 - bg_diag / 2;
          blit_y = lbgy + bgh / 2 - bg_diag / 2;
          gfx_a2 = 0;
          gfx_set(1, 1, 1, 1, 0x10000);
          gfx_rotoblit(img_bg, bg_rot * $pi / 180, blit_x, blit_y, bg_diag, bg_diag, 0, 0, bg_diag, bg_diag);
          gfx_img_free(img_bg);
        );

        // 13. Малюємо рядки з вирівнюванням
        cur_ly = ly;
        i = 0;
        line_start = 0;
        loop(src_len + 1,
          ch = (i < src_len) ? str_getchar(#text, i) : 10;
          (ch == 10 || ch == 13) ? (
            #line = "";
            copy_len = i - line_start;
            copy_len > 0 ? (
              j = 0;
              loop(copy_len,
                str_setchar(#line, j, str_getchar(#text, line_start + j));
                j += 1;
              );
              str_setchar(#line, copy_len, 0);
            );

            gfx_str_measure(#line, line_w, line_h);

            // Вирівнювання X для цього рядка
            align == 0 ? cur_lx = lx;
            align == 1 ? cur_lx = lx + (txtw - line_w) / 2;
            align == 2 ? cur_lx = lx + (txtw - line_w);

            // Тінь
            (sh_on > 0.5 && sh_a > 0) ? (
              gfx_a2 = 0;
              gfx_set(0, 0, 0, sh_a * fga);
              gfx_str_draw(#line, cur_lx + sh_x, cur_ly + sh_y);
            );

            // Контур
            (ol_on > 0.5 && outline_w > 0) ? (
              gfx_a2 = 0;
              gfx_set(outl_r, outl_g, outl_b, outl_a);
              oi = -outline_w;
              while(oi <= outline_w) (
                oj = -outline_w;
                while(oj <= outline_w) (
                  (oi != 0 || oj != 0) ? gfx_str_draw(#line, cur_lx + oi, cur_ly + oj);
                  oj += outline_w;
                );
                oi += outline_w;
              );
            );

            // Основний текст
            gfx_a2 = 0;
            gfx_set(fgc_r, fgc_g, fgc_b, fga);
            gfx_str_draw(#line, cur_lx, cur_ly);

            cur_ly += line_h;

            // Пропускаємо \r\n як одне
            (ch == 13 && i + 1 < src_len && str_getchar(#text, i + 1) == 10) ? (
              i += 1;
            );
            line_start = i + 1;
          );
          i += 1;
        );

        // 14. Повернення на основний canvas
        gfx_dest = -1;

        // 15. Рендер з поворотом
        final_x = obj_x1 + obj_w / 2 - obj_diag / 2;
        final_y = obj_y1 + obj_h / 2 - obj_diag / 2;
        gfx_set(1, 1, 1, 1, 0x10000);
        gfx_rotoblit(img_obj, rotate * $pi / 180, final_x, final_y, obj_diag, obj_diag, 0, 0, obj_diag, obj_diag);

        // 16. Очистка
        gfx_img_free(img_obj);
    ]=],
        custom_font,
        p.size or 0.065,
        math.floor((p.fontselect or 0) + 0.5),
        math.floor((p.fontstyle or 0) + 0.5),
        math.floor((p.underline or 0) + 0.5),
        p.xpos or 0.5,
        p.ypos or 0.98,
        p.fgc_r or 1.0,
        p.fgc_g or 1.0,
        p.fgc_b or 1.0,
        math.floor((p.align or 1) + 0.5),
        p.fga or 1.0,
        math.floor((p.bg_on or 0) + 0.5),
        p.bgypos or 0.5,
        p.bgxpos or 0.5,
        p.bgwidth or 1.0,
        p.bgheight or 1.0,
        p.bgc_r or 0.0,
        p.bgc_g or 0.0,
        p.bgc_b or 0.0,
        p.bga or 1.0,
        math.floor((p.ol_on or 0) + 0.5),
        math.floor((p.outline_w or 2) + 0.5),
        p.outl_r or 0.0,
        p.outl_g or 0.0,
        p.outl_b or 0.0,
        p.outl_a or 1.0,
        math.floor((p.sh_x or 5) + 0.5),
        math.floor((p.sh_y or 5) + 0.5),
        p.sh_a or 0.5,
        math.floor((p.sh_on or 1) + 0.5)
    )
end

--- Compact render for selected tracks
--- Packs all items from the selected track one after another onto a new
--- SUBASS_RENDER track (no gaps), copies FX, sets Time Selection, solos the track,
--- renders immediately to a WAV file chosen by the user, and embeds iXML metadata
--- with the original item positions for restoration on import.
function UTILS.compact_render()
    local sel_count = reaper.CountSelectedTracks(0)

    if sel_count == 0 then
        reaper.MB(T("CR_ERR_SELECT_TRACK"), T("COMPACT_RENDER"), 0)
        return
    end
    if sel_count > 1 then
        reaper.MB(
            T("CR_ERR_SELECT_ONE_T"),
            T("COMPACT_RENDER"), 0)
        return
    end

    local src_track  = reaper.GetSelectedTrack(0, 0)
    local _, trk_name = reaper.GetTrackName(src_track)
    if trk_name == "SUBASS_RENDER" then
        reaper.MB(T("CR_ERR_TRACK_SERVICE"), T("COMPACT_RENDER"), 0)
        return
    end
    local item_count = reaper.CountTrackMediaItems(src_track)

    if item_count == 0 then
        reaper.MB(T("CR_ERR_NO_MEDIA_ON_TRACK"), T("COMPACT_RENDER"), 0)
        return
    end

    -- ── 1. Determine Default Filename and Directory ──────────────────────
    local display_name = (cfg.dubber_name and cfg.dubber_name ~= "") and cfg.dubber_name or (os.getenv("USER") or os.getenv("USERNAME") or T("USER"))
    local _, proj_path = reaper.EnumProjects(-1)
    local proj_name = "Project"
    local default_dir = reaper.GetExtState(section_name, "compact_render_dir")
    if default_dir == "" then
        default_dir = "/Users"
        if proj_path and proj_path ~= "" then
            default_dir = proj_path:match("(.*)[/\\]") or "/Users"
        end
    end

    if proj_path and proj_path ~= "" then
        local filename = proj_path:match("([^/\\]+)$") or "Project"
        proj_name = filename:gsub("%.[Rr][Pp][Pp]$", ""):gsub("%.rpp$", ""):gsub("%.%w+$", "")
    end

    -- Clean names for safety in filenames
    local clean_user = display_name:gsub('[\\/:*?"<>|]', "_")
    local clean_proj = proj_name:gsub('[\\/:*?"<>|]', "_")
    local clean_trk = ""
    if trk_name and trk_name ~= "" and not trk_name:match("^Track %d+$") then
        clean_trk = "_" .. trk_name:gsub('[\\/:*?"<>|]', "_")
    end
    local default_filename = clean_user .. "_" .. clean_proj .. clean_trk .. "_compact.wav"
    local default_path = default_dir .. "/" .. default_filename

    -- ── 2. Ask user where to save the rendered WAV file ───────────────────
    local retval, file_path = reaper.JS_Dialog_BrowseForSaveFile(T("CR_SAVE_CR"), default_dir, default_filename, "WAV files (.wav)\0*.wav\0All Files (*.*)\0*.*\0")
    if retval ~= 1 or file_path == "" then
        return -- User cancelled
    end
    if not file_path:match("%.wav$") then file_path = file_path .. ".wav" end

    -- Зберігаємо шлях до папки для наступного рендеру в ExtState
    local new_dir = file_path:match("(.*)[/\\]")
    if new_dir then
        reaper.SetExtState(section_name, "compact_render_dir", new_dir, true)
    end

    -- Видаляємо існуючий файл перед рендером, якщо він є
    local f = io.open(file_path, "r")
    if f then
        f:close()
        os.remove(file_path)
    end

    reaper.Undo_BeginBlock()
    reaper.PreventUIRefresh(1)

    -- ── 3. Collect & sort items by position ───────────────────────────────
    local entries = {}
    for i = 0, item_count - 1 do
        local item = reaper.GetTrackMediaItem(src_track, i)
        if reaper.GetMediaItemInfo_Value(item, "B_MUTE") == 0 then
            table.insert(entries, {
                item = item,
                pos  = reaper.GetMediaItemInfo_Value(item, "D_POSITION"),
                len  = reaper.GetMediaItemInfo_Value(item, "D_LENGTH"),
            })
        end
    end
    table.sort(entries, function(a, b) return a.pos < b.pos end)

    -- ── 4. Зберігаємо стан кросфейдів та вимикаємо їх ─────────────────────
    local auto_xfade = reaper.GetToggleCommandState(40041) == 1
    if auto_xfade then
        reaper.Main_OnCommand(40041, 0) -- Toggle off
    end

    -- ── 5. Compact items on the source track ──────────────────────────────────
    local cursor = 0.0
    local metadata_items = {}
    
    for idx, e in ipairs(entries) do
        local src_item = e.item
        local src_take = reaper.GetActiveTake(src_item)
        local take_name = "Item"

        local src_startoffs = 0.0
        local playrate = 1.0
        local full_len = e.len
        if src_take then
            playrate = reaper.GetMediaItemTakeInfo_Value(src_take, "D_PLAYRATE")
            if playrate <= 0 then playrate = 1.0 end
            src_startoffs = reaper.GetMediaItemTakeInfo_Value(src_take, "D_STARTOFFS")
            local src_source = reaper.GetMediaItemTake_Source(src_take)
            if src_source then
                local source_len_sec = reaper.GetMediaSourceLength(src_source)
                full_len = source_len_sec / playrate
            end
            local _, tname = reaper.GetSetMediaItemTakeInfo_String(src_take, "P_NAME", "", false)
            if tname and tname ~= "" then take_name = tname end
        end

        local start_offset_project = src_startoffs / playrate
        local render_len = full_len  -- full source length from offset 0

        -- Capture fade values BEFORE zeroing them for metadata preservation
        local fade_in      = reaper.GetMediaItemInfo_Value(src_item, "D_FADEINLEN")
        local fade_out     = reaper.GetMediaItemInfo_Value(src_item, "D_FADEOUTLEN")
        local fade_in_auto = reaper.GetMediaItemInfo_Value(src_item, "D_FADEINLEN_AUTO")
        local fade_out_auto= reaper.GetMediaItemInfo_Value(src_item, "D_FADEOUTLEN_AUTO")

        reaper.SetMediaItemInfo_Value(src_item, "D_POSITION",       cursor)
        reaper.SetMediaItemInfo_Value(src_item, "D_LENGTH",         render_len)
        reaper.SetMediaItemInfo_Value(src_item, "D_FADEINLEN",      0)
        reaper.SetMediaItemInfo_Value(src_item, "D_FADEOUTLEN",     0)
        reaper.SetMediaItemInfo_Value(src_item, "D_FADEINLEN_AUTO", 0)
        reaper.SetMediaItemInfo_Value(src_item, "D_FADEOUTLEN_AUTO",0)
        -- Reset start offset to 0 so REAPER renders full source from the beginning.
        -- The original offset is preserved in metadata for restoration.
        if src_take then
            reaper.SetMediaItemTakeInfo_Value(src_take, "D_STARTOFFS", 0)
        end

        table.insert(metadata_items, {
            index        = idx,
            name         = take_name,
            compact_pos  = cursor,
            original_pos = e.pos,
            length       = e.len,
            start_offset = start_offset_project,
            full_length     = render_len,
            fade_in         = fade_in,
            fade_out        = fade_out,
            fade_in_auto    = fade_in_auto,
            fade_out_auto   = fade_out_auto
        })

        cursor = cursor + render_len
    end

    -- ── 6. Set Time Selection from 0 to end of last item ──────────────────
    reaper.GetSet_LoopTimeRange(true, false, 0.0, cursor, false)

    -- ── 7. Solo: clear all tracks, solo only the source track ────────────
    for i = 0, reaper.CountTracks(0) - 1 do
        reaper.SetMediaTrackInfo_Value(reaper.GetTrack(0, i), "I_SOLO", 0)
    end
    reaper.SetMediaTrackInfo_Value(src_track, "I_SOLO", 1)

    -- ── 11. Render settings: Time Selection + WAV format + 48000Hz mono ───
    reaper.GetSetProjectInfo(0, "RENDER_BOUNDSFLAG", 2, true) -- Time Selection
    reaper.GetSetProjectInfo(0, "RENDER_SRATE", 48000, true)  -- 48000 Hz
    reaper.GetSetProjectInfo(0, "RENDER_CHANNELS", 1, true)   -- Mono
    
    -- Extract directory and filename to set RENDER_FILE (directory) and RENDER_PATTERN (filename) correctly
    local out_dir = file_path:match("(.*)[/\\]") or ""
    local out_file = file_path:match("([^/\\]+)$") or "compact"
    local out_file_no_ext = out_file:gsub("%.[Ww][Aa][Vv]$", "")

    reaper.GetSetProjectInfo_String(0, "RENDER_FILE", out_dir, true)
    reaper.GetSetProjectInfo_String(0, "RENDER_PATTERN", out_file_no_ext, true)

    -- WAV PCM 24-bit format chunk
    reaper.GetSetProjectInfo_String(0, "RENDER_FORMAT", "evaw\1\0\0\0\255\0\0\0", true)

    -- ── 12. Refresh UI ──────
    reaper.PreventUIRefresh(-1)
    reaper.TrackList_AdjustWindows(false)
    reaper.UpdateArrange()

    reaper.Undo_EndBlock(T("COMPACT_RENDER") .. ": " .. trk_name, -1)

    -- ── 13. Perform Render ────────────────────────────────────────────────
    -- File: Render project, using the most recent render settings (silent/immediate)
    reaper.Main_OnCommand(41824, 0)

    -- ── 14. Embed iXML metadata into the rendered WAV file ────────────────
    -- Prepare XML payload
    local xml_parts = {
        '<?xml version="1.0" encoding="UTF-8"?>',
        '<SUBASS_METADATA>',
        '  <SOURCE_TRACK>' .. trk_name:gsub("[<&>]", {["<"]="&lt;", [">"]="&gt;", ["&"]="&amp;"}) .. '</SOURCE_TRACK>',
        '  <ITEMS_COUNT>' .. #metadata_items .. '</ITEMS_COUNT>',
        '  <ITEMS>'
    }
    for _, item in ipairs(metadata_items) do
        table.insert(xml_parts, '    <ITEM>')
        table.insert(xml_parts, '      <INDEX>' .. item.index .. '</INDEX>')
        table.insert(xml_parts, '      <NAME>' .. item.name:gsub("[<&>]", {["<"]="&lt;", [">"]="&gt;", ["&"]="&amp;"}) .. '</NAME>')
        table.insert(xml_parts, '      <COMPACT_POS>' .. string.format("%.6f", item.compact_pos) .. '</COMPACT_POS>')
        table.insert(xml_parts, '      <ORIGINAL_POS>' .. string.format("%.6f", item.original_pos) .. '</ORIGINAL_POS>')
        table.insert(xml_parts, '      <LENGTH>' .. string.format("%.6f", item.length) .. '</LENGTH>')
        table.insert(xml_parts, '      <START_OFFSET>' .. string.format("%.6f", item.start_offset or 0) .. '</START_OFFSET>')
        table.insert(xml_parts, '      <FULL_LENGTH>' .. string.format("%.6f", item.full_length or item.length) .. '</FULL_LENGTH>')
        table.insert(xml_parts, '      <FADE_IN>'       .. string.format("%.6f", item.fade_in       or 0.0) .. '</FADE_IN>')
        table.insert(xml_parts, '      <FADE_OUT>'      .. string.format("%.6f", item.fade_out      or 0.0) .. '</FADE_OUT>')
        table.insert(xml_parts, '      <FADE_IN_AUTO>'  .. string.format("%.6f", item.fade_in_auto  or 0.0) .. '</FADE_IN_AUTO>')
        table.insert(xml_parts, '      <FADE_OUT_AUTO>' .. string.format("%.6f", item.fade_out_auto or 0.0) .. '</FADE_OUT_AUTO>')
        table.insert(xml_parts, '    </ITEM>')
    end
    table.insert(xml_parts, '  </ITEMS>')
    table.insert(xml_parts, '</SUBASS_METADATA>')
    local xml_data = table.concat(xml_parts, "\n")

    -- Define the iXML WAV embedding function
    local function append_ixml_to_wav(filepath, xml_str)
        local f, err = io.open(filepath, "r+b")
        if not f then
            return false, T("CR_UNABLE_OPEN_TO_WRITE_META") .. tostring(err)
        end

        local header = f:read(12)
        if not header or #header < 12 then
            f:close()
            return false, T("INVALID_WAV_FORMAT_SHORT")
        end

        local riff_sig = header:sub(1, 4)
        local wave_sig = header:sub(9, 12)
        if riff_sig ~= "RIFF" or wave_sig ~= "WAVE" then
            f:close()
            return false, T("THE_FILE_IS_NOT_VALID_WAV")
        end

        -- Get current RIFF payload size (bytes 5-8, little-endian)
        local b1, b2, b3, b4 = header:byte(5, 8)
        local old_riff_size = b1 + b2 * 256 + b3 * 65536 + b4 * 16777216

        f:seek("end")
        local file_size = f:seek()

        local xml_len = #xml_str
        local chunk_id = "iXML"

        -- Convert length to 4 bytes little-endian
        local temp = xml_len
        local cb1 = temp % 256
        temp = (temp - cb1) / 256
        local cb2 = temp % 256
        temp = (temp - cb2) / 256
        local cb3 = temp % 256
        temp = (temp - cb3) / 256
        local cb4 = temp % 256
        local size_bytes = string.char(cb1, cb2, cb3, cb4)

        f:write(chunk_id)
        f:write(size_bytes)
        f:write(xml_str)

        local pad = 0
        if xml_len % 2 ~= 0 then
            f:write("\0")
            pad = 1
        end

        -- Update RIFF payload size (new size = old_size + 8 bytes for chunk header + xml_len + pad)
        local new_riff_size = old_riff_size + 8 + xml_len + pad
        f:seek("set", 4)
        local rb1 = new_riff_size % 256
        new_riff_size = (new_riff_size - rb1) / 256
        local rb2 = new_riff_size % 256
        new_riff_size = (new_riff_size - rb2) / 256
        local rb3 = new_riff_size % 256
        new_riff_size = (new_riff_size - rb3) / 256
        local rb4 = new_riff_size % 256
        local new_size_bytes = string.char(rb1, rb2, rb3, rb4)
        f:write(new_size_bytes)

        f:close()
        return true
    end

    -- ── 15. Restore original item positions via Undo ────────────────────────
    -- Undo the item-shift block so all items return to their original positions
    reaper.Main_OnCommand(40029, 0) -- Edit: Undo
    
    -- Restore global auto-crossfade toggle if it was on
    if auto_xfade and reaper.GetToggleCommandState(40041) == 0 then
        reaper.Main_OnCommand(40041, 0) -- Toggle back on
    end

    -- Force REAPER to redraw the arrange view after undo, prevents UI freeze
    reaper.PreventUIRefresh(-1)
    reaper.TrackList_AdjustWindows(false)
    reaper.UpdateArrange()

    -- Run embedding
    local ok, err = append_ixml_to_wav(file_path, xml_data)
    if ok then
        show_snackbar(T("CR_SUCC_DONE"), "success")
    else
        reaper.MB(T("CR_COMPLETE_BUT_ERR_SAVE_META") .. tostring(err), T("COMPACT_RENDER"), 0)
    end
end

-- ── Helpers for parsing/reading compact render iXML metadata ─────────────

function UTILS.read_ixml_from_wav(filepath)
    local f, err = io.open(filepath, "rb")
    if not f then
        return nil, T("UNABLE_TO_OPEN_FILE") .. ": " .. tostring(err)
    end

    local header = f:read(12)
    if not header or #header < 12 then
        f:close()
        return nil, T("INVALID_WAV_FORMAT_SHORT")
    end

    local riff_sig = header:sub(1, 4)
    local wave_sig = header:sub(9, 12)
    if riff_sig ~= "RIFF" or wave_sig ~= "WAVE" then
        f:close()
        return nil, T("THE_FILE_IS_NOT_VALID_WAV")
    end

    while true do
        local chunk_header = f:read(8)
        if not chunk_header or #chunk_header < 8 then
            break
        end

        local chunk_id = chunk_header:sub(1, 4)
        local cb1, cb2, cb3, cb4 = chunk_header:byte(5, 8)
        local chunk_size = cb1 + cb2 * 256 + cb3 * 65536 + cb4 * 16777216

        if chunk_id == "iXML" then
            local xml_data = f:read(chunk_size)
            f:close()
            if not xml_data or #xml_data < chunk_size then
                return nil, T("ERR_READ_IXML_DATA")
            end
            return xml_data
        else
            local seek_offset = chunk_size
            if chunk_size % 2 ~= 0 then
                seek_offset = seek_offset + 1
            end
            local current = f:seek("cur", seek_offset)
            if not current then
                break
            end
        end
    end

    f:close()
    return nil, T("ERR_NO_IXML_FOUND_IN_FILE")
end

function UTILS.parse_subass_xml(xml_str)
    if not xml_str:find("<SUBASS_METADATA>") then
        return nil, nil, T("NO_SUBASS_META_IN_FILE")
    end
    local items = {}
    local trk_name = xml_str:match("<SOURCE_TRACK>(.-)</SOURCE_TRACK>") or "Restored Track"
    trk_name = trk_name:gsub("&lt;", "<"):gsub("&gt;", ">"):gsub("&amp;", "&")

    for item_xml in xml_str:gmatch("<ITEM>(.-)</ITEM>") do
        local index = tonumber(item_xml:match("<INDEX>(.-)</INDEX>")) or 0
        local name = item_xml:match("<NAME>(.-)</NAME>") or "Item"
        name = name:gsub("&lt;", "<"):gsub("&gt;", ">"):gsub("&amp;", "&")
        local compact_pos  = tonumber(item_xml:match("<COMPACT_POS>(.-)</COMPACT_POS>"))   or 0.0
        local original_pos = tonumber(item_xml:match("<ORIGINAL_POS>(.-)</ORIGINAL_POS>")) or 0.0
        local length       = tonumber(item_xml:match("<LENGTH>(.-)</LENGTH>"))             or 0.0
        local start_offset = tonumber(item_xml:match("<START_OFFSET>(.-)</START_OFFSET>")) or 0.0
        local full_length  = tonumber(item_xml:match("<FULL_LENGTH>(.-)</FULL_LENGTH>"))   or length
        local fade_in      = tonumber(item_xml:match("<FADE_IN>(.-)</FADE_IN>"))           or 0.0
        local fade_out     = tonumber(item_xml:match("<FADE_OUT>(.-)</FADE_OUT>"))          or 0.0
        local fade_in_auto = tonumber(item_xml:match("<FADE_IN_AUTO>(.-)</FADE_IN_AUTO>"))  or 0.0
        local fade_out_auto= tonumber(item_xml:match("<FADE_OUT_AUTO>(.-)</FADE_OUT_AUTO>"))or 0.0
        table.insert(items, {
            index         = index,
            name          = name,
            compact_pos   = compact_pos,
            original_pos  = original_pos,
            length        = length,
            start_offset  = start_offset,
            full_length   = full_length,
            fade_in       = fade_in,
            fade_out      = fade_out,
            fade_in_auto  = fade_in_auto,
            fade_out_auto = fade_out_auto
        })
    end
    return trk_name, items
end

function UTILS.reconstruct_compact_render(file_path, parent_track)
    local proj_path = reaper.GetProjectPath("")
    if proj_path and proj_path ~= "" then
        local filename = file_path:match("([^/\\]+)$")
        if filename then
            local new_path = proj_path .. "/" .. filename
            if file_path:gsub("\\", "/") ~= new_path:gsub("\\", "/") then
                local in_file = io.open(file_path, "rb")
                if in_file then
                    local out_file = io.open(new_path, "wb")
                    if out_file then
                        while true do
                            local block = in_file:read(65536)
                            if not block then break end
                            out_file:write(block)
                        end
                        out_file:close()
                        file_path = new_path
                    end
                    in_file:close()
                end
            end
        end
    end

    local xml_data, err = UTILS.read_ixml_from_wav(file_path)
    if not xml_data then
        return false, err
    end

    local trk_name, metadata_items = UTILS.parse_subass_xml(xml_data)
    if not metadata_items then
        return false, trk_name or T("UNABLE_PARSE_METADATA")
    end

    if #metadata_items == 0 then
        return false, T("NO_RECORDS_IN_META_FOUND")
    end

    -- Sort items chronologically by original position
    table.sort(metadata_items, function(a, b) return a.original_pos < b.original_pos end)

    reaper.PreventUIRefresh(1)

    -- Determine where to insert the track
    local dest_idx = reaper.CountTracks(0)
    local parent_color = 0
    if parent_track then
        local parent_idx = reaper.GetMediaTrackInfo_Value(parent_track, "IP_TRACKNUMBER") -- 1-based
        reaper.InsertTrackAtIndex(parent_idx, true)
        dest_idx = parent_idx
        parent_color = reaper.GetTrackColor(parent_track)
    else
        reaper.InsertTrackAtIndex(dest_idx, true)
    end

    local filename = file_path:match("([^/\\]+)$") or "compact"
    local track_name = filename:gsub("%.[Ww][Aa][Vv]$", "")

    local dest_track = reaper.GetTrack(0, dest_idx)
    reaper.GetSetMediaTrackInfo_String(dest_track, "P_NAME", track_name, true)
    if parent_color ~= 0 then
        reaper.SetTrackColor(dest_track, parent_color)
    end

    local created_items = {}
    for _, info in ipairs(metadata_items) do
        local new_item = reaper.AddMediaItemToTrack(dest_track)
        reaper.SetMediaItemInfo_Value(new_item, "D_POSITION", info.original_pos)
        reaper.SetMediaItemInfo_Value(new_item, "D_LENGTH",   info.length)
        -- Restore original manual fade-in / fade-out values
        if (info.fade_in or 0) > 0 then
            reaper.SetMediaItemInfo_Value(new_item, "D_FADEINLEN",      info.fade_in)
        end
        if (info.fade_out or 0) > 0 then
            reaper.SetMediaItemInfo_Value(new_item, "D_FADEOUTLEN",     info.fade_out)
        end
        -- Restore automatic crossfade lengths
        if (info.fade_in_auto or 0) > 0 then
            reaper.SetMediaItemInfo_Value(new_item, "D_FADEINLEN_AUTO",  info.fade_in_auto)
        end
        if (info.fade_out_auto or 0) > 0 then
            reaper.SetMediaItemInfo_Value(new_item, "D_FADEOUTLEN_AUTO", info.fade_out_auto)
        end

        local new_take = reaper.AddTakeToMediaItem(new_item)
        local source = reaper.PCM_Source_CreateFromFile(file_path)
        reaper.SetMediaItemTake_Source(new_take, source)
        
        -- Обмежуємо джерело до розмірів оригінального айтема (Section Source)
        local _, chunk = reaper.GetItemStateChunk(new_item, "", false)
        local pattern = "(<SOURCE WAVE.->)"
        local replacement = string.format("<SOURCE SECTION\nLENGTH %.6f\nSTARTPOS %.6f\nOVERLAP 0\n%%1\n>", info.full_length, info.compact_pos)
        chunk = string.gsub(chunk, pattern, replacement, 1)
        reaper.SetItemStateChunk(new_item, chunk, false)

        local start_offset = info.start_offset or 0.0
        -- Тепер D_STARTOFFS рахується відносно початку нашої секції
        reaper.SetMediaItemTakeInfo_Value(new_take, "D_STARTOFFS", start_offset)
        reaper.GetSetMediaItemTakeInfo_String(new_take, "P_NAME", info.name, true)

        reaper.UpdateItemInProject(new_item)
    end

    reaper.PreventUIRefresh(-1)

    reaper.SetOnlyTrackSelected(dest_track)
    reaper.TrackList_AdjustWindows(false)
    reaper.UpdateArrange()

    return true, T("UNPUCK_CR_MSG_1") .. #metadata_items .. T("UNPUCK_CR_MSG_2") .. track_name .. "'!"
end

function UTILS.import_compact_wav(dropped_file)
    reaper.Undo_BeginBlock()
    local ok, msg = UTILS.reconstruct_compact_render(dropped_file, nil)
    if ok then
        reaper.Undo_EndBlock(T("IMPORT_OF_COMPACT_RENDER_DG"), -1)
        show_snackbar(msg, "success")
        return true
    else
        reaper.Undo_EndBlock(T("IMPORT_OF_COMPACT_RENDER_DG"), -1)
        return false, msg
    end
end

--- LUFS Normalization (ITU-R BS.1770-4 via SWS Extension)
--- Uses true LUFS measurement with K-weighting and integrated gating.
--- Includes "De-Boomer" spectral correction (cuts only) for muddy voices.
--- 
--- ADAPTIVE GAIN LIMITING:
--- Short clips naturally measure lower LUFS (less integration time).
--- To prevent over-amplification, gain is limited relative to LONG CLIPS median (>=2s):
---   - <0.5s clips: max 120% of long clips median gain
---   - 0.5-2s clips: max 150% of long clips median gain  
---   - >2s clips: max 250% of long clips median gain
--- This uses dialogue as baseline, preventing short clips from skewing the reference.
local function ebu_r128_replicas_normalize()
    -- Check SWS Extension availability
    if not reaper.APIExists("NF_AnalyzeTakeLoudness_IntegratedOnly") then
        show_snackbar(T("EBU_ERR_SWS_1"), "error")
        reaper.MB(T("EBU_ERR_SWS_2"), T("EBU_ERR_SWS_3"), 0)
        return
    end

    local items = {}
    local sel_item_count = reaper.CountSelectedMediaItems(0)
    
    if sel_item_count > 0 then
        for i = 0, sel_item_count - 1 do
            table.insert(items, reaper.GetSelectedMediaItem(0, i))
        end
    else
        local track_count = reaper.CountSelectedTracks(0)
        if track_count > 0 then
            local processed_tracks = {}
            for i = 0, track_count - 1 do
                local track = reaper.GetSelectedTrack(0, i)
                if not processed_tracks[track] then
                    processed_tracks[track] = true
                    local depth = reaper.GetTrackDepth(track)
                    local track_idx = reaper.GetMediaTrackInfo_Value(track, "IP_TRACKNUMBER")
                    local total_tracks = reaper.CountTracks(0)
                    for j = track_idx, total_tracks - 1 do
                        local child = reaper.GetTrack(0, j)
                        if child and reaper.GetTrackDepth(child) > depth then
                            processed_tracks[child] = true
                        else break end
                    end
                end
            end
            for tr in pairs(processed_tracks) do
                local track_item_count = reaper.CountTrackMediaItems(tr)
                for j = 0, track_item_count - 1 do
                    table.insert(items, reaper.GetTrackMediaItem(tr, j))
                end
            end
        end
    end

    if #items == 0 then
        show_snackbar(T("EBU_SELECT_M_ITEMS_T"), "error")
        return
    end

    local last_val = reaper.GetExtState(section_name, "lufs_norm_target")
    if last_val == "" then last_val = "-20.0" end

    local ok, ret_val = reaper.GetUserInputs(T("EBU_DIALOG_S_1"), 1, T("EBU_DIALOG_S_2"), last_val)
    if not ok then return end
    
    local target_lufs = tonumber(ret_val)
    if not target_lufs or target_lufs > -5 or target_lufs < -40 then
        show_snackbar(T("EBU_DIALOG_ERR_1"), "error")
        return
    end
    
    reaper.SetExtState(section_name, "lufs_norm_target", tostring(target_lufs), true)

    local start_time = reaper.time_precise()

    -- Helper: Measures spectral balance for De-Boomer AND robust RMS for peak handling
    local function analyze_take_structure(take)
        local source = reaper.GetMediaItemTake_Source(take)
        if not source then return -100, -100 end
        local samplerate = reaper.GetMediaSourceSampleRate(source)
        if not samplerate or samplerate < 1 then return -100, -100 end
        local accessor = reaper.CreateTakeAudioAccessor(take)
        local starttime = reaper.GetAudioAccessorStartTime(accessor)
        local endtime = reaper.GetAudioAccessorEndTime(accessor)
        local duration = endtime - starttime
        
        if duration <= 0 then reaper.DestroyAudioAccessor(accessor); return -100, -100 end
        if duration > 60 then duration = 60 end 

        local chunk_size_ms = 0.050 -- 50ms window
        local samples_per_chunk = math.floor(samplerate * chunk_size_ms)
        local buf = reaper.new_array(samples_per_chunk)
        
        -- Highpass Filter State (for presence analysis)
        local xp, yp = 0, 0
        local alpha = 0.93 -- ~500Hz HPF at 44.1k
        
        local bp_energy_sum = 0
        local chunk_count = 0
        local rms_list = {}
        local total_chunks = math.floor(duration / chunk_size_ms)
        
        if total_chunks < 1 then reaper.DestroyAudioAccessor(accessor); return -100, -100 end

        for i = 0, total_chunks - 1 do
            local t = i * chunk_size_ms
            reaper.GetAudioAccessorSamples(accessor, samplerate, 1, t, samples_per_chunk, buf)
            
            local bp_chunk_sum = 0
            local raw_chunk_sum = 0
            for j = 1, samples_per_chunk do
                local x = buf[j]
                raw_chunk_sum = raw_chunk_sum + (x*x)
                -- Highpass Energy (Presence)
                local y = x - xp + (alpha * yp)
                xp, yp = x, y
                bp_chunk_sum = bp_chunk_sum + (y*y)
            end
            
            bp_energy_sum = bp_energy_sum + bp_chunk_sum
            chunk_count = chunk_count + 1
            
            local rms = math.sqrt(raw_chunk_sum / samples_per_chunk)
            if rms > 0.001 then -- Gate -60dB
                table.insert(rms_list, 20 * math.log(rms, 10))
            end
        end
        reaper.DestroyAudioAccessor(accessor)

        if chunk_count == 0 then return -100, -100 end
        
        local avg_bp_energy = bp_energy_sum / (chunk_count * samples_per_chunk)
        local bp_db = 20 * math.log(math.sqrt(avg_bp_energy), 10)
        
        local median_rms = -100
        if #rms_list > 0 then
            table.sort(rms_list)
            median_rms = rms_list[math.ceil(#rms_list * 0.5)]
        end
        return bp_db, median_rms
    end

    reaper.Undo_BeginBlock()
    reaper.ShowConsoleMsg("═══════════════════════════════════════════\n")
    reaper.ShowConsoleMsg("[LUFS Normalization] Batch analyzing...\n")
    reaper.ShowConsoleMsg("═══════════════════════════════════════════\n\n")
    
    -- OPTIMIZATION: Batch LUFS Analysis via Reverse Engineering
    -- Instead of calling NF_AnalyzeTakeLoudness_IntegratedOnly 500 times (500 popup windows),
    -- we use SWS batch normalization to -23 LUFS, then calculate original LUFS from gain applied
    
    local track_groups = {}
    local normalized_count = 0
    
    -- Step 1: Save original volumes and prepare items
    reaper.ShowConsoleMsg(string.format("Preparing %d items for batch analysis...\n", #items))
    local take_data = {}
    
    for i = 1, #items do
        local item = items[i]
        local take = reaper.GetActiveTake(item)
        if take then
            local track = reaper.GetMediaItem_Track(item)
            
            -- Save original volumes (both take and item)
            local original_take_vol = reaper.GetMediaItemTakeInfo_Value(take, "D_VOL")
            local original_item_vol = reaper.GetMediaItemInfo_Value(item, "D_VOL")
            
            table.insert(take_data, {
                take = take,
                item = item,
                track = track,
                original_take_vol = original_take_vol,
                original_item_vol = original_item_vol,
                len = reaper.GetMediaItemInfo_Value(item, "D_LENGTH")
            })
            
            -- Reset both volumes to 1.0 (0 dB) for consistent measurement
            reaper.SetMediaItemTakeInfo_Value(take, "D_VOL", 1.0)
            reaper.SetMediaItemInfo_Value(item, "D_VOL", 1.0)
        end
    end
    
    -- Step 2: Select all items for batch normalization
    reaper.PreventUIRefresh(1)
    reaper.SelectAllMediaItems(0, false)
    for i = 1, #items do
        reaper.SetMediaItemSelected(items[i], true)
    end
    
    -- Step 3: Run SWS batch normalization to -23 LUFS
    -- This will analyze all items and normalize them in one operation
    reaper.ShowConsoleMsg("Running SWS batch LUFS analysis (this may take a moment)...\n")
    
    local sws_cmd = reaper.NamedCommandLookup("_BR_NORMALIZE_LOUDNESS_ITEMS23")
    if not sws_cmd or sws_cmd == 0 then
        -- Try alternative command names
        sws_cmd = reaper.NamedCommandLookup("_SWS_AWLOUDNORM")
    end
    
    if sws_cmd and sws_cmd > 0 then
        reaper.Main_OnCommand(sws_cmd, 0)
        reaper.ShowConsoleMsg("Batch analysis complete. Calculating LUFS values...\n\n")
    else
        -- Fallback to individual analysis if batch command not found
        reaper.ShowConsoleMsg("⚠️ SWS batch command not found. Using individual analysis...\n\n")
        reaper.PreventUIRefresh(-1)
        
        for i = 1, #take_data do
            local data = take_data[i]
            local take = data.take
            local track = data.track
            
            if not track_groups[track] then 
                track_groups[track] = { items = {}, bp_sum = 0, bp_cnt = 0 } 
            end
            
            -- Individual analysis (fallback)
            local retval, lufs = reaper.NF_AnalyzeTakeLoudness_IntegratedOnly(take)
            
            if not retval then
                reaper.ShowConsoleMsg("\n⚠️ Analysis cancelled.\n")
                show_snackbar(T("EBU_HB_INTERRAP"), "error")
                -- Restore original volumes (both take and item)
                for _, d in ipairs(take_data) do
                    reaper.SetMediaItemTakeInfo_Value(d.take, "D_VOL", d.original_take_vol)
                    reaper.SetMediaItemInfo_Value(d.item, "D_VOL", d.original_item_vol)
                end
                reaper.Undo_EndBlock("LUFS Normalization (Cancelled)", -1)
                return
            end

            local bp_db, median_rms = analyze_take_structure(take)
            
            -- Reset volumes to 1.0 for our custom normalization
            reaper.SetMediaItemTakeInfo_Value(take, "D_VOL", 1.0)
            reaper.SetMediaItemInfo_Value(data.item, "D_VOL", 1.0)
            
            if lufs and lufs > -100 then
                local item_data = {
                    take = take,
                    item = data.item,
                    lufs = lufs, 
                    bp_db = bp_db, 
                    med_rms = median_rms,
                    len = data.len
                }
                table.insert(track_groups[track].items, item_data)
                
                track_groups[track].bp_sum = track_groups[track].bp_sum + bp_db
                track_groups[track].bp_cnt = track_groups[track].bp_cnt + 1
            end
            
            if i % 50 == 0 or i == #take_data then
                local progress_pct = (i / #take_data) * 100
                reaper.ShowConsoleMsg(string.format("Progress: %d/%d (%.1f%%)\n", i, #take_data, progress_pct))
            end
        end
        
        goto skip_batch_processing
    end
    
    -- Step 4: Calculate original LUFS from applied gain
    -- Formula: original_LUFS = -23 - gain_applied_db
    -- where gain_applied_db = 20 * log10(new_volume / 1.0)
    
    for i = 1, #take_data do
        local data = take_data[i]
        local take = data.take
        local track = data.track
        
        if not track_groups[track] then 
            track_groups[track] = { items = {}, bp_sum = 0, bp_cnt = 0 } 
        end
        
        -- Read the volume after SWS normalization
        local normalized_vol = reaper.GetMediaItemTakeInfo_Value(take, "D_VOL")
        
        -- Calculate the gain that was applied (in dB)
        local gain_applied_db = 20 * math.log(normalized_vol, 10)
        
        -- Reverse-engineer the original LUFS
        -- If SWS applied +6dB to reach -23 LUFS, original was -29 LUFS
        local original_lufs = -23.0 - gain_applied_db
        
        -- Analyze spectral structure for De-Boomer
        local bp_db, median_rms = analyze_take_structure(take)
        
        -- Reset volumes to 1.0 for our custom normalization
        -- (We don't restore old volumes - we want to apply our own normalization)
        reaper.SetMediaItemTakeInfo_Value(take, "D_VOL", 1.0)
        reaper.SetMediaItemInfo_Value(data.item, "D_VOL", 1.0)
        
        if original_lufs > -100 then
            local item_data = {
                take = take,
                item = data.item,
                lufs = original_lufs, 
                bp_db = bp_db, 
                med_rms = median_rms,
                len = data.len
            }
            table.insert(track_groups[track].items, item_data)
            
            track_groups[track].bp_sum = track_groups[track].bp_sum + bp_db
            track_groups[track].bp_cnt = track_groups[track].bp_cnt + 1
        end
        
        -- Progress tracking (silent - only final message shown)
    end
    
    ::skip_batch_processing::
    
    reaper.PreventUIRefresh(-1)
    reaper.ShowConsoleMsg("\nApplying custom normalization with De-Boomer...\n\n")
    
    -- PROCESS PER TRACK
    for track, group in pairs(track_groups) do
        -- A. Pre-calculate gains for ALL items to allow fast lookups
        -- structure: { pos = number, len = number, gain_needed = number, bp_db = number, is_anchor = boolean }
        local item_gains = {}
        for _, res in ipairs(group.items) do
            local gain = target_lufs - res.lufs
            -- Identify "Anchors" (Long reliable clips > 2.0s)
            local is_anchor = (res.len >= 2.0)
            table.insert(item_gains, {
                pos = reaper.GetMediaItemInfo_Value(res.item, "D_POSITION"),
                len = res.len,
                gain_needed = gain,
                bp_db = res.bp_db,
                is_anchor = is_anchor
            })
        end
        
        -- Helper: Find Median Gain AND Mean BP (Spectral) of ANCHORS within time window
        local function get_local_context(center_pos, window_sec)
            local local_gains = {}
            local local_bp_sum = 0
            local local_bp_cnt = 0
            
            for _, d in ipairs(item_gains) do
                if d.is_anchor then
                    local dist = math.abs(d.pos - center_pos)
                    if dist <= window_sec then
                        table.insert(local_gains, d.gain_needed)
                        if d.bp_db > -100 then
                            local_bp_sum = local_bp_sum + d.bp_db
                            local_bp_cnt = local_bp_cnt + 1
                        end
                    end
                end
            end
            
            if #local_gains == 0 then return nil, nil end
            table.sort(local_gains)
            local median_gain = local_gains[math.floor(#local_gains * 0.5) + 1]
            local mean_bp = (local_bp_cnt > 0) and (local_bp_sum / local_bp_cnt) or -100
            
            return median_gain, mean_bp
        end

        -- Fallback: Global context
        local global_gains = {}
        local global_bp_sum = 0
        local global_bp_cnt = 0
        for _, d in ipairs(item_gains) do
            if d.is_anchor then 
                table.insert(global_gains, d.gain_needed)
                if d.bp_db > -100 then
                    global_bp_sum = global_bp_sum + d.bp_db
                    global_bp_cnt = global_bp_cnt + 1
                end
            end
        end
        table.sort(global_gains)
        local global_median = global_gains[math.floor(#global_gains * 0.5) + 1] or 0
        local global_mean_bp = (global_bp_cnt > 0) and (global_bp_sum / global_bp_cnt) or -100

        
        -- B. Apply Normalization with Relative Logic
        local track_stats = { norm=0, noise=0, boom=0, gain_sum=0 }
        
        for i, res in ipairs(group.items) do
            local gain_db = 0
            local classification = "Normal"
            local correction_db = 0
            
            -- Find Local Context (Window +/- 60s)
            local item_pos = reaper.GetMediaItemInfo_Value(res.item, "D_POSITION")
            local anchor_gain, anchor_bp = get_local_context(item_pos, 60.0)
            
            -- Fallbacks
            if not anchor_gain then anchor_gain, anchor_bp = get_local_context(item_pos, 120.0) end
            if not anchor_gain then anchor_gain, anchor_bp = global_median, global_mean_bp end
            
            -- SAFETY GATE: Ultra-low threshold (Capture all intentional sounds like breaths/hm)
            local noise_gate = -78.0
            if res.lufs < noise_gate then
                gain_db = 0.0
                classification = "Ignored (Silence)"
                track_stats.noise = track_stats.noise + 1
            else
                -- Gain Logic
                if res.len < 0.5 then
                    gain_db = anchor_gain
                    classification = "Breath (Rel)"
                elseif res.len < 2.0 then
                    local target_gain = target_lufs - res.lufs
                    local deviation = target_gain - anchor_gain
                    
                    -- Hybrid: stay close to dialogue scale (+/- 4dB)
                    local hybrid_gain = target_gain
                    if deviation > 5.0 then hybrid_gain = anchor_gain + 5.0 end
                    if deviation < -5.0 then hybrid_gain = anchor_gain - 5.0 end
                    
                    -- SAFETY: Hybrid gain should NOT push short clips way above target LUFS
                    -- (Limit overshoot to +1.5dB relative to strict target)
                    if hybrid_gain > target_gain + 1.5 then 
                        hybrid_gain = target_gain + 1.5 
                    end
                    
                    gain_db = hybrid_gain
                    classification = "Short (Hyb)"
                else
                    gain_db = target_lufs - res.lufs
                    classification = "Long (Strict)"
                end
                
                -- De-Boomer (Local Context)
                if anchor_bp and anchor_bp > -100 then
                    local presence_diff = anchor_bp - res.bp_db 
                    if presence_diff > 0 then
                        correction_db = presence_diff * 0.15 
                        if correction_db > 6.0 then correction_db = 6.0 end
                        if correction_db > 0.5 then track_stats.boom = track_stats.boom + 1 end
                    end
                end
                
                -- Only accumulate valid gain values
                local final_gain = gain_db - correction_db
                if final_gain == final_gain and final_gain ~= math.huge and final_gain ~= -math.huge then
                    track_stats.norm = track_stats.norm + 1
                    track_stats.gain_sum = track_stats.gain_sum + final_gain
                end
            end

            local final_vol = 10 ^ ((gain_db - correction_db) / 20)
            
            -- Safety limits
            if final_vol > 32.0 then final_vol = 32.0 end
            if final_vol < 0.01 then final_vol = 0.01 end
            
            reaper.SetMediaItemTakeInfo_Value(res.take, "D_VOL", final_vol)
            normalized_count = normalized_count + 1
        end
        
        -- Print Track Report
        local _, tr_name = reaper.GetTrackName(track)
        local avg_gain = (track_stats.norm > 0) and (track_stats.gain_sum / track_stats.norm) or 0
        local avg_sign = (avg_gain >= 0) and "+" or ""
        reaper.ShowConsoleMsg(string.format("TRACK: %s\n  Normalized: %d\n  Avg Gain: %s%.1fdB\n  Ignored (Noise): %d\n  De-Boomed: %d\n-----------------------\n", tr_name, track_stats.norm, avg_sign, avg_gain, track_stats.noise, track_stats.boom))
    end
    
    local elapsed = reaper.time_precise() - start_time
    reaper.ShowConsoleMsg(string.format("═══════════════════════\nTOTAL: %d items normalized in %.2f seconds.\n", normalized_count, elapsed))
    reaper.UpdateArrange()
    reaper.Undo_EndBlock("LUFS Normalization (Track-Smart)", -1)
end

local function filter_unique_item_replicas()
    local track_count = reaper.CountSelectedTracks(0)
    if track_count ~= 2 then
        show_snackbar(T("FU_WAVE_SELECT_2"), "error")
        return
    end

    local tr1 = reaper.GetSelectedTrack(0, 0)
    local tr2 = reaper.GetSelectedTrack(0, 1)
    local _, tr1_name = reaper.GetTrackName(tr1)
    local _, tr2_name = reaper.GetTrackName(tr2)

    local msg = T("FU_WAVE_HOW_WORKS") ..
                "YES: " .. tr1_name .. "\n" ..
                "NO: " .. tr2_name .. "\n" ..
                "CANCEL: " .. T("CANCEL")
    local ret = reaper.ShowMessageBox(msg, T("FU_WAVE_S_MAIN_T"), 3)

    local main_tr, target_tr
    if ret == 6 then main_tr, target_tr = tr1, tr2
    elseif ret == 7 then main_tr, target_tr = tr2, tr1
    else return end

    reaper.ClearConsole()
    reaper.ShowConsoleMsg("Waveform Match Analysis (Track Mode)\n")
    reaper.ShowConsoleMsg("Main: " .. (ret == 6 and tr1_name or tr2_name) .. "\n")
    reaper.ShowConsoleMsg("Target: " .. (ret == 6 and tr2_name or tr1_name) .. "\n\n")

    -- Version 1.0 Health Check: Project Params
    local proj_sr = tonumber(reaper.format_timestr_pos(1, "", 4):match(".-(%d+)$")) or 44100
    reaper.ShowConsoleMsg("HEALTH: Project Sample Rate ~" .. proj_sr .. "Hz\n")

    -- Track Accessors
    local main_aa = reaper.CreateTrackAudioAccessor(main_tr)
    local target_aa = reaper.CreateTrackAudioAccessor(target_tr)
    
    if not main_aa or not target_aa then
        reaper.ShowConsoleMsg("ERROR: Could not create Track Audio Accessors.\n")
        if main_aa then reaper.DestroyAudioAccessor(main_aa) end
        if target_aa then reaper.DestroyAudioAccessor(target_aa) end
        return
    end

    local aa_start = reaper.GetAudioAccessorStartTime(main_aa)
    local aa_end = reaper.GetAudioAccessorEndTime(main_aa)
    reaper.ShowConsoleMsg("HEALTH: Track Accessor range: " .. string.format("%.1fs to %.1fs", aa_start, aa_end) .. "\n\n")

    -- Helper: Read signature from Track Accessor
    local function get_signature_from_track(aa, item, item_name)
        local item_pos = reaper.GetMediaItemInfo_Value(item, "D_POSITION")
        local item_len = reaper.GetMediaItemInfo_Value(item, "D_LENGTH")
        if item_len < 0.1 then return nil end

        local sr = 44100 -- Use standard SR for analysis (REAPER resamples)
        local channels = 1 -- Mono analysis is sufficient for signatures
        local sample_res = 0.01 -- 10ms intervals
        
        local raw_sig = {}
        local all_rms = {}
        local buf_samples = math.ceil(sample_res * sr)
        local buffer = reaper.new_array(buf_samples) -- Mono buffer
        
        local total_samples_read = 0
        local non_zero_chunks = 0

        for t = item_pos, item_pos + item_len - sample_res, sample_res do
            -- TrackAccessor reads in PROJECT time
            local r = reaper.GetAudioAccessorSamples(aa, sr, channels, t, buf_samples, buffer)
            
            local rms = 0
            if r > 0 then
                total_samples_read = total_samples_read + r
                local sum_sq = 0
                for j = 1, buf_samples do
                    local val = buffer[j]
                    sum_sq = sum_sq + (val * val)
                end
                rms = math.sqrt(sum_sq / buf_samples)
                if rms > 1e-7 then non_zero_chunks = non_zero_chunks + 1 end
            end
            table.insert(raw_sig, rms)
            table.insert(all_rms, rms)
        end

        if #all_rms == 0 or non_zero_chunks == 0 then 
            reaper.ShowConsoleMsg("DEBUG: '" .. item_name .. "' is SILENT (Read: " .. total_samples_read .. " samples at " .. string.format("%.2f", item_pos) .. "s)\n")
            return nil 
        end
        
        -- Apply Version 3.3 Dynamic Noise Logic
        local sorted_rms = {}
        for i=1, #all_rms do sorted_rms[i] = all_rms[i] end
        table.sort(sorted_rms)
        
        local floor_idx = math.max(1, math.floor(#sorted_rms * 0.1))
        local noise_floor = sorted_rms[floor_idx] or 0
        local max_rms = sorted_rms[#sorted_rms] or 0
        
        if max_rms <= noise_floor + 1e-6 then return nil end
        
        local range = max_rms - noise_floor
        local threshold = noise_floor + range * 0.03
        local start_idx, end_idx = 1, #raw_sig
        while start_idx < #raw_sig and raw_sig[start_idx] < threshold do start_idx = start_idx + 1 end
        while end_idx > start_idx and raw_sig[end_idx] < threshold do end_idx = end_idx - 1 end
        
        start_idx = math.max(1, start_idx - 2)
        end_idx = math.min(#raw_sig, end_idx + 2)
        
        if end_idx - start_idx < 5 then return nil end
        
        local sig = {}
        local trim_max = 0
        for i = start_idx, end_idx do
            local v = math.max(0, raw_sig[i] - noise_floor)
            table.insert(sig, v)
            if v > trim_max then trim_max = v end
        end
        
        if trim_max > 0 then
            for i = 1, #sig do sig[i] = sig[i] / trim_max end
        end
        
        return sig
    end

    local function compare_signatures(sig1, sig2)
        local n1, n2 = #sig1, #sig2
        local s, l = sig1, sig2
        if n1 > n2 then s, l = sig2, sig1 end
        local sn, ln = #s, #l
        if sn / ln < 0.2 then return 0 end

        local max_sim = 0
        local max_offset = ln - sn
        for offset = 0, max_offset do
            local dot, magS, magL = 0, 0, 0
            for i = 1, sn do
                local vS = s[i]
                local vL = l[offset + i]
                dot = dot + (vS * vL)
                magS = magS + (vS * vS)
                magL = magL + (vL * vL)
            end
            if magS > 1e-9 and magL > 1e-9 then
                local sim = dot / (math.sqrt(magS) * math.sqrt(magL))
                if sim > max_sim then max_sim = sim end
                if max_sim > 0.99 then break end 
            end
        end
        return max_sim
    end

    -- Process Main Track
    local main_sigs = {}
    local main_count = reaper.CountTrackMediaItems(main_tr)
    for i = 0, main_count - 1 do
        local item = reaper.GetTrackMediaItem(main_tr, i)
        local _, name = reaper.GetSetMediaItemTakeInfo_String(reaper.GetActiveTake(item), "P_NAME", "", false)
        local sig = get_signature_from_track(main_aa, item, name)
        if sig then table.insert(main_sigs, {sig = sig, name = name, used = false}) end
    end
    reaper.ShowConsoleMsg("HEALTH: Loaded " .. #main_sigs .. " signatures from main track.\n\n")

    -- Process Target Track
    local to_delete = {}
    local target_count = reaper.CountTrackMediaItems(target_tr)
    local global_max_sim = 0
    
    for i = 0, target_count - 1 do
        local item = reaper.GetTrackMediaItem(target_tr, i)
        local item_pos = reaper.GetMediaItemInfo_Value(item, "D_POSITION")
        local _, name = reaper.GetSetMediaItemTakeInfo_String(reaper.GetActiveTake(item), "P_NAME", "", false)
        local sig = get_signature_from_track(target_aa, item, name)
        
        if sig then
            local max_item_sim = 0
            local best_match_idx = -1
            for idx, m in ipairs(main_sigs) do
                if not m.used then
                    local sim = compare_signatures(sig, m.sig)
                    if sim > max_item_sim then 
                        max_item_sim = sim 
                        best_match_idx = idx
                    end
                    if sim > 0.96 then break end
                end
            end
            
            if max_item_sim > global_max_sim then global_max_sim = max_item_sim end
            
            local time_str = "[" .. format_timestamp(item_pos) .. "]"
            if max_item_sim > 0.96 then
                local m = main_sigs[best_match_idx]
                reaper.ShowConsoleMsg("MATCH " .. time_str .. ": '" .. name .. "' (" .. math.floor(max_item_sim*100) .. "%) matches '" .. m.name .. "'\n")
                m.used = true -- Consume the reference item (1-to-1 match)
                table.insert(to_delete, item)
            else
                local best_name = best_match_idx ~= -1 and main_sigs[best_match_idx].name or "N/A"
                reaper.ShowConsoleMsg("UNIQUE " .. time_str .. ": '" .. name .. "' (Best: " .. math.floor(max_item_sim*100) .. "% with '" .. best_name .. "')\n")
            end
        end
    end

    reaper.DestroyAudioAccessor(main_aa)
    reaper.DestroyAudioAccessor(target_aa)

    if #to_delete > 0 then
        push_undo(T("FU_WAVE_REMOVE_UNDO"))
        for _, item in ipairs(to_delete) do reaper.DeleteTrackMediaItem(target_tr, item) end
        reaper.UpdateArrange()
        show_snackbar(T("FU_WAVE_DONE_1") .. #to_delete .. T("FU_WAVE_DONE_2"), "success")
    else
        local pct = math.floor(global_max_sim * 100)
        show_snackbar(T("FU_WAVE_NO_DUP_FOUND") .. pct .. "%)", "info")
    end
end

--- Register plugin usage on first run (Fire-and-Forget)
--- @param callback function Optional callback on completion
--- @param is_silent boolean If true, don't show full-screen loader
--- @param profile_override table Optional table with profile fields to send instead of cfg
function STATS.register_plugin_usage(callback, is_silent, profile_override) 
    if is_silent == nil then is_silent = true end
    -- Build Python script path
    local source = debug.getinfo(1,'S').source
    local script_path = source:match([[^@?(.*[\\/])]]) or ""
    local full_script_path = script_path .. "stats/subass_extra_stats.py"
    
    -- Get or generate stable Machine ID
    local machine_id = reaper.GetExtState(section_name, "MachineID")
    if not machine_id or machine_id == "" then
        machine_id = reaper.genGuid("")
        machine_id = machine_id:gsub("[%{%}%-]", ""):lower()
        reaper.SetExtState(section_name, "MachineID", machine_id, true)
    end
    
    -- Serialize ACHIEVEMENTS.stats to a temp JSON file
    local stats_file_path = script_path .. "stats/subass_ach_stats.json"
    local p = profile_override or cfg
    local stats_json = STATS.json_encode({
        stats=ACHIEVEMENTS.stats,
        dubber_name=(p.dubber_name and p.dubber_name ~= "") and p.dubber_name or (os.getenv("USER") or os.getenv("USERNAME") or T("USER")),
        dubber_bio = p.dubber_bio or "",
        dubber_contact = p.dubber_contact or "",
        dubber_samples = p.dubber_samples or "",
        dubber_equipment = p.dubber_equipment or "",
        dubber_conditions = p.dubber_conditions or "",
        dubber_voice = p.dubber_voice or "",
        dubber_timbre = p.dubber_timbre or "",
        dubber_specialization = p.dubber_specialization or "",
        dubber_archetypes = p.dubber_archetypes or "",
        dubber_languages = p.dubber_languages or "",
        dubber_vocals = p.dubber_vocals or "",
        dubber_status = p.dubber_status or "Звичайний аккаунт",
    })

    local sf = io.open(stats_file_path, "w")
    if sf then
        sf:write(stats_json)
        sf:close()
    end
    
    -- Execute in background (Fire-and-Forget)
    local cmd = string.format('python3 "%s" --register --script_title "%s" --machine_id "%s" --stats-file "%s"', 
                                full_script_path, GL.script_title, machine_id, stats_file_path)
    
    if reaper.GetOS():match("Win") then
        full_script_path = full_script_path:gsub("/", "\\")
        stats_file_path = stats_file_path:gsub("/", "\\")
        local py_exe = UTILS.get_win_py_exe(OTHER.rec_state.python and OTHER.rec_state.python.executable or "py -3")
        cmd = string.format('%s "%s" --register --script_title "%s" --machine_id "%s" --stats-file "%s"', 
                                    py_exe, full_script_path, GL.script_title, machine_id, stats_file_path)
    end
    
    -- Helper to read rankings from file
    --- @param silent_mode boolean If true, don't show error snackbar
    --- @return boolean success
    local function update_rankings_from_disk(silent_mode)
        local rankings_path = script_path .. "stats/subass_rankings.json"
        local f = io.open(rankings_path, "r")
        if f then
            local content = f:read("*a")
            f:close()
            if STATS and STATS.json_decode then
                local ok, data = pcall(STATS.json_decode, content)
                
                -- Check for corrupted data or non-table result
                if not ok or type(data) ~= "table" then
                    os.remove(rankings_path)
                    return false
                end

                if data.ok == false then
                    if not silent_mode then
                        show_snackbar(T("SYNC_ERR_RANKS") .. (data.error or "unknown"), "error")
                    end
                    os.remove(rankings_path) -- Delete error file so it doesn't persist
                    return false
                end

                if data.rankings then
                    ACHIEVEMENTS.rankings = data.rankings
                    
                    -- Sync profile from server if available
                    if data.rankings.profile then
                        local p = data.rankings.profile
                        local updated = false
                        
                        local fields = {
                            "dubber_name", "dubber_bio", "dubber_contact", 
                            "dubber_samples", "dubber_equipment", "dubber_conditions",
                            "dubber_voice", "dubber_timbre", "dubber_specialization",
                            "dubber_archetypes", "dubber_languages", "dubber_force_hide"
                        }
                        
                        for _, field in ipairs(fields) do
                            if p[field] and p[field] ~= "" and p[field] ~= cfg[field] then
                                cfg[field] = p[field]
                                updated = true
                            end
                        end
                        
                        if updated then
                            save_settings() -- Persist synced profile to ExtState
                        end
                    end
                    return true
                end
            end
        end
        return false
    end

    -- 1. Read existing data immediately (from previous run)
    update_rankings_from_disk(true)

    -- 2. Execute in background with callback to read fresh results
    run_async_command(cmd, function(exit_code)
        local success = update_rankings_from_disk(is_silent)
        if callback then callback(success) end
    end, is_silent, T("SYNCHRONIZING_DOTS"), false)
end

--- Fetch detailed profile for specific machine_id
function ACHIEVEMENTS.fetch_profile(machine_id)
    if not machine_id or machine_id == "" then return end
    
    local source = debug.getinfo(1,'S').source
    local script_path = source:match([[^@?(.*[\\/])]]) or ""
    local py_path = script_path .. "stats/subass_extra_stats.py"
    
    local cmd = string.format('python3 "%s" --get-profile "%s"', py_path, machine_id)
    local is_windows = reaper.GetOS():match("Win")
    if is_windows then
        local py_exe = UTILS.get_win_py_exe(OTHER.rec_state.python and OTHER.rec_state.python.executable or "py -3")
        cmd = string.format('%s "%s" --get-profile "%s"', py_exe, py_path, machine_id)
    end
    
    UI_STATE.script_loading_state.text = T("LOADING_PROFILE_DOTS")
    UI_STATE.script_loading_state.active = true
    UI_STATE.selected_profile = nil -- Clear old data
    ACHIEVEMENTS.profile_scroll_y = 0
    ACHIEVEMENTS.profile_target_scroll_y = 0
    
    run_async_command(cmd, function(exit_code)
        UI_STATE.script_loading_state.active = false
        
        local profile_path = script_path .. "stats/subass_profile_details.json"
        local f = io.open(profile_path, "r")
        if f then
            local content = f:read("*a")
            f:close()
            local ok, data = pcall(STATS.json_decode, content)
            if ok and type(data) == "table" and data.ok then
                UI_STATE.selected_profile = data.profile
                UI_STATE.show_profile_view = true
            else
                show_snackbar(T("FAILED_TO_LOAD_PROFILE"), "error")
                UI_STATE.show_profile_view = false
            end
            os.remove(profile_path)
        else
            show_snackbar(T("CON_OR_SCRIPT_ERR"), "error")
            UI_STATE.show_profile_view = false
        end
    end, false, T("LOADING_ELLIPSIS"), false)
end

--- Fetch paginated talents list
function ACHIEVEMENTS.fetch_talents(page)
    local page = page or 1
    local limit = 20
    local offset = (page - 1) * limit
    
    local source = debug.getinfo(1,'S').source
    local script_path = source:match([[^@?(.*[\\/])]]) or ""
    local py_path = script_path .. "stats/subass_extra_stats.py"
    
    local f = UI_STATE.talents_filters or {}
    local function t2s(t)
        local items = {}
        for k, v in pairs(t) do if v then table.insert(items, k) end end
        return #items > 0 and table.concat(items, ",") or nil
    end
    
    local f_data = {
        voice = f.voice,
        timbre = t2s(f.timbre or {}),
        conditions = f.conditions,
        vocals = f.vocals,
        specialization = t2s(f.specialization or {}),
        archetypes = t2s(f.archetypes or {}),
        languages = t2s(f.languages or {}),
        status = f.status,
    }
    
    local filter_file = script_path .. "stats/subass_talents_filter.json"
    local json_str = STATS.json_encode(f_data)
    local ff = io.open(filter_file, "w")
    if ff then
        ff:write(json_str)
        ff:close()
    end

    local cmd = string.format('python3 "%s" --get-talents --limit %d --offset %d --filters-file "%s"', py_path, limit, offset, filter_file)
    local is_windows = reaper.GetOS():match("Win")
    if is_windows then
        local py_exe = UTILS.get_win_py_exe(OTHER.rec_state.python and OTHER.rec_state.python.executable or "py -3")
        cmd = string.format('%s "%s" --get-talents --limit %d --offset %d --filters-file "%s"', py_exe, py_path, limit, offset, filter_file)
    end
    
    UI_STATE.talents_loading = true
    UI_STATE.talents_list = nil -- Clear existing list to show loading text
    UI_STATE.talents_scroll_y = 0
    UI_STATE.talents_target_scroll_y = 0
    
    run_async_command(cmd, function(exit_code)
        UI_STATE.talents_loading = false
        
        local talents_path = script_path .. "stats/subass_talents.json"
        local f = io.open(talents_path, "r")
        if f then
            local content = f:read("*a")
            f:close()
            local ok, data = pcall(STATS.json_decode, content)
            if ok and type(data) == "table" and data.ok and data.data then
                UI_STATE.talents_list = data.data.talents
                UI_STATE.talents_total = data.data.total_count
                UI_STATE.talents_free_count = data.data.free_talents_count or 0
                UI_STATE.talents_looking_count = data.data.looking_for_talents_count or 0
                UI_STATE.talents_page = page
            else
                show_snackbar(T("TALENTS_ERR_1"), "error")
            end
            os.remove(talents_path)
        else
            show_snackbar(T("TALENTS_ERR_2"), "error")
        end
    end, true, T("TALENTS_SEARCH_DOTS"), false)
end

-- ═══════════════════════════════════════════════════════════════
-- DUBBERS MODULE - Methods
-- ═══════════════════════════════════════════════════════════════

--- Format seconds as M:SS
function DUBBERS.format_duration(s)
    if not s or s < 0 then return "0:00" end
    local m = math.floor(s / 60)
    local sec = math.floor(s % 60)
    return string.format("%d:%02d", m, sec)
end

--- Get statistics for a specific actor
function DUBBERS.get_actor_stats(actor_name)
    local stats = { replicas = 0, words = 0, time = 0 }
    if not ass_lines then return stats end
    
    for _, line in ipairs(ass_lines) do
        if line.actor == actor_name then
            stats.replicas = stats.replicas + 1
            stats.time = stats.time + (line.t2 - line.t1)
            
            -- Word count logic from draw_file
            local clean = (line.text or ""):gsub("{{+.-}}+", ""):gsub("{.-}", ""):gsub("\\[Nnh]", " ")
            local _, count = clean:gsub("%S+", "")
            stats.words = stats.words + count
        end
    end
    return stats
end

--- Get statistics for a dubber (sum of assigned actors)
function DUBBERS.get_dubber_stats(dubber_name)
    local total = { replicas = 0, words = 0, time = 0, actors_count = 0 }
    local assigned = DUBBERS.data.assignments[dubber_name]
    if not assigned then return total end
    
    for act_name, is_on in pairs(assigned) do
        if is_on then
            total.actors_count = total.actors_count + 1
            local s = DUBBERS.get_actor_stats(act_name)
            total.replicas = total.replicas + s.replicas
            total.words = total.words + s.words
            total.time = total.time + s.time
        end
    end
    return total
end

--- Load dubber data from project extented state
function DUBBERS.load()
    local retval, json_str = reaper.GetProjExtState(0, section_name, "dubber_data")
    if retval and json_str ~= "" then
        local success, result = pcall(function() return STATS.json_decode(json_str) end)
        if success and type(result) == "table" then
            DUBBERS.data = result
            return
        end
    end
    -- Default/Empty state if not found
    DUBBERS.data = {
        names = {},
        assignments = {} -- dubber_name -> { actor1 = true, ... }
    }
end

--- Save dubber data to project extented state
function DUBBERS.save()
    local json_str = STATS.json_encode(DUBBERS.data)
    reaper.SetProjExtState(0, section_name, "dubber_data", json_str)
    reaper.MarkProjectDirty(0)
    DUBBERS.version = DUBBERS.version + 1
end

DUBBERS.conflicts = {}

function DUBBERS.refresh_conflicts()
    DUBBERS.conflicts = {}
    local threshold = cfg.dubber_conflict_threshold or 5.0 -- Safety gap in seconds
    
    if not ass_lines or #ass_lines == 0 then return end
    
    -- 1. Pre-calculate assignment counts per actor
    local actor_dubber_count = {}
    local has_any_dubber = false

    if DUBBERS.data and DUBBERS.data.assignments then
        for _, actors in pairs(DUBBERS.data.assignments) do
            has_any_dubber = true
            for actor, is_on in pairs(actors) do
                if is_on == true then
                    actor_dubber_count[actor] = (actor_dubber_count[actor] or 0) + 1
                end
            end
        end
    end

    if not has_any_dubber then return end

    -- 2. Collect all replicas assigned to SINGLE dubbers
    local reps = {}
    for i, line in ipairs(ass_lines) do
        local actor = line.actor
        if actor and actor ~= "" then
            -- SKIP if actor has multiple dubbers assigned (Crowd/Masovka)
            if (actor_dubber_count[actor] or 0) > 1 then
                goto next_line
            end
            
            -- Find which dubber is assigned to this actor
            local dubber = nil
            if DUBBERS.data and DUBBERS.data.assignments then
                for d_name, actors in pairs(DUBBERS.data.assignments) do
                    if actors[actor] == true then
                        dubber = d_name
                        break
                    end
                end
            end
            
            if dubber then
                table.insert(reps, {
                    row_id = line.index or i,
                    start = line.t1 or 0,
                    finish = line.t2 or 0,
                    actor = actor,
                    dubber = dubber
                })
            end
        end
        ::next_line::
    end
    
    if #reps < 2 then return end
    
    -- 2. Group by dubber
    local groups = {}
    for _, r in ipairs(reps) do
        if not groups[r.dubber] then groups[r.dubber] = {} end
        table.insert(groups[r.dubber], r)
    end
    
    -- 3. Analyze each dubber's timeline
    for dubber, d_reps in pairs(groups) do
        -- Sort chronologically
        table.sort(d_reps, function(a, b) return a.start < b.start end)
        
        for i = 1, #d_reps - 1 do
            local r1 = d_reps[i]
            local r2 = d_reps[i+1]
            
            -- Only conflict between DIFFERENT characters
            if r1.actor ~= r2.actor then
                local gap = r2.start - r1.finish
                if gap < threshold then
                    local level = gap < 0 and 2 or 1
                    local gap_abs = math.abs(gap)
                    
                    -- Mark R1
                    local msg1 = string.format(T("DUBBER_CONFLICT_TT_1"), 
                                              r2.actor, tostring(r2.row_id), gap_abs, 
                                              gap < 0 and T("DUBBER_CONFLICT_TT_2") or T("DUBBER_CONFLICT_TT_3"))
                    if not DUBBERS.conflicts[r1.row_id] or DUBBERS.conflicts[r1.row_id].level < level then
                        DUBBERS.conflicts[r1.row_id] = {
                            level = level, 
                            partner_id = r2.row_id, 
                            partner_actor = r2.actor,
                            time = r1.finish,
                            msg = msg1
                        }
                    end
                    
                    -- Mark R2
                    local msg2 = string.format(T("DUBBER_CONFLICT_TT_1"), 
                                              r1.actor, tostring(r1.row_id), gap_abs, 
                                              gap < 0 and T("DUBBER_CONFLICT_TT_2") or T("DUBBER_CONFLICT_TT_3"))
                    if not DUBBERS.conflicts[r2.row_id] or DUBBERS.conflicts[r2.row_id].level < level then
                        DUBBERS.conflicts[r2.row_id] = {
                            level = level, 
                            partner_id = r1.row_id, 
                            partner_actor = r1.actor,
                            time = r2.start,
                            msg = msg2
                        }
                    end
                end
            end
        end
    end
end

function DUBBERS.validate_name(name, current_name)
    if not name or name == "" then return false, T("NO_EMPTY_NAME") end
    local n_clean = name:match("^%s*(.-)%s*$")
    if n_clean == "" then return false, T("NO_EMPTY_NAME") end
    
    if n_clean:find("[|&]") then
        return false, T("INVALID_NAME_TEXT")
    end
    
    local n_lower = utf8_lower(n_clean)
    local cur_lower = current_name and utf8_lower(current_name:match("^%s*(.-)%s*$"))
    
    if n_lower ~= cur_lower then
        for _, d in ipairs(DUBBERS.data.names) do
            if utf8_lower(d:match("^%s*(.-)%s*$")) == n_lower then
                return false, T("DUBBER_NAME_ALREADY_EXISTS")
            end
        end
    end
    
    return true, n_clean
end

--- Copy distribution result to clipboard
--- @param extended boolean if true, adds per-actor stats and totals
function DUBBERS.copy_to_clipboard(extended)
    local lines = {}
    for _, name in ipairs(DUBBERS.data.names) do
        local assigned = DUBBERS.data.assignments[name] or {}
        local actors = {}
        for act, is_assigned in pairs(assigned) do
            if is_assigned then table.insert(actors, act) end
        end
        table.sort(actors)
        
        if not extended then
            -- Short mode
            if #actors > 0 then
                table.insert(lines, name .. ": " .. table.concat(actors, ", "))
            end
        else
            -- Extended mode
            if #actors > 0 then
                local dubber_block = { "【 " .. name .. " 】" }
                for _, act in ipairs(actors) do
                    local s = DUBBERS.get_actor_stats(act)
                    table.insert(dubber_block, string.format(T("COPY_DUBBER_STATS_1"), act, s.replicas, s.words, DUBBERS.format_duration(s.time)))
                end
                
                -- Add total for dubber
                local ts = DUBBERS.get_dubber_stats(name)
                table.insert(dubber_block, string.format(T("COPY_DUBBER_STATS_2"), ts.actors_count, ts.replicas, ts.words, DUBBERS.format_duration(ts.time)))
                table.insert(lines, table.concat(dubber_block, "\n"))
            end
        end
    end
    
    if #lines == 0 then
        show_snackbar(T("LIST_OF_DUBBERS_EMPTY"), "error")
        return
    end
    
    local out = table.concat(lines, "\n\n")
    set_clipboard(out)
    ACHIEVEMENTS.add_stat("ach_26_count", 1)
    show_snackbar(T("COPY_DUBBER_STATS_DONE"), "success")
end

--- Export distibution as ASS with embedded metadata
--- @param deadline_str string|nil Optional deadline prefix like "[31.01.26]"
function DUBBERS.export_as_ass(deadline_str)
    if not ass_lines then 
        show_snackbar(T("NO_LINES_TO_EXPORT"), "error")
        return 
    end

    -- Construct filename
    local export_count = 0
    local _, proj_path = reaper.EnumProjects(-1)
    local proj_name = "Project"
    if proj_path and proj_path ~= "" then
        proj_name = proj_path:match("([^/\\%s]+)%.[Rr][Pp][Pp]$") or proj_name
    end
    
    -- Construct dictionary metadata & get names
    local active_dicts = {}
    local active_dict_names = {}
    if DICT and DICT.dicts then
        for _, d in ipairs(DICT.dicts) do
            if DICT.is_selected(d.id) then
                table.insert(active_dicts, d)
                table.insert(active_dict_names, d.name)
            end
        end
    end
    local json_dicts = (#active_dicts > 0) and STATS.json_encode({ dicts = active_dicts }) or nil
    
    local default_filename = proj_name .. "_Distribution"
    if #active_dict_names > 0 then
        default_filename = default_filename .. "_" .. table.concat(active_dict_names, "_")
    end
    default_filename = default_filename .. ".ass"
    
    if deadline_str then
        default_filename = deadline_str .. " " .. default_filename
    end

    -- Save Dialog
    local retval, filename = reaper.JS_Dialog_BrowseForSaveFile(T("EXPORT_DISTRIBUTION_ASS"), "", default_filename, "ASS files (.ass)\0*.ass\0All Files (*.*)\0*.*\0")
    
    if retval == 1 and filename ~= "" then
        if not filename:match("%.ass$") then filename = filename .. ".ass" end
        
        local json_meta = STATS.json_encode(DUBBERS.data.assignments or {})
        local file = io.open(filename, "w")
        if not file then
            reaper.ShowMessageBox(T("FAILED_TO_CREATE_FILE") .. filename, T("ERROR"), 0)
            return
        end

        local function fmt_time_ass(secs)
            local h = math.floor(secs / 3600)
            local m = math.floor((secs % 3600) / 60)
            local s = math.floor(secs % 60)
            local ms = math.floor((secs % 1) * 100 + 0.5) % 100
            return string.format("%d:%02d:%02d.%02d", h, m, s, ms)
        end

        local function format_dialogue(l)
            if not ASS.ass_format_order or #ASS.ass_format_order == 0 then
                -- Default fallback
                local txt = l.text or ""
                local text = txt:gsub("\r\n", "\n"):gsub("\n", "\\N")
                return string.format("Dialogue: 0,%s,%s,Default,%s,0,0,0,,%s", 
                    fmt_time_ass(l.t1), fmt_time_ass(l.t2), l.actor or "Default", text)
            end
            
            local fields = {}
            for _, field in ipairs(ASS.ass_format_order) do
                local val = ""
                if field == "Start" then
                    val = fmt_time_ass(l.t1)
                elseif field == "End" then
                    val = fmt_time_ass(l.t2)
                elseif field == "Text" then
                    local txt = l.text or ""
                    val = txt:gsub("\r\n", "\n"):gsub("\n", "\\N")
                elseif field == "Name" or field == "Actor" then
                    val = l.actor or "Default"
                elseif field == "Style" then
                    val = (l.metadata and l.metadata[field]) or "Default"
                elseif field == "Effect" then
                    val = (l.metadata and l.metadata[field]) or ""
                else
                    val = (l.metadata and l.metadata[field]) or "0"
                end
                table.insert(fields, val)
            end
            return "Dialogue: " .. table.concat(fields, ",")
        end

        if ASS.ass_header_order and #ASS.ass_header_order > 0 then
            for _, section_name in ipairs(ASS.ass_header_order) do
                local lines = ASS.ass_header_sections[section_name]
                if lines then
                    for _, line in ipairs(lines) do
                        file:write(line .. "\n")
                    end
                end
                
                if section_name == "Events" then
                    -- Metadata Line
                    file:write(format_dialogue({
                        t1 = 0, t2 = 0, actor = "SubassMetadata", text = json_meta, enabled = true
                    }) .. "\n")
                    if json_dicts then
                        file:write(format_dialogue({
                            t1 = 0, t2 = 0, actor = "SubassDict", text = json_dicts, enabled = true
                        }) .. "\n")
                    end
                    
                    local out_lines = {}
                    for _, l in ipairs(ass_lines) do table.insert(out_lines, l) end
                    -- Strict sort by index to preserve original file order and layering
                    table.sort(out_lines, function(a, b) return (a.index or 0) < (b.index or 0) end)
                    
                    for _, l in ipairs(out_lines) do
                        file:write(format_dialogue(l) .. "\n")
                        export_count = export_count + 1
                    end
                end
            end
        else
            -- Default Fallback
            file:write("[Script Info]\nTitle: Subass Dubber Distribution\nScriptType: v4.00+\nPlayResX: 1920\nPlayResY: 1080\nScaledBorderAndShadow: yes\n\n")
            file:write("[V4+ Styles]\nFormat: Name, Fontname, Fontsize, PrimaryColour, SecondaryColour, OutlineColour, BackColour, Bold, Italic, Underline, StrikeOut, ScaleX, ScaleY, Spacing, Angle, BorderStyle, Outline, Shadow, Alignment, MarginL, MarginR, MarginV, Encoding\n")
            file:write("Style: Default,Arial,20,&H00FFFFFF,&H000000FF,&H00000000,&H00000000,0,0,0,0,100,100,0,0,1,2,2,2,10,10,10,1\n\n")
            file:write("[Events]\nFormat: Layer, Start, End, Style, Name, MarginL, MarginR, MarginV, Effect, Text\n")
            file:write(string.format("Dialogue: 0,0:00:00.00,0:00:00.00,Default,SubassMetadata,0,0,0,,%s\n", json_meta))
            if json_dicts then
                file:write(string.format("Dialogue: 0,0:00:00.00,0:00:00.00,Default,SubassDict,0,0,0,,%s\n", json_dicts))
            end
            
            local out_lines = {}
            for _, l in ipairs(ass_lines) do table.insert(out_lines, l) end
            -- Strict sort by index to preserve original file order and layering
            table.sort(out_lines, function(a, b) return (a.index or 0) < (b.index or 0) end)
            for _, l in ipairs(out_lines) do
                file:write(format_dialogue(l) .. "\n")
                export_count = export_count + 1
            end
        end
        
        file:close()
        show_snackbar(T("EXPORTED_1") .. export_count .. T("EXPORTED_2"), "success")
    end
end

--- Select a dubber and filter the project to their assigned actors
--- @param name string Name of the dubber to select
function DUBBERS.select_dubber(name)
    push_undo(T("CHANGE_THE_DUBBER") .. ": " .. (name or ""))
    local assigned_actors = DUBBERS.data.assignments[name] or {}
    
    -- Reset all filters
    for k in pairs(ass_actors) do ass_actors[k] = false end
    if ass_lines then
        for _, l in ipairs(ass_lines) do l.enabled = false end
        UI_STATE._markers_is_dirty = true
    end
    
    -- Apply assignments from this dubber
    local found_any = false
    for act, is_on in pairs(assigned_actors) do
        if is_on and ass_actors[act] ~= nil then
            ass_actors[act] = true
            found_any = true
        end
    end
    
    -- Sync lines enabled state
    if ass_lines then
        for _, l in ipairs(ass_lines) do
            if assigned_actors[l.actor] then
                l.enabled = true
            end
        end

        UI_STATE._markers_is_dirty = true
    end
    
    rebuild_regions()
    
    -- Update active index for UI consistency
    for i, d_name in ipairs(DUBBERS.data.names) do
        if d_name == name then
            DUBBERS.active_dubber_idx = i
            break
        end
    end
    
    if found_any then
        show_snackbar(T("DUBBER_SELECT_SUCC") .. name, "success")
    else
        show_snackbar(T("DUBBER_SELECT_FAILED_1") .. name .. T("DUBBER_SELECT_FAILED_2"), "warning")
    end
end

--- Check if the current filter state matches a dubber's assignments
--- @param name string Name of the dubber to check
--- @return boolean
function DUBBERS.is_dubber_active(name)
    if not DUBBERS.data or not DUBBERS.data.assignments then return false end
    local assigned = DUBBERS.data.assignments[name] or {}
    if not ass_actors then return false end
    
    for act, is_active_in_project in pairs(ass_actors) do
        local is_assigned = assigned[act] or false
        if is_active_in_project ~= is_assigned then
            return false
        end
    end
    return true
end

--- Draw Dubber Distribution Dashboard
--- Draw Dubber Distribution Dashboard
--- @param input_queue table Queue of character/keyboard inputs
function DUBBERS.draw_dashboard(input_queue)
    -- AUTO-REFRESH on open
    if not DUBBERS.dashboard_initialized then
        DUBBERS.refresh_conflicts()
        DUBBERS.dashboard_initialized = true
    end
    
    local pad = S(20)
    UI_STATE.mouse_handled = true -- Block interaction with background
    
    -- Background overlay
    set_color(UI.C_BG, 0.98)
    gfx.rect(0, 0, gfx.w, gfx.h, 1)
    
    -- --- DIMENSIONS & MEASUREMENTS ---
    gfx.setfont(F.title)
    local title = T("SPLIT_BY_DUBBERS")
    local tw, th = gfx.measurestr(title)
    local header_h = pad + th + S(15)
    
    local dubber_item_h = S(50)
    local actor_item_h = S(55)
    local section_gap = S(30)
    local grid_w = gfx.w - pad*2
    local actor_col_w = S(220)
    local cols = math.floor(grid_w / actor_col_w)
    if cols < 1 then cols = 1 end
    
    -- --- DATA PREP ---
    local sorted_actors = {}
    for act in pairs(ass_actors) do table.insert(sorted_actors, act) end
    table.sort(sorted_actors)
    
    local actor_to_dubbers = {}
    for _, d_name in ipairs(DUBBERS.data.names) do
        local assigned = DUBBERS.data.assignments[d_name] or {}
        for act, is_on in pairs(assigned) do
            if is_on then
                if not actor_to_dubbers[act] then actor_to_dubbers[act] = {} end
                table.insert(actor_to_dubbers[act], d_name)
            end
        end
    end
    
    -- Content Height Calculation
    local d_cols = 3
    local d_col_w = grid_w / d_cols
    local d_rows = math.ceil(#DUBBERS.data.names / d_cols)
    local dubbers_h = (d_rows * dubber_item_h) + S(75) -- + Title & Add button room
    
    local actors_start_relative = dubbers_h + section_gap
    local rows = math.ceil(#sorted_actors / cols)
    local actors_h = rows * actor_item_h
    local total_content_h = actors_start_relative + actors_h + pad + S(40) -- EXTRA PADDING AT BOTTOM
    
    -- --- CONFLICT AGGREGATION FOR TOOLTIPS ---
    local dubber_conflicts = {} -- name -> { partner1, partner2, ... }
    local actor_conflicts = {}  -- name -> { partner1, partner2, ... }
    
    if DUBBERS.conflicts then
        -- Index lines for fast lookup
        local line_map = {}
        if ass_lines then
            for _, l in ipairs(ass_lines) do if l.index then line_map[l.index] = l end end
        end
        
        -- Use sets for unique names
        local d_sets = {}
        local a_sets = {}
        
        for row_id, c in pairs(DUBBERS.conflicts) do
            local line = line_map[row_id]
            if line then
                local act = line.actor
                local p_act = c.partner_actor or "?"
                
                -- Use pre-calculated actor_to_dubbers
                local dbs = actor_to_dubbers[act] or {}
                local dubber = dbs[1] -- Primary dubber
                
                if dubber then
                    -- Actor Aggregation (Unique partners for this actor)
                    if not a_sets[act] then a_sets[act] = {} end
                    a_sets[act][p_act] = true
                    
                    -- Dubber Aggregation (Unique conflicting actors for this dubber)
                    if not d_sets[dubber] then d_sets[dubber] = {} end
                    d_sets[dubber][act] = true
                    d_sets[dubber][p_act] = true
                end
            end
        end
        
        -- Convert sets to sorted lists
        for act, names in pairs(a_sets) do
            local list = {}
            for n in pairs(names) do table.insert(list, "• " .. n) end
            table.sort(list); actor_conflicts[act] = list
        end
        for d, names in pairs(d_sets) do
            local list = {}
            for n in pairs(names) do table.insert(list, "• " .. n) end
            table.sort(list); dubber_conflicts[d] = list
        end
    end

    local view_h = gfx.h - header_h
    local max_scroll = math.max(0, total_content_h - view_h)
    
    -- SCROLL CONTROL
    if gfx.mouse_wheel ~= 0 then
        DUBBERS.target_scroll_y = math.max(0, math.min(DUBBERS.target_scroll_y - (gfx.mouse_wheel * 0.25), max_scroll))
        gfx.mouse_wheel = 0
    end
    local diff = DUBBERS.target_scroll_y - DUBBERS.scroll_y
    if math.abs(diff) > 0.5 then DUBBERS.scroll_y = DUBBERS.scroll_y + (diff * 0.8) else DUBBERS.scroll_y = DUBBERS.target_scroll_y end
    
    -- --- SCROLLABLE CONTENT ---
    local function get_y(rel_y) return header_h + rel_y - math.floor(DUBBERS.scroll_y) end
    
    -- 1. Dubbers Section
    local dy = get_y(0)
    if dy + S(25) > header_h then
        set_color(UI.C_TXT, 0.6)
        gfx.setfont(F.bld)
        gfx.x, gfx.y = pad, dy
        gfx.drawstr(T("DUBBERS"))
    end
    
    dy = dy + S(25)
    
    -- Add Dubber Button & Auto Distribution Button
    local add_w = S(120)
    local auto_w = S(170)
    if dy + S(25) > header_h and dy < gfx.h then
        -- Add Dubber
        if btn(pad, dy, add_w, S(25), "+ " .. T("ADD_DUBBER"), UI.C_BTN, UI.C_TXT) then
            local ok, name = reaper.GetUserInputs(T("NEW_DUBBER"), 1, T("NAME_DUBBER"), "")
            if ok then
                local is_valid, res = DUBBERS.validate_name(name)
                if not is_valid then
                    if res then show_snackbar(res, "error") end
                else
                    push_undo(T("ADD_DUBBER"))
                    table.insert(DUBBERS.data.names, res)
                    DUBBERS.save()
                end
            end
        end

        -- Auto Distribution
        if btn(pad + add_w + S(10), dy, auto_w, S(25), T("AUTOATIC_DISTRIBUTION"), UI.C_BTN, UI.C_TXT) then
            cfg.dubber_char_rules = cfg.dubber_char_rules or {}
            
            -- Get all project names
            local project_names = {}
            for p_name in pairs(cfg.dubber_char_rules) do
                table.insert(project_names, p_name)
            end
            table.sort(project_names)
            
            if #project_names == 0 then
                reaper.ShowMessageBox(T("NEED_TO_CREATE_PROJECT"), T("NO_PROJECTS"), 0)
            else
                -- Show context menu with projects list
                local menu_parts = {}
                for _, p_name in ipairs(project_names) do
                    table.insert(menu_parts, p_name)
                end
                
                gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
                local ret = gfx.showmenu(table.concat(menu_parts, "|"))
                if ret > 0 then
                    local selected_project = project_names[ret]
                    local selected_rules = cfg.dubber_char_rules[selected_project] or {}
                    
                    local added_dubs_count = 0
                    local assigned_chars_count = 0
                    
                    DUBBERS.data.assignments = DUBBERS.data.assignments or {}
                    
                    -- Snapshot state BEFORE any changes (so a single Ctrl+Z restores fully)
                    push_undo(T("AUTOATIC_DISTRIBUTION"))
                    
                    -- Keep track of existing names (for quick check and case-insensitivity)
                    local existing_names_map = {}
                    for _, dname in ipairs(DUBBERS.data.names) do
                        existing_names_map[utf8_lower(dname)] = dname
                    end
                    
                    -- Separate <all> rules from normal rules
                    local all_rules = {}
                    local normal_rules = {}
                    for _, rule in ipairs(selected_rules) do
                        if rule.dubber_name and utf8_lower(rule.dubber_name) == "<all>" then
                            table.insert(all_rules, rule)
                        else
                            table.insert(normal_rules, rule)
                        end
                    end
                    
                    -- Pass 1: normal rules — each actor may match multiple specific dubbers
                    if ass_actors then
                        for act in pairs(ass_actors) do
                            local matched_dubbers = {}
                            for _, rule in ipairs(normal_rules) do
                                if rule.dubber_name and rule.dubber_name ~= "" and rule.chars and rule.chars ~= "" then
                                    for char in rule.chars:gmatch("[^,]+") do
                                        char = char:match("^%s*(.-)%s*$")
                                        if utf8_lower(char) == utf8_lower(act) then
                                            table.insert(matched_dubbers, rule.dubber_name)
                                            break -- inner break: stop scanning chars for THIS rule
                                        end
                                    end
                                end
                            end
                            
                            for _, matched_dubber_name in ipairs(matched_dubbers) do
                                local norm_dubber_name = matched_dubber_name
                                local lower_norm = utf8_lower(norm_dubber_name)
                                if not existing_names_map[lower_norm] then
                                    local is_valid, res = DUBBERS.validate_name(norm_dubber_name)
                                    if is_valid then
                                        table.insert(DUBBERS.data.names, res)
                                        existing_names_map[lower_norm] = res
                                        added_dubs_count = added_dubs_count + 1
                                    end
                                else
                                    norm_dubber_name = existing_names_map[lower_norm]
                                end
                                
                                if not DUBBERS.data.assignments[norm_dubber_name] then
                                    DUBBERS.data.assignments[norm_dubber_name] = {}
                                end
                                if not DUBBERS.data.assignments[norm_dubber_name][act] then
                                    DUBBERS.data.assignments[norm_dubber_name][act] = true
                                    assigned_chars_count = assigned_chars_count + 1
                                end
                            end
                        end
                    end
                    
                    -- Pass 2: <all> rules — assign listed chars to EVERY existing dubber
                    if #all_rules > 0 then
                        for _, rule in ipairs(all_rules) do
                            if rule.chars and rule.chars ~= "" then
                                for char in rule.chars:gmatch("[^,]+") do
                                    local act = char:match("^%s*(.-)%s*$")
                                    -- Only assign if this actor actually exists in the project
                                    if act ~= "" and ass_actors and ass_actors[act] then
                                        for _, dname in ipairs(DUBBERS.data.names) do
                                            if not DUBBERS.data.assignments[dname] then
                                                DUBBERS.data.assignments[dname] = {}
                                            end
                                            if not DUBBERS.data.assignments[dname][act] then
                                                DUBBERS.data.assignments[dname][act] = true
                                                assigned_chars_count = assigned_chars_count + 1
                                            end
                                        end
                                    end
                                end
                            end
                        end
                    end
                    
                    if added_dubs_count > 0 or assigned_chars_count > 0 then
                        DUBBERS.save()
                        show_snackbar(T("DUBBERS_COMPLETE_P1") .. added_dubs_count .. T("DUBBERS_COMPLETE_P2") .. assigned_chars_count, "success")
                    else
                        -- No changes were made — pop the undo we just pushed to avoid a phantom entry
                        table.remove(undo_stack)
                        show_snackbar(T("DUBBERS_COMPLETE_NO"), "info")
                    end
                end
            end
        end

        -- Right-click anywhere in the button row: context menu
        if is_mouse_clicked(2) and gfx.mouse_y >= dy and gfx.mouse_y <= dy + S(25) and gfx.mouse_y > header_h then
            gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
            local ret = gfx.showmenu(T("DUBBERS_CLEAR_ALL"))
            if ret == 1 then
                if reaper.MB(T("DUBBERS_CLEAR_ALL_TILES"), T("CONFIRMATION"), 4) == 6 then
                    push_undo(T("DUBBERS_CLEAR_ALL"))
                    DUBBERS.data.assignments = {}
                    DUBBERS.save()
                    DUBBERS.refresh_conflicts()
                    show_snackbar(T("DUBBERS_CLEAR_ALL_DONE"), "info")
                end
            end
        end
    end
    
    dy = dy + S(35)
    
    for i, name in ipairs(DUBBERS.data.names) do
        local col = (i-1) % d_cols
        local row = math.floor((i-1) / d_cols)
        local dx = pad + col * d_col_w
        local item_y = dy + row * dubber_item_h
        
        local is_active = (i == DUBBERS.active_dubber_idx)
        
        if item_y + dubber_item_h > header_h and item_y < gfx.h then
            local bg = is_active and UI.C_ACCENT_N or UI.C_ROW
            local txt_c = is_active and UI.C_WHITE or UI.C_TXT
            
            -- Draw Row Background
            set_color(bg, is_active and 0.9 or 0.3)
            gfx.rect(dx, item_y, d_col_w - S(5), dubber_item_h - S(4), 1)
            
            -- Conflict Indication (Little dot at top-right)
            local d_conf = dubber_conflicts[name]
            if d_conf and #d_conf > 0 then
                local dot_sz = S(4)
                set_color(UI.C_ORANGE, 0.8)
                gfx.circle(dx + (d_col_w - S(5)) - dot_sz*2, item_y + dot_sz*2, dot_sz/2, 1)
                
                -- Tooltip logic
                if gfx.mouse_x >= dx and gfx.mouse_x <= dx + d_col_w and
                   gfx.mouse_y >= item_y and gfx.mouse_y <= item_y + dubber_item_h and gfx.mouse_y > header_h then
                    UI_STATE.tooltip_state.text = T("CONFLICTS_ACTORS_TT") .. table.concat(d_conf, "\n")
                end
            end
            
            -- Selection Logic
            if is_mouse_clicked() and gfx.mouse_x >= dx and gfx.mouse_x <= dx + d_col_w and
               gfx.mouse_y >= item_y and gfx.mouse_y <= item_y + dubber_item_h and gfx.mouse_y > header_h then
                DUBBERS.active_dubber_idx = i
            end
            
            -- ПКМ: Rename/Delete
            if is_mouse_clicked(2) and gfx.mouse_x >= dx and gfx.mouse_x <= dx + d_col_w and
               gfx.mouse_y >= item_y and gfx.mouse_y <= item_y + dubber_item_h and gfx.mouse_y > header_h then
                gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
                local ret = gfx.showmenu(T("DUBBERS_ACTIVE_MENU_1") .. "||" .. T("CHANGE_NAME") .. "|" .. T("DELETE"))
                if ret == 1 then
                    DUBBERS.select_dubber(name)
                elseif ret == 2 then
                    local ok, n_name = reaper.GetUserInputs(T("CHANGE_NAME"), 1, T("NEW_NAME"), name)
                    if ok then
                        local is_valid, res = DUBBERS.validate_name(n_name, name)
                        if not is_valid then
                            if res then show_snackbar(res, "error") end
                        else
                            push_undo(T("CHANGE_NAME") .. " " .. T("DUBBER_ONE"))
                            DUBBERS.data.assignments[res] = DUBBERS.data.assignments[name]
                            DUBBERS.data.assignments[name] = nil
                            DUBBERS.data.names[i] = res
                            DUBBERS.save()
                        end
                    end
                elseif ret == 3 then
                    if reaper.MB(T("DELETE") .. " '"..name.."'?", T("CONFIRMATION"), 4) == 6 then
                        push_undo(T("DELETE") .. " " .. T("DUBBER_ONE"))
                        table.remove(DUBBERS.data.names, i); DUBBERS.data.assignments[name] = nil
                        DUBBERS.active_dubber_idx = math.max(1, math.min(DUBBERS.active_dubber_idx, #DUBBERS.data.names))
                        DUBBERS.save()
                    end
                end
            end
            
            -- Labels
            gfx.setfont(F.bld)
            set_color(txt_c)
            gfx.x, gfx.y = dx + S(15), item_y + S(8)
            gfx.drawstr(fit_text_width(name, d_col_w - S(25)))
            
            local s = DUBBERS.get_dubber_stats(name)
            local meta = string.format(T("DUBBERS_DETAIL_FOOTER_1"), s.replicas, s.words, DUBBERS.format_duration(s.time), s.actors_count)
            gfx.setfont(F.tip)
            set_color(txt_c, 0.7)
            gfx.x, gfx.y = dx + S(15), item_y + S(28)
            gfx.drawstr(fit_text_width(meta, d_col_w - S(25)))
        end
    end
    
    -- 2. Actors Section
    local ay = get_y(actors_start_relative)
    local active_dubber = DUBBERS.data.names[DUBBERS.active_dubber_idx]
    
    if ay + S(40) > header_h and ay < gfx.h then
        set_color(UI.C_TXT, 0.6)
        gfx.setfont(F.bld)
        gfx.x, gfx.y = pad, ay
        local a_title = T("ACTORS")
        if active_dubber then a_title = a_title .. " (" .. T("FOR") .. ": " .. active_dubber .. ")" end
        gfx.drawstr(a_title)
    end
    
    ay = ay + S(30)
    
    for i, act in ipairs(sorted_actors) do
        local col = (i-1) % cols
        local row = math.floor((i-1) / cols)
        local ax = pad + col * actor_col_w
        local cur_ay = ay + row * actor_item_h
        
        if cur_ay + actor_item_h > header_h and cur_ay < gfx.h then
            local is_assigned = active_dubber and DUBBERS.data.assignments[active_dubber] and DUBBERS.data.assignments[active_dubber][act]
            local dbs = actor_to_dubbers[act]
            local has_any_assignment = (dbs and #dbs > 0)
            local fade = has_any_assignment and 1.0 or 0.4 -- Pale if no dubber assigned at all
            
            -- Card BG
            if is_assigned then
                set_color(UI.C_GREEN, 0.2) -- User preferred value
            else
                set_color(UI.C_ROW, 0.2 * fade)
            end
            gfx.rect(ax, cur_ay, actor_col_w - S(5), actor_item_h - S(5), 1)
            
            -- Conflict Indication (Actor Card dot at top-right)
            local a_conf = actor_conflicts[act]
            if a_conf and #a_conf > 0 then
                local dot_sz = S(4)
                set_color(UI.C_ORANGE, 0.8)
                gfx.circle(ax + (actor_col_w - S(5)) - dot_sz*2, cur_ay + dot_sz*2, dot_sz/2, 1)
                
                -- Tooltip logic
                if gfx.mouse_x >= ax and gfx.mouse_x <= ax + actor_col_w and
                   gfx.mouse_y >= cur_ay and gfx.mouse_y <= cur_ay + actor_item_h and gfx.mouse_y > header_h then
                    UI_STATE.tooltip_state.text = T("CONFLICTS_WITH") .. table.concat(a_conf, "\n")
                end
            end
            
            -- Border logic: Green if assigned, Transparent Red if not
            if has_any_assignment then
                set_color(UI.C_GREEN, 0.2)
            else
                set_color(UI.C_RED, 0.4)
            end
            gfx.rect(ax, cur_ay, actor_col_w - S(5), actor_item_h - S(5), 0)
            
            -- Checkbox / Assignment
            local a_col = get_actor_color(act)
            local r, g, b = reaper.ColorFromNative(a_col & 0xFFFFFF)
            
            if is_assigned then
                set_color({r/255, g/255, b/255})
                gfx.rect(ax + S(8), cur_ay + S(11), S(18), S(18), 1)
                set_color(UI.C_BLACK)
                gfx.line(ax + S(11), cur_ay + S(20), ax + S(15), cur_ay + S(25))
                gfx.line(ax + S(15), cur_ay + S(25), ax + S(22), cur_ay + S(14))
            else
                set_color(UI.C_BTN, fade)
                gfx.rect(ax + S(8), cur_ay + S(11), S(18), S(18), 0)
                set_color({r/255, g/255, b/255}, 0.3 * fade)
                gfx.rect(ax + S(13), cur_ay + S(16), S(8), S(8), 1)
            end
            
            -- Actor Name + Dubbers
            local label = act
            if has_any_assignment then label = label .. " [" .. table.concat(dbs, ", ") .. "]" end
            
            set_color(UI.C_TXT, fade)
            gfx.setfont(F.bld)
            gfx.x, gfx.y = ax + S(32), cur_ay + S(8)
            gfx.drawstr(fit_text_width(label, actor_col_w - S(40)))
            
            local s = DUBBERS.get_actor_stats(act)
            local meta = string.format(T("DUBBERS_DETAIL_FOOTER_2"), s.replicas, s.words, DUBBERS.format_duration(s.time))
            gfx.setfont(F.tip)
            set_color(UI.C_TXT, 0.6 * fade)
            gfx.x, gfx.y = ax + S(32), cur_ay + S(28)
            gfx.drawstr(fit_text_width(meta, actor_col_w - S(40)))
            
            -- Click logic
            if (is_mouse_clicked() or is_mouse_clicked(2)) and gfx.mouse_x >= ax and gfx.mouse_x <= ax + actor_col_w and
               gfx.mouse_y >= cur_ay and gfx.mouse_y <= cur_ay + actor_item_h and gfx.mouse_y > header_h then
                
                -- Right Click: Context Menu for all Dubbers
                if is_mouse_clicked(2) then
                    local menu_items = {}
                    for _, d_name in ipairs(DUBBERS.data.names) do
                        local is_assigned_to_this = DUBBERS.data.assignments[d_name] and DUBBERS.data.assignments[d_name][act]
                        local prefix = is_assigned_to_this and "!" or ""
                        table.insert(menu_items, prefix .. d_name)
                    end
                    
                    if #menu_items > 0 then
                        gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
                        local ret = gfx.showmenu(table.concat(menu_items, "|"))
                        if ret > 0 then
                            local selected_dubber = DUBBERS.data.names[ret]
                            push_undo(T("CAHNGE_DISTRIBUTION"))
                            if not DUBBERS.data.assignments[selected_dubber] then DUBBERS.data.assignments[selected_dubber] = {} end
                            DUBBERS.data.assignments[selected_dubber][act] = not (DUBBERS.data.assignments[selected_dubber][act])
                            DUBBERS.save()
                            DUBBERS.refresh_conflicts()
                        end
                    else
                        show_snackbar(T("LIST_OF_DUBBERS_EMPTY"), "error")
                    end
                
                -- Left Click: Toggle for Active Dubber
                else
                    if active_dubber then
                        push_undo(T("CAHNGE_DISTRIBUTION"))
                        if not DUBBERS.data.assignments[active_dubber] then DUBBERS.data.assignments[active_dubber] = {} end
                        DUBBERS.data.assignments[active_dubber][act] = not is_assigned
                        DUBBERS.save()
                        DUBBERS.refresh_conflicts()
                    else
                        show_snackbar(T("SELECT_DUBBER_ON_TOP"), "info")
                    end
                end
            end
        end
    end
    
    -- Draw Interactive Scrollbar
    if max_scroll > 0 then
        DUBBERS.target_scroll_y = draw_scrollbar(gfx.w - S(10), header_h, S(10), view_h, total_content_h, view_h, DUBBERS.target_scroll_y)
    end
    
    -- --- FIXED HEADER OVERLAY (Drawn last to stay on top) ---
    set_color(UI.C_BG, 1.0)
    gfx.rect(0, 0, gfx.w, header_h, 1)
    
    local close_sz = S(24)
    local copy_w = cfg.lng == "ua" and S(100) or S(70)
    local export_w = cfg.lng == "ua" and S(160) or S(120)
    local right_edge = gfx.w - pad - close_sz - S(10)
    
    set_color(UI.C_TXT)
    gfx.setfont(F.title)
    gfx.x, gfx.y = pad, pad
    local reserved_w = close_sz + copy_w + export_w + S(50)
    gfx.drawstr(fit_text_width(title, gfx.w - pad - reserved_w))
    
    local function close_dash() DUBBERS.show_dashboard = false end
    if btn(gfx.w - pad - close_sz, pad, close_sz, close_sz, "X", UI.C_BTN, UI.C_TXT) then close_dash() end
    
    if btn(right_edge - copy_w, pad, copy_w, close_sz, T("COPY"), UI.C_TAB_INA, UI.C_TXT) then
        gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
        local ret = gfx.showmenu(T("COPY_DUBBER_MENU"))
        if ret == 1 then
            DUBBERS.copy_to_clipboard(false)
        elseif ret == 2 then
            DUBBERS.copy_to_clipboard(true)
        end
    end

    if btn(right_edge - copy_w - S(10) - export_w, pad, export_w, close_sz, T("EXPORT_AS_ASS"), UI.C_TAB_INA, UI.C_TXT) then
        gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
        local ret = gfx.showmenu(T("EXPORT_DUBBER_MENU"))
        if ret == 1 then
            DUBBERS.export_as_ass()
        elseif ret == 2 then
            DEADLINE.open_picker(nil, function(ts)
                if not ts then return end
                local dt = os.date("*t", ts)
                local d_str = string.format("[%02d.%02d.%02d]", dt.day, dt.month, dt.year % 100)
                DUBBERS.export_as_ass(d_str)
            end)
        end
    end
    
    -- ESC key to close
    if input_queue then
        for _, c in ipairs(input_queue) do if c == 27 then close_dash() break end end
    end
end

-- =============================================================================
-- FILE IMPORT (SRT/ASS)
-- =============================================================================

--- Import SRT subtitle file
local function import_srt(file_path, dont_rebuild, forced_actor)
    local initial_len = #ass_lines
    local file = file_path
    if not file then
        local retval
        retval, file = reaper.GetUserFileNameForRead("", "Import SRT", "srt")
        if not retval then return end
    end
    local f = io.open(file, "r")
    if not f then 
        reaper.MB(T("IMPORT_FILE_UABLE_OPEN") .. tostring(file), T("IMPORT_ERROR"), 0)
        return 
    end
    UI_STATE.current_file_name = file:match("([^/\\]+)$")
    UI_STATE.current_file_path = file
    
    -- Auto-toggle dictionaries by rules based on filename
    DICT.auto_toggle_by_rules(file)
    
    local content = fix_encoding(f:read("*all"))
    f:close()
    content = content:gsub("\r\n", "\n")
    -- Ensure trailing double newline for matching last block
    if not content:match("\n\n$") then
        content = content .. "\n\n"
    end
    
    -- Derive Actor Name from Filename or use forced_actor
    local base_name = UI_STATE.current_file_name:gsub("%.srt$", ""):gsub("%.SRT$", "")
    local actor_name = forced_actor
    
    if not actor_name then
        -- Special Case: ВанПіс_989_... -> ВанПіс_989
        local ep = base_name:match("^ВанПіс_([%d]+)")
        if ep then
            actor_name = "ВанПіс_" .. ep
        else
            actor_name = base_name
        end
    end
    
    -- Check for deadline in filename
    local dl = DEADLINE.parse_from_name(UI_STATE.current_file_name)
    if dl then DEADLINE.set(dl) end
    
    -- Ensure State Init
    if not ass_lines then ass_lines = {} end
    if not ass_actors then ass_actors = {} end
    
    if not dont_rebuild then
        push_undo("Import SRT")
    end
    
    UI_STATE.ass_file_loaded = true -- Enable Actor view

    -- Clear UI state
    table_filter_state.text = ""
    table_selection = {}
    last_selected_row = nil
    
    -- We will rebuild ALL regions at the end, so we don't need to add markers manually here.
    -- Just populate ass_lines.
    local line_idx_counter = get_next_line_index()
    
    -- Robust SRT parsing: handle comma/dot, optional spaces, and ensure last block is captured
    local duplicates_skipped = 0
    for s_start, s_end, text in content:gmatch("(%d+:%d+:%d+[,.]%d+)%s*%-%->%s*(%d+:%d+:%d+[,.]%d+)%s*\n(.-)\n%s*\n") do
        local t1 = parse_timestamp(s_start)
        local t2 = parse_timestamp(s_end)
        
        local lines_processed = false
        
        -- Logic: If auto-split enabled, iterate lines
        if cfg.auto_srt_split == "():" or cfg.auto_srt_split == "[]:" then
            local lines_list = {}
            for l in (text.."\n"):gmatch("(.-)\n") do 
                -- Trim carriage returns just in case
                l = l:gsub("\r", "")
                if l ~= "" then table.insert(lines_list, l) end 
            end
            
            if #lines_list > 0 then
                lines_processed = true
                
                local current_block_actor = actor_name
                local segments = {} -- { {actor=A, text=T} }

                for _, line_txt in ipairs(lines_list) do
                    local found_act, found_txt
                    
                    if cfg.auto_srt_split == "():" then
                        -- Check for prefix before actor
                        local pre, act, post = line_txt:match("^(.-)%s*%(%s*(.-)%s*%):%s*(.*)")
                        if act then 
                            found_act = act
                            found_txt = (pre ~= "" and (pre .. " ") or "") .. post
                        end
                    elseif cfg.auto_srt_split == "[]:" then
                        local pre, act, post = line_txt:match("^(.-)%s*%[%s*(.-)%s*%]:%s*(.*)")
                        if act then
                            found_act = act
                            found_txt = (pre ~= "" and (pre .. " ") or "") .. post
                        end
                    end
                    
                    if found_act then
                        -- New actor detected
                        current_block_actor = found_act
                        -- Register
                        if not ass_actors[current_block_actor] then ass_actors[current_block_actor] = true end
                        
                        -- Add new segment
                        table.insert(segments, {actor=current_block_actor, text=found_txt})
                    else
                        -- No actor detected -> continuation or start of default
                        if #segments > 0 then
                            -- Append to last segment
                            local last = segments[#segments]
                            if last.text == "" then
                                last.text = line_txt
                            else
                                last.text = last.text .. "\n" .. line_txt
                            end
                        else
                            -- First line has no actor -> use filename actor (current_block_actor)
                            table.insert(segments, {actor=current_block_actor, text=line_txt})
                        end
                    end
                end
                
                -- Push segments with duplicate check
                for _, seg in ipairs(segments) do
                    if not is_duplicate_replica(seg.actor, t1, t2, seg.text) then
                        -- Lazy register actor
                        ass_actors[seg.actor] = true
                        
                        table.insert(ass_lines, {
                            t1 = t1,
                            t2 = t2,
                            text = seg.text,
                            actor = seg.actor,
                            enabled = true,
                            index = line_idx_counter
                        })
                        line_idx_counter = line_idx_counter + 1
                    else
                        duplicates_skipped = duplicates_skipped + 1
                    end
                end
            end
        end
        
        -- Fallback: If not processed by auto-split, check split_multiline
        if not lines_processed and cfg.split_multiline then
            local lines_list = {}
            for l in (text.."\n"):gmatch("(.-)\n") do
                l = l:gsub("\r", ""):match("^%s*(.-)%s*$")
                if l ~= "" then table.insert(lines_list, l) end
            end
             
            if #lines_list > 1 then
                lines_processed = true
                local dur = t2 - t1
                local step = dur / #lines_list
                for i, l in ipairs(lines_list) do
                    if not is_duplicate_replica(actor_name, t1 + (i-1) * step, t1 + i * step, l) then
                        ass_actors[actor_name] = true
                        table.insert(ass_lines, {
                            t1 = t1 + (i-1) * step,
                            t2 = t1 + i * step,
                            text = l,
                            actor = actor_name,
                            enabled = true,
                            index = line_idx_counter
                        })
                        line_idx_counter = line_idx_counter + 1
                    else
                        duplicates_skipped = duplicates_skipped + 1
                    end
                end
            end
        end
        
        if not lines_processed then
            local clean_text = text:gsub("\r", "")
            if not is_duplicate_replica(actor_name, t1, t2, clean_text) then
                ass_actors[actor_name] = true
                table.insert(ass_lines, {
                    t1 = t1,
                    t2 = t2,
                    text = clean_text,
                    actor = actor_name,
                    enabled = true,
                    index = line_idx_counter
                })
                line_idx_counter = line_idx_counter + 1
            else
                duplicates_skipped = duplicates_skipped + 1
            end
        end
    end
    
    if duplicates_skipped > 0 and not dont_rebuild then
        show_snackbar(T("IMPORT_OMIT_DUP_F") .. duplicates_skipped, "info")
    end
    
    local lines_added = #ass_lines - initial_len
    if lines_added > 0 then
        ACHIEVEMENTS.add_stat("ach_1_srt_import", 1)
        ACHIEVEMENTS.add_stat("ach_1_total_lines", lines_added)
    end
    
    if not dont_rebuild then
        rebuild_regions() -- This handles clearing old regions and re-adding all (including new ones)
    end
    
    return duplicates_skipped
end

--- Parse VTT timestamp format (HH:MM:SS.mmm or MM:SS.mmm)
--- @param str string Timestamp string
--- @return number Time in seconds
local function parse_vtt_timestamp(str)
    local h, m, s, ms = str:match("(%d+):(%d+):(%d+)%.(%d+)")
    if h then
        return (tonumber(h) * 3600) + (tonumber(m) * 60) + tonumber(s) + (tonumber(ms) / 1000)
    end
    -- Try MM:SS.mmm format
    m, s, ms = str:match("(%d+):(%d+)%.(%d+)")
    if m then
        return (tonumber(m) * 60) + tonumber(s) + (tonumber(ms) / 1000)
    end
    return 0
end

--- Import VTT subtitle file
--- @param file_path string|nil Absolute path to file or nil to prompt user
local function import_vtt(file_path, dont_rebuild)
    local initial_len = #ass_lines
    local file = file_path
    if not file then
        local retval
        retval, file = reaper.GetUserFileNameForRead("", "Import VTT", "vtt")
        if not retval then return end
    end
    local f = io.open(file, "r")
    if not f then return end
    UI_STATE.current_file_name = file:match("([^/\\]+)$")
    UI_STATE.current_file_path = file
    
    -- Auto-toggle dictionaries by rules based on filename
    DICT.auto_toggle_by_rules(file)
    
    -- Check for deadline in filename
    local dl = DEADLINE.parse_from_name(UI_STATE.current_file_name)
    if dl then DEADLINE.set(dl) end
    
    local content = fix_encoding(f:read("*all"))
    f:close()
    content = content:gsub("\r\n", "\n")
    
    -- Derive Actor Name from Filename
    local actor_name = UI_STATE.current_file_name:gsub("%.vtt$", ""):gsub("%.VTT$", "")
    
    -- Ensure State Init
    if not ass_lines then ass_lines = {} end
    if not ass_actors then ass_actors = {} end
    
    if not dont_rebuild then
        push_undo("Import VTT")
    end
    
    UI_STATE.ass_file_loaded = true

    -- Clear UI state
    table_filter_state.text = ""
    table_selection = {}
    last_selected_row = nil
    
    -- Register Actor
    ass_actors[actor_name] = true
    
    local line_idx_counter = get_next_line_index()
    
    local duplicates_skipped = 0
    -- VTT format: timestamp --> timestamp followed by text
    -- Skip WEBVTT header and optional metadata
    for s_start, s_end, text in content:gmatch("(%d[%d:%.]+) %-%-> (%d[%d:%.]+)[^\n]*\n(.-)\n\n") do
        local t1 = parse_vtt_timestamp(s_start)
        local t2 = parse_vtt_timestamp(s_end)
        
        -- Remove VTT tags like <v Name> or <c.classname>
        text = text:gsub("<[^>]+>", "")
        
        if not is_duplicate_replica(actor_name, t1, t2, text) then
            table.insert(ass_lines, {
                t1 = t1,
                t2 = t2,
                text = text,
                actor = actor_name,
                enabled = true,
                index = line_idx_counter
            })
            line_idx_counter = line_idx_counter + 1
        else
            duplicates_skipped = duplicates_skipped + 1
        end
    end
    
    if duplicates_skipped > 0 and not dont_rebuild then
        show_snackbar(T("IMPORT_OMIT_DUP_F") .. duplicates_skipped, "info")
    end
    
    local lines_added = #ass_lines - initial_len
    if lines_added > 0 then
        ACHIEVEMENTS.add_stat("ach_1_vtt_import", 1)
        ACHIEVEMENTS.add_stat("ach_1_total_lines", lines_added)
    end
    
    if not dont_rebuild then
        rebuild_regions()
    end
    
    return duplicates_skipped
end

--- Parse timestamp in various formats to seconds
--- Supports: MM:SS, M:SS, MM.SS, HH:MM:SS, HH:MM:SS.mmm, MM:SS.mmm, HH.MM.SS
--- @param str string Timestamp string
--- @return number|nil Time in seconds or nil if invalid
local function parse_notes_timestamp(str)
    -- Try HH:MM:SS.mmm format
    local h, m, s, ms = str:match("^(%d+):(%d+):(%d+)%.(%d+)$")
    if h then
        return (tonumber(h) * 3600) + (tonumber(m) * 60) + tonumber(s) + (tonumber(ms) / 1000)
    end
    
    -- Try MM:SS.mmm format (without hours)
    m, s, ms = str:match("^(%d+):(%d+)%.(%d+)$")
    if m then
        return (tonumber(m) * 60) + tonumber(s) + (tonumber(ms) / 1000)
    end
    
    -- Try HH:MM:SS format
    h, m, s = str:match("^(%d+):(%d+):(%d+)$")
    if h then
        return (tonumber(h) * 3600) + (tonumber(m) * 60) + tonumber(s)
    end
    
    -- Try HH.MM.SS format (dots instead of colons)
    h, m, s = str:match("^(%d+)%.(%d+)%.(%d+)$")
    if h then
        return (tonumber(h) * 3600) + (tonumber(m) * 60) + tonumber(s)
    end
    
    -- Try MM:SS format
    m, s = str:match("^(%d+):(%d+)$")
    if m then
        return (tonumber(m) * 60) + tonumber(s)
    end
    
    -- Try MM.SS format (dots instead of colons)
    m, s = str:match("^(%d+)%.(%d+)$")
    if m then
        return (tonumber(m) * 60) + tonumber(s)
    end
    
    return nil
end

--- Export selected subtitles to SRT format
local function export_as_srt()
    local out_lines, default_filename = UTILS.prepare_export_data(".srt")
    if not out_lines then return end

    -- Save Dialog
    local retval, filename = reaper.JS_Dialog_BrowseForSaveFile(T("EXPORT_TO_SRT"), "", default_filename, "SRT files (.srt)\0*.srt\0All Files (*.*)\0*.*\0")
    
    if retval == 1 and filename ~= "" then
        if not filename:match("%.srt$") then
            filename = filename .. ".srt"
        end
        
        local file = io.open(filename, "w")
        if not file then
            reaper.ShowMessageBox(T("FAILED_TO_CREATE_FILE") .. filename, T("ERROR"), 0)
            return
        end

        local fmt_time = function(secs)
            local h = math.floor(secs / 3600)
            local m = math.floor((secs % 3600) / 60)
            local s = math.floor(secs % 60)
            local ms = math.floor((secs % 1) * 1000)
            return string.format("%02d:%02d:%02d,%03d", h, m, s, ms)
        end

        for i, l in ipairs(out_lines) do
            -- SRT Index
            file:write(tostring(i) .. "\n")
            
            -- Timecode
            file:write(fmt_time(l.t1) .. " --> " .. fmt_time(l.t2) .. "\n")
            
            -- Text with optional Actor name
            local text = l.text
            if cfg.auto_srt_split == "():" then
                if l.actor and l.actor ~= "" then
                    text = "(" .. l.actor .. "): " .. text
                end
            elseif cfg.auto_srt_split == "[]:" then
                if l.actor and l.actor ~= "" then
                    text = "[" .. l.actor .. "]: " .. text
                end
            end
            
            file:write(text .. "\n\n")
        end
        
        file:close()
        show_snackbar(T("EXPORTED_1") .. #out_lines .. T("EXPORTED_3"), "success")
    end
end

local function export_as_ass()
    local out_lines, default_filename = UTILS.prepare_export_data(".ass")
    if not out_lines then return end

    -- Construct dictionary metadata & get names
    local active_dicts = {}
    local active_dict_names = {}
    if DICT and DICT.dicts then
        for _, d in ipairs(DICT.dicts) do
            if DICT.is_selected(d.id) then
                table.insert(active_dicts, d)
                table.insert(active_dict_names, d.name)
            end
        end
    end
    local json_dicts = (#active_dicts > 0) and STATS.json_encode({ dicts = active_dicts }) or nil
    
    if #active_dict_names > 0 then
        -- Insert dictionary names before the .ass extension
        local base = default_filename:gsub("%.ass$", "")
        default_filename = base .. "_" .. table.concat(active_dict_names, "_") .. ".ass"
    end

    -- Save Dialog
    local retval, filename = reaper.JS_Dialog_BrowseForSaveFile(T("EXPORT_TO_ASS"), "", default_filename, "ASS files (.ass)\0*.ass\0All Files (*.*)\0*.*\0")
    
    if retval == 1 and filename ~= "" then
        if not filename:match("%.ass$") then
            filename = filename .. ".ass"
        end
        
        local file = io.open(filename, "w")
        if not file then
            reaper.ShowMessageBox(T("FAILED_TO_CREATE_FILE") .. filename, T("ERROR"), 0)
            return
        end

        local function fmt_time_ass(secs)
            local h = math.floor(secs / 3600)
            local m = math.floor((secs % 3600) / 60)
            local s = math.floor(secs % 60)
            local ms = math.floor((secs % 1) * 100 + 0.5) % 100
            return string.format("%d:%02d:%02d.%02d", h, m, s, ms)
        end

        local function format_dialogue(l)
            if not ASS.ass_format_order or #ASS.ass_format_order == 0 then
                local text = l.text:gsub("\r\n", "\n"):gsub("\n", "\\N")
                return string.format("Dialogue: 0,%s,%s,Default,%s,0,0,0,,%s", 
                    fmt_time_ass(l.t1), fmt_time_ass(l.t2), l.actor or "Default", text)
            end
            
            local fields = {}
            for _, field in ipairs(ASS.ass_format_order) do
                local val = ""
                if field == "Start" then
                    val = fmt_time_ass(l.t1)
                elseif field == "End" then
                    val = fmt_time_ass(l.t2)
                elseif field == "Text" then
                    val = l.text:gsub("\r\n", "\n"):gsub("\n", "\\N")
                elseif field == "Name" or field == "Actor" then
                    val = l.actor or "Default"
                elseif field == "Style" then
                    val = (l.metadata and l.metadata[field]) or "Default"
                elseif field == "Effect" then
                    val = (l.metadata and l.metadata[field]) or ""
                else
                    val = (l.metadata and l.metadata[field]) or "0"
                end
                table.insert(fields, val)
            end
            return "Dialogue: " .. table.concat(fields, ",")
        end

        if ASS.ass_header_order and #ASS.ass_header_order > 0 then
            for _, section_name in ipairs(ASS.ass_header_order) do
                local lines = ASS.ass_header_sections[section_name]
                if lines then
                    for _, line in ipairs(lines) do
                        file:write(line .. "\n")
                    end
                end
                
                if section_name == "Events" then
                    if json_dicts then
                        file:write(format_dialogue({
                            t1 = 0, t2 = 0, actor = "SubassDict", text = json_dicts, enabled = true
                        }) .. "\n")
                    end
                    for _, l in ipairs(out_lines) do
                        file:write(format_dialogue(l) .. "\n")
                    end
                end
            end
        else
            -- Default Fallback
            file:write("[Script Info]\nTitle: Subass Export\nScriptType: v4.00+\nPlayResX: 1920\nPlayResY: 1080\nScaledBorderAndShadow: yes\n\n")
            file:write("[V4+ Styles]\nFormat: Name, Fontname, Fontsize, PrimaryColour, SecondaryColour, OutlineColour, BackColour, Bold, Italic, Underline, StrikeOut, ScaleX, ScaleY, Spacing, Angle, BorderStyle, Outline, Shadow, Alignment, MarginL, MarginR, MarginV, Encoding\n")
            file:write("Style: Default,Arial,20,&H00FFFFFF,&H000000FF,&H00000000,&H00000000,0,0,0,0,100,100,0,0,1,2,2,2,10,10,10,1\n\n")
            file:write("[Events]\nFormat: Layer, Start, End, Style, Name, MarginL, MarginR, MarginV, Effect, Text\n")
            if json_dicts then
                file:write(string.format("Dialogue: 0,0:00:00.00,0:00:00.00,Default,SubassDict,0,0,0,,%s\n", json_dicts))
            end
            for _, l in ipairs(out_lines) do
                file:write(format_dialogue(l) .. "\n")
            end
        end
        
        file:close()
        show_snackbar(T("EXPORTED_1") .. #out_lines .. T("EXPORTED_3"), "success")
    end
end

--- Copy per-actor statistics to clipboard
--- @param include_time boolean Whether to include time/duration in the statistics
local function copy_actors_statistics(include_time)
    local total_repl = 0
    local total_words = 0
    local total_time = 0
    
    local act_stats = {}
    for _, line in ipairs(ass_lines) do
        if line.enabled then
            local act = line.actor or "Unknown"
            if not act_stats[act] then
                act_stats[act] = {r = 0, w = 0, t = 0}
            end
            local st = act_stats[act]
            st.r = st.r + 1
            total_repl = total_repl + 1
            
            local clean = (line.text or ""):gsub("{{+.-}}+", ""):gsub("{.-}", ""):gsub("\\[Nnh]", " ")
            local _, count = clean:gsub("%S+", "")
            st.w = st.w + count
            total_words = total_words + count
            
            if include_time and line.t1 and line.t2 then
                local dur = line.t2 - line.t1
                st.t = st.t + dur
                total_time = total_time + dur
            end
        end
    end
    
    if total_repl == 0 then
        show_snackbar(T("NO_DATE"), "info")
        return
    end
    
    local sorted_actors = {}
    local max_actor_len = 0
    for act in pairs(act_stats) do 
        table.insert(sorted_actors, act) 
        -- Count physical bytes for rough padding
        if string.len(act) > max_actor_len then
            max_actor_len = string.len(act)
        end
    end
    
    -- Sort by lines descending, then alphabetically for ties
    table.sort(sorted_actors, function(a, b)
        if act_stats[a].r == act_stats[b].r then return a < b end
        return act_stats[a].r > act_stats[b].r
    end)
    
    local function fmt_time(secs)
        local h = math.floor(secs / 3600)
        local m = math.floor((secs % 3600) / 60)
        local s = math.floor(secs % 60)
        if h > 0 then
            return string.format("%02d:%02d:%02d", h, m, s)
        else
            return string.format("%02d:%02d", m, s)
        end
    end
    
    local lines = {}
    table.insert(lines, T("ST_C_TOTAL_LINES") .. total_repl)
    if include_time then
        table.insert(lines, T("ST_C_TOTAL_TIME") .. fmt_time(total_time))
    end
    table.insert(lines, T("ST_C_TOTAL_WORDS") .. total_words)
    table.insert(lines, "")
    table.insert(lines, T("ST_C_AC_STATS"))
    table.insert(lines, "")
    
    for i, act in ipairs(sorted_actors) do
        local st = act_stats[act]
        local l_pct = (st.r / total_repl) * 100
        local w_pct = total_words > 0 and ((st.w / total_words) * 100) or 0
        local t_pct = total_time > 0 and ((st.t / total_time) * 100) or 0
        
        -- Pad actor string
        local pad = string.rep(" ", math.max(0, max_actor_len - string.len(act)))
        table.insert(lines, string.format("%-2d %s%s", i, act, pad))
        
        -- Second line formatted with percentage spacing
        local stats_line = ""
        if include_time then
            stats_line = string.format(T("ST_C_FORMAT_1"), 
                st.r, l_pct, fmt_time(st.t), t_pct, st.w, w_pct)
        else
            stats_line = string.format(T("ST_C_FORMAT_2"), 
                st.r, l_pct, st.w, w_pct)
        end
        table.insert(lines, stats_line)
        table.insert(lines, "")
    end
    
    -- Remove trailing empty line for clean copy
    if #lines > 0 and lines[#lines] == "" then
        table.remove(lines, #lines)
    end
    
    local text = table.concat(lines, "\n")
    set_clipboard(text)

    ACHIEVEMENTS.add_stat("ach_26_count", 1)
    show_snackbar(T("ST_C_COPIED"), "success")
end

--- Import director notes from text format and create markers
local function import_notes()
    -- Show instruction dialog
    local response = reaper.ShowMessageBox(
        T("N_COPY_INFO"),
        T("N_IMPORT_RETAKES"),
        1  -- OK/Cancel
    )

    if response ~= 1 then return end
    
    -- Read from clipboard
    local input = fix_encoding(get_clipboard())
    if not input or input == "" then
        show_snackbar(T("CLIPBOARD_IS_EMPTY"), "error")
        return
    end
    
    -- Parse input
    local raw_notes = {}
    local failed_lines = {} -- Track lines that couldn't be parsed
    local current_actor = nil -- Track active actor (single, persistent)
    
    for line in input:gmatch("[^\r\n]+") do
        line = line:match("^%s*(.-)%s*$") -- Trim
        if line ~= "" then
            local matched = false
            
            -- Check for actor line: ⭐ Name
            local actor_name = line:match("^⭐(.*)$")
            if actor_name then
                -- Remove variation selector (U+FE0F = \239\184\143) and trim spaces
                actor_name = actor_name:gsub("\239\184\143", ""):match("^%s*(.-)%s*$")
                
                if actor_name == "" or actor_name == T("NO_RETAKES_DUBBER") then
                    current_actor = nil -- Clear active actor
                else
                    current_actor = actor_name -- Set new persistent actor
                end
                matched = true
            else
                -- Check if line starts with timestamp or # (new entry)
                -- If not, it's a continuation of previous note
                local is_continuation = not line:match("^[#%d]")
                
                if is_continuation and #raw_notes > 0 then
                    -- Append to last note's text
                    raw_notes[#raw_notes].text = raw_notes[#raw_notes].text .. "\n" .. line
                    matched = true
                else
                    -- Try region index format first: #N - text
                    local region_idx, note_text = line:match("^#(%d+)%s*%-%s*(.*)$")
                    if region_idx then
                        region_idx = tonumber(region_idx)
                        
                        -- Find region by index in ass_lines
                        local found = false
                        if ass_lines then
                            for _, ass_line in ipairs(ass_lines) do
                                if ass_line.index == region_idx then
                                    table.insert(raw_notes, {time = ass_line.t1, text = note_text, actor = current_actor})
                                    found = true
                                    matched = true
                                    break
                                end
                            end
                        end
                        
                        if not found then
                            table.insert(failed_lines, line)
                        end
                    else
                        -- More precise timestamp pattern that doesn't capture text
                        -- Match: digits, then colons/dots with digits, ending before " - "
                        -- Examples: 2:26, 02:38.080, 1:2:26, 2.30
                        
                        -- Try to match time range format: TIME - TIME - text
                        local time1_str, time2_str, note_text = line:match("^([%d:%.]+)%s*%-%s*([%d:%.]+)%s*%-%s*(.*)$")
                        
                        if time1_str and time2_str and note_text then
                            -- Time range format: create marker at first time with end time in text
                            local time1 = parse_notes_timestamp(time1_str)
                            local time2 = parse_notes_timestamp(time2_str)
                            
                            if time1 and time2 then
                                -- Normalize to "TIMESTAMP - Text" format for consistent highlighting
                                local full_text = string.format("%s - %s", time2_str, note_text)
                                table.insert(raw_notes, {time = time1, text = full_text, actor = current_actor})
                                matched = true
                            else
                                table.insert(failed_lines, line)
                            end
                        else
                            -- Try single time format: TIME - text
                            time1_str, note_text = line:match("^([%d:%.]+)%s*%-%s*(.*)$")
                            if time1_str and note_text then
                                local time = parse_notes_timestamp(time1_str)
                                if time then
                                    table.insert(raw_notes, {time = time, text = note_text, actor = current_actor})
                                    matched = true
                                else
                                    table.insert(failed_lines, line)
                                end
                            else
                                table.insert(failed_lines, line)
                            end
                        end
                    end
                end
            end
        end
    end

    -- Merge duplicate notes (same time and text) and combine actors
    local merged_notes = {}
    local note_map = {} -- key: "time_text", value: index in merged_notes

    for _, note in ipairs(raw_notes) do
        -- Create a unique key for matching duplicates (using formatted time to avoid float precision issues)
        local key = string.format("%.3f_%s", note.time, note.text)
        
        if note_map[key] then
            -- Note exists, check if we need to add actor
            local existing_note = merged_notes[note_map[key]]
            if note.actor then
                -- Check if actor is already in the list
                local has_actor = false
                for _, act in ipairs(existing_note.actors) do
                    if act == note.actor then has_actor = true; break; end
                end
                
                if not has_actor then
                    table.insert(existing_note.actors, note.actor)
                end
            end
        else
            -- New unique note
            local new_entry = {
                time = note.time,
                text = note.text,
                actors = {}
            }
            if note.actor then
                table.insert(new_entry.actors, note.actor)
            end
            table.insert(merged_notes, new_entry)
            note_map[key] = #merged_notes
        end
    end
    
    -- Finalize notes list for creation
    local notes = {}
    for _, note in ipairs(merged_notes) do
        if #note.actors > 0 then
            ensure_director_actors(note.actors)
        end

        local final_text = note.text
        if #note.actors > 0 then
            table.sort(note.actors) -- Sort actors alphabetically for consistency
            local actor_prefix = "[" .. table.concat(note.actors, ", ") .. "] "
            final_text = actor_prefix .. final_text
        end
        table.insert(notes, {time = note.time, text = final_text})
    end

    if #notes == 0 then
        show_snackbar(T("N_NO_RETAKES_IN_C_FOUND"), "error")
        return
    end
    
    -- Show warning if some lines failed to parse
    if #failed_lines > 0 then
        local warning_msg = string.format(T("N_UNABLE_REC_D"), #failed_lines)
        for i, failed_line in ipairs(failed_lines) do
            if i <= 10 then -- Show max 10 failed lines
                warning_msg = warning_msg .. "• " .. failed_line .. "\n"
            end
        end
        if #failed_lines > 10 then
            warning_msg = warning_msg .. string.format(T("N_ERR_ANOTHER_10"), #failed_lines - 10)
        end
        warning_msg = warning_msg .. T("N_ERR_CONTINUE")
        
        local response = reaper.ShowMessageBox(warning_msg, T("WARNING"), 4) -- 4 = Yes/No
        if response ~= 6 then -- 6 = Yes
            return
        end
    end
    
    -- Create markers
    push_undo(T("N_IMPORT_RETAKES"))
    
    -- Build lookup of existing markers
    update_marker_cache()
    local existing_markers = {}
    for _, m in ipairs(prompter_drawer.marker_cache.markers) do
        local key = string.format("%.3f_%s", m.pos, m.name)
        existing_markers[key] = true
    end

    local created_count = 0
    local skipped_count = 0

    reaper.PreventUIRefresh(1)
    reaper.Undo_BeginBlock()
    for _, note in ipairs(notes) do
        local key = string.format("%.3f_%s", note.time, note.text)
        if not existing_markers[key] then
            -- Always create marker (not region)
            reaper.AddProjectMarker2(0, false, note.time, 0, note.text, -1, reaper.ColorToNative(255, 200, 100) | 0x1000000)
            created_count = created_count + 1
        else
            skipped_count = skipped_count + 1
        end
    end
    reaper.Undo_EndBlock(T("N_IMPORT_RETAKES"), -1)
    reaper.PreventUIRefresh(-1)
    reaper.UpdateArrange()
    
    -- Force prompter drawer caches to refresh
    prompter_drawer.marker_cache.count = -1
    prompter_drawer.filtered_cache.state_count = -1
    prompter_drawer.has_markers_cache.count = -1

    ACHIEVEMENTS.add_stat("ach_5_import_count", 1)
    ACHIEVEMENTS.add_stat("ach_5_corr_item_count", created_count)

    local msg = T("N_MARKERS_CREATED") .. created_count
    if skipped_count > 0 then
        msg = msg .. T("N_EXISTING_OMITED") .. skipped_count .. ")"
    end
    show_snackbar(msg, "success")
    UI_STATE.ass_file_loaded = true -- Enable Actor view
end

--- Import director notes from CSV file and create markers
--- CSV format: #,Name,Start
--- @param file_path string|nil Optional file path, if nil shows file dialog
local function import_notes_from_csv(file_path)
    local file = file_path
    if not file then
        local retval
        retval, file = reaper.GetUserFileNameForRead("", T("IMPORT_RETAKES_FROM_CSV"), "*.csv")
        if not retval or not file then return end
    end

    UI_STATE.current_file_name = file:match("([^/\\]+)$")
    UI_STATE.current_file_path = file
    
    -- Check for deadline in filename
    local dl = DEADLINE.parse_from_name(UI_STATE.current_file_name)
    if dl then DEADLINE.set(dl) end
    
    local f = io.open(file, "r")
    if not f then
        show_snackbar(T("UNABLE_TO_OPEN_FILE"), "error")
        return
    end
    
    local content = fix_encoding(f:read("*all"))
    f:close()
    
    -- Parse CSV (RFC 4180 compliant - handles multiline quoted fields)
    local notes = {}
    
    -- Character-by-character parser to handle quoted fields with newlines
    local function parse_csv_content(text)
        local records = {}
        local current_record = {}
        local current_field = ""
        local in_quotes = false
        local i = 1
        
        while i <= #text do
            local char = text:sub(i, i)
            local next_char = text:sub(i+1, i+1)
            
            if in_quotes then
                if char == '"' then
                    if next_char == '"' then
                        -- Escaped quote ""
                        current_field = current_field .. '"'
                        i = i + 1
                    else
                        -- End of quoted field
                        in_quotes = false
                    end
                else
                    -- Any character inside quotes (including \n, \r)
                    current_field = current_field .. char
                end
            else
                if char == '"' then
                    -- Start of quoted field
                    in_quotes = true
                elseif char == ',' then
                    -- Field separator
                    table.insert(current_record, current_field)
                    current_field = ""
                elseif char == '\n' or char == '\r' then
                    -- End of record (skip \r\n combinations)
                    if char == '\r' and next_char == '\n' then
                        i = i + 1
                    end
                    if #current_field > 0 or #current_record > 0 then
                        table.insert(current_record, current_field)
                        if #current_record > 0 then
                            table.insert(records, current_record)
                        end
                        current_record = {}
                        current_field = ""
                    end
                else
                    -- Regular character
                    current_field = current_field .. char
                end
            end
            
            i = i + 1
        end
        
        -- Add last field and record if any
        if #current_field > 0 or #current_record > 0 then
            table.insert(current_record, current_field)
            if #current_record > 0 then
                table.insert(records, current_record)
            end
        end
        
        return records
    end
    
    local records = parse_csv_content(content)
    
    -- Process parsed records
    for line_num, parts in ipairs(records) do
        -- Skip header line (starts with #)
        if #parts >= 3 and not (parts[1] or ""):match("^#") then
            -- parts[1] = ID (M1, M2, etc)
            -- parts[2] = Name (text)
            -- parts[3] = Start (time)
            -- parts[4] = Color (optional)
            
            local name = parts[2]
            local time_str = parts[3]
            
            -- Parse REAPER time format: seconds.frames.subframes (e.g., 80.3.00)
            -- Or standard format: MM:SS.mmm
            local time
            
            -- Try REAPER format first (NNN.F.SS)
            local sec, frames = time_str:match("^(%d+)%.%d+%.%d+$")
            if sec then
                time = tonumber(sec)
            else
                -- Try standard timestamp formats
                time = parse_notes_timestamp(time_str)
            end
            
            if time and name then
                local color_hex = parts[4]
                local color_val
                if color_hex and color_hex:match("^%x%x%x%x%x%x$") then
                    local r = tonumber(color_hex:sub(1,2), 16)
                    local g = tonumber(color_hex:sub(3,4), 16)
                    local b = tonumber(color_hex:sub(5,6), 16)
                    color_val = reaper.ColorToNative(r, g, b) | 0x1000000
                end
                
                ensure_director_actors(name)
                table.insert(notes, {time = time, text = name, color = color_val})
            end
        end
    end
    
    if #notes == 0 then
        show_snackbar(T("MO_MARKERS_FOUND_IN_FILE"), "error")
        return
    end
    
    -- Create markers
    push_undo(T("IMPORT_RETAKES_FROM_CSV"))
    
    -- Build lookup of existing markers
    update_marker_cache()
    local existing_markers = {}
    for _, m in ipairs(prompter_drawer.marker_cache.markers) do
        local key = string.format("%.3f_%s", m.pos, m.name)
        existing_markers[key] = true
    end

    local created_count = 0
    local skipped_count = 0

    reaper.PreventUIRefresh(1)
    reaper.Undo_BeginBlock()
    for _, note in ipairs(notes) do
        local key = string.format("%.3f_%s", note.time, note.text)
        if not existing_markers[key] then
            local marker_color = note.color or (reaper.ColorToNative(255, 200, 100) | 0x1000000)
            reaper.AddProjectMarker2(0, false, note.time, 0, note.text, -1, marker_color)
            created_count = created_count + 1
        else
            skipped_count = skipped_count + 1
        end
    end
    reaper.Undo_EndBlock(T("IMPORT_RETAKES_FROM_CSV"), -1)
    reaper.PreventUIRefresh(-1)
    reaper.UpdateArrange()
    
    -- Force prompter drawer caches to refresh
    prompter_drawer.marker_cache.count = -1
    prompter_drawer.filtered_cache.state_count = -1
    prompter_drawer.has_markers_cache.count = -1

    ACHIEVEMENTS.add_stat("ach_5_import_count", 1)
    ACHIEVEMENTS.add_stat("ach_5_corr_item_count", created_count)

    local msg = T("N_MARKERS_CREATED") .. created_count
    if skipped_count > 0 then
        msg = msg .. T("N_EXISTING_OMITED") .. skipped_count .. ")"
    end
    show_snackbar(msg, "success")
end

--- Import ASS/SSA subtitle file, parsing styles and events
--- @param file_path string|nil Absolute path to file or nil to prompt user
local function import_ass(file_path, dont_rebuild)
    local initial_len = #ass_lines
    local file = file_path
    if not file then
        local retval
        retval, file = reaper.GetUserFileNameForRead("", "Import ASS", "ass")
        if not retval then return end
    end
    local f = io.open(file, "r")
    if not f then return end
    UI_STATE.current_file_name = file:match("([^/\\]+)$")
    UI_STATE.current_file_path = file
    
    -- Auto-toggle dictionaries by rules based on filename
    DICT.auto_toggle_by_rules(file)
    
    -- Check for deadline in filename
    local dl = DEADLINE.parse_from_name(UI_STATE.current_file_name)
    if dl then DEADLINE.set(dl) end
    
    local content = fix_encoding(f:read("*all"))
    f:close()
    
    content = content:gsub("\r\n", "\n")
    
    -- Ensure State Init
    if not ass_lines then ass_lines = {} end
    if not ass_actors then ass_actors = {} end
    
    UI_STATE.ass_file_loaded = true
    local line_idx_counter = get_next_line_index()
    
    -- Clear UI state
    table_filter_state.text = ""
    table_selection = {}
    last_selected_row = nil
    
    local duplicates_skipped = 0 -- Always 0 for ASS now
    local in_events = false
    local format_def = nil
    local current_section = nil

    ASS.ass_header_sections = {}
    ASS.ass_header_order = {}
    
    -- Dubber metadata detection
    local metadata_str = content:match("; SubassDubbers: ([^\n]+)")
    
    -- If not found in comments, scan Dialogue lines for SubassMetadata
    if not metadata_str then
        metadata_str = content:match("Dialogue:[^,]+,[^,]+,[^,]+,[^,]+,SubassMetadata,[^,]+,[^,]+,[^,]+,,([^\n]+)")
    end

    local selected_dubber_actors = nil
    if metadata_str then
        metadata_str = metadata_str:gsub("\\N", "\n"):gsub("\\n", "\n")
        local success, assignments = pcall(function() return STATS.json_decode(metadata_str) end)
        if success and type(assignments) == "table" then
            -- Sync with DUBBERS data
            if DUBBERS and DUBBERS.load then
                DUBBERS.load() -- Ensure latest data
                local dubber_names_map = {}
                for _, n in ipairs(DUBBERS.data.names) do dubber_names_map[n] = true end
                
                for name, assigned_actors in pairs(assignments) do
                    if type(name) == "string" and type(assigned_actors) == "table" then
                        if not dubber_names_map[name] then
                            table.insert(DUBBERS.data.names, name)
                            dubber_names_map[name] = true
                        end
                        if not DUBBERS.data.assignments[name] then
                            DUBBERS.data.assignments[name] = {}
                        end
                        for actor, is_on in pairs(assigned_actors) do
                            if type(actor) == "string" then
                                DUBBERS.data.assignments[name][actor] = (is_on == true)
                                DUBBERS.version = DUBBERS.version + 1
                            end
                        end
                    end
                end
                DUBBERS.save()
            end

            local dubber_names = {}
            for name, val in pairs(assignments) do 
                if type(name) == "string" and type(val) == "table" then
                    table.insert(dubber_names, name) 
                end
            end
            table.sort(dubber_names)
            
            if #dubber_names > 0 then
                local menu_str = T("IMPORT_VIEW_ALL_SC") .. table.concat(dubber_names, "|")
                gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
                local ret = gfx.showmenu(menu_str)
                if ret > 1 then
                    local chosen = dubber_names[ret - 1]
                    selected_dubber_actors = assignments[chosen] or {}
                    show_snackbar(T("DUBBER_MODE_IMPORT") .. chosen, "info")
                end
            end
        end
    end

    -- Dictionary metadata detection
    local dict_str = content:match("Dialogue:[^,]+,[^,]+,[^,]+,[^,]+,SubassDict,[^,]+,[^,]+,[^,]+,,([^\n]+)")
    if dict_str then
        dict_str = dict_str:gsub("\\N", "\n"):gsub("\\n", "\n")
        local success, imported_payload = pcall(function() return STATS.json_decode(dict_str) end)
        if success and type(imported_payload) == "table" then
            local imported_dicts = imported_payload.dicts or imported_payload
            if type(imported_dicts) == "table" and #imported_dicts > 0 then
                -- Load existing dictionaries
                local script_path = ({reaper.get_action_context()})[2]
                local base_dir = script_path:match("^(.*[\\/])") or ""
                local dict_file = base_dir .. "dictionary/data/user_dictionaries.json"
                
                local existing_data = { dictionaries = {} }
                local f = io.open(dict_file, "r")
                if f then
                    local fc = f:read("*a")
                    f:close()
                    local dec = STATS.json_decode(fc)
                    if type(dec) == "table" and type(dec.dictionaries) == "table" then
                        existing_data = dec
                    end
                end
                
                -- Merge imported dicts into existing
                local existing_map = {}
                for i, d in ipairs(existing_data.dictionaries) do
                    if d.id then existing_map[d.id] = i end
                end
                
                local imported_ids = {}
                local modified = false
                for _, imp_d in ipairs(imported_dicts) do
                    if type(imp_d) == "table" and imp_d.id and imp_d.name then
                        table.insert(imported_ids, imp_d.id)
                        if existing_map[imp_d.id] then
                            -- Replace existing with imported
                            existing_data.dictionaries[existing_map[imp_d.id]] = imp_d
                        else
                            -- Add new
                            table.insert(existing_data.dictionaries, imp_d)
                        end
                        modified = true
                    end
                end
                
                if modified then
                    local fw = io.open(dict_file, "w")
                    if fw then
                        fw:write(STATS.json_encode(existing_data))
                        fw:close()
                    end
                end
                
                -- Activate imported dictionaries
                if DICT then
                    for _, id in ipairs(imported_ids) do
                        DICT.selected_ids[id] = true
                    end
                    DICT.save_selected()
                    DICT.load()
                    show_snackbar(T("IMPORT_DIC_ACTV") .. #imported_ids, "success")
                end
            end
        end
    end

    for line in content:gmatch("([^\n]*)\n?") do
        local section = line:match("^%[(.*)%]")
        if section then
            in_events = (section == "Events")
            current_section = section
            table.insert(ASS.ass_header_order, section)
            ASS.ass_header_sections[section] = {}
        end

        if not current_section and not section then
            -- Pre-header section
            if not ASS.ass_header_sections["__pre__"] then
                table.insert(ASS.ass_header_order, 1, "__pre__")
                ASS.ass_header_sections["__pre__"] = {}
            end
            table.insert(ASS.ass_header_sections["__pre__"], line)
        elseif current_section then
            if in_events then
                if line:match("^Dialogue:") then
                    -- Process below
                else
                    -- Capture everything else in Events (Format, comments, empty lines)
                    table.insert(ASS.ass_header_sections[current_section], line)
                end
            else
                -- Normal section line (includes header)
                table.insert(ASS.ass_header_sections[current_section], line)
            end
        end

        if in_events then
            if line:match("^Format:") then
                ASS.ass_format_def = {}
                ASS.ass_format_order = {}
                local fmt_str = line:match("^Format:%s*(.*)")
                local idx = 1
                for field in (fmt_str .. ","):gmatch("(.-),") do
                    field = field:match("^%s*(.-)%s*$")
                    if field ~= "" then
                        ASS.ass_format_def[field] = idx
                        table.insert(ASS.ass_format_order, field)
                        idx = idx + 1
                    end
                end
            elseif line:match("^Dialogue:") and ASS.ass_format_def then
                -- Skip metadata line if it's in the actual event list
                if line:match(",SubassMetadata,") then goto next_line end

                local body = line:match("^Dialogue:%s*(.*)")
                local fields = {}
                local max_field_idx = 0
                for _, f_idx in pairs(ASS.ass_format_def) do
                    if f_idx > max_field_idx then max_field_idx = f_idx end
                end
                
                local search_start = 1
                for i = 1, max_field_idx - 1 do
                    local comma_pos = body:find(",", search_start)
                    if not comma_pos then break end
                    table.insert(fields, body:sub(search_start, comma_pos - 1))
                    search_start = comma_pos + 1
                end
                -- The rest of the line is the last field (usually 'Text')
                table.insert(fields, body:sub(search_start))
                
                local i_start = ASS.ass_format_def["Start"]
                local i_end = ASS.ass_format_def["End"]
                local i_text = ASS.ass_format_def["Text"]
                local i_name = ASS.ass_format_def["Name"] or ASS.ass_format_def["Actor"] -- Usually "Name" in ASS
                
                if i_start and i_end and i_text then
                    local t1 = parse_ass_timestamp(fields[i_start])
                    local t2 = parse_ass_timestamp(fields[i_end])
                    local text = fields[i_text]
                    local actor = i_name and fields[i_name] or "Unknown"
                    actor = actor:match("^%s*(.-)%s*$") -- Clean
                    if actor == "" then actor = "Unknown" end

                    -- Extract all metadata fields for duplicate check and storage
                    local line_metadata = {}
                    for field, f_idx in pairs(ASS.ass_format_def) do
                        if field ~= "Start" and field ~= "End" and field ~= "Text" and field ~= "Name" and field ~= "Actor" then
                            line_metadata[field] = fields[f_idx]
                        end
                    end

                    text = text:gsub("\\N", "\n"):gsub("\\n", "\n")
                    
                    local is_enabled = true
                    if selected_dubber_actors then
                        is_enabled = selected_dubber_actors[actor] == true
                    end

                    table.insert(ass_lines, {
                        t1=t1, t2=t2, text=text, actor=actor, enabled=is_enabled,
                        index = line_idx_counter,
                        metadata = line_metadata
                    })
                    line_idx_counter = line_idx_counter + 1
                    
                    if ass_actors[actor] == nil then 
                        ass_actors[actor] = is_enabled 
                    else
                        -- If actor already exists, we only enable it if it's assigned to us
                        if selected_dubber_actors then
                            ass_actors[actor] = ass_actors[actor] or (selected_dubber_actors[actor] == true)
                        end
                    end

                end
            end
        end
        ::next_line::
    end

    local lines_added = #ass_lines - initial_len
    if lines_added > 0 then
        ACHIEVEMENTS.add_stat("ach_1_ass_import", 1)
        ACHIEVEMENTS.add_stat("ach_1_total_lines", lines_added)
    end

    -- Initial Build
    if not dont_rebuild then
        push_undo("Import ASS")
        update_regions_cache() 
        rebuild_regions() -- This calls save_project_data
    end

    return duplicates_skipped or 0
end

-- =============================================================================
-- STRESS MARKS (UKRAINIAN ACCENT MARKS)
-- =============================================================================

--- Apply stress marks from dictionary file to all subtitles
-- Forward declaration
local apply_stress_marks_async 

-- Callback for when stress tool finishes
local function on_stress_complete(output, script_path, export_count, temp_out, log_file, temp_in, is_windows, python_success)
    local changed_lines = 0
    local ai_error_type = nil
    
    UI_STATE.script_loading_state.active = false
    
    -- Check if success by verifying output file content (run_async_command manages process wait)
    -- In run_async_command callback, 'output' is the STDOUT of the command wrapper.
    -- But we care about 'temp_out' file existence/content or log file errors.
    
    -- 1. Check temp_out
    local f_out = io.open(temp_out, "r")
    if f_out then
        local head = f_out:read(10) -- Peek
        f_out:close()
        
        if head and head ~= "" then
            -- SUCCESS: Parse output
            f_out = io.open(temp_out, "r")
            local content = f_out:read("*all")
            f_out:close()
            
            local stressed_texts = {}
            local current_text = ""
            local current_idx = -1
            
            for l in (content .. "\n"):gmatch("(.-)\r?\n") do
                local entry_start = l:match("^%s*%[SUBASS_ENTRY_START%]%s*$")
                local index_match = l:match("^%s*%[SUBASS_INDEX:(%d+)%]%s*$")
                local entry_end = l:match("^%s*%[SUBASS_ENTRY_END%]%s*$")
                
                if entry_start then
                    current_text = ""
                    current_idx = -1
                elseif index_match then
                    current_idx = tonumber(index_match)
                elseif entry_end then
                    if current_idx ~= -1 then
                        -- Strip a trailing newline that might have been added by the loop
                        if current_text:sub(-1) == "\n" then current_text = current_text:sub(1, -2) end
                        stressed_texts[current_idx] = current_text
                    end
                else
                    current_text = current_text .. l .. "\n"
                end
            end
            
            -- Important: stressed_texts is now indexed by the actual export index
            local ptr = 1
            local changed_count = 0
            for i, line in ipairs(ass_lines) do
                if ass_actors[line.actor] then
                    if stressed_texts[ptr] then
                        if line.text ~= stressed_texts[ptr] then
                            line.text = stressed_texts[ptr]
                            changed_lines = changed_lines + 1
                        end
                    end
                    ptr = ptr + 1
                end
            end
            python_success = true
            os.remove(temp_out)
        end
    end
    
    if not python_success then
        -- Check logs for errors
        local f_log = io.open(log_file, "r")
        if f_log then
            local logs = f_log:read("*all")
            f_log:close()
            if logs:find("PYTHON_VERSION_TOO_OLD") then ai_error_type = "VERSION"
            elseif logs:find("DEPENDENCY_INSTALL_FAILED") then ai_error_type = "DEPENDENCY"
            elseif logs:find("Operation not permitted") or logs:find("Access is denied") then ai_error_type = "PERMISSION"
            elseif logs:find("not recognized") or logs:find("not found") then ai_error_type = "PYTHON_MISSING"
            else ai_error_type = "UNKNOWN" end
                reaper.ShowConsoleMsg("AI Tool Failure Info:\n" .. logs .. "\n")
        else
            ai_error_type = "TIMEOUT_OR_CRASH"
        end
    end
    os.remove(temp_in)
    
    -- ERROR HANDLING (No fallback)
    if not python_success then
        UI_STATE.script_loading_state.active = false
        
        local msg = T("STRESS_ERR_HEADER")
        if ai_error_type == "PERMISSION" then
            if is_windows then
                msg = msg .. string.format(T("STRESS_ERR_PERMISSION_WIN"), script_path)
            else
                msg = msg .. T("STRESS_ERR_PERMISSION_MAC")
            end
        elseif ai_error_type == "PYTHON_MISSING" then
            if is_windows then
                msg = msg .. T("STRESS_ERR_PYTHON_MISSING_WIN")
            else
                msg = msg .. T("STRESS_ERR_PYTHON_MISSING_MAC")
            end
        elseif ai_error_type == "VERSION" then
            if is_windows then
                msg = msg .. T("STRESS_ERR_VERSION_WIN")
            else
                msg = msg .. T("STRESS_ERR_VERSION_MAC")
            end
        elseif ai_error_type == "DEPENDENCY" then
            msg = msg .. T("STRESS_ERR_DEPENDENCY")
        elseif ai_error_type == "TIMEOUT" or ai_error_type == "TIMEOUT_OR_CRASH" then
            msg = msg .. T("STRESS_ERR_TIMEOUT")
        else
            msg = msg .. T("STRESS_ERR_UNKNOWN")
        end
        
        msg = msg .. T("STRESS_ERR_PATH") .. script_path
        reaper.MB(msg, T("STRESS_ERR_TITLE"), 0)
        return
    end
    
    UI_STATE.script_loading_state.active = false
    
    if changed_lines > 0 then
        push_undo("Авто-наголоси (" .. changed_lines .. ")")
        cleanup_actors()
        rebuild_regions()
        save_project_data(UI_STATE.last_project_id)
        reaper.MarkProjectDirty(0) -- SAVE ON CHANGE
        show_snackbar(string.format(T("ACCENTS_ADDED"), changed_lines), "success")

        ACHIEVEMENTS.add_stat("ach_2_total_lines", changed_lines)
        ACHIEVEMENTS.add_stat("ach_2_run_count", 1)
    else
        show_snackbar(T("ACCENTS_NOT_NEEDED"), "info")
        ACHIEVEMENTS.add_stat("ach_2_run_count", 1)
    end

    UI_STATE.show_cats = UI_STATE.tmp_show_cats
end

--- Apply stress marks asynchronously
apply_stress_marks_async = function()
    UI_STATE.script_loading_state.active = true
    UI_STATE.script_loading_state.text = T("STRESS_INIT")
    
    -- Calculate paths OUTSIDE coroutine to avoid debug.getinfo issues
    local function get_actual_script_path()
        local info = debug.getinfo(1, "S")
        local path = info.source
        if path:sub(1, 1) == "@" then path = path:sub(2) end
        
        -- Fallback: try to get absolute path from action context if path is just a filename
        if not path:find("[\\/]") then
            local _, filename = reaper.get_action_context()
            if filename and filename ~= "" and filename:find("[\\/]") then
                path = filename
            end
        end

        local separator = package.config:sub(1, 1)
        local opposite_sep = (separator == "/" and "\\" or "/")
        
        -- Normalize path separators
        path = path:gsub(opposite_sep, separator)
        
        -- Extract the directory part (everything up to the last separator)
        local dir = path:gsub("[^" .. (separator == "\\" and "\\\\" or separator) .. "]*$", "")

        if not dir or dir == "" then 
            -- Ultimate fallback to ResourcePath/Scripts
            dir = reaper.GetResourcePath() .. separator .. "Scripts" .. separator
            dir = dir:gsub(opposite_sep, separator)
        end

        -- Ensure trailing separator and append 'stress'
        if dir:sub(-1) ~= separator then
            dir = dir .. separator
        end
        
        return dir .. "stress" .. separator
    end
    local script_path = get_actual_script_path()

    -- Use global coroutine for setup phase to allow yielding (fix initial freeze)
    global_coroutine = coroutine.create(function()
        coroutine.yield() -- Yield once to ensure Loader draws immediately

        UI_STATE.tmp_show_cats = UI_STATE.show_cats
        UI_STATE.show_cats = true
        
        local python_tool = script_path .. "ukrainian_stress_tool.py"
        
        -- Check Tool Existence
        local f_tool = io.open(python_tool, "r")
        local has_python_tool = (f_tool ~= nil)
        if f_tool then f_tool:close() end
    
        local export_count = 0
        local temp_in = script_path .. "temp_stress_in.srt"
        local temp_out = script_path .. "temp_stress_out.srt"
        local log_file = script_path .. "stress_debug.log"
        
        -- Prepare Data
        if has_python_tool then
            coroutine.yield()
            
            os.remove(temp_out)
            local f_in = io.open(temp_in, "w")
            if f_in then
                local time_batch_start = os.clock()
                for i, line in ipairs(ass_lines) do
                    if ass_actors[line.actor] then
                        export_count = export_count + 1
                        f_in:write("[SUBASS_ENTRY_START]\n")
                        f_in:write("[SUBASS_INDEX:" .. export_count .. "]\n")
                        f_in:write(line.text .. "\n")
                        f_in:write("[SUBASS_ENTRY_END]\n\n")
                    end
                    -- More aggressive yielding to prevent "Export Text" freeze
                    if (i % 50 == 0) and (os.clock() - time_batch_start > 0.01) then
                        coroutine.yield()
                        time_batch_start = os.clock()
                    end
                end

                f_in:close()

                if export_count > 0 then
                    UI_STATE.script_loading_state.text = T("STRESS_IT_TAKE_TIME")

                    coroutine.yield()
                    
                    local tool_p = python_tool
                    local in_p = temp_in
                    local out_p = temp_out
                    
                    local cmd_to_run = ""
                    
                    if is_windows then 
                        -- Windows: Directly run command to avoid blocking 'where python' check.
                        -- If python is missing, cmd will print error to log_file.
                        tool_p = tool_p:gsub("/", "\\")
                        in_p = in_p:gsub("/", "\\")
                        out_p = out_p:gsub("/", "\\")
                        log_file = log_file:gsub("/", "\\")
                        local py_exe = UTILS.get_win_py_exe(OTHER.rec_state.python.executable or "py -3")
                        cmd_to_run = string.format('%s "%s" "%s" -o "%s" > "%s" 2>&1', py_exe, tool_p, in_p, out_p, log_file)
                    else
                        -- Mac/Linux: Assume python3
                        cmd_to_run = string.format('python3 "%s" "%s" -o "%s" > "%s" 2>&1', tool_p, in_p, out_p, log_file)
                    end
                    
                    if cmd_to_run ~= "" then
                        -- We are done with coroutine setup, hand off to async system
                        run_async_command(cmd_to_run, function(out)
                            on_stress_complete(out, script_path, export_count, temp_out, log_file, temp_in, is_windows, false)
                        end, false, UI_STATE.script_loading_state.text)
                        global_coroutine = nil -- Coroutine finished its job
                        return 
                    end
                end
            end
        end
        
        -- If we got here, AI failed or tool missing, proceed immediately to fallback
        global_coroutine = nil
        on_stress_complete("", script_path, export_count, temp_out, log_file, temp_in, is_windows, false)
    end)
    
    -- Initial resume
    local ok, err = coroutine.resume(global_coroutine)
    if not ok then
        reaper.ShowConsoleMsg("Coroutine Error: " .. tostring(err) .. "\n")
        UI_STATE.script_loading_state.active = false
        global_coroutine = nil
    end
end

--- Handle Drag & Drop of SRT/ASS files
local function handle_drag_drop()
    local file_idx = 0
    local retval, dropped_file = gfx.getdropfile(file_idx)
    local imported_count = 0
    local total_duplicates = 0
    
    if retval > 0 then
        push_undo("Import (Drag & Drop)")
    end
    
    while retval > 0 do
        local ext = dropped_file:match("%.([^.]+)$")
        if ext then
            ext = ext:lower()
            if ext == "srt" then
                total_duplicates = total_duplicates + import_srt(dropped_file, true)
                imported_count = imported_count + 1
            elseif ext == "ass" then
                total_duplicates = total_duplicates + import_ass(dropped_file, true)
                imported_count = imported_count + 1
            elseif ext == "vtt" then
                total_duplicates = total_duplicates + import_vtt(dropped_file, true)
                imported_count = imported_count + 1
            elseif ext == "csv" then
                import_notes_from_csv(dropped_file)
            elseif ext == "wav" then
                local ok, err_msg = UTILS.import_compact_wav(dropped_file)
                if not ok then
                    show_snackbar(T("DG_IMPORT_ERR_1") .. tostring(err_msg), "error")
                end
            else
                show_snackbar(T("DG_IMPORT_ERR_F_1") .. ext:upper() .. T("DG_IMPORT_ERR_F_2"), "error")
            end
        else
            show_snackbar(T("DG_IMPORT_ERR_2"), "error")
        end
        
        file_idx = file_idx + 1
        retval, dropped_file = gfx.getdropfile(file_idx)
    end
    
    if imported_count > 0 then
        update_regions_cache()
        rebuild_regions()
        local msg = T("DG_FILE_I_COUNT") .. imported_count
        if total_duplicates > 0 then msg = msg .. T("DG_FILE_I_COUNT_DUP") .. total_duplicates .. ")" end
        show_snackbar(msg, "success")
    end
    
    gfx.getdropfile(-1) -- Clear drop queue
end

--- Delete all project regions
local function delete_all_regions()
    local resp = reaper.ShowMessageBox(T("DELETE_ALL_SURE_1"), T("DELETE_ALL_SURE_2"), 4)
    if resp ~= 6 then return end

    -- Clear project data
    ass_lines = {}
    ass_actors = {}
    
    -- Clear ASS metadata & styles
    ASS.actor_colors = {}
    ASS.ass_header_sections = {}
    ASS.ass_header_order = {}
    ASS.ass_events_header_lines = {}
    ASS.ass_format_def = nil
    ASS.ass_format_order = {}

    -- Clear Dubber data
    DUBBERS.data = {
        names = {},
        assignments = {}
    }
    DUBBERS.active_dubber_idx = 1

    UI_STATE.ass_file_loaded = false
    UI_STATE.current_file_name = nil
    UI_STATE.current_file_path = nil

    DICT.selected_ids = {}

    -- Clear undo/redo history
    undo_stack = {}
    redo_stack = {}

    rebuild_regions()
    save_project_data()
    DUBBERS.save() -- SAVE ON CHANGE
    DICT.save_selected()

    if show_snackbar then
        show_snackbar(T("DELETE_ALL_DONE"), "error")
    end
end

--- Get current script absolute path
local function get_script_path()
    local info = debug.getinfo(1, 'S')
    local path = ""
    if info and info.source then
        path = info.source:match("@?(.*)")
    end
    
    -- Fallback: try to get absolute path from action context
    if path == "" or not path:find("[\\/]") then
        local _, filename = reaper.get_action_context()
        if filename and filename ~= "" then
            path = filename
        end
    end

    local separator = package.config:sub(1, 1)
    local opposite_sep = (separator == "/" and "\\" or "/")
    return path:gsub(opposite_sep, separator)
end

--- Manage REAPER startup script. Edit REAPER __startup.lua file with our startup logic
--- @param enable boolean
local function toggle_reaper_startup(enable)
    local resource_path = reaper.GetResourcePath()
    local startup_path = resource_path:gsub("\\", "/") .. "/Scripts/__startup.lua"
    local script_path = get_script_path():gsub("\\", "/")
    
    if script_path == "" then return false end
    
    local lines = {}
    local f = io.open(startup_path, "r")
    if f then
        for line in f:lines() do
            table.insert(lines, line)
        end
        f:close()
    end
    
    -- Filter out existing subass startup lines
    local new_lines = {}
    local skip = false
    local tag_start = "-- Subass_Notes Startup Start"
    local tag_end = "-- Subass_Notes Startup End"
    
    for _, line in ipairs(lines) do
        if line:find(tag_start, 1, true) then
            skip = true
        elseif line:find(tag_end, 1, true) then
            skip = false
        elseif not skip then
            -- Cleanup legacy entries (untagged) that might contain unescaped Windows paths
            if not line:find("Subass_Notes.lua", 1, true) then
                table.insert(new_lines, line)
            end
        end
    end
    
    if enable then
        -- Find Command ID for better isolation
        local cmd_id = nil
        local kb_path = resource_path .. "/reaper-kb.ini"
        local f_kb = io.open(kb_path, "r")
        if f_kb then
            local escaped_path = script_path:gsub("([%%%^%$%(%)%.%[%]%*%+%-%?])", "%%%1")
            for line in f_kb:lines() do
                if line:find(escaped_path) then
                    local rs_part = line:match("RS([%a%d]+)")
                    if rs_part then
                        cmd_id = "_RS" .. rs_part
                        break
                    end
                end
            end
            f_kb:close()
        end

        local launch_cmd
        if cmd_id then
            launch_cmd = string.format("reaper.defer(function() reaper.Main_OnCommand(reaper.NamedCommandLookup(\"%s\"), 0) end)", cmd_id)
        else
            -- Fallback to dofile if not registered
            launch_cmd = string.format("reaper.defer(function() dofile([[%s]]) end)", script_path)
        end

        -- Add at the beginning to ensure it runs
        table.insert(new_lines, 1, tag_end)
        table.insert(new_lines, 1, launch_cmd)
        table.insert(new_lines, 1, tag_start)
    end
    
    local f_out = io.open(startup_path, "w")
    if f_out then
        for i, line in ipairs(new_lines) do
            f_out:write(line .. (i == #new_lines and "" or "\n"))
        end
        f_out:close()
        return true
    end
    return false
end

