-- TEXT EDITOR MODAL
-- =============================================================================

--- Wrap text to fit width, preserving newlines
local function wrap_text(text, max_w)
    local lines = {}
    -- Split by newline first to preserve manual paragraphs
    for p in string.gmatch(text.."\n", "(.-)\n") do
        if p:match("^%s*$") and p == "" then
            table.insert(lines, "")
        else
            local words = {}
            for w in p:gmatch("%S+") do table.insert(words, w) end
            
            local current_line = ""
            for _, w in ipairs(words) do
                local test_line = current_line == "" and w or (current_line .. " " .. w)
                -- Ignore stress marks for layout measurement
                local measure_line = test_line:gsub(acute or "", "")
                if gfx.measurestr(measure_line) > max_w then
                    table.insert(lines, current_line)
                    current_line = w
                else
                    current_line = test_line
                end
            end
            if current_line ~= "" then table.insert(lines, current_line) end
        end
    end
    
    -- Clean up the artificial trailing newline if original text didn't have one
    if #lines > 0 and lines[#lines] == "" and text:sub(-1) ~= "\n" then
        table.remove(lines)
    end
    
    return lines
end

--- Run auto-update script and show results
--- @param is_silent boolean If true, don't show "checking" loader or "up-to-date" message
local function check_for_updates(is_silent)
    local script_path = debug.getinfo(1,'S').source:match([[^@?(.*[\/])]])
    local py_script = script_path .. "subass_autoupdate.py"
    local py_exe = OTHER.rec_state.python.executable 
    
    if not py_exe or py_exe == "" then
        -- If detection hasn't finished, prefer 'py -3' on Windows as it's safer
        py_exe = is_windows and "py -3" or "python3"
    end
    
    if is_windows then py_exe = UTILS.get_win_py_exe(py_exe) end
    
    local cmd
    if is_windows then
        py_script = py_script:gsub("/", "\\")
        cmd = string.format('%s "%s" "%s"', py_exe, py_script, GL.script_title)
    else
        cmd = string.format("'%s' '%s' '%s'", py_exe, py_script, GL.script_title)
    end

    run_async_command(cmd, function(output)
        if not is_silent then UI_STATE.script_loading_state.active = false end
        if output and output ~= "" then
            -- Parse line-based format
            local data = {}
            data.update_available = output:match("UPDATE_AVAILABLE: (%a+)") == "true"
            data.current_title = output:match("CURRENT_TITLE: (.-)[\r\n]")
            data.latest_title = output:match("LATEST_TITLE: (.-)[\r\n]")
            data.manual_update = output:match("MANUAL_UPDATE: (%a+)") == "true"
            data.download_url = output:match("DOWNLOAD_URL: (.-)[\r\n]") or output:match("PATH: (.-)[\r\n]")
            data.description = output:match("DESCRIPTION_START[\r\n]*(.-)[\r\n]*DESCRIPTION_END")
            
            if data.update_available then
                local msg = string.format(T("SU_NEW_HAS_V"), data.latest_title or "v?", data.current_title or "v?")
                if data.description and data.description ~= "" then
                    msg = msg .. T("SU_WAHT_NEW") .. data.description .. "\n\n"
                end
                
                if data.manual_update then
                    msg = msg .. T("SU_MANUAL_UPDATE_TIP")
                    
                    -- MB Type 4 = Yes/No (Yes=6, No=7)
                    local res = reaper.MB(msg, T("SU_MANUAL_UPDATE"), 4)
                    if res == 6 then
                        UTILS.open_url("https://t.me/subass_notes")
                    end
                else
                    msg = msg .. T("SU_W_LIKE_UPDATE")
                    
                    -- MB Type 4 = Yes/No (Yes=6, No=7)
                    local res = reaper.MB(msg, T("SU_UPDATE_AVAILABLE"), 4)
                    if res == 6 then
                        -- Trigger update in python
                        local update_cmd
                        if is_windows then
                            update_cmd = string.format('%s "%s" --update "%s"', py_exe, py_script, data.download_url or "")
                        else
                            update_cmd = string.format("'%s' '%s' --update '%s'", py_exe, py_script, data.download_url or "")
                        end
                        
                        run_async_command(update_cmd, function(upd_output)
                            UI_STATE.script_loading_state.active = false
                            local ok_msg = T("SU_UPDATE_HB_DONE")
                            if upd_output and upd_output:find(ok_msg) then
                                reaper.MB(upd_output, T("SU_AUTO_UPDATER_TIT"), 0)
                                UTILS.restart_script()
                            else
                                reaper.MB(upd_output or T("SU_ERROR_UPDATE"), T("SU_AUTO_UPDATER_TIT"), 0)
                            end
                        end, false, T("SU_UPDATING"))
                    end
                end
            elseif not is_silent then
                -- If not available and NOT silent, we show either the python msg or "you have latest"
                local clean_out = output:gsub("UPDATE_AVAILABLE: false[\r\n]*", ""):gsub("CURRENT_TITLE: .-[\r\n]*", ""):match("^%s*(.-)%s*$")
                reaper.MB(clean_out ~= "" and clean_out or T("SU_YOU_LATEST_VERSION"), T("SU_CHECK_FOR_UP_TIT"), 0)
            end
        elseif not is_silent then
            reaper.MB(T("SU_ERROR_F_R_1") .. cmd, T("ERROR"), 0)
        end
    end, is_silent, T("SU_CHECKING_FOR_UPDATE"))
end

--- Wrap rich text (segments) to fit width
local function wrap_rich_text(segments, max_w, font_slot, font_name, base_size, is_header, first_line_indent)
    local lines = {}
    local current_line = {}
    local current_w = 0
    local is_first_line = true
    local last_was_space = true -- Track if we are at a word boundary
    
    for _, seg in ipairs(segments) do
        local tokens = {}
        -- Extract leading spaces if any
        local leading_sp = seg.text:match("^(%s+)")
        if leading_sp then table.insert(tokens, leading_sp) end
        
        -- Extract words and their trailing spaces
        for word, sp in seg.text:gmatch("(%S+)(%s*)") do
            table.insert(tokens, word)
            if sp ~= "" then table.insert(tokens, sp) end
        end
        
        if #tokens == 0 and #seg.text > 0 then
            table.insert(tokens, seg.text)
        end
        
        for _, token in ipairs(tokens) do
            local is_space = token:match("^%s+$") ~= nil
            
            -- Apply font based on segment/header status for measurement
            local f_flags, effective_font = 0, font_name
            local is_bold = seg.b or seg.is_bold or (is_header and not (seg.is_plain or seg.s))
            local is_italic = seg.i or seg.is_italic
            
            if is_italic then
                if font_name == "Helvetica" then effective_font = "Helvetica Oblique"
                else f_flags = f_flags + string.byte('i') end
            end
            if is_bold then
                if effective_font == font_name then 
                    if is_italic then f_flags = string.byte('b') | (string.byte('i') << 8)
                    else f_flags = string.byte('b') end
                elseif is_italic and font_name == "Helvetica" then 
                    effective_font = "Helvetica Bold Oblique"
                    f_flags = 0
                end
            end
            gfx.setfont(font_slot, effective_font, base_size, f_flags)
            
            -- Ignore stress marks for layout measurement
            local measure_word_for_width = token:gsub(acute, "")
            local token_w = gfx.measurestr(measure_word_for_width)
            
            local effective_max_w = (is_first_line and first_line_indent) and (max_w - first_line_indent) or max_w
            
            -- Trigger wrap if any part of a word overflows the line
            if not is_space and current_w + token_w > effective_max_w and current_w > 0 then
                if last_was_space then
                    -- Normal word-boundary break
                    table.insert(lines, current_line)
                    current_line = {}
                    current_w = 0
                    is_first_line = false
                else
                    -- Mid-word overflow! Backtrack to previous space in current line
                    local last_space_idx = nil
                    for j = #current_line, 1, -1 do
                        if current_line[j].text:match("%s$") then
                            last_space_idx = j
                            break
                        end
                    end
                    
                    if last_space_idx then
                        -- Everything after last_space_idx is part of the current word
                        local word_parts = {}
                        for j = last_space_idx + 1, #current_line do
                            table.insert(word_parts, current_line[j])
                        end
                        -- Remove from current line
                        for j = #current_line, last_space_idx + 1, -1 do
                            table.remove(current_line, j)
                        end
                        
                        table.insert(lines, current_line)
                        current_line = word_parts
                        current_w = 0
                        for _, p in ipairs(word_parts) do current_w = current_w + (p.width or 0) end
                        is_first_line = false
                    else
                        -- Entire line is one long word that doesn't fit. 
                        -- Move to new line (already ensured current_w > 0)
                        table.insert(lines, current_line)
                        current_line = {}
                        current_w = 0
                        is_first_line = false
                    end
                end
            end
            
            -- Skip leading spaces on a new line to avoid indenting wrapped text
            if current_w == 0 and is_space and #lines > 0 then
                -- skip this token
            else
                local last_seg = current_line[#current_line]
                
                -- Helper to compare colors
                local colors_match = false
                if not last_seg then
                elseif not last_seg.color and not seg.color then
                    colors_match = true
                elseif last_seg.color and seg.color then
                    colors_match = (last_seg.color[1] == seg.color[1] and 
                                    last_seg.color[2] == seg.color[2] and 
                                    last_seg.color[3] == seg.color[3])
                end

                local can_merge = last_seg and 
                    (last_seg.is_link == seg.is_link) and 
                    (last_seg.is_plain == seg.is_plain) and 
                    ((last_seg.b or last_seg.is_bold) == (seg.b or seg.is_bold)) and
                    ((last_seg.i or last_seg.is_italic) == (seg.i or seg.is_italic)) and
                    ((last_seg.u or false) == (seg.u or false)) and
                    ((last_seg.u_wave or false) == (seg.u_wave or false)) and
                    ((last_seg.s or false) == (seg.s or false)) and
                    (last_seg.comment == seg.comment) and
                    (last_seg.word == seg.word) and
                    colors_match
                
                if can_merge then
                    last_seg.text = last_seg.text .. token
                    last_seg.width = (last_seg.width or 0) + token_w
                else
                    local new_seg = {}
                    for k, v in pairs(seg) do new_seg[k] = v end
                    new_seg.text = token
                    new_seg.width = token_w
                    -- clear flags
                    new_seg.b = seg.b or seg.is_bold
                    new_seg.i = seg.i or seg.is_italic
                    new_seg.is_bold = new_seg.b
                    new_seg.is_italic = new_seg.i
                    new_seg.is_plain = seg.is_plain or false  -- Explicitly preserve is_plain
                    
                    table.insert(current_line, new_seg)
                end
                current_w = current_w + token_w
            end
            last_was_space = is_space
        end
    end
    
    if #current_line > 0 then
        table.insert(lines, current_line)
    end
    
    for _, l in ipairs(lines) do
        l.transformed = true
    end
    
    return lines
end

--- Draw and handle AI Assistant Overlay (Refined to Dropdown)
function DRAW_WINDOW.draw_ai_modal(skip_draw)
    if not ai_modal.show then 
        ai_modal.was_shown = false
        return 
    end

    local menu_w = 350
    local x = ai_modal.anchor_x - menu_w + 40
    local y = ai_modal.anchor_y + 5

    -- Pre-calculate content height to determine menu height
    local content_h = 0
    if ai_modal.current_step == "SELECT_TASK" then
        local list_h = #OTHER.AI_TASKS * (35 + 2) + 10
        local has_back = (#ai_modal.suggestions > 0)
        content_h = list_h + (has_back and 35 or 0)
    elseif ai_modal.current_step == "LOADING" then
        content_h = 60
    elseif ai_modal.current_step == "RESULTS" then
        local th = 0
        for _, sugg in ipairs(ai_modal.suggestions) do
            local wrapped = wrap_text(sugg.text, menu_w - 30)
            th = th + #wrapped * 18 + 15 + 5
        end
        content_h = th + 5 + 35 -- th + padding + footer
    elseif ai_modal.current_step == "ERROR" then
        content_h = 100
    end

    local menu_max_limit = 450
    local menu_h = math.min(content_h, menu_max_limit)
    
    -- Safety: don't go off screen vertically
    if y + menu_h > gfx.h - 10 then
        menu_h = gfx.h - y - 10
    end
    if menu_h < 40 then menu_h = 40 end

    -- Safety: don't go off screen horizontally
    if x < 10 then x = 10 end
    if x + menu_w > gfx.w - 10 then x = gfx.w - menu_w - 10 end

    -- Store bounds for focus checks
    ai_modal.x, ai_modal.y = x, y
    ai_modal.w, ai_modal.h = menu_w, menu_h

    -- Mouse Wheel Handling (High Priority)
    if gfx.mouse_wheel ~= 0 then
        if gfx.mouse_x >= x and gfx.mouse_x <= x + menu_w and gfx.mouse_y >= y and gfx.mouse_y <= y + menu_h then
            ai_modal.scroll = ai_modal.scroll + (gfx.mouse_wheel > 0 and -40 or 40)
            gfx.mouse_wheel = 0 -- Consume
        end
    end

    ai_modal.was_shown = true

    -- Clamp scroll (Unified)
    if ai_modal.scroll < 0 then ai_modal.scroll = 0 end
    if content_h > menu_h and ai_modal.scroll > content_h - menu_h then 
        ai_modal.scroll = content_h - menu_h 
    elseif content_h <= menu_h then
        ai_modal.scroll = 0
    end

    local changed = false
    
    if skip_draw then
        -- Interaction Handling (Only run in input pass)
        local mouse_in_menu = (gfx.mouse_x >= x and gfx.mouse_x <= x + menu_w and gfx.mouse_y >= y and gfx.mouse_y <= y + menu_h)
        local clicked = is_mouse_clicked()
        local now = os.clock()
        
        -- Capture current step at start of pass to isolate interaction
        local step = ai_modal.current_step

        -- Handle clicks outside
        if clicked and ai_modal.was_shown and (now - (ai_modal.last_click_time or 0) > 0.3) then
            if not mouse_in_menu then
                ai_modal.show = false
                return false
            end
        end
        
        -- Basic click debounce (general prevention of rapid clicks)
        local can_click = clicked and (now - (ai_modal.last_click_time or 0) > 0.25)
        
        -- HARD LOCK: If we just changed the step (e.g. Back button), 
        -- ignore ALL clicks for 0.5s to prevent bounce/phantom effects
        local state_locked = (now - (ai_modal.last_step_change_time or 0) < 0.5)
        if state_locked then can_click = false end

        if step == "SELECT_TASK" then
            local has_back = (#ai_modal.suggestions > 0)
            local footer_h = has_back and 35 or 0
            local view_h = menu_h - footer_h
            
            local btn_h = 35
            if can_click and mouse_in_menu then
                -- Check Footers FIRST (Prioritize navigation)
                if has_back and gfx.mouse_y >= y + view_h then
                    ai_modal.last_click_time = now
                    ai_modal.last_step_change_time = now
                    ai_modal.current_step = "RESULTS"
                    ai_modal.scroll = 0
                    return false -- Stop current pass after state change
                end

                -- Check List Items
                if gfx.mouse_y < y + view_h then
                    for i, t in ipairs(OTHER.AI_TASKS) do
                        local bx, by = x + 5, y + 5 + (i-1) * (btn_h + 2) - ai_modal.scroll
                        local bw = menu_w - 10
                        if by + btn_h > y and by < y + view_h then -- Visible?
                            if gfx.mouse_x >= bx and gfx.mouse_x <= bx + bw and gfx.mouse_y >= by and gfx.mouse_y <= by + btn_h then
                                ai_modal.last_click_time = now
                                if t.task == "CUSTOM" then
                                    local ok, input = reaper.GetUserInputs(T("AI_OPTION"), 1, T("AI_OPTION_F_E"), "")
                                    if ok and input ~= "" then
                                        request_ai_assistant_task(t.id, input, ai_modal.text, 3)
                                    end
                                else
                                    request_ai_assistant_task(t.id, t.task, ai_modal.text, t.count)
                                end
                                return false -- Handled
                            end
                        end
                    end
                end
            end
            
        elseif step == "RESULTS" then
            local footer_h = 35
            local view_h = menu_h - footer_h
            local curr_y = y + 5 - ai_modal.scroll
            
            if can_click and mouse_in_menu then
                -- Check Footer area (Half split for Back / Retry)
                if gfx.mouse_y >= y + view_h then
                    ai_modal.last_click_time = now
                    ai_modal.last_step_change_time = now
                    if gfx.mouse_x < x + menu_w / 2 then
                        ai_modal.current_step = "SELECT_TASK"
                        ai_modal.scroll = 0
                    else
                        -- ЩЕ Button
                        request_ai_assistant_task(ai_modal.last_id, ai_modal.last_task, ai_modal.text)
                        ai_modal.scroll = 0
                    end
                    return false -- Stop current pass after state change
                end

                -- Check Suggestions
                for i, sugg in ipairs(ai_modal.suggestions) do
                    local wrapped_lines = wrap_text(sugg.text, menu_w - 30)
                    local block_h = #wrapped_lines * 18 + 15
                    local bx, by = x + 5, curr_y
                    local bw = menu_w - 20
                    
                    if (by + block_h > y and by < y + view_h) and (gfx.mouse_y < y + view_h) then
                        if gfx.mouse_x >= bx and gfx.mouse_x <= bx + bw and
                           gfx.mouse_y >= by and gfx.mouse_y <= by + block_h then
                            ai_modal.last_click_time = now
                            local target = ai_modal.target_state or text_editor_state
                            local before = target.text:sub(1, ai_modal.sel_min)
                            local after = target.text:sub(ai_modal.sel_max + 1)
                            target.text = before .. sugg.text .. after
                            target.cursor = ai_modal.sel_min + #sugg.text
                            target.anchor = target.cursor
                            
                            changed = true
                            ai_modal.show = false
                            ai_modal.text = "" -- Clear session state on success
                            return true
                        end
                    end
                    curr_y = curr_y + block_h + 5
                end
            end
        elseif step == "ERROR" then
            if can_click and mouse_in_menu then
                -- Center button in footer for Error state
                if gfx.mouse_y >= y + menu_h - 40 then
                    ai_modal.last_click_time = now
                    ai_modal.last_step_change_time = now
                    ai_modal.current_step = "SELECT_TASK"
                    ai_modal.scroll = 0
                    return false
                end
            end
        end
        
        -- If mouse is interacting with this modal, blocking it from underlying elements
        if mouse_in_menu then
            gfx.mouse_cap = 0 
        end
        
        return changed
    end

    -- Draw Pass starts here
    local mouse_in_menu = UI_STATE.window_focused and (gfx.mouse_x >= x and gfx.mouse_x <= x + menu_w and
                           gfx.mouse_y >= y and gfx.mouse_y <= y + menu_h)

    -- Draw Menu Shadow
    set_color(UI.C_BLACK_OVERLAY)
    gfx.rect(x+3, y+3, menu_w, menu_h, 1)
    
    -- Capture current destination to return later
    local prev_dest = gfx.dest
    
    -- Prepare Buffer
    gfx.dest = OTHER.BUF.AI
    gfx.setimgdim(OTHER.BUF.AI, menu_w, menu_h)
    set_color(UI.C_TAB_INA)
    gfx.rect(0, 0, menu_w, menu_h, 1) -- Clear buffer with menu background
    
    if ai_modal.current_step == "SELECT_TASK" then
        local has_back = (#ai_modal.suggestions > 0)
        local footer_h = has_back and 35 or 0
        local view_h = menu_h - footer_h

        local btn_h = 35
        for i, t in ipairs(OTHER.AI_TASKS) do
            local bx, by = 5, 5 + (i-1) * (btn_h + 2) - ai_modal.scroll
            local bw = menu_w - 10
            
            -- Only draw if visible in view_h
            if by + btn_h > 0 and by < view_h then -- Visible?
                local hover = mouse_in_menu and 
                              (gfx.mouse_x >= x + bx and gfx.mouse_x <= x + bx + bw and
                               gfx.mouse_y >= y + by and gfx.mouse_y <= y + by + btn_h and
                               gfx.mouse_y < y + view_h)
                
                set_color(hover and UI.C_BTN_H or UI.C_BTN)
                gfx.rect(bx, by, bw, btn_h, 1)
                set_color(UI.C_TXT)
                gfx.setfont(F.std)
                local sw, sh = gfx.measurestr(T(t.name))
                gfx.x, gfx.y = bx + (bw - sw) / 2, by + (btn_h - sh) / 2
                gfx.drawstr(T(t.name))
            end
        end
        
        -- Draw Back Button Footer
        if has_back then
            set_color(UI.C_TAB_INA)
            gfx.rect(0, view_h, menu_w, footer_h, 1)
            set_color(UI.C_FR_BORDER)
            gfx.line(0, view_h, menu_w, view_h)
            
            local bbx, bby, bbw, bbh = 5, view_h + 5, menu_w - 10, footer_h - 10
            local hover_back = mouse_in_menu and
                               (gfx.mouse_x >= x + bbx and gfx.mouse_x <= x + bbx + bbw and
                                gfx.mouse_y >= y + bby and gfx.mouse_y <= y + bby + bbh)
            
            set_color(hover_back and UI.C_TAB_ACT or UI.C_TAB_INA)

            gfx.rect(bbx, bby, bbw, bbh, 1)
            set_color(UI.C_TXT)
            local sw, sh = gfx.measurestr(T("AI_BACK_TO_RESULTS"))
            gfx.x, gfx.y = bbx + (bbw - sw) / 2, bby + (bbh - sh) / 2
            gfx.drawstr(T("AI_BACK_TO_RESULTS"))
        end
        
    elseif ai_modal.current_step == "LOADING" then
        gfx.setfont(F.std)
        local msg = T("AI_WAIT_AI_WORKS")
        local mw, mh = gfx.measurestr(msg)
        gfx.x = (menu_w - mw) / 2
        gfx.y = (menu_h - mh) / 2
        gfx.drawstr(msg)
        
    elseif ai_modal.current_step == "RESULTS" then
        local footer_h = 35
        local view_h = menu_h - footer_h
        local curr_y = 5 - ai_modal.scroll
        
        for i, sugg in ipairs(ai_modal.suggestions) do
            local wrapped_lines = wrap_text(sugg.text, menu_w - 30)
            local block_h = #wrapped_lines * 18 + 15
            local bx, by = 5, curr_y
            local bw = menu_w - 20
            
            local alpha = sugg.is_old and 0.7 or 1.0
            
            local hover = mouse_in_menu and (by + block_h > 0 and by < view_h) and
                         (gfx.mouse_y < y + view_h) and
                         (gfx.mouse_x >= x + bx and gfx.mouse_x <= x + bx + bw and
                          gfx.mouse_y >= y + by and gfx.mouse_y <= y + by + block_h)
            
            set_color(hover and {UI.C_FR_MATCH_BG[1]*alpha, UI.C_FR_MATCH_BG[2]*alpha, UI.C_FR_MATCH_BG[3]*alpha, 1.0 * alpha} or 
                      {UI.C_FR_MATCH_INA[1]*alpha, UI.C_FR_MATCH_INA[2]*alpha, UI.C_FR_MATCH_INA[3]*alpha, 1.0 * alpha})
            gfx.rect(bx, by, bw, block_h, 1)
            set_color(UI.C_FR_MATCH_BORDER, alpha)
            gfx.rect(bx, by, bw, block_h, 0)
            
            set_color(UI.C_FR_MATCH_TXT, alpha)
            for li, line in ipairs(wrapped_lines) do
                gfx.x, gfx.y = bx + 8, by + 5 + (li-1) * 18
                gfx.drawstr(line)
            end
            curr_y = curr_y + block_h + 5
        end
        
        -- Fixed Footer with Back and Retry Buttons
        set_color(UI.C_TAB_INA)
        gfx.rect(0, view_h, menu_w, footer_h, 1)
        set_color(UI.C_FR_BORDER)
        gfx.line(0, view_h, menu_w, view_h)
        
        local bbx, bby, bbw, bbh = 5, view_h + 5, (menu_w / 2) - 7, footer_h - 10
        local hover_back = mouse_in_menu and
                          (gfx.mouse_x >= x + bbx and gfx.mouse_x <= x + bbx + bbw and
                           gfx.mouse_y >= y + bby and gfx.mouse_y <= y + bby + bbh)
        set_color(hover_back and UI.C_BTN_H or UI.C_BTN)
        gfx.rect(bbx, bby, bbw, bbh, 1)
        set_color(UI.C_TXT)
        local sw, sh = gfx.measurestr(T("BACK"))
        gfx.x, gfx.y = bbx + (bbw - sw) / 2, bby + (bbh - sh) / 2
        gfx.drawstr(T("BACK"))
        
        -- ЩЕ Button
        local rbx, rby, rbw, rbh = (menu_w / 2) + 2, view_h + 5, (menu_w / 2) - 7, footer_h - 10
        local hover_more = mouse_in_menu and
                           (gfx.mouse_x >= x + rbx and gfx.mouse_x <= x + rbx + rbw and
                            gfx.mouse_y >= y + rby and gfx.mouse_y <= y + rby + rbh)
        set_color(hover_more and UI.C_SEL or UI.C_BTN_DARK)
        gfx.rect(rbx, rby, rbw, rbh, 1)
        set_color(UI.C_TXT)
        local msw, msh = gfx.measurestr(T("MORE"))
        gfx.x, gfx.y = rbx + (rbw - msw) / 2, rby + (rbh - msh) / 2
        gfx.drawstr(T("MORE"))

    elseif ai_modal.current_step == "ERROR" then
        set_color(UI.C_FR_CLOSE)
        gfx.setfont(F.std)
        local mw, mh = gfx.measurestr(ai_modal.error_msg)
        gfx.x, gfx.y = (menu_w - mw) / 2, (menu_h - mh) / 2 - 20
        gfx.drawstr(ai_modal.error_msg)
        
        -- Back Button
        local bbx, bby, bbw, bbh = (menu_w - 80) / 2, menu_h - 35, 80, 25
        local hover = mouse_in_menu and
                     (gfx.mouse_x >= x + bbx and gfx.mouse_x <= x + bbx + bbw and
                      gfx.mouse_y >= y + bby and gfx.mouse_y <= y + bby + bbh)
        set_color(hover and UI.C_BTN_H or UI.C_BTN)
        gfx.rect(bbx, bby, bbw, bbh, 1)
        set_color(UI.C_TXT)
        local sw, sh = gfx.measurestr(T("BACK"))
        gfx.x, gfx.y = bbx + (bbw-sw)/2, bby + (bbh-sh)/2
        gfx.drawstr(T("BACK"))
    end

    -- Blit back to main destination
    gfx.dest = prev_dest
    gfx.blit(OTHER.BUF.AI, 1, 0, 0, 0, menu_w, menu_h, x, y, menu_w, menu_h)

    -- Draw Menu Border
    set_color(UI.C_TXT)
    gfx.rect(x, y, menu_w, menu_h, 0)

    -- Unified Scrollbar
    if content_h > menu_h then
        local sb_h = (menu_h / content_h) * menu_h
        local sb_y = y + (ai_modal.scroll / content_h) * menu_h
        set_color(UI.C_SCROLL_HDL)
        gfx.rect(x + menu_w - 8, sb_y, 4, sb_h, 1)
    end
    
    return changed
end

--- Play text-to-speech audio for Ukrainian word using ukrainian_tts.py
--- @param text string Text to synthesize
--- @param save_to_timeline boolean|nil If true, insert audio into active track at cursor
local function play_tts_audio(text, save_to_timeline)
    if not text then return end
    text = text:match("^%s*(.-)%s*$")
    if text == "" then return end

    if dict_modal.tts_loading then return end
    
    -- Set loading state immediately to prevent concurrent calls
    dict_modal.tts_loading = true
    dict_modal.tts_current_word = text
    UI_STATE.script_loading_state.active = true
    UI_STATE.script_loading_state.text = save_to_timeline and T("TTS_READING_2") or T("TTS_READING_1")
    
    -- Stop any existing preview
    if dict_modal.tts_preview and reaper.CF_Preview_Stop then
        reaper.CF_Preview_Stop(dict_modal.tts_preview)
        dict_modal.tts_preview = nil
    end

    -- Path to python script
    local script_path = debug.getinfo(1, "S").source:sub(2):match("(.*[/\\])")
    local tts_script = script_path .. "tts/ukrainian_tts.py"
    
    -- Check if TTS script exists
    local f = io.open(tts_script, "r")
    if not f then
        show_snackbar(T("TTS_S_NOT_FOUND"), "error")
        dict_modal.tts_loading = false
        UI_STATE.script_loading_state.active = false
        return
    end
    f:close()
    
    -- Determine voice and key based on configuration
    local voice_arg = ""
    local key_arg = ""

    local v_cfg = cfg.tts_voice_map[cfg.tts_voice] or cfg.tts_voice_map["Goroh: Оксана (Wavenet)"]
    voice_arg = string.format('--voice "%s"', v_cfg.voice)

    if v_cfg.engine == "eleven" then
        if cfg.eleven_api_key ~= "" then 
            key_arg = string.format('--eleven-key "%s"', cfg.eleven_api_key) 
        end
    end
    
    -- Build command using standardized python executable if available
    local is_windows = reaper.GetOS():match("Win")
    local tts_input_file = (script_path .. "/tts/tts_input.txt")
    if is_windows then tts_input_file = tts_input_file:gsub("/", "\\") end

    local f_in = io.open(tts_input_file, "w")
    if f_in then
        f_in:write(text)
        f_in:close()
    else
        show_snackbar(T("TTS_E_1"), "error")
        dict_modal.tts_loading = false
        UI_STATE.script_loading_state.active = false
        return
    end

    local cmd
    if is_windows then
        -- Normalize paths for Windows to avoid issues
        tts_script = tts_script:gsub("/", "\\")
        
        -- Use configured python executable from requirements state if available
        local py_exe = OTHER.rec_state.python.executable or "python"
        
        -- Pass text via file to avoid shell expansion/multiline issues
        cmd = string.format('%s "%s" --file "%s" %s %s', py_exe, tts_script, tts_input_file, voice_arg, key_arg)
    else
        -- Use detected python or fallback
        local py_exe = OTHER.rec_state.python.executable or "python3"
        -- Pass text via file for consistency and robustness
        cmd = string.format("'%s' '%s' --file '%s' %s %s", py_exe, tts_script, tts_input_file, voice_arg, key_arg)
    end
    
    -- Run command asynchronously using the standardized function
    run_async_command(cmd, function(output)
        dict_modal.tts_loading = false
        UI_STATE.script_loading_state.active = false
        
        if not output then
            show_snackbar(T("TTS_E_2"), "error")
            return
        end
        
        -- Extract MP3 path (last non-empty line of output)
        local mp3_path = nil
        for line in output:gmatch("[^\r\n]+") do
            if line and line ~= "" and not line:match("^Using cached") and not line:match("^Generating") and not line:match("^Successfully") then
                mp3_path = line
            end
        end
        
        if mp3_path then
            mp3_path = mp3_path:match("^%s*(.-)%s*$") -- Trim whitespace
        end
        
        if mp3_path and mp3_path ~= "" and not mp3_path:match("Error") and not mp3_path:match("Traceback") then
            -- Check if file exists
            local test_f = io.open(mp3_path, "r")
            if test_f then
                test_f:close()
                
                -- 1. Preview (Always for "Speak", or as requested)
                if not save_to_timeline then
                    local pcm_source = reaper.PCM_Source_CreateFromFile(mp3_path)
                    if pcm_source then
                        if reaper.CF_CreatePreview and reaper.CF_Preview_Play then
                            local preview = reaper.CF_CreatePreview(pcm_source)
                            if preview then
                                reaper.CF_Preview_Play(preview)
                                dict_modal.tts_preview = preview
                                show_snackbar(T("TTS_A_PLAY"), "success")
                            end
                        end
                    end
                end

                -- 2. Save to Timeline
                if save_to_timeline then
                    local track = reaper.GetSelectedTrack(0, 0)
                    if not track then
                        show_snackbar(T("TTS_S_TRACK_TO_I"), "error")
                    else
                        -- mode 0 = insert at edit cursor, move cursor? 
                        -- actually, mode 0 is standard. mode 1 = new track. 
                        reaper.InsertMedia(mp3_path, 0)
                        show_snackbar(T("TTS_A_ADDED_TO_T"), "success")
                    end
                end
            else
                show_snackbar(T("FILE_NOT_FOUND"), "error")
            end
        else
            show_snackbar(T("TTS_E_2"), "error")
            reaper.ShowConsoleMsg("\n══════════ TTS ERROR REPORT ══════════\n")
            reaper.ShowConsoleMsg(output or "No output available")
            reaper.ShowConsoleMsg("\n══════════════════════════════════════\n")
        end
    end, false, UI_STATE.script_loading_state.text)
end

--- Automatic actor assignment based on selected track activity
function UTILS.calc_track_items_by_actor()
    local sel_track_count = reaper.CountSelectedTracks(0)
    if sel_track_count == 0 then
        reaper.MB(T("SELECT_1_MORE_T_CTI"), T("ERROR"), 0)
        return
    end

    if not ass_lines or #ass_lines == 0 then
        reaper.MB(T("IMPORT_S_F_CTI"), T("ERROR"), 0)
        return
    end

    local tracks = {}
    for i = 0, sel_track_count - 1 do
        local tr = reaper.GetSelectedTrack(0, i)
        local _, name = reaper.GetTrackName(tr)
        table.insert(tracks, {obj = tr, name = name})
    end

    push_undo(T("CALC_L_CTI"))

    local new_ass_lines = {}
    local changed_count = 0

    for line_idx, line in ipairs(ass_lines) do
        local l_start = line.t1
        local l_end = line.t2
        if not l_start or not l_end then
            table.insert(new_ass_lines, line)
        else
            local replica_duration = l_end - l_start
            local track_overlaps = {}
            local max_overlap = 0
            local best_track_idx = nil
            
            for i, tr_info in ipairs(tracks) do
                local total_overlap = 0
                local it_count = reaper.CountTrackMediaItems(tr_info.obj)
                
                for j = 0, it_count - 1 do
                    local item = reaper.GetTrackMediaItem(tr_info.obj, j)
                    local i_start = reaper.GetMediaItemInfo_Value(item, "D_POSITION")
                    local i_len = reaper.GetMediaItemInfo_Value(item, "D_LENGTH")
                    local i_end = i_start + i_len

                    -- Calculate intersection duration
                    local overlap_start = math.max(i_start, l_start)
                    local overlap_end = math.min(i_end, l_end)
                    local overlap = overlap_end - overlap_start
                    
                    if overlap > 0 then
                        -- Significance check to avoid accidental "tails" from adjacent items
                        -- 1. Must be > 300ms (user threshold)
                        -- 2. Must cover > 20% of the ITEM itself OR > 50% of the REGION (for short regions)
                        local is_significant = (overlap > 0.300) and 
                                             ((overlap / i_len > 0.20) or (overlap / replica_duration > 0.50))
                        
                        if is_significant then
                            total_overlap = total_overlap + overlap
                        end
                    end
                end

                if total_overlap > 0 then
                    track_overlaps[i] = total_overlap
                    if total_overlap > max_overlap then
                        max_overlap = total_overlap
                        best_track_idx = i
                    end
                end
            end

            local found_actors = {}
            if best_track_idx then
                -- Always include the winner
                table.insert(found_actors, tracks[best_track_idx].name)
                
                -- Include other tracks if they are also significant and proportional to winner
                for i, overlap in pairs(track_overlaps) do
                    if i ~= best_track_idx then
                        -- Participant must be at least 50% of the winner and > 300ms
                        if overlap > (max_overlap * 0.5) and overlap > 0.300 then
                            table.insert(found_actors, tracks[i].name)
                        end
                    end
                end
            end

            if #found_actors == 0 then
                table.insert(new_ass_lines, line)
            elseif #found_actors == 1 then
                line.actor = found_actors[1]
                table.insert(new_ass_lines, line)
                changed_count = changed_count + 1
            else
                -- Multiple actors: Duplicate the line
                for _, act_name in ipairs(found_actors) do
                    local dup = {}
                    for k,v in pairs(line) do dup[k] = v end
                    dup.actor = act_name
                    table.insert(new_ass_lines, dup)
                end
                changed_count = changed_count + 1
            end
        end
    end

    ass_lines = new_ass_lines
    cleanup_actors()
    rebuild_regions()
    save_project_data()
    reaper.MarkProjectDirty(0) -- SAVE ON CHANGE
    show_snackbar(T("TAKES_PROCC_CTI") .. changed_count, "success")
end

--- Handle keyboard input for a text field state
--- @param input_queue table Key inputs
--- @param state table Input state {text, cursor, anchor}
--- @param is_multiline boolean Allow newlines
--- @return boolean True if text changed
local function process_input_events(input_queue, state, is_multiline, visual_lines)
    if not input_queue or #input_queue == 0 then return false end
    
    -- Reset auto-scroll suppression on any keyboard activity
    state.suppress_auto_scroll_until = 0
    
    local cap = gfx.mouse_cap
    local is_ctrl = (cap & 4 == 4)
    local is_alt = (cap & 16 == 16)
    local is_cmd = (cap & 32 == 32)
    local is_shift = (cap & 8 == 8)
    
    -- On Windows, AltGr triggers both Ctrl and Alt. We must not treat it as a modifier shortcut so characters like ґ can be typed.
    local is_mod = (is_ctrl and not is_alt) or is_cmd
    
    local changed = false
    local text = state.text or ""
    local cursor = state.cursor or #text
    local anchor = state.anchor or cursor
    
    local has_sel = (cursor ~= anchor)
    
    local function delete_selection()
        if not has_sel then return end
        local s_min, s_max = math.min(cursor, anchor), math.max(cursor, anchor)
        local before = text:sub(1, s_min)
        local after = text:sub(s_max + 1)
        text = before .. after
        cursor = s_min
        anchor = s_min
        has_sel = false
        changed = true
    end
    
    for _, char in ipairs(input_queue) do
        -- Select All (Mod+A)
        if char == 1 or (is_mod and (char == 97 or char == 65)) then
            anchor = 0
            cursor = #text
        elseif char == 4 then -- Ctrl+D (Deselect All)
            anchor = cursor
        -- Copy
        elseif (char == 3) or (is_mod and (char == 99 or char == 67)) then
            if has_sel then
                local s_min, s_max = math.min(cursor, anchor), math.max(cursor, anchor)
                set_clipboard(text:sub(s_min + 1, s_max))
            end
        -- Cut
        elseif (char == 24) or (is_mod and (char == 120 or char == 88)) then
            if has_sel then
                local s_min, s_max = math.min(cursor, anchor), math.max(cursor, anchor)
                set_clipboard(text:sub(s_min + 1, s_max))
                delete_selection()
            end
        -- Paste
        elseif (is_mod and (char == 118 or char == 86)) or (char == 22) then
            delete_selection()
            local clipboard = get_clipboard()
            if clipboard and clipboard ~= "" then
                if not is_multiline then clipboard = clipboard:gsub("\n", " "):gsub("\r", "") end
                text = text:sub(1, cursor) .. clipboard .. text:sub(cursor + 1)
                cursor = cursor + #clipboard
                anchor = cursor
                changed = true
            end
        -- Undo / Redo
        elseif (char == 26) or (is_mod and (char == 122 or char == 90)) then
            if state.history and state.history_pos then
                if is_shift then
                    -- Redo
                    if state.history_pos < #state.history then
                        state.history_pos = state.history_pos + 1
                        local snap = state.history[state.history_pos]
                        text, cursor, anchor = snap.text, snap.cursor, snap.anchor
                        changed = true
                    end
                else
                    -- Undo
                    if state.history_pos > 1 then
                        state.history_pos = state.history_pos - 1
                        local snap = state.history[state.history_pos]
                        text, cursor, anchor = snap.text, snap.cursor, snap.anchor
                        changed = true
                    end
                end
            end
        elseif is_mod and (char == 121 or char == 89) then -- Redo (Ctrl+Y)
            if state.history and state.history_pos and state.history_pos < #state.history then
                state.history_pos = state.history_pos + 1
                local snap = state.history[state.history_pos]
                text, cursor, anchor = snap.text, snap.cursor, snap.anchor
                changed = true
            end
        -- Escape / Enter
        elseif char == 27 or char == 13 then
            if char == 13 and is_shift and is_multiline then
                delete_selection()
                text = text:sub(1, cursor) .. "\n" .. text:sub(cursor + 1)
                cursor = cursor + 1
                anchor = cursor
                changed = true
            else
                state.focus = false
            end
        -- Backspace
        elseif char == 8 then
            if has_sel then
                delete_selection()
            elseif cursor > 0 then
                local before = text:sub(1, cursor)
                local after = text:sub(cursor + 1)
                local last_char_start = cursor
                while last_char_start > 1 do
                    local b = before:byte(last_char_start)
                    if not b or b < 128 or b >= 192 then break end
                    last_char_start = last_char_start - 1
                end
                text = before:sub(1, last_char_start - 1) .. after
                cursor = last_char_start - 1
                anchor = cursor
                changed = true
            end
        -- Delete (Forward Delete, e.g., Fn + Backspace on Mac)
        elseif char == 6579564 then
            if has_sel then
                delete_selection()
            elseif cursor < #text then
                local before = text:sub(1, cursor)
                local after = text:sub(cursor + 1)
                local next_char_end = 1
                while next_char_end < #after do
                    local b = after:byte(next_char_end + 1)
                    if not b or b < 128 or b >= 192 then break end
                    next_char_end = next_char_end + 1
                end
                text = before .. after:sub(next_char_end + 1)
                -- cursor doesn't move when forward deleting
                changed = true
            end 
        -- Navigation
        elseif char == 30064 then -- Up
            if not is_multiline or not visual_lines then
                cursor = 0
            else
                local cur_vi = 1
                for i, v in ipairs(visual_lines) do if cursor >= v.start_idx then cur_vi = i else break end end
                if cur_vi > 1 then
                    local cvl, pvl = visual_lines[cur_vi], visual_lines[cur_vi-1]
                    local rx = gfx.measurestr(cvl.text:sub(1, math.max(0, cursor - cvl.start_idx)))
                    local bd, bi = math.huge, 0
                    local coff = 0
                    while coff <= #pvl.text do
                        local d = math.abs(gfx.measurestr(pvl.text:sub(1, coff)) - rx)
                        if d < bd then bd, bi = d, coff end
                        if coff >= #pvl.text then break end
                        local b = pvl.text:byte(coff + 1); local len = 1
                        if b >= 240 then len = 4 elseif b >= 224 then len = 3 elseif b >= 192 then len = 2 end
                        coff = coff + len
                    end
                    cursor = pvl.start_idx + bi
                end
            end
            if not is_shift then anchor = cursor end
        elseif char == 1685026670 then -- Down
            if not is_multiline or not visual_lines then
                cursor = #text
            else
                local cur_vi = 1
                for i, v in ipairs(visual_lines) do
                    if cursor <= v.start_idx + #v.text then cur_vi = i; break end
                    cur_vi = i
                end
                if cur_vi < #visual_lines then
                    local cvl, nvl = visual_lines[cur_vi], visual_lines[cur_vi+1]
                    local rx = gfx.measurestr(cvl.text:sub(1, math.max(0, cursor - cvl.start_idx)))
                    local bd, bi = math.huge, 0
                    local coff = 0
                    while coff <= #nvl.text do
                        local d = math.abs(gfx.measurestr(nvl.text:sub(1, coff)) - rx)
                        if d < bd then bd, bi = d, coff end
                        if coff >= #nvl.text then break end
                        local b = nvl.text:byte(coff + 1); local len = 1
                        if b >= 240 then len = 4 elseif b >= 224 then len = 3 elseif b >= 192 then len = 2 end
                        coff = coff + len
                    end
                    cursor = nvl.start_idx + bi
                end
            end
            if not is_shift then anchor = cursor end
        elseif char == 1818584692 then -- Left
            if cursor > 0 then
                local cur = cursor
                while cur > 1 do
                    local b = text:byte(cur)
                    if not b or b < 128 or b >= 192 then break end
                    cur = cur - 1
                end
                cursor = cur - 1
                if not is_shift then anchor = cursor end
            end
        elseif char == 1919379572 then -- Right
            if cursor < #text then
                local cur = cursor + 1
                while cur < #text do
                    local b = text:byte(cur + 1)
                    if not b or b < 128 or b >= 192 then break end
                    cur = cur + 1
                end
                cursor = cur
                if not is_shift then anchor = cursor end
            end
        elseif char == 1752132965 then -- Home
            if not is_multiline or not visual_lines then
                cursor = 0
            else
                local cur_vi = 1
                for i, v in ipairs(visual_lines) do if cursor >= v.start_idx and cursor <= v.start_idx + #v.text then cur_vi = i; break end end
                cursor = visual_lines[cur_vi].start_idx
            end
            if not is_shift then anchor = cursor end
        elseif char == 6647396 then -- End
            if not is_multiline or not visual_lines then
                cursor = #text
            else
                local cur_vi = 1
                for i, v in ipairs(visual_lines) do if cursor >= v.start_idx and cursor <= v.start_idx + #v.text then cur_vi = i; break end end
                cursor = visual_lines[cur_vi].start_idx + #visual_lines[cur_vi].text
            end
            if not is_shift then anchor = cursor end
        -- Typing (Safe UTF-8)
        elseif not is_mod then
            -- Filter control codes
            if char >= 32 or char < 0 then
                delete_selection()
                local char_str = ""
                
                -- Handle high-bit flags from Reaper if present (unlikely for simple chars but possible)
                local unicode_flag = 0x75000000
                local cp = char
                if cp >= unicode_flag and cp < unicode_flag + 0x1000000 then
                    cp = cp - unicode_flag
                end
                
                -- Windows Reaper workaround: AltGr+г generates wrong Unicode (277/276 or ASCII 117/85) instead of ґ/Ґ
                if is_ctrl and is_alt then
                    if cp == 277 or cp == 117 then cp = is_shift and 1168 or 1169 end -- Ґ or ґ
                    if cp == 276 or cp == 85  then cp = 1168 end                      -- Ґ
                end

                -- UA Input Mapping (QWERTY -> UA ЙЦУКЕН)
                if state.ua_mode then
                    -- Detect OS layout: if we see UA letters, OS is in UA mode. 
                    -- If we see EN letters, OS is in EN mode.
                    if cp > 127 and cp < 2000 then 
                        state.os_is_ua = true
                    elseif (cp >= 97 and cp <= 122) or (cp >= 65 and cp <= 90) then
                        state.os_is_ua = false
                    end
                    
                    if not state.os_is_ua and OTHER.QWERTY_TO_UA[cp] then
                        cp = OTHER.QWERTY_TO_UA[cp]
                    end
                end

                -- Full UTF-8 Encode
                if cp < 128 then char_str = string.char(cp)
                elseif cp < 2048 then
                    char_str = string.char(192 + math.floor(cp/64), 128 + (cp % 64))
                elseif cp < 65536 then
                    char_str = string.char(224 + math.floor(cp/4096), 128 + math.floor((cp % 4096)/64), 128 + (cp % 64))
                elseif cp <= 1114111 then
                    char_str = string.char(0xF0 + math.floor(cp/262144), 0x80 + math.floor((cp % 262144)/4096), 0x80 + math.floor((cp % 4096)/64), 0x80 + (cp % 64))
                end
                
                if #char_str > 0 then
                    text = text:sub(1, cursor) .. char_str .. text:sub(cursor + 1)
                    cursor = cursor + #char_str
                    anchor = cursor
                    changed = true
                end
            end
        end
    end
    
    state.text = text
    state.cursor = cursor
    state.anchor = anchor
    return changed
end

-- Helper: Get char index from relative X
local function get_char_index_at_x(text, rel_x)
    if not text or text == "" then return 0 end
    local best_idx = 0
    local best_dist = 1000000
    
    local idx = 0
    while idx <= #text do
        local w = gfx.measurestr(text:sub(1, idx))
        local dist = math.abs(w - rel_x)
        if dist < best_dist then
            best_dist = dist
            best_idx = idx
        end
        
        if idx >= #text then break end
        
        -- Advance utf8
        local b = text:byte(idx + 1)
        local adv = 1
        if b then
            if b >= 240 then adv = 4
            elseif b >= 224 then adv = 3
            elseif b >= 192 then adv = 2
            end
        end
        idx = idx + adv
    end
    return best_idx
end

local function record_field_history(state)
    if not state.history then state.history = {} end
    if not state.history_pos then state.history_pos = 0 end
    
    -- Only record if something actually changed from the last history point
    local last_hist = state.history[state.history_pos]
    if last_hist and last_hist.text == state.text and 
       last_hist.cursor == state.cursor and 
       last_hist.anchor == state.anchor then
        return
    end

    if state.history_pos < #state.history then
        for i = #state.history, state.history_pos + 1, -1 do
            table.remove(state.history, i)
        end
    end
    table.insert(state.history, {
        text = state.text or "",
        cursor = state.cursor or 0,
        anchor = state.anchor or 0
    })
    state.history_pos = #state.history
    if #state.history > 100 then
        table.remove(state.history, 1)
        state.history_pos = state.history_pos - 1
    end
end

local function ui_text_input(id, x, y, w, h, state, placeholder, input_queue, is_multiline, is_director_mode, font_category_size, max_len)
    -- Load persistent UA mode if ID is provided and state is not yet initialized for this session
    if id and state.ua_mode == nil then
        state.ua_mode = (reaper.GetExtState(section_name, "ua_mode_" .. id) == "1")
    end
    gfx.setfont(font_category_size or F.std)
    local padding = S(5)
    local line_h = gfx.texth
    local text_w = w - padding * 2
    
    state.scroll = state.scroll or 0
    state.target_scroll = state.target_scroll or state.scroll
    state.suppress_auto_scroll_until = state.suppress_auto_scroll_until or 0
    state.cursor = state.cursor or 0
    state.anchor = state.anchor or state.cursor
    if (gfx.mouse_cap & 1 == 0) then state.is_dragging = false end
    
    if state.needs_focus_nudge and state.needs_focus_nudge > 0 then
        state.focus = true
        state.needs_focus_nudge = state.needs_focus_nudge - 1
    end

    -- Initialize history if not present
    if not state.history then
        state.history = {}
        state.history_pos = 0
        record_field_history(state)
    end

    local before_text = state.text or ""

    -- --- LAYOUT: Visual Wrapping ---
    local visual_lines = {}
    if is_multiline then
        local raw_pos = 0
        for ln in (before_text .. "\n"):gmatch("(.-)\n") do
            if ln == "" then
                table.insert(visual_lines, {text = "", start_idx = raw_pos, is_wrapped = false})
            else
                local remaining = ln
                local line_start = raw_pos
                while #remaining > 0 do
                    local fit_count = 0
                    local char_len = utf8.len(remaining) or #remaining
                    local low, high = 1, char_len
                    while low <= high do
                        local mid = math.floor((low + high) / 2)
                        local CharEnd = utf8.offset(remaining, mid + 1) or (#remaining + 1)
                        if gfx.measurestr(remaining:sub(1, CharEnd - 1)) <= text_w - S(5) then
                            fit_count = CharEnd - 1
                            low = mid + 1
                        else
                            high = mid - 1
                        end
                    end
                    if fit_count == 0 then 
                        local first_char_end = utf8.offset(remaining, 2) or (#remaining + 1)
                        fit_count = first_char_end - 1 
                    end
                    local segment = remaining:sub(1, fit_count)
                    remaining = remaining:sub(fit_count + 1)
                    table.insert(visual_lines, {text = segment, start_idx = line_start, is_wrapped = (#remaining > 0)})
                    line_start = line_start + fit_count
                end
            end
            raw_pos = raw_pos + #ln + 1
        end
        if #visual_lines == 0 then table.insert(visual_lines, {text = "", start_idx = 0}) end
    end

    -- --- INTERACTION ---
    local hover = UI_STATE.window_focused and (gfx.mouse_x >= x and gfx.mouse_x <= x + w and gfx.mouse_y >= y and gfx.mouse_y <= y + h)
    
    -- UA Toggle Button (Triangle in top-right)
    local ua_btn_w, ua_btn_h = S(16), S(16)
    local ua_btn_x, ua_btn_y = x + w - ua_btn_w, y
    local ua_btn_hover = hover and (gfx.mouse_x >= ua_btn_x and gfx.mouse_x <= ua_btn_x + ua_btn_w and gfx.mouse_y >= ua_btn_y and gfx.mouse_y <= ua_btn_y + ua_btn_h)
    
    if ua_btn_hover then
        local tip_id = "ua_input_toggle"
        if UI_STATE.tooltip_state.hover_id ~= tip_id then
            UI_STATE.tooltip_state.hover_id = tip_id
            UI_STATE.tooltip_state.start_time = reaper.time_precise()
        end
        UI_STATE.tooltip_state.text = T("FAST_UA_INPUT")
    end
    
    if (gfx.mouse_cap & 1 == 1) and (UI_STATE.last_mouse_cap & 1 == 0) and ua_btn_hover then
        state.ua_mode = not state.ua_mode
        if id then
            reaper.SetExtState(section_name, "ua_mode_" .. id, state.ua_mode and "1" or "0", true)
        end
        UI_STATE.mouse_handled = true
        return -- Defer other clicks to next frame or ignore
    end

    local function get_cursor_from_xy(mx, my)
        if not is_multiline then
            local rel_x = mx - (x + padding) + state.scroll
            return get_char_index_at_x(state.text, rel_x)
        else
            local rel_y = my - (y + padding) + state.scroll
            local v_idx = math.floor(rel_y / line_h) + 1
            v_idx = math.max(1, math.min(v_idx, #visual_lines))
            local v_line = visual_lines[v_idx]
            local rel_x = mx - (x + padding)
            local char_idx = get_char_index_at_x(v_line.text, rel_x)
            return v_line.start_idx + char_idx
        end
    end

    if (gfx.mouse_cap & 1 == 1) and (UI_STATE.last_mouse_cap & 1 == 0) and hover and not UI_STATE.mouse_handled then
        -- Check for interaction suppression (e.g., preventing bleed-through from opening click)
        if state.interaction_start_time and reaper.time_precise() < state.interaction_start_time then
            -- Ignore this click
        else
            state.focus = true
            state.is_dragging = true
            local idx = get_cursor_from_xy(gfx.mouse_x, gfx.mouse_y)
            local now = reaper.time_precise()
        if (now - (state.last_click_time or 0)) < 0.3 then
            state.last_click_state = (state.last_click_state or 0) + 1
        else
            state.last_click_state = 1
        end
        state.last_click_time = now
        
        if state.last_click_state == 1 then
            if (gfx.mouse_cap & 8 == 8) then
                state.cursor = idx
            else
                state.cursor, state.anchor = idx, idx
            end
        elseif state.last_click_state == 2 then
            local s, e = idx, idx
            while s > 0 do
                local c = state.text:sub(s, s)
                if c:match("[%s%p]") then break end
                s = s - 1
            end
            while e < #state.text do
                local c = state.text:sub(e+1, e+1)
                if c:match("[%s%p]") then break end
                e = e + 1

                end
                state.cursor, state.anchor = e, s
            elseif state.last_click_state >= 3 then
                state.cursor, state.anchor = #state.text, 0
            end
        end
    elseif (gfx.mouse_cap & 1 == 1) and state.focus and state.is_dragging then
        -- Check for interaction suppression
        if state.interaction_start_time and reaper.time_precise() < state.interaction_start_time then
            -- Ignore drag during suppression period
        else
            -- Dragging
            if (state.last_click_state or 0) >= 3 then
                -- Triple click (Select All) should adhere to full selection even if mouse jitters
                state.cursor, state.anchor = #state.text, 0
            elseif (state.last_click_state or 0) == 2 then
                -- Double click (Word Select) - Snap to word boundaries
                local raw = get_cursor_from_xy(gfx.mouse_x, gfx.mouse_y)
                if raw >= state.anchor then
                    -- Dragging Right: Snap to End of Word
                    local e = raw
                    while e < #state.text do
                        local c = state.text:sub(e+1, e+1)
                        if c:match("[%s%p]") then break end
                        e = e + 1
                    end
                    state.cursor = e
                else
                    -- Dragging Left: Snap to Start of Word
                    local s = raw
                    while s > 0 do
                        local c = state.text:sub(s, s)
                        if c:match("[%s%p]") then break end
                        s = s - 1
                    end
                    state.cursor = s
                end
            else
                state.cursor = get_cursor_from_xy(gfx.mouse_x, gfx.mouse_y)
            end
        end
    elseif (gfx.mouse_cap & 1 == 1) and (UI_STATE.last_mouse_cap & 1 == 0) and not hover and not UI_STATE.mouse_handled then
        -- Guard: Don't lose focus if clicking inside the AI modal OR if ai_modal was JUST shown (prevents closing focus on suggestion selection)
        local in_ai = false
        if ai_modal and ai_modal.show and ai_modal.x then
            if gfx.mouse_x >= ai_modal.x and gfx.mouse_x <= ai_modal.x + ai_modal.w and
               gfx.mouse_y >= ai_modal.y and gfx.mouse_y <= ai_modal.y + ai_modal.h then
                in_ai = true
            end
        end

        -- Also check if we just clicked the AI button itself to prevent focus flickers
        local ai_btn_hover = UI_STATE.window_focused and (gfx.mouse_x >= ai_modal.anchor_x - 40 and gfx.mouse_x <= ai_modal.anchor_x and 
                              gfx.mouse_y >= ai_modal.anchor_y - 24 and gfx.mouse_y <= ai_modal.anchor_y)

        if not in_ai and not ai_btn_hover then
            state.focus = false
        end
    elseif (gfx.mouse_cap & 2 == 2) and (UI_STATE.last_mouse_cap & 2 == 0) and hover and not UI_STATE.mouse_handled then
        -- Context Menu (Right Click) - Rising Edge Detection
        UI_STATE.mouse_handled = true -- Prevent global context menu from opening
        state.focus = true
        gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
        local sel_min, sel_max = math.min(state.cursor, state.anchor), math.max(state.cursor, state.anchor)
        local has_sel = sel_min ~= sel_max
        
        -- Build Dynamic Menu
        local dict_label = has_sel and T("SEARCH_IN_GOROH") or T("FIND_NEW_G_PCX")
        local menu_items = { T("CUT"), T("COPY"), T("PASTE"), T("SELECT_ALL"), "", dict_label, "", T("VOICE_OVER_M"), T("VOICE_OVER_SAVE_M"), "", T("CHANGE_VOICE_M") }
        for _, v_name in ipairs(cfg.tts_voices_order) do
            local check = (v_name == cfg.tts_voice) and "• " or ""
            table.insert(menu_items, check .. (v_name:gsub("|", "||")))
        end
        table.insert(menu_items, "<")
        
        local split_ret_idx = nil
        if id == "editor_panel" and editor_state.last_line_data then
            table.insert(menu_items, "")
            table.insert(menu_items, T("SPLIT_REPLICA_BY_CURSOR"))
            split_ret_idx = 8 + #cfg.tts_voices_order
        end
        
        local menu_str = table.concat(menu_items, "|")
        local ret = gfx.showmenu(menu_str)
        
        -- Force update UI_STATE.last_mouse_cap to current state to prevent immediate re-trigger loop 
        -- if the user is somehow still holding the button (though showmenu blocks).
        UI_STATE.last_mouse_cap = gfx.mouse_cap 
        
        if ret == 1 and has_sel then
            -- Cut
            set_clipboard(state.text:sub(sel_min + 1, sel_max))
            state.text = state.text:sub(1, sel_min) .. state.text:sub(sel_max + 1)
            state.cursor, state.anchor = sel_min, sel_min
            record_field_history(state)
        elseif ret == 2 and has_sel then
            -- Copy
            set_clipboard(state.text:sub(sel_min + 1, sel_max))
        elseif ret == 3 then
            -- Paste
            local clip = get_clipboard()
            if clip and clip ~= "" then
                if not is_multiline then clip = clip:gsub("\n", " "):gsub("\r", "") end
                if has_sel then
                    state.text = state.text:sub(1, sel_min) .. clip .. state.text:sub(sel_max + 1)
                    state.cursor = sel_min + #clip
                else
                    state.text = state.text:sub(1, state.cursor) .. clip .. state.text:sub(state.cursor + 1)
                    state.cursor = state.cursor + #clip
                end
                state.anchor = state.cursor
                record_field_history(state)
            end
        elseif ret == 4 then
            -- Select All
            state.anchor = 0
            state.cursor = #state.text
        elseif ret == 5 then
            -- Search in GOROH
            if has_sel then
                local target = state.text:sub(sel_min + 1, sel_max)
                if target and target ~= "" then
                    trigger_dictionary_lookup(target)
                end
            else
                local ok, input = reaper.GetUserInputs(T("GOROH"), 1, T("SEARCH_TERM_200"), "")
                if ok and input ~= "" then
                    trigger_dictionary_lookup(input)
                end
            end
        elseif ret == 6 or ret == 7 then
            -- Speak (Озвучити) / Speak & Save
            local text_to_speak = ""
            if not has_sel then
                -- Select All first
                state.anchor = 0
                state.cursor = #state.text
                text_to_speak = state.text
            else
                text_to_speak = state.text:sub(sel_min + 1, sel_max)
            end

            if text_to_speak ~= "" then
                play_tts_audio(text_to_speak, ret == 7)
            end
        elseif ret >= 8 and ret < 8 + #cfg.tts_voices_order then
            -- Change TTS Voice
            cfg.tts_voice = cfg.tts_voices_order[ret - 7]
            save_settings()
            show_snackbar(T("VOICE_HB_CHANGED_TO") .. cfg.tts_voice)
        elseif split_ret_idx and ret == split_ret_idx then
            local line_ref = editor_state.last_line_data
            if line_ref then
                local original_pos = line_ref._i
                local line = ass_lines[original_pos]
                if line then
                    local cursor_pos = state.cursor
                    local txt = state.text
                    local part1 = txt:sub(1, cursor_pos):match("^%s*(.-)%s*$")
                    local part2 = txt:sub(cursor_pos + 1):match("^%s*(.-)%s*$")
                    
                    if part1 == "" or part2 == "" then
                        show_snackbar(T("SPLIT_CURSOR_EDGE_ERR"), "warning")
                    else
                        local t1 = line.t1
                        local t2 = line.t2
                        local len1 = utf8.len(part1) or #part1
                        local len2 = utf8.len(part2) or #part2
                        local total_len = len1 + len2
                        local ratio = len1 / total_len
                        local split_time = t1 + (t2 - t1) * ratio
                        if split_time - t1 < 0.1 then split_time = t1 + 0.1 end
                        if t2 - split_time < 0.1 then split_time = t2 - 0.1 end
                        
                        push_undo(T("SPLIT_REPLICA_BY_CURSOR"))
                        
                        -- Update first part
                        line.text = part1
                        line.t2 = split_time
                        
                        local col = get_actor_color(line.actor)
                        if not col or col == 0 then col = -1 end
                        reaper.SetProjectMarker3(0, line.rgn_idx, true, t1, split_time, part1, col)
                        
                        -- Create and insert second part
                        local new_replica = {}
                        for k, v in pairs(line) do new_replica[k] = v end
                        new_replica.text = part2
                        new_replica.t1 = split_time
                        new_replica.t2 = t2
                        
                        local r_idx = reaper.AddProjectMarker2(0, true, split_time, t2, part2, -1, col)
                        local _, _, _, _, _, r_id = reaper.EnumProjectMarkers3(0, r_idx)
                        new_replica.rgn_idx = r_id
                        
                        -- Generate new unique index
                        local max_idx = 0
                        for _, l in ipairs(ass_lines) do
                            if type(l.index) == "number" and l.index > max_idx then
                                max_idx = l.index
                            end
                        end
                        new_replica.index = max_idx + 1
                        
                        table.insert(ass_lines, original_pos + 1, new_replica)
                        UI_STATE._markers_is_dirty = true
                        
                        cleanup_actors()
                        rebuild_regions()
                        save_project_data(UI_STATE.last_project_id)
                        reaper.MarkProjectDirty(0)
                        
                        table_selection = {}
                        table_selection[line.index or original_pos] = true
                        
                        table_data_cache.state_count = -1
                        last_layout_state.state_count = -1
                        editor_state.needs_sync = true
                        editor_state.last_region_id = -1
                        editor_state.last_state_count = -1
                        
                        -- Update text input immediately for fluid UX
                        state.text = part1
                        state.cursor = #part1
                        state.anchor = #part1
                        
                        show_snackbar(T("REPLICA_SPLIT_SUCCESS"), "success")
                    end
                end
            end
        end
    end
    
    if state.focus then process_input_events(input_queue, state, is_multiline, visual_lines) end
    
    if max_len and utf8.len(state.text or "") > max_len then
        local offset = utf8.offset(state.text, max_len + 1)
        if offset then
            state.text = state.text:sub(1, offset - 1)
            state.cursor = math.min(state.cursor, #state.text)
            state.anchor = math.min(state.anchor, #state.text)
        end
    end

    -- Scroll Handling
    if hover and gfx.mouse_wheel ~= 0 then
        local scroll_step = (gfx.mouse_wheel / 120) * line_h * 3
        if is_multiline then
            state.target_scroll = state.target_scroll - scroll_step
            local max_s = math.max(0, (#visual_lines * line_h) - (h - padding*2))
            state.target_scroll = math.max(0, math.min(state.target_scroll, max_s))
        else
            state.target_scroll = state.target_scroll - (gfx.mouse_wheel * 0.5)
            local txt_w = gfx.measurestr(state.text)
            local max_s = math.max(0, txt_w - text_w)
            state.target_scroll = math.max(0, math.min(state.target_scroll, max_s))
        end
        state.suppress_auto_scroll_until = reaper.time_precise() + 1.0
        gfx.mouse_wheel = 0 -- Consume
    end

    -- Smooth Interpolation
    local s_diff = state.target_scroll - state.scroll
    if math.abs(s_diff) > 0.1 then
        state.scroll = state.scroll + s_diff * 0.4
    else
        state.scroll = state.target_scroll
    end

    -- --- RENDERING ---
    local prev_dest = gfx.dest
    gfx.setimgdim(OTHER.BUF.TABLE, w, h)
    gfx.dest = OTHER.BUF.TABLE
    set_color(state.focus and UI.C_BG or UI.C_TAB_INA)
    gfx.rect(0, 0, w, h, 1)

    -- Render UA Toggle (Internal coords)
    local ua_btn_w, ua_btn_h = S(16), S(16)
    local ua_btn_x, ua_btn_y = w - ua_btn_w, 0
    if state.ua_mode then
        -- UA Flag themed indicator (Two triangles forming ONE large corner triangle)
        local mh = ua_btn_h / 2
        -- Top Triangle (Blue)
        set_color({0.0, 0.45, 0.85, 0.9}) -- Blue
        gfx.triangle(ua_btn_x, ua_btn_y, ua_btn_x + ua_btn_w, ua_btn_y, ua_btn_x + ua_btn_w, ua_btn_y + mh)
        -- Bottom Triangle (Yellow)
        set_color({1.0, 0.85, 0.0, 0.9}) -- Yellow
        gfx.triangle(ua_btn_x, ua_btn_y, ua_btn_x + ua_btn_w, ua_btn_y + mh, ua_btn_x + ua_btn_w, ua_btn_y + ua_btn_h)
    else
        set_color(UI.C_TXT, 0.2)
        -- Draw outline triangle
        gfx.line(ua_btn_x + ua_btn_w, ua_btn_y, ua_btn_x + ua_btn_w, ua_btn_y + ua_btn_h)
        gfx.line(ua_btn_x + ua_btn_w, ua_btn_y + ua_btn_h, ua_btn_x + S(2), ua_btn_y)
        gfx.line(ua_btn_x + S(2), ua_btn_y, ua_btn_x + ua_btn_w, ua_btn_y)
    end

    if #state.text == 0 and not state.focus then
        set_color(UI.C_ED_GUTTER)
        gfx.x, gfx.y = padding, is_multiline and padding or (h - line_h) / 2
        gfx.drawstr(placeholder or "")
    else
        local sel_min, sel_max = math.min(state.cursor, state.anchor), math.max(state.cursor, state.anchor)
        local has_sel = (sel_min ~= sel_max)
        
        -- Director mode highlight detection ([Actor])
        local bracket_end = -1
        if is_director_mode and state.text and state.text:sub(1,1) == "[" then
            bracket_end = state.text:find("]") or -1
        end

        -- Highlight detection ({...} yellow, {{...}} pink)
        local highlight_ranges = {}
        if state.text then
            local s_idx = 1
            while true do
                local s, e = state.text:find("%b{}", s_idx)
                if not s then break end
                local color = UI.C_HILI_YELLOW
                if state.text:sub(s, s+1) == "{{" and state.text:sub(e-1, e) == "}}" then
                    color = UI.C_HILI_PINK
                end
                table.insert(highlight_ranges, {s = s - 1, e = e, color = color})
                s_idx = e + 1
            end
        end

        if not is_multiline then
            -- Single line logic
            local cx = gfx.measurestr(state.text:sub(1, state.cursor))
            if state.focus and reaper.time_precise() > state.suppress_auto_scroll_until then
                if cx < state.target_scroll then state.target_scroll = cx
                elseif cx > state.target_scroll + text_w then state.target_scroll = cx - text_w end
            end
            if not state.focus then state.target_scroll = 0 end

            local ty = (h - line_h) / 2
            
            -- Director mode highlight for single line
            if is_director_mode and bracket_end > 0 then
                local b_end = math.min(#state.text, bracket_end)
                local bw = gfx.measurestr(state.text:sub(1, b_end))
                set_color(UI.C_ED_HILI_G) -- Subtle green highlight
                gfx.rect(padding - state.scroll - S(2), ty - S(1), bw + S(4), line_h + S(2), 1)
            end

            -- Highlight for single line
            for _, range in ipairs(highlight_ranges) do
                local x1 = padding + gfx.measurestr(state.text:sub(1, range.s)) - state.scroll
                local x2 = padding + gfx.measurestr(state.text:sub(1, range.e)) - state.scroll
                set_color(range.color)
                gfx.rect(x1 - S(1), ty - S(1), (x2 - x1) + S(2), line_h + S(2), 1)
            end

            if has_sel then
                local w_before = gfx.measurestr(state.text:sub(1, sel_min))
                local w_sel = gfx.measurestr(state.text:sub(sel_min + 1, sel_max))
                set_color(UI.C_ED_HILI_B)
                gfx.rect(padding + w_before - state.scroll, S(3), w_sel, h - S(6), 1)
            end
            set_color(UI.C_TXT)
            gfx.x, gfx.y = padding - state.scroll, ty
            gfx.drawstr(state.focus and state.text or fit_text_width(state.text, text_w))
            
            if state.focus and (math.floor(reaper.time_precise() * 2) % 2 == 0) then
                local cur_x = padding + cx - state.scroll
                set_color(UI.C_TXT)
                gfx.line(cur_x, S(3), cur_x, h - S(3))
            end
        else
            -- Multiline logic
            local total_h = #visual_lines * line_h
            if state.focus and reaper.time_precise() > state.suppress_auto_scroll_until then
                local cur_vi = 1
                for i, v in ipairs(visual_lines) do if state.cursor >= v.start_idx then cur_vi = i end end
                local cur_y = (cur_vi - 1) * line_h
                if cur_y < state.target_scroll then state.target_scroll = cur_y
                elseif cur_y + line_h > state.target_scroll + h - padding*2 then state.target_scroll = cur_y + line_h - (h - padding*2) end
            end

            for i, v_line in ipairs(visual_lines) do
                local ly = padding + (i-1) * line_h - state.scroll
                if ly + line_h > 0 and ly < h then
                    local l_start, l_end = v_line.start_idx, v_line.start_idx + #v_line.text
                    if has_sel then
                        local s_start, s_end = math.max(l_start, sel_min), math.min(l_end, sel_max)
                        if s_start < s_end then
                            local x1 = padding + gfx.measurestr(v_line.text:sub(1, s_start - l_start))
                            local sw = gfx.measurestr(v_line.text:sub(s_start - l_start + 1, s_end - l_start))
                            set_color(UI.C_ED_HILI_B)
                            gfx.rect(x1, ly, sw, line_h, 1)
                        end
                        if not v_line.is_wrapped and sel_max > l_end and sel_min <= l_end then
                            set_color(UI.C_ED_HILI_B)
                            gfx.rect(padding + gfx.measurestr(v_line.text), ly, S(5), line_h, 1)
                        end
                    end
                    -- Director mode syntax highlighting ([Actor])
                    if is_director_mode and bracket_end > 0 then
                        local l_start, l_end = v_line.start_idx, v_line.start_idx + #v_line.text
                        local b_start, b_end = math.max(l_start, 0), math.min(l_end, bracket_end)
                        if b_start < b_end then
                            local x1 = padding + gfx.measurestr(v_line.text:sub(1, b_start - l_start))
                            local x2 = padding + gfx.measurestr(v_line.text:sub(1, b_end - l_start))
                            set_color(UI.C_ED_HILI_G) -- Subtle green highlight
                            gfx.rect(x1 - S(2), ly - S(1), (x2 - x1) + S(4), line_h + S(2), 1)
                        end
                    end

                    -- Highlight for multi-line
                    for _, range in ipairs(highlight_ranges) do
                        local b_start, b_end = math.max(l_start, range.s), math.min(l_end, range.e)
                        if b_start < b_end then
                            local x1 = padding + gfx.measurestr(v_line.text:sub(1, b_start - l_start))
                            local x2 = padding + gfx.measurestr(v_line.text:sub(1, b_end - l_start))
                            set_color(range.color)
                            gfx.rect(x1 - S(1), ly - S(1), (x2 - x1) + S(2), line_h + S(2), 1)
                        end
                    end

                    set_color(UI.C_TXT)
                    gfx.x, gfx.y = padding, ly
                    gfx.drawstr(v_line.text)
                    
                    if state.focus and (math.floor(reaper.time_precise() * 2) % 2 == 0) then
                        if state.cursor >= l_start and state.cursor <= l_end then
                            -- Check if cursor is at the very end of a wrapped line (should stay on this line, but if empty, it's ambiguous)
                            local show_here = true
                            if state.cursor == l_end and v_line.is_wrapped then show_here = false end
                            if show_here then
                                local cx = padding + gfx.measurestr(v_line.text:sub(1, state.cursor - l_start))
                                set_color(UI.C_TXT)
                                gfx.line(cx, ly, cx, ly + line_h)
                            end
                        elseif state.cursor == l_start and i == #visual_lines and #v_line.text == 0 then
                            -- Empty last line
                            set_color(UI.C_TXT)
                            gfx.line(padding, ly, padding, ly + line_h)
                        end
                    end
                end
            end
        end
    end
    if state.text ~= before_text then
        record_field_history(state)
    end

    gfx.dest = prev_dest
    gfx.blit(OTHER.BUF.TABLE, 1, 0, 0, 0, w, h, x, y, w, h)
    set_color(state.focus and {0.7, 0.7, 1.0} or UI.C_BTN_H)
    gfx.rect(x, y, w, h, 0)
    gfx.setfont(F.std)
end

local function trigger_ai_modal(target_state, anchor_x, anchor_y, provider_name)
    local prov = cfg.ai_provider or "gemini"
    local key, status
    if prov == "mistral" then
        key, status = cfg.mistral_api_key, cfg.mistral_key_status
    elseif prov == "groq" then
        key, status = cfg.groq_api_key, cfg.groq_key_status
    else
        key, status = cfg.gemini_api_key, cfg.gemini_key_status
    end
    
    if not key or key == "" or (status ~= 200 and status ~= 429) then
        show_snackbar(T("TE_AI_KEY_E_1") .. provider_name .. T("TE_AI_KEY_E_2"), "error")
        return
    end

    local sel_min = math.min(target_state.cursor, target_state.anchor)
    local sel_max = math.max(target_state.cursor, target_state.anchor)
    local has_sel = (sel_min ~= sel_max)

    if has_sel then
        -- Word wrap selection logic
        local word_pattern = "[%a\128-\255\'%-]+[\128-\255]*"
        local new_min, new_max = sel_min, sel_max
        local pos = 1
        while pos <= #target_state.text do
            local s, e = target_state.text:find(word_pattern, pos)
            if not s then break end
            local w_min, w_max = s - 1, e
            if w_max > sel_min and w_min < sel_max then
                if w_min < new_min then new_min = w_min end
                if w_max > new_max then new_max = w_max end
            end
            pos = e + 1
        end
        if target_state.cursor > target_state.anchor then
            target_state.cursor, target_state.anchor = new_max, new_min
        else
            target_state.cursor, target_state.anchor = new_min, new_max
        end
        sel_min, sel_max = new_min, new_max
    end

    local function init_selection(s_min, s_max)
        ai_modal.text = target_state.text:sub(s_min + 1, s_max)
        ai_modal.sel_min, ai_modal.sel_max = s_min, s_max
        ai_modal.current_step = "SELECT_TASK"
        ai_modal.suggestions = {}
        ai_modal.scroll = 0
        ai_modal.anchor_x, ai_modal.anchor_y = anchor_x, anchor_y
        ai_modal.target_state = target_state
        ai_modal.show = true
        ai_modal.last_click_time = os.clock()
        ai_modal.last_step_change_time = os.clock()
    end
    
    if has_sel and sel_max - sel_min < 8 then
        show_snackbar(T("TE_AI_S_MORE"), "error")
    elseif has_sel then
        if (ai_modal.text ~= "") and sel_min == ai_modal.sel_min and sel_max == ai_modal.sel_max and ai_modal.target_state == target_state then
            ai_modal.show = true
            ai_modal.last_click_time = os.clock()
        else
            init_selection(sel_min, sel_max)
        end
    elseif (ai_modal.text ~= "") and ai_modal.target_state == target_state then
        target_state.cursor, target_state.anchor = ai_modal.sel_max, ai_modal.sel_min
        ai_modal.anchor_x, ai_modal.anchor_y = anchor_x, anchor_y
        ai_modal.show = true
        ai_modal.last_click_time = os.clock()
    elseif #target_state.text > 0 then
        target_state.anchor, target_state.cursor = 0, #target_state.text
        init_selection(0, #target_state.text)
    else
        show_snackbar(T("TE_AI_S_T_TEXT"), "error")
    end
end

--- Draw and handle text editor modal dialog
--- @param input_queue table Input events queue
--- @return boolean True if editor consumed the input
function DRAW_WINDOW.draw_text_editor(input_queue)
    if not text_editor_state.active then return false end
    
    local content_changed = false
    
    -- AI Modal Input Pass
    if DRAW_WINDOW.draw_ai_modal(true) then 
        content_changed = true 
        -- Update history via the new unified helper for AI changes
        record_field_history(text_editor_state)
        -- Reset auto-scroll suppression for immediate feedback
        text_editor_state.suppress_auto_scroll_until = 0
    end
    
    -- Darken background
    gfx.set(0, 0, 0, 0.7)
    gfx.rect(0, 0, gfx.w, gfx.h, 1)
    
    -- Editor box
    local pad = 25
    local box_x, box_y = pad, pad
    local box_w, box_h = gfx.w - pad * 2, gfx.h - pad * 2
    
    set_color(UI.C_TAB_INA)
    gfx.rect(box_x, box_y, box_w, box_h, 1)
    
    -- AI Button dimensions
    local provider_name = (cfg.ai_provider == "mistral") and "Mistral" or (cfg.ai_provider == "groq" and "Groq" or "Gemini")
    local ai_btn_text = T("ASK_NAME") .. provider_name
    local ai_btn_w, ai_btn_h = cfg.lng == "ua" and S(130) or S(90), S(24)
    local ai_btn_x, ai_btn_y = box_x + box_w - ai_btn_w - S(10), box_y + S(8)
    local ai_box_x = box_w - S(24)

    -- AI History Button
    local hist_btn_w, hist_btn_h = S(30), S(24)
    local hist_btn_x, hist_btn_y = box_x + box_w - ai_btn_w - hist_btn_w - S(15), box_y + S(8)

    -- Title with Truncation
    set_color(UI.C_TXT)
    gfx.setfont(F.std)
    gfx.x, gfx.y = box_x + S(10), box_y + S(10)
    
    local title_txt = T("TE_TITLE")
    local limit_x = hist_btn_x - S(10)
    local max_title_w = limit_x - gfx.x
    
    local tw, th = gfx.measurestr(title_txt)
    if tw > max_title_w then
        while tw > max_title_w and #title_txt > 0 do
            title_txt = title_txt:sub(1, -2)
            tw = gfx.measurestr(title_txt .. "...")
        end
        title_txt = title_txt .. "..."
    end
    gfx.drawstr(title_txt)
    
    if #ai_modal.history > 0 then
        if btn(hist_btn_x, hist_btn_y, hist_btn_w, hist_btn_h, "#") then
            -- Build history text for display
            reaper.ShowConsoleMsg("")
            local history_text = "=== THE HISTORY OF AI OPERATIONS ===\n\n"
            for i = #ai_modal.history, 1, -1 do
                local entry = ai_modal.history[i]
                history_text = history_text .. string.format("[%s] %s\n\n", entry.timestamp, entry.task)
                history_text = history_text .. "ORIGINAL TEXT:\n" .. entry.original .. "\n\n"
                history_text = history_text .. "OPTIONS FROM AI:\n"
                for j, variant in ipairs(entry.variants) do
                    history_text = history_text .. string.format("%d. %s\n", j, variant)
                end
                history_text = history_text .. "\n" .. string.rep("=", 80) .. "\n\n"
            end
            reaper.ShowConsoleMsg(history_text)
            if reaper.GetToggleCommandState(40004) == 0 then reaper.Main_OnCommand(40004, 0) end
        end
    end

    -- AI Button interaction
    local sel_min = math.min(text_editor_state.cursor, text_editor_state.anchor)
    local sel_max = math.max(text_editor_state.cursor, text_editor_state.anchor)
    local has_sel = (sel_min ~= sel_max)

    local ai_hover = (gfx.mouse_x >= ai_btn_x and gfx.mouse_x <= ai_btn_x + ai_btn_w and gfx.mouse_y >= ai_btn_y and gfx.mouse_y <= ai_btn_y + ai_btn_h)

    if ai_hover and is_right_mouse_clicked() then
        local menu_str = (cfg.ai_provider == "gemini" and "!" or "") .. "Gemini AI|" .. 
                         (cfg.ai_provider == "mistral" and "!" or "") .. "Mistral AI|" ..
                         (cfg.ai_provider == "groq" and "!" or "") .. "Groq AI"
        gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
        local ret = gfx.showmenu(menu_str)
        if ret == 1 then
            cfg.ai_provider = "gemini"
            save_settings()
        elseif ret == 2 then
            cfg.ai_provider = "mistral"
            save_settings()
        elseif ret == 3 then
            cfg.ai_provider = "groq"
            save_settings()
        end
        UI_STATE.mouse_handled = true
    end

    if btn(ai_btn_x, ai_btn_y, ai_btn_w, ai_btn_h, ai_btn_text) then
        trigger_ai_modal(text_editor_state, ai_box_x, ai_btn_y + ai_btn_h, provider_name)
    end
    
    local text_x, text_y = box_x + S(10), box_y + S(35)
    local text_w, text_h = box_w - S(20), box_h - S(80)

    -- Main editor interaction
    ui_text_input("text_editor", text_x, text_y, text_w, text_h, text_editor_state, T("ENTER_TEXT_DOTS"), input_queue, true, text_editor_state.is_director_mode, F[cfg.t_editor_size])

    local btn_y = box_y + box_h - S(40)
    if btn(box_x + S(10), btn_y, S(90), S(30), T("CANCEL")) then 
        text_editor_state.active = false
        ai_modal.text = ""
        ai_modal.suggestions = {}
        ai_modal.history = {}
    end
    if btn(box_x + box_w - S(90), btn_y, S(80), S(30), T("SAVE")) then
        if text_editor_state.callback then text_editor_state.callback(text_editor_state.text) end
        if text_editor_state.context_line_idx == editor_state.last_region_id then 
            editor_state.last_region_id = -1
        end
        text_editor_state.active = false
        ai_modal.text = ""
        ai_modal.suggestions = {}
        ai_modal.history = {}
    end

    -- Global Shortcuts Pass (Fallback for when input focus is lost)
    if input_queue then
        local cap = gfx.mouse_cap
        local is_ctrl = (cap & 4 == 4)
        local is_cmd = (cap & 32 == 32)
        local is_shift = (cap & 8 == 8)
        local is_mod = (is_ctrl or is_cmd)
        
        for _, char in ipairs(input_queue) do
            -- Undo / Redo (Fallback for focus loss)
            if not text_editor_state.focus then -- Only run here if ui_text_input didn't already process it
                if (char == 26) or (is_mod and (char == 122 or char == 90)) then
                    if text_editor_state.history and text_editor_state.history_pos then
                        if is_shift then
                            if text_editor_state.history_pos < #text_editor_state.history then
                                text_editor_state.history_pos = text_editor_state.history_pos + 1
                                local snap = text_editor_state.history[text_editor_state.history_pos]
                                text_editor_state.text, text_editor_state.cursor, text_editor_state.anchor = snap.text, snap.cursor, snap.anchor
                                content_changed = true
                            end
                        else
                            if text_editor_state.history_pos > 1 then
                                text_editor_state.history_pos = text_editor_state.history_pos - 1
                                local snap = text_editor_state.history[text_editor_state.history_pos]
                                text_editor_state.text, text_editor_state.cursor, text_editor_state.anchor = snap.text, snap.cursor, snap.anchor
                                content_changed = true
                            end
                        end
                    end
                elseif is_mod and (char == 121 or char == 89) then -- Redo (Ctrl+Y)
                    if text_editor_state.history and text_editor_state.history_pos and text_editor_state.history_pos < #text_editor_state.history then
                        text_editor_state.history_pos = text_editor_state.history_pos + 1
                        local snap = text_editor_state.history[text_editor_state.history_pos]
                        text_editor_state.text, text_editor_state.cursor, text_editor_state.anchor = snap.text, snap.cursor, snap.anchor
                        content_changed = true
                    end
                end
            end

            -- Main shortcuts (Enter to Save, Esc to Cancel)
            if char == 13 and not is_shift then
                if text_editor_state.callback then text_editor_state.callback(text_editor_state.text) end
                if text_editor_state.context_line_idx == editor_state.last_region_id then 
                    editor_state.last_region_id = -1
                end
                text_editor_state.active = false
                ai_modal.text = ""
                ai_modal.suggestions = {}
                ai_modal.history = {}
            elseif char == 27 then
                text_editor_state.active = false
                ai_modal.text = ""
                ai_modal.suggestions = {}
                ai_modal.history = {}
            end
        end
    end

    -- Draw pass for AI modal
    DRAW_WINDOW.draw_ai_modal(false)
    
    return true
end

--- Draw Text Items Style Editor Modal
function DRAW_WINDOW.draw_text_items_style_editor(input_queue)
    if not UI_STATE.text_items_style or not UI_STATE.text_items_style.show then
        return false
    end

    local state = UI_STATE.text_items_style
    local pad = S(20)
    local header_h = S(65)
    local footer_editor_h = UI_STATE.subass_items_editor_mode and S(140) or 0
    local content_h = gfx.h - header_h - footer_editor_h

    -- Перевірка чи трек ще існує
    local track_exists = false
    local tc = reaper.CountTracks(0)
    for t = 0, tc - 1 do
        local tr = reaper.GetTrack(0, t)
        if tr == state.track then
            track_exists = true
            break
        end
    end

    -- Якщо трек видалено
    if not track_exists then
        set_color(UI.C_BG, 1.0)
        gfx.rect(0, 0, gfx.w, gfx.h, 1)

        local title = T("TEXT_ITEMS_STYLE_TITLE")
        local desc = ""
        local btn_msg = T("CREATE_TEXT_ITEMS_FROM_REGIONS")

        gfx.setfont(F.title)
        local title_w, title_h = gfx.measurestr(title)

        gfx.setfont(F.std)
        local desc_w, desc_h = gfx.measurestr(desc)

        local bw = S(220)
        local bh = S(42)

        local total_h = title_h + desc_h + S(26) + bh
        local start_y = (gfx.h - total_h) / 2

        gfx.setfont(F.title)
        set_color(UI.C_TXT, 1)
        gfx.x = (gfx.w - title_w) / 2
        gfx.y = start_y
        gfx.drawstr(title)

        gfx.setfont(F.std)
        set_color(UI.C_TXT_DIM or UI.C_TXT, 1)
        gfx.x = (gfx.w - desc_w) / 2
        gfx.y = start_y + title_h + S(8)
        gfx.drawstr(desc)

        local btn_y = start_y + title_h + desc_h + S(26)

        if btn((gfx.w - bw) / 2, btn_y, bw, bh, btn_msg, UI.C_BTN_MEDIUM, UI.C_TXT, true) then
            UTILS.create_text_items_from_regions()

            local new_track = nil
            local tc = reaper.CountTracks(0)
            for t = 0, tc - 1 do
                local tr = reaper.GetTrack(0, t)
                local _, tn = reaper.GetTrackName(tr)
                if tn == "SUBASS_ITEMS" then
                    new_track = tr
                    break
                end
            end

            if new_track then
                local new_fx_idx = -1
                local num_fx = reaper.TrackFX_GetCount(new_track)
                for f = 0, num_fx - 1 do
                    local retval, fx_name = reaper.TrackFX_GetFXName(new_track, f, "")
                    if retval and (fx_name:lower():find("video processor") or fx_name:lower():find("video_processor")) then
                        new_fx_idx = f
                        break
                    end
                end

                if new_fx_idx >= 0 then
                    -- Завантажуємо збережені стилі з ExtState
                    local saved_styles = UTILS.load_text_items_styles()

                    if saved_styles and saved_styles.params then
                        -- Застосовуємо збережені параметри до FX
                        for key, idx in pairs(OTHER.TEXT_ITEMS_PARAM_INDICES) do
                            local val = saved_styles.params[key]
                            if val ~= nil then
                                reaper.TrackFX_SetParam(new_track, new_fx_idx, idx, val)
                                UI_STATE.text_items_style.params[key] = val
                            else
                                -- Якщо в збережених немає - беремо з DEFAULT
                                local default_val = OTHER.TEXT_ITEMS_DEFAULT_PARAMS[key]
                                reaper.TrackFX_SetParam(new_track, new_fx_idx, idx, default_val)
                                UI_STATE.text_items_style.params[key] = default_val
                            end
                        end

                        -- Відновлюємо custom font name
                        if saved_styles.custom_font_name then
                            UI_STATE.text_items_style.custom_font_name = saved_styles.custom_font_name
                            -- Застосовуємо custom font до Video Processor
                            local function set_custom_font_to_track(track, fx_idx, font_name)
                                local ret, chunk = reaper.GetTrackStateChunk(track, "", false)
                                if not ret then return false end

                                local fx_start = nil
                                local fx_end = nil
                                local current_idx = -1
                                local s_idx = 1

                                while true do
                                    local s, e = chunk:find("<VIDEO_EFFECT", s_idx)
                                    if not s then break end
                                    current_idx = current_idx + 1

                                    if current_idx == fx_idx then
                                        fx_start = s
                                        local b_end = chunk:find("\n>", e)
                                        if b_end then
                                            fx_end = b_end
                                        end
                                        break
                                    end
                                    s_idx = e + 1
                                end

                                if not fx_start or not fx_end then return false end

                                local fx_chunk = chunk:sub(fx_start, fx_end)
                                local new_fx_chunk = fx_chunk:gsub('#custom_font = "[^"]*"',
                                    '#custom_font = "' .. font_name .. '"')

                                if new_fx_chunk == fx_chunk then
                                    new_fx_chunk = fx_chunk:gsub('font="Arial";',
                                        'font="Arial";\n#custom_font = "' .. font_name .. '";')
                                end

                                local new_chunk = chunk:sub(1, fx_start - 1) .. new_fx_chunk .. chunk:sub(fx_end + 1)
                                reaper.SetTrackStateChunk(track, new_chunk, false)
                                return true
                            end

                            set_custom_font_to_track(new_track, new_fx_idx, saved_styles.custom_font_name)
                        end
                    else
                        -- Якщо немає збережених стилів, використовуємо DEFAULT
                        for key, default_val in pairs(OTHER.TEXT_ITEMS_DEFAULT_PARAMS) do
                            reaper.TrackFX_SetParam(new_track, new_fx_idx, OTHER.TEXT_ITEMS_PARAM_INDICES[key], default_val)
                            UI_STATE.text_items_style.params[key] = default_val
                        end
                    end

                    UI_STATE.text_items_style.track = new_track
                    UI_STATE.text_items_style.fx_idx = new_fx_idx
                end
            end

            show_snackbar(T("TRACK_CREATED"), "success")
        end

        -- Close button
        local close_sz = S(24)
        local close_x = gfx.w - S(20) - close_sz

        if btn(close_x, S(20), close_sz, close_sz, "X", UI.C_BTN, UI.C_TXT, true) then
            UI_STATE.text_items_style = nil
        end

        -- ESC to close
        if input_queue then
            for _, c in ipairs(input_queue) do
                if c == 27 then
                    UI_STATE.text_items_style = nil
                    break
                end
            end
        end

        UI_STATE.mouse_handled = true
        return true
    end
    -- Background overlay
    set_color(UI.C_BG, 1.0)
    gfx.rect(0, 0, gfx.w, gfx.h, 1)

    -- Content area with scroll
    local content_y = header_h
    local cy = content_y + S(20) - (state.scroll_y or 0)

    -- Local checkbox drawing function
    local function draw_checkbox_local(x, y, checked)
        local chk_sz = S(18)
        set_color(UI.C_ED_GUTTER)
        gfx.rect(x, y, chk_sz, chk_sz, 0)
        if checked then
            set_color(UI.C_TXT)
            gfx.line(x + S(4), y + S(9), x + S(8), y + S(13))
            gfx.line(x + S(5), y + S(9), x + S(9), y + S(13))
            gfx.line(x + S(8), y + S(13), x + S(14), y + S(5))
            gfx.line(x + S(9), y + S(13), x + S(15), y + S(5))
        end
    end

    -- Helper functions
    local function draw_slider(label, param_key, min_val, max_val, decimals, invert)
        local val = state.params[param_key]
        if not val then return end

        local row_h = S(60)
        local label_w = S(140)
        local slider_w = gfx.w - pad * 2 - label_w - S(60)

        if cy + row_h > content_y and cy < content_y + content_h then
            -- Label
            set_color(UI.C_TXT)
            gfx.setfont(F.std)
            gfx.x, gfx.y = pad, cy + S(12)
            gfx.drawstr(label)

             -- Value display
            local fmt = decimals == 0 and "%.0f" or "%.1f"
            local display_val = invert and (max_val + min_val - val) or val
            local percent_val = ((display_val - min_val) / (max_val - min_val)) * 100
            local val_str = string.format(fmt .. "%%", percent_val)
            local val_w = gfx.measurestr(val_str)
            local slider_x = pad + label_w
            local val_x = slider_x + slider_w + S(15)
            
            gfx.x, gfx.y = val_x, cy + S(12)
            gfx.drawstr(val_str)

            -- Slider background (сірий)
            set_color(UI.C_BTN)
            gfx.rect(slider_x, cy + S(15), slider_w, S(10), 1)

            -- ВИЗНАЧАЄМО ТИП ПАРАМЕТРА ДЛЯ РІЗНОГО ЗАПОВНЕННЯ
            local is_center_param = (param_key == "xpos" or param_key == "ypos" or
                param_key == "bgxpos" or param_key == "bgypos" or
                param_key == "sh_x" or param_key == "sh_y")

            local t = (val - min_val) / (max_val - min_val)
            if invert then t = 1 - t end
            local handle_radius = S(10)
            local handle_x = slider_x + t * slider_w
            local handle_y = cy + S(20)

            -- ЗАПОВНЕННЯ СЛАЙДЕРА
            if is_center_param then
                -- Для X, Y, bgxpos, bgypos: заповнення ВІД ЦЕНТРУ
                local center_t = 0.5
                local center_x = slider_x + center_t * slider_w

                if handle_x >= center_x then
                    -- Заповнення від центру вправо
                    local fill_w = handle_x - center_x
                    if fill_w > 0 then
                        set_color(UI.C_GREEN, 0.6)
                        gfx.rect(center_x, cy + S(15), fill_w, S(10), 1)
                    end
                else
                    -- Заповнення від центру вліво
                    local fill_w = center_x - handle_x
                    if fill_w > 0 then
                        set_color(UI.C_BLUE_BRIGHT, 0.6)
                        gfx.rect(handle_x, cy + S(15), fill_w, S(10), 1)
                    end
                end
                -- Малюємо центральну позначку
                set_color(UI.C_WHITE, 0.8)
                gfx.line(center_x, cy + S(12), center_x, cy + S(28))
            else
                -- Для звичайних параметрів: заповнення ЗЛІВА НАПРАВО
                local fill_w = handle_x - slider_x
                if fill_w > 0 then
                    local progress = t
                    local r = math.min(1.0, progress * 2)
                    local g = math.min(1.0, (1 - progress) * 2)
                    set_color({ r, g, 0.2 }, 0.6)
                    gfx.rect(slider_x, cy + S(15), fill_w, S(10), 1)
                end
            end

            -- КРУГЛА РУЧКА
            set_color(UI.C_RED)
            gfx.circle(handle_x, handle_y, handle_radius, 1)

            -- Чорний обідок
            set_color(UI.C_BLACK, 0.8)
            gfx.circle(handle_x, handle_y, handle_radius, 0)

            -- ПОДВІЙНИЙ КЛІК ПО РУЧЦІ - СКИДАННЯ ДО СТАНДАРТНОГО ЗНАЧЕННЯ
            local now = reaper.time_precise()
            local hover_handle = UI_STATE.window_focused and
                math.sqrt((gfx.mouse_x - handle_x) ^ 2 + (gfx.mouse_y - handle_y) ^ 2) <= handle_radius + S(4)

            if hover_handle and (gfx.mouse_cap & 1 == 1) and (UI_STATE.last_mouse_cap & 1 == 0) then
                if UI_STATE.last_click_time and (now - UI_STATE.last_click_time) < 0.3 then
                    -- Подвійний клік
                    local default_val = state.default_params[param_key]
                    if default_val ~= nil then
                        state.params[param_key] = default_val
                        reaper.TrackFX_SetParam(state.track, state.fx_idx, OTHER.TEXT_ITEMS_PARAM_INDICES[param_key],
                            default_val)
                        UTILS.save_text_items_styles()
                    end
                    UI_STATE.last_click_time = nil
                    UI_STATE.mouse_handled = true
                else
                    UI_STATE.last_click_time = now
                end
            end

            -- КЛІК ПО ЛІНІЇ СЛАЙДЕРА
            local hover_line = UI_STATE.window_focused and
                gfx.mouse_x >= slider_x and gfx.mouse_x <= slider_x + slider_w and
                gfx.mouse_y >= cy + S(15) and gfx.mouse_y <= cy + S(25)

            if hover_line and (gfx.mouse_cap & 1 == 1) and (UI_STATE.last_mouse_cap & 1 == 0) and not UI_STATE.mouse_handled then
                local dist_to_handle = math.sqrt((gfx.mouse_x - handle_x) ^ 2 + (gfx.mouse_y - handle_y) ^ 2)
                if dist_to_handle > handle_radius + S(2) then
                    -- Переміщуємо ручку в позицію кліку
                    local mouse_t = (gfx.mouse_x - slider_x) / slider_w
                    mouse_t = math.max(0, math.min(1, mouse_t))
                    if invert then mouse_t = 1 - mouse_t end
                    local new_val = min_val + mouse_t * (max_val - min_val)
                    if decimals == 0 then
                        new_val = math.floor(new_val + 0.5)
                    end
                    state.params[param_key] = new_val
                    reaper.TrackFX_SetParam(state.track, state.fx_idx, OTHER.TEXT_ITEMS_PARAM_INDICES[param_key], new_val)
                    UTILS.save_text_items_styles()
                    UI_STATE.mouse_handled = true
                end
            end

            -- Звичайне перетягування за ручку
            local hover_drag = UI_STATE.window_focused and
                math.sqrt((gfx.mouse_x - handle_x) ^ 2 + (gfx.mouse_y - handle_y) ^ 2) <= handle_radius + S(4)

            if (state.dragging == param_key) or (hover_drag and is_mouse_clicked() and not UI_STATE.mouse_handled) then
                state.dragging = param_key
                UI_STATE.mouse_handled = true
            end

            if state.dragging == param_key and (gfx.mouse_cap & 1 == 1) then
                local mouse_t = (gfx.mouse_x - slider_x) / slider_w
                mouse_t = math.max(0, math.min(1, mouse_t))
                if invert then mouse_t = 1 - mouse_t end
                local new_val = min_val + mouse_t * (max_val - min_val)
                if decimals == 0 then
                    new_val = math.floor(new_val + 0.5)
                end
                state.params[param_key] = new_val
                reaper.TrackFX_SetParam(state.track, state.fx_idx, OTHER.TEXT_ITEMS_PARAM_INDICES[param_key], new_val)
                UTILS.save_text_items_styles()
            elseif state.dragging == param_key then
                state.dragging = nil
            end
        end
        cy = cy + row_h + S(5)
    end

    -- Font list
    local font_options = { "Arial", "Calibri", "Roboto", "Segoe UI", "Trebuchet MS", "Verdana", "Cambria", "Impact",
        "Georgia", "Times New Roman", "Consolas", "Courier New" }

    -- Helper function to set custom font in Video Processor
    local function set_custom_font(font_name)
        -- Get the track chunk to modify the custom_font variable
        local ret, chunk = reaper.GetTrackStateChunk(state.track, "", false)
        if not ret then return false end

        -- Find the Video Processor FX block
        local fx_start = nil
        local fx_end = nil
        local current_idx = -1
        local s_idx = 1

        while true do
            local s, e = chunk:find("<VIDEO_EFFECT", s_idx)
            if not s then break end
            current_idx = current_idx + 1

            if current_idx == state.fx_idx then
                fx_start = s
                local b_end = chunk:find("\n>", e)
                if b_end then
                    fx_end = b_end
                end
                break
            end
            s_idx = e + 1
        end

        if not fx_start or not fx_end then return false end

        -- Find and replace #custom_font value
        local fx_chunk = chunk:sub(fx_start, fx_end)
        local new_fx_chunk = fx_chunk:gsub('#custom_font = "[^"]*"', '#custom_font = "' .. font_name .. '"')

        if new_fx_chunk == fx_chunk then
            -- If not found, insert the variable
            new_fx_chunk = fx_chunk:gsub('font="Arial";', 'font="Arial";\n#custom_font = "' .. font_name .. '";')
        end

        -- Replace in main chunk
        local new_chunk = chunk:sub(1, fx_start - 1) .. new_fx_chunk .. chunk:sub(fx_end + 1)
        reaper.SetTrackStateChunk(state.track, new_chunk, false)

        return true
    end

    -- Font list with custom font option (index 12, after separator at 13)
    local custom_font_label = state.custom_font_name and (T("CUSTOM_FONT_PREFIX") .. state.custom_font_name) or
    T("ADD_CUSTOM_FONT")
    local font_options_with_custom = { "Arial", "Calibri", "Roboto", "Segoe UI", "Trebuchet MS", "Verdana", "Cambria",
        "Impact", "Georgia", "Times New Roman", "Consolas", "Courier New", custom_font_label }    

    local function draw_color_picker(label, r_key, g_key, b_key)
        local row_h = S(45)

        if cy + row_h > content_y and cy < content_y + content_h then
            set_color(UI.C_TXT)
            gfx.setfont(F.std)
            gfx.x, gfx.y = pad, cy + S(10)
            gfx.drawstr(label)

            local box_sz = S(24)
            local bx = pad + S(140)
            local r = state.params[r_key] or 0
            local g = state.params[g_key] or 0
            local b = state.params[b_key] or 0

            set_color({ r, g, b })
            gfx.rect(bx, cy + S(8), box_sz, box_sz, 1)
            set_color(UI.C_TXT)
            gfx.rect(bx, cy + S(8), box_sz, box_sz, 0)

            if is_mouse_clicked() and gfx.mouse_x >= bx and gfx.mouse_x <= bx + box_sz and
                gfx.mouse_y >= cy + S(8) and gfx.mouse_y <= cy + S(8) + box_sz then
                local native_color = reaper.ColorToNative(math.floor(r * 255), math.floor(g * 255), math.floor(b * 255))
                local retval, color = reaper.GR_SelectColor(reaper.GetMainHwnd(), native_color)
                if retval > 0 then
                    local nr, ng, nb = reaper.ColorFromNative(color)
                    state.params[r_key] = nr / 255
                    state.params[g_key] = ng / 255
                    state.params[b_key] = nb / 255
                    reaper.TrackFX_SetParam(state.track, state.fx_idx, OTHER.TEXT_ITEMS_PARAM_INDICES[r_key],
                        state.params[r_key])
                    reaper.TrackFX_SetParam(state.track, state.fx_idx, OTHER.TEXT_ITEMS_PARAM_INDICES[g_key],
                        state.params[g_key])
                    reaper.TrackFX_SetParam(state.track, state.fx_idx, OTHER.TEXT_ITEMS_PARAM_INDICES[b_key],
                        state.params[b_key])
                    UTILS.save_text_items_styles()
                end
                UI_STATE.mouse_handled = true
            end
        end
        cy = cy + row_h + S(5)
    end

    local function draw_checkbox(label, param_key)
        local val = state.params[param_key] > 0.5
        local row_h = S(35)

        if cy + row_h > content_y and cy < content_y + content_h then
            local chk_sz = S(18)
            local chk_x = pad
            local chk_y = cy + S(5)

            draw_checkbox_local(chk_x, chk_y, val)

            set_color(UI.C_TXT)
            gfx.setfont(F.std)
            gfx.x, gfx.y = chk_x + chk_sz + S(8), chk_y + S(2)
            gfx.drawstr(label)

            local hover = UI_STATE.window_focused and
                gfx.mouse_x >= chk_x and gfx.mouse_x <= chk_x + chk_sz + gfx.measurestr(label) + S(15) and
                gfx.mouse_y >= chk_y and gfx.mouse_y <= chk_y + chk_sz

            if hover and is_mouse_clicked() and not UI_STATE.mouse_handled then
                state.params[param_key] = val and 0 or 1
                reaper.TrackFX_SetParam(state.track, state.fx_idx, OTHER.TEXT_ITEMS_PARAM_INDICES[param_key],
                    state.params[param_key])
                UTILS.save_text_items_styles()
                UI_STATE.mouse_handled = true
            end
        end
        cy = cy + row_h + S(5)
    end

    -- Функція для Шрифт, Стиль, Вирівнювання
    local function draw_font_dropdown()
        local row_h = S(45)
        local btn_w = S(120)
        local gap = S(6)

        -- Отримуємо поточні значення
        local font_val = math.floor(state.params["fontselect"] + 0.5)
        local style_val = math.floor(state.params["fontstyle"] + 0.5)
        local align_val = math.floor(state.params["align"] + 0.5)

        -- Тексти для кнопок
        local font_options_list = font_options_with_custom
        local style_options_list = { T("FONT_NORMAL"), T("FONT_BOLD"), T("FONT_ITALIC"), T("FONT_BOLD_ITALIC") }
        local align_options_list = { T("LEFT"), T("CENTER"), T("RIGHT") }
        local style_labels = { T("FONT_NORMAL"), T("FONT_BOLD"), T("FONT_ITALIC"), T("FONT_BOLD_ITALIC") }
        local align_labels = { T("LEFT"), T("CENTER"), T("RIGHT") }

        -- Поточні вибрані значення
        local current_font = font_options_list[font_val + 1] or tostring(font_val)
        local current_style = style_options_list[style_val + 1] or tostring(style_val)
        local current_align = align_options_list[align_val + 1] or tostring(align_val)

        -- Розраховуємо позиції
        local total_width = btn_w * 3 + gap * 2
        local start_x = pad + S(140)

        if cy + row_h > content_y and cy < content_y + content_h then
            -- Лейбл "Шрифт"
            set_color(UI.C_TXT)
            gfx.setfont(F.std)
            gfx.x, gfx.y = pad, cy + S(12)
            gfx.drawstr(T("FONT_NAME"))

            -- Кнопка вибору шрифта
            if btn(start_x, cy + S(2), btn_w, S(32), current_font, UI.C_BTN, UI.C_TXT, true) then
                local menu_str = table.concat(font_options_list, "|")
                local ret = gfx.showmenu(menu_str)
                if ret > 0 then
                    local new_val = ret - 1
                    if new_val == 12 then -- custom font
                        local ok, font_name = reaper.GetUserInputs(T("CUSTOM_FONT_CHOOSE"), 1, T("CUSTOM_FONT_INPUT"),
                            state.custom_font_name or "")
                        if ok and font_name ~= "" then
                            set_custom_font(font_name)
                            state.custom_font_name = font_name
                            state.params["fontselect"] = new_val
                            reaper.TrackFX_SetParam(state.track, state.fx_idx, OTHER.TEXT_ITEMS_PARAM_INDICES["fontselect"],
                                new_val)
                            UTILS.save_text_items_styles()
                            show_snackbar(string.format(T("CUSTOM_FONT_SET"), font_name), "success")
                        else
                            state.params["fontselect"] = font_val
                        end
                    else
                        state.params["fontselect"] = new_val
                        reaper.TrackFX_SetParam(state.track, state.fx_idx, OTHER.TEXT_ITEMS_PARAM_INDICES["fontselect"],
                            new_val)
                        UTILS.save_text_items_styles()
                    end
                    UI_STATE.mouse_handled = true
                end
            end

            -- Кнопка вибору стилю шрифта
            local style_x = start_x + btn_w + gap
            if btn(style_x, cy + S(2), btn_w, S(32), current_style, UI.C_BTN, UI.C_TXT, true) then
                local menu_str = table.concat(style_labels, "|")
                local ret = gfx.showmenu(menu_str)
                if ret > 0 then
                    local new_val = ret - 1
                    state.params["fontstyle"] = new_val
                    reaper.TrackFX_SetParam(state.track, state.fx_idx, OTHER.TEXT_ITEMS_PARAM_INDICES["fontstyle"], new_val)
                    UTILS.save_text_items_styles()
                    UI_STATE.mouse_handled = true
                end
            end

            -- Кнопка вибору вирівнювання
            local align_x = style_x + btn_w + gap
            if btn(align_x, cy + S(2), btn_w, S(32), current_align, UI.C_BTN, UI.C_TXT, true) then
                local menu_str = table.concat(align_labels, "|")
                local ret = gfx.showmenu(menu_str)
                if ret > 0 then
                    local new_val = ret - 1
                    state.params["align"] = new_val
                    reaper.TrackFX_SetParam(state.track, state.fx_idx, OTHER.TEXT_ITEMS_PARAM_INDICES["align"], new_val)
                    UTILS.save_text_items_styles()
                    UI_STATE.mouse_handled = true
                end
            end
        end
        cy = cy + row_h + S(5)
    end

    -- Функція для рядка: Колір тексту + Підкреслення
    local function draw_underline_color_row()
        local row_h = S(45)
        local chk_sz = S(18)
        local color_box_sz = S(24)
        local center_y = cy + S(12)

        if cy + row_h > content_y and cy < content_y + content_h then
            -- Колір тексту
            local color_label = T("TEXT_COLOR")
            set_color(UI.C_TXT)
            gfx.setfont(F.std)
            gfx.x, gfx.y = pad, center_y
            gfx.drawstr(color_label)

            -- Квадрат кольору
            local bx = pad + S(140)
            local box_y = cy + S(8)
            local r = state.params["fgc_r"] or 0
            local g = state.params["fgc_g"] or 0
            local b = state.params["fgc_b"] or 0

            set_color({ r, g, b })
            gfx.rect(bx, box_y, color_box_sz, color_box_sz, 1)
            set_color(UI.C_TXT)
            gfx.rect(bx, box_y, color_box_sz, color_box_sz, 0)

            if is_mouse_clicked() and gfx.mouse_x >= bx and gfx.mouse_x <= bx + color_box_sz and
                gfx.mouse_y >= box_y and gfx.mouse_y <= box_y + color_box_sz then
                local native_color = reaper.ColorToNative(math.floor(r * 255), math.floor(g * 255), math.floor(b * 255))
                local retval, color = reaper.GR_SelectColor(reaper.GetMainHwnd(), native_color)
                if retval > 0 then
                    local nr, ng, nb = reaper.ColorFromNative(color)
                    state.params["fgc_r"] = nr / 255
                    state.params["fgc_g"] = ng / 255
                    state.params["fgc_b"] = nb / 255
                    reaper.TrackFX_SetParam(state.track, state.fx_idx, OTHER.TEXT_ITEMS_PARAM_INDICES["fgc_r"],
                        state.params["fgc_r"])
                    reaper.TrackFX_SetParam(state.track, state.fx_idx, OTHER.TEXT_ITEMS_PARAM_INDICES["fgc_g"],
                        state.params["fgc_g"])
                    reaper.TrackFX_SetParam(state.track, state.fx_idx, OTHER.TEXT_ITEMS_PARAM_INDICES["fgc_b"],
                        state.params["fgc_b"])
                    UTILS.save_text_items_styles()
                end
                UI_STATE.mouse_handled = true
            end

            -- Підкреслення праворуч від кольору
            local underline_val = state.params["underline"] > 0.5
            local chk_x = bx + color_box_sz + S(25)
            local chk_y = cy + S(10)

            draw_checkbox_local(chk_x, chk_y, underline_val)

            set_color(UI.C_TXT)
            gfx.setfont(F.std)
            gfx.x, gfx.y = chk_x + chk_sz + S(8), chk_y + S(2)
            gfx.drawstr(T("UNDERLINE"))

            local hover_underline = UI_STATE.window_focused and
                gfx.mouse_x >= chk_x and gfx.mouse_x <= chk_x + chk_sz + gfx.measurestr(T("UNDERLINE")) + S(15) and
                gfx.mouse_y >= chk_y and gfx.mouse_y <= chk_y + chk_sz

            if hover_underline and is_mouse_clicked() and not UI_STATE.mouse_handled then
                state.params["underline"] = underline_val and 0 or 1
                reaper.TrackFX_SetParam(state.track, state.fx_idx, OTHER.TEXT_ITEMS_PARAM_INDICES["underline"],
                    state.params["underline"])
                UTILS.save_text_items_styles()
                UI_STATE.mouse_handled = true
            end
        end
        cy = cy + row_h + S(5)
    end

    -- Draw all controls
    draw_slider(T("TEXT_SIZE"), "size", 0.01, 0.2, 3)
    draw_font_dropdown()
    draw_underline_color_row()

    draw_slider(T("POSITION_X"), "xpos", 0, 1, 2)
    draw_slider(T("POSITION_Y"), "ypos", 0, 1, 2)
    draw_slider(T("TEXT_ALPHA"), "fga", 0, 1, 2, true)

    draw_checkbox(T("BACKGROUND"), "bg_on")
    if state.params.bg_on > 0.5 then
        draw_color_picker(T("BG_COLOR"), "bgc_r", "bgc_g", "bgc_b")
        draw_slider(T("BG_ALPHA"), "bga", 0, 1, 2, true)
        draw_slider(T("BG_OFFSET_X"), "bgxpos", 0, 1, 2)
        draw_slider(T("BG_OFFSET_Y"), "bgypos", 0, 1, 2)
        draw_slider(T("BG_WIDTH"), "bgwidth", 0.5, 2, 2)
        draw_slider(T("BG_HEIGHT"), "bgheight", 0.5, 2, 2)
    end

    draw_checkbox(T("OUTLINE"), "ol_on")
    if state.params.ol_on > 0.5 then
        draw_color_picker(T("OUTLINE_COLOR"), "outl_r", "outl_g", "outl_b")
        draw_slider(T("OUTLINE_WIDTH"), "outline_w", 1, 10, 0)
        draw_slider(T("OUTLINE_ALPHA"), "outl_a", 0, 1, 2, true)
    end

    draw_checkbox(T("SHADOW"), "sh_on")
    if state.params.sh_on > 0.5 then
        draw_slider(T("SHADOW_OFFSET_X"), "sh_x", -100, 100, 0)
        draw_slider(T("SHADOW_OFFSET_Y"), "sh_y", -100, 100, 0)
        draw_slider(T("SHADOW_ALPHA"), "sh_a", 0, 1, 2, true)
    end

    -- Store total height for scroll
    local total_h = cy - (content_y + S(20)) + (state.scroll_y or 0) + S(40)
    local max_scroll = math.max(0, total_h - content_h)

    -- Mouse wheel для прокрутки
    if gfx.mouse_wheel ~= 0 and gfx.mouse_x >= 0 and gfx.mouse_x <= gfx.w and
        gfx.mouse_y >= content_y and gfx.mouse_y <= content_y + content_h then
        state.target_scroll_y = (state.target_scroll_y or 0) - (gfx.mouse_wheel * 0.5)
        gfx.mouse_wheel = 0
    end

    state.target_scroll_y = math.max(0, math.min(state.target_scroll_y or 0, max_scroll))
    local diff = (state.target_scroll_y or 0) - (state.scroll_y or 0)
    if math.abs(diff) > 0.5 then
        state.scroll_y = (state.scroll_y or 0) + diff * 0.8
    else
        state.scroll_y = state.target_scroll_y or 0
    end

    -- Scrollbar
    if max_scroll > 0 then
        local new_scroll = draw_scrollbar(gfx.w - S(10), content_y, S(10), content_h, total_h, content_h,
            state.scroll_y or 0)
        if new_scroll ~= (state.scroll_y or 0) then
            state.scroll_y = new_scroll
            state.target_scroll_y = new_scroll
        end
    end

    -- Header
    set_color(UI.C_BG, 1.0)
    gfx.rect(0, 0, gfx.w, header_h, 1)
    set_color(UI.C_TXT, 0.1)
    gfx.line(0, header_h, gfx.w, header_h)
    
    gfx.setfont(F.title)
    set_color(UI.C_TXT)
    gfx.x, gfx.y = pad, pad - S(2)
    
    -- Close button (X) - Top Right
    local close_sz = S(24)
    local close_x = gfx.w - pad - close_sz
    
    -- Знаходимо найближчий елемент ліворуч для розрахунку доступної ширини
    -- Враховуємо: кнопку Close, FX Toggle, Reset, Apply to Item, Editor Toggle
    local right_buttons_width = close_sz + S(10) 
    
    -- Якщо є FX Toggle button
    local bypass_w = S(100)
    local bypass_x = close_x - bypass_w - S(10)
    right_buttons_width = right_buttons_width + bypass_w + S(10)
    
    -- Якщо є Reset button
    local reset_w = S(100)
    local reset_x = bypass_x - reset_w - S(8)
    right_buttons_width = right_buttons_width + reset_w + S(8)
    
    -- Якщо є Apply to Item button
    local apply_w = S(120)
    local apply_x = reset_x - apply_w - S(8)
    right_buttons_width = right_buttons_width + apply_w + S(8)
    
    -- Якщо є Editor Toggle button
    local editor_toggle_w = S(35)
    local editor_toggle_x = apply_x - editor_toggle_w - S(8)
    right_buttons_width = right_buttons_width + editor_toggle_w + S(8)
    
    -- Розраховуємо доступну ширину для заголовка
    local avail_tw = gfx.w - pad - right_buttons_width - S(10)
    local draw_title = fit_text_width(T("TEXT_ITEMS_STYLE_TITLE"), avail_tw)
    gfx.x, gfx.y = pad, pad + S(1)
    gfx.drawstr(draw_title)

    local close_hover = UI_STATE.window_focused and (gfx.mouse_x >= close_x and gfx.mouse_x <= close_x + close_sz and
        gfx.mouse_y >= pad and gfx.mouse_y <= pad + close_sz)

    -- Tooltip для кнопки Close
    if close_hover then
        local tip_id = "close_text_items_style"
        if UI_STATE.tooltip_state.hover_id ~= tip_id then
            UI_STATE.tooltip_state.hover_id = tip_id
            UI_STATE.tooltip_state.start_time = reaper.time_precise()
        end
        UI_STATE.tooltip_state.text = "Esc"
    end

    -- Обробка кліку миші по кнопці Close
    if btn(close_x, pad, close_sz, close_sz, "X", UI.C_BTN, UI.C_TXT, true) then
        UTILS.save_text_items_styles()
        UI_STATE.text_items_style = nil
        UI_STATE.apply_button_active = false
        UI_STATE.text_items_style_backup = nil
    end

    -- Обробка Esc для кнопки Close
    if input_queue then
        for _, c in ipairs(input_queue) do
            if c == 27 then
                UTILS.save_text_items_styles()
                UI_STATE.text_items_style = nil
                UI_STATE.apply_button_active = false
                UI_STATE.text_items_style_backup = nil
                break
            end
        end
    end

    -- FX Toggle Button
    local bypass_w = S(100)
    local bypass_x = close_x - bypass_w - S(8)
    
    -- Track FX enabled state
    local fx_enabled = state.track and (reaper.GetMediaTrackInfo_Value(state.track, "I_FXEN") > 0) or false
    -- Track mute state
    local track_muted = state.track and (reaper.GetMediaTrackInfo_Value(state.track, "B_MUTE") > 0) or false
    
    local bypass_text = ""
    local bypass_color = UI.C_BTN_MEDIUM
    
    if track_muted then
        bypass_text = T("FX_DISABLED")
        bypass_color = UI.C_BTN_ERROR
    elseif fx_enabled then
        bypass_text = T("FX_ENABLED")
        bypass_color = UI.C_BTN_MEDIUM
    else
        bypass_text = T("FX_DISABLED")
        bypass_color = UI.C_BTN_ERROR
    end
    
    if btn(bypass_x, pad, bypass_w, close_sz, bypass_text, bypass_color, UI.C_TXT, true) then
        if state.track then
            if track_muted then
                -- Якщо доріжка в mute, вимикаємо mute і вмикаємо FX
                reaper.SetMediaTrackInfo_Value(state.track, "B_MUTE", 0)
                reaper.SetMediaTrackInfo_Value(state.track, "I_FXEN", 1)
                show_snackbar(T("FX_ENABLED_MSG"), "info")
            elseif fx_enabled then
                -- Якщо FX увімкнено, вимикаємо FX і вмикаємо mute
                reaper.SetMediaTrackInfo_Value(state.track, "I_FXEN", 0)
                reaper.SetMediaTrackInfo_Value(state.track, "B_MUTE", 1)
                show_snackbar(T("FX_DISABLED_MSG"), "info")
            else
                -- Якщо FX вимкнено і доріжка не в mute, просто вмикаємо FX
                reaper.SetMediaTrackInfo_Value(state.track, "I_FXEN", 1)
                show_snackbar(T("FX_ENABLED_MSG"), "info")
            end
        end
    end

    -- Reset Button (зліва від FX Toggle, на 8 пікселів)
    local reset_w = S(100)
    local reset_x = bypass_x - reset_w - S(8)

    if btn(reset_x, pad, reset_w, close_sz, T("RESET_STYLES"), UI.C_BTN, UI.C_TXT, true) then
        -- Reset all parameters to default values
        for key, default_val in pairs(state.default_params) do
            state.params[key] = default_val
            if state.fx_idx and state.fx_idx >= 0 then
                reaper.TrackFX_SetParam(state.track, state.fx_idx, OTHER.TEXT_ITEMS_PARAM_INDICES[key], default_val)
            end
        end
        UTILS.save_text_items_styles()
        show_snackbar(T("STYLES_RESET"), "success")
    end

    -- Apply to Item button (toggle)
    local apply_w = S(120)
    local apply_x = reset_x - apply_w - S(8)
    
    local apply_active = UI_STATE.apply_to_item_mode or false
    local apply_color = apply_active and UI.C_BTN_MEDIUM or UI.C_BTN
    
    if btn(apply_x, pad, apply_w, close_sz, T("APPLY_TO_ITEM"), apply_color, UI.C_TXT, true) then
        if not apply_active then
            -- Активація: зберігаємо бекап параметрів у ExtState
            local backup = {}
            if UI_STATE.text_items_style and UI_STATE.text_items_style.params then
                for key, val in pairs(UI_STATE.text_items_style.params) do
                    backup[key] = val
                end
            end
            backup["_custom_font_name"] = UI_STATE.text_items_style and UI_STATE.text_items_style.custom_font_name or ""
            local json_str = STATS.json_encode(backup)
            reaper.SetExtState(section_name, "apply_to_item_backup", json_str, false)
            UI_STATE.apply_to_item_mode = true
        else
            -- Деактивація: застосовуємо до всіх виділених item, потім відновлюємо бекап
            UTILS.apply_styles_to_selected_items()
            
            -- Відновлюємо бекап
            local json_str = reaper.GetExtState(section_name, "apply_to_item_backup")
            if json_str and json_str ~= "" then
                local success, backup = pcall(function() return STATS.json_decode(json_str) end)
                if success and type(backup) == "table" and UI_STATE.text_items_style then
                    for key, _ in pairs(OTHER.TEXT_ITEMS_PARAM_INDICES) do
                        if backup[key] ~= nil then
                            local val = tonumber(backup[key]) or backup[key]
                            UI_STATE.text_items_style.params[key] = val
                            if UI_STATE.text_items_style.track and UI_STATE.text_items_style.fx_idx >= 0 then
                                reaper.TrackFX_SetParam(UI_STATE.text_items_style.track, UI_STATE.text_items_style.fx_idx, OTHER.TEXT_ITEMS_PARAM_INDICES[key], val)
                            end
                        end
                    end
                    if backup["_custom_font_name"] and backup["_custom_font_name"] ~= "" then
                        UI_STATE.text_items_style.custom_font_name = backup["_custom_font_name"]
                    end
                    UTILS.save_text_items_styles()
                end
            end
            
            reaper.SetExtState(section_name, "apply_to_item_backup", "", false)
            UI_STATE.apply_to_item_mode = false
        end
    end

    -- Toggle Button for SUBASS ITEMS Editor
    local editor_toggle_w = S(35)
    local editor_toggle_x = apply_x - editor_toggle_w - S(8)
    local editor_toggle_text = UI_STATE.subass_items_editor_mode and "✏" or "✏"
    local editor_toggle_bg = UI_STATE.subass_items_editor_mode and UI.C_BTN_MEDIUM or UI.C_BTN

    if btn(editor_toggle_x, pad, editor_toggle_w, close_sz, editor_toggle_text, editor_toggle_bg, UI.C_TXT, true) then
        UI_STATE.subass_items_editor_mode = not UI_STATE.subass_items_editor_mode
    end

    -- Tooltip для кнопки редактора
    local editor_toggle_hover = UI_STATE.window_focused and
    (gfx.mouse_x >= editor_toggle_x and gfx.mouse_x <= editor_toggle_x + editor_toggle_w and
        gfx.mouse_y >= pad and gfx.mouse_y <= pad + close_sz)
    if editor_toggle_hover then
        local tip_id = "subass_items_editor_toggle"
        if UI_STATE.tooltip_state.hover_id ~= tip_id then
            UI_STATE.tooltip_state.hover_id = tip_id
            UI_STATE.tooltip_state.start_time = reaper.time_precise()
        end
        UI_STATE.tooltip_state.text = T("SUBASS_ITEMS_EDITOR")
    end

    -- Simplified robust helper to set FX code (Track or Take)
    local function set_fx_code_simple(target, fx_idx, code_str, is_take)
        -- Try API first
        local setter = is_take and reaper.TakeFX_SetNamedConfigParm or reaper.TrackFX_SetNamedConfigParm
        if setter then
            if setter(target, fx_idx, "code", code_str) then return true end
        end

        -- Fallback to chunk hacking (target is track or take)
        local encoded = "|" .. code_str:gsub("\n", "\n|")
        local ret, chunk
        local item = is_take and reaper.GetMediaItemTake_Item(target) or nil

        if is_take then
            ret, chunk = reaper.GetItemStateChunk(item, "", false)
        else
            ret, chunk = reaper.GetTrackStateChunk(target, "", false)
        end

        if ret then
            -- Find the fx_idx-th VIDEO_EFFECT block (0-indexed)
            local current_idx = -1
            local s_idx = 1
            while true do
                local s, e = chunk:find("<VIDEO_EFFECT", s_idx)
                if not s then break end
                current_idx = current_idx + 1

                if current_idx == fx_idx then
                    local b_end = chunk:find("\n>", e)
                    if b_end then
                        local code_s, code_e = chunk:find("<CODE.-%s>", s)
                        local new_chunk
                        if code_s and code_s < b_end then
                            new_chunk = chunk:sub(1, code_s - 1) ..
                            "<CODE\n" .. encoded .. "\n>" .. chunk:sub(code_e + 1)
                        else
                            -- Find first newline after VIDEO_EFFECT to insert NI and CODE
                            local head_end = chunk:find("\n", e) or e
                            new_chunk = chunk:sub(1, head_end) ..
                            "\n<CODE\n" .. encoded .. "\n>" .. chunk:sub(head_end + 1)
                        end

                        if is_take then
                            reaper.SetItemStateChunk(item, new_chunk, false)
                        else
                            reaper.SetTrackStateChunk(target, new_chunk, false)
                        end
                        return true
                    end
                end
                s_idx = e + 1
            end
        end
        return false
    end

    -- Редактор SUBASS ITEMS (футер)
    if UI_STATE.subass_items_editor_mode then
        local editor_panel_h = S(140)
        local editor_panel_y = gfx.h - editor_panel_h
        local editor_panel_w = gfx.w
        local editor_panel_x = 0

        -- Фон панелі
        set_color(UI.C_BG, 0.98)
        gfx.rect(editor_panel_x, editor_panel_y, editor_panel_w, editor_panel_h, 1)
        set_color(UI.C_MEDIUM_GREY)
        gfx.line(editor_panel_x, editor_panel_y, editor_panel_w, editor_panel_y)

        -- Заголовок панелі
        gfx.setfont(F.std)
        set_color(UI.C_TXT, 0.7)
        gfx.x, gfx.y = pad, editor_panel_y + S(8)
        gfx.drawstr(T("SUBASS_ITEMS_EDITOR"))

        -- Отримуємо виділення (Time Selection)
        local sel_start, sel_end = reaper.GetSet_LoopTimeRange2(0, false, false, 0, 0, false)
        local has_time_selection = (sel_start ~= sel_end and sel_end > sel_start)
        local cursor_pos = reaper.GetCursorPosition()
        local is_in_selection = has_time_selection and cursor_pos >= sel_start and cursor_pos <= sel_end

        -- Отримуємо item під курсором на треку SUBASS_ITEMS
        local track_name = "SUBASS_ITEMS"
        local target_track = nil
        local tc = reaper.CountTracks(0)
        for t = 0, tc - 1 do
            local tr = reaper.GetTrack(0, t)
            local _, tn = reaper.GetTrackName(tr)
            if tn == track_name then
                target_track = tr
                break
            end
        end

        local current_item = nil
        local current_text = ""
        local is_editing_existing = false

        if target_track then
            local item_count = reaper.CountTrackMediaItems(target_track)

            -- Шукаємо item під курсором
            for i = 0, item_count - 1 do
                local item = reaper.GetTrackMediaItem(target_track, i)
                local item_pos = reaper.GetMediaItemInfo_Value(item, "D_POSITION")
                local item_len = reaper.GetMediaItemInfo_Value(item, "D_LENGTH")

                if cursor_pos >= item_pos and cursor_pos <= item_pos + item_len then
                    current_item = item
                    local take = reaper.GetActiveTake(item)
                    if take then
                        local ret, name = reaper.GetSetMediaItemTakeInfo_String(take, "P_NAME", "", false)
                        if ret then current_text = name end
                    end
                    is_editing_existing = true
                    break
                end
            end
        end

        -- Якщо є Time Selection і курсор в ньому, і немає item під курсором - створюємо новий
        local can_create_new = has_time_selection and is_in_selection and not is_editing_existing

        -- Поле для редагування тексту
        local input_x = pad
        local input_y = editor_panel_y + S(30)
        local input_w = gfx.w - pad * 2 - S(100)
        local input_h = editor_panel_h - S(50)

        -- Стан для редактора тексту
        if not UI_STATE.subass_items_edit_state then
            UI_STATE.subass_items_edit_state = {
                text = "",
                cursor = 0,
                anchor = 0,
                focus = false,
                history = {},
                history_pos = 0
            }
        end

        -- Оновлюємо текст при зміні item або створенні нового
        local should_update = (UI_STATE.subass_items_edit_state.last_item ~= current_item) or
            (UI_STATE.subass_items_edit_state.last_selection_start ~= sel_start) or
            (UI_STATE.subass_items_edit_state.last_selection_end ~= sel_end)

        if should_update then
            if is_editing_existing then
                UI_STATE.subass_items_edit_state.text = current_text
            elseif can_create_new then
                UI_STATE.subass_items_edit_state.text = ""
            end
            UI_STATE.subass_items_edit_state.cursor = #UI_STATE.subass_items_edit_state.text
            UI_STATE.subass_items_edit_state.anchor = #UI_STATE.subass_items_edit_state.text
            UI_STATE.subass_items_edit_state.last_item = current_item
            UI_STATE.subass_items_edit_state.last_selection_start = sel_start
            UI_STATE.subass_items_edit_state.last_selection_end = sel_end
            UI_STATE.subass_items_edit_state.focus = true
            record_field_history(UI_STATE.subass_items_edit_state)
        end

        -- Функція форматування тексту (перенос рядків)
        local function format_text(in_text, limit)
            local text = in_text:gsub("{{+.-}}+", ""):gsub("{.-}", "")

            local lines = {}
            -- Розбиваємо вхідний текст на існуючі рядки
            for line in text:gmatch("[^\r\n]+") do
                -- Якщо рядок короткий, додаємо як є
                if #line <= limit then
                    table.insert(lines, line)
                else
                    -- Якщо рядок задовгий, розбиваємо його на підрядки
                    local current_line = ""
                    for word in line:gmatch("%S+") do
                        if #current_line + #word + 1 > limit then
                            table.insert(lines, current_line)
                            current_line = word
                        else
                            current_line = (current_line == "" and "" or current_line .. " ") .. word
                        end
                    end
                    table.insert(lines, current_line)
                end
            end

            -- Збираємо все назад у один текст
            return table.concat(lines, "\n")
        end

        -- Функція створення нового TEXT ITEM
        local function create_text_item_from_selection(text_content)
            if not has_time_selection or not is_in_selection then
                show_snackbar(T("NO_REGIONS_IN_PROJ"), "warning")
                return false
            end

            -- Знаходимо або створюємо трек
            if not target_track then
                reaper.InsertTrackAtIndex(0, true)
                target_track = reaper.GetTrack(0, 0)
                reaper.GetSetMediaTrackInfo_String(target_track, "P_NAME", track_name, true)

                -- Додаємо FX на новий трек
                local track_fx_idx = reaper.TrackFX_AddByName(target_track, "Video processor", false, 1)
                if track_fx_idx >= 0 then
                    local saved_styles = UTILS.load_text_items_styles()
                    if saved_styles and saved_styles.params then
                        for key, idx in pairs(OTHER.TEXT_ITEMS_PARAM_INDICES) do
                            local val = saved_styles.params[key]
                            if val then reaper.TrackFX_SetParam(target_track, track_fx_idx, idx, val) end
                        end
                    end
                end
            end

            -- Створюємо item в межах Time Selection
            local item = reaper.AddMediaItemToTrack(target_track)
            reaper.SetMediaItemInfo_Value(item, "D_POSITION", sel_start)
            reaper.SetMediaItemInfo_Value(item, "D_LENGTH", math.max(sel_end - sel_start, 0.001))

            local take = reaper.AddTakeToMediaItem(item)
            if take then
                -- Форматуємо текст з переносом рядків
                local formatted_text = format_text(text_content, 80)

                reaper.GetSetMediaItemTakeInfo_String(take, "P_NAME", formatted_text, true)
                reaper.GetSetMediaItemInfo_String(item, "P_NOTES", formatted_text, true)

                -- Додаємо Video Processor FX на take
                local take_fx = reaper.TakeFX_AddByName(take, "Video processor", 1)
                if take_fx >= 0 then
                    local item_code = "gfx_blit(0, 1);\ngmem[0] = 1;"
                    set_fx_code_simple(take, take_fx, item_code, true)
                end
            end

            reaper.UpdateItemInProject(item)
            return true
        end

        -- Функція збереження
        local function save_subass_item()
            local new_text = UI_STATE.subass_items_edit_state.text
        
            if new_text == "" then
                show_snackbar(T("NO_EMPTY_NAME"), "warning")
                return
            end
        
            if is_editing_existing and current_item then
                push_undo("Edit Subass Text Item")
                
                -- Зберігаємо позицію та довжину старого item
                local item_pos = reaper.GetMediaItemInfo_Value(current_item, "D_POSITION")
                local item_len = reaper.GetMediaItemInfo_Value(current_item, "D_LENGTH")
                
                -- Видаляємо старий item
                reaper.DeleteTrackMediaItem(target_track, current_item)
                
                -- Створюємо новий item на тому ж місці
                local new_item = reaper.AddMediaItemToTrack(target_track)
                reaper.SetMediaItemInfo_Value(new_item, "D_POSITION", item_pos)
                reaper.SetMediaItemInfo_Value(new_item, "D_LENGTH", item_len)
                
                local take = reaper.AddTakeToMediaItem(new_item)
                if take then
                    -- Форматуємо текст
                    local formatted_text = new_text
                    
                    reaper.GetSetMediaItemTakeInfo_String(take, "P_NAME", formatted_text, true)
                    reaper.GetSetMediaItemInfo_String(new_item, "P_NOTES", formatted_text, true)
                    
                    -- Додаємо Video Processor FX на take
                    local take_fx = reaper.TakeFX_AddByName(take, "Video processor", 1)
                    if take_fx >= 0 then
                        local item_code = "gfx_blit(0, 1);\ngmem[0] = 1;"
                        set_fx_code_simple(take, take_fx, item_code, true)
                    end
                end
                
                reaper.UpdateItemInProject(new_item)
                show_snackbar(T("SAVED"), "success")
                
            elseif can_create_new then
                -- Створюємо новий item з виділення
                push_undo("Create Subass Text Item")
                if create_text_item_from_selection(new_text) then
                    show_snackbar(T("TRACK_CREATED"), "success")
                    -- Оновлюємо стан після створення
                    UI_STATE.subass_items_edit_state.last_item = nil
                end
            else
                show_snackbar(T("SELECT_AND_GO_REGION"), "warning")
            end
        end

        -- Запам'ятовуємо стан фокусу
        local was_focused = UI_STATE.subass_items_edit_state and UI_STATE.subass_items_edit_state.focus

        -- Нормалізуємо input_queue
        local normalized_queue = nil
        if input_queue and was_focused then
            normalized_queue = {}
            for _, char in ipairs(input_queue) do
                if char == 0 then
                    table.insert(normalized_queue, 32) -- пробіл
                else
                    table.insert(normalized_queue, char)
                end
            end
        else
            normalized_queue = input_queue
        end

        -- Малюємо поле вводу
        ui_text_input("subass_items_editor", input_x, input_y, input_w, input_h,
            UI_STATE.subass_items_edit_state, "", normalized_queue, true, false, F[cfg.t_editor_size])

        -- Кнопка Save
        local save_btn_w = S(90)
        local save_btn_x = gfx.w - pad - save_btn_w
        local save_btn_y = editor_panel_y + S(30)
        
        if btn(save_btn_x, save_btn_y, save_btn_w, input_h, T("SAVE_TEXT_ITEM"), UI.C_BTN_MEDIUM, UI.C_TXT, true) then
            save_subass_item()
        end

         -- Обробка Enter для збереження
        if normalized_queue and was_focused then
            for _, char in ipairs(normalized_queue) do
                if char == 13 then 
                    local shift_pressed = false
                    if gfx.mouse_cap & 8 == 8 or gfx.mouse_cap & 16 == 16 then
                        shift_pressed = true
                    end 
                    if not shift_pressed then
                        save_subass_item()
                    end
                    break
                end
            end
        end
    end

    UI_STATE.mouse_handled = true
    return true
end

-- --- Search Item Modal ---

function SEARCH_ITEM.open()
    SEARCH_ITEM.show = true
    SEARCH_ITEM.input.focus = false
    SEARCH_ITEM.results = nil
    
    local play_state = reaper.GetPlayState()
    local cur_pos = (play_state & 1 == 1) and reaper.GetPlayPosition() or reaper.GetCursorPosition()
    
    for _, rgn in ipairs(regions) do
        if cur_pos >= rgn.pos and cur_pos < rgn.rgnend then
            local t = rgn.name:gsub("{{+.-}}+", ""):gsub("{.-}", ""):gsub("\\n", " "):gsub("\n", " "):gsub("  +", " "):gsub("^%s+", ""):gsub("%s+$", "")
            SEARCH_ITEM.input.text = t
            local l = #t
            SEARCH_ITEM.input.cursor = l
            SEARCH_ITEM.input.anchor = l
            break
        end
    end
end

function SEARCH_ITEM.pick_folder(callback)
    if reaper.JS_Dialog_BrowseForFolder then
        local retval, folder = reaper.JS_Dialog_BrowseForFolder(T("SRC_SELECT_F_FOR_S_2"), cfg.search_item_path or "")
        if retval == 1 and folder ~= "" then
            cfg.search_item_path = folder
            save_settings()
            if callback then callback() end
            return true
        end
    else
        show_snackbar(T("SRC_JS_API_RQ"), "error")
    end
    return false
end

function SEARCH_ITEM.perform_search()
    local q = SEARCH_ITEM.input.text
    if q == "" then return end

    if not cfg.search_item_path or cfg.search_item_path == "" then
        SEARCH_ITEM.pick_folder(function()
            SEARCH_ITEM.perform_search()
        end)
        return
    end

    SEARCH_ITEM.last_query = q
    SEARCH_ITEM.loading = true
    
    local info = debug.getinfo(1, 'S')
    local path = info.source:match("@?(.*)")
    local dir = path:match("(.*[/\\])")
    
    if not dir then
        show_snackbar(T("SRC_PATH_ERR") .. tostring(path), "error")
        SEARCH_ITEM.loading = false
        return
    end

    local separator = package.config:sub(1,1)
    local python_tool = dir .. "stats" .. separator .. "subass_search.py"
    local search_item_path = cfg.search_item_path

    local py_exe = is_windows and UTILS.get_win_py_exe(OTHER.rec_state.python.executable or "py -3") or "python3"
    
    local cmd = string.format('%s "%s" "%s" "%s"', py_exe, python_tool, q:gsub('"', '\\"'), search_item_path)
    
    run_async_command(cmd, function(out)
        SEARCH_ITEM.loading = false
        if out and out ~= "" then
            local status, data = pcall(function() return STATS.json_decode(out) end)
            if status and type(data) == "table" then
                SEARCH_ITEM.results = data
            else
                SEARCH_ITEM.results = {}
            end
        else
            SEARCH_ITEM.results = {}
        end
        SEARCH_ITEM.scroll_y = 0
        SEARCH_ITEM.target_scroll_y = 0
    end, false, T("SEARCH_DOTS"))
end

function SEARCH_ITEM.play_item(item, from_pos)
    -- Cleanup any leftover hidden track from the failed experiment
    local tr_count = reaper.CountTracks(0)
    for i = tr_count - 1, 0, -1 do
        local tr = reaper.GetTrack(0, i)
        local _, name = reaper.GetSetMediaTrackInfo_String(tr, "P_NAME", "", false)
        if name == "Subass Preview" then reaper.DeleteTrack(tr) end
    end

    if SEARCH_ITEM.current_preview and reaper.CF_Preview_Stop then
        reaper.CF_Preview_Stop(SEARCH_ITEM.current_preview)
        SEARCH_ITEM.current_preview = nil
    end
    
    if not item or not item.file_path then 
        SEARCH_ITEM.current_item = nil
        SEARCH_ITEM.player_paused = false
        SEARCH_ITEM.pause_pos = 0
        SEARCH_ITEM.play_start_time = nil
        return 
    end
    
    local clean_path = item.file_path:gsub("\\", "/")
    
    -- Verify path
    local f = io.open(clean_path, "r")
    if not f then
        show_snackbar(T("FILE_NOT_FOUND"), "error")
        return
    end
    f:close()

    local pcm_source = reaper.PCM_Source_CreateFromFile(clean_path)
    if not pcm_source then
        show_snackbar(T("SRC_F_OPEN_A_SOURCE"), "error")
        return
    end

    if reaper.CF_CreatePreview and reaper.CF_Preview_Play then
        local preview = reaper.CF_CreatePreview(pcm_source)
        if preview then
            local start_pos = from_pos or item.pos or 0
            local length = item.length or reaper.GetMediaSourceLength(pcm_source)
            
            -- Simplest possible approach: just play
            reaper.CF_Preview_Play(preview)
            
            local fname = clean_path:match("([^/\\]+)$")
            
            SEARCH_ITEM.current_preview = preview
            SEARCH_ITEM.current_source = pcm_source
            SEARCH_ITEM.current_item = item
            SEARCH_ITEM.segment_start = 0  -- Always from start for now
            SEARCH_ITEM.preview_length = length
            SEARCH_ITEM.player_paused = false
            SEARCH_ITEM.wait_frames = 0
            SEARCH_ITEM.last_tracked_pos = -1
            SEARCH_ITEM.play_start_time = reaper.time_precise()  -- Track time manually
            SEARCH_ITEM.open_time = reaper.time_precise() -- Track open time for debounce
        end
    end
end

function SEARCH_ITEM.toggle_pause()
    if not SEARCH_ITEM.current_item then return end
    
    if SEARCH_ITEM.player_paused then
        -- Resume
        SEARCH_ITEM.play_item(SEARCH_ITEM.current_item, SEARCH_ITEM.pause_pos)
    else
        -- Pause
        if reaper.CF_Preview_GetValue then
            local val = reaper.CF_Preview_GetValue(SEARCH_ITEM.current_preview, "D_POSITION")
            SEARCH_ITEM.pause_pos = type(val) == "number" and val or 0
        end
        if SEARCH_ITEM.current_preview and reaper.CF_Preview_Stop then
            reaper.CF_Preview_Stop(SEARCH_ITEM.current_preview)
        end
        SEARCH_ITEM.current_preview = nil
        SEARCH_ITEM.player_paused = true
    end
end

function SEARCH_ITEM.draw_mini_player()
    if not SEARCH_ITEM.current_item and not SEARCH_ITEM.player_paused then return end
    
    local h = S(60)  -- Reduced height
    local x, y, w = S(20), gfx.h - h - S(20), gfx.w - S(40)
    
    -- Background
    set_color(UI.C_BG, 0.98)
    gfx.rect(x, y, w, h, 1)
    set_color(UI.C_TXT, 0.2)
    gfx.rect(x, y, w, h, 0) -- border
    
    local pad = S(10)
    local btn_sz = S(40)
    local btn_x = x + pad
    local btn_y = y + pad
    
    -- Play/Pause Button
    local label = SEARCH_ITEM.player_paused and "▶" or "Ⅱ"
    if btn(btn_x, btn_y, btn_sz, btn_sz, label, UI.C_BTN, UI.C_TXT) then
        -- Debounce: prevent immediate interaction if player just opened
        if reaper.time_precise() - (SEARCH_ITEM.open_time or 0) > 0.3 then
            SEARCH_ITEM.toggle_pause()
        end
        UI_STATE.mouse_handled = true
    end
    
    -- File name
    local name_x = btn_x + btn_sz + pad
    local item = SEARCH_ITEM.current_item
    local name = item.item or item.file_path:match("([^/\\]+)$")
    gfx.setfont(F.bld)
    set_color(UI.C_TXT)
    local avail_nw = w - (name_x - x) - S(120)  -- Space for close and menu buttons
    local draw_name = fit_text_width(name, avail_nw)
    gfx.x, gfx.y = name_x, y + pad - S(2) -- Slightly higher
    gfx.drawstr(draw_name)
    
    -- Calculate playback position
    local abs_pos = 0 
    if SEARCH_ITEM.player_paused then
        abs_pos = SEARCH_ITEM.pause_pos or 0
    elseif SEARCH_ITEM.current_preview then
        if not SEARCH_ITEM.play_start_time then
            SEARCH_ITEM.play_start_time = reaper.time_precise()
        end
        
        local elapsed = reaper.time_precise() - SEARCH_ITEM.play_start_time
        abs_pos = elapsed
        
        -- Auto-stop at end (but keep player open)
        if abs_pos >= (SEARCH_ITEM.preview_length or 0) then
            if SEARCH_ITEM.current_preview and reaper.CF_Preview_Stop then
                reaper.CF_Preview_Stop(SEARCH_ITEM.current_preview)
            end
            SEARCH_ITEM.current_preview = nil
            SEARCH_ITEM.player_paused = true
            SEARCH_ITEM.pause_pos = SEARCH_ITEM.preview_length or 0
            abs_pos = SEARCH_ITEM.pause_pos
        end
    end
    
    local cur_pos = math.max(0, abs_pos - (SEARCH_ITEM.segment_start or 0))
    local display_length = SEARCH_ITEM.preview_length or 0
    
    -- Progress Bar (below file name)
    local pb_x = name_x
    local pb_y = y + pad + S(22)  -- Below file name (increased spacing)
    local pb_w = w - (pb_x - x) - S(120)
    local pb_h = S(4)
    
    set_color(UI.C_TXT, 0.2)
    gfx.rect(pb_x, pb_y, pb_w, pb_h, 1)
    
    if display_length > 0 then
        local prog = math.min(1, math.max(0, cur_pos / display_length))
        set_color(UI.C_ORANGE)
        gfx.rect(pb_x, pb_y, pb_w * prog, pb_h, 1)
    end
    
    -- Timer (below progress bar)
    local raw_timer = string.format("%s / %s", format_timestamp(cur_pos), format_timestamp(display_length))
    local timer_text = fit_text_width(raw_timer, pb_w)
    gfx.setfont(F.tip)
    set_color(UI.C_TXT, 0.5)
    gfx.x, gfx.y = pb_x, pb_y + S(8)
    gfx.drawstr(timer_text)
    
    -- Menu Button (≡)
    local menu_sz = S(30)
    local menu_x = x + w - pad - menu_sz - S(40)  -- Space for close button
    local menu_y = y + pad
    if btn(menu_x, menu_y, menu_sz, menu_sz, "≡", UI.C_BTN, UI.C_TXT) then
        local menu_str = T("SRC_I_MENU")
        local ret = gfx.showmenu(menu_str)
        
        if ret == 1 then
            -- Insert audio
            if item and item.file_path then
                reaper.InsertMedia(item.file_path, 0)
                show_snackbar(T("AUDIO_ADDED"), "success")
            end
        elseif ret == 2 then
            -- Open project
            if item and item.project_path then
                local target_path = item.project_path
                local target_pos = item.pos
                local target_track = item.track

                -- Definition of function to jump to position
                local function jump_to_pos()
                    if target_pos then
                        reaper.SetEditCurPos(target_pos, true, false)
                        
                        -- Try to find track and scroll to it
                        if target_track and target_track ~= "" then
                            local tr_count = reaper.CountTracks(0)
                            for i = 0, tr_count - 1 do
                                local tr = reaper.GetTrack(0, i)
                                local _, tr_name = reaper.GetSetMediaTrackInfo_String(tr, "P_NAME", "", false)
                                if tr_name == target_track then
                                    reaper.SetOnlyTrackSelected(tr)
                                    reaper.Main_OnCommand(40913, 0) -- Track: Vertical scroll to selected tracks
                                    break
                                end
                            end
                        end
                    end
                end

                if reaper.file_exists(target_path) then
                    -- Check if project is already open
                    local found_proj = nil
                    local i = 0
                    while true do
                        local proj, projfn = reaper.EnumProjects(i, "")
                        if not proj then break end
                        if projfn and projfn:gsub("\\", "/") == target_path:gsub("\\", "/") then
                            found_proj = proj
                            break
                        end
                        i = i + 1
                    end

                    if found_proj then
                        reaper.SelectProjectInstance(found_proj)
                        show_snackbar(T("SRC_I_SW_OPEN_PROJ"), "success")
                    else
                        reaper.Main_OnCommand(40859, 0) -- New project tab
                        reaper.Main_openProject(target_path)
                        show_snackbar(T("SRC_I_OPEN_PROJ"), "success")
                    end
                    
                    jump_to_pos()
                else
                    local result = reaper.MB(T("SRC_I_NF_1") .. target_path .. T("SRC_I_NF_2"), T("SRC_I_NF_3"), 4)
                    if result == 6 then -- Yes
                        local retval, new_path = reaper.GetUserFileNameForRead(target_path, T("FIND_A_PROJ_UF"), "rpp")
                        if retval and new_path then
                            -- Check if project is already open
                            local found_proj = nil
                            local i = 0
                            while true do
                                local proj, projfn = reaper.EnumProjects(i, "")
                                if not proj then break end
                                if projfn and projfn:gsub("\\", "/") == new_path:gsub("\\", "/") then
                                    found_proj = proj
                                    break
                                end
                                i = i + 1
                            end

                            if found_proj then
                                reaper.SelectProjectInstance(found_proj)
                                show_snackbar(T("SRC_I_SW_OPEN_PROJ"), "success")
                            else
                                reaper.Main_OnCommand(40859, 0)
                                reaper.Main_openProject(new_path)
                                show_snackbar(T("SRC_I_OPEN_PROJ"), "success")
                            end
                            
                            jump_to_pos()
                        end
                    end
                end
            else
                show_snackbar(T("SRC_NO_PATH_PROJ_UF"), "error")
            end
        end
        UI_STATE.mouse_handled = true
    end
    
    -- Close Button (×)
    local close_sz = S(30)
    local close_x = x + w - pad - close_sz
    local close_y = y + pad
    if btn(close_x, close_y, close_sz, close_sz, "x", UI.C_BTN, UI.C_TXT) then
        SEARCH_ITEM.play_item(nil)  -- Close player
        UI_STATE.mouse_handled = true
    end
end

function SEARCH_ITEM.show_item_menu(items)
    local menu_str = ""
    for i, item in ipairs(items) do
        local name = item.item or item.file_path:match("([^/\\]+)$")
        local track = item.track or ""
        local display = string.format("%s (Tr: %s)", name, track)
        menu_str = menu_str .. (i > 1 and "|" or "") .. display
    end
    
    local ret = gfx.showmenu(menu_str)
    if ret > 0 then
        SEARCH_ITEM.play_item(items[ret])
    end
end

function SEARCH_ITEM.draw_window(input_queue)
    if not SEARCH_ITEM.show then return end
    
    -- Block clicks on player area FIRST (before processing any other UI elements)
    if SEARCH_ITEM.current_item or SEARCH_ITEM.player_paused then
        local player_h = S(70)
        local player_x = S(20)
        local player_y = gfx.h - player_h - S(20)
        local player_w = gfx.w - S(40)
        
        if gfx.mouse_x >= player_x and gfx.mouse_x <= player_x + player_w and 
           gfx.mouse_y >= player_y and gfx.mouse_y <= player_y + player_h then
            if gfx.mouse_cap & 1 == 1 then  -- Left click
                UI_STATE.mouse_handled = true
            end
        end
    end
    
    -- Background overlay (Full Screen)
    set_color(UI.C_BG, 1.0)
    gfx.rect(0, 0, gfx.w, gfx.h, 1)
    
    local pad = S(20)
    
    -- 1. Calculate Header Height and res_y
    local th = S(30) -- Title height
    local input_h = S(32)
    local path_h = (cfg.search_item_path and cfg.search_item_path ~= "") and (S(14) + S(4)) or 0
    local header_h = pad + th + S(15) + input_h + S(4) + path_h + S(10)
    
    local res_y = header_h
    local res_h = gfx.h - res_y - pad
    
    -- 2. Draw Background
    set_color(UI.C_BG, 1.0)
    gfx.rect(0, 0, gfx.w, gfx.h, 1)

    -- 3. Draw Results List
    if SEARCH_ITEM.results and #SEARCH_ITEM.results > 0 then
        local rect_x, rect_y, rect_w, rect_h = pad, res_y, gfx.w - pad*2, res_h
        
        -- Measure total height
        local total_h = 0
        for _, proj in ipairs(SEARCH_ITEM.results) do
            total_h = total_h + S(30) -- Project title
            for _, m in ipairs(proj.matches) do
                total_h = total_h + S(45) -- Match row
            end
            total_h = total_h + S(10) -- Padding per project
        end
        
        -- Add bottom padding if player is visible
        if SEARCH_ITEM.current_item or SEARCH_ITEM.player_paused then
            total_h = total_h + S(90)  -- Player height (70) + spacing (20)
        end
        
        local max_scroll = math.max(0, total_h - res_h)
        if gfx.mouse_x >= rect_x and gfx.mouse_x <= rect_x + rect_w and gfx.mouse_y >= rect_y and gfx.mouse_y <= rect_y + rect_h then
            if gfx.mouse_wheel ~= 0 then
                SEARCH_ITEM.target_scroll_y = math.max(0, math.min(max_scroll, SEARCH_ITEM.target_scroll_y - gfx.mouse_wheel * 0.5))
                gfx.mouse_wheel = 0
            end
        end
        SEARCH_ITEM.scroll_y = SEARCH_ITEM.scroll_y + (SEARCH_ITEM.target_scroll_y - SEARCH_ITEM.scroll_y) * 0.5
        
        -- Draw List with Clipping
        local draw_y = res_y - math.floor(SEARCH_ITEM.scroll_y)
        
        for _, proj in ipairs(SEARCH_ITEM.results) do
            if draw_y + S(30) > res_y and draw_y < res_y + res_h then
                set_color(UI.C_TXT, 0.4)
                gfx.setfont(F.std)
                gfx.x, gfx.y = rect_x, draw_y + S(5)
                gfx.drawstr(proj.project_name:upper())
            end
            draw_y = draw_y + S(30)
            
            for _, m in ipairs(proj.matches) do
                if draw_y + S(45) > res_y and draw_y < res_y + res_h then
                    local row_y = draw_y
                    -- Background for row
                    set_color(UI.C_TXT, 0.05)
                    gfx.rect(rect_x, row_y, rect_w, S(40), 1)
                    
                    -- Play button
                    local p_btn_sz = S(30)
                    local p_btn_x = rect_x + S(5)
                    local p_btn_y = row_y + S(5)
                    if btn(p_btn_x, p_btn_y, p_btn_sz, p_btn_sz, "▶", UI.C_BTN, UI.C_ORANGE) and not UI_STATE.mouse_handled then
                        if m.items and #m.items > 0 then
                            -- Inject project path into items
                            for _, it in ipairs(m.items) do
                                it.project_path = proj.project_path
                            end

                            if #m.items == 1 then
                                SEARCH_ITEM.play_item(m.items[1])
                            else
                                SEARCH_ITEM.show_item_menu(m.items)
                            end
                        else
                            show_snackbar(T("NO_ACTIVE_3"), "error")
                        end
                        UI_STATE.mouse_handled = true
                    end
                    
                    local content_start_x = p_btn_x + p_btn_sz + S(10)
                    
                    set_color(UI.C_ORANGE)
                    gfx.setfont(F.bld)
                    gfx.x, gfx.y = content_start_x, row_y + S(5)
                    local actor_name = m.actor
                    if #actor_name > 30 then 
                        -- Simple byte truncation for now as requested
                        actor_name = actor_name:sub(1, 27) .. "..." 
                    end
                    local disp_actor = actor_name .. ": "
                    gfx.drawstr(disp_actor)
                    
                    local actor_w = gfx.measurestr(disp_actor)
                    set_color(UI.C_TXT)
                    gfx.setfont(F.std)
                    local avail_tw = rect_w - (content_start_x - rect_x) - actor_w - S(10)
                    local clean_text = m.text:gsub("[\n\r]+", " ")
                    local draw_text = fit_text_width(clean_text, avail_tw)
                    gfx.drawstr(draw_text)
                    
                    set_color(UI.C_TXT, 0.5)
                    gfx.x, gfx.y = content_start_x, row_y + S(22)
                    gfx.setfont(F.tip)
                    gfx.drawstr(string.format("%.2f s", m.time / 1000))
                end
                draw_y = draw_y + S(45)
            end
            draw_y = draw_y + S(10)
        end
        
        -- Draw Scrollbar
        if max_scroll > 0 then
            local sb_w = S(6)
            local sb_x = gfx.w - pad/2 - sb_w
            local sb_track_h = res_h
            local sb_h = math.max(S(20), (res_h / total_h) * sb_track_h)
            local sb_y = res_y + (SEARCH_ITEM.scroll_y / max_scroll) * (sb_track_h - sb_h)
            set_color(UI.C_TXT, 0.1)
            gfx.rect(sb_x, res_y, sb_w, sb_track_h, 1)
            set_color(UI.C_TXT, 0.3)
            gfx.rect(sb_x, sb_y, sb_w, sb_h, 1)
        end
        
    elseif SEARCH_ITEM.loading then
        set_color(UI.C_TXT, 0.5)
        gfx.setfont(F.std)
        local s = T("SRC_IN_ALL_PROJ")
        local sw, sh = gfx.measurestr(s)
        gfx.x, gfx.y = pad + (gfx.w - pad*2 - sw)/2, res_y + (res_h - sh)/2
        gfx.drawstr(s)
    elseif SEARCH_ITEM.last_query ~= "" then
        set_color(UI.C_TXT, 0.5)
        gfx.setfont(F.std)
        local s = T("SRC_NO_FOUND")
        local sw, sh = gfx.measurestr(s)
        gfx.x, gfx.y = pad + (gfx.w - pad*2 - sw)/2, res_y + (res_h - sh)/2
        gfx.drawstr(s)
    else
        -- Initial State
        set_color(UI.C_TXT, 0.5)
        gfx.setfont(F.std)
        local s1 = T("SRC_ENTER_SF_TEXT")
        local s2 = cfg.search_item_path ~= "" and cfg.search_item_path or T("SRC_NO_F_SELECTED")
        
        local sw1, sh1 = gfx.measurestr(s1)
        local sw2, sh2 = gfx.measurestr(s2)
        
        local total_h = sh1 + sh2 + S(10)
        local start_y = res_y + (res_h - total_h)/2
        
        gfx.x, gfx.y = pad + (gfx.w - pad*2 - sw1)/2, start_y
        gfx.drawstr(s1)
        
        gfx.x, gfx.y = pad + (gfx.w - pad*2 - sw2)/2, start_y + sh1 + S(10)
        
        -- Truncate path if too long
        local avail_w = gfx.w - pad*2
        if sw2 > avail_w then
            s2 = fit_text_width(s2, avail_w)
            sw2 = gfx.measurestr(s2)
            gfx.x = pad + (gfx.w - pad*2 - sw2)/2
        end
        
        gfx.drawstr(s2)
    end

    -- 4. Draw Header Overlay (draw ON TOP of results)
    set_color(UI.C_BG, 1.0)
    gfx.rect(0, 0, gfx.w, res_y, 1) -- Opaque background to hide results behind it
    
    -- Close button (Top Right)
    local close_sz = S(24)
    local close_x, close_y = gfx.w - pad - close_sz, pad
    local function close_search()
        SEARCH_ITEM.show = false
        UI_STATE.mouse_handled = true
        SEARCH_ITEM.play_item(nil) -- Stop preview
    end
    if btn(close_x, close_y, close_sz, close_sz, "X", UI.C_BTN, UI.C_TXT) then
        close_search()
    end

    -- Title
    gfx.setfont(F.title)
    set_color(UI.C_TXT)
    local title = T("GLOBAL_SEARCH_FOR_TAKES")
    local avail_tw = close_x - pad - S(10)
    local draw_title = fit_text_width(title, avail_tw)
    gfx.x, gfx.y = pad, pad
    gfx.drawstr(draw_title)
    
    local content_y = pad + th + S(15)
    
    -- Search Input + Buttons
    local f_btn_sz = S(32)
    local s_btn_w = S(80) 
    local spacing = S(8)
    local input_w = gfx.w - pad*2 - s_btn_w - f_btn_sz - spacing*2
    
    ui_text_input("search_modal", pad, content_y, input_w, input_h, SEARCH_ITEM.input, T("SRC_ENTER_TEXT_SEARCH_WANT"), input_queue)
    
    -- Search Button next to input
    local s_btn_x = pad + input_w + spacing
    if btn(s_btn_x, content_y, s_btn_w, input_h, T("SEARCH"), UI.C_SNACK_SUCCESS, UI.C_TXT) then
        SEARCH_ITEM.perform_search()
        UI_STATE.mouse_handled = true
    end

    -- Folder Button next to search
    local f_btn_x = s_btn_x + s_btn_w + spacing
    if btn(f_btn_x, content_y, f_btn_sz, input_h, "≡", UI.C_BTN, UI.C_TXT) then
        SEARCH_ITEM.pick_folder()
        UI_STATE.mouse_handled = true
    end

    -- Tooltip for folder button
    if gfx.mouse_x >= f_btn_x and gfx.mouse_x <= f_btn_x + f_btn_sz and gfx.mouse_y >= content_y and gfx.mouse_y <= content_y + input_h then
        UI_STATE.tooltip = T("SRC_SELECT_F_FOR_S_1") .. (cfg.search_item_path or T("NOT_SELECTED"))
    end
    
    if input_queue then
        for _, char in ipairs(input_queue) do
            if char == 13 then -- Enter
                SEARCH_ITEM.perform_search()
            elseif char == 27 then -- Esc
                close_search()
            end
        end
    end
    
    -- Path info
    if cfg.search_item_path and cfg.search_item_path ~= "" then
        local path_y = content_y + input_h + S(4)
        set_color(UI.C_TXT, 0.4)
        gfx.setfont(F.tip)
        local p_text = T("SRC_FOLDER") .. cfg.search_item_path
        local avail_pw = gfx.w - pad*2
        local draw_path = fit_text_width(p_text, avail_pw)
        gfx.x, gfx.y = pad, path_y
        gfx.drawstr(draw_path)
    end
    
    SEARCH_ITEM.draw_mini_player()
end

function ACHIEVEMENTS.fetch_leaderboard(ach_id, rank_key, page)
    if ACHIEVEMENTS.loading_ach then return end
    ACHIEVEMENTS.loading_ach = ach_id
    local current_page = page or 1
    
    local source = debug.getinfo(1,'S').source
    local script_path = source:match([[^@?(.*[\\/])]]) or ""
    local full_script_path = script_path .. "stats/subass_extra_stats.py"
    
    local machine_id = reaper.GetExtState(section_name, "MachineID")
    if not machine_id or machine_id == "" then
        machine_id = reaper.genGuid("")
        machine_id = machine_id:gsub("[%{%}%-]", ""):lower()
        reaper.SetExtState(section_name, "MachineID", machine_id, true)
    end

    local cmd = string.format('python3 "%s" --get-leaderboard --ach-prefix "%s" --machine_id "%s" --page %d', 
                                full_script_path, rank_key, machine_id, current_page)
    
    if reaper.GetOS():match("Win") then
        full_script_path = full_script_path:gsub("/", "\\")
        local py_exe = UTILS.get_win_py_exe(OTHER.rec_state.python and OTHER.rec_state.python.executable or "py -3")
        cmd = string.format('%s "%s" --get-leaderboard --ach-prefix "%s" --machine_id "%s" --page %d', 
                                     py_exe, full_script_path, rank_key, machine_id, current_page)
    end

    -- id for async tracking
    local async_id = tostring(os.time()) .. "_" .. math.random(1000,9999)
    
    run_async_command(cmd, function()
        ACHIEVEMENTS.loading_ach = nil
        local leaderboard_path = script_path .. "stats/subass_leaderboard.json"
        local f = io.open(leaderboard_path, "r")
        if f then
            local content = f:read("*a")
            f:close()
            if STATS and STATS.json_decode then
                local ok, data = pcall(STATS.json_decode, content)
                if ok and type(data) == "table" and data.ok then
                    if current_page == 1 then
                        ACHIEVEMENTS.leaderboard_data = data
                        ACHIEVEMENTS.leaderboard_data.ach_name = ach_id
                        ACHIEVEMENTS.leaderboard_data.rank_key = rank_key
                        ACHIEVEMENTS.show_leaderboard = true
                        ACHIEVEMENTS.leaderboard_scroll_y = 0
                        ACHIEVEMENTS.leaderboard_target_scroll_y = 0
                    else
                        -- Append items
                        if data.leaderboard then
                            for _, item in ipairs(data.leaderboard) do
                                table.insert(ACHIEVEMENTS.leaderboard_data.leaderboard, item)
                            end
                        end
                        ACHIEVEMENTS.leaderboard_data.has_more = data.has_more
                        ACHIEVEMENTS.leaderboard_data.page = data.page
                    end
                    
                    -- Pre-calculate rows to draw (Optimization: avoid per-frame loop)
                    local lb = ACHIEVEMENTS.leaderboard_data.leaderboard or {}
                    local me = ACHIEVEMENTS.leaderboard_data.me
                    
                    local me_in_list = false
                    for _, item in ipairs(lb) do
                        if item.is_me then me_in_list = true break end
                    end
                    
                    local rows = {}
                    for _, item in ipairs(lb) do table.insert(rows, item) end
                    if me and not me_in_list then
                        table.insert(rows, { is_sep = true })
                        table.insert(rows, me)
                    end
                    ACHIEVEMENTS.leaderboard_data.rows = rows
                else
                    show_snackbar(T("ACH_ER_LOAD_L"), "error")
                end
            else
                show_snackbar(T("ACH_ER_JSON_L"), "error")
            end
            os.remove(leaderboard_path)
        else
            show_snackbar(T("ACH_ER_CON_L"), "error")
        end
    end, true, "Fetching " .. ach_id .. " leaderboard...", false)
end

function ACHIEVEMENTS.get_ach_hint(ach_id)
    local hint_key = "ACH_HINT_" .. ach_id
    return T(hint_key)
end

function ACHIEVEMENTS.draw_dialog()
    if not ACHIEVEMENTS.show_leaderboard or not ACHIEVEMENTS.leaderboard_data then return end
    
    local w, h = gfx.w, gfx.h
    local x, y = (gfx.w - w) / 2, (gfx.h - h) / 2
    local pad = S(20)
    
    -- Darken background
    set_color(UI.C_BG, 0.6)
    gfx.rect(0, 0, gfx.w, gfx.h, 1)
    
    -- Main Dialog Box
    set_color(UI.C_BG, 1.0)
    gfx.rect(x, y, w, h, 1)
    set_color(UI.C_TXT, 0.1)
    gfx.rect(x, y, w, h, 0)
    
    -- Close button size
    local close_sz = S(24)
    local content_y = y + pad + S(45)
    local row_h = S(35)
    local list_h = h - (content_y - y) - pad
    
    -- List Data
    local rows_to_draw = ACHIEVEMENTS.leaderboard_data.rows or {}
    
    local total_content_h = #rows_to_draw * row_h
    if ACHIEVEMENTS.leaderboard_data.has_more then
        total_content_h = total_content_h + row_h + S(10)
    end
    local max_scroll = math.max(0, total_content_h - list_h)
    
    if gfx.mouse_x >= x and gfx.mouse_x <= x + w and gfx.mouse_y >= content_y and gfx.mouse_y <= y + h - pad then
        if gfx.mouse_wheel ~= 0 then
            ACHIEVEMENTS.leaderboard_target_scroll_y = math.max(0, math.min(max_scroll, ACHIEVEMENTS.leaderboard_target_scroll_y - gfx.mouse_wheel * 0.5))
            gfx.mouse_wheel = 0
        end
    end
    ACHIEVEMENTS.leaderboard_scroll_y = ACHIEVEMENTS.leaderboard_scroll_y + (ACHIEVEMENTS.leaderboard_target_scroll_y - ACHIEVEMENTS.leaderboard_scroll_y) * 0.5
    
    -- DRAW CONTENT
    for i, row in ipairs(rows_to_draw) do
        local rx = x + pad
        local ry = content_y + S(5) + (i - 1) * row_h - ACHIEVEMENTS.leaderboard_scroll_y
        
        if ry + row_h > content_y and ry < content_y + list_h then
            if row.is_sep then
                set_color(UI.C_TXT, 0.1)
                gfx.line(rx, ry + row_h/2, x + w - pad, ry + row_h/2)
            else
                if row.is_me then
                    set_color(UI.C_TAB_INA, 0.5)
                    gfx.rect(x + S(5), ry, w - S(10), row_h, 1)
                end
                
                -- Full row hover & click detection
                local mx, my = gfx.mouse_x, gfx.mouse_y
                local row_hover = mx >= x + S(5) and mx <= x + w - S(5) and my >= ry and my <= ry + row_h
                
                if row_hover then
                    set_color(UI.C_TXT, 0.05)
                    gfx.rect(x + S(5), ry, w - S(10), row_h, 1)
                    UI_STATE.mouse_handled = true
                    
                    if (gfx.mouse_cap & 1 == 1) and (UI_STATE.last_mouse_cap & 1 == 0) then
                        if row.machine_id and row.machine_id ~= "" then
                            ACHIEVEMENTS.fetch_profile(row.machine_id)
                        else
                            show_snackbar(T("USER_ID_NOT_FOUND"), "error")
                        end
                    end
                end
 
                gfx.setfont(F.std)
                set_color(UI.C_TXT, (row.is_me or row_hover) and 1.0 or 0.7)
                
                local ty = ry + (row_h - S(14))/2
                
                -- Rank / Medal
                local pos = row.rank
                if pos and pos <= 9 then
                    local frame_idx = 9 - pos
                    local sw, sh = gfx.getimgdim(OTHER.ACH_PLACE_CFG.buf)
                    if sw and sw > 0 then
                        local fw = sw / 9
                        local bw, bh = S(24), S(24)
                        local bx = rx + S(1)
                        local by = ry + (row_h - bh)/2
                        gfx.mode = 0
                        gfx.set(1, 1, 1, 1)
                        gfx.blit(OTHER.ACH_PLACE_CFG.buf, 1, 0, fw * frame_idx, 0, fw, sh, bx, by, bw, bh)
                    end
                else
                    gfx.x, gfx.y = rx + S(5), ty
                    gfx.drawstr(string.format("%d.", pos or 0))
                end
                
                -- Value
                local val_str = UTILS.format_number(row.value or 0)
                local vw = gfx.measurestr(val_str)
                local val_x = x + w - pad - vw - S(10)
                
                -- Name with ellipsis
                local name_x = rx + S(40)
                local avail_name_w = val_x - name_x - S(15)
                local draw_name = fit_text_width(row.dubber_name or T("ANONYMOUS"), avail_name_w)
                
                gfx.x, gfx.y = name_x, ty
                gfx.drawstr(draw_name)
                
                set_color(UI.C_TXT, (row.is_me or row_hover) and 1.0 or 0.5)
                gfx.x, gfx.y = val_x, ty
                gfx.drawstr(val_str)
            end
        end
    end
 
    -- Load More Button
    if ACHIEVEMENTS.leaderboard_data.has_more then
        local btn_w = S(160)
        local btn_h = S(30)
        local btn_x = x + (w - btn_w) / 2
        local btn_y = content_y + S(5) + #rows_to_draw * row_h + S(5) - ACHIEVEMENTS.leaderboard_scroll_y
        
        if btn_y + btn_h > content_y and btn_y < content_y + list_h then
            if btn(btn_x, btn_y, btn_w, btn_h, T("LOAD_MORE"), UI.C_BTN, UI.C_TXT) then
                local next_page = (ACHIEVEMENTS.leaderboard_data.page or 1) + 1
                ACHIEVEMENTS.fetch_leaderboard(ACHIEVEMENTS.leaderboard_data.ach_name, ACHIEVEMENTS.leaderboard_data.rank_key, next_page)
                UI_STATE.mouse_handled = true
            end
        end
    end
 
    -- MASK TOP (Header area) - Draw this after content to cover overlap
    set_color(UI.C_BG, 1.0)
    gfx.rect(x, y, w, content_y - y, 1)
    set_color(UI.C_TXT, 0.1)
    gfx.line(x, content_y, x + w, content_y)
 
    -- Draw Title & Close Button
    gfx.setfont(F.title)
    set_color(UI.C_TXT, 1)
    local ach_name = ACHIEVEMENTS.leaderboard_data.ach_name or T("ACHIEVEMENTS_LBL")
    for _, ach in ipairs(OTHER.ACH_CFG) do
        if ach.id == ach_name then
            ach_name = T("ACH_NAME_" .. ach.id)
            break
        end
    end
    
    gfx.x, gfx.y = x + pad, y + pad - S(2)
    local draw_title = fit_text_width(string.format(T("LEADERBOARD_TITLE"), ach_name), w - pad*2 - close_sz - S(10))
    gfx.drawstr(draw_title)
    
    gfx.setfont(F.tip)
    set_color(UI.C_TXT, 0.6)
    local current_ach_id = ACHIEVEMENTS.leaderboard_data.ach_name
    local hint = ACHIEVEMENTS.get_ach_hint(current_ach_id)
    if ACHIEVEMENTS.stats[current_ach_id .. "_tracking"] ~= 1 then
        hint = T("ACH_LOCKED_HINT")
    end
    gfx.x, gfx.y = x + pad, y + pad + S(24)
    gfx.drawstr(fit_text_width(hint, w - pad*2 - close_sz - S(10)))
    
    if btn(x + w - pad - close_sz, y + pad, close_sz, close_sz, "X", UI.C_BTN, UI.C_TXT) then
        ACHIEVEMENTS.show_leaderboard = false
        UI_STATE.mouse_handled = true
    end
 
    -- Draw Border over everything
    set_color(UI.C_TXT, 0.1)
    gfx.rect(x, y, w, h, 0)
    
    if max_scroll > 0 then
        ACHIEVEMENTS.leaderboard_target_scroll_y = draw_scrollbar(x + w - S(8), content_y, S(8), list_h, total_content_h, list_h, ACHIEVEMENTS.leaderboard_target_scroll_y)
    end
    
    UI_STATE.mouse_handled = true
end

function ACHIEVEMENTS.open_edit_profile()
    UI_STATE.show_edit_profile = true
    -- Helper for initialization (temporary local copy until refactored globally)
    local function s2t(str)
        local t = {}
        if str then for i in str:gmatch("[^,]+") do 
            local tr = i:match("^%s*(.-)%s*$")
            if tr ~= "" then t[tr:sub(1,1):upper() .. tr:sub(2):lower()] = true end
        end end
        return t
    end
    OTHER.profile_state = {
        name = { text = cfg.dubber_name or "", cursor = 0, anchor = 0, focus = false },
        specialization = s2t(cfg.dubber_specialization),
        bio = { text = cfg.dubber_bio or "", cursor = 0, anchor = 0, focus = false },
        contact = { text = cfg.dubber_contact or "", cursor = 0, anchor = 0, focus = false },
        samples = { text = cfg.dubber_samples or "", cursor = 0, anchor = 0, focus = false },
        equipment = { text = cfg.dubber_equipment or "", cursor = 0, anchor = 0, focus = false },
        conditions = cfg.dubber_conditions,
        voice = cfg.dubber_voice,
        timbre = s2t(cfg.dubber_timbre),
        archetypes = s2t(cfg.dubber_archetypes),
        languages = s2t(cfg.dubber_languages),
        vocals = cfg.dubber_vocals,
        status = cfg.dubber_status or "Звичайний аккаунт",
        scroll_y = 0,
        target_scroll_y = 0
    }
end

function ACHIEVEMENTS.draw_window(input_queue)
    if not ACHIEVEMENTS.show then return end

    if ACHIEVEMENTS.has_new then
        ACHIEVEMENTS.has_new = false
        reaper.SetExtState(section_ach_name, "has_new", "0", true)
    end

    ACHIEVEMENTS.load_assets()
    ACHIEVEMENTS.sync_stats()
    
    local pad = S(20)
    local th = S(30) -- Title height
    local content_y = pad + th + S(15)
    
    -- Background overlay (Full Screen)
    set_color(UI.C_BG, 1.0)
    gfx.rect(0, 0, gfx.w, gfx.h, 1)
    
    -- Draw Achievements Grid
    local item_sz = S(180)
    local spacing = S(16)
    local res_h = gfx.h - content_y - pad
    local avail_w = gfx.w - pad * 2
    local cols = math.max(1, math.floor((avail_w + spacing) / (item_sz + spacing)))
    
    local rows = math.ceil(#OTHER.ACH_CFG / cols)
    local total_h = rows * (item_sz + spacing) - spacing + S(10)
    local max_scroll = math.max(0, total_h - res_h)
    
    if not ACHIEVEMENTS.show_leaderboard and gfx.mouse_x >= pad and gfx.mouse_x <= gfx.w - pad and gfx.mouse_y >= content_y and gfx.mouse_y <= gfx.h - pad then
        if gfx.mouse_wheel ~= 0 then
            ACHIEVEMENTS.target_scroll_y = math.max(0, math.min(max_scroll, ACHIEVEMENTS.target_scroll_y - gfx.mouse_wheel * 0.5))
            gfx.mouse_wheel = 0
        end

        -- Right click context menu
        if is_right_mouse_clicked() then
            gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
            local ret = gfx.showmenu(T("REFRESH_DATA"))
            if ret == 1 then
                STATS.register_plugin_usage()
                show_snackbar(T("UPDATING_DATA_ELLIPSIS"))
            end
            UI_STATE.mouse_handled = true
        end
    end
    ACHIEVEMENTS.scroll_y = ACHIEVEMENTS.scroll_y + (ACHIEVEMENTS.target_scroll_y - ACHIEVEMENTS.scroll_y) * 0.5
    
    local open_count = 0
    for _, ach in ipairs(OTHER.ACH_CFG) do
        if ACHIEVEMENTS.stats[ach.id .. "_tracking"] == 1 then
            open_count = open_count + 1
        end
    end

    for i, ach in ipairs(OTHER.ACH_CFG) do
        local col = (i - 1) % cols
        local row = math.floor((i - 1) / cols)
        
        local cx = pad + col * (item_sz + spacing)
        local cy = content_y + S(10) + row * (item_sz + spacing) - math.floor(ACHIEVEMENTS.scroll_y)
        
        if cy + item_sz > content_y and cy < content_y + res_h then
            -- Draw Background
            set_color(UI.C_TAB_INA, 0.3)
            gfx.rect(cx, cy, item_sz, item_sz, 1)
            -- Placeholder Border
            set_color(UI.C_TXTINA, 0.2)
            gfx.rect(cx, cy, item_sz, item_sz, 0)

            -- Progress Counter (Top Left)
            local total = 0
            if ach.id == "ach_1" then
                total = ACHIEVEMENTS.stats["ach_1_total_lines"] or 0
            elseif ach.id == "ach_3" then
                total = (ACHIEVEMENTS.stats["ach_3_definition"] or 0) + 
                        (ACHIEVEMENTS.stats["ach_3_conjugation"] or 0) + 
                        (ACHIEVEMENTS.stats["ach_3_synonyms"] or 0) +
                        (ACHIEVEMENTS.stats["ach_3_idioms"] or 0) +
                        (ACHIEVEMENTS.stats["ach_3_word_usage"] or 0)
            elseif ach.id == "ach_4" then
                for _, task in ipairs(OTHER.AI_TASKS) do
                    total = total + (ACHIEVEMENTS.stats["ach_4_" .. task.id .. "_count"] or 0)
                end
            elseif ach.id == "ach_7" then
                total = ACHIEVEMENTS.stats["ach_7_itachi_uchiha"] or 0
            elseif ach.id == "ach_2" then
                total = ACHIEVEMENTS.stats["ach_2_total_lines"] or 0
            elseif ach.id == "ach_8" then
                total = ACHIEVEMENTS.stats["ach_8_corr_item_count"] or 0
            elseif ach.id == "ach_6" then
                total = ACHIEVEMENTS.stats["ach_6_failed_count"] or 0
            elseif ach.id == "ach_5" then
                total = ACHIEVEMENTS.stats["ach_5_corr_item_count"] or 0
            elseif ach.id == "ach_29" then
                total = ACHIEVEMENTS.stats["ach_29_import_count"] or 0
            else
                -- Standard count mapping for ach_10, ach_11, ach_12, ach_13, ach_14, ach_18, etc.
                total = ACHIEVEMENTS.stats[ach.id .. "_count"] or 0
            end

            if total > 0 then
                gfx.setfont(F.bld)
                set_color(UI.C_TXT, 0.5)
                gfx.x, gfx.y = cx + S(6), cy + S(4)
                gfx.drawstr(UTILS.format_number(total))
            end
            
            -- Image
            local iw, ih = gfx.getimgdim(ach.buf)
            local is_unlocked = ACHIEVEMENTS.stats[ach.id .. "_tracking"] == 1 and total > 0
            
            if iw and iw > 0 and ih > 0 then
                local max_img_w = item_sz - S(20)
                local max_img_h = item_sz - S(40)
                local scale = math.min(max_img_w / iw, max_img_h / ih)
                local dw, dh = iw * scale, ih * scale
                local dx = cx + (item_sz - dw) / 2
                local dy = cy + (item_sz - S(20) - dh) / 2 + S(5)
                
                -- Image drawing with Locked/Unlocked state
                gfx.mode = 0
                if is_unlocked then
                    gfx.set(1, 1, 1, 1.0)
                    gfx.blit(ach.buf, 1, 0, 0, 0, iw, ih, dx, dy, dw, dh)
                else
                    gfx.set(1, 1, 1, 0.3) -- Add a bit of transparency for locked icons
                    -- Use the pre-rendered disabled image from the configuration
                    gfx.blit(ach.dis_buf, 1, 0, 0, 0, iw, ih, dx, dy, dw, dh)
                end
            end
            
            -- Name Label
            gfx.setfont(F.std)
            set_color(is_unlocked and UI.C_TXT or UI.C_MEDIUM_GREY)
            local draw_name = fit_text_width(T("ACH_NAME_" .. ach.id), item_sz - S(10))
            local tw, th_meas = gfx.measurestr(draw_name)
            gfx.x = cx + (item_sz - tw) / 2
            gfx.y = cy + item_sz - th_meas - S(10)
            gfx.drawstr(draw_name)

            local rank_key = ach.id .. "_count"
            if ach.id == "ach_1" then rank_key = "ach_1_total_lines"
            elseif ach.id == "ach_2" then rank_key = "ach_2_total_lines"
            elseif ach.id == "ach_5" then rank_key = "ach_5_corr_item_count"
            elseif ach.id == "ach_6" then rank_key = "ach_6_failed_count"
            elseif ach.id == "ach_7" then rank_key = "ach_7_itachi_uchiha"
            elseif ach.id == "ach_8" then rank_key = "ach_8_corr_item_count"
            elseif ach.id == "ach_29" then rank_key = "ach_29_import_count"
            end

            local r_data = ACHIEVEMENTS.rankings and ACHIEVEMENTS.rankings[rank_key]

            -- Interaction & Tooltips
            if not ACHIEVEMENTS.show_leaderboard and gfx.mouse_x >= cx and gfx.mouse_x <= cx + item_sz and
               gfx.mouse_y >= cy and gfx.mouse_y <= cy + item_sz then
                
                -- CLICK TO FETCH LEADERBOARD
                if is_mouse_clicked(1) then
                    -- For achievements with sub-keys (ach_3, ach_4), fetch using base prefix
                    local fetch_prefix = rank_key
                    if ach.id == "ach_3" or ach.id == "ach_4" then
                        fetch_prefix = ach.id
                    end
                    ACHIEVEMENTS.fetch_leaderboard(ach.id, fetch_prefix)
                end

                local tooltip_text = ""
                if is_unlocked then
                    if ach.id == "ach_1" then
                        local srt = ACHIEVEMENTS.stats["ach_1_srt_import"] or 0
                        local ass = ACHIEVEMENTS.stats["ach_1_ass_import"] or 0
                        local vtt = ACHIEVEMENTS.stats["ach_1_vtt_import"] or 0
                        local total = ACHIEVEMENTS.stats["ach_1_total_lines"] or 0
                        
                        tooltip_text = string.format(T("ACH_TIP_1"), 
                            UTILS.format_number(srt), UTILS.format_number(ass), UTILS.format_number(vtt), string.rep("—", 12), UTILS.format_number(total))
                    elseif ach.id == "ach_3" then
                        local def = ACHIEVEMENTS.stats["ach_3_definition"] or 0
                        local conj = ACHIEVEMENTS.stats["ach_3_conjugation"] or 0
                        local syn = ACHIEVEMENTS.stats["ach_3_synonyms"] or 0
                        local idiom = ACHIEVEMENTS.stats["ach_3_idioms"] or 0
                        local usage = ACHIEVEMENTS.stats["ach_3_word_usage"] or 0
                        
                        tooltip_text = string.format(T("ACH_TIP_3"), 
                            string.rep("—", 12), UTILS.format_number(def), UTILS.format_number(conj), UTILS.format_number(syn), UTILS.format_number(idiom), UTILS.format_number(usage))
                    elseif ach.id == "ach_7" then
                        local total = ACHIEVEMENTS.stats["ach_7_itachi_uchiha"] or 0
                        tooltip_text = string.format(T("ACH_TIP_7"), 
                            string.rep("—", 12), UTILS.format_number(total))
                    elseif ach.id == "ach_2" then
                        local total = ACHIEVEMENTS.stats["ach_2_total_lines"] or 0
                        local runs = ACHIEVEMENTS.stats["ach_2_run_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_2"), 
                            UTILS.format_number(runs), UTILS.format_number(total), string.rep("—", 12))
                    elseif ach.id == "ach_8" then
                        local export = ACHIEVEMENTS.stats["ach_8_export_count"] or 0
                        local items = ACHIEVEMENTS.stats["ach_8_corr_item_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_8"), 
                            UTILS.format_number(export), UTILS.format_number(items), string.rep("—", 12))
                    elseif ach.id == "ach_6" then
                        local total = ACHIEVEMENTS.stats["ach_6_failed_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_6"), 
                            UTILS.format_number(total), string.rep("—", 12))
                    elseif ach.id == "ach_4" then
                        local parts = { T("ACH_TIP_4_HEADER") .. string.rep("—", 12) }
                        
                        -- Dynamically build tooltip from OTHER.AI_TASKS
                        for _, task in ipairs(OTHER.AI_TASKS) do
                            local stat_key = "ach_4_" .. task.id .. "_count"
                            local val = ACHIEVEMENTS.stats[stat_key] or 0
                            if val > 0 then
                                local translated_name = T("AI_TASK_" .. task.id)
                                if translated_name == "AI_TASK_" .. task.id then
                                    translated_name = task.name
                                end
                                table.insert(parts, string.format("%s: %s", translated_name, UTILS.format_number(val)))
                            end
                        end
                        
                        if #parts == 1 then
                            tooltip_text = T("ACH_TIP_4_NONE")
                        else
                            tooltip_text = table.concat(parts, "\n")
                        end
                    elseif ach.id == "ach_5" then
                        local imports = ACHIEVEMENTS.stats["ach_5_import_count"] or 0
                        local items = ACHIEVEMENTS.stats["ach_5_corr_item_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_5"), 
                            UTILS.format_number(imports), UTILS.format_number(items), string.rep("—", 12))
                    elseif ach.id == "ach_11" then
                        local total = ACHIEVEMENTS.stats["ach_11_count"] or 0
                        local words = ACHIEVEMENTS.stats["ach_11_word_count"] or 0
                        local duration = ACHIEVEMENTS.stats["ach_11_total_duration"] or 0
                        tooltip_text = string.format(T("ACH_TIP_11"), 
                            UTILS.format_number(total), UTILS.format_number(words), ACHIEVEMENTS.format_long_duration(duration), string.rep("—", 12))
                    elseif ach.id == "ach_10" then
                        local total = ACHIEVEMENTS.stats["ach_10_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_10"), 
                            UTILS.format_number(total), string.rep("—", 12))
                    elseif ach.id == "ach_14" then
                        local total = ACHIEVEMENTS.stats["ach_14_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_14"), 
                            UTILS.format_number(total), string.rep("—", 12))
                    elseif ach.id == "ach_15" then
                        local total = ACHIEVEMENTS.stats["ach_15_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_15"), 
                            UTILS.format_number(total), string.rep("—", 12))
                    elseif ach.id == "ach_12" then
                        local total = ACHIEVEMENTS.stats["ach_12_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_12"), 
                            UTILS.format_number(total), string.rep("—", 12))
                    elseif ach.id == "ach_9" then
                        local total = ACHIEVEMENTS.stats["ach_9_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_9"), 
                            UTILS.format_number(total), string.rep("—", 12))
                    elseif ach.id == "ach_13" then
                        local total = ACHIEVEMENTS.stats["ach_13_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_13"), 
                            UTILS.format_number(total), string.rep("—", 12))
                    elseif ach.id == "ach_18" then
                        local total = ACHIEVEMENTS.stats["ach_18_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_18"), 
                            UTILS.format_number(total), string.rep("—", 12))
                    elseif ach.id == "ach_16" then
                        local total = ACHIEVEMENTS.stats["ach_16_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_16"), 
                            UTILS.format_number(total), string.rep("—", 12))
                    elseif ach.id == "ach_17" then
                        local total = ACHIEVEMENTS.stats["ach_17_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_17"), 
                            UTILS.format_number(total), string.rep("—", 12))
                    elseif ach.id == "ach_19" then
                        local total = ACHIEVEMENTS.stats["ach_19_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_19"), 
                            UTILS.format_number(total), string.rep("—", 12))
                    elseif ach.id == "ach_20" then
                        local total = ACHIEVEMENTS.stats["ach_20_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_20"), 
                            UTILS.format_number(total), string.rep("—", 12))
                    elseif ach.id == "ach_21" then
                        local total = ACHIEVEMENTS.stats["ach_21_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_21"), 
                            UTILS.format_number(total), string.rep("—", 12))
                    elseif ach.id == "ach_22" then
                        local total = ACHIEVEMENTS.stats["ach_22_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_22"), 
                            UTILS.format_number(total), string.rep("—", 12))
                    elseif ach.id == "ach_23" then
                        local total = ACHIEVEMENTS.stats["ach_23_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_23"), 
                            UTILS.format_number(total), string.rep("—", 12))
                    elseif ach.id == "ach_24" then
                        local total = ACHIEVEMENTS.stats["ach_24_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_24"), 
                            UTILS.format_number(total), string.rep("—", 12))
                    elseif ach.id == "ach_25" then
                        local total = ACHIEVEMENTS.stats["ach_25_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_25"), 
                            UTILS.format_number(total), string.rep("—", 12))
                    elseif ach.id == "ach_26" then
                        local total = ACHIEVEMENTS.stats["ach_26_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_26"), 
                            UTILS.format_number(total), string.rep("—", 12))
                    elseif ach.id == "ach_27" then
                        local total = ACHIEVEMENTS.stats["ach_27_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_27"), 
                            UTILS.format_number(total), string.rep("—", 12))
                    elseif ach.id == "ach_28" then
                        local total = ACHIEVEMENTS.stats["ach_28_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_28"), 
                            UTILS.format_number(total), string.rep("—", 12))
                    elseif ach.id == "ach_29" then
                        local total = ACHIEVEMENTS.stats["ach_29_count"] or 0
                        local import_count = ACHIEVEMENTS.stats["ach_29_import_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_29"), 
                            UTILS.format_number(total), UTILS.format_number(import_count), string.rep("—", 12))
                    elseif ach.id == "ach_30" then
                        local total = ACHIEVEMENTS.stats["ach_30_count"] or 0
                        tooltip_text = string.format(T("ACH_TIP_30"), 
                            UTILS.format_number(total), string.rep("—", 12))
                    else
                        tooltip_text = T("ACH_NAME_" .. ach.id)
                    end
                else
                    tooltip_text = string.format(T("ACH_NOT_UNLOCKED"), T("ACH_NAME_" .. ach.id))
                end

                if tooltip_text ~= "" then
                    -- Check if we should override with Ranking Tooltip
                    local show_rank_tooltip = false
                    local r_tooltip = ""
                    local bx, by = cx + item_sz - S(32), cy + S(2)
                    local bw, bh = S(32), S(32)

                    if r_data and (r_data.position or r_data.unlocked_by) then
                        if r_data.position and r_data.position > 9 then
                            gfx.setfont(F.std)
                            local pw, ph = gfx.measurestr("#" .. tostring(r_data.position))
                            bw, bh = pw + S(10), ph + S(10)
                            bx = cx + item_sz - bw
                        end
                        if gfx.mouse_x >= bx and gfx.mouse_x <= cx + item_sz and
                           gfx.mouse_y >= cy and gfx.mouse_y <= cy + bh then
                            show_rank_tooltip = true
                            if r_data.position then
                                r_tooltip = string.format(T("ACH_RANK_MY_POSITION"), UTILS.format_number(r_data.position), UTILS.format_number(r_data.total_competitors or 0))
                            elseif r_data.unlocked_by then
                                r_tooltip = string.format(T("ACH_RANK_POPULARITY"), UTILS.format_number(r_data.unlocked_by))
                            end
                        end
                    end

                    if show_rank_tooltip and r_tooltip ~= "" then
                        UI_STATE.tooltip_state.text = r_tooltip
                        if UI_STATE.tooltip_state.hover_id ~= "ach_rank_" .. i then
                            UI_STATE.tooltip_state.hover_id = "ach_rank_" .. i
                            UI_STATE.tooltip_state.start_time = reaper.time_precise()
                        end
                    else
                        UI_STATE.tooltip_state.text = tooltip_text
                        if UI_STATE.tooltip_state.hover_id ~= "ach_" .. i then
                            UI_STATE.tooltip_state.hover_id = "ach_" .. i
                            UI_STATE.tooltip_state.start_time = reaper.time_precise()
                        end
                    end
                end
            end

            -- LOADING INDICATOR
            if ACHIEVEMENTS.loading_ach == ach.id then
                set_color(UI.C_BG, 0.7)
                gfx.rect(cx, cy, item_sz, item_sz, 1)
                set_color(UI.C_TXT, 1)
                gfx.setfont(F.bld)
                local lw, lh = gfx.measurestr(T("LOADING_ELLIPSIS"))
                gfx.x, gfx.y = cx + (item_sz - lw) / 2, cy + (item_sz - lh) / 2
                gfx.drawstr(T("LOADING_ELLIPSIS"))
            end

            -- Draw Ranking Badge (Top Right)
            if r_data and (r_data.position or r_data.unlocked_by) then
                local bx, by = cx + item_sz - S(32), cy + S(2)
                local bw, bh = S(24), S(24)
                
                if r_data.position then
                    local pos = r_data.position
                    if pos <= 9 then
                        local frame_idx = 9 - pos
                        local sw, sh = gfx.getimgdim(OTHER.ACH_PLACE_CFG.buf)
                        if sw and sw > 0 then
                            local fw = sw / 9
                            gfx.mode = 0
                            gfx.set(1, 1, 1, 1)
                            gfx.blit(OTHER.ACH_PLACE_CFG.buf, 1, 0, fw * frame_idx, 0, fw, sh, bx, by, bw, bh)
                        end
                    else
                        gfx.setfont(F.std)
                        local p_str = "#" .. tostring(pos)
                        local pw, ph = gfx.measurestr(p_str)
                        bw, bh = pw + S(4), ph
                        bx = cx + item_sz - bw - S(6)
                        set_color(UI.C_TXT, 0.4)
                        gfx.x, gfx.y = bx, by
                        gfx.drawstr(p_str)
                    end
                elseif r_data.unlocked_by then
                    gfx.setfont(F.std)
                    local p_str = tostring(r_data.unlocked_by)
                    local pw, ph = gfx.measurestr(p_str)
                    bw, bh = pw + S(4), ph
                    bx = cx + item_sz - bw - S(6)
                    set_color(UI.C_TXT, 0.4)
                    gfx.x, gfx.y = bx, by
                    gfx.drawstr(p_str)
                end
            end
        end
    end
    
    -- Draw scrollbar
    if max_scroll > 0 then
        ACHIEVEMENTS.target_scroll_y = draw_scrollbar(gfx.w - S(10), content_y, S(10), res_h, total_h, res_h, ACHIEVEMENTS.target_scroll_y)
    end

    -- Draw Header Overlay (draw ON TOP of grid items when scrolling)
    set_color(UI.C_BG, 1.0)
    gfx.rect(0, 0, gfx.w, content_y, 1)
    set_color(UI.C_TXT, 0.1)
    gfx.line(0, content_y, gfx.w, content_y)

    -- Close button (Top Right)
    local close_sz = S(24)
    local close_x, close_y = gfx.w - pad - close_sz, pad
    local function close_achievements()
        ACHIEVEMENTS.show = false
        UI_STATE.mouse_handled = true
    end
    if btn(close_x, close_y, close_sz, close_sz, "X", UI.C_BTN, UI.C_TXT) and not ACHIEVEMENTS.show_leaderboard then
        close_achievements()
    end
    
    -- Title (Two-line personalized header)
    local display_name = (cfg.dubber_name and cfg.dubber_name ~= "") and cfg.dubber_name or (os.getenv("USER") or os.getenv("USERNAME") or T("USER"))
    local avail_tw = close_x - pad - S(30) -- Adjusted for edit button

    -- Edit Name Button
    local edit_w = cfg.lng == "ua" and S(145) or S(90)
    local edit_h = S(24)
    local edit_x = close_x - edit_w - S(8)
    if btn(edit_x, pad, edit_w, edit_h, T("EDIT_PROFILE_TITLE"), UI.C_BTN, UI.C_TXT) and not ACHIEVEMENTS.show_leaderboard then
        ACHIEVEMENTS.open_edit_profile()
        UI_STATE.mouse_handled = true
    end

    -- Line 1: User Name
    gfx.setfont(F.title)
    set_color(UI.C_TXT)
    gfx.x, gfx.y = pad, pad - S(2)
    local name_title = fit_text_width(string.format(T("ACH_HALL_OF_FAME"), display_name), edit_x - pad - S(5))
    gfx.drawstr(name_title)
    
    -- Line 2: Progress Status
    gfx.setfont(F.tip)
    set_color(UI.C_TXT, 0.6)
    gfx.x, gfx.y = pad, pad + S(24)
    local pct = math.floor(tonumber(ACHIEVEMENTS.rankings and ACHIEVEMENTS.rankings["overall_percentile"]) or 0)
    local progress_text = string.format(T("ACH_PROGRESS_TEXT"), open_count, #OTHER.ACH_CFG, pct)
    gfx.drawstr(fit_text_width(progress_text, edit_x - pad - S(5)))

    -- Handle Esc key
    if input_queue then
        for i = #input_queue, 1, -1 do
            local char = input_queue[i]
            if char == 27 then -- Esc
                if ACHIEVEMENTS.show_leaderboard then
                    ACHIEVEMENTS.show_leaderboard = false
                else
                    close_achievements()
                end
                table.remove(input_queue, i)
            end
        end
    end

    -- DRAW LEADERBOARD DIALOG ON TOP
    ACHIEVEMENTS.draw_dialog()
end

--- Draw user profile editor modal (Full Screen ACHIEVEMENTS style)
--- @param input_queue table List of key inputs
function DRAW_WINDOW.draw_edit_profile(input_queue)
    if not UI_STATE.show_edit_profile then return end
    if not OTHER.profile_state then return end

    local function str_to_table(str)
        local t = {}
        if str then 
            for item in str:gmatch("[^,]+") do 
                local trimmed = item:match("^%s*(.-)%s*$")
                if trimmed ~= "" then
                    -- Store with first letter capitalized to match UI options
                    local formatted = trimmed:sub(1,1):upper() .. trimmed:sub(2):lower()
                    t[formatted] = true 
                end
            end 
        end
        return t
    end

    local function t_to_str(t, options)
        local items = {}
        if not t then return "" end
        for _, opt in ipairs(options) do
            if t[opt] then table.insert(items, opt) end
        end
        return table.concat(items, ", ")
    end

    local state = OTHER.profile_state
    local pad = S(20)
    local header_h = S(65)
    local footer_h = S(55)
    
    -- Background overlay (Full Screen)
    set_color(UI.C_BG, 1.0)
    gfx.rect(0, 0, gfx.w, gfx.h, 1)

    -- SCROLLABLE CONTENT AREA
    local content_y = header_h
    local content_h = gfx.h - header_h - footer_h
    local total_content_h = state.last_content_h or S(700)
    local max_scroll = math.max(0, total_content_h - content_h)

    -- Handle mouse wheel
    if gfx.mouse_x >= 0 and gfx.mouse_x <= gfx.w and gfx.mouse_y >= content_y and gfx.mouse_y <= content_y + content_h then
        if gfx.mouse_wheel ~= 0 then
            state.target_scroll_y = math.max(0, math.min(max_scroll, state.target_scroll_y - gfx.mouse_wheel * 0.5))
            gfx.mouse_wheel = 0
        end
    end
    state.scroll_y = state.scroll_y + (state.target_scroll_y - state.scroll_y) * 0.5

    local cy = content_y + S(20) - state.scroll_y
    local is_narrow = gfx.w < S(450)
    local label_w = is_narrow and 0 or S(120)
    local input_w = gfx.w - pad * 2 - label_w
    local input_h = S(30)
    local spacing = S(20)

    local function draw_row(label, state_key, h, is_multi, placeholder, max_len)
        local row_h = h
        if is_narrow then
            row_h = h + S(20) -- Extra space for label on top
        end

        if cy + row_h > content_y and cy < content_y + content_h then
            gfx.setfont(F.std)
            set_color(UI.C_TXT, 0.7)
            
            local ix, iy, iw = pad + label_w, cy, input_w
            if is_narrow then
                gfx.x, gfx.y = pad, cy
                gfx.drawstr(label)
                iy = cy + S(20)
            else
                gfx.x, gfx.y = pad, cy + (is_multi and 0 or (h - gfx.texth) / 2)
                gfx.drawstr(label)
            end
            
            ui_text_input("profile_" .. state_key, ix, iy, iw, h, state[state_key], placeholder or "", input_queue, is_multi, nil, nil, max_len)
        end
        cy = cy + row_h + spacing
    end

    local function draw_radio(label, state_key, options, tooltips, c_rw)
        local start_cy = cy
        local ry = cy
        if is_narrow then
            ry = cy + S(20)
        end

        -- Pre-calculate height
        local temp_cy = ry
        local temp_rx = pad + label_w
        local rw = c_rw or S(100)
        for i, opt in ipairs(options) do
            if temp_rx + rw > gfx.w - pad then
                temp_rx = pad + label_w
                temp_cy = temp_cy + input_h + S(5)
            end
            temp_rx = temp_rx + rw + S(5)
        end
        local section_h = temp_cy - start_cy + input_h

        if cy + section_h > content_y and cy < content_y + content_h then
            gfx.setfont(F.std)
            set_color(UI.C_TXT, 0.7)
            
            if is_narrow then
                gfx.x, gfx.y = pad, cy
                gfx.drawstr(label)
            else
                gfx.x, gfx.y = pad, cy + (input_h - gfx.texth) / 2
                gfx.drawstr(label)
            end
            
            local rx = pad + label_w
            local ry = is_narrow and cy + S(20) or cy
            
            for i, opt in ipairs(options) do
                if rx + rw > gfx.w - pad then
                    rx = pad + label_w
                    ry = ry + input_h + S(5)
                end

                local is_sel = state[state_key] == opt
                local bg = is_sel and UI.C_ACCENT_G or UI.C_BTN
                local txt = is_sel and UI.C_BG or UI.C_TXT
                
                local hover = (gfx.mouse_x >= rx and gfx.mouse_x <= rx + rw and gfx.mouse_y >= ry and gfx.mouse_y <= ry + input_h)
                if hover and tooltips and tooltips[i] then
                    local tip_id = "profile_radio_" .. state_key .. "_" .. i
                    if UI_STATE.tooltip_state.hover_id ~= tip_id then
                        UI_STATE.tooltip_state.hover_id = tip_id
                        UI_STATE.tooltip_state.start_time = reaper.time_precise()
                    end
                    UI_STATE.tooltip_state.text = tooltips[i]
                end

                local display_opt = PROFILE_META.translate_opt(state_key, opt)
                if btn(rx, ry, rw, input_h, display_opt, bg, txt, false, content_y, content_y + content_h) then
                    state[state_key] = opt
                end
                rx = rx + rw + S(5)
            end
        end
        cy = start_cy + section_h + spacing
    end

    local function draw_multi_select(label, state_key, options, tooltips)
        local start_cy = cy
        local ry = cy
        if is_narrow then
            ry = cy + S(20)
        end

        -- Pre-calculate height even if not drawing
        local temp_cy = ry
        local temp_rx = pad + label_w
        local rw = S(110)
        for i, opt in ipairs(options) do
            if temp_rx + rw > gfx.w - pad then
                temp_rx = pad + label_w
                temp_cy = temp_cy + input_h + S(5)
            end
            temp_rx = temp_rx + rw + S(5)
        end
        local section_h = temp_cy - start_cy + input_h

        if cy + section_h > content_y and cy < content_y + content_h then
            gfx.setfont(F.std)
            set_color(UI.C_TXT, 0.7)
            
            if is_narrow then
                gfx.x, gfx.y = pad, cy
                gfx.drawstr(label)
            else
                gfx.x, gfx.y = pad, cy + (input_h - gfx.texth) / 2
                gfx.drawstr(label)
            end
            
            local rx = pad + label_w
            local ry = is_narrow and cy + S(20) or cy
            
            for i, opt in ipairs(options) do
                if rx + rw > gfx.w - pad then
                    rx = pad + label_w
                    ry = ry + input_h + S(5)
                end

                local is_sel = state[state_key] and state[state_key][opt]
                local bg = is_sel and UI.C_ACCENT_G or UI.C_BTN
                local txt = is_sel and UI.C_BG or UI.C_TXT
                
                local hover = (gfx.mouse_x >= rx and gfx.mouse_x <= rx + rw and gfx.mouse_y >= ry and gfx.mouse_y <= ry + input_h)
                if hover and tooltips and tooltips[i] then
                    local tip_id = "profile_multi_" .. state_key .. "_" .. i
                    if UI_STATE.tooltip_state.hover_id ~= tip_id then
                        UI_STATE.tooltip_state.hover_id = tip_id
                        UI_STATE.tooltip_state.start_time = reaper.time_precise()
                    end
                    UI_STATE.tooltip_state.text = tooltips[i]
                end

                local display_opt = PROFILE_META.translate_opt(state_key, opt)
                if btn(rx, ry, rw, input_h, display_opt, bg, txt, false, content_y, content_y + content_h) then
                    state[state_key] = state[state_key] or {}
                    state[state_key][opt] = not state[state_key][opt]
                end
                rx = rx + rw + S(5)
            end
        end
        cy = start_cy + section_h + spacing
    end

    draw_row(T("PROFILE_NAME"), "name", input_h, false, T("PLACEHOLDER_NAME"), 40)
    draw_row(T("PROFILE_BIO"), "bio", S(100), true, T("PLACEHOLDER_BIO"), 1000)
    draw_row(T("PROFILE_CONTACT"), "contact", input_h, false, T("PLACEHOLDER_CONTACT"), 1000)
    draw_row(T("PROFILE_SAMPLES"), "samples", input_h, false, T("PLACEHOLDER_SAMPLES"), 1000)
    draw_row(T("PROFILE_EQUIPMENT"), "equipment", input_h, false, T("PLACEHOLDER_EQUIPMENT"), 1000)
    draw_multi_select(T("TF_SPECIALIZATION") .. ":", "specialization", PROFILE_META.SPECIALIZATION.opts, PROFILE_META.get_tips("SPECIALIZATION"))
    draw_multi_select(T("TF_ROLE") .. ":", "archetypes", PROFILE_META.ARCHETYPES.opts, PROFILE_META.get_tips("ARCHETYPES"))

    draw_radio(T("TF_RECORD_ENV") .. ":", "conditions", PROFILE_META.CONDITIONS.opts, PROFILE_META.get_tips("CONDITIONS"))
    draw_radio(T("TF_VOICE") .. ":", "voice", PROFILE_META.VOICE.opts, PROFILE_META.get_tips("VOICE"))
    draw_multi_select(T("TF_TIMBRE") .. ":", "timbre", PROFILE_META.TIMBRE.opts, PROFILE_META.get_tips("TIMBRE"))
    draw_radio(T("TF_VOCALS") .. ":", "vocals", PROFILE_META.VOCALS.opts, PROFILE_META.get_tips("VOCALS"), S(150))

    draw_multi_select(T("TF_LANGUAGES") .. ":", "languages", PROFILE_META.LANGUAGES.opts)

    -- Store dynamic height for next frame
    state.last_content_h = (cy + state.scroll_y) - content_y + S(20)

    -- Draw scrollbar
    if max_scroll > 0 then
        state.target_scroll_y = draw_scrollbar(gfx.w - S(10), content_y, S(10), content_h, total_content_h, content_h, state.target_scroll_y)
    end

    -- HEADER (Draw over content)
    set_color(UI.C_BG, 1.0)
    gfx.rect(0, 0, gfx.w, header_h, 1)
    set_color(UI.C_TXT, 0.1)
    gfx.line(0, content_y, gfx.w, content_y)
    
    -- Header Title (Left)
    gfx.setfont(F.title)
    set_color(UI.C_TXT)
    gfx.x, gfx.y = pad, pad - S(2)
    local close_sz = S(24)
    local draw_title = fit_text_width(T("EDIT_PROFILE_TITLE"), gfx.w - pad * 2 - close_sz - S(20))
    gfx.drawstr(draw_title)
    
    -- Close button (Right)
    if btn(gfx.w - pad - close_sz, pad, close_sz, close_sz, "X", UI.C_BTN, UI.C_TXT) then
        UI_STATE.show_edit_profile = false
        OTHER.profile_state = nil
    end

    -- FOOTER (Draw over content)
    set_color(UI.C_BG, 1.0)
    gfx.rect(0, gfx.h - footer_h, gfx.w, footer_h, 1)
    set_color(UI.C_FR_BORDER, 0.3)
    gfx.line(0, gfx.h - footer_h, gfx.w, gfx.h - footer_h)

    -- Check for changes and validation
    local name_trimmed = state.name.text:match("^%s*(.-)%s*$") or ""
    local is_name_valid = name_trimmed ~= ""
    local spec_str = t_to_str(state.specialization, PROFILE_META.SPECIALIZATION.opts)
    local timbre_str = t_to_str(state.timbre, PROFILE_META.TIMBRE.opts)
    local arch_str = t_to_str(state.archetypes, PROFILE_META.ARCHETYPES.opts)
    local lngs_str = t_to_str(state.languages, PROFILE_META.LANGUAGES.opts)
    
    local has_changes = (state.name.text ~= (cfg.dubber_name or "")) or
                        (state.bio.text ~= (cfg.dubber_bio or "")) or
                        (state.contact.text ~= (cfg.dubber_contact or "")) or
                        (state.samples.text ~= (cfg.dubber_samples or "")) or
                        (state.equipment.text ~= (cfg.dubber_equipment or "")) or
                        (state.conditions ~= (cfg.dubber_conditions)) or
                        (state.voice ~= (cfg.dubber_voice)) or
                        (timbre_str ~= (cfg.dubber_timbre or "")) or
                        (spec_str ~= (cfg.dubber_specialization or "")) or
                        (arch_str ~= (cfg.dubber_archetypes or "")) or
                        (lngs_str ~= (cfg.dubber_languages or "")) or
                        (state.vocals ~= (cfg.dubber_vocals or "")) or
                        (state.status ~= (cfg.dubber_status or "Звичайний аккаунт"))

    local btn_w = S(140)
    local btn_h = S(36)
    local bx = gfx.w - pad - btn_w
    local by = gfx.h - footer_h + (footer_h - btn_h) / 2

    -- Status Button (left side of footer)
    local status_opts = PROFILE_META.STATUS.opts
    local display_status = PROFILE_META.translate_opt("STATUS", state.status)
    local status_label = (display_status and display_status ~= "") and display_status or T("STATUS_LABEL")
    local status_w = S(150)
    local status_x = pad
    
    local sb_bg = UI.C_BTN
    local sb_txt = UI.C_TXT
    local tp_text = ""

    if state.status == "Шукаю талант" then
        sb_bg = UI.C_ORANGE
        sb_txt = UI.C_BG
        tp_text = T("STATUS_TIP_LOOKING")
    elseif state.status == "Вільний талант" then
        sb_bg = UI.C_ACCENT_G
        sb_txt = UI.C_BG
        tp_text = T("STATUS_TIP_FREE")
    elseif state.status == "Приховати аккаунт" then
        sb_bg = UI.C_RED
        sb_txt = UI.C_BG
        tp_text = T("STATUS_TIP_HIDE")
    elseif state.status == "Звичайний аккаунт" then
        sb_bg = UI.C_BTN
        sb_txt = UI.C_TXT
        tp_text = T("STATUS_TIP_REGULAR")
    end

    if UI_STATE.window_focused and (gfx.mouse_x >= status_x and gfx.mouse_x <= status_x + status_w and gfx.mouse_y >= by and gfx.mouse_y <= by + btn_h) then
        UI_STATE.tooltip_state.text = T("CHANGE_STATUS_TIP") .. tp_text
    end
    
    if btn(status_x, by, status_w, btn_h, status_label, sb_bg, sb_txt) then
        gfx.x, gfx.y = status_x, by + btn_h
        local menu_opts = {}
        for _, opt in ipairs(status_opts) do
            table.insert(menu_opts, PROFILE_META.translate_opt("STATUS", opt))
        end
        local menu_str = table.concat(menu_opts, "|")
        local ret = gfx.showmenu(menu_str)
        if ret and ret > 0 then
            local selected_opt = status_opts[ret]
            local contact_trimmed = state.contact.text:match("^%s*(.-)%s*$") or ""
            
            if (selected_opt == "Шукаю талант" or selected_opt == "Вільний талант") and contact_trimmed == "" then
                reaper.MB(T("FILL_CONTACT_FIRST"), T("CONTACTS_REQUIRED"), 0)
            elseif selected_opt == "Приховати аккаунт" then
                local res1 = reaper.MB(T("HIDE_PROFILE_CONFIRM_1"), T("HIDE_ACCOUNT_Q"), 4)
                if res1 == 6 then -- Yes
                    local res2 = reaper.MB(T("HIDE_PROFILE_CONFIRM_2"), T("LAST_WARNING"), 4)
                    if res2 == 6 then -- Yes (User agreed that it's better to choose simple account)
                        state.status = "Звичайний аккаунт"
                    else -- No (User wants to hide anyway)
                        state.status = selected_opt
                    end
                end
            else
                state.status = selected_opt
            end
        end
    end

    -- Save Button
    local contact_trimmed = state.contact.text:match("^%s*(.-)%s*$") or ""
    local is_contact_valid = not ((state.status == "Шукаю талант" or state.status == "Вільний талант") and contact_trimmed == "")
    local can_save = has_changes and is_name_valid and is_contact_valid
    local save_bg = can_save and UI.C_ACCENT_G or UI.C_BTN
    local save_txt = can_save and UI.C_BG or UI.C_TXT
    if btn(bx, by, btn_w, btn_h, T("SAVE"), save_bg, save_txt) then
        if not is_name_valid then
            show_snackbar(T("NO_EMPTY_NAME"), "error")
        elseif not is_contact_valid then
            show_snackbar(T("FILL_CONTACT"), "error")
        elseif has_changes then
            cfg.profile_edit_seen = true
            save_settings()

            local new_profile_data = {
                dubber_name = name_trimmed,
                dubber_bio = state.bio.text:match("^%s*(.-)%s*$") or "",
                dubber_contact = state.contact.text:match("^%s*(.-)%s*$") or "",
                dubber_samples = state.samples.text:match("^%s*(.-)%s*$") or "",
                dubber_equipment = state.equipment.text:match("^%s*(.-)%s*$") or "",
                dubber_conditions = state.conditions,
                dubber_voice = state.voice,
                dubber_timbre = timbre_str,
                dubber_specialization = spec_str,
                dubber_archetypes = arch_str,
                dubber_languages = lngs_str,
                dubber_vocals = state.vocals,
                dubber_status = state.status,
            }
            
            STATS.register_plugin_usage(function(success)
                if success then
                    -- Commit changes to local config only on confirmed success
                    for k, v in pairs(new_profile_data) do
                        cfg[k] = v
                    end
                    save_settings()
                    
                    show_snackbar(T("PROFILE_UPDATED"), "success")
                    UI_STATE.show_edit_profile = false
                    OTHER.profile_state = nil
                else
                    -- If failed, cfg remains unchanged, so has_changes remains true
                    -- and the "Save" button stays green for another attempt.
                end
            end, false, new_profile_data) -- is_silent = false, pass override data
        end
    end

    -- Close on Esc
    if input_queue then
        for i = #input_queue, 1, -1 do
            if input_queue[i] == 27 then
                UI_STATE.show_edit_profile = false
                OTHER.profile_state = nil
                table.remove(input_queue, i)
            end
        end
    end
    
    UI_STATE.mouse_handled = true
end

--- Draw remote user profile (Full Screen style)
function DRAW_WINDOW.draw_remote_profile(input_queue)
    if not UI_STATE.show_profile_view then return end
    
    local p = UI_STATE.selected_profile
    local pad = S(20)
    local header_h = S(64)
    
    -- Background overlay (Full Screen)
    set_color(UI.C_BG, 1.0)
    gfx.rect(0, 0, gfx.w, gfx.h, 1)

    if not p then
        -- Background overlay
        set_color(UI.C_BG, 1.0)
        gfx.rect(0, 0, gfx.w, gfx.h, 1)

        -- Loading state
        set_color(UI.C_TXT, 0.3)
        local txt = T("LOADING_DATA")
        gfx.setfont(F.title)
        local tw, th = gfx.measurestr(txt)
        gfx.x, gfx.y = (gfx.w - tw) / 2, (gfx.h - th) / 2
        gfx.drawstr(txt)
        
        -- Header Mask
        set_color(UI.C_BG, 1.0)
        gfx.rect(0, 0, gfx.w, header_h, 1)

        -- Title
        gfx.setfont(F.title)
        set_color(UI.C_TXT, 1)
        gfx.x, gfx.y = pad, pad - S(2)
        gfx.drawstr(T("USER_PROFILE"))

        -- Close button
        local close_sz = S(24)
        if btn(gfx.w - pad - close_sz, pad, close_sz, close_sz, "X", UI.C_BTN, UI.C_TXT) then
            UI_STATE.show_profile_view = false
        end

        UI_STATE.mouse_handled = true
        return
    end

    -- SCROLLABLE CONTENT AREA
    local content_y = header_h
    local content_h = gfx.h - header_h
    
    -- Use persistent max_scroll from previous frame (or 0 initially)
    local max_scroll = ACHIEVEMENTS.profile_max_scroll or 0

    if not ACHIEVEMENTS.profile_scroll_y then ACHIEVEMENTS.profile_scroll_y = 0 end
    if not ACHIEVEMENTS.profile_target_scroll_y then ACHIEVEMENTS.profile_target_scroll_y = 0 end

    -- Mouse wheel scroll
    if gfx.mouse_x >= 0 and gfx.mouse_x <= gfx.w and gfx.mouse_y >= content_y and gfx.mouse_y <= content_y + content_h then
        if gfx.mouse_wheel ~= 0 then
            ACHIEVEMENTS.profile_target_scroll_y = math.max(0, math.min(max_scroll, ACHIEVEMENTS.profile_target_scroll_y - gfx.mouse_wheel * 0.5))
            gfx.mouse_wheel = 0
        end
    end
    ACHIEVEMENTS.profile_scroll_y = ACHIEVEMENTS.profile_scroll_y + (ACHIEVEMENTS.profile_target_scroll_y - ACHIEVEMENTS.profile_scroll_y) * 0.5

    local cy = content_y + S(20) - ACHIEVEMENTS.profile_scroll_y
    local width = gfx.w - pad * 2

    -- Helper for drawing sections and calculating height
    local function draw_view_section(title, text, w, tooltip_text)
        if not text or text == "" or text == "Не співаю" or text == "No singing" then return 0 end
        gfx.setfont(F.tip_big) -- Explicitly set standard font before text measurements
        local actual_text = text:match("^%s*(.-)%s*$") or ""
        local lines = wrap_text(actual_text, w, S(16))
        local section_h = S(22) + #lines * S(18) + S(25)
        
        if cy + section_h > content_y and cy < content_y + content_h then
            -- Tooltip
            if tooltip_text and gfx.mouse_x >= pad and gfx.mouse_x <= pad + w and gfx.mouse_y >= cy and gfx.mouse_y <= cy + section_h then
                UI_STATE.tooltip_state.text = tooltip_text
                if UI_STATE.tooltip_state.hover_id ~= title then
                    UI_STATE.tooltip_state.hover_id = title
                    UI_STATE.tooltip_state.start_time = reaper.time_precise()
                end
            end

            -- Right click to show context menu
            if gfx.mouse_x >= pad and gfx.mouse_x <= pad + w and gfx.mouse_y >= cy and gfx.mouse_y <= cy + section_h then
                if (gfx.mouse_cap & 2 == 2) and (UI_STATE.last_mouse_cap & 2 == 0) and not UI_STATE.mouse_handled then
                    gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
                    
                    local tg_username = actual_text:match("^%s*@([%w_]+)%s*$")
                    local menu_str = T("COPY_ST")

                    if tg_username then
                        menu_str = menu_str .. "|" .. T("OPEN_TG")
                    end
                    
                    local ret = gfx.showmenu(menu_str)
                    if ret == 1 then
                        set_clipboard(actual_text)
                        show_snackbar(T("COPIED") .. "!", "success")
                    elseif ret == 2 and tg_username then
                        UTILS.open_url("https://t.me/" .. tg_username)
                    end
                    
                    UI_STATE.mouse_handled = true
                end
            end

            gfx.setfont(F.tip)
            set_color(UI.C_TXT, 0.7)
            gfx.x, gfx.y = pad, cy
            gfx.drawstr(title)
            cy = cy + S(20)
            
            gfx.setfont(F.tip_big)
            for _, line in ipairs(lines) do
                if cy + S(18) > content_y and cy < content_y + content_h then
                    local has_link = line:match("http[s]?://%S+") or line:match("www%.%S+") or line:match("t%.me/%S+")
                    if has_link then
                        local cx = pad
                        local remaining = line
                        while remaining and remaining ~= "" do
                            local link_start, link_end = remaining:find("http[s]?://%S+")
                            if not link_start then link_start, link_end = remaining:find("www%.%S+") end
                            if not link_start then link_start, link_end = remaining:find("t%.me/%S+") end
                            
                            if link_start then
                                local before = remaining:sub(1, link_start - 1)
                                local link = remaining:sub(link_start, link_end)
                                remaining = remaining:sub(link_end + 1)
                                
                                -- Strip trailing punctuation
                                local trailing = link:match("[%.,;!%?]+$")
                                if trailing then
                                    link = link:sub(1, -(#trailing + 1))
                                    remaining = trailing .. remaining
                                end
                                
                                if before ~= "" then
                                    set_color(UI.C_TXT, has_txt and 1.0 or 0.7)
                                    gfx.x, gfx.y = cx, cy
                                    gfx.drawstr(before)
                                    cx = cx + gfx.measurestr(before)
                                end
                                
                                set_color(UI.C_BLUE_BRIGHT or UI.C_ACCENT)
                                gfx.x, gfx.y = cx, cy
                                gfx.drawstr(link)
                                local link_w = gfx.measurestr(link)
                                
                                -- Hover & Click logic for link
                                if gfx.mouse_y >= cy and gfx.mouse_y <= cy + S(18) and gfx.mouse_x >= cx and gfx.mouse_x <= cx + link_w then
                                    gfx.line(cx, cy + S(16), cx + link_w, cy + S(16))
                                    if (gfx.mouse_cap & 1 == 1) and (UI_STATE.last_mouse_cap & 1 == 0) and not UI_STATE.mouse_handled then
                                        local url = link
                                        if url:match("^www%.") then url = "http://" .. url end
                                        if url:match("^t%.me/") then url = "https://" .. url end
                                        UTILS.open_url(url)
                                        UI_STATE.mouse_handled = true
                                    end
                                end
                                cx = cx + link_w
                            else
                                set_color(UI.C_TXT, 1.0)
                                gfx.x, gfx.y = cx, cy
                                gfx.drawstr(remaining)
                                remaining = ""
                            end
                        end
                    else
                        set_color(UI.C_TXT, 1.0)
                        gfx.x, gfx.y = pad, cy
                        gfx.drawstr(line)
                    end
                end
                cy = cy + S(18)
            end
            
            -- Separator line
            set_color(UI.C_TXT, 0.05)
            gfx.line(pad, cy + S(15), pad + w, cy + S(15))
            
            cy = cy + S(30)
        else
            cy = cy + section_h
        end
        return section_h
    end

    -- Track total height for NEXT frame's scroll limit
    local current_total_h = S(40) -- Start padding

    if p.dubber_status ~= "Приховати аккаунт" then
        current_total_h = current_total_h + draw_view_section(T("SECTION_BIO"), p.dubber_bio, width)
        
        -- Dynamic Specialization Tooltip
        local spec_tooltip = ""
        if p.dubber_specialization then
            for opt in p.dubber_specialization:gmatch("[^,]+") do
                local clean = opt:match("^%s*(.-)%s*$")
                local tip_item = PROFILE_META.tip_by_name("SPECIALIZATION", clean)
                if tip_item then
                    local display_opt = PROFILE_META.translate_opt("SPECIALIZATION", clean)
                    spec_tooltip = spec_tooltip .. (spec_tooltip == "" and "" or "\n") .. "• " .. display_opt .. ": " .. tip_item
                end
            end
        end
        local tr_spec = PROFILE_META.translate_val("SPECIALIZATION", p.dubber_specialization)
        current_total_h = current_total_h + draw_view_section(utf8_upper(T("TF_SPECIALIZATION")), tr_spec, width, spec_tooltip ~= "" and spec_tooltip or nil)

        -- Dynamic Archetypes Tooltip
        local arch_tooltip = ""
        if p.dubber_archetypes then
            for opt in p.dubber_archetypes:gmatch("[^,]+") do
                local clean = opt:match("^%s*(.-)%s*$")
                local tip_item = PROFILE_META.tip_by_name("ARCHETYPES", clean)
                if tip_item then
                    local display_opt = PROFILE_META.translate_opt("ARCHETYPES", clean)
                    arch_tooltip = arch_tooltip .. (arch_tooltip == "" and "" or "\n") .. "• " .. display_opt .. ": " .. tip_item
                end
            end
        end
        local tr_arch = PROFILE_META.translate_val("ARCHETYPES", p.dubber_archetypes)
        current_total_h = current_total_h + draw_view_section(utf8_upper(T("TF_ROLE")), tr_arch, width, arch_tooltip ~= "" and arch_tooltip or nil)

        -- Voice & Timbre Tooltip
        local timbre_tooltip = ""
        if p.dubber_timbre then
            for opt in p.dubber_timbre:gmatch("[^,]+") do
                local clean = opt:match("^%s*(.-)%s*$")
                local tip_item = PROFILE_META.tip_by_name("TIMBRE", clean)
                if tip_item then
                    local display_opt = PROFILE_META.translate_opt("TIMBRE", clean)
                    timbre_tooltip = timbre_tooltip .. (timbre_tooltip == "" and "" or "\n") .. "• " .. display_opt .. ": " .. tip_item
                end
            end
        end

        -- Languages
        local tr_lngs = PROFILE_META.translate_val("LANGUAGES", p.dubber_languages)
        current_total_h = current_total_h + draw_view_section(utf8_upper(T("TF_LANGUAGES")), tr_lngs, width, nil)

        local has_voice = p.dubber_voice and p.dubber_voice ~= ""
        local has_timbre = p.dubber_timbre and p.dubber_timbre ~= ""
        local tr_voice = PROFILE_META.translate_val("VOICE", p.dubber_voice)
        local tr_timbre = PROFILE_META.translate_val("TIMBRE", p.dubber_timbre)
        local combined_voice = (has_voice and has_timbre) and (tr_voice .. " (" .. tr_timbre .. ")") or ""
        local vocal_tooltip = p.dubber_vocals and PROFILE_META.tip_by_name("VOCALS", p.dubber_vocals)
        local cond_tooltip = p.dubber_conditions and PROFILE_META.tip_by_name("CONDITIONS", p.dubber_conditions)

        local tr_vocals = PROFILE_META.translate_val("VOCALS", p.dubber_vocals)
        local tr_cond = PROFILE_META.translate_val("CONDITIONS", p.dubber_conditions)

        current_total_h = current_total_h + draw_view_section(T("SECTION_VOICE_TIMBRE"), combined_voice, width, timbre_tooltip ~= "" and timbre_tooltip or nil)
        current_total_h = current_total_h + draw_view_section(utf8_upper(T("TF_VOCALS")), tr_vocals, width, vocal_tooltip)
        current_total_h = current_total_h + draw_view_section(T("SECTION_EQUIPMENT"), p.dubber_equipment, width)
        current_total_h = current_total_h + draw_view_section(utf8_upper(T("TF_RECORD_ENV")), tr_cond, width, cond_tooltip)
        current_total_h = current_total_h + draw_view_section(T("SECTION_CONTACTS"), p.dubber_contact, width)
        current_total_h = current_total_h + draw_view_section(T("SECTION_PORTFOLIO"), p.dubber_samples, width)
    end

    -- If no sections were drawn, show "Profile is empty"
    if current_total_h <= S(45) then -- S(40) is base padding
        local empty_txt = T("PROFILE_EMPTY_OR_HIDDEN")
        gfx.setfont(F.tip_big)
        local tw, th = gfx.measurestr(empty_txt)
        local tx = (gfx.w - tw) / 2
        local ty = content_y + (content_h - th) / 2
        
        set_color(UI.C_TXT, 0.3)
        gfx.x, gfx.y = tx, ty
        gfx.drawstr(empty_txt)
        current_total_h = current_total_h + S(40)
    end

    -- Save max_scroll for the next frame
    ACHIEVEMENTS.profile_max_scroll = math.max(0, (current_total_h + S(40)) - content_h)

    -- MASK TOP & HEADER (Draw on top of content)
    set_color(UI.C_BG, 1.0)
    gfx.rect(0, 0, gfx.w, header_h, 1)
    
    if p.dubber_status == "Шукаю талант" then
        set_color(UI.C_ORANGE, 0.2)
        gfx.rect(0, 0, gfx.w, header_h, 1)
    elseif p.dubber_status == "Вільний талант" then
        set_color(UI.C_ACCENT_G, 0.2)
        gfx.rect(0, 0, gfx.w, header_h, 1)
    end
    
    set_color(UI.C_TXT, 0.1)
    gfx.line(0, header_h, gfx.w, header_h)
    
    gfx.setfont(F.title)
    set_color(UI.C_TXT)
    gfx.x, gfx.y = pad, pad - S(2)
    -- Fix: Reduced the cut-off margin from S(100) to S(40) so it doesn't disappear in narrow windows
    gfx.drawstr(fit_text_width(p.dubber_name or T("ANONYMOUS"), gfx.w - pad*2 - S(40)))

    gfx.setfont(F.tip)
    set_color(UI.C_TXT, 0.6)
    gfx.x, gfx.y = pad, pad + S(24)
    local sub_txt = T("USER_PROFILE")
    if p.dubber_status == "Шукаю талант" or p.dubber_status == "Вільний талант" then
        sub_txt = PROFILE_META.translate_opt("STATUS", p.dubber_status)
    end
    gfx.drawstr(sub_txt)

    -- Close button
    local close_sz = S(24)
    if btn(gfx.w - pad - close_sz, pad, close_sz, close_sz, "X", UI.C_BTN, UI.C_TXT) then
        UI_STATE.show_profile_view = false
    end

    -- Draw Border & Scrollbar
    set_color(UI.C_TXT, 0.1)
    gfx.rect(0, 0, gfx.w, gfx.h, 0)

    if ACHIEVEMENTS.profile_max_scroll > 0 then
        ACHIEVEMENTS.profile_target_scroll_y = draw_scrollbar(gfx.w - S(8), content_y, S(8), content_h, current_total_h + S(40), content_h, ACHIEVEMENTS.profile_target_scroll_y)
    end

    -- Handle Esc key
    if input_queue then
        for i = #input_queue, 1, -1 do
            if input_queue[i] == 27 then
                UI_STATE.show_profile_view = false
                table.remove(input_queue, i)
            end
        end
    end
    
    UI_STATE.mouse_handled = true
end

--- Draw talent filters UI
function DRAW_WINDOW.draw_talent_filters(input_queue)
    local pad = S(20)
    local header_h = S(65)
    local footer_h = S(55)
    
    -- Ensure we have a temporary state for editing
    if not UI_STATE.talents_filters_temp then
        UI_STATE.talents_filters_temp = {
            voice = UI_STATE.talents_filters.voice,
            timbre = {},
            conditions = UI_STATE.talents_filters.conditions,
            vocals = UI_STATE.talents_filters.vocals,
            specialization = {},
            archetypes = {},
            languages = {},
            status = UI_STATE.talents_filters.status
        }
        -- Deep copy tables
        if UI_STATE.talents_filters.timbre then
            for k, v in pairs(UI_STATE.talents_filters.timbre) do UI_STATE.talents_filters_temp.timbre[k] = v end
        end
        if UI_STATE.talents_filters.specialization then
            for k, v in pairs(UI_STATE.talents_filters.specialization) do UI_STATE.talents_filters_temp.specialization[k] = v end
        end
        if UI_STATE.talents_filters.archetypes then
            for k, v in pairs(UI_STATE.talents_filters.archetypes) do UI_STATE.talents_filters_temp.archetypes[k] = v end
        end
        if UI_STATE.talents_filters.languages then
            for k, v in pairs(UI_STATE.talents_filters.languages) do UI_STATE.talents_filters_temp.languages[k] = v end
        end
    end
    
    local f_state = UI_STATE.talents_filters_temp

    -- Background overlay (Full Screen)
    set_color(UI.C_BG, 1.0)
    gfx.rect(0, 0, gfx.w, gfx.h, 1)

    -- SCROLLABLE CONTENT AREA
    local content_y = header_h
    local content_h = gfx.h - header_h - footer_h
    local total_content_h = UI_STATE.talents_filters_last_h or S(600)
    local max_scroll = math.max(0, total_content_h - content_h)

    -- Handle mouse wheel
    if gfx.mouse_x >= 0 and gfx.mouse_x <= gfx.w and gfx.mouse_y >= content_y and gfx.mouse_y <= content_y + content_h then
        if gfx.mouse_wheel ~= 0 then
            UI_STATE.talents_filters_target_scroll_y = math.max(0, math.min(max_scroll, (UI_STATE.talents_filters_target_scroll_y or 0) - gfx.mouse_wheel * 0.5))
            gfx.mouse_wheel = 0
        end
    end
    UI_STATE.talents_filters_scroll_y = (UI_STATE.talents_filters_scroll_y or 0) + ((UI_STATE.talents_filters_target_scroll_y or 0) - (UI_STATE.talents_filters_scroll_y or 0)) * 0.5

    local cy = content_y + S(20) - UI_STATE.talents_filters_scroll_y
    local is_narrow = gfx.w < S(450)
    local label_w = is_narrow and 0 or S(120)
    local input_h = S(30)
    local spacing = S(20)

    local function draw_radio(label, state_key, options, tooltips, c_rw)
        local start_cy = cy
        local ry = cy
        if is_narrow then ry = cy + S(20) end

        -- Pre-calculate height
        local temp_cy = ry
        local temp_rx = pad + label_w
        local rw = c_rw or S(110)
        for i, opt in ipairs(options) do
            if temp_rx + rw > gfx.w - pad then
                temp_rx = pad + label_w
                temp_cy = temp_cy + input_h + S(5)
            end
            temp_rx = temp_rx + rw + S(5)
        end
        local section_h = temp_cy - start_cy + input_h

        if cy + section_h > content_y and cy < content_y + content_h then
            gfx.setfont(F.std)
            set_color(UI.C_TXT, 0.7)
            if is_narrow then
                gfx.x, gfx.y = pad, cy
                gfx.drawstr(label)
            else
                gfx.x, gfx.y = pad, cy + (input_h - gfx.texth) / 2
                gfx.drawstr(label)
            end
            
            local rx = pad + label_w
            local ry = is_narrow and cy + S(20) or cy
            for i, opt in ipairs(options) do
                if rx + rw > gfx.w - pad then
                    rx = pad + label_w
                    ry = ry + input_h + S(5)
                end
                local is_sel = f_state[state_key] == opt
                local bg = is_sel and UI.C_ACCENT_G or UI.C_BTN
                local txt = is_sel and UI.C_BG or UI.C_TXT

                local hover = (gfx.mouse_x >= rx and gfx.mouse_x <= rx + rw and gfx.mouse_y >= ry and gfx.mouse_y <= ry + input_h)
                if hover and tooltips and tooltips[i] then
                    local tip_id = "profile_radio_" .. state_key .. "_" .. i
                    if UI_STATE.tooltip_state.hover_id ~= tip_id then
                        UI_STATE.tooltip_state.hover_id = tip_id
                        UI_STATE.tooltip_state.start_time = reaper.time_precise()
                    end
                    UI_STATE.tooltip_state.text = tooltips[i]
                end

                local display_opt = PROFILE_META.translate_opt(state_key, opt)
                if btn(rx, ry, rw, input_h, display_opt, bg, txt, false, content_y, content_y + content_h) then
                    if f_state[state_key] == opt then f_state[state_key] = nil else f_state[state_key] = opt end
                end
                rx = rx + rw + S(5)
            end
        end
        cy = start_cy + section_h + spacing
    end

    local function draw_multi_select(label, state_key, options, tooltips)
        local start_cy = cy
        local ry = cy
        if is_narrow then ry = cy + S(20) end

        -- Pre-calculate height
        local temp_cy = ry
        local temp_rx = pad + label_w
        local rw = S(110)
        for i, opt in ipairs(options) do
            if temp_rx + rw > gfx.w - pad then
                temp_rx = pad + label_w
                temp_cy = temp_cy + input_h + S(5)
            end
            temp_rx = temp_rx + rw + S(5)
        end
        local section_h = temp_cy - start_cy + input_h

        if cy + section_h > content_y and cy < content_y + content_h then
            gfx.setfont(F.std)
            set_color(UI.C_TXT, 0.7)
            if is_narrow then
                gfx.x, gfx.y = pad, cy
                gfx.drawstr(label)
            else
                gfx.x, gfx.y = pad, cy + (input_h - gfx.texth) / 2
                gfx.drawstr(label)
            end
            
            local rx = pad + label_w
            local ry = is_narrow and cy + S(20) or cy
            for i, opt in ipairs(options) do
                if rx + rw > gfx.w - pad then
                    rx = pad + label_w
                    ry = ry + input_h + S(5)
                end
                local is_sel = f_state[state_key] and f_state[state_key][opt]
                local bg = is_sel and UI.C_ACCENT_G or UI.C_BTN
                local txt = is_sel and UI.C_BG or UI.C_TXT

                local hover = (gfx.mouse_x >= rx and gfx.mouse_x <= rx + rw and gfx.mouse_y >= ry and gfx.mouse_y <= ry + input_h)
                if hover and tooltips and tooltips[i] then
                    local tip_id = "profile_multi_" .. state_key .. "_" .. i
                    if UI_STATE.tooltip_state.hover_id ~= tip_id then
                        UI_STATE.tooltip_state.hover_id = tip_id
                        UI_STATE.tooltip_state.start_time = reaper.time_precise()
                    end
                    UI_STATE.tooltip_state.text = tooltips[i]
                end

                local display_opt = PROFILE_META.translate_opt(state_key, opt)
                if btn(rx, ry, rw, input_h, display_opt, bg, txt, false, content_y, content_y + content_h) then
                    f_state[state_key] = f_state[state_key] or {}
                    f_state[state_key][opt] = not f_state[state_key][opt]
                end
                rx = rx + rw + S(5)
            end
        end
        cy = start_cy + section_h + spacing
    end

    draw_radio(T("TF_VOICE") .. ":", "voice", PROFILE_META.VOICE.opts, PROFILE_META.get_tips("VOICE"))
    draw_multi_select(T("TF_TIMBRE") .. ":", "timbre", PROFILE_META.TIMBRE.opts, PROFILE_META.get_tips("TIMBRE"))
    draw_radio(T("TF_RECORD_ENV") .. ":", "conditions", PROFILE_META.CONDITIONS.opts, PROFILE_META.get_tips("CONDITIONS"))
    draw_radio(T("TF_VOCALS") .. ":", "vocals", PROFILE_META.VOCALS.filter, PROFILE_META.VOCALS.filter_tips, S(150))
    draw_multi_select(T("TF_SPECIALIZATION") .. ":", "specialization", PROFILE_META.SPECIALIZATION.opts, PROFILE_META.get_tips("SPECIALIZATION"))
    draw_multi_select(T("TF_ROLE") .. ":", "archetypes", PROFILE_META.ARCHETYPES.opts, PROFILE_META.get_tips("ARCHETYPES"))
    draw_multi_select(T("TF_LANGUAGES") .. ":", "languages", PROFILE_META.LANGUAGES.opts)

    UI_STATE.talents_filters_last_h = (cy + UI_STATE.talents_filters_scroll_y) - content_y + S(20)

    -- Scrollbar
    if max_scroll > 0 then
        UI_STATE.talents_filters_target_scroll_y = draw_scrollbar(gfx.w - S(10), content_y, S(10), content_h, total_content_h, content_h, UI_STATE.talents_filters_target_scroll_y or 0)
    end

    -- FOOTER
    set_color(UI.C_BG, 1.0)
    gfx.rect(0, gfx.h - footer_h, gfx.w, footer_h, 1)
    set_color(UI.C_TXT, 0.1)
    gfx.line(0, gfx.h - footer_h, gfx.w, gfx.h - footer_h)

    local bw, bh = S(120), S(34)
    local bx = gfx.w - pad - bw
    if btn(bx, gfx.h - footer_h + (footer_h - bh)/2, bw, bh, T("APPLY"), UI.C_ACCENT_G, UI.C_BG) then
        -- Commit temp filters to main state
        UI_STATE.talents_filters = UI_STATE.talents_filters_temp
        UI_STATE.talents_filters_temp = nil
        UI_STATE.talents_show_filters = false
        ACHIEVEMENTS.fetch_talents(1)
    end
    
    bx = bx - bw - S(10)
    if btn(bx, gfx.h - footer_h + (footer_h - bh)/2, bw, bh, T("RESET"), UI.C_BTN, UI.C_TXT) then
        UI_STATE.talents_filters_temp = { voice = nil, timbre = {}, conditions = nil, vocals = nil, specialization = {}, archetypes = {}, languages = {}, status = nil }
    end

    -- HEADER (Draw over content)
    set_color(UI.C_BG, 1.0)
    gfx.rect(0, 0, gfx.w, header_h, 1)
    set_color(UI.C_TXT, 0.1)
    gfx.line(0, header_h, gfx.w, header_h)
    
    gfx.setfont(F.title)
    set_color(UI.C_TXT)
    gfx.x, gfx.y = pad, pad - S(2)
    local close_sz = S(24)
    gfx.drawstr(fit_text_width(T("FILTERS"), gfx.w - pad * 2 - close_sz - S(100)))

    -- Back button
    local filter_btn_w = S(80)
    if btn(gfx.w - pad - close_sz - filter_btn_w - S(10), pad, filter_btn_w, close_sz, T("BACK"), UI.C_TAB_ACT, UI.C_TXT) then
        UI_STATE.talents_filters_temp = nil
        UI_STATE.talents_show_filters = false
    end

    -- Close button
    if btn(gfx.w - pad - close_sz, pad, close_sz, close_sz, "X", UI.C_BTN, UI.C_TXT) then
        UI_STATE.talents_filters_temp = nil
        UI_STATE.talents_show_filters = false
        UI_STATE.show_talent_search = false
    end

    -- Handle Esc key
    if input_queue then
        for i = #input_queue, 1, -1 do
            if input_queue[i] == 27 then
                UI_STATE.talents_filters_temp = nil
                UI_STATE.talents_show_filters = false
                table.remove(input_queue, i)
            end
        end
    end
end

function DRAW_WINDOW.draw_talent_search(input_queue)
    if not UI_STATE.show_talent_search then return end

    local function get_active_filters_count()
        local count = 0
        local f = UI_STATE.talents_filters
        if not f then return 0 end
        if f.voice then count = count + 1 end
        if f.conditions then count = count + 1 end
        if f.vocals then count = count + 1 end
        
        local has_timbre = false
        if f.timbre then
            for k, v in pairs(f.timbre) do if v then has_timbre = true break end end
        end
        if has_timbre then count = count + 1 end
        
        local has_spec = false
        if f.specialization then
            for k, v in pairs(f.specialization) do if v then has_spec = true break end end
        end
        if has_spec then count = count + 1 end
        
        local has_arch = false
        if f.archetypes then
            for k, v in pairs(f.archetypes) do if v then has_arch = true break end end
        end
        if has_arch then count = count + 1 end

        local has_lngs = false
        if f.languages then
            for k, v in pairs(f.languages) do if v then has_lngs = true break end end
        end
        if has_lngs then count = count + 1 end

        return count
    end

    if UI_STATE.talents_show_filters then
        DRAW_WINDOW.draw_talent_filters(input_queue)
        return
    end
    
    local footer_h = S(40)
    local header_h = S(64)
    local pad = S(20)

    -- 1. BACKGROUND
    set_color(UI.C_BG)
    gfx.rect(0, 0, gfx.w, gfx.h, 1)

    -- Define content area bounds
    local content_y = header_h
    local content_h = gfx.h - header_h - footer_h
    local width = gfx.w - pad * 2
    local total_h = 0
    local top_pad = 0

    -- 2. SCROLL LOGIC
    local max_scroll = ACHIEVEMENTS.talents_max_scroll or 0
    if UI_STATE.window_focused and gfx.mouse_x > 0 and gfx.mouse_x < gfx.w and gfx.mouse_y > header_h and gfx.mouse_y < gfx.h - footer_h then
        if gfx.mouse_wheel ~= 0 then
            UI_STATE.talents_target_scroll_y = math.max(0, math.min(max_scroll, UI_STATE.talents_target_scroll_y - gfx.mouse_wheel * 0.5))
            gfx.mouse_wheel = 0
        end
    end
    UI_STATE.talents_scroll_y = UI_STATE.talents_scroll_y + (UI_STATE.talents_target_scroll_y - UI_STATE.talents_scroll_y) * 0.5

    -- 3. DRAW CONTENT (Masked by header/footer rects later)
    if UI_STATE.talents_loading and not UI_STATE.talents_list then
        set_color(UI.C_TXT, 0.3)
        local txt = T("TL_LOADING_ITMS")
        gfx.setfont(F.title)
        local tw, th = gfx.measurestr(txt)
        gfx.x, gfx.y = (gfx.w - tw) / 2, content_y + (content_h - th) / 2
        gfx.drawstr(txt)
    elseif not UI_STATE.talents_list or #UI_STATE.talents_list == 0 then
        set_color(UI.C_TXT, 0.3)
        local txt = UI_STATE.talents_loading and T("TL_UPDATING") or T("TL_NO_FOUND")
        gfx.setfont(F.title)
        local tw, th = gfx.measurestr(txt)
        gfx.x, gfx.y = (gfx.w - tw) / 2, content_y + (content_h - th) / 2
        gfx.drawstr(txt)
    else
        -- Draw List
        top_pad = S(15)
        local badge_gap = S(4)
        
        -- Pre-calculate row data
        local row_data = {}
        total_h = 0
        for i, t in ipairs(UI_STATE.talents_list) do
            local bio_raw = (t.dubber_bio or ""):match("^%s*(.-)%s*$") or ""
            local has_bio = bio_raw ~= ""
            local bio_final = ""
            local bio_lines = 0
            
            if has_bio then
                gfx.setfont(F.std)
                local max_w = width - S(40)
                local words = {}
                for w in bio_raw:gmatch("%S+") do table.insert(words, w) end
                
                local line1 = ""
                local idx = 1
                while idx <= #words do
                    local w = words[idx]
                    local test = (line1 == "") and w or (line1 .. " " .. w)
                    if gfx.measurestr(test) <= max_w then
                        line1 = test
                        idx = idx + 1
                    else
                        break
                    end
                end
                
                if idx <= #words then
                    local line2_raw = ""
                    for i = idx, #words do
                        line2_raw = (line2_raw == "") and words[i] or (line2_raw .. " " .. words[i])
                    end
                    local line2 = fit_text_width(line2_raw, max_w)
                    bio_final = line1 .. "\n" .. line2
                    bio_lines = 2
                else
                    bio_final = line1
                    bio_lines = 1
                end
            end
            
            -- Collect all badges
            local badges = {}
            local show_other_badges = true
            
            if t.dubber_status == "Шукаю талант" then
                table.insert(badges, {txt = PROFILE_META.translate_opt("STATUS", t.dubber_status), clr = UI.C_ORANGE, alpha = 0.3})
            elseif t.dubber_status == "Вільний талант" then
                table.insert(badges, {txt = PROFILE_META.translate_opt("STATUS", t.dubber_status), clr = UI.C_ACCENT_G, alpha = 0.3})
            end

            if show_other_badges then
                local v_clr = UI.C_HILI_WHITE
                if t.dubber_voice and t.dubber_voice == "Жіночий" then
                    v_clr = UI.C_HILI_RED
                elseif t.dubber_voice and t.dubber_voice == "Чоловічий" then
                    v_clr = UI.C_HILI_BLUE
                end

                local voice_raw = t.dubber_voice or ""
                local timbre_raw = (t.dubber_timbre and t.dubber_timbre ~= "") and t.dubber_timbre or nil
                local voice_disp = PROFILE_META.translate_opt("VOICE", voice_raw)
                local timbre_disp = timbre_raw and PROFILE_META.translate_val("TIMBRE", timbre_raw) or nil
                local voice_txt = voice_disp .. (timbre_disp and (", " .. timbre_disp) or "")
                if voice_txt ~= "" then table.insert(badges, {txt = voice_txt, clr = v_clr, alpha = 0.2}) end

                if t.dubber_specialization and t.dubber_specialization ~= "" then
                    for s in t.dubber_specialization:gmatch("([^,]+)") do
                        s = s:match("^%s*(.-)%s*$")
                        if s ~= "" then
                            table.insert(badges, {txt = PROFILE_META.translate_opt("SPECIALIZATION", s), clr = UI.C_ORANGE, alpha = 0.2})
                        end
                    end
                end

                if t.dubber_vocals and t.dubber_vocals ~= "" and t.dubber_vocals ~= "Не співаю" then
                    table.insert(badges, {txt = PROFILE_META.translate_opt("VOCALS", t.dubber_vocals), clr = UI.C_HILI_GREEN, alpha = 0.15})
                end

                if t.dubber_conditions and t.dubber_conditions ~= "" then
                    table.insert(badges, {txt = PROFILE_META.translate_opt("CONDITIONS", t.dubber_conditions), clr = UI.C_HILI_PINK, alpha = 0.12})
                end

                local gear = t.dubber_equipment or t.dubber_mic or ""
                if gear ~= "" then
                    for g in gear:gmatch("([^,]+)") do
                        g = g:match("^%s*(.-)%s*$")
                        if g ~= "" then table.insert(badges, {txt = g, clr = UI.C_HILI_WHITE_LOW, alpha = 0.08}) end
                    end
                end
            end
            
            -- Simulate wrap to find badge height
            local badge_lines = 0
            local badges_total_h = 0
            if #badges > 0 then
                gfx.setfont(F.tip)
                local bh = gfx.texth + S(6)
                local b_step = bh + badge_gap
                badge_lines = 1
                local cur_tx = 0
                local max_tx = width - S(12)
                for _, b in ipairs(badges) do
                    local bw = gfx.measurestr(b.txt) + S(12)
                    if cur_tx + bw > max_tx then
                        cur_tx = 0
                        badge_lines = badge_lines + 1
                    end
                    cur_tx = cur_tx + bw + badge_gap
                end
                badges_total_h = badge_lines * b_step - badge_gap -- Total height of the badge block
            end
            
            local text_y_off = badges_total_h > 0 and (badges_total_h + S(18)) or S(16)
            
            local bio_h = 0
            if has_bio then
                bio_h = (bio_lines == 2) and S(32) or S(18)
            end
            
            local rh = text_y_off + S(25) + bio_h -- Name area + Bio area
            rh = rh + S(18) -- Bottom pad
            
            row_data[i] = {
                h = rh, 
                y = total_h, 
                badges = badges, 
                has_bio = has_bio, 
                bio_txt = bio_final,
                text_y_off = text_y_off
            }
            total_h = total_h + rh
        end
        
        ACHIEVEMENTS.talents_max_scroll = math.max(0, total_h + top_pad * 2 - content_h)
        local cy_base = content_y + top_pad - UI_STATE.talents_scroll_y
        
        for i, t in ipairs(UI_STATE.talents_list) do
            local rd = row_data[i]
            local rx, ry, rw, rh = pad - S(12), cy_base + rd.y, width + S(12), rd.h
            
            if ry + rh > header_h and ry < gfx.h - footer_h then
                local hover = UI_STATE.window_focused and (gfx.mouse_x >= rx and gfx.mouse_x <= rx + rw and gfx.mouse_y >= ry and gfx.mouse_y <= ry + rh)
                if hover and (gfx.mouse_y < header_h or gfx.mouse_y > gfx.h - footer_h) then hover = false end

                if t.dubber_status == "Шукаю талант" then
                    set_color(UI.C_ORANGE, 0.2)
                    gfx.rect(rx, ry, rw, rh, 1)
                elseif t.dubber_status == "Вільний талант" then
                    set_color(UI.C_ACCENT_G, 0.2)
                    gfx.rect(rx, ry, rw, rh, 1)
                end

                if hover then
                    set_color(UI.C_BTN, 0.15)
                    gfx.rect(rx, ry, rw, rh, 1)
                    if is_mouse_clicked() then
                        ACHIEVEMENTS.fetch_profile(t.machine_id)
                    end
                end

                -- Draw Badges with Wrapping
                if #rd.badges > 0 then
                    local bx = rx + S(12)
                    local by = ry + S(12)
                    local max_bx = bx + (width - S(12))
                    gfx.setfont(F.tip)
                    local bh = gfx.texth + S(6)
                    local b_step = bh + badge_gap
                    local cur_rel_x = 0
                    for _, b in ipairs(rd.badges) do
                        local tw, th = gfx.measurestr(b.txt)
                        local bw = tw + S(12)
                        if cur_rel_x + bw > (width - S(12)) then
                            cur_rel_x = 0
                            by = by + b_step
                        end
                        set_color(b.clr, b.alpha)
                        gfx.rect(bx + cur_rel_x, by, bw, bh, 1)
                        set_color(UI.C_TXT, 0.8)
                        gfx.x, gfx.y = bx + cur_rel_x + S(6), by + S(3)
                        gfx.drawstr(b.txt)
                        cur_rel_x = cur_rel_x + bw + badge_gap
                    end
                end

                -- 2. NAME
                gfx.setfont(F.title)
                set_color(UI.C_TXT, 1)
                gfx.x, gfx.y = rx + S(12), ry + rd.text_y_off
                gfx.drawstr(fit_text_width(t.dubber_name or T("ANONYMOUS"), rw - S(30)))
                
                -- 3. BIO
                if rd.has_bio then
                    gfx.setfont(F.std)
                    set_color(UI.C_TXT, 0.5)
                    gfx.x, gfx.y = rx + S(12), ry + rd.text_y_off + S(30)
                    gfx.drawstr(rd.bio_txt)
                end
                
                -- Separator
                set_color(UI.C_TXT, 0.05)
                gfx.line(rx + S(12), ry + rh - 1, rx + rw - S(12), ry + rh - 1)
            end
        end
    end
    
    -- Draw Scrollbar
    if total_h and total_h + top_pad * 2 > content_h then
        local sb_w = S(10)
        local sb_h = content_h - S(10)
        local sb_x = gfx.w - sb_w - S(2)
        local sb_y = content_y + S(5)
        local new_scroll = draw_scrollbar(sb_x, sb_y, sb_w, sb_h, total_h + top_pad * 2, content_h, UI_STATE.talents_scroll_y)
        if new_scroll and new_scroll ~= UI_STATE.talents_scroll_y then
            UI_STATE.talents_target_scroll_y = new_scroll
            UI_STATE.talents_scroll_y = new_scroll
        end
    end

    -- 4. HEADER (Masking content)
    set_color(UI.C_BG, 1.0)
    gfx.rect(0, 0, gfx.w, header_h, 1)
    set_color(UI.C_TXT, 0.1)
    gfx.line(0, header_h, gfx.w, header_h)
    
    local close_sz = S(24)
    local f_count = get_active_filters_count()
    local filter_text = T("FILTER") .. (f_count > 0 and (" (" .. f_count .. ")") or "")
    local filter_btn_w = S(80)

    -- Prepare quick filters info for width calculation
    local look_count = UI_STATE.talents_looking_count or 0
    local is_look_sel = UI_STATE.talents_filters and UI_STATE.talents_filters.status == "Шукаю талант"
    local free_count = UI_STATE.talents_free_count or 0
    local is_free_sel = UI_STATE.talents_filters and UI_STATE.talents_filters.status == "Вільний талант"

    local show_look = look_count > 0 or is_look_sel
    local show_free = free_count > 0 or is_free_sel
    
    -- Adaptive labels for narrow windows
    local look_text = T("LOOKING_FOR_TALENT") .. " (" .. look_count .. ")"
    local free_text = T("FREE_TALENT") .. " (" .. free_count .. ")"
    if gfx.w < S(550) then
        look_text = T("LOOKING") .. " (" .. look_count .. ")"
        free_text = T("FREE") .. " (" .. free_count .. ")"
    end

    -- 1. Calculate total buttons width to truncate title properly
    gfx.setfont(F.std)
    local look_w = show_look and (gfx.measurestr(look_text) + S(20)) or 0
    local free_w = show_free and (gfx.measurestr(free_text) + S(20)) or 0
    
    local buttons_w = close_sz + S(10) + filter_btn_w + S(10)
    if show_look then buttons_w = buttons_w + look_w + S(10) end
    if show_free then buttons_w = buttons_w + free_w + S(10) end

    -- 2. Draw Title
    gfx.setfont(F.title)
    set_color(UI.C_TXT)
    gfx.x, gfx.y = pad, pad - S(2)
    gfx.drawstr(fit_text_width(T("TALEND_SEARCH_PR"), gfx.w - pad * 2 - buttons_w - S(10)))

    -- 3. Draw Buttons (Right to Left)
    local current_x = gfx.w - pad - close_sz
    
    -- Close
    if btn(current_x, pad, close_sz, close_sz, "X", UI.C_BTN, UI.C_TXT) then
        UI_STATE.show_talent_search = false
    end
    current_x = current_x - S(10)
    
    -- Filter
    current_x = current_x - filter_btn_w
    local btn_bg = UI_STATE.talents_show_filters and UI.C_TAB_ACT or UI.C_BTN
    local btn_txt = UI.C_TXT
    if not UI_STATE.talents_show_filters and f_count > 0 then
        btn_bg = UI.C_RED
        btn_txt = UI.C_BG
    end
    if btn(current_x, pad, filter_btn_w, close_sz, UI_STATE.talents_show_filters and T("BACK") or filter_text, btn_bg, btn_txt) then
        UI_STATE.talents_show_filters = not UI_STATE.talents_show_filters
        if not UI_STATE.talents_show_filters then ACHIEVEMENTS.fetch_talents(1) end
    end
    current_x = current_x - S(10)

    -- Look for talent
    if show_look then
        current_x = current_x - look_w
        local look_bg = is_look_sel and UI.C_ORANGE or UI.C_BTN
        local look_txt = is_look_sel and UI.C_BG or UI.C_TXT
        if btn(current_x, pad, look_w, close_sz, look_text, look_bg, look_txt) then
            UI_STATE.talents_filters = UI_STATE.talents_filters or {}
            if is_look_sel then
                UI_STATE.talents_filters.status = nil
            else
                UI_STATE.talents_filters.status = "Шукаю талант"
            end
            ACHIEVEMENTS.fetch_talents(1)
        end
        current_x = current_x - S(10)
    end

    -- Free talents
    if show_free then
        current_x = current_x - free_w
        local free_bg = is_free_sel and UI.C_ACCENT_G or UI.C_BTN
        local free_txt = is_free_sel and UI.C_BG or UI.C_TXT
        if btn(current_x, pad, free_w, close_sz, free_text, free_bg, free_txt) then
            UI_STATE.talents_filters = UI_STATE.talents_filters or {}
            if is_free_sel then
                UI_STATE.talents_filters.status = nil
            else
                UI_STATE.talents_filters.status = "Вільний талант"
            end
            ACHIEVEMENTS.fetch_talents(1)
        end
    end

    -- 5. FOOTER (Masking content)
    set_color(UI.C_BG, 1.0)
    gfx.rect(0, gfx.h - footer_h, gfx.w, footer_h, 1)
    set_color(UI.C_TXT, 0.1)
    gfx.line(0, gfx.h - footer_h, gfx.w, gfx.h - footer_h)

    if UI_STATE.talents_total and UI_STATE.talents_total > 0 then
        local total_pages = math.ceil(UI_STATE.talents_total / 20)
        local pag_w = S(120)
        local pag_x = (gfx.w - pag_w) / 2
        local pag_y = gfx.h - footer_h + (footer_h - S(26)) / 2
        
        -- Prev
        if total_pages > 1 and (UI_STATE.talents_page or 1) > 1 then
            if btn(pag_x, pag_y, S(30), S(26), "<", UI.C_BTN, UI.C_TXT) then
                ACHIEVEMENTS.fetch_talents(UI_STATE.talents_page - 1)
            end
        end
        
        -- Info
        gfx.setfont(F.std)
        set_color(UI.C_TXT, 0.6)
        local p_txt = string.format("%d / %d", UI_STATE.talents_page or 1, total_pages)
        local tw, th = gfx.measurestr(p_txt)
        gfx.x, gfx.y = (gfx.w - tw) / 2, pag_y + (S(26) - th) / 2
        gfx.drawstr(p_txt)
        
        -- Next
        if total_pages > 1 and (UI_STATE.talents_page or 1) < total_pages then
            if btn(pag_x + pag_w - S(30), pag_y, S(30), S(26), ">", UI.C_BTN, UI.C_TXT) then
                ACHIEVEMENTS.fetch_talents(UI_STATE.talents_page + 1)
            end
        end
    end

    -- 6. HANDLE ESC
    if input_queue then
        for i = #input_queue, 1, -1 do
            if input_queue[i] == 27 then
                UI_STATE.show_talent_search = false
                table.remove(input_queue, i)
            end
        end
    end

    UI_STATE.mouse_handled = true
end

--- Draw dictionary modal with definitions and synonyms, ГОРОХ
--- @param input_queue table List of key inputs
function DRAW_WINDOW.draw_dictionary_modal(input_queue)
    if not dict_modal.show then return end
    
    local hovered_segment = nil

    -- Helper to find word under cursor within a text string (Character-accurate)
    local function get_word_at_x(text, rel_x)
        if not text or text == "" then return 0, 0, "" end
        
        local cur_x = 0
        local i = 1
        local len = #text
        
        local current_word = ""
        local word_start_x = 0
        local word_width = 0
        
        -- Helper: check if a character is a word character (letter or apostrophe)
        local function is_word_char(char)
            local clean = char:gsub(acute, "")
            -- Accept Cyrillic, Latin letters, and apostrophes
            if clean:match("[%a']") then return true end
            if clean:match("[А-Яа-яЁёІіЇїЄєҐґ]") then return true end
            return false
        end
        
        while i <= len do
            -- Decode char (bytes check)
            local b = text:byte(i)
            local char_len = 1
            if b >= 240 then char_len = 4
            elseif b >= 224 then char_len = 3
            elseif b >= 192 then char_len = 2
            end
            
            local char_start = i
            local char_end = i + char_len - 1
            local next_i = i + char_len
            
            -- Handle acute accent (combining char)
            if next_i <= len and text:byte(next_i) == 204 and text:byte(next_i+1) == 129 then
                char_end = next_i + 1
                next_i = next_i + 2
            end
            
            local char = text:sub(char_start, char_end)
            local sw = gfx.measurestr((char:gsub(acute, "")))
            
            -- Check if this is a word character or separator
            if not is_word_char(char) then
                -- Separator: check if we just finished a word
                if current_word ~= "" then
                    if rel_x >= word_start_x and rel_x < cur_x then
                        return word_start_x, word_width, current_word 
                    end
                end
                
                -- Reset for next word
                current_word = ""
                word_width = 0
                word_start_x = cur_x + sw
            else
                -- Word character
                if current_word == "" then word_start_x = cur_x end
                current_word = current_word .. char
                word_width = word_width + sw
            end
            
            cur_x = cur_x + sw
            i = next_i
        end
        
        -- Check last word
        if current_word ~= "" then
            if rel_x >= word_start_x and rel_x <= cur_x then
                return word_start_x, word_width, current_word
            end
        end
        
        return 0, 0, ""
    end

    local function process_context_menu(target_text)
        if not target_text then return end
        target_text = target_text:match("^%s*(.-)%s*$")
        if target_text == "" then return end
        
        local menu_items = { T("COPY"), "", T("SEARCH_IN_GOROH"), "", T("VOICE_OVER_M"), T("VOICE_OVER_SAVE_M"), "", T("CHANGE_VOICE_M") }
        for _, v_name in ipairs(cfg.tts_voices_order) do
            local check = (v_name == cfg.tts_voice) and "• " or ""
            table.insert(menu_items, check .. (v_name:gsub("|", "||")))
        end
        table.insert(menu_items, "<")
        
        local menu_str = table.concat(menu_items, "|")
        gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
        local ret = gfx.showmenu(menu_str)
        UI_STATE.last_mouse_cap = gfx.mouse_cap 
        
        -- Reset dragging state and handle mouse to prevent expansion-drag on menu click
        dict_modal.selection.active = false
        UI_STATE.mouse_handled = true
        if ret == 1 then
            set_clipboard(target_text)
            show_snackbar(T("TEXT_COPIED"))
        elseif ret == 2 then
            trigger_dictionary_lookup(target_text)
        elseif ret == 3 or ret == 4 then
            play_tts_audio(target_text, ret == 4)
        elseif ret >= 5 and ret < 5 + #cfg.tts_voices_order then
            cfg.tts_voice = cfg.tts_voices_order[ret - 4]
            save_settings()
            show_snackbar(T("VOICE_HB_CHANGED_TO") .. cfg.tts_voice)
        end
    end

    -- Check for resize (clear selection as layout shifts)
    if dict_modal.last_w ~= gfx.w or dict_modal.last_h ~= gfx.h then
        dict_modal.selection = { active = false, start_x = 0, start_y = 0, end_x = 0, end_y = 0, text = "" }
        dict_modal.last_w, dict_modal.last_h = gfx.w, gfx.h
    end

    -- Handle pending context menu from previous frame (so selection draws first)
    if dict_modal.pending_menu then
        process_context_menu(dict_modal.pending_menu)
        dict_modal.pending_menu = nil
    end

    if dict_modal.pending_empty_menu then
        dict_modal.pending_empty_menu = nil
        gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
        local ret = gfx.showmenu(T("FIND_NEW_G_PCX"))
        if ret == 1 then
            local ok, input = reaper.GetUserInputs(T("GOROH"), 1, T("SEARCH_TERM_200"), "")
            if ok and input ~= "" then
                trigger_dictionary_lookup(input)
            end
        end
    end

    -- 1. Navigation & History (Handle FIRST to ensure state is clean for layout)
    local navigated = false
    
    -- Selection and Context Menu Globals (PRE-CALCULATE)
    local mouse_x, mouse_y = gfx.mouse_x, gfx.mouse_y
    local is_lmb_down = gfx.mouse_cap & 1 == 1
    local is_lmb_released = (gfx.mouse_cap & 1 == 0) and (UI_STATE.last_mouse_cap & 1 == 1)
    local is_rmb_clicked = (gfx.mouse_cap & 2 == 2) and (UI_STATE.last_mouse_cap & 2 == 0)
    
    -- Keyboard shortcuts handling
    if input_queue then
        for i, key in ipairs(input_queue) do
            if key == 27 then -- ESC
                dict_modal.show = false
                dict_modal.selection = { active = false, start_x = 0, start_y = 0, end_x = 0, end_y = 0, text = "" }
                return
            elseif key == 8 then -- BACKSPACE
                if dict_modal.history and #dict_modal.history > 0 then
                    local prev_state = table.remove(dict_modal.history)
                    dict_modal.word = prev_state.word
                    dict_modal.content = prev_state.content
                    dict_modal.selected_tab = prev_state.selected_tab
                    dict_modal.scroll_y = prev_state.scroll_y
                    dict_modal.target_scroll_y = prev_state.target_scroll_y
                    navigated = true
                end

                dict_modal.selection = { active = false, start_x = 0, start_y = 0, end_x = 0, end_y = 0, text = "" }
            end
        end
    end

    -- Back Button Detection (Early)
    local pad = 0
    local box_x, box_y = pad, pad
    local box_w, box_h = gfx.w - pad * 2, gfx.h - pad * 2
    local btn_w, btn_h = S(85), S(25)
    local btn_back_x = box_x + box_w - S(200)
    local btn_back_y = box_y + box_h - S(35)
    
    local close_sz = S(30)
    local close_x = box_x + box_w - close_sz - S(10)
    local close_y = box_y + S(10)
    local close_hover = UI_STATE.window_focused and (gfx.mouse_x >= close_x and gfx.mouse_x <= close_x + close_sz and
                        gfx.mouse_y >= close_y and gfx.mouse_y <= close_y + close_sz)

    local is_hover_back_btn = false
    if #dict_modal.history > 0 then
        is_hover_back_btn = UI_STATE.window_focused and not close_hover and 
                            gfx.mouse_x >= btn_back_x and gfx.mouse_x <= btn_back_x + btn_w and
                            gfx.mouse_y >= btn_back_y and gfx.mouse_y <= btn_back_y + btn_h
        
        if is_hover_back_btn and is_mouse_clicked() then
            local last = table.remove(dict_modal.history)
            dict_modal.word = last.word
            dict_modal.content = (type(last.content) == "table") and last.content or {}
            dict_modal.selected_tab = last.selected_tab
            dict_modal.scroll_y = last.scroll_y
            dict_modal.target_scroll_y = last.target_scroll_y
            navigated = true
        end
    end

    if navigated then return end -- Skip one frame to re-trigger with new state

    local function draw_dict_text_with_selection(text, use_all_caps, line_h, text_color)
        if not text or text == "" then return 0 end
        
        local d_text = text
        if use_all_caps then d_text = utf8_upper(text) end
        
        local sel = dict_modal.selection
        local has_any_sel = (sel.start_x ~= sel.end_x or sel.start_y ~= sel.end_y)
        
        if not sel.active and not has_any_sel then
            if text_color then set_color(text_color) end
            draw_text_with_stress_marks(d_text)
            return gfx.measurestr((d_text:gsub(acute, "")))
        end

        local cur_x, cur_y = gfx.x, gfx.y
        local v_scroll = dict_modal.scroll_y or 0
        local x1, y1 = sel.start_x, sel.start_y
        local x2, y2 = sel.end_x, sel.end_y
        
        -- Adjustment for buffered rendering: selection is stored in absolute-ish space
        -- but we are drawing in a buffer starting at content_y.
        local content_y = dict_modal.content_y or 0
        y1 = y1 + v_scroll - content_y
        y2 = y2 + v_scroll - content_y
        
        -- Point to tiny selection range
        if y1 == y2 then y2 = y2 + 0.001 end
        
        -- Normalize for logic: sy1 is always the top one
        local iy1, ix1, iy2, ix2
        if (y2 - y1) > line_h * 0.5 or (math.abs(y1 - y2) < line_h * 0.5 and x1 < x2) then
            iy1, ix1, iy2, ix2 = y1, x1, y2, x2
        else
            iy1, ix1, iy2, ix2 = y2, x2, y1, x1
        end

        local i = 1
        local len = #d_text
        local total_sw = 0
        
        while i <= len do
            local b = d_text:byte(i)
            local char_len = 1
            if b >= 240 then char_len = 4
            elseif b >= 224 then char_len = 3
            elseif b >= 192 then char_len = 2
            end
            
            local char = d_text:sub(i, i + char_len - 1)
            local next_i = i + char_len
            if next_i <= len and d_text:byte(next_i) == 204 and d_text:byte(next_i+1) == 129 then
                char = char .. acute
                next_i = next_i + 2
            end
            
            local sw = gfx.measurestr((char:gsub(acute, "")))
            
            local is_selected = false
            
            -- Tighten Overlap Logic
            local line_top = cur_y
            local line_bot = cur_y + line_h
            
            -- Use iy1 as TOP and iy2 as BOTTOM (already normalized)
            local iy1_in = (iy1 >= line_top and iy1 < line_bot)
            local iy2_in = (iy2 > line_top and iy2 <= line_bot)
            
            if iy1_in and iy2_in then
                -- Single line selection match
                local char_x2 = cur_x + sw
                if cur_x < ix2 and ix1 < char_x2 then is_selected = true end
            elseif iy1_in then
                -- Starts on this line
                if cur_x + sw > ix1 then is_selected = true end 
            elseif iy2_in then
                -- Ends on this line
                if cur_x < ix2 then is_selected = true end
            elseif iy1 < line_top and iy2 >= line_bot then
                -- Middle lines: spans across this line completely
                is_selected = true
            end
            
            if is_selected then
                set_color(UI.C_HILI_BLUE)
                gfx.rect(cur_x, cur_y, sw, line_h, 1)
                sel.text = sel.text .. char
            end
            
            if text_color then set_color(text_color) else set_color(UI.C_TXT) end
            gfx.x, gfx.y = cur_x, cur_y
            draw_text_with_stress_marks(char)
            
            cur_x = cur_x + sw
            total_sw = total_sw + sw
            i = next_i
        end
        
        gfx.x = cur_x
        return total_sw
    end
    
    -- Helper to check if mouse is within the current selection relative to the current line being hovered
    local function is_mouse_in_selection(line_h, line_y)
        -- Check if there is ANY selection (active or persisted)
        local sel = dict_modal.selection
        if not sel.active and (sel.start_x == sel.end_x and sel.start_y == sel.end_y) then return false end
        
        local v_scroll = dict_modal.scroll_y or 0
        local mx = gfx.mouse_x
        local iy1, ix1, iy2, ix2
        local x1, y1 = dict_modal.selection.start_x, dict_modal.selection.start_y
        local x2, y2 = dict_modal.selection.end_x, dict_modal.selection.end_y
        
        -- Convert Absolute Selection to Visual for hit detection
        local content_y = dict_modal.content_y or 0
        y1 = y1 + v_scroll - content_y
        y2 = y2 + v_scroll - content_y
        
        -- Point to tiny selection range
        if y1 == y2 then y2 = y2 + 0.001 end
        
        -- Normalize
        if (y2 - y1) > line_h * 0.5 or (math.abs(y1 - y2) < line_h * 0.5 and x1 < x2) then
            iy1, ix1, iy2, ix2 = y1, x1, y2, x2
        else
            iy1, ix1, iy2, ix2 = y2, x2, y1, x1
        end
        
        -- Tighten Overlap Logic
        local line_top = line_y
        local line_bot = line_y + line_h
        
        local iy1_in = (iy1 >= line_top and iy1 < line_bot)
        local iy2_in = (iy2 > line_top and iy2 <= line_bot)
        
        if iy1_in and iy2_in then
            -- Entire selection is visually on this line (Single Line)
            return mx >= ix1 and mx <= ix2
        elseif iy1_in then
            -- Starts on this line
            return mx >= ix1
        elseif iy2_in then
            -- Ends on this line
            return mx <= ix2
        elseif iy1 < line_top and iy2 >= line_bot then
            -- Selection spans across this line completely
            return true
        end
        
        return false
    end
    
    -- Darken background
    gfx.set(0, 0, 0, 0.85)
    gfx.rect(0, 0, gfx.w, gfx.h, 1)
    
    -- Modal box
    set_color(UI.C_TAB_INA)
    gfx.rect(box_x, box_y, box_w, box_h, 1)

    -- Title (Clickable for TTS)
    gfx.setfont(F.lrg, "Comic Sans MS", S(35), string.byte('b'))
    local title_x = box_x + S(15)
    local title_y = box_y
    
    -- Calculate available width for title before it hits the close button
    local max_title_w = (close_x - title_x) - S(10)
    local display_word = fit_text_width(dict_modal.word, max_title_w)
    
    local title_w = gfx.measurestr(display_word)
    local title_h = gfx.texth
    
    -- Hover detection (Blocked by close button)
    local title_hover = UI_STATE.window_focused and not close_hover and 
                        gfx.mouse_x >= title_x and gfx.mouse_x <= title_x + title_w and
                        gfx.mouse_y >= title_y and gfx.mouse_y <= title_y + title_h
    
    -- Draw hover background
    if title_hover and not dict_modal.tts_loading then
        set_color(UI.C_HILI_RED)
        gfx.rect(title_x - S(5), title_y - S(2), title_w + S(10), title_h + S(4), 1)
        
        -- Support context menu for title -> Auto-select
        if is_rmb_clicked and not is_mouse_in_selection(title_h, title_y) then
            local rel_x = gfx.mouse_x - title_x
            local wx, ww, wtxt = get_word_at_x(dict_modal.word, rel_x)
            
            hovered_segment = { text = wtxt }
            -- Visual selection
            dict_modal.selection = {
                active = true,
                start_x = title_x + wx, start_y = title_y - (dict_modal.scroll_y or 0),
                end_x = title_x + wx + ww, end_y = title_y - (dict_modal.scroll_y or 0),
                text = wtxt
            }
        end
    end
    
    -- Draw title text
    set_color(title_hover and UI.C_DICT_TITLE_HOVER or UI.C_DICT_TITLE_NORM)
    gfx.x = title_x
    gfx.y = title_y
    gfx.drawstr(display_word)
    
    -- Click detection
    if title_hover and is_mouse_clicked() and not dict_modal.tts_loading then
        play_tts_audio(dict_modal.word)
    end
    
    -- Render Close Button
    if close_hover then
        set_color(UI.C_HILI_RED)
        gfx.rect(close_x, close_y, close_sz, close_sz, 1)
    end
    set_color(close_hover and UI.C_BTN_ERROR or UI.C_TXT)
    gfx.setfont(F.std)
    gfx.x = close_x + (close_sz - gfx.measurestr("X")) / 2
    gfx.y = close_y + (close_sz - gfx.texth) / 2
    gfx.drawstr("X")
    
    if close_hover and gfx.mouse_cap == 1 and UI_STATE.last_mouse_cap == 0 then
        dict_modal.show = false
        return
    end
    
    -- Tabs UI
    local categories = {T("GD_Interpretation"), T("GD_Conjugation"), T("GD_Synonyms"), T("GD_Idioms"), T("GD_Word_usage")}
    local tab_x = box_x + S(15)
    local tab_y = box_y + S(55)
    local tab_w = S(125)
    
    -- Dynamic resizing if UI_STATE.tabs don't fit
    local max_width = box_w - S(50) -- Available width minus margins (increased right padding)
    local total_req_w = #categories * tab_w
    if total_req_w > max_width then
        tab_w = math.floor(max_width / #categories)
    end
    
    local tab_h = S(30)
    
    gfx.setfont(F.dict_std_sm)
    for _, cat in ipairs(categories) do
        local is_sel = (dict_modal.selected_tab == cat)
        local bx = tab_x
        local by = tab_y
        
        -- Tab button
        if is_sel then
            set_color(UI.C_DICT_TITLE_NORM)
            gfx.rect(bx, by, tab_w, tab_h, 1)
            set_color(UI.C_BG)
        else
            set_color(UI.C_TAB_INA)
            gfx.rect(bx, by, tab_w, tab_h, 1)
            set_color(UI.C_BORDER_MUTED) -- Border
            gfx.rect(bx, by, tab_w, tab_h, 0)
            set_color(UI.C_TXT)
        end
        
        -- Tab Label
        local display_text = fit_text_width(cat, tab_w - S(10))
        local tw, th = gfx.measurestr(display_text)
        gfx.x = bx + (tab_w - tw) / 2
        gfx.y = by + (tab_h - th) / 2
        gfx.drawstr(display_text)
        
        -- Click detection
        if is_mouse_clicked() then
            if gfx.mouse_x >= bx and gfx.mouse_x <= bx + tab_w and
               gfx.mouse_y >= by and gfx.mouse_y <= by + tab_h then
                if dict_modal.selected_tab ~= cat then
                    dict_modal.selected_tab = cat
                    dict_modal.scroll_y = 0
                    dict_modal.target_scroll_y = 0
                    -- Lazy load content for this tab if missing
                    if not dict_modal.content[cat] then
                        dict_modal.content[cat] = fetch_dictionary_category(dict_modal.word, cat)
                    end
                    -- Reset selection on tab switch
                    dict_modal.selection = {
                        active = false,
                        start_x = 0, start_y = 0,
                        end_x = 0, end_y = 0,
                        text = ""
                    }
                end
            end
        end
        
        tab_x = tab_x + tab_w + S(5)
    end
    
    -- Content Area
    local content_x = box_x + S(15)
    local content_y = tab_y + tab_h + S(8)
    local content_w = box_w - S(30)
    local content_h = box_h - (content_y - box_y) - S(5)
    
    gfx.setfont(F.dict_std)
    local line_h = gfx.texth + S(4)
    
    -- Inputs (ESC to close)
    
    -- Layout Helper (Extracted to ensure copy works on unrendered items)
    local function ensure_item_layout(item, width)
        if item.layout and item.layout.width == width then return end
        
        item.layout = { width = width }
                
        if item.is_separator then
            -- Separator Layout
            item.layout = { width = width, is_separator = true, total_h = math.ceil(S(30)) }
        elseif type(item) == "table" and item.is_table then
            -- Table Layout (Pass 1)
            local col_w = width / item.cols
            local occupancy = {} 
            local is_start = {}
            local row_heights = {}
            local row_y_pos = {}
            local running_y = 0
            
            item.layout.col_w = col_w
            item.layout.occupancy = occupancy
            item.layout.is_start = is_start
            item.layout.row_heights = row_heights
            
            for r_idx, grid_row in ipairs(item.rows) do
                occupancy[r_idx] = occupancy[r_idx] or {}
                is_start[r_idx] = is_start[r_idx] or {}
                local l_col = 1
                local max_row_h = line_h 
                
                for _, cell in ipairs(grid_row.cells) do
                    while occupancy[r_idx][l_col] do l_col = l_col + 1 end
                    
                    local cell_w = col_w * cell.colspan
                    
                    -- Wrapping
                    local wrapped = wrap_rich_text(cell.segments, cell_w - 8, F.dict_std, "Arial", S(17), cell.is_header or grid_row.is_header)
                    local needed_h = #wrapped * line_h
                    
                    local cell_info = {
                        text = cell.text, 
                        wrapped = wrapped,
                        colspan = cell.colspan,
                        rowspan = cell.rowspan,
                        is_header = cell.is_header or grid_row.is_header,
                        w = cell_w,
                        x = (l_col - 1) * col_w
                    }
                    
                    is_start[r_idx][l_col] = true
                    for rr = 0, cell.rowspan - 1 do
                        local target_r = r_idx + rr
                        occupancy[target_r] = occupancy[target_r] or {}
                        is_start[target_r] = is_start[target_r] or {}
                        for cc = 0, cell.colspan - 1 do
                            occupancy[target_r][l_col + cc] = cell_info
                        end
                    end
                    
                    if cell.rowspan == 1 then
                        if needed_h > max_row_h then max_row_h = needed_h end
                    end
                    l_col = l_col + cell.colspan
                end
                row_heights[r_idx] = max_row_h + S(20)
                row_y_pos[r_idx] = running_y
                running_y = running_y + row_heights[r_idx]
            end
            item.layout.row_y_pos = row_y_pos
            item.layout.total_h = math.ceil(running_y + S(48)) -- + margin
            
        else
            -- Paragraph Layout
            local para_data = item
             -- Support legacy string
            if type(item) == "string" then para_data = {segments = {{text = item}}, indent = 0} end
            
            local segments = para_data.segments or {}
            local indent = para_data.indent or 0
            -- Fix for phantom header issue: ensure is_header is respected from data
            local is_header = para_data.is_header or false
            
            local indent_x = indent * 24
            local effective_w = width - indent_x - 100
            
            local lines_to_draw = wrap_rich_text(segments, effective_w, F.dict_std, "Arial", S(17), is_header)
            
            item.layout.wrapped = lines_to_draw
            item.layout.indent_x = indent_x
            item.layout.is_header = is_header
            local h_calc = #lines_to_draw * line_h + S(10) -- slight margin
            
            -- Headers have tighter spacing
            if is_header then h_calc = h_calc + S(4) else h_calc = h_calc + S(12) end
            item.layout.total_h = math.ceil(h_calc)
        end
    end

    -- On-Demand Selection Text Generation (Iterates full content)
    local function reconstruct_selection_text()
        local s = dict_modal.selection
        if (s.start_x == s.end_x and s.start_y == s.end_y) then return "" end
       
        -- Normalize selection: sy1 is top, sy2 is bottom (Use Absolute Content Space)
        local sy1, sy2 = s.start_y, s.end_y
        local sx1, sx2 = s.start_x, s.end_x
        local iy1, ix1, iy2, ix2
        if (sy2 - sy1) > line_h * 0.5 or (math.abs(sy1 - sy2) < line_h * 0.5 and sx1 < sx2) then
            iy1, ix1, iy2, ix2 = sy1, sx1, sy2, sx2
        else
            iy1, ix1, iy2, ix2 = sy2, sx2, sy1, sx1
        end
        
        -- Use normalized coordinates for the rest of the function
        sy1, sx1, sy2, sx2 = iy1, ix1, iy2, ix2
        
        -- Convert point selection to tiny range to ensure consistent logic [top, bot)
        if sy1 == sy2 then sy2 = sy2 + 0.001 end
        
        local res_text = ""
        local cur_scan_y = content_y + S(20)
        
        local items = dict_modal.filtered_data or (dict_modal.content and dict_modal.content[dict_modal.selected_tab])
        if not items then return "" end

        -- Helper to parse rich lines with character accuracy
        local function get_line_selection(rich_line, line_top, line_bot, start_cx, is_header)
            -- Exclusive hit test: [top, bot)
            if sy1 >= line_bot or sy2 < line_top then return "" end
            
            local take_full = (sy1 <= line_top and sy2 >= line_bot)
            local take_from = (sy1 >= line_top and sy1 < line_bot)
            local take_to = (sy2 > line_top and sy2 <= line_bot)
            
            if not (take_full or take_from or take_to) then return "" end
            
            local line_txt = ""
            local cx = start_cx
            
            for _, seg in ipairs(rich_line) do
                if seg and seg.text then
                    local is_bld = seg.is_bold or (is_header and not seg.is_plain)
                    gfx.setfont(is_bld and F.dict_bld or F.dict_std)
                    local full_seg_w = gfx.measurestr((seg.text:gsub(acute, "")))
                    
                    if take_full then
                        line_txt = line_txt .. seg.text
                        cx = cx + full_seg_w
                    else
                        -- Character-accurate split
                        local d_text = seg.text
                        local i = 1
                        local len = #d_text
                        while i <= len do
                            local b = d_text:byte(i)
                            local char_len = 1
                            if b >= 240 then char_len = 4
                            elseif b >= 224 then char_len = 3
                            elseif b >= 192 then char_len = 2
                            end
                            local char = d_text:sub(i, i + char_len - 1)
                            local next_i = i + char_len
                            if next_i <= len and d_text:byte(next_i) == 204 and d_text:byte(next_i+1) == 129 then
                                char = char .. acute
                                next_i = next_i + 2
                            end
                            
                            local sw = gfx.measurestr((char:gsub(acute, "")))
                            local char_x2 = cx + sw
                            
                            local is_selected = false
                            if take_from and take_to then
                                -- Selection starts and ends on this line
                                if cx < sx2 and sx1 < char_x2 then is_selected = true end
                            elseif take_from then
                                -- Selection starts here (continues below)
                                if char_x2 > sx1 then is_selected = true end
                            elseif take_to then
                                -- Selection ends here (started above)
                                if cx < sx2 then is_selected = true end
                            end
                            
                            if is_selected then line_txt = line_txt .. char end
                            cx = char_x2
                            i = next_i
                        end
                    end
                end
            end
            return line_txt
        end

        for _, item in ipairs(items) do
            ensure_item_layout(item, content_w)
            local item_h = (item.layout and item.layout.total_h) or 0
            
            if sy2 >= cur_scan_y and sy1 < cur_scan_y + item_h then
                if item.is_table then
                    local L = item.layout
                    if L and L.row_heights and L.occupancy then
                        for r_idx=1, #L.row_heights do
                            local row_rel_y = L.row_y_pos[r_idx] or 0
                            local row_y = cur_scan_y + row_rel_y
                            for l_col = 1, item.cols do
                                if L.is_start[r_idx] and L.is_start[r_idx][l_col] then
                                    local cell = L.occupancy[r_idx][l_col]
                                    if cell and cell.wrapped then
                                        local total_cell_h = 0
                                        for rr = 0, cell.rowspan - 1 do total_cell_h = total_cell_h + (L.row_heights[r_idx + rr] or 0) end
                                        local ty = row_y + (total_cell_h - (#cell.wrapped * line_h))/2
                                        for l_idx, rich_line in ipairs(cell.wrapped) do
                                            local ly = ty + (l_idx - 1) * line_h
                                            
                                            local current_x = content_x + (cell.x or 0) + 4
                                            if (cell.colspan == item.cols) then -- Spanned Header Centering
                                                local tw = 0
                                                for _, seg in ipairs(rich_line) do
                                                    local bld = seg.is_bold or (cell.is_header and not seg.is_plain)
                                                    gfx.setfont(bld and F.dict_bld or F.dict_std)
                                                    tw = tw + gfx.measurestr((seg.text:gsub(acute, "")))
                                                end
                                                current_x = content_x + (cell.x or 0) + (cell.w - tw) / 2
                                            end

                                            local line_txt = get_line_selection(rich_line, ly, ly + line_h, current_x, cell.is_header)
                                           
                                            if line_txt ~= "" then
                                                res_text = res_text .. line_txt
                                                if l_idx < #cell.wrapped then
                                                    if res_text:sub(-1) ~= "-" and res_text:sub(-1) ~= " " then res_text = res_text .. " " end
                                                else
                                                    local is_last_in_row = (l_col + cell.colspan - 1 == item.cols)
                                                    if is_last_in_row then
                                                        if res_text:sub(-1) ~= "\n" then res_text = res_text .. "\n" end
                                                    else
                                                        if res_text:sub(-1) ~= " " then res_text = res_text .. " " end
                                                    end
                                                end
                                            end
                                        end
                                    end
                                end
                            end
                        end
                    end
                elseif item.is_separator then
                    if res_text ~= "" and res_text:sub(-1) ~= "\n" then res_text = res_text .. "\n" end
                    res_text = res_text .. "\n"
                else
                    local L = item.layout
                    if L and L.wrapped then
                        local para_y = cur_scan_y
                        for l_idx, rich_line in ipairs(L.wrapped) do
                            local ly = para_y + (l_idx - 1) * line_h
                            local line_txt = get_line_selection(rich_line, ly, ly + line_h, content_x + (L.indent_x or 0), L.is_header)
                           
                            if line_txt ~= "" then
                                res_text = res_text .. line_txt
                                if l_idx < #L.wrapped then
                                    if res_text:sub(-1) ~= "-" and res_text:sub(-1) ~= " " then res_text = res_text .. " " end
                                else
                                    if res_text:sub(-1) ~= "\n" then res_text = res_text .. "\n" end
                                end
                            end
                        end
                    end
                end
            end
            cur_scan_y = cur_scan_y + item_h
        end
        return res_text
    end

    if input_queue then
        for _, char in ipairs(input_queue) do
            -- Check for Ctrl+C (3) OR Command+C (Mac)
            local is_copy = (char == 3)
            
            -- Alternative: Check modifiers globally
            local is_cmd = (gfx.mouse_cap & 4 == 4)
            if is_cmd and (char == 99 or char == 67) then is_copy = true end -- c or C
            
            if char == 27 then -- ESC
                dict_modal.show = false
            elseif is_copy then
                local s = dict_modal.selection
                if (s.start_x ~= s.end_x or s.start_y ~= s.end_y) then
                    local txt = reconstruct_selection_text()
                    if txt and txt ~= "" then
                        set_clipboard(txt:match("^%s*(.-)%s*$"))
                        show_snackbar(T("TEXT_COPIED"))
                    end
                end
            end
        end
    end
    
    local in_content_area = mouse_x >= content_x and mouse_x <= content_x + content_w and
                            mouse_y >= content_y and mouse_y <= content_y + content_h

    if is_lmb_down and in_content_area and not UI_STATE.mouse_handled and not is_obstructed then
        if not dict_modal.selection.active then
            local is_shift = (gfx.mouse_cap & 8 == 8)
            local s = dict_modal.selection
            local has_sel = (s.start_x ~= s.end_x or s.start_y ~= s.end_y)
            
            if is_shift and has_sel then
                -- Shift-Click: Extend selection
                local mx, my = mouse_x, mouse_y - (dict_modal.scroll_y or 0)
                local d1 = (mx - s.start_x)^2 + (my - s.start_y)^2
                local d2 = (mx - s.end_x)^2 + (my - s.end_y)^2
                
                if d1 < d2 then
                    -- Closer to Start: anchored at End, drag new Start (which becomes visual End logic)
                    s.start_x, s.start_y = s.end_x, s.end_y
                end
                -- If closer to End: anchored at Start (default), dragging End.
                
                -- Update active state immediately
                s.active = true
                s.end_x, s.end_y = mx, my
                s.text = "" 
            else
                -- New Selection
                dict_modal.selection.active = true
                dict_modal.selection.start_x = mouse_x
                dict_modal.selection.start_y = mouse_y - (dict_modal.scroll_y or 0)
                dict_modal.selection.end_x = mouse_x
                dict_modal.selection.end_y = mouse_y - (dict_modal.scroll_y or 0)
                dict_modal.selection.text = ""
            end
        else
            dict_modal.selection.end_x = mouse_x
            dict_modal.selection.end_y = mouse_y - (dict_modal.scroll_y or 0)
            dict_modal.selection.text = ""
        end
    elseif not is_lmb_down then
        dict_modal.selection.active = false
    end

    -- Reset selection if clicking elsewhere
    if is_mouse_clicked(1) and (not in_content_area or is_obstructed) then
        dict_modal.selection = { active = false, start_x = 0, start_y = 0, end_x = 0, end_y = 0, text = "" }
    end
    
    -- Set content_y for helper functions
    dict_modal.content_y = content_y
    
    -- Draw text within clip
    local top_padding = S(20)
    local cur_y = content_y + dict_modal.scroll_y + top_padding
    local total_h = top_padding
    
    local is_hover_close_btn = UI_STATE.window_focused and 
                               gfx.mouse_x >= (box_x + box_w - S(100)) and gfx.mouse_x <= (box_x + box_w - S(100) + btn_w) and
                               gfx.mouse_y >= (box_y + box_h - S(35)) and gfx.mouse_y <= (box_y + box_h - S(35) + btn_h)
    
    local is_obstructed = is_hover_close_btn or is_hover_back_btn or close_hover

    -- Defensive check: ensure content exists
    local content_tbl = (type(dict_modal) == "table" and type(dict_modal.content) == "table") and dict_modal.content or {}
    local active_content = content_tbl[dict_modal.selected_tab]
    
    if active_content == "ERR:SERVER_DOWN" then
        set_color(UI.C_BTN_ERROR) -- Display in error red
        gfx.x = content_x
        gfx.y = content_y + 20
        gfx.drawstr(T("GOROH_500"))
    elseif active_content and #active_content == 0 then
        set_color(UI.C_BORDER_MUTED)
        gfx.x = content_x
        gfx.y = content_y + 20
        gfx.drawstr(T("THERES_NOTHING_FOR") .. dict_modal.selected_tab)
    elseif not active_content or type(active_content) == "string" then
        set_color(UI.C_BORDER_MUTED)
        gfx.x = content_x
        gfx.y = content_y + 20
        local msg = (type(active_content) == "string") and active_content or T("NO_DATA_OR_LOADING")
        gfx.drawstr(msg)
    else
        local hovered_segment = nil
        
        -- Buffering: Setup content buffer
        local buf = OTHER.BUF.DICTIONARY
        gfx.setimgdim(buf, gfx.w, content_h)
        local prev_dest = gfx.dest
        gfx.dest = buf
        
        -- Initial clear with background color
        set_color(UI.C_TAB_INA)
        gfx.rect(0, 0, gfx.w, content_h, 1)

        for _, item in ipairs(active_content) do
            
            -- LAYOUT PHASE (Cache results)
            ensure_item_layout(item, content_w)
            
            -- RENDER PHASE (Clipping)
            local item_h = item.layout.total_h
            local item_y = cur_y
            
            -- Items are rendered relative to content area top
            local rel_item_y = item_y - content_y -- Rendering relative to content area top in buffer

            -- Check visibility (Render even if partially visible)
            if rel_item_y + item_h > 0 and rel_item_y < content_h then
                if item.is_separator then
                    -- Render Horizontal Rule
                    local line_y = rel_item_y + item_h / 2
                    set_color(UI.C_HILI_WHITE_BRIGHT) -- Subtle white
                    gfx.line(content_x, line_y, content_x + content_w, line_y)
                elseif type(item) == "table" and item.is_table then
                    -- Render Table from Cached Layout
                    local table_start_y = rel_item_y
                    local L = item.layout
                    
                    -- Background for top line
                    set_color(UI.C_HILI_WHITE)
                    if table_start_y > 0 and table_start_y < content_h then
                        gfx.line(content_x, table_start_y, content_x + content_w, table_start_y)
                    end
                    
                    for r_idx=1, #L.row_heights do
                        local row_rel_y = L.row_y_pos[r_idx]
                        local row_y = table_start_y + row_rel_y
                        local row_h = L.row_heights[r_idx]
                        
                        -- Row clipping optimization
                        if row_y + row_h > 0 and row_y < content_h then
                            for l_col = 1, item.cols do
                                if L.is_start[r_idx] and L.is_start[r_idx][l_col] then
                                    local cell = L.occupancy[r_idx][l_col]
                                    local cell_x = content_x + cell.x
                                    local cell_w = cell.w
                                    
                                    -- Calculate total height of this spanned cell
                                    local total_cell_h = 0
                                    for rr = 0, cell.rowspan - 1 do
                                        total_cell_h = total_cell_h + (L.row_heights[r_idx + rr] or 0)
                                    end
                                    
                                    -- Background
                                    local is_span_header = (cell.colspan == item.cols)
                                    if cell.is_header or is_span_header then
                                        set_color(UI.C_HILI_WHITE)
                                        local bg_y = math.max(row_y, 0)
                                        local bg_h = math.min(row_y + total_cell_h, content_h) - bg_y
                                        if bg_h > 0 then gfx.rect(cell_x, bg_y, cell_w, bg_h, 1) end
                                    end
                                    
                                    -- Text
                                    local text_h = #cell.wrapped * line_h
                                    local text_y = row_y + (total_cell_h - text_h) / 2
                                    
                                    for l_idx, rich_line in ipairs(cell.wrapped) do
                                        local ly = text_y + (l_idx - 1) * line_h
                                        -- Clip individual lines
                                        if ly + line_h > 0 and ly < content_h then
                                            local current_x = cell_x + 4
                                            if is_span_header then
                                                local tw = 0
                                                for _, seg in ipairs(rich_line) do
                                                    gfx.setfont(seg.is_bold and F.dict_bld or F.dict_std)
                                                    tw = tw + gfx.measurestr((seg.text:gsub(acute, "")))
                                                end
                                                current_x = cell_x + (cell_w - tw) / 2
                                            end
                                            
                                            gfx.y = ly
                                            
                                            for _, seg in ipairs(rich_line) do
                                                if seg.is_bold or (cell.is_header and not seg.is_plain) then gfx.setfont(F.dict_bld) else gfx.setfont(F.dict_std) end
                                                local sw = gfx.measurestr((seg.text:gsub(acute, "")))
                                                -- Use relative mouse Y for hover detection inside buffer
                                                local seg_hover = UI_STATE.window_focused and gfx.mouse_x >= current_x and gfx.mouse_x <= current_x + sw and 
                                                                  (gfx.mouse_y - content_y) >= ly and (gfx.mouse_y - content_y) < ly + line_h
                                                    
                                                if seg_hover and is_rmb_clicked and not is_obstructed and not is_mouse_in_selection(line_h, ly) then
                                                    local rel_x = gfx.mouse_x - current_x
                                                    local wx, ww, wtxt = get_word_at_x(seg.text, rel_x)
                                                    
                                                    hovered_segment = { text = wtxt, word = seg.word } 
                                                    
                                                    -- Auto-select for visual feedback
                                                    dict_modal.selection = {
                                                        active = true,
                                                        start_x = current_x + wx, start_y = ly - (dict_modal.scroll_y or 0),
                                                        end_x = current_x + wx + ww, end_y = ly - (dict_modal.scroll_y or 0),
                                                        text = "" 
                                                    }
                                                end

                                                if seg.is_link then
                                                    set_color(UI.C_DICT_TITLE_NORM)
                                                    gfx.line(current_x, ly + gfx.texth, current_x + sw, ly + gfx.texth)
                                                    if is_lmb_released and not is_obstructed and seg_hover then
                                                        local s = dict_modal.selection
                                                        local dist = math.abs(s.start_x - s.end_x) + math.abs(s.start_y - s.end_y)
                                                        if dist < 3 then
                                                            dict_modal.selection = { active = false, start_x=0, start_y=0, end_x=0, end_y=0, text="" }
                                                            trigger_dictionary_lookup(seg.word)
                                                        end
                                                    end
                                                elseif not cell.is_header and not is_excluded then
                                                    local is_inflection_tab = dict_modal.selected_tab == T("GD_Conjugation")
                                                    if is_inflection_tab and seg_hover and not is_obstructed then
                                                        set_color(UI.C_HILI_RED)
                                                        gfx.rect(current_x - 2, ly - 1, sw + 4, line_h + 2, 1)
                                                        set_color(UI.C_TXT or UI.C_SEL)
                                                        if is_mouse_clicked(1) and (gfx.mouse_cap & 2 == 0) and not dict_modal.tts_loading then
                                                            local tts_text = seg.word
                                                            if not tts_text or tts_text == "" then tts_text = seg.text end
                                                            play_tts_audio(tts_text)
                                                        end
                                                    end
                                                end
                                                
                                                gfx.x = current_x; gfx.y = ly
                                                local eff_color = seg.is_link and UI.C_DICT_TITLE_NORM or (seg.color or UI.C_TXT)
                                                local drawn_w = draw_dict_text_with_selection(seg.text, false, line_h, eff_color)
                                                current_x = current_x + drawn_w
                                            end
                                        end
                                    end
                                    
                                    -- Borders
                                    set_color(UI.C_HILI_WHITE)
                                    local line_y = row_y + total_cell_h
                                    if line_y > 0 and line_y < content_h then gfx.line(cell_x, line_y, cell_x + cell_w, line_y) end
                                    if l_col + cell.colspan - 1 < item.cols then
                                        local vline_x = cell_x + cell_w
                                        local vline_start = math.max(row_y, 0)
                                        local vline_end = math.min(row_y + total_cell_h, content_h)
                                        if vline_start < vline_end then gfx.line(vline_x, vline_start, vline_x, vline_end) end
                                    end
                                end
                            end
                        end
                    end
                else
                     -- Render Paragraph
                    local L = item.layout
                    local current_line_y = rel_item_y
                    
                    for l_idx, rich_line in ipairs(L.wrapped) do
                        if current_line_y + line_h > 0 and current_line_y < content_h then
                            local segment_x = content_x + L.indent_x
                            for _, seg in ipairs(rich_line) do
                                if seg.is_bold or (L.is_header and not seg.is_plain) then gfx.setfont(F.dict_bld) else gfx.setfont(F.dict_std) end
                                gfx.x = segment_x; gfx.y = current_line_y
                                
                                local sw = gfx.measurestr((seg.text:gsub(acute, "")))
                                
                                local seg_hover = UI_STATE.window_focused and gfx.mouse_x >= gfx.x and gfx.mouse_x <= gfx.x + sw and 
                                                  (gfx.mouse_y - content_y) >= gfx.y and (gfx.mouse_y - content_y) < gfx.y + line_h

                                if seg_hover and is_rmb_clicked and not is_obstructed and not is_mouse_in_selection(line_h, gfx.y) then
                                    local rel_x = gfx.mouse_x - gfx.x
                                    local wx, ww, wtxt = get_word_at_x(seg.text, rel_x)
                                    
                                    hovered_segment = { text = wtxt, word = seg.word }
                                    
                                    -- Auto-select for visual feedback
                                    dict_modal.selection = {
                                        active = true,
                                        start_x = gfx.x + wx, start_y = gfx.y - (dict_modal.scroll_y or 0),
                                        end_x = gfx.x + wx + ww, end_y = gfx.y - (dict_modal.scroll_y or 0),
                                        text = "" 
                                    }
                                end

                                if seg.is_link then
                                    set_color(UI.C_HILI_BLUE_LIGHT)
                                    gfx.line(gfx.x, gfx.y + gfx.texth, gfx.x + sw, gfx.y + gfx.texth)
                                    if is_lmb_released and not is_obstructed and seg_hover then
                                        local s = dict_modal.selection
                                        local dist = math.abs(s.start_x - s.end_x) + math.abs(s.start_y - s.end_y)
                                        if dist < 3 then
                                            dict_modal.selection = { active = false, start_x=0, start_y=0, end_x=0, end_y=0, text="" }
                                            trigger_dictionary_lookup(seg.word)
                                        end
                                    end
                                else
                                    -- Text / Selection
                                    if L.is_header and not seg.is_plain and seg.text:match("%S") then
                                        local clean_txt = seg.text:gsub(acute, ""):match("^%s*(.-)%s*$")
                                        local is_symbol = clean_txt:match("^[%p%s]+$")
                                        local is_inflection_tab = dict_modal.selected_tab == T("GD_Conjugation")
                                        if is_inflection_tab and not is_symbol and seg_hover and not is_obstructed then
                                            set_color(UI.C_HILI_RED)
                                            gfx.rect(gfx.x - 2, gfx.y - 1, sw + 4, line_h + 2, 1)
                                            set_color(UI.C_TXT or UI.C_SEL)
                                            if is_mouse_clicked(1) and (gfx.mouse_cap & 2 == 0) and not dict_modal.tts_loading then
                                                local tts_text = seg.word
                                                if not tts_text or tts_text == "" then tts_text = seg.text end
                                                play_tts_audio(tts_text)
                                            end
                                        end
                                    end
                                end
                                gfx.x = segment_x; gfx.y = current_line_y
                                local eff_color = seg.is_link and UI.C_DICT_TITLE_NORM or (seg.color or UI.C_TXT)
                                local drawn_w = draw_dict_text_with_selection(seg.text, false, line_h, eff_color)
                                segment_x = segment_x + drawn_w
                            end     
                        end
                        current_line_y = current_line_y + line_h
                    end
                end
            end
            
            -- Advance cursor by total height regardless of visibility
            cur_y = item_y + item.layout.total_h
            total_h = total_h + item.layout.total_h
        end
        
        -- Restore gfx.dest and blit the content area to the main window
        gfx.dest = prev_dest
        gfx.a = 1.0
        gfx.mode = 0
        gfx.blit(buf, 1, 0, content_x, 0, content_w, content_h, content_x, content_y)

        -- Trigger context menu if needed
        if is_rmb_clicked and not is_obstructed then
            local target_text = ""
            
            -- On-Demand Reconstruction for Context Menu
            if dict_modal.selection.active or (dict_modal.selection.start_x ~= dict_modal.selection.end_x) then
                local txt = reconstruct_selection_text()
                if txt and txt ~= "" then
                    dict_modal.selection.text = txt -- Populate for external consumer!
                    target_text = txt
                end
            end
            
            if target_text == "" and hovered_segment then
                target_text = hovered_segment.text
            end

            if target_text ~= "" then
                -- Defer menu to next frame to allow selection to draw
                dict_modal.pending_menu = target_text
            else
                -- Empty area click
                dict_modal.pending_empty_menu = true
            end
        end
    end
    
    dict_modal.max_scroll = math.ceil(math.max(0, total_h - content_h))
    
    -- 1. Handle mouse wheel
    if gfx.mouse_wheel ~= 0 then
        dict_modal.target_scroll_y = dict_modal.target_scroll_y + (gfx.mouse_wheel > 0 and 1 or -1) * line_h * 2
        gfx.mouse_wheel = 0
    end

    -- 2. Handle scrollbar (Update target only on drag)
    local current_abs_scroll = -dict_modal.target_scroll_y
    local new_abs_scroll = draw_scrollbar(box_x + box_w - S(10), content_y, S(10), content_h, total_h, content_h, current_abs_scroll)
    
    if (gfx.mouse_cap & 1 == 1) and math.abs(new_abs_scroll - current_abs_scroll) > 0.001 then
        dict_modal.target_scroll_y = -new_abs_scroll
    end
    
    -- 3. Final Clamping
    if dict_modal.target_scroll_y > 0 then dict_modal.target_scroll_y = 0 end
    if dict_modal.target_scroll_y < -dict_modal.max_scroll then dict_modal.target_scroll_y = -dict_modal.max_scroll end

    -- 4. Smooth scroll interpolation (Apply to scroll_y for NEXT frame)
    dict_modal.scroll_y = dict_modal.scroll_y + (dict_modal.target_scroll_y - dict_modal.scroll_y) * 0.8
    if math.abs(dict_modal.target_scroll_y - dict_modal.scroll_y) < 0.5 then
        dict_modal.scroll_y = dict_modal.target_scroll_y
    end
    
    -- Bottom Buttons
    if btn(box_x + box_w - S(100), box_y + box_h - S(35), S(85), S(25), T("CLOSE")) then
        dict_modal.show = false
    end
    
    if #dict_modal.history > 0 then
        local back_label = T("BACK")
        if is_hover_back_btn then set_color(UI.C_SEL_BG) end
        if btn(btn_back_x, btn_back_y, S(85), S(25), back_label) then
            -- Logic handled at top
        end
    end
    
    -- Also close if clicked outside
    if is_mouse_clicked() then
        if gfx.mouse_x < box_x or gfx.mouse_x > box_x + box_w or
           gfx.mouse_y < box_y or gfx.mouse_y > box_y + box_h then
            dict_modal.show = false
        end
    end
end

--- Check Python version
-- @return boolean support, string version
local function get_py_ver()
    local function extract_ver(s)
        if not s or type(s) ~= "string" or s == "" then return nil end
        s = s:gsub("Python%s+", "")
        for v in s:gmatch("[%d%.]+") do
            local major, minor = v:match("(%d+)%.(%d+)")
            if major and minor then
                local n_maj, n_min = tonumber(major), tonumber(minor)
                if n_maj and n_min then
                    if n_maj > 3 or (n_maj == 3 and n_min >= 9) then return true, v end
                    return false, v
                end
            end
        end
        return nil
    end

    local os_name = reaper.GetOS()
    if os_name:match("Win") then
        -- Async check for Windows to avoid terminal popup
        local cmds = {
            { cmd = "py -3 --version", exe = "py -3" },
            { cmd = "python --version", exe = "python" },
            { cmd = "python3 --version", exe = "python3" }
        }
        
        local function try_next_cmd(idx)
            if idx > #cmds then
                OTHER.rec_state.python.version = "N/A"
                OTHER.rec_state.python.ok = false
                OTHER.rec_state.checking = false -- Check finished
                return
            end
            
            run_async_command(cmds[idx].cmd, function(output)
                local success, version = extract_ver(output)
                if success ~= nil then
                    OTHER.rec_state.python.ok = success
                    OTHER.rec_state.python.version = version
                    OTHER.rec_state.python.executable = cmds[idx].exe
                    -- Updates state if success
                    if OTHER.rec_state.python.ok then
                        OTHER.rec_state.all_ok = (OTHER.rec_state.sws and OTHER.rec_state.reapack and 
                                                    OTHER.rec_state.js_api and OTHER.rec_state.reaimgui and 
                                                    OTHER.rec_state.python.ok)
                        
                        -- Register telemetry once Python is verified
                        STATS.register_plugin_usage()
                        
                        -- If everything became OK, we can potentially hide window or re-layout
                        if OTHER.rec_state.all_ok then OTHER.rec_state.show = false end
                    end
                    OTHER.rec_state.checking = false -- Check finished
                else
                    try_next_cmd(idx + 1)
                end
            end)
        end
            
        -- Start async chain
        OTHER.rec_state.python.version = T("RQ_C_PY")
        OTHER.rec_state.checking = true -- checking started
        try_next_cmd(1)
        
        -- Return pending state
        return false, T("RQ_C_PY") 
    else
        -- macOS/Linux - Keep synchronous as it works fine
        local p = "PATH=/usr/local/bin:/usr/bin:/bin:/usr/sbin:/sbin:/opt/homebrew/bin "
        local cmds = {
            "/opt/homebrew/bin/python3 --version",
            "/usr/local/bin/python3 --version",
            "/usr/bin/python3 --version",
            '/bin/sh -c "' .. p .. 'python3 --version 2>&1"',
            '/bin/sh -c "' .. p .. 'python --version 2>&1"',
            "python3 --version",
            "python --version"
        }
        
        -- 1. Try ExecProcess
        for _, cmd in ipairs(cmds) do
            local _, output = reaper.ExecProcess(cmd, 2000)
            local success, version = extract_ver(output)
            if success ~= nil then 
                -- Extract executable name from command (first word)
                local exe = cmd:match("^%S+")
                -- Special handling for /bin/sh -c commands
                if cmd:find("/bin/sh -c") then
                    exe = "python3" -- Fallback for the complex shell command
                end
                OTHER.rec_state.python.executable = exe
                return success, version 
            end
        end
    
        -- 2. Try io.popen
        for _, cmd in ipairs(cmds) do
            local f = io.popen(cmd)
            if f then
                local output = f:read("*a")
                f:close()
                local success, version = extract_ver(output)
                if success ~= nil then 
                    -- Extract executable name
                    local exe = cmd:match("^/bin/sh %-c \".-([%w%d/._-]+) %-%-version")
                    if not exe then exe = cmd:match("^%S+") end
                    if cmd:find("/bin/sh -c") and not exe then exe = "python3" end
                    OTHER.rec_state.python.executable = exe
                    return success, version 
                end
            end
        end
    
        -- 3. Direct path probing
        local paths = {"/opt/homebrew/bin/python3", "/usr/local/bin/python3", "/usr/bin/python3", "/usr/bin/python"}
        for _, path in ipairs(paths) do
            local file = io.open(path, "rb")
            if file then
                file:close()
                OTHER.rec_state.python.executable = path
                local _, output = reaper.ExecProcess(path .. " --version 2>&1", 2000)
                local success, version = extract_ver(output)
                if success ~= nil then return success, version end
            end
        end
            
        return false, "N/A"
    end
end

--- Perform requirements check
local function do_check()
    OTHER.rec_state.sws = (reaper.CF_SetClipboard ~= nil)
    OTHER.rec_state.reapack = (reaper.ReaPack_GetOwner ~= nil)
    OTHER.rec_state.js_api = (reaper.JS_Window_Find ~= nil)
    OTHER.rec_state.reaimgui = (reaper.ImGui_CreateContext ~= nil)

    local py_ok, py_ver = get_py_ver()
    
    -- If sync check returned definitive result (or for non-Windows), set it. 
    -- For Windows async, 'py_ver' will be "Checking..." initially.
    if py_ver ~= T("RQ_C_PY") or not reaper.GetOS():match("Win") then
        OTHER.rec_state.python.ok = py_ok
        OTHER.rec_state.python.version = py_ver
        
        -- Register telemetry once Python is verified synchronously (macOS/Linux)
        if py_ok then
            STATS.register_plugin_usage()
        end
    end

    OTHER.rec_state.all_ok = (OTHER.rec_state.sws and OTHER.rec_state.reapack and 
                                OTHER.rec_state.js_api and OTHER.rec_state.reaimgui and 
                                OTHER.rec_state.python.ok)
    if not OTHER.rec_state.all_ok then OTHER.rec_state.show = true end
    OTHER.rec_state.checked = true
end

function DRAW_WINDOW.draw_requirements_window()
    if not OTHER.rec_state.checked then do_check() end

    -- STARTUP LOADING SCREEN (Prevent flash)
    if OTHER.rec_state.checking then
        -- Backdrop
        gfx.set(0, 0, 0, 0.7)
        gfx.rect(0, 0, gfx.w, gfx.h, 1)
        
        -- Centered Text
        gfx.setfont(F.dict_bld)
        set_color(UI.C_WHITE)
        local str = T("RQ_CHECK_TXT")
        local sw, sh = gfx.measurestr(str)
        gfx.x, gfx.y = (gfx.w - sw)/2, (gfx.h - sh)/2
        gfx.drawstr(str)
        return
    end

    if not OTHER.rec_state.show then return end

    -- Backdrop
    gfx.set(0, 0, 0, 0.7)
    gfx.rect(0, 0, gfx.w, gfx.h, 1)
    
    -- Responsive Main Box (70% width, 80% height, with smaller min constraints)
    local bw = math.max(S(200), math.min(S(700), gfx.w * 0.85))
    local bh = math.max(S(200), math.min(S(600), gfx.h * 0.85))
    local bx, by = (gfx.w - bw) / 2, (gfx.h - bh) / 2
    
    -- Background
    set_color(UI.C_DARK_GREY)
    gfx.rect(bx, by, bw, bh, 1)

    --- Draw a bold dashed rectangle to draw attention
    dash_len = 15
    thickness = 4
    set_color(UI.C_YELLOW) -- Yellow
    
    for t = 0, thickness - 1 do
        local tx, ty, tw, th = bx - t, by - t, bw + t*2, bh + t*2
        -- Top
        for i = tx, tx + tw, dash_len * 2 do
            gfx.line(i, ty, math.min(i + dash_len, tx + tw), ty)
        end
        -- Bottom
        for i = tx, tx + tw, dash_len * 2 do
            gfx.line(i, ty + th, math.min(i + dash_len, tx + tw), ty + th)
        end
        -- Left
        for i = ty, ty + th, dash_len * 2 do
            gfx.line(tx, i, tx, math.min(i + dash_len, ty + th))
        end
        -- Right
        for i = ty, ty + th, dash_len * 2 do
            gfx.line(tx + tw, i, tx + tw, math.min(i + dash_len, ty + th))
        end
    end

    -- List Requirements
    local items = {
        { 
            name = "SWS Extension", 
            ok = OTHER.rec_state.sws, 
            info = T("RQ_SWS")
        },
        { 
            name = "ReaPack", 
            ok = OTHER.rec_state.reapack, 
            info = T("RQ_REAPACK")
        },
        { 
            name = "JS_ReaScriptAPI", 
            ok = OTHER.rec_state.js_api, 
            reapack_search = "js_ReaScriptAPI: API functions for ReaScripts",
            info = T("RQ_JS_REA")
        },
        { 
            name = "ReaImGui", 
            ok = OTHER.rec_state.reaimgui, 
            reapack_search = "ReaImGui: ReaScript binding for Dear ImGui",
            info = T("RQ_REAIMGUI")
        },
        {
            name = "Python (>= 3.12)", 
            ok = OTHER.rec_state.python.ok, 
            info = T("RQ_PYTHON_1") .. OTHER.rec_state.python.version .. T("RQ_PYTHON_2")
        }
    }
    
    -- Content Area Setup (increased spacing after title)
    local view_y = by + S(60)
    local view_h = bh - S(70)
    local col_x = bx + S(40)
    
    -- Calculate layout and total height (cache layout to ensure stable rendering)
    local total_h = 0
    gfx.setfont(F.dict_std_sm)
    local wrap_w = bw - S(120)
    
    for i, item in ipairs(items) do
        local entry_base_h = S(28)  -- Icon + name height
        item.render_lines = {} -- Store laid out lines here: array of {parts}
        
        if item.ok then
            -- If requirement is met, only show header (collapsed)
            item.entry_h = entry_base_h + S(5) -- Minimal spacing
        else
            -- Split by newlines first
            local lines_raw = {}
            for line in (item.info .. "\n"):gmatch("(.-)\n") do
                table.insert(lines_raw, line)
            end
            
            -- Process each line
            for _, raw_line in ipairs(lines_raw) do
                if raw_line ~= "" then
                    -- Parse line into segments (text, links, bold)
                    local segments = {}
                    local remaining = raw_line
                    
                    while remaining ~= "" do
                        local link_start, link_end, link_text, link_url = remaining:find("%[(.-)%]%((.-)%)")
                        local bold_start, bold_end, bold_text = remaining:find("%*%*(.-)%*%*")
                        
                        local next_special = nil
                        local next_pos = math.huge
                        
                        if link_start and link_start < next_pos then
                            next_special = "link"
                            next_pos = link_start
                        end
                        if bold_start and bold_start < next_pos then
                            next_special = "bold"
                            next_pos = bold_start
                        end
                        
                        if next_special == "link" then
                            if link_start > 1 then
                                table.insert(segments, {type = "text", content = remaining:sub(1, link_start - 1)})
                            end
                            table.insert(segments, {type = "link", text = link_text, url = link_url})
                            remaining = remaining:sub(link_end + 1)
                        elseif next_special == "bold" then
                            if bold_start > 1 then
                                table.insert(segments, {type = "text", content = remaining:sub(1, bold_start - 1)})
                            end
                            table.insert(segments, {type = "bold", content = bold_text})
                            remaining = remaining:sub(bold_end + 1)
                        else
                            table.insert(segments, {type = "text", content = remaining})
                            remaining = ""
                        end
                    end
                    
                    -- Build line parts
                    local line_parts = {}
                    for _, seg in ipairs(segments) do
                        if seg.type == "text" then
                            for word in seg.content:gmatch("%S+") do
                                table.insert(line_parts, {type = "text", content = word})
                            end
                        elseif seg.type == "bold" then
                            for word in seg.content:gmatch("%S+") do
                                table.insert(line_parts, {type = "bold", content = word})
                            end
                        else
                            table.insert(line_parts, {type = "link", content = seg.text, url = seg.url})
                        end
                    end
                    
                    -- Wrap lines and store in render_lines
                    local current_line = {}
                    local current_width = 0
                    
                    for i, part in ipairs(line_parts) do
                        local part_text = part.content
                        
                        -- Measure with appropriate font
                        if part.type == "bold" then
                            gfx.setfont(F.dict_bld_sm)
                        else
                            gfx.setfont(F.dict_std_sm)
                        end
                        
                        local test_text = (#current_line > 0) and " " .. part_text or part_text
                        local test_w = gfx.measurestr(test_text)
                        
                        if current_width + test_w > wrap_w and #current_line > 0 then
                            -- Flush current line
                            table.insert(item.render_lines, current_line)
                            
                            -- Start new line
                            current_line = {part}
                            current_width = gfx.measurestr(part_text)
                        else
                            table.insert(current_line, part)
                            current_width = current_width + test_w
                        end
                    end
                    if #current_line > 0 then
                        table.insert(item.render_lines, current_line)
                    end
                else
                    -- Empty line
                    table.insert(item.render_lines, {})
                end
            end
            
            local text_h = #item.render_lines * S(22)
            
            -- Extra space for ReaPack button if available
            if OTHER.rec_state.reapack and item.reapack_search then
                text_h = text_h + S(35)
            end
            
            item.entry_h = entry_base_h + text_h + S(20)  -- Add spacing between entries
        end
        total_h = total_h + item.entry_h
    end
    
    -- Smooth Scroll Logic (similar to draw_file)
    local max_scroll = math.max(0, total_h - view_h)
    
    if gfx.mouse_x >= bx and gfx.mouse_x <= bx + bw and gfx.mouse_y >= by and gfx.mouse_y <= by + bh then
        if gfx.mouse_wheel ~= 0 then
            OTHER.rec_state.target_scroll_y = OTHER.rec_state.target_scroll_y - (gfx.mouse_wheel * 0.25)
            if OTHER.rec_state.target_scroll_y < 0 then OTHER.rec_state.target_scroll_y = 0 end
            if OTHER.rec_state.target_scroll_y > max_scroll then OTHER.rec_state.target_scroll_y = max_scroll end
            gfx.mouse_wheel = 0
        end
    end
    
    -- Interpolate scroll position
    local diff = OTHER.rec_state.target_scroll_y - OTHER.rec_state.scroll_y
    if math.abs(diff) > 0.5 then
        OTHER.rec_state.scroll_y = OTHER.rec_state.scroll_y + (diff * 0.8)
    else
        OTHER.rec_state.scroll_y = OTHER.rec_state.target_scroll_y
    end
    
    -- Clamp scroll
    if OTHER.rec_state.scroll_y < 0 then OTHER.rec_state.scroll_y = 0 end
    if OTHER.rec_state.scroll_y > max_scroll then OTHER.rec_state.scroll_y = max_scroll end

    -- Draw content with scroll offset (clipped to view area)
    local draw_y = view_y - math.floor(OTHER.rec_state.scroll_y)

    for _, item in ipairs(items) do
        -- Use cached height from layout calculation
        local entry_h = item.entry_h or (S(28) + S(20)) -- Fallback if not calculated
        
        -- Check visibility (draw if any part is in view)
        if draw_y + entry_h > view_y and draw_y < view_y + view_h then
            
            -- Header (Icon + Name)
            -- Only draw if header is visible below the mask area
            if draw_y + S(28) > view_y then
                gfx.setfont(F.dict_bld)

                if item.ok then
                    set_color(UI.C_GREEN) -- Green
                    gfx.x, gfx.y = col_x, draw_y
                    gfx.drawstr("[OK]")
                else
                    set_color(UI.C_RED) -- Red
                    gfx.x, gfx.y = col_x, draw_y
                    gfx.drawstr("[ X ]")
                end
                
                -- Name
                set_color(UI.C_TXT)
                gfx.x = col_x + S(50)
                gfx.y = draw_y
                gfx.drawstr(item.name)
            end
            
            local line_y = draw_y + S(28)
            
            -- Draw cached lines
            if item.render_lines then
                for _, line_parts in ipairs(item.render_lines) do
                    if #line_parts == 0 then
                        -- Empty line
                        line_y = line_y + S(22)
                    else
                        -- Draw visible lines only
                        if line_y + S(22) > view_y and line_y < view_y + view_h then
                            local draw_x = col_x + S(50)
                            
                            for j, p in ipairs(line_parts) do
                                -- Add space if not first
                                if j > 1 then
                                    gfx.setfont(F.dict_std_sm)
                                    set_color(UI.C_LIGHT_GREY)
                                    gfx.x, gfx.y = draw_x, line_y
                                    local space_w = gfx.measurestr(" ")
                                    gfx.drawstr(" ")
                                    draw_x = draw_x + space_w
                                end
                                
                                if p.type == "link" then
                                    gfx.setfont(F.dict_std_sm)
                                    set_color(UI.C_BLUE_BRIGHT)
                                    gfx.x, gfx.y = draw_x, line_y
                                    local link_w = gfx.measurestr(p.content)
                                    gfx.drawstr(p.content)
                                    
                                    if is_mouse_clicked() and gfx.mouse_x >= draw_x and gfx.mouse_x <= draw_x + link_w and
                                       gfx.mouse_y >= line_y and gfx.mouse_y <= line_y + S(22) then
                                        UTILS.open_url(p.url)
                                        UI_STATE.mouse_handled = true
                                    end
                                    draw_x = draw_x + link_w
                                elseif p.type == "bold" then
                                    gfx.setfont(F.dict_bld_sm)
                                    set_color(UI.C_WHITE)
                                    gfx.x, gfx.y = draw_x, line_y
                                    local bold_w = gfx.measurestr(p.content)
                                    gfx.drawstr(p.content)
                                    draw_x = draw_x + bold_w
                                else
                                    gfx.setfont(F.dict_std_sm)
                                    set_color(UI.C_LIGHT_GREY)
                                    gfx.x, gfx.y = draw_x, line_y
                                    local text_w = gfx.measurestr(p.content)
                                    gfx.drawstr(p.content)
                                    draw_x = draw_x + text_w
                                end
                            end
                        end
                        line_y = line_y + S(22)
                    end
                end
                
                -- Draw "Open in ReaPack" button
                if OTHER.rec_state.reapack and item.reapack_search and not item.ok then
                    local btn_y = line_y + S(5)
                    local btn_h = S(24)
                    local btn_w = S(180)
                    local btn_x = col_x + S(50)
                    
                    if btn_y + btn_h > view_y and btn_y < view_y + view_h then
                        if btn(btn_x, btn_y, btn_w, btn_h, T("OPEN_IN_REAPACK")) then
                            if reaper.ReaPack_BrowsePackages then
                                reaper.ReaPack_BrowsePackages(item.reapack_search)
                            else
                                reaper.MB(T("REAPACK_NOT_FOUND"), T("ERROR"), 0)
                            end
                        end
                    end
                end
            end
        end
        draw_y = draw_y + entry_h
    end
    
    -- Header Background (Mask) & Title Elements (Moved here for Z-ordering)
    -- Opaque background to mask scrolling content (inset to preserve border)
    set_color(UI.C_DARK_GREY) 
    gfx.rect(bx + S(4), by + S(4), bw - S(8), S(56), 1)

    -- Close Button (Red X)
    local btn_size = S(24)
    local cbx, cby = bx + bw - btn_size - S(10), by + S(10)
    local over_close = gfx.mouse_x >= cbx and gfx.mouse_x <= cbx + btn_size and 
                      gfx.mouse_y >= cby and gfx.mouse_y <= cby + btn_size
    
    if over_close then
        set_color(UI.C_HILI_RED_BRIGHT)
        if is_mouse_clicked() then
            OTHER.rec_state.show = false
            return
        end
    else
        set_color(UI.C_HILI_RED_DARK)
    end

    gfx.rect(cbx, cby, btn_size, btn_size, 1)
    set_color(UI.C_WHITE)
    gfx.line(cbx + 5, cby + 5, cbx + btn_size - 5, cby + btn_size - 5)
    gfx.line(cbx + btn_size - 5, cby + 5, cbx + 5, cby + btn_size - 5)
    
    -- Content Header (Re-drawn over mask)
    local title = T("ENVIRONMENT_SETUP")
    gfx.setfont(F.dict_bld)
    set_color(UI.C_TXT)
    local title_max_w = bw - S(80)
    local title_display = fit_text_width(title, title_max_w)
    
    gfx.x, gfx.y = bx + S(20), by + S(15)
    gfx.drawstr(title_display)

    -- Scrollbar indicator if needed (thicker for visibility)
    if total_h > view_h then
        set_color(UI.C_MEDIUM_GREY)
        local sbw = S(8)  -- Increased from S(4)
        local sbx = bx + bw - sbw - S(4)
        local progress = OTHER.rec_state.scroll_y / max_scroll
        local sb_track_h = view_h - S(10)
        local sbh = math.max(S(20), (view_h / total_h) * sb_track_h)
        local sby = view_y + progress * (sb_track_h - sbh)
        gfx.rect(sbx, sby, sbw, sbh, 1)
    end

    UI_STATE.mouse_handled = true
end

--- Open the text editor modal
--- @param initial_text string Text to edit
--- @param callback function Function to call on save(new_text)
--- @param line_idx number|nil Optional context line index
--- @param all_lines table|nil Optional context all lines
local function open_text_editor(initial_text, callback, line_idx, all_lines, is_director_mode)
    text_editor_state.active = true
    text_editor_state.focus = true -- Auto-focus the input field
    text_editor_state.needs_focus_nudge = 10 -- Nudge focus for several frames to overcome OS delays
    text_editor_state.text = initial_text or ""
    text_editor_state.cursor = #text_editor_state.text
    text_editor_state.anchor = text_editor_state.cursor
    text_editor_state.is_director_mode = is_director_mode
    text_editor_state.callback = callback
    text_editor_state.context_line_idx = line_idx
    text_editor_state.context_all_lines = all_lines

    if dict_modal.show then
        dict_modal.show = false
    end
    
    -- Suppress interaction for a split second to prevent double-click bleed-through
    text_editor_state.interaction_start_time = reaper.time_precise() + 0.25
    
    -- Init History
    text_editor_state.history = {
        {
            text = text_editor_state.text,
            cursor = text_editor_state.cursor,
            anchor = text_editor_state.anchor
        }
    }
    text_editor_state.history_pos = 1
end

--- Draw main navigation UI_STATE.tabs
function DRAW_TABS.draw_tabs()
    local btn_scan_w = S(30)
    local btn_dash_w = S(30) -- New "D" button width
    
    -- Calculate available width for main tabs
    -- Total = Dashboard + gap + Tabs + gap + Scan
    local total_tab_w = gfx.w - btn_scan_w - btn_dash_w
    local tab_w_base = total_tab_w / #UI_STATE.tabs
    local h = S(25)
    gfx.setfont(F.std)
    local _, dh = gfx.measurestr(T("D_UPPER"))
    
    -- 1. Dashboard Button ("Д")
    local d_x = 0
    local dash_col = DEADLINE.get_overall_urgency()
    set_color(dash_col)
    gfx.rect(d_x, 0, btn_dash_w, h, 1)
    
    -- DEADLINE GIF ANIMATION (if urgent/red)
    local animation_drawn = false
    if dash_col == UI.C_RED and OTHER.DEADLINE_GIF_CFG and UI_STATE.current_tab == 1 then
        local cfg = OTHER.DEADLINE_GIF_CFG
        local img_w, img_h = gfx.getimgdim(cfg.buf)
        if img_w > 0 then
            animation_drawn = true -- Never show "Д" if on first tab and red
            local frame_w = cfg.frame_w or (img_w / cfg.frames)
            local frame_h = img_h
            local elapsed = reaper.time_precise()
            local total_cycle = cfg.frames * 7
            local cycle_idx = math.floor(elapsed * (cfg.fps or 10)) % total_cycle
            
            -- Play frames 0 to (frames-1), then pause on frame 0
            local frame_idx = (cycle_idx < cfg.frames) and cycle_idx or 0
            
            -- Center in button
            local zoom = cfg.zoom or 1
            local dest_h = h * zoom
            local dest_w = (frame_w / frame_h) * dest_h
            local gx = d_x + (btn_dash_w - dest_w) / 2
            local gy = (h - dest_h) / 2
            
            gfx.blit(cfg.buf, 1, 0, frame_idx * frame_w, 0, frame_w, frame_h, gx, gy, dest_w, dest_h)
            reaper.defer(function() end) -- Force refresh for animation
        end
    end
    
    if not animation_drawn then
        set_color(UI.C_TXT)
        local btn_dw, _ = gfx.measurestr(T("D_UPPER"))
        gfx.x = d_x + (btn_dash_w - btn_dw)/2
        gfx.y = (h - dh)/2
        gfx.drawstr(T("D_UPPER"))
    end
    
    if is_mouse_clicked() and not dict_modal.show then
        if gfx.mouse_x >= d_x and gfx.mouse_x < d_x + btn_dash_w and gfx.mouse_y >= 0 and gfx.mouse_y <= h then
            DEADLINE.dashboard_show = true
        end
    end
    
    -- 2. Main Tabs
    local tabs_start_x = btn_dash_w
    
    for i, name in ipairs(UI_STATE.tabs) do
        -- Integer calculation to prevent gaps
        local x_start = tabs_start_x + math.floor((i - 1) * total_tab_w / #UI_STATE.tabs)
        local x_end = tabs_start_x + math.floor(i * total_tab_w / #UI_STATE.tabs)
        local tab_w = x_end - x_start
        local x = x_start
        
        local is_act = (UI_STATE.current_tab == i)
        
        set_color(is_act and UI.C_TAB_ACT or UI.C_TAB_INA)
        gfx.rect(x, 0, tab_w, h, 1)


        set_color(UI.C_TXT)
        gfx.setfont(F.std)
        local display_name = fit_text_width(T(name), tab_w - S(10))
        local str_w, str_h = gfx.measurestr(display_name)
        gfx.x = x + (tab_w - str_w) / 2
        gfx.y = (h - dh) / 2 -- Use same vertical centering
        gfx.drawstr(display_name)
        
        -- Click
        if is_mouse_clicked() and not dict_modal.show then
            if gfx.mouse_x >= x and gfx.mouse_x < x+tab_w and gfx.mouse_y >= 0 and gfx.mouse_y <= h then
                -- Save current tab's scroll position
                UI_STATE.tab_scroll_y[UI_STATE.current_tab] = UI_STATE.scroll_y
                UI_STATE.tab_target_scroll_y[UI_STATE.current_tab] = UI_STATE.target_scroll_y
                -- Switch tab
                UI_STATE.current_tab = i
                -- Restore new tab's scroll position
                UI_STATE.scroll_y = UI_STATE.tab_scroll_y[UI_STATE.current_tab] or 0
                UI_STATE.target_scroll_y = UI_STATE.tab_target_scroll_y[UI_STATE.current_tab] or 0
                UI_STATE.mouse_handled = true
            end
        end
    end
    
    -- 3. Jump to Region Button (Small Tab at the end)
    local btn_x = tabs_start_x + total_tab_w
    
    set_color(UI.C_TAB_INA) -- Use inactive tab color
    gfx.rect(btn_x, 0, btn_scan_w, h, 1)

    -- Achievement Logic: Animation and dot notification
    local animation_drawn = false
    local cfg = (ACHIEVEMENTS.has_new and OTHER.COPA_GIF_CFG) or OTHER.COPA_INACTIVE_CFG

    if cfg then
        local img_w, img_h = gfx.getimgdim(cfg.buf)
        if img_w > 0 then
            animation_drawn = true
            local frame_w = cfg.frames and (cfg.frame_w or (img_w / cfg.frames)) or img_w
            local frame_h = img_h
            local frame_idx = 0 -- Default to frozen first frame
            
            if ACHIEVEMENTS.has_new and cfg.frames then
                local elapsed = reaper.time_precise()
                local total_cycle = cfg.frames * 7
                local cycle_idx = math.floor(elapsed * (cfg.fps or 8)) % total_cycle
                frame_idx = (cycle_idx < cfg.frames) and cycle_idx or 0
                reaper.defer(function() end) -- Force refresh for animation
            end
            
            -- Center in button
            local zoom = cfg.zoom or 1
            local dest_h = h * zoom
            local dest_w = (frame_w / frame_h) * dest_h
            local gx = btn_x + (btn_scan_w - dest_w) / 2
            local gy = (h - dest_h) / 2
            
            gfx.blit(cfg.buf, 1, 0, frame_idx * frame_w, 0, frame_w, frame_h, gx, gy, dest_w, dest_h)

            -- Notification dot
            if ACHIEVEMENTS.has_new then
                set_color(UI.C_RED)
                local r_dot = S(3)
                gfx.circle(btn_x + btn_scan_w - r_dot - S(2), r_dot + S(2), r_dot, 1)
            end
        end
    end
    
    if not animation_drawn then
        set_color(UI.C_TXT)
        gfx.setfont(F.std)
        local bw, bh = gfx.measurestr("#")
        
        gfx.x = btn_x + (btn_scan_w - bw)/2
        gfx.y = (h - bh)/2
        gfx.drawstr("#")
    end

    if is_mouse_clicked() and not dict_modal.show then
        if gfx.mouse_x >= btn_x and gfx.mouse_x <= gfx.w and
           gfx.mouse_y >= 0 and gfx.mouse_y <= h then
            ACHIEVEMENTS.show = true
        end
    end
end

--- Tabs Views ---
--- Draw the detailed file view with import buttons and actor stats
function DRAW_TABS.draw_file()
    -- PRE-CALCULATE CONTENT HEIGHT FOR SCROLLING
    local is_narrow = gfx.w < S(470)
    local content_h = 0
    
    if not cfg.profile_edit_seen then
        content_h = content_h + S(65) + S(15)
    end
    
    -- 1. Action Buttons Height
    if is_narrow then
        content_h = content_h + S(40) + S(5) + S(40) -- Two rows
    else
        content_h = content_h + S(40) -- One row
    end
    
    -- 2. Filename display row
    if UI_STATE.ass_file_loaded and UI_STATE.current_file_name then
        content_h = content_h + S(25)
    end
    
    -- 3. Spacer before filter
    content_h = content_h + S(60)
    
    -- 4. Actor Filter Section
    if UI_STATE.ass_file_loaded then
        -- Header rows
        if is_narrow then 
            content_h = content_h + S(25) + S(25) + S(45)
        else 
            content_h = content_h + S(35) 
        end
        
        -- Actors grid
        local actor_count = 0
        for _ in pairs(ass_actors) do actor_count = actor_count + 1 end
        local cols = math.floor((gfx.w - S(40)) / S(150))
        if cols < 1 then cols = 1 end
        local row_count = math.ceil(actor_count / cols)
        
        content_h = content_h + (row_count * S(30)) + S(20)
        
        -- Statistics row
        content_h = content_h + S(45)
        
        -- Stress marks button
        content_h = content_h + S(50)
    else
        -- Help text
        content_h = content_h + S(30)
    end
    
    -- 5. Drop zone area
    content_h = content_h + S(80)

    -- Fixed jitter: Use the real height from the previous frame to stabilize clamping
    if last_file_h and last_file_h > 0 then
        content_h = last_file_h
    end

    local start_y = S(50)
    local avail_h = gfx.h - start_y
    local max_scroll = math.max(0, content_h - avail_h)
    
    -- Smooth Scroll Logic
    if gfx.mouse_wheel ~= 0 then
        UI_STATE.target_scroll_y = UI_STATE.target_scroll_y - (gfx.mouse_wheel * 0.25)
        gfx.mouse_wheel = 0
    end
    
    if UI_STATE.target_scroll_y < 0 then UI_STATE.target_scroll_y = 0 end
    if UI_STATE.target_scroll_y > max_scroll then UI_STATE.target_scroll_y = max_scroll end

    local diff = UI_STATE.target_scroll_y - UI_STATE.scroll_y
    if math.abs(diff) > 0.5 then
        UI_STATE.scroll_y = UI_STATE.scroll_y + (diff * 0.8)
    else
        UI_STATE.scroll_y = UI_STATE.target_scroll_y
    end
    
    if UI_STATE.scroll_y < 0 then UI_STATE.scroll_y = 0 end
    if UI_STATE.scroll_y > max_scroll then UI_STATE.scroll_y = max_scroll end

    local function get_y(offset)
        return start_y + offset - math.floor(UI_STATE.scroll_y)
    end

    -- Action Buttons Layout
    local padding = S(20)
    local spacing = S(5)
    local btn_h = S(40)
    
    local y_cursor = 0
    
    if not cfg.profile_edit_seen then
        local cur_y = get_y(y_cursor)
        local banner_h = S(65)
        local banner_w = gfx.w - padding * 2
        
        -- 1. Draw Red Warning Background
        set_color({1.0, 0.1, 0.1}, 0.08) -- Soft Red Background
        gfx.rect(padding, cur_y, banner_w, banner_h, 1)
        
        -- 3. Thick Red Border (2px effect)
        set_color({1.0, 0.2, 0.2}, 0.6)
        gfx.rect(padding, cur_y, banner_w, banner_h, 0)
        gfx.rect(padding + 1, cur_y + 1, banner_w - 2, banner_h - 2, 0)
        
        -- 4. Two-Line Text
        local b_btn_w = S(110)
        local text_x = padding + S(15)
        local text_max_w = banner_w - b_btn_w - S(45)
        
        -- Line 1: Strong Title
        gfx.setfont(F.std)
        set_color({1.0, 0.4, 0.4}, 1.0)
        gfx.x = text_x
        gfx.y = cur_y + S(15)
        gfx.drawstr(fit_text_width(T("TAB_FILL_ALERT_TITLE"), text_max_w))
        
        -- Line 2: Subtitle/Explanation
        gfx.setfont(F.std)
        set_color(UI.C_TXT, 0.8)
        gfx.x = text_x
        gfx.y = cur_y + S(35)
        gfx.drawstr(fit_text_width(T("TAB_FILL_ALERT_SUB_TITLE"), text_max_w))
        
        -- 5. Button
        local b_btn_h = S(38)
        local bx = gfx.w - padding - b_btn_w - S(15)
        local by = cur_y + (banner_h - b_btn_h) / 2
        
        if btn(bx, by, b_btn_w, b_btn_h, T("FILL_OUT"), {0.8, 0.2, 0.2, 1.0}, UI.C_BG) then
            ACHIEVEMENTS.open_edit_profile()
            UI_STATE.current_tab = 4
            UI_STATE.mouse_handled = true
        end
        
        y_cursor = y_cursor + banner_h + S(15)
    end
    
    local cur_y = get_y(y_cursor)
    
    -- Calculate widths based on mode
    local import_w, notes_w, deadline_w
    if is_narrow then
        import_w = gfx.w - padding * 2
        notes_w = (gfx.w - padding * 2 - spacing) / 2
        deadline_w = notes_w
    else
        import_w = S(230)
        notes_w = S(80)
        deadline_w = S(105)
    end

    gfx.setfont(F.std)
    -- 1. Import Button
    if cur_y + btn_h > start_y - S(50) and cur_y < gfx.h + S(50) then 
        if btn(padding, cur_y, import_w, btn_h, fit_text_width(T("IMPORT_FILE") .. " (.srt/.ass/.vtt/.wav)", import_w - S(10)), nil, nil, true) then
            local retval, file_list
            if reaper.JS_Dialog_BrowseForOpenFiles then
                retval, file_list = reaper.JS_Dialog_BrowseForOpenFiles(T("IMPORT_FILE"), "", "", "Supported files (*.srt;*.ass;*.vtt;*.wav)\0*.srt;*.ass;*.vtt;*.wav\0All files\0*\0", true)
            else
                retval, file_list = reaper.GetUserFileNameForRead("", T("IMPORT_FILE"), "*.srt;*.ass;*.vtt;*.wav")
            end
            
            if retval and file_list ~= "" then
                push_undo(T("IMPORT_FILE"))
                local files = {}
                if reaper.JS_Dialog_BrowseForOpenFiles then
                    local dir = file_list:match("^(.-)\0")
                    if dir then
                        for f in file_list:gmatch("\0([^\0]+)") do
                            if f ~= "" then
                                table.insert(files, dir .. "/" .. f)
                            end
                        end
                    else
                        -- Only one file selected
                        table.insert(files, file_list)
                    end
                else
                    table.insert(files, file_list)
                end
                
                local imported_count = 0
                local total_duplicates = 0
                for _, file in ipairs(files) do
                    local ext = file:match("%.([^.]+)$")
                    if ext then
                        ext = ext:lower()
                        if ext == "srt" then
                            total_duplicates = total_duplicates + import_srt(file, true)
                            imported_count = imported_count + 1
                        elseif ext == "ass" then
                            total_duplicates = total_duplicates + import_ass(file, true)
                            imported_count = imported_count + 1
                        elseif ext == "vtt" then
                            total_duplicates = total_duplicates + import_vtt(file, true)
                            imported_count = imported_count + 1
                        elseif ext == "wav" then
                            UTILS.import_compact_wav(file)
                            imported_count = imported_count + 1
                        else
                            show_snackbar(T("THE_FORMAT") .. " ." .. ext:upper() .. " " .. T("IS_NOT_SUPPORTED"), "error")
                        end
                    else
                        show_snackbar(T("TAB_FILE_FAILED_FORMAT"), "error")
                    end
                end
                
                if imported_count > 0 then
                    update_regions_cache()
                    rebuild_regions()
                    local msg = T("FILES_IMPORTED") .. ": " .. imported_count
                    if total_duplicates > 0 then msg = msg .. " (" .. T("DUPLICATES") .. ": " .. total_duplicates .. ")" end
                    show_snackbar(msg, "success")
                end
            end
        end
    end
    
    -- Positions for the remaining buttons
    local nx, dx, ny
    if is_narrow then
        -- Wrap to second row (Full Width distribution)
        y_cursor = y_cursor + btn_h + S(5)
        ny = get_y(y_cursor)
        nx = padding
        dx = padding + notes_w + spacing
    else
        -- Same row, align right
        ny = cur_y
        dx = gfx.w - padding - deadline_w
        nx = dx - spacing - notes_w
    end
    
    -- 2. Notes Button
    if ny + btn_h > start_y - S(50) and ny < gfx.h + S(50) then
        if btn(nx, ny, notes_w, btn_h, fit_text_width(T("RETAKES"), notes_w - S(10)), nil, nil, true) then
            gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
            local ret = gfx.showmenu(T("TAB_FILE_IMPORT_FROM_TEXT") .. "|" .. T("TAB_FILE_IMPORT_FROM_FILE"))
            if ret == 1 then import_notes()
            elseif ret == 2 then import_notes_from_csv() end
        end
    end
    
    -- 3. Deadline Button
    if ny + btn_h > start_y - S(50) and ny < gfx.h + S(50) then
        local dl_text = T("DEADLINE")
        local dl_bg = UI.C_ROW
        local dl_txt = nil -- Use default text color
        if DEADLINE.project_deadline then
            local days = math.ceil((DEADLINE.project_deadline - os.time()) / 86400)
            if days < 0 then
                dl_text = T("DEADLINE_PASSED")
                dl_bg = UI.C_SNACK_ERROR
                dl_txt = UI.C_WHITE
            elseif days == 0 then
                dl_text = T("DEADLINE_TODAY")
                dl_bg = UI.C_RED
            else
                dl_text = os.date("%d.%m", DEADLINE.project_deadline) .. " (" .. days .. T("D") .. ")"
                if days == 1 then
                    dl_bg = UI.C_ORANGE
                else
                    dl_bg = UI.C_SNACK_SUCCESS
                    dl_txt = UI.C_WHITE
                end
            end
        end
        
        if btn(dx, ny, deadline_w, btn_h, fit_text_width(dl_text, deadline_w - S(10)), dl_bg, dl_txt, true) then
            DEADLINE.open_picker(DEADLINE.project_deadline, function(ts)
                DEADLINE.set(ts)
                show_snackbar(ts and (T("DEADLINE_IS_SET") .. ": " .. os.date("%d.%m.%Y", ts)) or T("DEADLINE_CANCELED"), "info")
            end)
        end
    end
    
    y_cursor = y_cursor + btn_h + S(10)
    
    -- Filename Display Row
    if UI_STATE.ass_file_loaded and UI_STATE.current_file_name then
        local fn_y = get_y(y_cursor)
        if fn_y + S(75) > start_y and fn_y < gfx.h + S(50) then
            gfx.setfont(F.tip)
            set_color(UI.C_MEDIUM_GREY)
            local str = T("SELECTED") .. ": " .. UI_STATE.current_file_name
            str = fit_text_width(str, gfx.w - padding * 2)
            gfx.x = padding
            gfx.y = fn_y
            gfx.drawstr(str)
        end
        y_cursor = y_cursor + S(25)
    end
    
    -- Active Dictionaries Row
    do
        local active_dict_names = {}
        for _, d in ipairs(DICT.dicts) do
            if DICT.is_selected(d.id) then
                table.insert(active_dict_names, d.name)
            end
        end
        if #active_dict_names > 0 then
            y_cursor = y_cursor + S(5)
            local ad_y = get_y(y_cursor)
            if ad_y + S(70) > start_y and ad_y < gfx.h + S(50) then
                gfx.setfont(F.tip)
                set_color(UI.C_LIGHT_GREY)
                local ad_str = T("ACTIVE_GLOSSARIES") .. ": " .. table.concat(active_dict_names, ", ")
                ad_str = fit_text_width(ad_str, gfx.w - padding * 2)
                gfx.x = padding
                gfx.y = ad_y
                gfx.drawstr(ad_str)
            end
            y_cursor = y_cursor + S(20)
        end
    end
    
    y_cursor = y_cursor + S(25)

    -- Actor Filter (if loaded)
    if UI_STATE.ass_file_loaded then
        local t_y = get_y(y_cursor)
        local actor_header_y = t_y
        
        -- Statistics calculation (needed for both layouts)
        local selected_count = 0
        local total_count = 0
        for _, v in pairs(ass_actors) do
            total_count = total_count + 1
            if v then selected_count = selected_count + 1 end
        end
        local count_text = selected_count .. "/" .. total_count

        if is_narrow then
            -- NARROW LAYOUT
            if t_y + S(160) > start_y and t_y < gfx.h + S(50) then
                -- Row 1: Title + Count
                set_color(UI.C_TXT)
                gfx.setfont(F.std)
                gfx.x, gfx.y = S(20), t_y
                gfx.drawstr(fit_text_width(T("ACTOR_FILTER"), gfx.w - S(100)))
                
                local tw, th = gfx.measurestr(count_text)
                gfx.x = gfx.w - S(20) - tw
                gfx.drawstr(count_text)
            end

            y_cursor = y_cursor + S(25)
            t_y = get_y(y_cursor)
            
            if t_y + S(70) > start_y and t_y < gfx.h + S(50) then
                -- Row 2: Quick Select
                if btn(S(20), t_y, gfx.w - S(40), S(20), fit_text_width(T("QUICK_SELECTION"), gfx.w - S(50)), UI.C_ROW, nil, true) then
                    local ret, csv = reaper.GetUserInputs(T("QUICK_ACTOR_SELECTION"), 1, T("LIST_OF_ACTORS_COMMAN"), "")
                    if ret then
                        push_undo(T("QUICK_ACTOR_SELECTION"))
                        for k in pairs(ass_actors) do ass_actors[k] = false end
                        for _, l in ipairs(ass_lines) do l.enabled = false end
                        local selected = {}
                        for act_name in csv:gmatch("([^,]+)") do
                            act_name = act_name:match("^%s*(.-)%s*$")
                            if ass_actors[act_name] ~= nil then
                                ass_actors[act_name] = true
                                selected[act_name] = true
                            end
                        end
                        for _, l in ipairs(ass_lines) do
                            if selected[l.actor] then l.enabled = true end
                        end
                        UI_STATE._markers_is_dirty = true
                        rebuild_regions()
                    end
                end
            end

            y_cursor = y_cursor + S(25)
            t_y = get_y(y_cursor)
            
            if t_y + S(70) > start_y and t_y < gfx.h + S(50) then
                -- Row 3: None / All
                local half_w = (gfx.w - S(50)) / 2
                if btn(S(20), t_y, half_w, S(20), fit_text_width(T("NO_ONE"), half_w - S(10)), UI.C_ROW, nil, true) then
                    push_undo(T("HIDE_ALL"))
                    for k in pairs(ass_actors) do ass_actors[k] = false end
                    for _, l in ipairs(ass_lines) do l.enabled = false end
                    UI_STATE._markers_is_dirty = true
                    rebuild_regions()
                end
                if btn(S(20) + half_w + S(10), t_y, half_w, S(20), fit_text_width(T("EVERYONE"), half_w - S(10)), UI.C_ROW, nil, true) then
                    push_undo(T("SHOW_ALL"))
                    for k in pairs(ass_actors) do ass_actors[k] = true end
                    for _, l in ipairs(ass_lines) do l.enabled = true end
                    UI_STATE._markers_is_dirty = true
                    rebuild_regions()
                end
            end
            
            y_cursor = y_cursor + S(45)
        else
            -- WIDE LAYOUT
            if t_y + S(70) > start_y and t_y < gfx.h + S(50) then
                set_color(UI.C_TXT)
                gfx.setfont(F.std)
                gfx.x, gfx.y = S(20), t_y
                gfx.drawstr(fit_text_width(T("FILTER") .. ":", S(60)))
                
                -- Batch Select
                local quick_btn_w = S(110)
                if btn(S(80), t_y - S(2), quick_btn_w, S(20), fit_text_width(T("QUICK_SELECTION"), quick_btn_w - S(5)), UI.C_ROW, nil, true) then
                    local ret, csv = reaper.GetUserInputs(T("QUICK_ACTOR_SELECTION"), 1, T("LIST_OF_ACTORS_COMMAN"), "")
                    if ret then
                        push_undo(T("QUICK_ACTOR_SELECTION"))
                        for k in pairs(ass_actors) do ass_actors[k] = false end
                        for _, l in ipairs(ass_lines) do l.enabled = false end
                        local selected = {}
                        for act_name in csv:gmatch("([^,]+)") do
                            act_name = act_name:match("^%s*(.-)%s*$")
                            if ass_actors[act_name] ~= nil then
                                ass_actors[act_name] = true
                                selected[act_name] = true
                            end
                        end
                        for _, l in ipairs(ass_lines) do
                            if selected[l.actor] then l.enabled = true end
                        end
                        UI_STATE._markers_is_dirty = true
                        rebuild_regions()
                    end
                end
                
                -- Right side layout: [count text] [None] [All]
                local right_edge = gfx.w - S(20)
                local all_btn_w = S(50)
                local none_btn_w = S(75)
                
                local all_btn_x = right_edge - all_btn_w
                local none_btn_x = all_btn_x - none_btn_w - S(5)
                
                local tw, th = gfx.measurestr(count_text)
                local count_x = none_btn_x - tw - S(10)
                
                -- Check for overlap between Quick Select and Count
                if count_x < S(80) + quick_btn_w + S(10) then
                    count_x = S(80) + quick_btn_w + S(10)
                end
                
                gfx.x, gfx.y = count_x, t_y
                gfx.drawstr(count_text)
                
                if btn(none_btn_x, t_y - S(2), none_btn_w, S(20), fit_text_width(T("NO_ONE"), none_btn_w - S(5)), UI.C_ROW, nil, true) then
                    push_undo(T("HIDE_ALL"))
                    for k in pairs(ass_actors) do ass_actors[k] = false end
                    for _, l in ipairs(ass_lines) do l.enabled = false end
                    UI_STATE._markers_is_dirty = true
                    rebuild_regions()
                end
                
                if btn(all_btn_x, t_y - S(2), all_btn_w, S(20), fit_text_width(T("EVERYONE"), all_btn_w - S(5)), UI.C_ROW, nil, true) then
                    push_undo(T("SHOW_ALL"))
                    for k in pairs(ass_actors) do ass_actors[k] = true end
                    for _, l in ipairs(ass_lines) do l.enabled = true end
                    UI_STATE._markers_is_dirty = true
                    rebuild_regions()
                end
            end
            y_cursor = y_cursor + S(35)
        end
        
        -- Sort actors for consistent display
        local sorted_actors = {}
        for act in pairs(ass_actors) do table.insert(sorted_actors, act) end
        table.sort(sorted_actors)
        
        -- AUTO-GRID CALCULATION
        local item_w = S(150) -- Min width per item
        local cols = math.floor((gfx.w - S(40)) / item_w)
        if cols < 1 then cols = 1 end
        
        -- Calculate rows needed
        local row_count = math.ceil(#sorted_actors / cols)
        
        -- Pre-calculate stats per actor and dubber assignments for tooltips
        local actor_tooltips = {}
        local actor_to_dubber = {}
        
        -- Get dubber assignments
        if DUBBERS and DUBBERS.data and DUBBERS.data.assignments then
            for d_name, assigned in pairs(DUBBERS.data.assignments) do
                for actor_name, is_on in pairs(assigned) do
                    if is_on then
                        -- Store as string, handle multiple dubbers if assigned (rare but possible)
                        if actor_to_dubber[actor_name] then
                            actor_to_dubber[actor_name] = actor_to_dubber[actor_name] .. ", " .. d_name
                        else
                            actor_to_dubber[actor_name] = d_name
                        end
                    end
                end
            end
        end

        for _, line in ipairs(ass_lines) do
            local act = line.actor or "Default"
            if not actor_tooltips[act] then actor_tooltips[act] = {replicas = 0, words = 0} end
            actor_tooltips[act].replicas = actor_tooltips[act].replicas + 1
            local clean = (line.text or ""):gsub("{{+.-}}+", ""):gsub("{.-}", ""):gsub("\\[Nnh]", " ")
            local _, count = clean:gsub("%S+", "")
            actor_tooltips[act].words = actor_tooltips[act].words + count
        end

        for i, act in ipairs(sorted_actors) do
            -- Grid Indexing (0-based for math)
            local idx = i - 1
            local col = idx % cols
            local row = math.floor(idx / cols)
            
            local x_pos = S(20) + (col * item_w)
            local y_rel = y_cursor + (row * S(30)) -- 30px per row
            local chk_y = get_y(y_rel)
            
            if chk_y + S(80) > start_y and chk_y < gfx.h + S(50) then
                local enabled = ass_actors[act]
                
                -- HOVER CHECK
                if UI_STATE.window_focused and gfx.mouse_y > S(25) and
                   gfx.mouse_x >= x_pos - S(2) and gfx.mouse_x <= x_pos + item_w - S(5) and
                   gfx.mouse_y >= chk_y - S(2) and gfx.mouse_y <= chk_y + S(22) then
                    set_color(UI.C_HILI_WHITE) -- Slight white highlight
                    gfx.rect(x_pos - S(2), chk_y - S(2), item_w - S(3), S(24), 1)
                end
                
                -- Checkbox
                -- Use actor color for visual feedback
                local a_col = get_actor_color(act)

                if not cfg.random_color_actors then
                    a_col = 2500134 -- Default color {0.15, 0.15, 0.15}
                end

                local native_r, native_g, native_b = reaper.ColorFromNative(a_col & 0xFFFFFF)
                
                -- Draw filled background with actor color (dimmed slightly?)
                -- Or stroke? Let's do filled for visibility.
                if enabled then
                    set_color({native_r/255, native_g/255, native_b/255})
                    gfx.rect(x_pos, chk_y, S(20), S(20), 1) -- Filled

                    set_color(UI.C_ED_GUTTER)
                    gfx.rect(x_pos, chk_y, S(20), S(20), 0)
                    
                    -- Checkmark (Contrast color? Black or White depending on luminance)
                    local lum = (native_r * 0.299 + native_g * 0.587 + native_b * 0.114) / 255
                    if lum > 0.5 then set_color(UI.C_BLACK) else set_color(UI.C_WHITE) end
                else
                    -- Disabled: Grey outline
                    set_color(UI.C_ED_GUTTER)
                    gfx.rect(x_pos, chk_y, S(20), S(20), 0) -- Outline
                    
                    -- Small indicator of their color inside?
                    set_color({native_r/255, native_g/255, native_b/255})
                    gfx.rect(x_pos + S(6), chk_y + S(6), S(8), S(8), 1)
                end

                if enabled then
                    -- Checkmark (tick)
                    -- Left stroke (shorter)
                    gfx.line(x_pos + S(4), chk_y + S(10), x_pos + S(8), chk_y + S(16))
                    gfx.line(x_pos + S(5), chk_y + S(10), x_pos + S(9), chk_y + S(16)) -- Bold
                    
                    -- Right stroke (longer)
                    gfx.line(x_pos + S(8), chk_y + S(16), x_pos + S(16), chk_y + S(4))
                    gfx.line(x_pos + S(9), chk_y + S(16), x_pos + S(17), chk_y + S(4)) -- Bold
                end
                
                -- Label (Truncate if too long)
                set_color(UI.C_TXT)
                gfx.setfont(F.std)  -- Explicitly set font to prevent jumping
                gfx.x, gfx.y = x_pos + S(25), chk_y + S(2)
                
                local max_txt_w = item_w - S(30) -- padding
                local display_act = fit_text_width(act, max_txt_w)
                
                gfx.setfont(F.std)  -- Re-set after fit_text_width in case it changed
                gfx.drawstr(display_act, 4 | 256, x_pos + item_w - S(5), chk_y + S(20))

                -- Tooltip Logic
                if UI_STATE.window_focused and gfx.mouse_y > S(25) and
                   gfx.mouse_x >= x_pos - S(2) and gfx.mouse_x <= x_pos + item_w - S(5) and
                   gfx.mouse_y >= chk_y - S(2) and gfx.mouse_y <= chk_y + S(22) then
                    
                    local stats = actor_tooltips[act] or {replicas = 0, words = 0}
                    local assigned_dubber = actor_to_dubber[act]
                    local dubber_info = assigned_dubber and ("\n—\n" .. T("DUBBER") .. ": " .. assigned_dubber) or "\n—\n"
                    local tooltip = string.format(T("TOOLTIP_DUBBER_FILE"), act, dubber_info, stats.replicas, stats.words)
                    
                    local tip_id = "actor_tip_" .. act
                    if UI_STATE.tooltip_state.hover_id ~= tip_id then
                        UI_STATE.tooltip_state.hover_id = tip_id
                        UI_STATE.tooltip_state.start_time = reaper.time_precise()
                    end
                    UI_STATE.tooltip_state.text = tooltip
                end
            
                -- Click Logic
                if is_mouse_clicked() and gfx.mouse_y > S(25) then
                    -- Hit test
                    if gfx.mouse_x >= x_pos and gfx.mouse_x <= x_pos + item_w - S(5) and
                       gfx.mouse_y >= chk_y and gfx.mouse_y <= chk_y + S(20) then
                        push_undo(T("TAB_FILE_ACTOR_VISIBILITY") .. act)
                        local new_state = not enabled
                        ass_actors[act] = new_state
                        -- Batch update all lines for this actor
                        for _, l in ipairs(ass_lines) do
                            if l.actor == act then l.enabled = new_state end
                        end
                        UI_STATE._markers_is_dirty = true
                        rebuild_regions()
                    end
                elseif is_right_mouse_clicked() and gfx.mouse_y > S(25) then
                    -- Right-click hit test for actor management menu
                    if gfx.mouse_x >= x_pos and gfx.mouse_x <= x_pos + item_w - S(5) and
                       gfx.mouse_y >= chk_y and gfx.mouse_y <= chk_y + S(20) then
                        
                        gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
                        -- local ret = gfx.showmenu("Змінити колір|Змінити ім'я актора||Видалити актора")
                        local ret = gfx.showmenu(T("CHANGE_COLOR") .. "|" .. T("CHANGE_ACTOR_NAME") .. "||" .. T("DELETE_ACTOR"))
                        if ret == 1 then
                            -- Handle Scheduled Color Picker (Move from main to draw_file)
                            local current_native = get_actor_color(act)

                            if current_native == 0 then current_native = 2500134 end
                            local retval, color = reaper.GR_SelectColor(reaper.GetMainHwnd(), current_native)
                            if retval > 0 then
                                local final_color = color | 0x1000000
                                ASS.actor_colors[act] = final_color
                                OTHER.update_global_actor_color(act, final_color)
                                
                                cfg.random_color_actors = true
                                rebuild_regions()
                                save_project_data()
                                reaper.MarkProjectDirty(0) -- SAVE ON CHANGE
                            end
                        elseif ret == 2 then
                            local ok, new_name = reaper.GetUserInputs(T("TAB_FILE_C_ACTOR_NAME"), 1, T("TAB_FILE_C_ACTOR_NAME_EXT"), act)
                            if ok then
                                -- Remove variation selector (U+FE0F = \239\184\143) and trim spaces
                                new_name = new_name:gsub("\239\184\143", ""):match("^%s*(.-)%s*$")
                                
                                push_undo(T("TAB_FILE_C_ACTOR_NAME"))
                                -- Update lines
                                for _, l in ipairs(ass_lines) do
                                    if l.actor == act then l.actor = new_name end
                                end
                                -- Update actors state
                                local state = ass_actors[act]
                                ass_actors[act] = nil
                                if state ~= nil then
                                    ass_actors[new_name] = state
                                else
                                    ass_actors[new_name] = true
                                end
                                -- Update color: ALWAYS preserve the color even if it was auto-generated
                                local current_color = get_actor_color(act)
                                if current_color and current_color ~= 0 then
                                    ASS.actor_colors[new_name] = current_color
                                end
                                -- Clear the old name's color just in case
                                ASS.actor_colors[act] = nil
                                
                                cleanup_actors()
                                rebuild_regions()
                                save_project_data()
                                reaper.MarkProjectDirty(0) -- SAVE ON CHANGE
                            end
                        elseif ret == 3 then
                            local confirm = reaper.MB(T("DELETE_ACTOR") .. " '" .. act .. "' " .. T("AND_ALL_HIS_LINES"), T("CONFIRMATION"), 4)
                            if confirm == 6 then
                                push_undo(T("REMOVING_AN_ACTOR") .. act)
                                
                                -- Remove from actors list
                                ass_actors[act] = nil
                                ASS.actor_colors[act] = nil
                                
                                -- Remove all lines for this actor in one pass (O(N) vs O(N^2))
                                local new_lines = {}
                                for _, line in ipairs(ass_lines) do
                                    if line.actor ~= act then
                                        table.insert(new_lines, line)
                                    end
                                end
                                ass_lines = new_lines

                                cleanup_actors()
                                rebuild_regions()
                                save_project_data()
                                reaper.MarkProjectDirty(0) -- SAVE ON CHANGE
                            end
                        end
                        UI_STATE.mouse_handled = true -- Suppress global context menu
                    end
                end
            end
        end
        
        y_cursor = y_cursor + (row_count * S(30)) + S(20)

        -- Statistics: Count Replicas and Words for Selected Actors
        local stats_replicas = 0
        local stats_words = 0
        local stats_time = 0
        
        for _, line in ipairs(ass_lines) do
            if line.enabled then
                stats_replicas = stats_replicas + 1
                -- Word count: Strip tags, convert breaks to spaces, count non-whitespace chunks
                local clean = (line.text or ""):gsub("{{+.-}}+", ""):gsub("{.-}", ""):gsub("\\[Nnh]", " ")
                local _, count = clean:gsub("%S+", "")
                stats_words = stats_words + count
                -- Calculate time
                if line.t1 and line.t2 then
                    stats_time = stats_time + (line.t2 - line.t1)
                end
            end
        end
        
        local stats_y = get_y(y_cursor)
        if stats_y + S(90) > start_y and stats_y < gfx.h + S(50) then
            set_color(UI.C_TXT)
            gfx.setfont(F.std)
            gfx.x = S(20)
            gfx.y = stats_y
            local time_str = format_time_hms(stats_time)
            local str = T("SELECTED") .. ": " .. stats_replicas .. T("TAB_FILE_START_LINES") .. stats_words .. T("TAB_FILE_START_WORDS_TIME") .. time_str
            local bw, bh = gfx.measurestr(str)
            gfx.drawstr(fit_text_width(str, gfx.w - S(40)))
            
            -- Hook right click for quick copy
            if is_mouse_clicked(2) and not UI_STATE.mouse_handled and gfx.mouse_y > S(25) and gfx.mouse_y >= stats_y and gfx.mouse_y <= stats_y + bh and gfx.mouse_x >= S(20) and gfx.mouse_x <= S(20) + bw then
                gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
                local ret = gfx.showmenu(T("TAB_FILE_COPY_START"))
                UI_STATE.mouse_handled = true
                if ret == 1 then
                    copy_actors_statistics(false)
                elseif ret == 2 then
                    copy_actors_statistics(true)
                end
            end
        end
        y_cursor = y_cursor + S(45)

        -- Apply Stress Marks Button
        local s_y = get_y(y_cursor)
        if s_y + S(75) > start_y and s_y < gfx.h + S(50) then
            -- CATS EASTER EGG
            if not is_narrow then
                local draw_w, draw_h = S(100), S(100)
                local dot_x = gfx.w - S(18)
                local dot_y = s_y - S(2)
                if UI_STATE.show_cats then
                    local cfg = OTHER.CATS_CFG
                    if cfg then
                        local frame = math.floor((reaper.time_precise() * cfg.fps) % cfg.frames)
                        local gx, gy = dot_x - draw_w + S(14), dot_y - draw_h + S(12)
                        
                        gfx.mode = 0
                        gfx.a = 1
                        gfx.blit(cfg.buf, 1, 0, frame * cfg.frame_w, 0, cfg.frame_w, cfg.frame_w, gx, gy, draw_w, draw_h)
                        
                        if is_mouse_clicked() and not UI_STATE.mouse_handled and 
                           gfx.mouse_x >= gx and gfx.mouse_x <= gx + draw_w and 
                           gfx.mouse_y >= gy and gfx.mouse_y <= gy + draw_h then
                            UI_STATE.show_cats = false
                            UI_STATE.mouse_handled = true
                        end
                    end
                else
                    set_color(UI.C_TAB_ACT)
                    gfx.rect(dot_x - 2, dot_y - 2, 2, 2, 1)
                    if is_mouse_clicked() and not UI_STATE.mouse_handled and 
                       gfx.mouse_x >= dot_x - 10 and gfx.mouse_x <= dot_x and 
                       gfx.mouse_y >= dot_y - 10 and gfx.mouse_y <= dot_y then
                        UI_STATE.show_cats = true
                        UI_STATE.mouse_handled = true
                    end
                end
            end

            local is_running = UI_STATE.script_loading_state.active
            local btn_text = is_running and T("AI_PROCESSING") or T("APPLY_ACCENTS")
            local btn_col = is_running and UI.C_BTN_H or UI.C_TAB_ACT
            
            if btn(S(20), s_y, gfx.w - S(40), S(40), fit_text_width(btn_text, gfx.w - S(60)), btn_col, nil, true) and not is_running then
                push_undo(T("APPLY_ACCENTS_UNDO"))
                apply_stress_marks_async()
            end
        end
        y_cursor = y_cursor + S(50)
    else
        y_cursor = y_cursor + (is_narrow and S(30) or 0)
        -- Default text
        local t_y = get_y(y_cursor)
        if t_y + S(70) > start_y and t_y < gfx.h + S(50) then
            gfx.setfont(F.std)
            gfx.x, gfx.y = S(20), t_y
            local name = (cfg.dubber_name and cfg.dubber_name ~= "") and cfg.dubber_name or (os.getenv("USER") or os.getenv("USERNAME") or T("USER"))
            local txt_see_more_options = fit_text_width(T("HELLO") .. ": " .. name .. "\n" .. T("TAB_FILE_IMPORT_TO_SEE_OPTIONS"), gfx.w - S(40))
            gfx.drawstr(txt_see_more_options)
        end
        y_cursor = y_cursor + S(65)
    end
    
    -- Drop Zone Visual
    local drop_y = get_y(y_cursor)
    if drop_y + S(110) > start_y and drop_y < gfx.h + S(50) then
        local dw = gfx.w - S(40)
        local dh = S(60)
        local dx = S(20)
        
        -- Dashed Border
        set_color(UI.C_HILI_GREY_LOW)
        for dash_x = dx, dx + dw - S(10), S(10) do
            gfx.line(dash_x, drop_y, dash_x + S(5), drop_y)
            gfx.line(dash_x, drop_y + dh, dash_x + S(5), drop_y + dh)
        end
        for dash_y = drop_y, drop_y + dh - S(10), S(10) do
            gfx.line(dx, dash_y, dx, dash_y + S(5))
            gfx.line(dx + dw, dash_y, dx + dw, dash_y + S(5))
        end
        
        -- Text
        set_color(UI.C_HILI_GREY_MID)
        gfx.setfont(F.std)
        local str = fit_text_width(T("TAB_FILE_DRAG_TEXT"), dw - S(20))
        local sw, sh = gfx.measurestr(str)
        gfx.x, gfx.y = dx + (dw - sw) / 2, drop_y + (dh - sh) / 2
        gfx.drawstr(str)
    end
    y_cursor = y_cursor + S(70)

    -- Footer
    local footer_txt = fit_text_width(T("TAB_FILE_FOOTER_TEXT"), gfx.w - S(10))
    gfx.setfont(F.tip)
    gfx.x, gfx.y = padding, get_y(y_cursor)
    if gfx.y + S(70) > start_y and gfx.y < gfx.h + S(50) then
        gfx.drawstr(footer_txt)
    end

    -- Click to Copy handle (using existing helpers)
    local f_sy = get_y(y_cursor)
    if f_sy + S(20) > start_y and f_sy < gfx.h then
        local tw, th = gfx.measurestr(footer_txt)
        if is_mouse_clicked() and gfx.mouse_y > S(25) and gfx.mouse_x >= padding and gfx.mouse_x <= padding + tw and
           gfx.mouse_y >= f_sy and gfx.mouse_y <= f_sy + th then
            set_clipboard("@fusion_ford")
            show_snackbar(T("COPIED") .. ": @fusion_ford", "info")
            ACHIEVEMENTS.add_stat("ach_25_count", 1)
        end
    end
    y_cursor = y_cursor + S(40)

    -- Context Menu (Right Click on background)
    if is_mouse_clicked(2) and not UI_STATE.mouse_handled then
        gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
        local is_docked = gfx.dock(-1) > 0
        local dock_check = is_docked and "!" or ""
        
        local has_dubbers = DUBBERS.data and DUBBERS.data.names and #DUBBERS.data.names > 0
        local dubbers_ass = has_dubbers and "||" .. T("EXPORT_ASS_SPLIT_DUBBERS") or ""
        local menu = "|>" .. T("SPECIAL_ACTIONS") .. "|" .. T("DELETE_ALL_DATA") .. "||" .. T("CREATE_TEXT_ITEMS_FROM_REGIONS") .. "|" .. T("OPEN_TEXT_ITEMS_STYLE") .. "||" .. T("CALCULATE_LINES_BY_ACTORS") .. "|" .. T("REMOVE_ACCENTS_FROM_LINES") .. "||" .. T("COMPACT_RENDER_WAV") .. "|<|||" .. T("SPLIT_BY_DUBBERS") .. "|" .. T("VIEW_MY_DEADLINES") .. "||>" .. T("EXPORT_SUBTITLES") .. "|" .. T("EXPORT_AS_SRT") .. "|" .. T("EXPORT_AS_ASS") .. dubbers_ass .. "|<"

        -- Add "Change Dubber" submenu if dubbers exist
        if has_dubbers then
            local dubber_menu_items = {}
            for i, d_name in ipairs(DUBBERS.data.names) do
                local prefix = DUBBERS.is_dubber_active(d_name) and "!" or ""
                table.insert(dubber_menu_items, prefix .. d_name)
            end
            menu = menu .. "|>" .. T("CHANGE_THE_DUBBER") .. "|" .. table.concat(dubber_menu_items, "|") .. "|<"
        end
        
        -- Add "Словники" submenu from user_dictionaries.json
        DICT.load(true) -- always reload from disk on context menu open
        local dict_count = #DICT.dicts
        if dict_count > 0 then
            local dict_menu_items = {}
            for _, d in ipairs(DICT.dicts) do
                local prefix = DICT.is_selected(d.id) and "!" or ""
                -- Visually replace pipes in names for menu display (since | is the separator)
                local safe_name = d.name:gsub("|", "¦")
                table.insert(dict_menu_items, prefix .. safe_name)
            end
            menu = menu .. "||>" .. T("DICTIONARIES") .. "|" .. table.concat(dict_menu_items, "|") .. "|<"
        else
            menu = menu .. T("DICTIONARIES_NOT_FOUND_EXT")
        end
        
        menu = menu .. "||" .. dock_check .. T("DOCK_THE_WINDOW")
        
        local ret = gfx.showmenu(menu)
        UI_STATE.mouse_handled = true -- Tell framework we handled this click
        
        -- Mapping logic for dynamic menu
        -- Fixed items: 1=delete regions, 2=create text items, 3=open style editor, 4=calc replicas, 5=remove accents, 6=compact render, 7=dubbers dashboard, 8=deadlines, 9=export SRT, 10=export ASS, 11=export ASS (dubbers) if has_dubbers
        local dubber_count = has_dubbers and #DUBBERS.data.names or 0
        local base_items = has_dubbers and 11 or 10
        -- After fixed items come dubber selection items (if any), then dict items, then dock
        local dict_start = base_items + dubber_count + 1 -- +1: submenu header ">Словники" doesn't count as a clickable item
        local dock_ret = dict_start + (dict_count > 0 and dict_count or 1) -- skip dict items or the disabled placeholder
        
        if ret == 1 then
            delete_all_regions()
        elseif ret == 2 then
            UTILS.create_text_items_from_regions()
        elseif ret == 3 then
            UTILS.open_text_items_style_editor()
        elseif ret == 4 then
            UTILS.calc_track_items_by_actor()
        elseif ret == 5 then
            UTILS.remove_all_acute_for_selected_actors()
        elseif ret == 6 then
            UTILS.compact_render()
        elseif ret == 7 then
            DUBBERS.show_dashboard = true
            DUBBERS.load()
        elseif ret == 8 then
            DEADLINE.dashboard_show = true
        elseif ret == 9 then
            export_as_srt()
        elseif ret == 10 then
            export_as_ass()
        elseif has_dubbers and ret == 11 then
            DUBBERS.export_as_ass()
        elseif has_dubbers and ret >= (has_dubbers and 12 or 11) and ret <= base_items + dubber_count then
            -- Handle Dubber Selection
            local offset = has_dubbers and 11 or 10
            local selected_name = DUBBERS.data.names[ret - offset]
            DUBBERS.select_dubber(selected_name)
        elseif dict_count > 0 and ret >= dict_start and ret < dict_start + dict_count then
            -- Handle Dictionary Toggle (multi-select)
            local dict_idx = ret - dict_start + 1
            local selected_dict = DICT.dicts[dict_idx]
            if selected_dict then
                DICT.toggle(selected_dict.id)
                local state = DICT.is_selected(selected_dict.id) and T("TAB_FILE_DICT_ON") or T("TAB_FILE_DICT_OFF")
                show_snackbar(selected_dict.name .. ": " .. state, "info")
            end
        elseif ret == dock_ret then
            -- Toggle Docking
            if is_docked then
                gfx.dock(0)
                GL.last_dock_state = 0
                reaper.SetExtState(section_name, "dock", "0", true)
            else
                gfx.dock(GL.last_dock_id or 1)
                GL.last_dock_state = gfx.dock(-1)
                reaper.SetExtState(section_name, "dock", tostring(GL.last_dock_state), true)
            end
        end
    end

    last_file_h = y_cursor
    
    -- Scrollbar
    UI_STATE.target_scroll_y = draw_scrollbar(gfx.w - 10, start_y, 10, avail_h, last_file_h, avail_h, UI_STATE.target_scroll_y)
end

-- =============================================================================
-- KARAOKE MODE HELPERS
-- =============================================================================

local karaoke_cache = {} -- Cache for energy maps: [region_id] = {total_energy, points={{t, cum_energy}...}}
local KARAOKE_SAMPLES_PER_SEC = 20 -- 50ms resolution

--- Find the first track that is not muted and has items
--- @return MediaTrack|nil The track object or nil
local function get_first_valid_audio_track()
    local count = reaper.CountTracks(0)
    for i = 0, count - 1 do
        local tr = reaper.GetTrack(0, i)
        local mute = reaper.GetMediaTrackInfo_Value(tr, "B_MUTE")
        -- Simple heuristic: if not muted and has items
        if mute == 0 and reaper.CountTrackMediaItems(tr) > 0 then
            return tr
        end
    end
    return nil
end

--- Collect audio energy (RMS) map for a time range
--- @param start_time number Region start time
--- @param end_time number Region end time
--- @return table|nil Map of energy points {total, points={{t,e,cum}}}
local function get_audio_energy_map(start_time, end_time)
    local tr = get_first_valid_audio_track()
    if not tr then return nil end

    local duration = end_time - start_time
    if duration <= 0 then return nil end
    
    local sample_points = math.floor(duration * KARAOKE_SAMPLES_PER_SEC)
    if sample_points < 1 then sample_points = 1 end
    
    local step_size = duration / sample_points
    
    -- We need to access audio. 
    -- Since we can't easily access "track output" directly without playing, 
    -- we have to iterate items on the track that overlap this range.
    -- For simplicity/performance, let's assume one item or just scan the track logic 
    -- using a specialized function if possible, but Lua API for "render track audio" is complex.
    -- ALTERNATIVE: Use GetMediaItemTake_Peaks? Or AudioAccessor on specific takes.
    -- Let's iterate items in range.
    
    local mapping = {}
    local total_energy = 0
    
    -- Pre-fill mapping with time points
    for i = 0, sample_points - 1 do
        mapping[i+1] = {
            t = start_time + (i * step_size),
            e = 0, 
            cum = 0,
            raw_e = 0
        }
    end
    
    local item_count = reaper.CountTrackMediaItems(tr)
    for i = 0, item_count - 1 do
        local item = reaper.GetTrackMediaItem(tr, i)
        local i_pos = reaper.GetMediaItemInfo_Value(item, "D_POSITION")
        local i_len = reaper.GetMediaItemInfo_Value(item, "D_LENGTH")
        local i_end = i_pos + i_len
        
        -- Check overlap
        if i_end > start_time and i_pos < end_time then
            local take = reaper.GetActiveTake(item)
            if take and not reaper.TakeIsMIDI(take) then
                local aa = reaper.CreateTakeAudioAccessor(take)
                local src = reaper.GetMediaItemTake_Source(take)
                local src_sr = reaper.GetMediaSourceSampleRate(src)
                if src_sr == 0 then src_sr = 44100 end
                local num_channels = reaper.GetMediaSourceNumChannels(src)
                
                -- Rate mapping
                -- NOTE: CreateTakeAudioAccessor time=0 already maps to D_STARTOFFS in source.
                -- So we only need the offset within the item (time_in_item), NOT start_offs + time_in_item.
                local play_rate = reaper.GetMediaItemTakeInfo_Value(take, "D_PLAYRATE")
                
                -- Iterate our sample points
                for k, point in ipairs(mapping) do
                    if point.t >= i_pos and point.t < i_end then
                        local time_in_item = point.t - i_pos
                        local time_in_take = time_in_item * play_rate
                        
                        -- Read a small chunk (approx step_size)
                        local buf_size = math.ceil(step_size * src_sr)

                        -- Limit buffer for performance (don't read massive chunks if step is huge)
                        if buf_size > 2048 then buf_size = 2048 end
                        
                        local buffer = reaper.new_array(buf_size * num_channels)
                        local ret = reaper.GetAudioAccessorSamples(aa, src_sr, num_channels, time_in_take, buf_size, buffer)
                        
                        if ret > 0 then
                            local sum_sq = 0
                            local count_s = 0
                            for s_idx = 1, #buffer do
                                local s = buffer[s_idx]
                                sum_sq = sum_sq + (s * s)
                                count_s = count_s + 1
                            end
                            if count_s > 0 then
                                local rms = math.sqrt(sum_sq / count_s)
                                point.e = point.e + rms
                                point.raw_e = point.e
                            end
                        end
                    end
                end
                
                reaper.DestroyAudioAccessor(aa)
            end
        end
    end
    
    -- Integrate energy and calculate dynamic noise floor
    local all_energies = {}
    local non_zero_sum = 0
    local non_zero_count = 0
    for _, point in ipairs(mapping) do
        table.insert(all_energies, point.e)
    end
    
    -- Calculate noise floor (e.g. 20th percentile)
    table.sort(all_energies)
    local floor_idx = math.max(1, math.floor(#all_energies * 0.20))
    local noise_floor = all_energies[floor_idx] or 0
    if noise_floor < 0.05 then noise_floor = 0.05 end
    
    -- Step 1: Subtract noise floor and collect adjusted energy
    local adj_energies = {}
    for i, point in ipairs(mapping) do
        local e_adj = math.max(0, point.e - noise_floor)
        adj_energies[i] = e_adj
        if e_adj > 0 then
            non_zero_sum = non_zero_sum + e_adj
            non_zero_count = non_zero_count + 1
        end
    end
    
    -- Step 2: Peak Limiting (Cap individual points to prevent jumps on loud plosives)
    local avg_e = (non_zero_count > 0) and (non_zero_sum / non_zero_count) or 0
    local peak_cap = avg_e * 2.5 -- Slightly tighter cap for more consistency
    if peak_cap < 0.15 then peak_cap = 0.15 end
    
    for i = 1, #adj_energies do
        if adj_energies[i] > peak_cap then
            adj_energies[i] = peak_cap
        end
    end

    -- Step 3: Extra Temporal Smoothing (5-point moving average for "liquid" feel)
    local smoothed = {}
    for i = 1, #adj_energies do
        local sum = 0
        local count = 0
        -- Look 2 points back and 2 points forward
        for j = i - 2, i + 2 do
            if adj_energies[j] then
                sum = sum + adj_energies[j]
                count = count + 1
            end
        end
        smoothed[i] = sum / count
    end
    
    -- Step 4: Add Bias (Ensures constant slow flow even during silence)
    -- This prevents the "stuck" feeling during gaps.
    local bias = avg_e * 0.2 -- 20% of average speech energy as a constant floor
    if bias < 0.01 then bias = 0.01 end

    -- Final integration
    total_energy = 0
    for i, point in ipairs(mapping) do
        point.e = smoothed[i] + bias
        total_energy = total_energy + point.e
        point.cum = total_energy
    end
    
    return {
        total = total_energy,
        points = mapping
    }
end

--- Calculate current word index based on audio energy
--- @param rgn_start number Region start
--- @param rgn_end number Region end
--- @param cur_pos number Current playhead position
--- @param word_count number Total words in line
--- @return number Current word index (1-based)
local function get_karaoke_word_index(rgn_start, rgn_end, cur_pos, word_count)
    if word_count <= 1 then return 1 end
    
    -- Cache Key: region start/end (simple)
    local cache_key = tostring(rgn_start) .. "_" .. tostring(rgn_end)
    local map = karaoke_cache[cache_key]
    
    if not map then
        -- Generate map
        map = get_audio_energy_map(rgn_start, rgn_end)
        if not map or map.total <= 0.0001 then
            -- Fallback or empty audio
            -- Return nil to trigger linear fallback? Or just handle as linear.
            karaoke_cache[cache_key] = { empty = true }
             return nil
        end
        karaoke_cache[cache_key] = map
    elseif map.empty then
        return nil -- Fallback to linear
    end
    
    -- Find current cumulative energy
    local current_energy = 0
    local found = false
    
    -- Binary search or simple loop? Simple loop is fast enough for ~100 points
    local points = map.points
    if not points then return nil end
    
    -- Optimization: points are sorted by time
    -- Find point closest to cur_pos
    for i = 1, #points do
        if points[i].t >= cur_pos then
            current_energy = points[i].cum
            found = true
            break
        end
    end
    
    if not found then 
        -- Past the end?
        if cur_pos >= rgn_end then current_energy = map.total end
    end
    
    local energy_per_word = map.total / word_count
    local idx = math.floor(current_energy / energy_per_word) + 1
    if idx > word_count then idx = word_count end
    
    return idx
end

--- Draw ambient audio waveform background
--- @param map table Energy map from get_audio_energy_map
--- @param x number X pos
--- @param y number Y pos
--- @param w number Width
--- @param h number Height
--- @param progress number 0.0-1.0 Completion progress
local function draw_waveform_bg(map, x, y, w, h, progress)
    if not map or not map.points or #map.points < 2 then return end
    
    -- Save color
    local orig_r, orig_g, orig_b, orig_a = gfx.r, gfx.g, gfx.b, gfx.a

    local points = map.points
    local n_points = #points
    local step_x = w / (n_points - 1)
    
    -- Find max energy to normalize dynamically for this specific region
    local max_e = 0.0001
    for i = 1, n_points do
        local r_val = (points[i].raw_e and points[i].raw_e > 0) and points[i].raw_e or points[i].e
        if r_val > max_e then max_e = r_val end
    end
    
    local center_y = y + h / 2
    local half_h = h * 0.75
    
    -- Draw continuous filled symmetric wave using triangles
    for i = 1, n_points - 1 do
        -- Determine alpha based on progress (Requested: past part 0.05, future part 0.035)
        local segment_progress = i / n_points
        local alpha = 0.025
        if cfg.wave_bg_progress and segment_progress <= (progress or 0) then
            alpha = 0.04
        end
        gfx.set(cfg.p_cr, cfg.p_cg, cfg.p_cb, alpha)

        -- Use raw_e for visuals, fallback to a tiny amount so it doesn't just disappear
        local raw1 = (points[i].raw_e and points[i].raw_e > 0) and points[i].raw_e or (points[i].e > 0 and points[i].e or 0.001)
        local raw2 = (points[i+1].raw_e and points[i+1].raw_e > 0) and points[i+1].raw_e or (points[i+1].e > 0 and points[i+1].e or 0.001)
        
        local e1 = math.min(1.0, raw1 / max_e)
        local e2 = math.min(1.0, raw2 / max_e)
        
        local px1 = 1 + x + (i-1) * step_x
        local px2 = x + i * step_x
        
        local ph1 = e1 * half_h
        local ph2 = e2 * half_h
        
        -- Top Trapezoid
        gfx.triangle(px1, center_y, px2, center_y, px2, center_y - ph2, px1, center_y - ph1)
        -- Bottom Trapezoid
        gfx.triangle(px1, center_y + 1, px2, center_y, px2, center_y + ph2, px1, center_y + ph1)
    end
    
    -- Restore
    gfx.set(orig_r, orig_g, orig_b, orig_a)
end

-- Helper: Delete corrections logic for prompter drawer
local function prompter_delete_logic()
    local sel_indices = {}
    for idx, _ in pairs(prompter_drawer.selection) do table.insert(sel_indices, idx) end
    
    if #sel_indices > 0 then
        push_undo(T("DELETING_RETAKES"))
        -- Sort descending to avoid index shift issues (though markers are by index, it's safer)
        table.sort(sel_indices, function(a,b) return a > b end)
        for _, m_idx in ipairs(sel_indices) do
            reaper.DeleteProjectMarker(0, m_idx, false)
        end
        prompter_drawer.selection = {}
        prompter_drawer.last_selected_idx = nil
        reaper.UpdateTimeline()
        -- Invalidate caches
        ass_markers = capture_project_markers()
        prompter_drawer.marker_cache.count = -1
        prompter_drawer.filtered_cache.state_count = -1
        prompter_drawer.has_markers_cache.count = -1
        table_data_cache.state_count = -1
        last_layout_state.state_count = -1
        
        show_snackbar(T("RETAKES_DELETED") .. #sel_indices, "error")
    end
end

--- Draw prompter display with current and next subtitles
function DRAW_WINDOW.draw_prompter_drawer(input_queue)
    update_marker_cache()
    
    local drawer_top_y = S(25)
    local drawer_x = cfg.p_drawer_left and 0 or (gfx.w - prompter_drawer.width)
    local max_w = math.floor(gfx.w * 0.95)

    if not prompter_drawer.open then
        -- Performance-optimized marker check
        local state_count = reaper.GetProjectStateChangeCount(0)
        if state_count ~= prompter_drawer.has_markers_cache.count then
            if prompter_drawer.has_markers_cache.count == -1 or UTILS.is_markers_regions_changed() then
                prompter_drawer.has_markers_cache.result = false
                local i = 0
                while true do
                    local retval, isrgn = reaper.EnumProjectMarkers(i)
                    if retval == 0 then break end
                    if not isrgn then
                        prompter_drawer.has_markers_cache.result = true
                        break
                    end
                    i = i + 1
                end
            end

            prompter_drawer.has_markers_cache.count = state_count
        end

        if not prompter_drawer.has_markers_cache.result then return end

        -- Draw vertical "ПРАВКИ" button
        gfx.setfont(F.tip)
        local text = T("RETAKES_PROMPT")
        local btn_w = S(15)
        
        -- Calculate dynamic height based on text
        local btn_h = S(16) -- Top/Bottom padding S(8)*2
        for _, code in utf8.codes(text) do
            local _, ch = gfx.measurestr(utf8.char(code))
            btn_h = btn_h + ch - 1
        end

        local btn_x = cfg.p_drawer_left and 0 or (gfx.w - btn_w)
        local btn_y = drawer_top_y + (gfx.h - drawer_top_y - btn_h) / 2
        
        local hover = UI_STATE.window_focused and (gfx.mouse_x >= btn_x and gfx.mouse_x <= btn_x + btn_w and
                       gfx.mouse_y >= btn_y and gfx.mouse_y <= btn_y + btn_h)
        
        set_color(hover and UI.C_BTN_H or UI.C_BTN)
        gfx.rect(btn_x, btn_y, btn_w, btn_h, 1)
        
        -- Draw vertical text "ПРАВКИ"
        set_color(UI.C_TXT)

        -- Rotate text 90 degrees (draw character by character vertically)
        local char_y = btn_y + S(8)
        for _, code in utf8.codes(text) do
            local char = utf8.char(code)
            local cw, ch = gfx.measurestr(char)
            gfx.x = btn_x + (btn_w - cw) / 2
            gfx.y = char_y
            gfx.drawstr(char)
            char_y = char_y + ch - 1
        end
        
        -- Use robust click detection
        if hover and is_mouse_clicked(1) and not UI_STATE.mouse_handled then
            prompter_drawer.open = true
            UI_STATE.mouse_handled = true
            -- Ensure width is sane when opening
            if not prompter_drawer.width or prompter_drawer.width < S(80) then
                prompter_drawer.width = S(300)
            end
        end
    else
        -- Drawer is open
        -- Clamp width
        if prompter_drawer.width > max_w then
            prompter_drawer.width = max_w
        end
        
        -- Auto-close if too narrow
        if prompter_drawer.width < S(80) and not prompter_drawer.dragging then
            prompter_drawer.open = false
            prompter_drawer.width = S(300)
            save_settings()
        else
            -- Draw drawer panel
            set_color(UI.C_TAB_INA)
            gfx.rect(drawer_x, drawer_top_y, prompter_drawer.width, gfx.h - drawer_top_y, 1)
            
            -- (Header drawing logic moved to the end for layering, but height is needed here)
            local header_h = S(34)
            local table_y = drawer_top_y + header_h
            local base_row_h = S(28)
            local col_id_w = S(40)
            local col_text_x = drawer_x + col_id_w
            local col_text_w = prompter_drawer.width - col_id_w - S(5)
            
            local state_count = reaper.GetProjectStateChangeCount(0)
            local raw_query = prompter_drawer.filter.text
            local query = strip_accents(utf8_lower(raw_query))
            
            -- 1. Update RAW Marker Cache if project changed
            update_marker_cache()
            
            -- 2. Update FILTERED and LAYOUT Cache if needed
            if (state_count ~= prompter_drawer.filtered_cache.state_count and UTILS.is_markers_regions_changed()) or 
               query ~= prompter_drawer.filtered_cache.query or
               prompter_drawer.filtered_cache.state_count == -1 or
               prompter_drawer.width ~= prompter_drawer.filtered_cache.width or
               cfg.gui_scale ~= prompter_drawer.filtered_cache.gui_scale then
                
                prompter_drawer.filtered_cache.state_count = state_count
                prompter_drawer.filtered_cache.query = query
                prompter_drawer.filtered_cache.width = prompter_drawer.width
                prompter_drawer.filtered_cache.gui_scale = cfg.gui_scale
                prompter_drawer.filtered_cache.list = {}
                prompter_drawer.filtered_cache.total_h = 0

                -- Parse Query into OR/AND groups once
                local queries = {}
                local or_terms = {}
                for term in query:gmatch("[^|]+") do table.insert(or_terms, term) end
                for _, or_term in ipairs(or_terms) do
                    local and_terms = {}
                    for and_part in or_term:gmatch("[^&]+") do
                        local t = and_part:match("^%s*(.-)%s*$")
                        if t ~= "" then table.insert(and_terms, t) end
                    end
                    if #and_terms > 0 then table.insert(queries, and_terms) end
                end
                prompter_drawer.filtered_cache.parsed_queries = queries

                gfx.setfont(F.std)
                for _, m in ipairs(prompter_drawer.marker_cache.markers) do
                    local full_id = "M" .. tostring(m.markindex)
                    local clean_name = strip_accents(utf8_lower(m.name))
                    local clean_id = utf8_lower(full_id)
                    
                    -- Parse Query into OR/AND groups
                    local any_match = false
                    if #queries == 0 then
                        any_match = true
                    else
                        for _, and_group in ipairs(queries) do
                            local all_and_matched = true
                            for _, q in ipairs(and_group) do
                                -- Each term must match either the ID or the Name
                                if not (clean_id:find(q, 1, true) or clean_name:find(q, 1, true)) then
                                    all_and_matched = false
                                    break
                                end
                            end
                            if all_and_matched then
                                any_match = true
                                break
                            end
                        end
                    end
                    
                    if any_match then
                        local lines = {}
                        
                        -- Split by newlines first
                        local raw_lines = {}
                        for line in (m.name .. "\n"):gmatch("(.-)\n") do
                            table.insert(raw_lines, line)
                        end
                        if #raw_lines == 0 then table.insert(raw_lines, "") end

                        for _, raw_line in ipairs(raw_lines) do
                            local current_text = raw_line
                            if current_text == "" then
                                table.insert(lines, "")
                            else
                                -- Improved Word-based wrapping with hyphenation
                                local words = {}
                                for w in current_text:gmatch("%S+") do table.insert(words, w) end
                                if #words == 0 and #current_text > 0 then words = {current_text} end
                                
                                local cur_l = ""
                                local max_wrap_w = col_text_w - S(10)
                                
                                for _, w in ipairs(words) do
                                    local test_l = cur_l == "" and w or (cur_l .. " " .. w)
                                    if gfx.measurestr(test_l) <= max_wrap_w then
                                        cur_l = test_l
                                    else
                                        if cur_l ~= "" then table.insert(lines, cur_l) end
                                        
                                        -- If word itself is too long, break it with hyphenation
                                        if gfx.measurestr(w) > max_wrap_w then
                                            local partial = ""
                                            local w_len = utf8.len(w) or #w
                                            for j = 1, w_len do
                                                local char_start = utf8.offset(w, j)
                                                local char_end = (utf8.offset(w, j+1) or #w+1) - 1
                                                local char = w:sub(char_start, char_end)
                                                
                                                -- Check if adding char + optional hyphen fits
                                                local test_char = char
                                                if j < w_len then test_char = char .. "-" end
                                                
                                                if gfx.measurestr(partial .. test_char) > max_wrap_w then
                                                    if partial ~= "" then 
                                                        table.insert(lines, partial .. "-") 
                                                    end
                                                    partial = char
                                                else
                                                    partial = partial .. char
                                                end
                                            end
                                            cur_l = partial
                                        else
                                            cur_l = w
                                        end
                                    end
                                end
                                if cur_l ~= "" then table.insert(lines, cur_l) end
                            end
                        end
                        
                        local m_h = math.max(1, #lines) * base_row_h
                        table.insert(prompter_drawer.filtered_cache.list, {
                            id = full_id,
                            markindex = m.markindex,
                            name = m.name,
                            pos = m.pos,
                            color = m.color,
                            lines = lines,
                            h = m_h,
                            y_start = prompter_drawer.filtered_cache.total_h
                        })
                        prompter_drawer.filtered_cache.total_h = prompter_drawer.filtered_cache.total_h + m_h
                    end
                end
            end

            if state_count ~= prompter_drawer.filtered_cache.state_count then
                prompter_drawer.filtered_cache.state_count = state_count
            end
            
            local filtered_markers = prompter_drawer.filtered_cache.list
            local total_list_h = prompter_drawer.filtered_cache.total_h
            
            -- --- KEYBOARD SHORTCUTS ---
            if input_queue then
                for _, key in ipairs(input_queue) do
                    if not prompter_drawer.filter.focus then
                        -- Ctrl+A (Select All Filtered)
                        if key == 1 then
                            prompter_drawer.selection = {}
                            for _, m in ipairs(filtered_markers) do
                                prompter_drawer.selection[m.markindex] = true
                            end
                            prompter_drawer.last_selected_idx = nil
                        end
                        -- Ctrl+D (Deselect All)
                        if key == 4 then
                            prompter_drawer.selection = {}
                            prompter_drawer.last_selected_idx = nil
                        end
                        -- Delete (6579564) or Backspace (8)
                        if key == 6579564 or key == 8 then
                            prompter_delete_logic()
                        end

                        -- Arrow Navigation: Up (30064), Down (1685026670)
                        if (key == 30064 or key == 1685026670) and #filtered_markers > 0 then
                            local curr_idx = prompter_drawer.last_selected_idx or 0
                            if curr_idx == 0 then curr_idx = 1 end
                            
                            local new_idx = (key == 30064) and (curr_idx - 1) or (curr_idx + 1)
                            new_idx = math.max(1, math.min(new_idx, #filtered_markers))
                            
                            local m = filtered_markers[new_idx]
                            if m then
                                prompter_drawer.selection = {[m.markindex] = true}
                                prompter_drawer.last_selected_idx = new_idx
                                reaper.SetEditCurPos(m.pos, true, false)
                                
                                -- Auto-Scroll
                                local view_h = gfx.h - table_y - S(10)
                                local item_top = m.y_start
                                local item_bottom = m.y_start + m.h
                                
                                if item_top < prompter_drawer.scroll_y then
                                    prompter_drawer.scroll_y = item_top
                                elseif item_bottom > prompter_drawer.scroll_y + view_h then
                                    prompter_drawer.scroll_y = item_bottom - view_h
                                end
                            end
                        end
                    end
                end
            end
            
            -- Draw List with Scroll
            local view_h = gfx.h - table_y - S(10)
            
            -- Handle Mousewheel (Update TARGET)
            if prompter_drawer.width > S(50) then
                if gfx.mouse_x >= drawer_x and gfx.mouse_x <= drawer_x + prompter_drawer.width and
                   gfx.mouse_y >= table_y and gfx.mouse_y <= gfx.h then
                    if gfx.mouse_wheel ~= 0 then
                        prompter_drawer.target_scroll_y = (prompter_drawer.target_scroll_y or prompter_drawer.scroll_y) - (gfx.mouse_wheel / 120 * base_row_h * 3)
                        gfx.mouse_wheel = 0
                    end
                end
            end

            -- Clamp Target Scroll
            local max_scroll = math.max(0, total_list_h - view_h)
            prompter_drawer.target_scroll_y = math.max(0, math.min(prompter_drawer.target_scroll_y or 0, max_scroll))

            -- Auto-Scroll to Active Marker (Centering)
            if prompter_drawer.active_markindex and prompter_drawer.active_markindex ~= prompter_drawer.last_active_markindex then
                -- Only trigger if not intentionally scrolling manually (mouse button not held in drawer)
                if not (gfx.mouse_cap & 1 == 1 and gfx.mouse_x >= drawer_x) then
                    -- Find target item in filtered list
                    local target_m = nil
                    for _, m in ipairs(filtered_markers) do
                        if m.markindex == prompter_drawer.active_markindex then
                            target_m = m
                            break
                        end
                    end
                    
                    if target_m then
                        local item_top = target_m.y_start
                        local item_bottom = target_m.y_start + target_m.h
                        -- Set NEW target to center item
                        prompter_drawer.target_scroll_y = (item_top + item_bottom) / 2 - (view_h / 2)
                        prompter_drawer.last_active_markindex = prompter_drawer.active_markindex
                    end
                end
            end

            -- Reset last_active if index is cleared
            if not prompter_drawer.active_markindex then prompter_drawer.last_active_markindex = -1 end

            -- Smooth Interpolation (Lerp)
            if math.abs((prompter_drawer.target_scroll_y or 0) - prompter_drawer.scroll_y) > 0.1 then
                prompter_drawer.scroll_y = prompter_drawer.scroll_y + ((prompter_drawer.target_scroll_y or 0) - prompter_drawer.scroll_y) * 0.2
            else
                prompter_drawer.scroll_y = prompter_drawer.target_scroll_y or 0
            end

            -- Final clamp for safety
            prompter_drawer.scroll_y = math.max(0, math.min(prompter_drawer.scroll_y, max_scroll))
            
            -- Draw Rows
            for idx, m in ipairs(filtered_markers) do
                local row_y = table_y + m.y_start - prompter_drawer.scroll_y
                
                -- Check visibility
                if row_y + m.h > table_y and row_y < gfx.h then
                    local row_hover = UI_STATE.window_focused and (gfx.mouse_x >= drawer_x and gfx.mouse_x <= drawer_x + prompter_drawer.width and
                                       gfx.mouse_y >= row_y and gfx.mouse_y <= row_y + m.h and
                                       gfx.mouse_y >= table_y)
                    
                    -- Strictly clip backgrounds to table_y
                    local bg_draw_y = math.max(row_y, table_y)
                    local bg_draw_h = math.min(row_y + m.h, gfx.h) - bg_draw_y
                    
                    if bg_draw_h > 0 then
                        -- Zebra Stripe
                        if idx % 2 == 0 then
                            set_color(UI.C_HILI_WHITE_LOW) -- Slight white highlight
                            gfx.rect(drawer_x, bg_draw_y, prompter_drawer.width, bg_draw_h, 1)
                        end
                        
                        if prompter_drawer.selection[m.markindex] then
                            set_color(UI.C_HILI_GREEN) -- Green selection (matching table)
                            gfx.rect(drawer_x, bg_draw_y, prompter_drawer.width, bg_draw_h, 1)
                        elseif m.markindex == prompter_drawer.active_markindex then
                            set_color(UI.C_HILI_GREEN) -- Active marker highlight (p_color)
                            gfx.rect(drawer_x, bg_draw_y, prompter_drawer.width, bg_draw_h, 1)
                        end
                        
                        if row_hover then
                            set_color(UI.C_HILI_WHITE)
                            gfx.rect(drawer_x, bg_draw_y, prompter_drawer.width, bg_draw_h, 1)
                            
                            -- LEFT CLICK
                            if gfx.mouse_cap & 1 == 1 and UI_STATE.last_mouse_cap & 1 == 0 and not UI_STATE.mouse_handled then
                                local now = reaper.time_precise()
                                local cap = gfx.mouse_cap
                                local is_ctrl = (cap & 4 == 4) or (cap & 32 == 32)
                                local is_shift = (cap & 8 == 8)
                                
                                if is_ctrl then
                                    if prompter_drawer.selection[m.markindex] then
                                        prompter_drawer.selection[m.markindex] = nil
                                    else
                                        prompter_drawer.selection[m.markindex] = true
                                        prompter_drawer.last_selected_idx = idx
                                    end
                                elseif is_shift and prompter_drawer.last_selected_idx then
                                    local start_v = math.min(prompter_drawer.last_selected_idx, idx)
                                    local end_v = math.max(prompter_drawer.last_selected_idx, idx)
                                    prompter_drawer.selection = {}
                                    for k = start_v, end_v do
                                        local d_m = filtered_markers[k]
                                        if d_m then prompter_drawer.selection[d_m.markindex] = true end
                                    end
                                else
                                    -- Normal Click
                                    if prompter_drawer.last_click_idx == m.markindex and (now - prompter_drawer.last_click_time < 0.35) then
                                        -- Double Click Zone Check
                                        if gfx.mouse_x < col_text_x then
                                            -- ID Column: Cycle Color
                                            local g_r, g_g, g_b = 0, 255, 0
                                            local orange_r, orange_g, orange_b = 255, 200, 100
                                            local target_color
                                            local cur_r, cur_g, cur_b = reaper.ColorFromNative((m.color or 0) & 0xFFFFFF)
                                            if cur_r == 0 and cur_g == 255 and cur_b == 0 then
                                                target_color = reaper.ColorToNative(orange_r, orange_g, orange_b) | 0x1000000
                                            else
                                                target_color = reaper.ColorToNative(g_r, g_g, g_b) | 0x1000000
                                            end
                                            reaper.SetProjectMarker4(0, m.markindex, false, m.pos, 0, m.name == T("EMPTY") and "" or m.name, target_color, 0)
                                            reaper.UpdateTimeline()
                                            prompter_drawer.marker_cache.count = -1
                                            prompter_drawer.filtered_cache.state_count = -1
                                            table_data_cache.state_count = -1 -- FORCE UPDATE TABLE
                                            last_layout_state.state_count = -1 -- FORCE UPDATE LAYOUT
                                        else
                                            -- Text Column: Edit Text
                                            local mock_lines = {}
                                            local current_edit_idx = 1
                                            for l_idx, flt_m in ipairs(filtered_markers) do
                                                table.insert(mock_lines, { text = flt_m.name == T("EMPTY") and "" or flt_m.name })
                                                if flt_m.markindex == m.markindex then current_edit_idx = l_idx end
                                            end

                                            local function drawer_marker_callback(new_text)
                                                push_undo(T("EDIT_RETAKE"))
                                                -- Find marker index again (robustly)
                                                local target_idx = -1
                                                local m_count = reaper.CountProjectMarkers(0)
                                                for i = 0, m_count - 1 do
                                                    local _, isrgn, pos, _, _, markindex = reaper.EnumProjectMarkers3(0, i)
                                                    if not isrgn and (markindex == m.markindex or math.abs(pos - m.pos) < 0.001) then
                                                        target_idx = i
                                                        break
                                                    end
                                                end
                                                if target_idx ~= -1 then
                                                    reaper.SetProjectMarkerByIndex(0, target_idx, false, m.pos, 0, m.markindex, new_text, m.color or 0)
                                                else
                                                    reaper.SetProjectMarker4(0, m.markindex, false, m.pos, 0, new_text, m.color or 0, 0)
                                                end
                                                 
                                                ass_markers = capture_project_markers()
                                                prompter_drawer.marker_cache.count = -1
                                                prompter_drawer.filtered_cache.state_count = -1
                                                table_data_cache.state_count = -1 -- FORCE UPDATE TABLE
                                                last_layout_state.state_count = -1 -- FORCE UPDATE LAYOUT
                                                update_marker_cache()
                                                rebuild_regions()
                                                reaper.UpdateTimeline()
                                                reaper.UpdateArrange()
                                             end

                                            open_text_editor(m.name == T("EMPTY") and "" or m.name, drawer_marker_callback, current_edit_idx, mock_lines, true)
                                        end
                                        prompter_drawer.last_click_idx = -1
                                    else
                                        -- Single Click: Navigation & Selection
                                        reaper.SetEditCurPos(m.pos, true, false)
                                        prompter_drawer.selection = {[m.markindex] = true}
                                        prompter_drawer.last_selected_idx = idx
                                        prompter_drawer.last_click_idx = m.markindex
                                        prompter_drawer.last_click_time = now
                                    end
                                end
                                UI_STATE.mouse_handled = true
                            -- RIGHT CLICK
                            elseif gfx.mouse_cap & 2 == 2 and UI_STATE.last_mouse_cap & 2 == 0 and not UI_STATE.mouse_handled then
                                if not prompter_drawer.selection[m.markindex] then
                                    prompter_drawer.selection = {[m.markindex] = true}
                                    prompter_drawer.last_selected_idx = idx
                                end
                                
                                gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
                                local sel_count = 0
                                for _ in pairs(prompter_drawer.selection) do sel_count = sel_count + 1 end
                                local menu_str = (sel_count > 1) and T("DELETE_SELECTED_RETAKES_PS") .. sel_count .. ")" or T("DELETE_RETAKE")
                                local ret = gfx.showmenu(menu_str)
                                if ret == 1 then
                                    prompter_delete_logic()
                                end
                                UI_STATE.mouse_handled = true
                            end
                        end
                    end
                    
                    -- ID ("M" + ID, allow partial overlapping with header area)
                    if row_y + base_row_h > table_y and row_y <= gfx.h then
                        gfx.setfont(F.tip)
                        local draw_x = drawer_x + S(5)
                        local draw_y = row_y + (base_row_h - gfx.texth) / 2
                        
                        -- Entire ID string with marker color
                        if m.color and m.color ~= 0 then
                            local r, g, b = reaper.ColorFromNative(m.color & 0xFFFFFF)
                            set_color({r/255, g/255, b/255, 1})
                        else
                            -- Default marker color (Red in REAPER by default)
                            set_color(UI.C_RED)
                        end
                        gfx.x, gfx.y = draw_x, draw_y
                        gfx.drawstr(m.id)
                    end
                    
                    -- Name (Multiline + Highlighting)
                    gfx.setfont(F.std)
                    for l_idx, line_text in ipairs(m.lines) do
                        local line_y = row_y + (l_idx - 1) * base_row_h
                        -- Allow line to draw even if it partially overlaps with header area
                        if line_y + base_row_h > table_y and line_y <= gfx.h then
                            local lx = col_text_x + S(5)
                            local ly = line_y + (base_row_h - gfx.texth) / 2
                            
                            -- Search Highlighting (Multiple Terms Support)
                            if prompter_drawer.filtered_cache.parsed_queries and #prompter_drawer.filtered_cache.parsed_queries > 0 then
                                local low_line = utf8_lower(line_text)
                                for _, and_group in ipairs(prompter_drawer.filtered_cache.parsed_queries) do
                                    for _, q in ipairs(and_group) do
                                        local start_pos = 1
                                        while true do
                                            local s, e = low_line:find(q, start_pos, true)
                                            if not s then break end
                                            
                                            -- Calculate pixel position of the match
                                            local prefix = line_text:sub(1, s - 1)
                                            local match_str = line_text:sub(s, e)
                                            local px = lx + gfx.measurestr(prefix)
                                            local pw = gfx.measurestr(match_str)
                                            
                                            set_color(UI.C_HILI_YELLOW) -- Yellow highlight
                                            gfx.rect(px, line_y + S(2), pw, base_row_h - S(4), 1)
                                            
                                            start_pos = e + 1
                                        end
                                    end
                                end
                            end
                            
                            set_color(UI.C_TXT)
                            gfx.x, gfx.y = lx, ly
                            gfx.drawstr(line_text)
                        end
                    end
                end
            end
            
            -- Draw Scrollbar if needed
            if max_scroll > 0 then
                local sb_w = S(4)
                local sb_h = (view_h / total_list_h) * view_h
                local sb_y = table_y + (prompter_drawer.scroll_y / total_list_h) * view_h
                set_color(UI.C_HILI_WHITE_MID)
                gfx.rect(drawer_x + prompter_drawer.width - sb_w - S(1), sb_y, sb_w, sb_h, 1)
            end
            
            -- Draw resize handle
            local strip_w = S(2)
            local grab_w = S(12)
            local grab_h = S(40)
            
            local grab_x = cfg.p_drawer_left and (drawer_x + prompter_drawer.width) or (drawer_x - grab_w)
            local grab_y = drawer_top_y + (gfx.h - drawer_top_y - grab_h) / 2
            
            -- Helper: Check if mouse is strictly inside window
            -- Hover detection
            local handle_hover = UI_STATE.window_focused and UI_STATE.inside_window and (gfx.mouse_x >= grab_x - S(4) and gfx.mouse_x <= grab_x + grab_w + S(4))
            
            -- Draw 2px vertical line
            set_color(handle_hover and UI.C_HILI_WHITE_MID or UI.C_HILI_WHITE)
            gfx.rect(cfg.p_drawer_left and (drawer_x + prompter_drawer.width - S(1)) or drawer_x, drawer_top_y, strip_w, gfx.h - drawer_top_y, 1)
            
            -- Draw the central grab handle square only on hover
            if handle_hover or prompter_drawer.dragging then
                set_color(UI.C_WHITE, 0.8)
                gfx.rect(grab_x, grab_y, grab_w, grab_h, 1)
                
                -- Subtle border for the grab handle
                set_color(UI.C_BLACK_TRANSP)
                gfx.rect(grab_x, grab_y, grab_w, grab_h, 0)
            end
            
            -- Handle dragging (Priority: ignore UI_STATE.mouse_handled if hovering the handle strip)
            if handle_hover and (gfx.mouse_cap & 1 == 1) and UI_STATE.last_mouse_cap == 0 then
                prompter_drawer.dragging = true
                UI_STATE.mouse_handled = true
            end
            
            if prompter_drawer.dragging then
                if (gfx.mouse_cap & 1 == 1) then
                    local new_width
                    if cfg.p_drawer_left then
                        new_width = gfx.mouse_x - drawer_x
                    else
                        new_width = (drawer_x + prompter_drawer.width) - gfx.mouse_x
                    end
                    new_width = math.max(0, math.min(new_width, max_w))
                    
                    if new_width < S(80) then
                        prompter_drawer.open = false
                        prompter_drawer.dragging = false
                        prompter_drawer.width = S(300)
                        save_settings()
                    else
                        prompter_drawer.width = new_width
                    end
                else
                    -- Mouse released
                    prompter_drawer.dragging = false
                    save_settings()
                end
            end
            -- --- HEADER ROW (Re-drawn on top for perfect layering) ---
            local padding = S(5)
            local close_sz = S(24)
            local filter_w = prompter_drawer.width - close_sz - (padding * 3)
            
            -- Header Background
            set_color(UI.C_TAB_INA)
            gfx.rect(drawer_x, drawer_top_y, prompter_drawer.width, header_h, 1)

            -- Filter Input
            gfx.setfont(F.std)
            local p_counter_reserve = S(0)
            if prompter_drawer.filter.text ~= "" and prompter_drawer.filtered_cache.list then
                local p_count_text = tostring(#prompter_drawer.filtered_cache.list)
                p_counter_reserve = gfx.measurestr(p_count_text) + S(16)
            end
            ui_text_input("prompter_filter", drawer_x + padding, drawer_top_y + padding, filter_w - p_counter_reserve, close_sz, prompter_drawer.filter, T("SEARCH_AND_OR"), input_queue)

            -- Results count
            if p_counter_reserve > 0 then
                local p_count_text = tostring(#prompter_drawer.filtered_cache.list)
                local p_count_w = gfx.measurestr(p_count_text)
                local p_count_x = drawer_x + padding + filter_w - p_count_w - S(8)
                local p_count_y = drawer_top_y + padding + (close_sz - gfx.texth) / 2
                set_color(UI.C_TXT_DIM)
                gfx.x, gfx.y = p_count_x, p_count_y
                gfx.drawstr(p_count_text)
            end
            
            -- Close Button
            local close_x = drawer_x + padding + filter_w + padding
            local close_y = drawer_top_y + padding
            local close_hover = UI_STATE.window_focused and (gfx.mouse_x >= close_x and gfx.mouse_x <= close_x + close_sz and
                                 gfx.mouse_y >= close_y and gfx.mouse_y <= close_y + close_sz)
            
            if close_hover then
                set_color(UI.C_HILI_RED)
                gfx.rect(close_x, close_y, close_sz, close_sz, 1)
            end

            set_color(close_hover and UI.C_BTN_ERROR or UI.C_TXT)
            gfx.setfont(F.std)
            gfx.x = close_x + (close_sz - gfx.measurestr("X")) / 2
            gfx.y = close_y + (close_sz - gfx.texth) / 2
            gfx.drawstr("X")
            
            if close_hover and gfx.mouse_cap == 1 and UI_STATE.last_mouse_cap == 0 and not UI_STATE.mouse_handled then
                prompter_drawer.open = false
                save_settings()
                UI_STATE.mouse_handled = true
            end
        end
    end
end

local function draw_rich_line(line_spans, center_x, y_base, font_slot, font_name, base_size, no_assimilation, actor_name, available_w, content_offset_left, content_offset_right)
    -- Optimization: Apply transformations only once (usually pre-applied in cache)
    if not line_spans.transformed then
        line_spans = UTILS.apply_text_transforms(line_spans, no_assimilation)
    end
    -- === END DICTIONARY WORD REPLACEMENT ===
    
    local total_w, pending_karaoke_comp = 0, 0
    for i, span in ipairs(line_spans) do
        local f_flags, effective_font = 0, font_name
        local measure_bold = span.b
        if cfg.karaoke_mode and (font_slot == F.lrg or font_slot == F.nxt) then measure_bold = true end
        if span.i then
            if font_name == "Helvetica" then effective_font = "Helvetica Oblique"
            else f_flags = f_flags + string.byte('i') end
        end
        if measure_bold then
            if effective_font == font_name then 
                if span.i then f_flags = string.byte('b') | (string.byte('i') << 8)
                else f_flags = string.byte('b') end
            elseif span.i and font_name == "Helvetica" then 
                effective_font = "Helvetica Bold Oblique"
                f_flags = 0
            end
        end
        gfx.setfont(font_slot, effective_font, base_size, f_flags)
        local measure_text = span.text
        if cfg.all_caps_acute and not cfg.all_caps then measure_text = apply_accent_caps(measure_text) end
        measure_text = measure_text:gsub(acute, "")
        if cfg.all_caps then measure_text = utf8_upper(measure_text) end
        span.width = gfx.measurestr(measure_text)
        span.height = gfx.texth
        
        if cfg.karaoke_mode and (font_slot == F.lrg or font_slot == F.nxt) then
            local nf, nfl = effective_font, f_flags
            if not span.b then
                if nf == "Helvetica Bold Oblique" then nf = "Helvetica Oblique" end
                if nfl == string.byte('b') then nfl = 0 end
            end
            gfx.setfont(font_slot, nf, base_size, nfl)
            local normal_w = gfx.measurestr(measure_text)
            gfx.setfont(font_slot, effective_font, base_size, f_flags)
            local target_w = gfx.measurestr(measure_text)
            local is_connected = false
            if i < #line_spans then
                local next_s = line_spans[i+1]
                if not span.text:match("%s$") and not next_s.text:match("^%s") then is_connected = true end
            end
            if is_connected then
                span.text_width = normal_w
                if span.i then
                    gfx.setfont(font_slot, effective_font, base_size, f_flags)
                    span.width = gfx.measurestr(measure_text)
                else span.width = normal_w end
                pending_karaoke_comp = pending_karaoke_comp + (target_w - normal_w)
            else
                span.width = target_w + pending_karaoke_comp
                if span.i then
                    gfx.setfont(font_slot, effective_font, base_size, f_flags)
                    span.text_width = gfx.measurestr(measure_text)
                else span.text_width = normal_w end
                pending_karaoke_comp = 0
            end
        end
        total_w = total_w + span.width
    end
    
    local actor_w, full_actor_text = 0, ""
    if cfg.show_actor_name_infront and actor_name and actor_name ~= "" then
        full_actor_text = "[" .. actor_name .. "] "
        gfx.setfont(font_slot, font_name, math.max(10, base_size - 2))
        actor_w = gfx.measurestr(full_actor_text)
        total_w = total_w + actor_w
    end

    local start_x 
    if cfg.p_align == "left" then 
        start_x = content_offset_left + 20
    elseif cfg.p_align == "right" then 
        start_x = gfx.w - content_offset_right - total_w - 20
    else 
        start_x = center_x - (total_w / 2) 
    end

    -- Clamp to visible area
    local min_x = content_offset_left + 20
    local max_x = gfx.w - content_offset_right - 20
    if start_x < min_x then start_x = min_x end
    if start_x + total_w > max_x and total_w < (max_x - min_x) then
        start_x = max_x - total_w
    end
    
    local cursor_x = start_x
    
    if cfg.show_actor_name_infront and actor_name and actor_name ~= "" then
        local r, g, b, a = gfx.r, gfx.g, gfx.b, gfx.a
        gfx.set(r, g, b, a * 0.45)
        gfx.setfont(font_slot, font_name, math.max(10, base_size - 2))
        gfx.x, gfx.y = cursor_x, y_base + 1
        gfx.drawstr(full_actor_text)
        gfx.set(r, g, b, a)
        cursor_x = cursor_x + actor_w
    end

    for _, span in ipairs(line_spans) do
        local f_flags, effective_font = 0, font_name
        if span.i then
           if font_name == "Helvetica" then effective_font = "Helvetica Oblique"
           else f_flags = f_flags + string.byte('i') end
        end
        if span.b then
            if effective_font == font_name then 
                if span.i then f_flags = string.byte('b') | (string.byte('i') << 8)
                else f_flags = string.byte('b') end
            elseif span.i and font_name == "Helvetica" then 
                effective_font = "Helvetica Bold Oblique"
                f_flags = 0
            end
        end
        gfx.setfont(font_slot, effective_font, base_size, f_flags)
        gfx.x, gfx.y = cursor_x, y_base
        
        local segments = UTILS.get_words_and_separators(span.text)
        local temp_x = cursor_x
        for _, seg in ipairs(segments) do
            local text_for_render = seg.text
            if cfg.all_caps_acute and not cfg.all_caps then
                text_for_render = apply_accent_caps(text_for_render)
            end
            local measure_text = text_for_render:gsub(acute, "")
            if cfg.all_caps then measure_text = utf8_upper(measure_text) end
            local sw = gfx.measurestr(measure_text)
            if seg.is_word and (not dict_modal.show) then
                local is_over = gfx.mouse_x >= temp_x - 2 and gfx.mouse_x <= temp_x + sw + 2 and gfx.mouse_y >= y_base - 5 and gfx.mouse_y <= y_base + span.height + 5
                if is_over then
                    if gfx.mouse_cap & 1 == 1 then
                        if UI_STATE.last_mouse_cap == 0 then
                            local clean = seg.text:gsub(acute, "")
                            if clean:find("[%a\128-\255]") then
                                word_trigger.active, word_trigger.start_time, word_trigger.word, word_trigger.triggered = true, reaper.time_precise(), span.orig_word or clean, false
                                word_trigger.hit_x, word_trigger.hit_y, word_trigger.hit_w, word_trigger.hit_h = temp_x, y_base, sw, span.height
                            end
                        elseif word_trigger.active and not word_trigger.triggered then
                            if reaper.time_precise() - word_trigger.start_time > 0.4 then word_trigger.triggered = true; trigger_dictionary_lookup(word_trigger.word) end
                        end
                    end
                elseif word_trigger.active and not word_trigger.triggered then
                    if not (gfx.mouse_x >= word_trigger.hit_x - 10 and gfx.mouse_x <= word_trigger.hit_x + word_trigger.hit_w + 10 and gfx.mouse_y >= word_trigger.hit_y - 10 and gfx.mouse_y <= word_trigger.hit_y + word_trigger.hit_h + 10) then word_trigger.active = false end
                end
            end
            temp_x = temp_x + sw
        end
        if word_trigger.active and gfx.mouse_cap & 1 == 0 then word_trigger.active = false end
        if span.comment and (not dict_modal.show) then
            if gfx.mouse_x >= cursor_x and gfx.mouse_x <= cursor_x + span.width and gfx.mouse_y >= y_base and gfx.mouse_y <= y_base + span.height then
                local id = tostring(span)
                if UI_STATE.tooltip_state.hover_id ~= id then UI_STATE.tooltip_state.hover_id, UI_STATE.tooltip_state.start_time = id, reaper.time_precise() end
                UI_STATE.tooltip_state.text, UI_STATE.tooltip_state.immediate = span.comment, true
            end
        elseif span.u_wave and span.orig_word and (not dict_modal.show) then
            -- Тултіп асиміляції: показуємо оригінальне слово (нижчий пріоритет ніж коментар)
            if gfx.mouse_x >= cursor_x and gfx.mouse_x <= cursor_x + span.width and gfx.mouse_y >= y_base and gfx.mouse_y <= y_base + span.height then
                local id = "assim_" .. tostring(span)
                if UI_STATE.tooltip_state.hover_id ~= id then UI_STATE.tooltip_state.hover_id, UI_STATE.tooltip_state.start_time = id, reaper.time_precise() end
                UI_STATE.tooltip_state.text = "← " .. span.orig_word
            end
        end
        draw_text_with_stress_marks(span.text, cfg.all_caps, cfg.all_caps_acute)
        if span.comment then
            local sr, sg, sb, sa = gfx.r, gfx.g, gfx.b, gfx.a
            set_color(UI.GET_P_COLOR(0.5))
            local comment_width = span.text_width or span.width
            local comm_len = utf8.len(span.comment) or #span.comment
            local dash_w = math.max(S(3), S(8) - math.min(S(5), math.floor(comm_len / 15)))
            local gap_w = math.max(S(3), dash_w - S(1))
            local cur_dash_x = cursor_x
            while cur_dash_x < cursor_x + comment_width do
                local draw_w = math.min(dash_w, cursor_x + comment_width - cur_dash_x)
                gfx.rect(cur_dash_x, y_base + span.height - 2, draw_w, 3, 1)
                cur_dash_x = cur_dash_x + dash_w + gap_w
            end
            gfx.r, gfx.g, gfx.b, gfx.a = sr, sg, sb, sa
        end
        if span.u then local ly = y_base + span.height - 2; local uw = span.text_width or span.width; gfx.line(cursor_x, ly, cursor_x + uw, ly) end
        if span.u_wave then
            local wave_y, wave_h, step, x_pos, uw = y_base + span.height - S(2), S(2), S(3), cursor_x, span.text_width or span.width
            local end_x, up = x_pos + uw, true
            while x_pos < end_x do
                local next_x = math.min(x_pos + step, end_x)
                local y1, y2 = up and wave_y or (wave_y + wave_h), up and (wave_y + wave_h) or wave_y
                gfx.line(x_pos, y1, next_x, y2); x_pos, up = next_x, not up
            end
        end
        if span.s then local ly = y_base + span.height / 2; local sw = span.text_width or span.width; gfx.line(cursor_x, ly, cursor_x + sw, ly) end
        cursor_x = cursor_x + span.width
    end
    return start_x, y_base, total_w, (#line_spans > 0 and line_spans[1].height or gfx.texth)
end

local function handle_prompter_context_menu(is_show_final_stats)
    if is_mouse_clicked(2) and not UI_STATE.mouse_handled then
        gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
        local is_docked = gfx.dock(-1) > 0
        local dock_check = is_docked and "!" or ""
        local slider_check = cfg.prompter_slider_mode and "• " or ""
        
        local dock_idx = 6
        local stats_str = ""
        if is_show_final_stats then
            stats_str = T("CLEAR_MY_STATS_PCX")
            dock_idx = 7
        end
        
        local etc_prefix = ""
        local etc_offset = 0
        if cfg.show_speed_in_prompter then
            local etc_speed, etc_time = STATS.get_etc_strings()
            etc_prefix = etc_speed .. "|" .. etc_time .. "||"
            etc_offset = 2
            dock_idx = dock_idx + etc_offset
        end
         
        local menu = etc_prefix .. T("DISPLAY_SUBOVERLAY_PCX") .. "||" .. T("FIND_NEW_G_PCX") .. "|" .. T("DISPLAY_DICTIONARY_PCX") .. "|" .. slider_check .. T("SLIDER_MODE") .. "||" .. T("GLOBAL_SEARCH_FOR_TAKES") .. stats_str .. "||" .. dock_check .. T("DOCK_THE_WINDOW")
        
        local ret = gfx.showmenu(menu)
        UI_STATE.mouse_handled = true -- Tell framework we handled this click
        
        -- Offset ret to skip the disabled ETC items (if shown)
        if etc_offset > 0 and ret > etc_offset then
            ret = ret - etc_offset
        elseif etc_offset > 0 and ret > 0 and ret <= etc_offset then
            ret = 0 -- Ignore clicks on disabled ETC items
        end
        
        if ret == 1 then
            UTILS.run_satellite_script("overlay", "Lionzz_SubOverlay_Subass.lua", "Overlay")
        elseif ret == 2 then
            local ok, input = reaper.GetUserInputs(T("GOROH"), 1, T("SEARCH_TERM_200"), "")
            if ok and input ~= "" then
                trigger_dictionary_lookup(input)
            end
        elseif ret == 3 then
            UTILS.run_satellite_script("dictionary", "Subass_Dictionary.lua", "Dictionary")
        elseif ret == 4 then
            cfg.prompter_slider_mode = not cfg.prompter_slider_mode
            save_settings()
        elseif ret == 5 then
            if SEARCH_ITEM.open then SEARCH_ITEM.open() end
        elseif is_show_final_stats and ret == 6 then
            STATS.clear_stats()
        elseif (ret + etc_offset) == dock_idx then
            -- Toggle Docking
            if is_docked then
                gfx.dock(0)
                GL.last_dock_state = 0
                reaper.SetExtState(section_name, "dock", "0", true)
            else
                gfx.dock(GL.last_dock_id or 1)
                GL.last_dock_state = gfx.dock(-1)
                reaper.SetExtState(section_name, "dock", tostring(GL.last_dock_state), true)
            end
        end
    end
end

-- --- Shared Prompter Helpers ---
--- Helper: Count words in lines
local function count_words_in_lines(lines_structure)
    local count = 0
    for _, line in ipairs(lines_structure) do
        for _, span in ipairs(line) do
            for _ in span.text:gmatch("[^%s]+") do
                count = count + 1
            end
        end
    end
    return count
end

--- Helper: Apply Karaoke Styling
local function apply_karaoke_style(lines_structure, active_idx)
    if not active_idx then return lines_structure end
    
    local new_lines = {}
    local word_counter = 0
    
    for _, line in ipairs(lines_structure) do
        local new_line = {}
        for _, span in ipairs(line) do
            local text = span.text
            
            -- Manual tokenizer to preserve exact original text and spacing
            local current_idx = 1
            while current_idx <= #text do
                -- Find next non-space
                local s_start, s_end = text:find("[^%s]+", current_idx)
                
                if not s_start then
                    -- Only whitespace remaining
                    local remainder = text:sub(current_idx)
                    if #remainder > 0 then
                        local new_seg = {}
                        for k, v in pairs(span) do new_seg[k] = v end
                        new_seg.text = remainder
                        new_seg.b = (word_counter < active_idx) or span.b
                        table.insert(new_line, new_seg)
                    end
                    break
                end
                
                -- Space before word
                if s_start > current_idx then
                    local space = text:sub(current_idx, s_start - 1)
                    local new_seg = {}
                    for k, v in pairs(span) do new_seg[k] = v end
                    new_seg.text = space
                    new_seg.b = (word_counter < active_idx) or span.b
                    table.insert(new_line, new_seg)
                end
                
                -- The Word
                word_counter = word_counter + 1
                local word = text:sub(s_start, s_end)
                local new_seg = {}
                for k, v in pairs(span) do new_seg[k] = v end
                new_seg.text = word
                new_seg.b = (word_counter <= active_idx) or span.b
                table.insert(new_line, new_seg)
                
                current_idx = s_end + 1
            end
        end
        table.insert(new_lines, new_line)
    end
    return new_lines
end

--- Get corrections to display based on timing rules
--- @param cur_pos number
--- @param active_rgns table Current regions list
--- @return table markers, number total_h
local function get_corrections_to_draw(cur_pos, active_rgns, override_fsize)
    if not cfg.p_corr then return {}, 0 end
    
    local seen = {}
    local cor_markers = {}
    
    local function add(m)
        if not seen[m.markindex] then
            table.insert(cor_markers, m)
            seen[m.markindex] = true
        end
    end

    local m_list = prompter_drawer.marker_cache.markers
    if #m_list == 0 then return {}, 0 end

    -- RULE 1: Inside active region (Show all for full duration)
    if active_rgns and #active_rgns > 0 then
        for _, r in ipairs(active_rgns) do
            for _, m in ipairs(m_list) do
                if m.pos >= r.pos and m.pos < r.rgnend then
                    add(m)
                end
            end
        end
    end

    -- RULE 2: Outside regions (Show next upcoming marker regardless of time)
    local r_ptr = 1
    for _, m in ipairs(m_list) do
        local is_inside_any = false
        while r_ptr <= #regions and regions[r_ptr].rgnend <= m.pos do
            r_ptr = r_ptr + 1
        end
        
        if r_ptr <= #regions and m.pos >= regions[r_ptr].pos then
            is_inside_any = true
        end
        
        if not is_inside_any then
            if cur_pos >= m.pos and cur_pos < m.pos + 10 then
                add(m)
            end
        end
    end

    if #cor_markers == 0 then return {}, 0 end
    
    table.sort(cor_markers, function(a, b) return a.pos < b.pos end)
    
    local project_last_passed_pos = -1
    for _, m in ipairs(m_list) do
        if m.pos <= cur_pos and m.pos > project_last_passed_pos then
            project_last_passed_pos = m.pos
        end
    end
    
    local filtered_candidates = {}
    for _, m in ipairs(cor_markers) do
        if m.pos >= project_last_passed_pos then
            table.insert(filtered_candidates, m)
        end
    end
    
    if #filtered_candidates == 0 then return {}, 0 end

    local best_m = nil
    for _, m in ipairs(filtered_candidates) do
        if m.pos > cur_pos then
            best_m = m
            break
        end
    end
    
    if not best_m then
        best_m = filtered_candidates[#filtered_candidates]
    end
    
    cor_markers = { best_m }
    
    gfx.setfont(F.cor, cfg.p_font, override_fsize or cfg.c_fsize)
    local raw_lh = gfx.texth
    local line_h = math.floor(raw_lh * (cfg.c_lheight or 1.0))
    
    local total_lines = 0
    for _, m in ipairs(cor_markers) do
        local lines = parse_prompter_to_lines(m.name or "", true)
        total_lines = total_lines + #lines
    end
    
    return cor_markers, total_lines * line_h
end

--- Render corrections (markers) 
--- @param cor_markers table
--- @param y_offset number
local function render_corrections(cor_markers, y_offset, font_size, center_x, available_w, content_offset_left, content_offset_right)
    if #cor_markers == 0 then return end
    
    local fsize = font_size or cfg.c_fsize
    set_color(UI.GET_C_COLOR())
    gfx.setfont(F.cor, cfg.p_font, fsize)
    
    local raw_lh = gfx.texth
    local line_h = math.floor(raw_lh * (cfg.c_lheight or 1.0))
    local y_off = math.floor((line_h - raw_lh) / 2)
    local total_h = 0
    
    for i, m in ipairs(cor_markers) do
        local name = m.name or ""
        if name == "" then name = T("EMPTY") end
        
        local c_x1, c_y1, c_x2, c_y2 = gfx.w, gfx.h, 0, 0
        local c_y = y_offset + total_h
        local spans_lines = parse_prompter_to_lines(name, true)
        
        for i_line, spans in ipairs(spans_lines) do
            local y = c_y + (i_line-1) * line_h
            local lx, ly, lw, l_h = draw_rich_line(spans, center_x, y + y_off, F.cor, cfg.p_font, fsize, true, nil, available_w, content_offset_left, content_offset_right)
            
            if lx < c_x1 then c_x1 = lx end
            if ly < c_y1 then c_y1 = ly end
            if lx + lw > c_x2 then c_x2 = lx + lw end
            if ly + l_h > c_y2 then c_y2 = ly + l_h end
            
            total_h = total_h + line_h
        end

        if is_mouse_clicked() and (not dict_modal.show) and (not UI_STATE.mouse_handled) then
            if gfx.mouse_x >= c_x1 - 20 and gfx.mouse_x <= c_x2 + 20 and
               gfx.mouse_y >= c_y1 - 10 and gfx.mouse_y <= c_y2 + 10 then
                UI_STATE.mouse_handled = true
                local now = reaper.time_precise()
                if UI_STATE.last_click_row == -5 and (now - UI_STATE.last_click_time) < 0.5 then
                    local mock_lines = {}
                    local current_edit_idx = 1
                    for idx, cm in ipairs(cor_markers) do
                        table.insert(mock_lines, { text = cm.name:gsub(T("EMPTY"), "") })
                        if cm.markindex == m.markindex then current_edit_idx = idx end
                    end

                    local function marker_callback(new_text)
                        push_undo(T("EDIT_RETAKE"))
                        local target_idx = -1
                        local marker_count = reaper.CountProjectMarkers(0)
                        for j = 0, marker_count - 1 do
                            local _, isrgn, pos, _, _, markindex = reaper.EnumProjectMarkers3(0, j)
                            if not isrgn then
                                if markindex == m.markindex or math.abs(pos - m.pos) < 0.001 then
                                    target_idx = j
                                    m.pos = pos
                                    break
                                end
                            end
                        end
                        if target_idx ~= -1 then reaper.SetProjectMarkerByIndex(0, target_idx, false, m.pos, 0, m.markindex, new_text, m.color or 0)
                        else reaper.SetProjectMarker4(0, m.markindex, false, m.pos, 0, new_text, m.color or 0, 0) end
                        ass_markers = capture_project_markers()
                        prompter_drawer.marker_cache.count = -1
                        table_data_cache.state_count = -1 
                        last_layout_state.state_count = -1 
                        update_marker_cache()
                        rebuild_regions()
                        reaper.UpdateTimeline()
                        reaper.UpdateArrange()
                    end
                    open_text_editor(m.name:gsub(T("EMPTY"), ""), marker_callback, current_edit_idx, mock_lines, true)
                    UI_STATE.last_click_row = 0
                else
                    UI_STATE.last_click_time = now
                    UI_STATE.last_click_row = -5
                end
            end
        end
    end
end

local function handle_info_overlay_interaction(content_offset_left, content_offset_right, active_regions, override_time)
    if not cfg.p_info then return end
    
    local display_time = override_time or (reaper.GetPlayState() & 1 == 1 and reaper.GetPlayPosition() or reaper.GetCursorPosition())
    local left_str = format_timestamp(display_time + 0.001)
    
    -- Interaction: Left Info
    if left_str ~= "" then
        gfx.setfont(F.std)
        local tw, th = gfx.measurestr(left_str)
        if gfx.mouse_x >= (content_offset_left + S(10)) and gfx.mouse_x <= (content_offset_left + S(10)) + tw and
           gfx.mouse_y >= S(30) and gfx.mouse_y <= S(30) + th then
             if is_mouse_clicked() and not UI_STATE.mouse_handled then
                UI_STATE.mouse_handled = true
                local now = reaper.time_precise()
                if UI_STATE.last_click_row == -6 and (now - UI_STATE.last_click_time) < 0.3 then
                    set_clipboard(left_str)
                    show_snackbar(T("COPIED") .. ": " .. left_str, "info")
                    UI_STATE.last_click_row = 0
                else
                    UI_STATE.last_click_time = now
                    UI_STATE.last_click_row = -6
                end
            end
        end
    end

    -- Interaction: Right Info (Progress %)
    if not (active_regions and #active_regions > 0) and cfg.p_progress and regions and #regions > 0 then
        local percent = UTILS.get_recording_progress()
        local right_str = percent .. "%"
        gfx.setfont(F.std)
        local tw, th = gfx.measurestr(right_str)
        local x_pos = gfx.w - tw - S(10) - content_offset_right
        
        if gfx.mouse_x >= x_pos and gfx.mouse_x <= x_pos + tw and
           gfx.mouse_y >= S(30) and gfx.mouse_y <= S(30) + th then
            if is_mouse_clicked() and not UI_STATE.mouse_handled then
                UI_STATE.mouse_handled = true
                local now = reaper.time_precise()
                -- Double click check
                if UI_STATE.last_click_row == -7 and (now - UI_STATE.last_click_time) < 0.3 then
                    UTILS.jump_to_first_unrecorded_region()
                    UI_STATE.last_click_row = 0
                else
                    UI_STATE.last_click_time = now
                    UI_STATE.last_click_row = -7
                end
            end
        end
    end
end

function DRAW_WINDOW.draw_info_overlay_graphics(content_offset_left, content_offset_right, active_regions, override_time, active_idx)
    if not cfg.p_info then return end
    
    gfx.setfont(F.std)
    gfx.set(cfg.p_cr, cfg.p_cg, cfg.p_cb, 0.5)
    
    local display_time = override_time or (reaper.GetPlayState() & 1 == 1 and reaper.GetPlayPosition() or reaper.GetCursorPosition())
    local left_str = format_timestamp(display_time + 0.001)
    local right_str = ""
    
    if active_regions and #active_regions > 0 then
        local r = active_regions[1]
        
        -- Use provided active_idx or find it sequentially in regions table
        local current_seq_idx = active_idx
        if not current_seq_idx then
            for i, region in ipairs(regions) do
                if region.idx == r.idx then current_seq_idx = i; break end
            end
        end
        
        local display_idx = current_seq_idx and current_seq_idx or r.idx
        local remaining = #regions - (current_seq_idx or 1)
        local normal_str = tostring(display_idx) .. "/" .. tostring(#regions)
        
        if cfg.p_always_show_left and remaining > 0 then
            normal_str = normal_str .. " ⁞ " .. tostring(remaining)
        end
        
        -- Hover detection: determine bounds of the region counter
        local tw, th = gfx.measurestr(normal_str)
        local rx = gfx.w - tw - S(10) - content_offset_right
        local ry = S(30)
        
        if gfx.mouse_x >= rx - S(5) and gfx.mouse_x <= gfx.w - content_offset_right and
           gfx.mouse_y >= ry - S(5) and gfx.mouse_y <= ry + th + S(5) then
            -- Show remaining count on hover
            right_str = "-" .. tostring(remaining)
            if remaining == 0 then right_str = T("THIS_LAST_REG_IDLE") end
        else
            right_str = normal_str
        end
    elseif cfg.p_progress and regions and #regions > 0 then
        local percent = UTILS.get_recording_progress()
        right_str = percent .. "%"
    end
    
    if left_str ~= "" then
        gfx.x = content_offset_left + S(10)
        gfx.y = S(30)
        gfx.drawstr(left_str)
    end
    
    if right_str ~= "" then
        local iw, ih = gfx.measurestr(right_str)
        gfx.x = gfx.w - iw - S(10) - content_offset_right
        gfx.y = S(30)
        gfx.drawstr(right_str)
    end
    
    gfx.set(cfg.p_cr, cfg.p_cg, cfg.p_cb, 1)
end

UI_STATE.confetti_particles = nil
UI_STATE.confetti_finished = false

--- Update, draw or clear the falling confetti particles
--- @param active boolean Whether the confetti effect is currently active
function UI_STATE.draw_confetti(active)
    if not cfg.show_confetti then return end

    if not active then
        UI_STATE.confetti_particles = nil
        UI_STATE.confetti_finished = false
        return
    end

    if UI_STATE.confetti_finished then
        return
    end

    -- Initialize/Reset confetti particles if not already initialized
    if not UI_STATE.confetti_particles or #UI_STATE.confetti_particles == 0 then
        UI_STATE.confetti_particles = {}
        for i = 1, 50 do
            table.insert(UI_STATE.confetti_particles, {
                x = math.random() * gfx.w,
                y = -math.random() * S(300), -- Compact burst above the screen
                speed_y = S(1.5) + math.random() * S(3),
                speed_x = -S(0.5) + math.random() * S(1),
                size_w = S(5) + math.random() * S(8),
                size_h = S(3) + math.random() * S(5),
                angle = math.random() * 360,
                spin = -6 + math.random() * 12,
                color = {
                    math.random(120, 255) / 255, -- Bright, festive colors!
                    math.random(120, 255) / 255,
                    math.random(120, 255) / 255,
                    0.5 + math.random() * 0.5
                }
            })
        end
    end

    -- Draw and Update Confetti
    local orig_r, orig_g, orig_b, orig_a = gfx.r, gfx.g, gfx.b, gfx.a
    local has_active = false
    
    for _, p in ipairs(UI_STATE.confetti_particles) do
        -- Only update and draw if it hasn't fallen off the bottom of the screen yet
        if p.y < gfx.h + S(15) then
            has_active = true
            
            -- Update position
            p.y = p.y + p.speed_y
            p.x = p.x + p.speed_x + math.sin(os.clock() * 3 + p.y * 0.02) * S(0.3)
            p.angle = p.angle + p.spin
            
            -- Horizontal wrap (keep them within screen sides)
            if p.x < -S(15) then p.x = gfx.w + S(15)
            elseif p.x > gfx.w + S(15) then p.x = -S(15) end
            
            -- Only draw if visible on screen
            if p.y > -p.size_h and p.y < gfx.h then
                -- Set color
                gfx.set(p.color[1], p.color[2], p.color[3], p.color[4])
                
                -- Draw rotated rectangle
                local rad = math.rad(p.angle)
                local cos_a = math.cos(rad)
                local sin_a = math.sin(rad)
                local hw = p.size_w / 2
                local hh = p.size_h / 2
                
                local x1 = p.x - hw * cos_a + hh * sin_a
                local y1 = p.y - hw * sin_a - hh * cos_a
                local x2 = p.x + hw * cos_a + hh * sin_a
                local y2 = p.y + hw * sin_a - hh * cos_a
                local x3 = p.x + hw * cos_a - hh * sin_a
                local y3 = p.y + hw * sin_a + hh * cos_a
                local x4 = p.x - hw * cos_a - hh * sin_a
                local y4 = p.y - hw * sin_a + hh * cos_a
                
                gfx.triangle(x1, y1, x2, y2, x3, y3)
                gfx.triangle(x1, y1, x3, y3, x4, y4)
            end
        end
    end
    gfx.set(orig_r, orig_g, orig_b, orig_a)
    
    -- If there are no more active particles, finish the animation and clear the list
    if not has_active then
        UI_STATE.confetti_finished = true
        UI_STATE.confetti_particles = nil
    end
end

--- Render statistics summary when prompter is idle
function STATS.render_prompter_idle(available_w, content_offset_left, content_offset_right)
    local takes, dur = STATS.get_session_summary()
    local play_state = reaper.GetPlayState()
    local is_recording = (play_state & 4) == 4

    if not UI_STATE.ass_file_loaded or not ass_lines or #ass_lines == 0 then
        UI_STATE.draw_confetti(false)
        -- Need to import subtitles
        set_color(UI.GET_P_COLOR(0.3))
        gfx.setfont(F.std)
        local name = (cfg.dubber_name and cfg.dubber_name ~= "") and cfg.dubber_name or (os.getenv("USER") or os.getenv("USERNAME") or T("USER"))
        local txt = name .. T("NEED_IMPORT_SUBS_IDLE")
        local tw, th = gfx.measurestr(txt)
        gfx.x = content_offset_left + (available_w - tw) / 2
        gfx.y = (gfx.h - th) / 2
        if cfg.p_valign == "top" then gfx.y = S(70)
        elseif cfg.p_valign == "bottom" then gfx.y = gfx.h - th - S(50) end
        gfx.drawstr(txt)
    elseif (takes > 0 or dur > 0) and not is_recording and cfg.show_final_stats then
        local name = (cfg.dubber_name and cfg.dubber_name ~= "") and cfg.dubber_name or (os.getenv("USER") or os.getenv("USERNAME") or T("USER"))
        local title = T("GREAT_JOB_IDLE") .. name .. "!"
        local progress = UTILS.get_recording_progress() or 0
        local speed = (dur > 0) and math.floor(takes / (dur / 3600)) or 0

        -- Concept Pro: SUCCESS SCREEN with Confetti!
        UI_STATE.draw_confetti(progress == 100)
        
        -- Center and Base Y
        local cx = content_offset_left + available_w / 2
        local cy = gfx.h / 2
        
        -- Base position logic (centering the whole block)
        local block_h = S(270) -- Орієнтовна повна висота
        local base_ty = cy - block_h / 2
        
        if cfg.p_valign == "top" then base_ty = S(36)
        elseif cfg.p_valign == "bottom" then base_ty = gfx.h - block_h - S(36) end
        
        local min_top_pad = S(20)
        if base_ty < min_top_pad then base_ty = min_top_pad end
        
        UI_STATE.prompter_idle_target_scroll_y = UI_STATE.prompter_idle_target_scroll_y or 0
        UI_STATE.prompter_idle_scroll_y = UI_STATE.prompter_idle_scroll_y or 0
        UI_STATE.prompter_idle_total_h = UI_STATE.prompter_idle_total_h or gfx.h
        
        local max_scroll = math.max(0, UI_STATE.prompter_idle_total_h - gfx.h)
        
        if gfx.mouse_wheel ~= 0 then
            UI_STATE.prompter_idle_target_scroll_y = UI_STATE.prompter_idle_target_scroll_y - (gfx.mouse_wheel * 0.3)
            gfx.mouse_wheel = 0
        end
        
        if UI_STATE.prompter_idle_target_scroll_y < 0 then UI_STATE.prompter_idle_target_scroll_y = 0 end
        if UI_STATE.prompter_idle_target_scroll_y > max_scroll then UI_STATE.prompter_idle_target_scroll_y = max_scroll end
        
        local diff = UI_STATE.prompter_idle_target_scroll_y - UI_STATE.prompter_idle_scroll_y
        if math.abs(diff) > 0.5 then
            UI_STATE.prompter_idle_scroll_y = UI_STATE.prompter_idle_scroll_y + (diff * 0.8)
        else
            UI_STATE.prompter_idle_scroll_y = UI_STATE.prompter_idle_target_scroll_y
        end
        
        if UI_STATE.prompter_idle_scroll_y < 0 then UI_STATE.prompter_idle_scroll_y = 0 end
        if UI_STATE.prompter_idle_scroll_y > max_scroll then UI_STATE.prompter_idle_scroll_y = max_scroll end
        
        local ty = math.floor(base_ty - UI_STATE.prompter_idle_scroll_y)

        -- 1. Title
        gfx.setfont(F.title)
        set_color(UI.GET_P_COLOR(0.4))
        local tw, th = gfx.measurestr(title)
        gfx.x, gfx.y = cx - tw/2, ty + S(20)
        gfx.drawstr(title)
        
        -- 3. Horizontal Divider
        local line_w = S(160)
        local line_y = gfx.y + th + S(12)
        set_color(UI.GET_P_COLOR(0.15))
        gfx.line(cx - line_w/2, line_y, cx + line_w/2, line_y)
        
        -- 4. Stats: Takes and Time (Two columns)
        local stat_y = line_y + S(25)
        local col_w = S(80)
        
        -- LEFT: Takes
        gfx.setfont(F.lrg)
        set_color(UI.GET_P_COLOR(1.0))
        local s_takes = tostring(takes)
        local sw1, sh1 = gfx.measurestr(s_takes)
        gfx.x, gfx.y = cx - col_w - sw1/2, stat_y
        gfx.drawstr(s_takes)
        
        gfx.setfont(F.std)
        set_color(UI.GET_P_COLOR(0.4))
        local lbl1 = T("TAKES_IDLE")
        local lw1, lh1 = gfx.measurestr(lbl1)
        gfx.x, gfx.y = cx - col_w - lw1/2, stat_y + sh1 + S(2)
        gfx.drawstr(lbl1)
        
        -- RIGHT: Time
        gfx.setfont(F.lrg)
        set_color(UI.GET_P_COLOR(1.0))
        local s_time = STATS.format_hms(dur)
        local sw2, sh2 = gfx.measurestr(s_time)
        gfx.x, gfx.y = cx + col_w - sw2/2, stat_y
        gfx.drawstr(s_time)
        
        gfx.setfont(F.std)
        set_color(UI.GET_P_COLOR(0.4))
        local lbl2 = T("TIME_IDLE")
        local lw2, lh2 = gfx.measurestr(lbl2)
        gfx.x, gfx.y = cx + col_w - lw2/2, stat_y + sh2 + S(2)
        gfx.drawstr(lbl2)
        
        -- 5. Progress Bar
        local pb_w = S(220)
        local pb_h = S(3)
        local pb_y = stat_y + sh1 + lh1 + S(45)
        
        -- Label
        gfx.setfont(F.std)
        set_color(UI.GET_P_COLOR(0.6))
        local p_txt = string.format(T("RECORDED_IDLE"), math.floor(progress))
        local pw, ph = gfx.measurestr(p_txt)
        gfx.x, gfx.y = cx - pw/2, pb_y - ph - S(6)
        gfx.drawstr(p_txt)
        
        -- Track
        set_color(UI.GET_P_COLOR(0.1))
        gfx.rect(cx - pb_w/2, pb_y, pb_w, pb_h, 1)
        -- Fill (Highlight)
        set_color(UI.GET_P_COLOR(0.7))
        gfx.rect(cx - pb_w/2, pb_y, pb_w * (progress/100), pb_h, 1)
        
        -- 6. Attempts
        local num_regions = (regions and #regions > 0) and #regions or 1
        local attempts = takes / num_regions
        local attempts_txt = string.format(T("ATTEMPTS_IDLE"), attempts)
        local spw, sph = gfx.measurestr(attempts_txt)
        gfx.x, gfx.y = cx - spw/2, pb_y + pb_h + S(18)
        set_color(UI.GET_P_COLOR(0.4))
        gfx.drawstr(attempts_txt)

        local r_btn_w = S(140)
        local r_btn_y = pb_y + pb_h + S(18) + sph + S(36)
        if btn(cx - r_btn_w/2, r_btn_y, r_btn_w, S(24), fit_text_width(T("COMPACT_RENDER"), r_btn_w - S(5)), UI.C_ROW, nil, true) then
            UTILS.compact_render()
        end

        local un_scrolled_bottom = r_btn_y + S(48) + UI_STATE.prompter_idle_scroll_y
        UI_STATE.prompter_idle_total_h = un_scrolled_bottom + S(20) - base_ty
        UI_STATE.prompter_idle_target_scroll_y = draw_scrollbar(gfx.w - S(10), 0, S(10), gfx.h, UI_STATE.prompter_idle_total_h, gfx.h, UI_STATE.prompter_idle_target_scroll_y)

        return true
    else
        UI_STATE.draw_confetti(false)
        -- Simplified message: always "End of Subtitles"
        set_color(UI.GET_P_COLOR(0.3))
        gfx.setfont(F.std)
        
        local txt = T("END_OF_SUBTITLES_IDLE")
        local tw, th = gfx.measurestr(txt)
        gfx.x = content_offset_left + (available_w - tw) / 2
        gfx.y = (gfx.h - th) / 2
        if cfg.p_valign == "top" then gfx.y = S(70)
        elseif cfg.p_valign == "bottom" then gfx.y = gfx.h - th - S(50) end
        gfx.drawstr(txt)
    end

    return false
end

function DRAW_WINDOW.draw_prompter_slider(input_queue)
    local bg_r, bg_g, bg_b = cfg.bg_cr, cfg.bg_cg, cfg.bg_cb
    set_color({bg_r, bg_g, bg_b})
    gfx.rect(0, 0, gfx.w, gfx.h, 1)

    update_marker_cache()

    -- === EARLY DRAWER BUTTON CLICK CHECK ===
    if not prompter_drawer.open and prompter_drawer.has_markers_cache and prompter_drawer.has_markers_cache.result then
        local drawer_top_y = S(25)
        local btn_w = S(15)
        
        -- Calculate dynamic height (consistent with draw_prompter_drawer)
        gfx.setfont(F.tip)
        local btn_h = S(16)
        for _, code in utf8.codes(T("RETAKES_PROMPT")) do
            local _, ch = gfx.measurestr(utf8.char(code))
            btn_h = btn_h + ch - 1
        end

        local btn_x = cfg.p_drawer_left and 0 or (gfx.w - btn_w)
        local btn_y = drawer_top_y + (gfx.h - drawer_top_y - btn_h) / 2
        
        if gfx.mouse_x >= btn_x and gfx.mouse_x <= btn_x + btn_w and
           gfx.mouse_y >= btn_y and gfx.mouse_y <= btn_y + btn_h then
             if is_mouse_clicked(1) and not UI_STATE.mouse_handled then
                prompter_drawer.open = true
                UI_STATE.mouse_handled = true
                if not prompter_drawer.width or prompter_drawer.width < S(80) then
                    prompter_drawer.width = S(300)
                end
             end
        end
    end

    local content_offset_left, content_offset_right = 0, 0
    local mouse_over_drawer = false
    if prompter_drawer.open and prompter_drawer.width >= S(80) then
        if cfg.p_drawer_left then content_offset_left = prompter_drawer.width else content_offset_right = prompter_drawer.width end
        if cfg.p_drawer_left then
            if gfx.mouse_x < content_offset_left then mouse_over_drawer = true end
        else
            if gfx.mouse_x > gfx.w - content_offset_right then mouse_over_drawer = true end
        end
    end
    local available_w = gfx.w - content_offset_left - content_offset_right
    local center_x = content_offset_left + (available_w / 2)
    
    -- Catch Info Overlay Interaction EARLY to prevent fall-through
    local active_idx = -1
    local play_pos = reaper.GetPlayState() & 1 == 1 and reaper.GetPlayPosition() or reaper.GetCursorPosition()
    for i, rgn in ipairs(regions) do
        if play_pos >= rgn.pos and play_pos < rgn.rgnend then active_idx = i; break end
    end
    
    local current_active_regions = {}
    if active_idx ~= -1 then table.insert(current_active_regions, regions[active_idx]) end
    
    -- Initialize latched time if not set
    if not UI_STATE.latched_overlay_time then
        if active_idx ~= -1 then
            UI_STATE.latched_overlay_time = regions[active_idx].pos
            UI_STATE.latched_overlay_region = regions[active_idx]
        else
            UI_STATE.latched_overlay_time = play_pos
        end
    end
    
    -- Detect manual jump
    local edit_cursor = reaper.GetCursorPosition()
    local edit_cursor_changed = math.abs(edit_cursor - UI_STATE.last_edit_cursor) > 0.01
    local is_playing = (reaper.GetPlayState() & 1) == 1
    UI_STATE.last_edit_cursor = edit_cursor
    
    -- Update latched time on replica change or manual click
    if active_idx ~= -1 then
        if not UI_STATE.latched_overlay_region or UI_STATE.latched_overlay_region.idx ~= regions[active_idx].idx then
            UI_STATE.latched_overlay_time = regions[active_idx].pos
            UI_STATE.latched_overlay_region = regions[active_idx]
        elseif edit_cursor_changed then
            -- Manual click within region - show click position
            UI_STATE.latched_overlay_time = edit_cursor
        end
    elseif edit_cursor_changed then
        -- Manual click outside regions - show click position
        UI_STATE.latched_overlay_time = edit_cursor
        UI_STATE.latched_overlay_region = nil
    end
    
    handle_info_overlay_interaction(content_offset_left, content_offset_right, current_active_regions, UI_STATE.latched_overlay_time)

    local state_count = reaper.GetProjectStateChangeCount(0)
    local dict_ts = DICT.last_update_ts or ""
    
    if (prompter_slider_cache.state_count ~= state_count and UTILS.is_markers_regions_changed()) or prompter_slider_cache.state_count == -1 or prompter_slider_cache.w ~= available_w or 
       prompter_slider_cache.fsize ~= cfg.p_fsize or prompter_slider_cache.font ~= cfg.p_font or prompter_slider_cache.project_id ~= reaper.GetProjectName(0, "") or
       prompter_slider_cache.p_corr ~= cfg.p_corr or prompter_slider_cache.dict_ts ~= dict_ts or
       prompter_slider_cache.p_lheight ~= cfg.p_lheight or prompter_slider_cache.c_lheight ~= cfg.c_lheight or
       prompter_slider_cache.text_assimilations ~= cfg.text_assimilations or prompter_slider_cache.text_euphonics ~= cfg.text_euphonics then

        prompter_slider_cache.state_count, prompter_slider_cache.w, prompter_slider_cache.fsize, prompter_slider_cache.font = state_count, available_w, cfg.p_fsize, cfg.p_font
        prompter_slider_cache.project_id = reaper.GetProjectName(0, "")
        prompter_slider_cache.p_corr = cfg.p_corr
        prompter_slider_cache.dict_ts = dict_ts
        prompter_slider_cache.p_lheight = cfg.p_lheight
        prompter_slider_cache.c_lheight = cfg.c_lheight
        prompter_slider_cache.text_assimilations = cfg.text_assimilations
        prompter_slider_cache.text_euphonics = cfg.text_euphonics
        prompter_slider_cache.items, prompter_slider_cache.total_h = {}, 0
        
        local raw_items = {}
        for idx, rgn in ipairs(regions) do
            table.insert(raw_items, { type = "region", pos = rgn.pos, data = rgn, idx = idx })
        end
        if cfg.p_corr then
            for idx, m in ipairs(prompter_drawer.marker_cache.markers) do
                table.insert(raw_items, { type = "correction", pos = m.pos, data = m, idx = idx })
            end
        end
        table.sort(raw_items, function(a, b) return a.pos < b.pos end)

        local max_w = available_w - S(40)
        
        for _, raw in ipairs(raw_items) do
            if raw.type == "region" then
                local rgn = raw.data
                local p_lines = parse_prompter_to_lines(rgn.name)
                local flattened = {}
                for i, pl in ipairs(p_lines) do
                    if i > 1 and #flattened > 0 then table.insert(flattened, {text=" ", is_newline = true}) end
                    for _, span in ipairs(pl) do table.insert(flattened, span) end
                end
                
                local target_fsize = cfg.p_fsize
                local min_fsize = 12
                local lines, item_h, lh
                
                local actor_indent = 0
                if cfg.show_actor_name_infront and rgn.actor and rgn.actor ~= "" then
                    gfx.setfont(F.lrg, cfg.p_font, S(target_fsize - 2))
                    actor_indent = gfx.measurestr("[" .. rgn.actor .. "] ")
                end

                repeat
                    gfx.setfont(F.lrg, cfg.p_font, S(target_fsize))
                    lh = math.floor(gfx.texth * cfg.p_lheight)
                    
                    local current_actor_indent = 0
                    if actor_indent > 0 then
                        gfx.setfont(F.lrg, cfg.p_font, S(target_fsize - 2))
                        current_actor_indent = gfx.measurestr("[" .. rgn.actor .. "] ")
                    end

                    lines = wrap_rich_text(flattened, max_w, F.lrg, cfg.p_font, S(target_fsize), false, current_actor_indent)
                    item_h = #lines * lh + S(40)
                    if item_h < gfx.h * 0.7 or target_fsize <= min_fsize then break end
                    target_fsize = target_fsize - 2
                until false
                
                table.insert(prompter_slider_cache.items, {type = "region", h = item_h, lines = lines, y = prompter_slider_cache.total_h, fsize = S(target_fsize), lh = lh, region = rgn, region_idx = raw.idx})
                prompter_slider_cache.total_h = prompter_slider_cache.total_h + item_h
            else
                -- Correction Item
                local m = raw.data
                local name = m.name or ""
                if name == "" then name = T("EMPTY") end
                local p_lines = parse_prompter_to_lines(name, true)
                local flattened = {}
                for i, pl in ipairs(p_lines) do
                    if i > 1 and #flattened > 0 then table.insert(flattened, {text=" ", is_newline = true}) end
                    for _, span in ipairs(pl) do table.insert(flattened, span) end
                end
                
                gfx.setfont(F.cor, cfg.p_font, S(cfg.c_fsize))
                local lh = math.floor(gfx.texth * (cfg.c_lheight or 1.0))
                local lines = wrap_rich_text(flattened, max_w, F.cor, cfg.p_font, S(cfg.c_fsize), false, 0)
                local item_h = #lines * lh + S(20)
                
                table.insert(prompter_slider_cache.items, {type = "correction", h = item_h, lines = lines, y = prompter_slider_cache.total_h, fsize = S(cfg.c_fsize), lh = lh, marker = m})
                prompter_slider_cache.total_h = prompter_slider_cache.total_h + item_h
            end
        end
    end

    if prompter_slider_cache.state_count ~= state_count then
        prompter_slider_cache.state_count = state_count
    end

    local now = reaper.time_precise()
    local is_playing = reaper.GetPlayState() & 1 == 1
    local pos_jumped = math.abs(play_pos - (UI_STATE.last_tracked_pos or 0)) > 0.5

    -- Auto-resume auto-scroll on significant jump or playback start
    if pos_jumped or (is_playing and not UI_STATE.last_play_state) then
        UI_STATE.skip_auto_scroll = false
    end
    UI_STATE.last_tracked_pos = play_pos
    UI_STATE.last_play_state = is_playing

    if gfx.mouse_wheel ~= 0 and not mouse_over_drawer then
        UI_STATE.prompter_slider_target_y = UI_STATE.prompter_slider_target_y - (gfx.mouse_wheel * 0.5)
        
        -- Clamp scroll position to content bounds
        local min_y = 0
        local max_y = prompter_slider_cache.total_h
        if prompter_slider_cache.items and #prompter_slider_cache.items > 0 then
            local first_item = prompter_slider_cache.items[1]
            local last_item = prompter_slider_cache.items[#prompter_slider_cache.items]
            min_y = first_item.y + first_item.h / 2
            max_y = last_item.y + last_item.h / 2
        end
        UI_STATE.prompter_slider_target_y = math.max(min_y, math.min(max_y, UI_STATE.prompter_slider_target_y))
        
        gfx.mouse_wheel = 0
        UI_STATE.skip_auto_scroll = true
    end

    if active_idx ~= -1 and not UI_STATE.skip_auto_scroll then
        for _, item in ipairs(prompter_slider_cache.items) do
            if item.type == "region" and item.region_idx == active_idx then
                UI_STATE.prompter_slider_target_y = item.y + item.h / 2
                break
            end
        end
    end

    local diff = UI_STATE.prompter_slider_target_y - UI_STATE.prompter_slider_y
    if math.abs(diff) > 0.1 then UI_STATE.prompter_slider_y = UI_STATE.prompter_slider_y + diff * 0.15 else UI_STATE.prompter_slider_y = UI_STATE.prompter_slider_target_y end

    local screen_center_y = gfx.h / 2
    local draw_y_offset = screen_center_y - UI_STATE.prompter_slider_y

    for i, item in ipairs(prompter_slider_cache.items) do
        local y_top = item.y + draw_y_offset
        local y_bottom = y_top + item.h
        if y_bottom > 0 and y_top < gfx.h then
            -- Interaction detection
            if is_mouse_clicked(1) and not UI_STATE.mouse_handled and gfx.mouse_y > S(25) then
                if gfx.mouse_x >= content_offset_left and gfx.mouse_x <= gfx.w - content_offset_right and
                   gfx.mouse_y >= y_top and gfx.mouse_y <= y_bottom then
                    
                    if item.type == "region" then
                        if UI_STATE.last_click_row == -100 - i and (now - UI_STATE.last_click_time) < 0.35 then
                            -- DOUBLE CLICK: Open Editor
                            local rgn = item.region
                            for idx, line in ipairs(ass_lines) do
                                if math.abs(line.t1 - rgn.pos) < 0.01 and 
                                   math.abs(line.t2 - rgn.rgnend) < 0.01 and
                                   UTILS.compare_sub_text(line.text, rgn.name) then
                                    local edit_line = line
                                    open_text_editor(line.text, function(new_text)
                                        push_undo(T("EDIT_LINE"))
                                        edit_line.text = new_text
                                        UI_STATE._markers_is_dirty = true
                                        rebuild_regions()
                                    end, idx, ass_lines)
                                    break
                                end
                            end
                            UI_STATE.last_click_row = 0
                        else
                            -- SINGLE CLICK: Scroll to
                            reaper.SetEditCurPos(item.region.pos, true, false)
                            UI_STATE.skip_auto_scroll = false
                            UI_STATE.last_click_time = now
                            UI_STATE.last_click_row = -100 - i
                        end
                    elseif item.type == "correction" then
                         if UI_STATE.last_click_row == -100 - i and (now - UI_STATE.last_click_time) < 0.35 then
                            -- DOUBLE CLICK: Open Editor for Correction
                            local m = item.marker
                            local function marker_callback(new_text)
                                push_undo(T("EDIT_RETAKE"))
                                local target_idx = -1
                                local marker_count = reaper.CountProjectMarkers(0)
                                for j = 0, marker_count - 1 do
                                    local _, isrgn, pos, _, _, markindex = reaper.EnumProjectMarkers3(0, j)
                                    if not isrgn then
                                        if markindex == m.markindex or math.abs(pos - m.pos) < 0.001 then
                                            target_idx = j; m.pos = pos; break
                                        end
                                    end
                                end

                                if target_idx ~= -1 then
                                    reaper.SetProjectMarkerByIndex(0, target_idx, false, m.pos, 0, m.markindex, new_text, m.color or 0)
                                else
                                    reaper.SetProjectMarker4(0, m.markindex, false, m.pos, 0, new_text, m.color or 0, 0)
                                end
                                ass_markers = capture_project_markers()
                                prompter_drawer.marker_cache.count = -1
                                table_data_cache.state_count = -1 
                                last_layout_state.state_count = -1 
                                update_marker_cache()
                                rebuild_regions()
                                reaper.UpdateTimeline()
                                reaper.UpdateArrange()
                            end
                            open_text_editor(m.name:gsub(T("EMPTY"), ""), marker_callback, 1, {{text = m.name:gsub(T("EMPTY"), "")}}, true)
                            UI_STATE.last_click_row = 0
                        else
                            -- SINGLE CLICK: Scroll to
                            reaper.SetEditCurPos(item.marker.pos, true, false)
                            UI_STATE.skip_auto_scroll = false
                            UI_STATE.last_click_time = now
                            UI_STATE.last_click_row = -100 - i
                        end
                    end
                    UI_STATE.mouse_handled = true
                end
            end

            -- Drawing
            local lines_to_draw = item.lines
            local text_y = y_top + (item.type == "region" and S(20) or S(10))
            
            if item.type == "region" then
                local is_active = (item.region_idx == active_idx)
                local alpha = is_active and 1.0 or 0.2
                set_color(UI.GET_P_COLOR(alpha))
                
                if cfg.karaoke_mode and is_active then
                    local w_count = count_words_in_lines(item.lines)
                    local k_idx = get_karaoke_word_index(item.region.pos, item.region.rgnend, play_pos, w_count)
                    if k_idx then
                        lines_to_draw = apply_karaoke_style(item.lines, k_idx)
                    end
                end

                for idx, line in ipairs(lines_to_draw) do
                    local act = (idx == 1) and item.region.actor or nil
                    draw_rich_line(line, center_x, text_y, F.lrg, cfg.p_font, item.fsize, false, act, available_w, content_offset_left, content_offset_right)
                    text_y = text_y + item.lh
                end
            else
                -- Correction Rendering
                local m = item.marker
                local alpha = 1.0 -- Corrections are always visible if they are in view? 
                -- Or maybe dim them if they are far? Let's keep them bright for now as they are "pravki".
                set_color(UI.GET_C_COLOR(alpha))
                
                for idx, line in ipairs(lines_to_draw) do
                    draw_rich_line(line, center_x, text_y, F.cor, cfg.p_font, item.fsize, true, nil, available_w, content_offset_left, content_offset_right)
                    text_y = text_y + item.lh
                end
            end
        end
    end

    -- Compact render button pinned after all slider items
    if #prompter_slider_cache.items > 0 then
        local last_item = prompter_slider_cache.items[#prompter_slider_cache.items]
        local btn_y = last_item.y + last_item.h + draw_y_offset + S(36)
        local r_btn_w = S(140)
        local btn_x = content_offset_left + (available_w - r_btn_w) / 2
        gfx.setfont(F.std) -- ensure correct font before fit_text_width measurement
        if btn(btn_x, btn_y, r_btn_w, S(24), fit_text_width(T("COMPACT_RENDER"), r_btn_w - S(5)), UI.C_ROW, nil, true) then
            UTILS.compact_render()
        end
    end

    local is_show_final_stats = false
    if #prompter_slider_cache.items == 0 then
        is_show_final_stats = STATS.render_prompter_idle(available_w, content_offset_left, content_offset_right)
    end

    -- Info Overlay graphics (at the end of content)
    local current_active_regions = {}
    if active_idx ~= -1 then table.insert(current_active_regions, regions[active_idx]) end
    DRAW_WINDOW.draw_info_overlay_graphics(content_offset_left, content_offset_right, current_active_regions, UI_STATE.latched_overlay_time, active_idx)

    if cfg.p_drawer then DRAW_WINDOW.draw_prompter_drawer(input_queue) end

    handle_prompter_context_menu(is_show_final_stats)

    -- Post-interaction check: resume auto-scroll if clicked on background
    if is_mouse_clicked(1) and not UI_STATE.mouse_handled then
        UI_STATE.skip_auto_scroll = false
    end
end

function DRAW_TABS.draw_prompter(input_queue)
    if cfg.prompter_slider_mode then
        DRAW_WINDOW.draw_prompter_slider(input_queue)
        return
    end

    -- Draw Custom Background
    set_color(UI.GET_BG_COLOR())
    gfx.rect(0, 0, gfx.w, gfx.h, 1)

    -- === EARLY DRAWER BUTTON CLICK CHECK ===
    if not prompter_drawer.open and prompter_drawer.has_markers_cache and prompter_drawer.has_markers_cache.result then
        local drawer_top_y = S(25)
        local btn_w = S(15)
        
        -- Calculate dynamic height (consistent with draw_prompter_drawer)
        gfx.setfont(F.tip)
        local btn_h = S(16)
        for _, code in utf8.codes(T("RETAKES_PROMPT")) do
            local _, ch = gfx.measurestr(utf8.char(code))
            btn_h = btn_h + ch - 1
        end

        local btn_x = cfg.p_drawer_left and 0 or (gfx.w - btn_w)
        local btn_y = drawer_top_y + (gfx.h - drawer_top_y - btn_h) / 2
        
        if gfx.mouse_x >= btn_x and gfx.mouse_x <= btn_x + btn_w and
           gfx.mouse_y >= btn_y and gfx.mouse_y <= btn_y + btn_h then
            if is_mouse_clicked(1) and not UI_STATE.mouse_handled then
                prompter_drawer.open = true
                UI_STATE.mouse_handled = true
                if not prompter_drawer.width or prompter_drawer.width < S(80) then
                    prompter_drawer.width = S(300)
                end
            end
        end
    end

    -- === DRAWER CONTENT OFFSET CALCULATION ===
    local content_offset_left = 0
    local content_offset_right = 0
    if prompter_drawer.open and prompter_drawer.width >= S(80) then
        if cfg.p_drawer_left then
            content_offset_left = prompter_drawer.width
        else
            content_offset_right = prompter_drawer.width
        end
    end
    local available_w = gfx.w - content_offset_left - content_offset_right
    local center_x = content_offset_left + (available_w / 2)
    -- === END DRAWER OFFSET ===

    -- Logic: Use Play Position if playing, otherwise Edit Cursor
    local play_state = reaper.GetPlayState()
    local cur_pos = 0
    if (play_state & 1) == 1 then
        cur_pos = reaper.GetPlayPosition()
    else
        cur_pos = reaper.GetCursorPosition()
    end

    -- EARLY INTERACTION CHECK
    local active_regions_for_info = {}
    for _, rgn in ipairs(regions) do
        if cur_pos >= rgn.pos and cur_pos < rgn.rgnend then
            table.insert(active_regions_for_info, rgn)
        end
    end
    
    -- Initialize latched time if not set
    if not UI_STATE.latched_overlay_time then
        if #active_regions_for_info > 0 then
            UI_STATE.latched_overlay_time = active_regions_for_info[1].pos
            UI_STATE.latched_overlay_region = active_regions_for_info[1]
        else
            UI_STATE.latched_overlay_time = cur_pos
        end
    end
    
    -- Detect manual jump (edit cursor change)
    local edit_cursor = reaper.GetCursorPosition()
    local edit_cursor_changed = math.abs(edit_cursor - UI_STATE.last_edit_cursor) > 0.01
    UI_STATE.last_edit_cursor = edit_cursor
    
    -- Update latched time on replica change or manual click
    if #active_regions_for_info > 0 then
        if not UI_STATE.latched_overlay_region or UI_STATE.latched_overlay_region.idx ~= active_regions_for_info[1].idx then
            UI_STATE.latched_overlay_time = active_regions_for_info[1].pos
            UI_STATE.latched_overlay_region = active_regions_for_info[1]
        elseif edit_cursor_changed then
            -- Manual click within region - show click position
            UI_STATE.latched_overlay_time = edit_cursor
        end
    elseif edit_cursor_changed then
        -- Manual click outside regions - show click position
        UI_STATE.latched_overlay_time = edit_cursor
        UI_STATE.latched_overlay_region = nil
    end
    
    handle_info_overlay_interaction(content_offset_left, content_offset_right, active_regions_for_info, UI_STATE.latched_overlay_time)

    update_marker_cache()

    -- Find ALL regions that contain the current position
    local active_regions = {}
    local active_idx = -1
    local next_rgn = nil
    local next_rgn2 = nil
    local prev_rgn_end = 0
    for i, rgn in ipairs(regions) do
        if cur_pos >= rgn.pos and cur_pos < rgn.rgnend then
            table.insert(active_regions, rgn)
            if active_idx == -1 then active_idx = i end
        end
        if rgn.pos > cur_pos then
            if not next_rgn then
                next_rgn = rgn
            elseif not next_rgn2 then
                next_rgn2 = rgn
            end
        end
        if rgn.rgnend <= cur_pos then
            if rgn.rgnend > prev_rgn_end then
                prev_rgn_end = rgn.rgnend
            end
        end
    end

    -- CPS Warning Strip
    if cfg.cps_warning then
        local max_cps = 0
        local regions_to_check = active_regions
        
        -- If no active regions, check the next available region
        if #active_regions == 0 and next_rgn then
            regions_to_check = {next_rgn}
        end

        if #regions_to_check > 0 then
            for _, rgn in ipairs(regions_to_check) do
                local dur = rgn.rgnend - rgn.pos
                if dur > 0 then
                    -- Strip formatting and comments for accurate char count
                    local clean_text = rgn.name:gsub("{{+.-}}+", ""):gsub("{.-}", ""):gsub("\\N", ""):gsub("\n", ""):gsub(" ", ""):gsub(acute, "")
                    -- Use utf8.len
                    local char_count = utf8.len(clean_text) or #clean_text
                    local cps = char_count / dur
                    if cps > max_cps then max_cps = cps end
                end
            end

            if max_cps >= 15 then
                local col = UTILS.get_cps_color(max_cps)
                set_color({col[1], col[2], col[3], 0.8})
                gfx.rect(content_offset_left, S(25), available_w, S(2), 1) -- Top warning strip
            end
        end
    end
    
    -- Use first active region for interactions (backward compatibility)
    local region_idx = -1
    if #active_regions > 0 then
        -- We already have rgn_index (internal REAPER index) stored in our region object!
        -- No need to loop through EnumProjectMarkers every frame.
        region_idx = active_regions[1].rgn_index or -1
    end
    
    -- Helper function to render next replica (defined here to be accessible in both branches)
    local function render_next_replica(next_rgn, y_position_mode, override_fsize, y_offset)
        if not next_rgn then return 0, 0 end
        y_offset = y_offset or 0
        
        set_color(UI.GET_N_COLOR())
        
        -- Parse Text (with Cache)
        local display_name = next_rgn.name
        if not display_name or display_name:gsub("{{+.-}}+", ""):gsub("{.-}", ""):match("^%s*$") then display_name = T("EMPTY") end
        if not draw_prompter_cache.next_cache[display_name] then
            draw_prompter_cache.next_cache[display_name] = parse_prompter_to_lines(display_name)
        end
        local n_lines = draw_prompter_cache.next_cache[display_name]
        
        -- Scale Next
        local max_w = available_w - S(40)
        local n_max_raw_w = 0
        local n_flags = 0
        if cfg.karaoke_mode then n_flags = string.byte('b') end
        
        local base_fsize = override_fsize or cfg.n_fsize
        gfx.setfont(F.nxt, cfg.p_font, base_fsize, n_flags)
        
        local next_actor_w = 0
        if cfg.show_actor_name_infront and next_rgn.actor and next_rgn.actor ~= "" then
            gfx.setfont(F.nxt, cfg.p_font, math.max(10, base_fsize - 2))
            next_actor_w = gfx.measurestr("[" .. next_rgn.actor .. "] ")
            gfx.setfont(F.nxt, cfg.p_font, base_fsize, n_flags)
        end

        for _, line in ipairs(n_lines) do
            local raw = ""
            for _, span in ipairs(line) do 
                local t = span.text:gsub(acute, "")
                if cfg.all_caps then t = utf8_upper(t) end
                raw = raw .. t 
            end
            local w = gfx.measurestr(raw) + next_actor_w
            if w > n_max_raw_w then n_max_raw_w = w end
        end
        
        local n_draw_size = base_fsize
        if n_max_raw_w > max_w then
            local ratio = max_w / n_max_raw_w
            n_draw_size = math.floor(n_draw_size * ratio)
            if n_draw_size < S(10) then n_draw_size = S(10) end
        end
        
        gfx.setfont(F.nxt, cfg.p_font, n_draw_size, n_flags)
        local raw_lh = gfx.texth
        local n_lh = math.floor(raw_lh * (cfg.n_lheight or 1.0))
        local n_total_h = #n_lines * n_lh
        
        -- Center text vertically within line height if needed
        local y_off = math.floor((n_lh - raw_lh) / 2)
        
        -- Position: bottom (when in region) or center (when not in region)
        local n_start_y
        if type(y_position_mode) == "number" then
            n_start_y = y_position_mode + y_offset
        elseif y_position_mode == "bottom" then
            n_start_y = gfx.h - n_total_h - S(10) - y_offset
        elseif y_position_mode == "top" then
            n_start_y = S(50) + y_offset
        else -- "center"
            n_start_y = (gfx.h - n_total_h) / 2 + y_offset
        end
        
        -- Bounds for click
        local n_x1, n_y1, n_x2, n_y2 = gfx.w, gfx.h, 0, 0
        
        for i, line in ipairs(n_lines) do
            local y = n_start_y + (i-1) * n_lh
            -- Pass next_rgn.actor if available
            local actor_arg = (i==1 and next_rgn) and next_rgn.actor or nil 
            -- Assuming we only show actor on first line of multi-line? 
            if i > 1 then actor_arg = nil end
            
            local lx, ly, lw, l_h = draw_rich_line(line, center_x, y + y_off, F.nxt, cfg.p_font, n_draw_size, false, actor_arg, available_w, content_offset_left, content_offset_right)
            
            if lx < n_x1 then n_x1 = lx end
            if ly < n_y1 then n_y1 = ly end
            if lx + lw > n_x2 then n_x2 = lx + lw end
            if ly + l_h > n_y2 then n_y2 = ly + l_h end
        end
        
        -- Double-click on next text to edit
        if is_mouse_clicked() and (not dict_modal.show) and (not UI_STATE.mouse_handled) then
            if gfx.mouse_x >= n_x1 - 20 and gfx.mouse_x <= n_x2 + 20 and
               gfx.mouse_y >= n_y1 - 10 and gfx.mouse_y <= n_y2 + 10 then
                UI_STATE.mouse_handled = true
                local now = reaper.time_precise()
                if UI_STATE.last_click_row == -2 and (now - UI_STATE.last_click_time) < 0.5 then
                    -- Find corresponding ass_line
                    for i, line in ipairs(ass_lines) do
                        if math.abs(line.t1 - next_rgn.pos) < 0.01 and math.abs(line.t2 - next_rgn.rgnend) < 0.01 then
                            local edit_line = line
                            open_text_editor(line.text, function(new_text)
                                push_undo(T("EDIT_LINE"))
                                edit_line.text = new_text
                                UI_STATE._markers_is_dirty = true
                                rebuild_regions()
                            end, i, ass_lines)
                            break
                        end
                    end
                    UI_STATE.last_click_row = 0
                else
                    UI_STATE.last_click_time = now
                    UI_STATE.last_click_row = -2 -- Use -2 as marker for next text
                end
            end
        end
        
        return n_total_h, n_start_y
    end
    
    local is_show_final_stats = false
    if region_idx >= 0 then
        local retval, isrgn, pos, rgnend, name, idx = reaper.EnumProjectMarkers(region_idx)
        
        if isrgn then
            -- Collect ALL text blocks to display
            local max_w = available_w - S(40)
            local total_combined_height = 0
            local all_text_blocks = {}
            local S_GAP = S(15)

            for region_num, rgn in ipairs(active_regions) do
                local lines
                
                -- Use cache for first region (optimization)
                if region_num == 1 then
                    local display_name = rgn.name
                    if not display_name or display_name:gsub("{{+.-}}+", ""):gsub("{.-}", ""):match("^%s*$") then display_name = T("EMPTY") end
                    if display_name ~= draw_prompter_cache.last_text then
                        draw_prompter_cache.lines = parse_prompter_to_lines(display_name)
                        draw_prompter_cache.last_text = display_name
                    end
                    lines = draw_prompter_cache.lines
                    
                    -- KARAOKE LOGIC APPLICATION
                    if cfg.karaoke_mode then
                        -- Clone structure to avoid modifying cache permanently for this frame
                        -- (Actually we parse every time lazily, but modifying 'lines' which is ref to cache is bad)
                        local w_count = count_words_in_lines(lines)
                        local k_idx = get_karaoke_word_index(rgn.pos, rgn.rgnend, cur_pos, w_count)
                        if k_idx then
                            lines = apply_karaoke_style(lines, k_idx)
                        end
                    end
                else
                    -- Parse text for other regions
                    local display_name = rgn.name
                    if not display_name or display_name:gsub("{{+.-}}+", ""):gsub("{.-}", ""):match("^%s*$") then display_name = T("EMPTY") end
                    lines = parse_prompter_to_lines(display_name)
                    if cfg.karaoke_mode then
                        local w_count = count_words_in_lines(lines)
                        local k_idx = get_karaoke_word_index(rgn.pos, rgn.rgnend, cur_pos, w_count)
                        if k_idx then
                            lines = apply_karaoke_style(lines, k_idx)
                        end
                    end
                end
                
                -- Find max width and calculate scale
                local max_raw_w = 0
                local p_flags = 0
                if cfg.karaoke_mode then p_flags = string.byte('b') end
                
                local current_actor_w = 0
                if cfg.show_actor_name_infront and rgn.actor and rgn.actor ~= "" then
                    gfx.setfont(F.lrg, cfg.p_font, math.max(10, cfg.p_fsize - 2))
                    current_actor_w = gfx.measurestr("[" .. rgn.actor .. "] ")
                end

                gfx.setfont(F.lrg, cfg.p_font, cfg.p_fsize, p_flags)
                
                for _, line in ipairs(lines) do
                    local raw = ""
                    for _, span in ipairs(line) do 
                        local t = span.text:gsub(acute, "")
                        if cfg.all_caps then t = utf8_upper(t) end
                        raw = raw .. t 
                    end
                    local w = gfx.measurestr(raw) + current_actor_w
                    if w > max_raw_w then max_raw_w = w end
                end
                
                local draw_size = cfg.p_fsize
                if max_raw_w > max_w then
                    local ratio = max_w / max_raw_w
                    draw_size = math.floor(draw_size * ratio)
                    if draw_size < 10 then draw_size = 10 end
                end
                
                gfx.setfont(F.lrg, cfg.p_font, draw_size, p_flags)
                local raw_lh = gfx.texth
                local lh = math.floor(raw_lh * (cfg.p_lheight or 1.0))
                local block_height = #lines * lh
                
                table.insert(all_text_blocks, {
                    lines = lines,
                    draw_size = draw_size,
                    lh = lh,
                    raw_lh = raw_lh,
                    block_height = block_height,
                    actor = rgn.actor -- Capture actor
                })
                
                if #all_text_blocks > 1 then
                    total_combined_height = total_combined_height + S_GAP
                end
                total_combined_height = total_combined_height + block_height
            end
            
            -- --- VERTICAL SCALING LOGIC ---
            local next_r = nil
            local next_r2 = nil
            for _, r in ipairs(regions) do
                if r.pos > cur_pos then
                    if not next_r then next_r = r
                    else next_r2 = r break end
                end
            end
            
            -- --- COORDINATED LAYOUT LOGIC ---
            -- 1. Estimate Unscaled Heights
            local unscaled_next_h = 0
            if cfg.p_next and next_r then
                gfx.setfont(F.nxt, cfg.p_font, cfg.n_fsize)
                local n_lines = parse_prompter_to_lines(next_r.name)
                unscaled_next_h = #n_lines * math.floor(gfx.texth * (cfg.n_lheight or 1.0))
                
                if cfg.show_next_two and next_r2 then
                    local n_lines2 = parse_prompter_to_lines(next_r2.name)
                    unscaled_next_h = unscaled_next_h + S(15) + #n_lines2 * math.floor(gfx.texth * (cfg.n_lheight or 1.0))
                end
            end
            
            local cms, unscaled_ch = get_corrections_to_draw(cur_pos, active_regions)
            
            -- Calculate total unscaled stack height
            local total_unscaled_h = total_combined_height
            if unscaled_ch > 0 then 
                total_unscaled_h = total_unscaled_h + (total_unscaled_h > 0 and S_GAP or 0) + unscaled_ch 
            end
            if unscaled_next_h > 0 then 
                total_unscaled_h = total_unscaled_h + (total_unscaled_h > 0 and S_GAP or 0) + unscaled_next_h 
            end
            
            local available_h = gfx.h - 100 -- Margin for info overlay and padding
            local v_scale = 1.0
            if total_unscaled_h > available_h then
                v_scale = available_h / total_unscaled_h
            end

            -- 2. Apply scaling and update final heights
            total_combined_height = 0
            for i, block in ipairs(all_text_blocks) do
                block.draw_size = math.max(10, math.floor(block.draw_size * v_scale))
                gfx.setfont(F.lrg, cfg.p_font, block.draw_size, p_flags)
                block.raw_lh = gfx.texth
                block.lh = math.floor(block.raw_lh * (cfg.p_lheight or 1.0))
                block.block_height = #block.lines * block.lh
                
                if i > 1 then total_combined_height = total_combined_height + S_GAP end
                total_combined_height = total_combined_height + block.block_height
            end
            
            local scaled_n_fsize = math.max(10, math.floor(cfg.n_fsize * v_scale))
            local next_h = 0
            if cfg.p_next and next_r then
                gfx.setfont(F.nxt, cfg.p_font, scaled_n_fsize)
                local n_lines = parse_prompter_to_lines(next_r.name)
                next_h = #n_lines * math.floor(gfx.texth * (cfg.n_lheight or 1.0))
                
                if cfg.show_next_two and next_r2 then
                    local n_lines2 = parse_prompter_to_lines(next_r2.name)
                    next_h = next_h + S(15) + #n_lines2 * math.floor(gfx.texth * (cfg.n_lheight or 1.0))
                end
            end

            local cms, _ = get_corrections_to_draw(cur_pos, active_regions)
            local max_c_raw_w = 0
            gfx.setfont(F.cor, cfg.p_font, cfg.c_fsize)
            for _, m in ipairs(cms) do
                local c_lines = parse_prompter_to_lines(m.name or "", true)
                for _, line in ipairs(c_lines) do
                    local raw = ""
                    for _, span in ipairs(line) do raw = raw .. span.text:gsub(acute, "") end
                    if cfg.all_caps then raw = utf8_upper(raw) end
                    local w = gfx.measurestr(raw)
                    if w > max_c_raw_w then max_c_raw_w = w end
                end
            end
            
            local c_draw_size = cfg.c_fsize
            if max_c_raw_w > max_w then
                c_draw_size = math.floor(c_draw_size * (max_w / max_c_raw_w))
            end

            local scaled_c_fsize = math.max(10, math.floor(c_draw_size * v_scale))
            local _, corrections_h = get_corrections_to_draw(cur_pos, active_regions, scaled_c_fsize)
            
            -- Recalculate Final Pooled Height for Centering
            local active_corr_h = total_combined_height
            if corrections_h > 0 then 
                active_corr_h = active_corr_h + (active_corr_h > 0 and S_GAP or 0) + corrections_h 
            end

            -- Set active marker for drawer synchronization
            prompter_drawer.active_markindex = (corrections_h > 0) and cms[1].markindex or nil
            -- --- END VERTICAL SCALING ---

            -- Calculate starting Y position: 
            local start_y = (gfx.h - active_corr_h) / 2
            local next_reserve = S(30)
            if cfg.p_next and next_r then
                next_reserve = next_h + S(30)
                if cfg.next_attach then
                    next_reserve = next_h + S(cfg.next_padding) + S(25)
                end
            end
            
            if cfg.p_valign == "top" then
                start_y = S(60)
            elseif cfg.p_valign == "bottom" then
                start_y = gfx.h - active_corr_h - next_reserve
            end

            local top_limit = S(50) -- Account for info overlay and top margin
            local bottom_limit = (next_h > 0) and (gfx.h - next_reserve) or (gfx.h - S(50))
            
            -- Resolve collisions: if we hit boundaries, shift text
            if start_y < top_limit then start_y = top_limit end
            if start_y + active_corr_h > bottom_limit then
                start_y = bottom_limit - active_corr_h
                -- Final safety check against top if everything is too tight
                if start_y < top_limit then start_y = top_limit end
            end
            local current_y = start_y
            
            -- Store bounds for each block for click detection
            local block_bounds = {}
            
            -- Draw Waveform Background FIRST (behind text, centered on screen)
            if cfg.wave_bg and #active_regions > 0 then
                -- 1. KEEP ORIGINAL BEHAVIOR: Trigger analysis for active_regions[1] to not break karaoke mode
                local main_rgn = active_regions[1]
                local main_key = tostring(main_rgn.pos) .. "_" .. tostring(main_rgn.rgnend)
                local main_map = karaoke_cache[main_key]
                
                if not main_map then
                    -- Trigger analysis if not in cache (Decoupled from Karaoke Logic)
                    main_map = get_audio_energy_map(main_rgn.pos, main_rgn.rgnend)
                    if main_map then
                       karaoke_cache[main_key] = main_map
                    else
                       karaoke_cache[main_key] = { empty = true }
                    end
                end

                -- 2. WAVEFORM DRAWING LOGIC: Find best region to draw (<= 60s)
                local target_rgn = nil
                for _, r in ipairs(active_regions) do
                    local duration = r.rgnend - r.pos
                    if duration <= 60 then
                        if not target_rgn or duration < (target_rgn.rgnend - target_rgn.pos) then
                            target_rgn = r
                        end
                    end
                end

                if target_rgn then
                    local target_key = tostring(target_rgn.pos) .. "_" .. tostring(target_rgn.rgnend)
                    local target_map = karaoke_cache[target_key]
                    
                    if not target_map then
                        target_map = get_audio_energy_map(target_rgn.pos, target_rgn.rgnend)
                        if target_map then
                           karaoke_cache[target_key] = target_map
                        else
                           karaoke_cache[target_key] = { empty = true }
                        end
                    end
                    
                    if target_map and not target_map.empty then
                        -- Draw centered on screen (accounting for drawer offset)
                        local wave_h = gfx.h * 0.5
                        local progress = (cur_pos - target_rgn.pos) / (target_rgn.rgnend - target_rgn.pos)
                        draw_waveform_bg(target_map, content_offset_left + 20, (gfx.h - wave_h) / 2, available_w - 40, wave_h, progress)
                    end
                end
            end
 
            -- Draw all text blocks with prompt color
            set_color(UI.GET_P_COLOR())
            for block_idx, block in ipairs(all_text_blocks) do
                local block_x1, block_y1, block_x2, block_y2 = gfx.w, gfx.h, 0, 0
                
                -- Apply vertical scaling to block dimensions
                local scaled_draw_size = math.max(10, math.floor(block.draw_size * v_scale))
                local scaled_lh = math.floor(block.lh * v_scale)
                local scaled_raw_lh = math.floor(block.raw_lh * v_scale)
                local y_off = math.floor((scaled_lh - scaled_raw_lh) / 2)
                
                for i, line in ipairs(block.lines) do
                    local y = current_y + (i-1) * scaled_lh
                    -- Show actor on first line of block only
                    local act = (i == 1) and block.actor or nil
                    local lx, ly, lw, l_h = draw_rich_line(line, center_x, y + y_off, F.lrg, cfg.p_font, scaled_draw_size, false, act, available_w, content_offset_left, content_offset_right)
                    
                    -- Update bounds for this block
                    if lx < block_x1 then block_x1 = lx end
                    if ly < block_y1 then block_y1 = ly end
                    if lx + lw > block_x2 then block_x2 = lx + lw end
                    if ly + l_h > block_y2 then block_y2 = ly + l_h end
                end
                
                -- Store bounds with padding for this block
                table.insert(block_bounds, {
                    x1 = block_x1 - 20,
                    y1 = block_y1 - 10,
                    x2 = block_x2 + 20,
                    y2 = block_y2 + 10,
                    region = active_regions[block_idx]
                })
                
                local actual_block_h = #block.lines * scaled_lh
                current_y = current_y + actual_block_h + S_GAP
                
                -- Draw separator if not the last block
                if block_idx < #all_text_blocks then
                    local sep_w = S(40)
                    local sep_y = current_y - S_GAP / 2
                    set_color(UI.GET_P_COLOR(0.2))
                    gfx.line(center_x - sep_w/2, sep_y, center_x + sep_w/2, sep_y)
                    set_color(UI.GET_P_COLOR(1.0))
                end
            end
            
            -- Double-click to edit (check all blocks)
            if is_mouse_clicked() and (not dict_modal.show) and (not UI_STATE.mouse_handled) then
                -- Check which block was clicked
                for _, bounds in ipairs(block_bounds) do
                    if gfx.mouse_x >= bounds.x1 and gfx.mouse_x <= bounds.x2 and
                       gfx.mouse_y >= bounds.y1 and gfx.mouse_y <= bounds.y2 then
                        UI_STATE.mouse_handled = true
                        local now = reaper.time_precise()
                        if UI_STATE.last_click_row == -1 and (now - UI_STATE.last_click_time) < 0.5 then
                            -- Find the corresponding ass_line for this region
                            for i, line in ipairs(ass_lines) do
                                if math.abs(line.t1 - bounds.region.pos) < 0.01 and 
                                   math.abs(line.t2 - bounds.region.rgnend) < 0.01 and
                                   UTILS.compare_sub_text(line.text, bounds.region.name) then
                                    local edit_line = line
                                    open_text_editor(line.text, function(new_text)
                                        push_undo(T("EDIT_LINE"))
                                        edit_line.text = new_text
                                        UI_STATE._markers_is_dirty = true
                                        rebuild_regions()
                                    end, i, ass_lines)
                                    break
                                end
                            end
                            UI_STATE.last_click_row = 0
                        else
                            UI_STATE.last_click_time = now
                            UI_STATE.last_click_row = -1
                        end
                        break -- Stop checking other blocks once we found a hit
                    end
                end
            end
            
            -- Show Next Line & Corrections Drawing
            -- (next_r and current_k were already calculated above)
            if corrections_h > 0 then
                render_corrections(cms, current_y, scaled_c_fsize, center_x, available_w, content_offset_left, content_offset_right)
                current_y = current_y + corrections_h + S_GAP
            end
            
            -- Draw Next Line
            if cfg.p_next and next_r then
                local next_y = "bottom"
                if cfg.next_attach then
                    next_y = current_y + S(cfg.next_padding)
                end
                
                if cfg.show_next_two and next_r2 then
                    if cfg.next_attach then
                        local h1, y1 = render_next_replica(next_r, next_y, scaled_n_fsize)
                        render_next_replica(next_r2, y1 + h1 + S(15), scaled_n_fsize)
                    else
                        local h2, y2 = render_next_replica(next_r2, "bottom", scaled_n_fsize)
                        render_next_replica(next_r, "bottom", scaled_n_fsize, h2 + S(15))
                    end
                else
                    render_next_replica(next_r, next_y, scaled_n_fsize)
                end
            end
        else
            is_show_final_stats = STATS.render_prompter_idle(available_w, content_offset_left, content_offset_right)
        end
    else
        -- Not in any region. We might have upcoming regions or upcoming markers.
        if #regions > 0 or #prompter_drawer.marker_cache.markers > 0 then
            -- Find the next region after current position
            local next_rgn = nil
            local next_rgn2 = nil
            for _, rgn in ipairs(regions) do
                if rgn.pos > cur_pos then
                    if not next_rgn then next_rgn = rgn
                    else next_rgn2 = rgn break end
                end
            end
            
            if next_rgn and (cfg.p_next and cfg.always_next) then
                -- Estimate height for wait mode
                gfx.setfont(F.nxt, cfg.p_font, cfg.n_fsize)
                local n_lines = parse_prompter_to_lines(next_rgn.name)
                local n_h_est = #n_lines * math.floor(gfx.texth * (cfg.n_lheight or 1.0)) + 30
                if cfg.show_next_two and next_rgn2 then
                    local n_lines2 = parse_prompter_to_lines(next_rgn2.name)
                    n_h_est = n_h_est + #n_lines2 * math.floor(gfx.texth * (cfg.n_lheight or 1.0)) + 15
                end
                
                local cms, ch = get_corrections_to_draw(cur_pos, nil)
                prompter_drawer.active_markindex = (ch > 0) and cms[1].markindex or nil
                local c_h_est = ch -- get_corrections_to_draw now returns pixel height!
                if ch > 0 then c_h_est = ch + 20 end
                
                local total_wait_h = n_h_est + c_h_est
                local available_h = gfx.h - 100
                
                local wait_draw_n_fsize = cfg.n_fsize
                local wait_draw_c_fsize = cfg.c_fsize
                
                if total_wait_h > available_h then
                    local v_scale = available_h / total_wait_h
                    wait_draw_n_fsize = math.max(10, math.floor(wait_draw_n_fsize * v_scale))
                    wait_draw_c_fsize = math.max(10, math.floor(wait_draw_c_fsize * v_scale))
                end

                local n_h, n_y = 0, gfx.h - 10
                if cfg.next_attach then
                    local position_mode = cfg.p_valign or "center"
                    if cfg.show_next_two and next_rgn2 then
                        local h1, y1 = render_next_replica(next_rgn, position_mode, wait_draw_n_fsize)
                        local h2, y2 = render_next_replica(next_rgn2, y1 + h1 + S(15), wait_draw_n_fsize)
                        n_h = h1 + h2 + S(15)
                        n_y = y1
                    else
                        n_h, n_y = render_next_replica(next_rgn, position_mode, wait_draw_n_fsize)
                    end
                else
                    if cfg.show_next_two and next_rgn2 then
                        local h2, y2 = render_next_replica(next_rgn2, "bottom", wait_draw_n_fsize)
                        n_h, n_y = render_next_replica(next_rgn, "bottom", wait_draw_n_fsize, h2 + S(15))
                        n_h = n_h + h2 + S(15) -- Total group height for corrections positioning
                    else
                        n_h, n_y = render_next_replica(next_rgn, "bottom", wait_draw_n_fsize)
                    end
                end
                
                if ch > 0 then
                    gfx.setfont(F.cor, cfg.p_font, wait_draw_c_fsize)
                    render_corrections(cms, n_y - ch - 15, wait_draw_c_fsize, center_x, available_w, content_offset_left, content_offset_right)
                end
            else
                -- Just corrections? (if playhead after all subtitles but markers are ahead, or no regions at all, OR always_next is off)
                local cms, ch = get_corrections_to_draw(cur_pos, nil)
                prompter_drawer.active_markindex = (ch > 0) and cms[1].markindex or nil

                if ch > 0 then
                    -- Render the actual corrections instead of just a placeholder text
                    local cor_fsize = cfg.c_fsize
                    gfx.setfont(F.cor, cfg.p_font, cor_fsize)
                    local cor_y = (gfx.h - ch) / 2
                    if cfg.p_valign == "top" then cor_y = S(70)
                    elseif cfg.p_valign == "bottom" then cor_y = gfx.h - ch - S(50) end
                    render_corrections(cms, cor_y, cor_fsize, center_x, available_w, content_offset_left, content_offset_right)
                else
                    if not next_rgn then
                        is_show_final_stats = STATS.render_prompter_idle(available_w, content_offset_left, content_offset_right)
                    end
                end
            end
        else
            is_show_final_stats = STATS.render_prompter_idle(available_w, content_offset_left, content_offset_right)
        end
    end
    
    -- Draw Countdown Timer (Only in gaps when no active replica is present)
    if cfg.count_timer and next_rgn and #active_regions == 0 then
        local gap_to_next = next_rgn.pos - cur_pos
        local total_gap = next_rgn.pos - prev_rgn_end

        -- --- JUMP TO NEXT BUTTON ---
        if gap_to_next > 3 then
            local btn_w, btn_h = 60, 100
            local btn_x = gfx.w - content_offset_right - btn_w - 20
            local btn_y = (gfx.h - btn_h) / 2
            
            local hover = UI_STATE.window_focused and (gfx.mouse_x >= btn_x and gfx.mouse_x <= btn_x + btn_w and
                           gfx.mouse_y >= btn_y and gfx.mouse_y <= btn_y + btn_h)
                   
            -- Draw arrow (vector)
            set_color(hover and {cfg.p_cr, cfg.p_cg, cfg.p_cb, 0.8} or {cfg.p_cr, cfg.p_cg, cfg.p_cb, 0.4})
            local ax = btn_x + 25
            local ay = btn_y + btn_h / 2
            local sz = 25
            gfx.line(ax, ay - sz, ax + sz, ay, 1)
            gfx.line(ax + sz, ay, ax, ay + sz, 1)
            -- Double arrow for "fast forward" feel
            gfx.line(ax - 15, ay - sz, ax + sz - 15, ay, 1)
            gfx.line(ax + sz - 15, ay, ax - 15, ay + sz, 1)

            if hover and gfx.mouse_cap == 1 and UI_STATE.last_mouse_cap == 0 and not UI_STATE.mouse_handled then
                reaper.SetEditCurPos(next_rgn.pos, true, true) -- true, true = move view AND seek play
                
                -- Robust focus return for macOS
                return_focus_to_reaper()
                
                UI_STATE.mouse_handled = true
            end
        end

        local alpha = 0.04 -- Very faint for long wait
        if gap_to_next <= 3.0 then alpha = 0.25 end -- Prominent for entry

        -- Set color with determined alpha
        gfx.set(cfg.p_cr, cfg.p_cg, cfg.p_cb, alpha)
        
        if gap_to_next > 0 and total_gap >= 3.0 and cfg.count_timer_show_numbers then
            local countdown_str = ""
            if gap_to_next > 60 then
                local m = math.floor(gap_to_next / 60)
                local s = math.floor(gap_to_next % 60)
                countdown_str = string.format("%d:%02d", m, s)
            else
                countdown_str = tostring(math.ceil(gap_to_next))
            end
            
            -- Use a huge font size for impact
            local count_font_size = math.min(gfx.h, gfx.w) * 0.4
            gfx.setfont(10, cfg.p_font or "Arial", count_font_size, string.byte('b'))
            
            -- Center of available space
            local tw, th = gfx.measurestr(countdown_str)
            gfx.x = content_offset_left + (available_w - tw) / 2
            gfx.y = (gfx.h - th) / 2
            gfx.drawstr(countdown_str)
        end

        -- Progress Bars
        if gap_to_next > 0 and total_gap >= 0.1 then
            local progress = 1.0 - math.min(1.0, gap_to_next / math.max(1.0, total_gap))
            
            if cfg.count_timer_bottom then
                -- Bottom Horizontal Progress Bar
                local bar_h = 6
                local avail_w = gfx.w - content_offset_left - content_offset_right
                local bar_w = avail_w * progress
                -- Draw centered
                gfx.rect(content_offset_left + (avail_w - bar_w)/2, gfx.h - bar_h, bar_w, bar_h, 1)
            else
                -- Side Progress Bars (Vertical)
                local bar_w = 8
                local bar_h = gfx.h * progress
                -- Left Bar
                gfx.rect(content_offset_left, gfx.h - bar_h + 25, bar_w, bar_h, 1)
                -- Right Bar
                gfx.rect(gfx.w - content_offset_right - bar_w, gfx.h - bar_h + 25, bar_w, bar_h, 1)
            end
        end

        gfx.set(cfg.p_cr, cfg.p_cg, cfg.p_cb)
    end

    -- Info Overlay graphics (OVER EVERYTHING ELSE)
    DRAW_WINDOW.draw_info_overlay_graphics(content_offset_left, content_offset_right, active_regions, UI_STATE.latched_overlay_time, active_idx)

    -- === DRAWER UI DRAWING (OVER EVERYTHING) ===
    if cfg.p_drawer then
        DRAW_WINDOW.draw_prompter_drawer(input_queue)
    end
    -- === END DRAWER UI ===

    -- Handle Right-Click Context Menu for Overlay
    handle_prompter_context_menu(is_show_final_stats)
end

local last_settings_h = 0 -- Persistent storage for Settings height

-- Helper to draw a custom color picker square
function UI_STATE.draw_custom_color_box(bx, screen_y, box_sz, r, g, b, on_change, is_selected)
    -- Background
    if is_selected then
        set_color({r, g, b})
    else
        set_color(UI.C_BLACK_OVERLAY)
    end
    gfx.rect(bx, screen_y, box_sz, box_sz, 1)
    
    -- Border
    if is_selected then
        set_color(UI.C_WHITE)
        draw_selection_border(bx, screen_y, box_sz, box_sz)
    else
        set_color(UI.C_HILI_WHITE_MID)
        gfx.rect(bx, screen_y, box_sz, box_sz, 0)
    end
    
    -- Plus sign
    if is_selected then
        local lum = (r * 0.299 + g * 0.587 + b * 0.114)
        set_color(lum > 0.5 and UI.C_BLACK or UI.C_WHITE)
    else
        set_color(UI.C_LIGHT_GREY)
    end

    gfx.setfont(F.std)
    local tw, th = gfx.measurestr("＋")
    gfx.x = bx + (box_sz - tw) / 2
    gfx.y = screen_y + (box_sz - th) / 2
    gfx.drawstr("＋")
    
    if is_mouse_clicked() and gfx.mouse_y > S(25) then
        if gfx.mouse_x >= bx and gfx.mouse_x <= bx + box_sz and gfx.mouse_y >= screen_y and gfx.mouse_y <= screen_y + box_sz then
            local initial_color = reaper.ColorToNative(math.floor(r * 255), math.floor(g * 255), math.floor(b * 255))
            local retval, selected_color = reaper.GR_SelectColor(reaper.GetMainHwnd(), initial_color)
            if retval > 0 then
                local nr, ng, nb = reaper.ColorFromNative(selected_color)
                on_change(nr / 255, ng / 255, nb / 255)
            end
        end
    end
end

-- =============================================================================
-- UI: SETTINGS TAB
-- =============================================================================

function DRAW_TABS.draw_settings()
    local x_start = S(20)
    local start_y = S(50)
    local content_h = 0 
    
    -- Setup Scroll Logic for Settings (Smooth)
    local avail_h = gfx.h - start_y
    local max_scroll = math.max(0, last_settings_h - avail_h) -- Use PREVIOUS frame's height
    
    -- Accumulate target scroll
    if gfx.mouse_wheel ~= 0 then
        UI_STATE.target_scroll_y = UI_STATE.target_scroll_y - (gfx.mouse_wheel * 0.25)
        -- Immediate Clamp on input
        if UI_STATE.target_scroll_y < 0 then UI_STATE.target_scroll_y = 0 end
        if UI_STATE.target_scroll_y > max_scroll then UI_STATE.target_scroll_y = max_scroll end
        
        gfx.mouse_wheel = 0
    end
    
    -- Smoothly interpolate
    local diff = UI_STATE.target_scroll_y - UI_STATE.scroll_y
    if math.abs(diff) > 0.5 then
        UI_STATE.scroll_y = UI_STATE.scroll_y + (diff * 0.8)
    else
        UI_STATE.scroll_y = UI_STATE.target_scroll_y
    end
    
    -- HARD Clamp UI_STATE.scroll_y before drawing to prevent "blinking"
    if UI_STATE.scroll_y < 0 then UI_STATE.scroll_y = 0 end
    if UI_STATE.scroll_y > max_scroll then UI_STATE.scroll_y = max_scroll end
    
    -- Reset tooltip state at the start of settings drawing
    UI_STATE.tooltip_state.text = ""
    gfx.setfont(F.std)

    -- Helper to offset Y and check boundaries (INTEGER ROUNDING)
    local function get_y(offset)
        return start_y + offset - math.floor(UI_STATE.scroll_y)
    end
    
    -- Button Helper wrapper for scrolling
    local y_cursor = 0 -- Relative Y from start (Moved up for closure capture)
    
    local function s_btn(x, y_rel, w, h, text, tooltip, bg_col)
        local screen_y = get_y(y_rel)
        if screen_y + h < start_y - S(50) or screen_y > gfx.h + S(50) then return false end -- Cull
        
        local hover = UI_STATE.window_focused and (gfx.mouse_x >= x and gfx.mouse_x <= x+w and gfx.mouse_y >= screen_y and gfx.mouse_y <= screen_y+h)
        if hover and gfx.mouse_y < S(26) then hover = false end

        set_color(hover and UI.C_BTN_H or (bg_col or UI.C_BTN))
        gfx.rect(x, screen_y, w, h, 1)
        set_color(UI.C_TXT)
        gfx.setfont(F.std)
        local str_w, str_h = gfx.measurestr(text)
        gfx.x = x + (w - str_w) / 2
        gfx.y = screen_y + (h - str_h) / 2
        gfx.drawstr(text)

        if hover and tooltip then
            local id = "btn_" .. text .. "_" .. y_rel
            if UI_STATE.tooltip_state.hover_id ~= id then
                UI_STATE.tooltip_state.hover_id = id
                UI_STATE.tooltip_state.start_time = reaper.time_precise()
            end
            UI_STATE.tooltip_state.text = tooltip
        end

        if hover and is_mouse_clicked() then return true end
        return false
    end

    local function checkbox_box(show_param_checkbox, x_checkbox_start, y_checkbox_start)
        set_color(UI.C_ED_GUTTER)
        gfx.rect(x_checkbox_start, y_checkbox_start, S(20), S(20), 0)
        if show_param_checkbox then
            set_color(UI.C_TXT)
            gfx.line(x_checkbox_start + S(4), y_checkbox_start + S(10), x_checkbox_start + S(8), y_checkbox_start + S(16))
            gfx.line(x_checkbox_start + S(5), y_checkbox_start + S(10), x_checkbox_start + S(9), y_checkbox_start + S(16))
            gfx.line(x_checkbox_start + S(8), y_checkbox_start + S(16), x_checkbox_start + S(16), y_checkbox_start + S(4))
            gfx.line(x_checkbox_start + S(9), y_checkbox_start + S(16), x_checkbox_start + S(17), y_checkbox_start + S(4))
        end
    end

    -- Checkbox Helper
    local function checkbox(x, y_rel, text, checked, tooltip)
        local chk_sz = S(20)
        local screen_y = get_y(y_rel)
        if screen_y + chk_sz < start_y - S(50) or screen_y > gfx.h + S(50) then return false end -- Cull
        
        checkbox_box(checked, x, screen_y)
    
        gfx.setfont(F.std)
        gfx.x, gfx.y = x + chk_sz + S(10), screen_y + S(4)
        gfx.drawstr(text)
        set_color(UI.C_TXT)
        
        local hover = UI_STATE.window_focused and (gfx.mouse_x >= x and gfx.mouse_x <= x + chk_sz + gfx.measurestr(text) + S(10) and
                       gfx.mouse_y >= screen_y and gfx.mouse_y <= screen_y + chk_sz)

        if hover and gfx.mouse_y < S(26) then hover = false end

        if hover then
            set_color(UI.C_HILI_WHITE) -- Slight white highlight
            gfx.rect(x - S(2), screen_y - S(2), chk_sz + gfx.measurestr(text) + S(18), chk_sz + S(4), 1)
            set_color(UI.C_TXT)
        end
        
        if hover and tooltip then
            local id = "chk_" .. text .. "_" .. y_rel
            if UI_STATE.tooltip_state.hover_id ~= id then
                UI_STATE.tooltip_state.hover_id = id
                UI_STATE.tooltip_state.start_time = reaper.time_precise()
            end
            UI_STATE.tooltip_state.text = tooltip
        end

        return hover and is_mouse_clicked()
    end

    -- Text Helper
    local function s_text(x, y_rel, text, font, tooltip)
        local screen_y = get_y(y_rel)
        if screen_y + 15 < start_y - S(50) or screen_y > gfx.h + S(50) then return end
        gfx.setfont(font or F.std)
        gfx.x, gfx.y = x, screen_y
        gfx.drawstr(text)

        if tooltip then
            local tw, th = gfx.measurestr(text)
            local hover = UI_STATE.window_focused and (gfx.mouse_x >= x and gfx.mouse_x <= x + tw and gfx.mouse_y >= screen_y and gfx.mouse_y <= screen_y + th)
            if hover and gfx.mouse_y > S(25) then
                local id = "txt_" .. text .. "_" .. y_rel
                if UI_STATE.tooltip_state.hover_id ~= id then
                    UI_STATE.tooltip_state.hover_id = id
                    UI_STATE.tooltip_state.start_time = reaper.time_precise()
                end
                UI_STATE.tooltip_state.text = tooltip
            end
        end
    end
    
    -- Section Header helper
    local function s_section(y_rel, title)
        local screen_y = get_y(y_rel)
        if screen_y + S(30) < start_y - S(50) or screen_y > gfx.h + S(50) then return end
        
        -- Line
        set_color(UI.C_MEDIUM_GREY)
        gfx.rect(x_start, screen_y + S(10), gfx.w - S(40), 1, 1)
        
        -- Title background
        gfx.setfont(F.std)
        local tw = gfx.measurestr(title)
        set_color(UI.C_BG)
        gfx.rect(x_start, screen_y, tw + S(10), S(20), 1)
        
        -- Title text
        set_color(UI.C_LIGHT_GREY)
        gfx.setfont(F.std)
        gfx.x = x_start
        gfx.y = screen_y
        gfx.drawstr(title)
        set_color(UI.C_TXT)
    end
    
    -- Color Palette Helper
    local function draw_color_palette(x, palette, cur_r, cur_g, cur_b, on_change, scale)
        scale = scale or 1.0
        local box_sz = S(30)
        local gap = S(10)
        local pal_sel = false
        
        for i, col in ipairs(palette) do
            local bx = x + ((i-1) * (box_sz + gap))
            local screen_y = get_y(y_cursor)
            
            if screen_y + box_sz > start_y - S(50) and screen_y < gfx.h + S(50) then
                local r, g, b = col[1] * scale, col[2] * scale, col[3] * scale
                set_color({r, g, b})
                gfx.rect(bx, screen_y, box_sz, box_sz, 1)
                
                local is_sel = (math.abs(cur_r - r) < 0.01 and 
                                math.abs(cur_g - g) < 0.01 and 
                                math.abs(cur_b - b) < 0.01)
                if is_sel then
                    pal_sel = true
                    set_color(UI.C_WHITE)
                    draw_selection_border(bx, screen_y, box_sz, box_sz)
                else
                    set_color(UI.C_HILI_WHITE_MID)
                    gfx.rect(bx, screen_y, box_sz, box_sz, 0)
                end
                
                if is_mouse_clicked() and gfx.mouse_y > S(25) then
                    if gfx.mouse_x >= bx and gfx.mouse_x <= bx + box_sz and gfx.mouse_y >= screen_y and gfx.mouse_y <= screen_y + box_sz then
                        on_change(r, g, b)
                    end
                end
            end
        end
        
        -- Custom Box
        local custom_bx = x + (#palette * (box_sz + gap))
        local custom_y = get_y(y_cursor)
        if custom_y + box_sz > start_y - S(50) and custom_y < gfx.h + S(50) then
            UI_STATE.draw_custom_color_box(custom_bx, custom_y, box_sz, cur_r / scale, cur_g / scale, cur_b / scale, function(r, g, b)
                on_change(r * scale, g * scale, b * scale)
            end, not pal_sel)
        end
        
        return box_sz + 10
    end

    -- ═══════════════════════════════════════════
    -- 0. ІНСТРУМЕНТИ (Tools)
    -- ═══════════════════════════════════════════
    s_section(y_cursor, T("TOOLS"))
    y_cursor = y_cursor + S(35)
    
    local col_count = gfx.w < S(450) and 1 or 2
    local btn_w = (gfx.w - x_start * 2 - (col_count - 1) * S(10)) / col_count
    local btn_h = S(40)
    
    local tools = {
        {name = T("TALEND_SEARCH"), tip = T("TALEND_SEARCH_TIP"), color = UI.C_TAL_BG, action = function() UI_STATE.show_talent_search = true ACHIEVEMENTS.fetch_talents(1) end},
        {name = cfg.dubber_force_hide and T("EDIT_PROFILE_BAN") or T("EDIT_PROFILE"), tip = T("EDIT_PROFILE_TIP"), action = function() ACHIEVEMENTS.open_edit_profile() end},
        {name = T("MY_STATISTICS"), tip = T("MY_STATISTICS_TIP"), action = function() UTILS.launch_python_script("stats/subass_stats.py") end},
        {name = T("MY_DEADLINES"), tip = T("MY_DEADLINES_TIP"), action = function() DEADLINE.dashboard_show = true end},
        {name = T("SPLIT_BY_DUBBERS"), tip = T("SPLIT_BY_DUBBERS_TIP"), action = function() DUBBERS.show_dashboard = true DUBBERS.load() end},
        {name = T("WEB_ACCENT_MANAGER"), tip = T("WEB_ACCENT_MANAGER_TIP"), action = function() UTILS.launch_python_script("stress/ukrainian_stress_tool.py") end},
        {name = T("GLOBAL_SEARCH_FOR_TAKES"), tip = T("GLOBAL_SEARCH_FOR_TAKES_TIP"), action = function() SEARCH_ITEM.show = true SEARCH_ITEM.input.focus = true end},
        {name = T("FIND_A_WORD_IN_GOROH"), tip = T("FIND_A_WORD_IN_GOROH_TIP"), action = function() 
            local ok, input = reaper.GetUserInputs(T("GOROH"), 1, T("SEARCH_TERM_200"), "")
            if ok and input ~= "" then
                trigger_dictionary_lookup(input)
            end
        end},
        {name = T("OPEN_NOTEPAD"), tip = T("OPEN_NOTEPAD_TIP"), action = function() UTILS.run_satellite_script("imnotbad", "imnotbad_Notepad.lua", "Notepad") end}, 
        {name = T("OPEN_DICTIONARY"), tip = T("OPEN_DICTIONARY_TIP"), action = function() UTILS.run_satellite_script("dictionary", "Subass_Dictionary.lua", "Dictionary") end}, 
        {name = T("OPEN_SUBOVERLAY_BY"), tip = T("OPEN_SUBOVERLAY_BY_TIP"), action = function() UTILS.run_satellite_script("overlay", "Lionzz_SubOverlay_Subass.lua", "Overlay") end},
        {name = T("OPEN_PDF_READER"), tip = T("OPEN_PDF_READER_TIP"), action = function() 
            UTILS.run_satellite_script("overlay", "Subass_PDF.lua", "PDF Рідер")
        end},
        {name = T("TABLE_MENU_SHOW_DIRECTOR"), tip = T("TABLE_MENU_SHOW_DIRECTOR_TIP"), color = cfg.director_mode and UI.C_BTN_MEDIUM or nil, action = function() 
            UI_STATE.current_tab = 2 
            cfg.director_mode = not cfg.director_mode 
            cfg.editor_mode = false
            save_settings() 
        end},
        {name = T("SLIDER_MODE"), tip = T("SLIDER_MODE_TIP"), color = cfg.prompter_slider_mode and UI.C_BTN_MEDIUM or nil, action = function() 
            UI_STATE.current_tab = 3 
            cfg.prompter_slider_mode = not cfg.prompter_slider_mode 
            save_settings() 
        end},
        {name = T("OPEN_MKV_EXTRACT"), tip = T("OPEN_MKV_EXTRACT_TIP"), action = function() UTILS.run_satellite_script("imnotbad", "imnotbad_MP4_MKV_Extract.lua", "MKV/MP4 Extract") end},
