local last_auto_scroll_idx = nil
local suppress_auto_scroll_frames = 0

-- Helper for inline buttons
local function draw_btn_inline(x, y, w, h, text, bg_col, suppress_hover)
    local hover = UI_STATE.window_focused and (gfx.mouse_x >= x and gfx.mouse_x <= x + w and gfx.mouse_y >= y and gfx.mouse_y <= y + h) and not suppress_hover
    set_color(hover and UI.C_BTN_H or (bg_col or UI.C_BTN))
    gfx.rect(x, y, w, h, 1)
    set_color(UI.C_TXT)
    local str_w, str_h = gfx.measurestr(text)
    gfx.x = x + (w - str_w) / 2
    gfx.y = y + (h - str_h) / 2
    gfx.drawstr(text)
    if hover and is_mouse_clicked() then return true end
    return false
end

-- Helper: Get current actor from text
-- Helper: Parse actors from text (supports comma-separated "Actor1, Actor2")
local function get_actors_from_text(text)
    local content = text:match("^%[(.-)%]")
    if not content then return {}, {} end
    
    local list = {}
    local set = {}
    for part in string.gmatch(content, "([^,]+)") do
        local name = part:match("^%s*(.-)%s*$")
        if name and name ~= "" then
            table.insert(list, name)
            set[name] = true
        end
    end
    return list, set
end

-- Helper: Rename actor globally in all project markers
local function rename_actor_globally(old_name, new_name)
    local count = 0
    
    -- 1. Update Project Markers/Regions
    local i = 0
    while true do
        local retval, isrgn, pos, rgnend, mark_name, markindex = reaper.EnumProjectMarkers3(0, i)
        if not retval or retval == 0 then break end
        
        local actors, actor_set = get_actors_from_text(mark_name)
        if actor_set[old_name] then
            -- Replace in the list
            local new_actors = {}
            for _, a in ipairs(actors) do
                table.insert(new_actors, (a == old_name) and new_name or a)
            end
            
            -- Rebuild text
            local clean_text = mark_name:gsub("^%[.-%]%s*", "")
            local new_text = "[" .. table.concat(new_actors, ", ") .. "] " .. clean_text
            
            reaper.SetProjectMarker4(0, markindex, isrgn, pos, rgnend, new_text, 0, 0)
            count = count + 1
        end
        i = i + 1
    end
    
    -- 2. Invalidate caches
    ass_markers = capture_project_markers()
    prompter_drawer.marker_cache.count = -1
    table_data_cache.state_count = -1
    last_layout_state.state_count = -1
    
    return count
end

-- Helper: Delete actor prefix globally in all project markers
local function delete_actor_globally(name)
    local count = 0
    
    -- 1. Update Project Markers/Regions
    local i = 0
    while true do
        local retval, isrgn, pos, rgnend, mark_name, markindex = reaper.EnumProjectMarkers3(0, i)
        if not retval or retval == 0 then break end
        
        local actors, actor_set = get_actors_from_text(mark_name)
        if actor_set[name] then
            -- Remove from the list
            local new_actors = {}
            for _, a in ipairs(actors) do
                if a ~= name then table.insert(new_actors, a) end
            end
            
            -- Rebuild text
            local clean_text = mark_name:gsub("^%[.-%]%s*", "")
            local new_text = clean_text
            if #new_actors > 0 then
                new_text = "[" .. table.concat(new_actors, ", ") .. "] " .. clean_text
            end

            -- SetProjectMarker ignores empty strings, so fallback to a space if empty
            if new_text == "" then new_text = T("EMPTY_ACT_GLB") end
            
            reaper.SetProjectMarker4(0, markindex, isrgn, pos, rgnend, new_text, 0, 0)
            count = count + 1
        end
        i = i + 1
    end
    
    -- 2. Invalidate caches
    ass_markers = capture_project_markers()
    prompter_drawer.marker_cache.count = -1
    table_data_cache.state_count = -1
    last_layout_state.state_count = -1
    
    return count
end

function UTILS.update_corr_time_prefix(calc_only, cur_time)
    -- --- AUTO-ATTACH TIME SELECTION ---
    if not calc_only then
        local sel_start, sel_end = reaper.GetSet_LoopTimeRange2(0, false, false, 0, 0, false)
        if sel_start ~= sel_end and sel_end > sel_start then
            -- ONLY attach if the selection starts near the current cursor/marker (within 150ms)
            if math.abs(sel_start - cur_time) < 0.150 then
                if sel_end ~= director_state.last_time_sel_end then
                    director_state.last_time_sel_end = sel_end
                    
                    local time_str = format_timestamp(sel_end)
                    local txt = director_state.input.text
                    
                    -- Extract optional [actor] prefix and the rest of the text
                    local prefix, rest = txt:match("^(%[%s*.-%s*%]%s*)(.*)")
                    if not prefix then
                        prefix = ""
                        rest = txt
                    end
                    
                    -- Aggressively remove ANY existing time prefixes to clean up stacked times
                    while true do
                        local new_rest = rest:gsub("^%d+[:%.][%d:%.]*%s*-%s*", "")
                        if new_rest == rest then break end
                        rest = new_rest
                    end
                    
                    local new_txt = prefix .. time_str .. " - " .. rest
                    
                    if director_state.input.text ~= new_txt then
                        director_state.input.text = new_txt
                        director_state.input.cursor = #director_state.input.text
                        director_state.input.anchor = director_state.input.cursor
                    end
                end
            elseif director_state.last_time_sel_end then
                -- Selection is too far away, and we WERE tracking a selection. Remove it.
                local txt = director_state.input.text
                local prefix, rest = txt:match("^(%[%s*.-%s*%]%s*)(.*)")
                if not prefix then prefix = ""; rest = txt end
                
                local cleaned_rest = rest
                while true do
                    local new_rest = cleaned_rest:gsub("^%d+[:%.][%d:%.]*%s*-%s*", "")
                    if new_rest == cleaned_rest then break end
                    cleaned_rest = new_rest
                end
                
                local new_txt = prefix .. cleaned_rest
                if director_state.input.text ~= new_txt then
                    director_state.input.text = new_txt
                end
                director_state.last_time_sel_end = nil
            end
        elseif director_state.last_time_sel_end then
            -- No selection, and we WERE tracking one. Remove it.
            local txt = director_state.input.text
            local prefix, rest = txt:match("^(%[%s*.-%s*%]%s*)(.*)")
            if not prefix then prefix = ""; rest = txt end
            
            local cleaned_rest = rest
            while true do
                local new_rest = cleaned_rest:gsub("^%d+[:%.][%d:%.]*%s*-%s*", "")
                if new_rest == cleaned_rest then break end
                cleaned_rest = new_rest
            end
            
            local new_txt = prefix .. cleaned_rest
            if director_state.input.text ~= new_txt then
                director_state.input.text = new_txt
            end
            director_state.last_time_sel_end = nil
        end
    end
end

--- Helper to export markers to CSV
function UTILS.export_markers_to_csv(markers, deadline_str)
    if not reaper.JS_Dialog_BrowseForSaveFile then
        local msg = T("NEED_JS_REA_1")
        local has_reapack = reaper.ReaPack_GetOwner ~= nil
        if not has_reapack then
            msg = msg .. T("NEED_JS_REA_2")
        else
            msg = msg .. T("NEED_JS_REA_3")
        end
        reaper.MB(msg, T("MISSIBG_COMPONENTS"), 0)
        return
    end

    if #markers == 0 then
        show_snackbar(T("NO_ACTIVE_2"), "info")
        return
    end

    -- Отримуємо ім'я проекту для дефолтної назви файлу
    local _, proj_path = reaper.EnumProjects(-1)
    local proj_name = "Project"
    if proj_path and proj_path ~= "" then
        proj_name = proj_path:match("([^/\\%s]+)%.[Rr][Pp][Pp]$") or proj_name
    end
    
    local default_filename = proj_name .. T("EXPORT_RETAKES_FILE_EXT")
    if deadline_str then
        default_filename = deadline_str .. " " .. proj_name .. T("EXPORT_RETAKES_FILE_EXT")
    end

    -- Відкриваємо діалог збереження файлу
    local retval, filename = reaper.JS_Dialog_BrowseForSaveFile(T("EXPORT_RETAKES_TITLE"), "", default_filename, "CSV files (.csv)\0*.csv\0All Files (*.*)\0*.*\0")
    
    if retval == 1 and filename ~= "" then
        if not filename:match("%.csv$") then filename = filename .. ".csv" end
        
        local file = io.open(filename, "w")
        if not file then
            reaper.ShowMessageBox(T("FAILED_TO_CREATE_FILE") .. filename, T("ERROR"), 0)
            return
        end
        
        local exported_count = 0
        file:write("#,Name,Start,Color\n")
        for _, m in ipairs(markers) do
            -- Ignore green if option is active
            local is_green = false
            if cfg.director_ignore_green then
                local r, g, b = reaper.ColorFromNative((m.color or 0) & 0xFFFFFF)
                if r == 0 and g == 255 and b == 0 then
                    is_green = true
                end
            end

            if not is_green then
                exported_count = exported_count + 1
                local marker_id = "M" .. m.markindex
                local time_str = reaper.format_timestr(m.pos, "")
                local escaped_name = m.name
                if m.name:match('[,"\n\r]') then
                    escaped_name = '"' .. m.name:gsub('"', '""') .. '"'
                end
                
                local color_str = ""
                if m.color and m.color > 0 then
                    local r, g, b = reaper.ColorFromNative((m.color or 0) & 0xFFFFFF)
                    color_str = string.format("%02X%02X%02X", r, g, b)
                end
                
                file:write(string.format("%s,%s,%s,%s\n", marker_id, escaped_name, time_str, color_str))
            end
        end
        file:close()

        if exported_count > 0 then
            show_snackbar(T("EXPORTED_1") .. exported_count .. T("EXPORTED_4"), "success")
            ACHIEVEMENTS.add_stat("ach_8_export_count", 1)
            ACHIEVEMENTS.add_stat("ach_8_corr_item_count", exported_count)
        else
            show_snackbar(T("NO_ACTIVE_4"), "info")
        end
    end
end

function UTILS.copy_markers_to_clipboard(markers, filter_actors)
    if #markers > 0 then
        local groups = {}
        local no_actor_key = T("NO_RETAKES_DUBBER")
        local actors_list = {} -- Keep track of actors found for sorting
        local seen_actors = {}
        local total_filtered = 0

        for _, m in ipairs(markers) do
            local text = m.name
            local list, _ = get_actors_from_text(text)
            local content = ""
            
            local has_actor = (#list > 0)
            local current_actors = {}
            
            if has_actor then
                content = text:gsub("^%[.-%]%s*", "")
                current_actors = list
            else
                -- Fallback: Try pattern "Actor: Text"
                local s, e, act = string.find(text, "^(.-):%s*")
                if s and not act:match("^%d+$") then
                    table.insert(current_actors, act)
                    content = string.sub(text, e + 1)
                else
                    content = text
                    table.insert(current_actors, no_actor_key)
                end
            end

            -- Apply filter if provided
            local skip = false

            -- Check for green color if the option is active
            if cfg.director_ignore_green then
                local r, g, b = reaper.ColorFromNative((m.color or 0) & 0xFFFFFF)
                if r == 0 and g == 255 and b == 0 then
                    skip = true
                end
            end

            if not skip and filter_actors then
                skip = true
                for _, a in ipairs(current_actors) do
                    if filter_actors[a] then
                        skip = false
                        break
                    end
                end
            end

            if not skip then
                total_filtered = total_filtered + 1
                for _, actor in ipairs(current_actors) do
                    -- Double check filter on the actor level during grouping
                    if not filter_actors or filter_actors[actor] then
                        if not groups[actor] then
                            groups[actor] = {}
                            if not seen_actors[actor] then
                                table.insert(actors_list, actor)
                                seen_actors[actor] = true
                            end
                        end
                        table.insert(groups[actor], {time = m.pos, text = content})
                    end
                end
            end
        end

        if total_filtered == 0 then
            show_snackbar(T("NO_ACTIVE_5"), "info")
            return
        end

        -- Sort actors alphabetically, but put no_actor_key last
        table.sort(actors_list, function(a, b)
            if a == no_actor_key then return false end
            if b == no_actor_key then return true end
            return a < b
        end)

        local out_lines = {}
        for _, act in ipairs(actors_list) do
            -- Clean actor name: remove VS16 and trim spaces
            local clean_act = act:gsub("\239\184\143", ""):match("^%s*(.-)%s*$")
            table.insert(out_lines, "⭐ " .. clean_act)
            -- Sort markers by time
            table.sort(groups[act], function(a, b) return a.time < b.time end)
            
            for _, entry in ipairs(groups[act]) do
                local time_str = reaper.format_timestr(entry.time, "")
                table.insert(out_lines, time_str .. " - " .. entry.text)
            end
            table.insert(out_lines, "") -- Empty line between groups
        end
        
        set_clipboard(table.concat(out_lines, "\n"))
        show_snackbar(T("COPIED") .. " " .. total_filtered .. T("RETAKES_COPY_END"), "success")

        ACHIEVEMENTS.add_stat("ach_8_export_count", 1)
        ACHIEVEMENTS.add_stat("ach_8_corr_item_count", total_filtered)
    else
        show_snackbar(T("NO_ACTIVE_6"), "info")
    end
end

--- Helper: Clean actor name from ASS or Director Panel
--- Removes variation selectors (e.g. U+FE0F / \239\184\143) and trims whitespace
function UTILS.clean_name_ass_actor(name)
    if not name then return nil end
    -- Remove variation selector (\239\184\143 is U+FE0F) and trim
    return name:gsub("\239\184\143", ""):match("^%s*(.-)%s*$")
end

--- Build (or rebuild) a t1-sorted index of ass_lines for fast binary search.
--- Called automatically by get_ass_actors_at_time when ass_lines reference changes.
function UTILS.rebuild_actors_index()
    local idx = {}
    for i, line in ipairs(ass_lines) do
        idx[#idx + 1] = { 
            t1 = line.t1, 
            t2 = line.t2, 
            actor = line.actor, 
            text = line.text, 
            enabled = (line.enabled ~= false),
            rgn_idx = line.rgn_idx,
            _i = i
        }
    end

    table.sort(idx, function(a, b) return a.t1 < b.t1 end)
    
    -- Augmented Interval logic: compute prefix-maximum of t2
    local running_max = -1
    for i = 1, #idx do
        if idx[i].t2 > running_max then running_max = idx[i].t2 end
        idx[i].max_t2 = running_max
    end

    director_state._actors_index     = idx
    director_state._actors_index_ref = ass_lines   -- detect future change
    director_state._actors_cache     = nil          -- invalidate frame cache
end

--- Find all ass_lines (index entries) at a specific project time with tolerance.
--- Uses binary search on director_state._actors_index.
--- @param time number The project time (seconds)
--- @param tolerance number Optional time tolerance (seconds, defaults to 0.001)
--- @return table List of entries { t1, t2, actor, _i }
function UTILS.get_ass_lines_at_time(time, tolerance)
    if not ass_lines or #ass_lines == 0 then return {} end
    tolerance = tolerance or 0.001

    -- Auto-rebuild sorted index when ass_lines table changes or manual invalidation occurred
    if director_state._actors_index_ref ~= ass_lines or UI_STATE._markers_is_dirty then
        UTILS.rebuild_actors_index()
        UI_STATE._markers_is_dirty = false
    end

    local idx = director_state._actors_index
    local n   = #idx
    if n == 0 then return {} end

    -- Binary search: find the rightmost index where t1 <= time + tolerance
    local lo, hi = 1, n
    while lo < hi do
        local mid = math.floor((lo + hi + 1) / 2)
        if idx[mid].t1 <= time + tolerance then lo = mid else hi = mid - 1 end
    end
    
    -- Robust walk-back using augmented max_t2
    local start = lo
    while start > 1 and idx[start - 1].max_t2 >= time - tolerance do
        start = start - 1
    end

    local list = {}
    for i = start, n do
        local entry = idx[i]
        if entry.t1 > time + tolerance then break end -- sorted list, no more matches
        if time >= (entry.t1 - tolerance) and time <= (entry.t2 + tolerance) then
            list[#list + 1] = entry
        end
    end

    return list
end

--- Find all ASS lines that overlap with the given time range [t1, t2].
--- Optimized with binary search.
--- @param t1 number Range start
--- @param t2 number Range end
--- @return table List of overlapping entries
function UTILS.get_ass_lines_in_range(t1, t2)
    if not ass_lines or #ass_lines == 0 then return {} end
    if t1 > t2 then t1, t2 = t2, t1 end

    if director_state._actors_index_ref ~= ass_lines or UI_STATE._markers_is_dirty then
        UTILS.rebuild_actors_index()
        UI_STATE._markers_is_dirty = false
    end

    local idx = director_state._actors_index
    local n   = #idx
    if n == 0 then return {} end

    -- Binary search: find rightmost index where entry.t1 < t2
    local lo, hi = 1, n
    while lo < hi do
        local mid = math.floor((lo + hi + 1) / 2)
        if idx[mid].t1 < t2 then lo = mid else hi = mid - 1 end
    end
    
    local list = {}
    -- Walk back: regions starting before t2, checking if they end after t1
    for i = lo, 1, -1 do
        local entry = idx[i]
        -- If the cumulative maximum end-time of all entries from 1..i is less than t1,
        -- no entry in this range can possibly overlap [t1, t2].
        if entry.max_t2 <= t1 then break end
        
        if entry.t2 > t1 then
            table.insert(list, entry)
        end
    end

    return list
end

--- Find all speaking character names at a specific project time.
--- Uses a pre-sorted index + binary search so cost is O(log n + k) per unique
--- call instead of O(n). Frame-level cache makes repeated calls within the same
--- rendering tick O(1). Index is rebuilt automatically when ass_lines changes.
--- @param time number The project time (seconds)
--- @return table List of unique cleaned actor names
function UTILS.get_ass_actors_at_time(time)
    if not ass_lines or #ass_lines == 0 then return {} end

    -- Frame-level cache: same time → return instantly
    local cache = director_state._actors_cache
    if cache and math.abs(cache.time - time) < 0.001 then
        return cache.result
    end

    local lines = UTILS.get_ass_lines_at_time(time, 0.001)
    
    local list = {}
    local seen = {}
    for _, entry in ipairs(lines) do
        if entry.actor and entry.actor ~= "" then
            local cname = UTILS.clean_name_ass_actor(entry.actor)
            if not seen[cname] then
                list[#list + 1] = cname
                seen[cname] = true
            end
        end
    end

    -- Store in frame cache
    director_state._actors_cache = { time = time, result = list }
    return list
end

--- Sync ALL DUBBERS assignments into the Director actor-to-dubber mapping.
--- Iterates every dubber in DUBBERS.data.assignments and fills any empty slot
--- in the provided mapping table. Existing manual overrides are preserved.
--- @param mapping table  director_state.region_actor_to_dubber (modified in-place)
function UTILS.sync_dubbers_to_director(mapping)
    if not mapping then return end
    if not DUBBERS.data or not DUBBERS.data.assignments then return end
    for dubber_name, actors in pairs(DUBBERS.data.assignments) do
        for ass_actor, _ in pairs(actors) do
            if mapping[ass_actor] == nil then
                mapping[ass_actor] = dubber_name
            end
        end
    end
end

--- Helper: Sync director panel with current markers and performing auto-fill
function UTILS.update_director_marker_and_autofill(cur_time, current_ass_actors)
    -- But first: Validate that the currently held marker ID still exists (it might have been deleted externally)
    if director_state.last_marker_id then
        local found_sync = nil
        for _, m in ipairs(ass_markers) do
            if m.markindex == director_state.last_marker_id then
                found_sync = m
                break
            end
        end
        if not found_sync then
            director_state.last_marker_id = nil
            director_state.input.text = ""
            director_state.input.cursor = 0
        else
            -- Sync with external changes (e.g. from modal text editor)
            if found_sync.name ~= (director_state.original_text or "") then
                -- Only update input if it hasn't been significantly modified by the user here, 
                -- or if it was exactly matching the previous state.
                if director_state.input.text == director_state.original_text then
                    director_state.input.text = found_sync.name
                    director_state.input.cursor = #found_sync.name
                    director_state.input.anchor = director_state.input.cursor
                end
                director_state.original_text = found_sync.name
            end
        end
    end

    if not UTILS.is_near(cur_time, director_state.last_time) then
        director_state.last_time = cur_time
        
        local found_m = nil
        for _, m in ipairs(ass_markers) do
            if UTILS.is_near(m.pos, cur_time) then
                found_m = m
                break
            end
        end
        
        if found_m then
            if found_m.markindex ~= director_state.last_marker_id then
                director_state.last_marker_id = found_m.markindex
                director_state.input.text = found_m.name
                director_state.original_text = found_m.name
                director_state.input.cursor = #found_m.name
                director_state.input.anchor = director_state.input.cursor -- Reset selection
            end
        else
            local cur_actor = (#current_ass_actors == 1) and current_ass_actors[1] or nil
            local actor_changed = (cur_actor ~= director_state.last_ass_actor)
            local needs_refill = (director_state.input.text == "") or (director_state.input.text:match("^%[.-%]%s*$"))
            
            if director_state.last_marker_id ~= nil or actor_changed or (needs_refill and cur_actor ~= nil) then
                -- If we just left a marker region, clear the input explicitly
                if director_state.last_marker_id ~= nil then
                    director_state.input.text = ""
                    director_state.input.cursor = 0
                    director_state.input.anchor = 0
                end
                director_state.last_marker_id = nil
                director_state.original_text = ""
                
                -- --- AUTO-FILL (Memory Logic) ---
                if needs_refill then
                    local total_ass_actors = 0
                    if cfg.director_autofill and ass_actors then
                        for _ in pairs(ass_actors) do total_ass_actors = total_ass_actors + 1 end
                    end
                    
                    if cfg.director_autofill and total_ass_actors > 1 then
                        -- ONLY auto-fill if exactly ONE actor is speaking
                        local mapped_name = nil
                        if cur_actor then
                            mapped_name = director_state.region_actor_to_dubber[cur_actor]
                        end
                        
                        -- Validate that mapped name is still in director_actors
                        local name_is_valid = false
                        if mapped_name then
                            for _, act in ipairs(director_actors) do
                                if act == mapped_name then name_is_valid = true break end
                            end
                        end
                        
                        if name_is_valid then
                            director_state.input.text = "[" .. mapped_name .. "] "
                        else
                            director_state.input.text = ""
                        end
                    else
                        -- Auto-fill disabled
                        director_state.input.text = ""
                    end
                end
                
                director_state.input.cursor = #director_state.input.text
                director_state.input.anchor = director_state.input.anchor -- Reset selection
            end
        end
        
        -- Always update last context when jumping
        director_state.last_ass_actor = (#current_ass_actors == 1) and current_ass_actors[1] or nil
    end
end

function UTILS.integrate_correction_tracks()
    reaper.Undo_BeginBlock()
    local proj = 0
    local timer_track_name = "SUBASS TIMER"
    local corr_track_name = "SUBASS CORR"
    
    local function find_or_create_track(name)
        local num_tracks = reaper.CountTracks(proj)
        for i = 0, num_tracks - 1 do
            local t = reaper.GetTrack(proj, i)
            local _, t_name = reaper.GetSetMediaTrackInfo_String(t, "P_NAME", "", false)
            if t_name == name then return t, false end
        end
        reaper.InsertTrackAtIndex(0, true)
        local track = reaper.GetTrack(proj, 0)
        reaper.GetSetMediaTrackInfo_String(track, "P_NAME", name, true)
        return track, true 
    end
    
    local corr_track = find_or_create_track(corr_track_name)
    local timer_track = find_or_create_track(timer_track_name)
    
    local function move_to_top(t)
        local cur_idx = reaper.CSurf_TrackToID(t, false) - 1
        if cur_idx ~= 0 then
            reaper.SetOnlyTrackSelected(t)
            reaper.ReorderSelectedTracks(0, 0)
        end
    end
    
    move_to_top(corr_track)
    move_to_top(timer_track)
    
    -- Ensure fresh data
    rebuild_regions()
    update_marker_cache()
    local markers = prompter_drawer.marker_cache.markers
    
    -- Clean the tracks (Items AND FX)
    for _, t in ipairs({timer_track, corr_track}) do
        local n = reaper.CountTrackMediaItems(t)
        for i = n - 1, 0, -1 do reaper.DeleteTrackMediaItem(t, reaper.GetTrackMediaItem(t, i)) end
        
        -- Clean Track FX
        local nf = reaper.TrackFX_GetCount(t)
        for i = nf - 1, 0, -1 do reaper.TrackFX_Delete(t, i) end
        
        -- Clean Input FX
        local ni = reaper.TrackFX_GetRecCount(t)
        for i = ni - 1, 0, -1 do reaper.TrackFX_Delete(t, 0x1000000 + i) end
    end
    
    -- Simplified robust helper to set FX code (Track or Take)
    local function set_fx_code_simple(target, fx_idx, code_str, is_take)
        -- Try API first
        local setter = is_take and reaper.TakeFX_SetNamedConfigParm or reaper.TrackFX_SetNamedConfigParm
        if setter then
            if setter(target, fx_idx, "code", code_str) then return true end
        end
        
        -- Fallback to chunk hacking (target is track or take)
        local encoded = "|" .. code_str:gsub("\n", "\n|")
        local ret, chunk
        local item = is_take and reaper.GetMediaItemTake_Item(target) or nil
        
        if is_take then
             ret, chunk = reaper.GetItemStateChunk(item, "", false)
        else
             ret, chunk = reaper.GetTrackStateChunk(target, "", false)
        end
        
        if ret then
            -- Find the fx_idx-th VIDEO_EFFECT block (0-indexed)
            local current_idx = -1
            local s_idx = 1
            while true do
                local s, e = chunk:find("<VIDEO_EFFECT", s_idx)
                if not s then break end
                current_idx = current_idx + 1
                
                if current_idx == fx_idx then
                    local b_end = chunk:find("\n>", e)
                    if b_end then
                        local code_s, code_e = chunk:find("<CODE.-%s>", s)
                        local new_chunk
                        if code_s and code_s < b_end then
                            new_chunk = chunk:sub(1, code_s - 1) .. "<CODE\n" .. encoded .. "\n>" .. chunk:sub(code_e + 1)
                        else
                            -- Find first newline after VIDEO_EFFECT to insert NI and CODE
                            local head_end = chunk:find("\n", e) or e
                            new_chunk = chunk:sub(1, head_end) .. "\n<CODE\n" .. encoded .. "\n>" .. chunk:sub(head_end + 1)
                        end
                        
                        if is_take then
                            reaper.SetItemStateChunk(item, new_chunk, false)
                        else
                            reaper.SetTrackStateChunk(target, new_chunk, false)
                        end
                        return true
                    end
                end
                s_idx = e + 1
            end
        end
        return false
    end

    -- --- TIMER TRACK ---
    -- Item for Timer
    local max_len = 0; local num_tracks = reaper.CountTracks(proj)
    for i = 0, num_tracks - 1 do
        local t = reaper.GetTrack(proj, i); local ic = reaper.CountTrackMediaItems(t)
        if ic > 0 then
            local li = reaper.GetTrackMediaItem(t, ic - 1)
            local p = reaper.GetMediaItemInfo_Value(li, "D_POSITION")
            local l = reaper.GetMediaItemInfo_Value(li, "D_LENGTH")
            if p + l > max_len then max_len = p + l end
        end
    end
    if max_len < 10 then max_len = 7200 end
    local t_item = reaper.CreateNewMIDIItemInProj(timer_track, 0, max_len, false)
    local t_take = reaper.GetActiveTake(t_item)
    reaper.GetSetMediaItemTakeInfo_String(t_take, "P_NAME", "Subass Timer", true)

    local vp_timer = [=[// Subass Timer Output
#text=""; font="Arial";

//@param1:size 'text height' 0.06 0.01 0.2 0.06 0.001
//@param2:ypos 'y position' 0.05 0 1 0.05 0.01
//@param3:xpos 'x position' 0.95 0 1 0.95 0.01
//@param4:bga 'bg alpha' 0.5 0 1 0.5 0.01
//@param5:fga 'text alpha' 1.0 0 1 1.0 0.01

border = 0.1;
fgc = 1.0;
bgc = 0.0;
bgfit = 1;
ignoreinput = 0;

input = ignoreinput ? -2:0;
input_info(-1,project_w,project_h); (project_w<=0||project_h<=0)?(project_w=1920;project_h=1080;);
gfx_a2=0;
gfx_blit(input,1);
gfx_setfont(size*project_h,font);

t = floor((project_time + project_timeoffs) * framerate + 0.0000001);
f = ceil(framerate); f<=0?f=25;
sprintf(#text,"%02d:%02d:%02d", floor(t/(f*3600)), floor(t/(f*60))%60, floor(t/f)%60);

gfx_str_measure(#text,txtw,txth);
b = (border*txth)|0;
yt = ((project_h - txth - b*2)*ypos)|0;
xp = (xpos * (project_w-txtw))|0;
gfx_set(bgc,bgc,bgc,bga);
bga>0?gfx_fillrect(bgfit?xp-b:0, yt, bgfit?txtw+b*2:project_w, txth+b*2);
gfx_set(fgc,fgc,fgc,fga);
gfx_str_draw(#text,xp,yt+b);]=]
    
    local t_fx = reaper.TakeFX_AddByName(t_take, "Video processor", 1)
    if t_fx >= 0 then 
        set_fx_code_simple(t_take, t_fx, vp_timer, true)
        reaper.TakeFX_SetParam(t_take, t_fx, 0, 0.06) -- size
        reaper.TakeFX_SetParam(t_take, t_fx, 1, 0.05) -- ypos
        reaper.TakeFX_SetParam(t_take, t_fx, 2, 0.95) -- xpos
        reaper.TakeFX_SetParam(t_take, t_fx, 3, 0.5)  -- bga
        reaper.TakeFX_SetParam(t_take, t_fx, 4, 1.0)  -- fga
    end

    -- --- CORRECTION MASTER (Track) ---
    local c_master = reaper.TrackFX_AddByName(corr_track, "Video processor", false, -1)
    local master_code = [=[// Subass Style Master
//@param1:size 'text height' 0.05 0.01 0.2 0.05 0.001
//@param2:ypos 'y position' 0.5 0 1 0.5 0.01
//@param3:xpos 'x position' 0.5 0 1 0.5 0.01
//@param4:bga 'bg alpha' 0.75 0 1 0.75 0.01
//@param5:fga 'text alpha' 1.0 0 1 1.0 0.01
gmem[1000]=size; gmem[1001]=ypos; gmem[1002]=xpos; gmem[1003]=bga; gmem[1004]=fga;
gfx_blit(0,1);]=]
    if c_master >= 0 then 
        set_fx_code_simple(corr_track, c_master, master_code, false)
        reaper.TrackFX_SetParam(corr_track, c_master, 0, 0.05)
        reaper.TrackFX_SetParam(corr_track, c_master, 1, 0.5)
        reaper.TrackFX_SetParam(corr_track, c_master, 2, 0.5)
        reaper.TrackFX_SetParam(corr_track, c_master, 3, 0.75)
    end
    
    -- Slave Code Template (for items)
    local slave_template = [=[// Subass Style Slave
#text="INSERT_TEXT_HERE"; font="Arial"; border = 0.2; fgc = 1.0; bgc = 0.0; bgfit = 1;
input_info(-1,project_w,project_h);
(project_w <= 0 || project_h <= 0) ? ( project_w = 1920; project_h = 1080; );
gfx_blit(0,1);
size=gmem[1000] > 0 ? gmem[1000] : 0.05;
ypos=gmem[1001] > 0 ? gmem[1001] : 0.5;
xpos=gmem[1002] > 0 ? gmem[1002] : 0.5;
bga=gmem[1003] > 0 ? gmem[1003] : 0.75;
fga=gmem[1004] > 0 ? gmem[1004] : 1.0;
size > 0 ? (
  gfx_setfont(size*project_h,font);
  gfx_str_measure(#text,txtw,txth);
  b = (border*txth)|0; yt = ((project_h - txth - b*2)*ypos)|0; xp = (xpos * (project_w-txtw))|0;
  gfx_set(bgc,bgc,bgc,bga); bga>0?gfx_fillrect(bgfit?xp-b:0, yt, bgfit?txtw+b*2:project_w, txth+b*2);
  gfx_set(fgc,fgc,fgc,fga); gfx_str_draw(#text,xp,yt+b);
);]=]

    -- Populate CORR Items
    table.sort(markers, function(a, b) return a.pos < b.pos end)
    table.sort(regions, function(a, b) return a.pos < b.pos end)
    for i, m in ipairs(markers) do
        local in_rgn = false; local r_obj = nil
        for _, r in ipairs(regions) do
            if m.pos >= r.pos and m.pos < r.rgnend then r_obj = r; in_rgn = true; break end
        end
        local sp = m.pos; local ep = m.pos + 10
        if in_rgn then
            local is_first = true
            for j = 1, i - 1 do
                local m_prev = markers[j]
                if m_prev.pos >= r_obj.pos and m_prev.pos < r_obj.rgnend then is_first = false; break end
            end
            if is_first then sp = r_obj.pos end
            ep = r_obj.rgnend
        end
        if i < #markers then
            local next_m = markers[i+1]
            if next_m.pos < ep then ep = next_m.pos end
        end
        
        -- NEW: Clip EP by the start of the next available region (prevents overlap)
        for _, r in ipairs(regions) do
            if r.pos > m.pos and r.pos < ep then
                ep = r.pos
                break
            end
        end

        if ep > sp + 0.001 then
            local dn = m.name or ""
            if #dn > 80 then
                local w = {}; local cl = ""
                for word in dn:gmatch("%S+") do
                    if #cl + #word + 1 > 80 then table.insert(w, cl); cl = word
                    else cl = (cl == "" and word or cl .. " " .. word) end
                end
                table.insert(w, cl); dn = table.concat(w, "\n")
            end
            local mi = reaper.CreateNewMIDIItemInProj(corr_track, sp, ep, false)
            local mt = reaper.GetActiveTake(mi)
            if mt then
                reaper.GetSetMediaItemTakeInfo_String(mt, "P_NAME", dn, true)
                local mfx = reaper.TakeFX_AddByName(mt, "Video processor", 1)
                if mfx >= 0 then 
                    local safe_dn = dn:gsub('"', [[']])
                    local item_code = slave_template:gsub("INSERT_TEXT_HERE", function() return safe_dn end)
                    set_fx_code_simple(mt, mfx, item_code, true) 
                end
            end
        end
    end

    reaper.Undo_EndBlock(T("CREATE_RETAKES_TRACK"), -1)
    reaper.UpdateArrange()
end

local function show_panel_preset_dialog(panel_type, idx)
    local is_new = (idx == nil)
    local target_presets = (panel_type == "director") and cfg.director_presets or cfg.fmt_presets
    local panel_name = (panel_type == "director") and T("DIRECTOR") or T("EDITOR")
    
    local preset = not is_new and target_presets[idx] or {label="", val=""}
    
    local ok, ret = reaper.GetUserInputs(is_new and (T("ADD_RESET_M") .. panel_name .. ")") or (T("EDIT_RESET_M") .. panel_name .. ")"), 2, 
        T("EDIT_PRESET_MENU_T_1") .. (panel_type == "editor" and T("EDIT_PRESET_MENU_T_2") or "") .. ",extrawidth=250", 
        preset.label .. "," .. preset.val)
    
    if ok then
        local l, v = ret:match("^(.-),(.*)$")
        if l and v then
            local off_l = utf8.offset(l, 4)
            if off_l then l = l:sub(1, off_l - 1) end
            if l == "" then 
                l = v
                local off_v = utf8.offset(l, 4)
                if off_v then l = l:sub(1, off_v - 1) end
            end
            local new_preset = {label = l, val = v}
            if is_new then table.insert(target_presets, new_preset)
            else target_presets[idx] = new_preset end
            save_settings()
        end
    end
end

function DRAW_WINDOW.draw_director_panel(panel_x, panel_y, panel_w, panel_h, input_queue, calc_only)
    gfx.setfont(F.std)
    if not calc_only then
        set_color(UI.C_BG)
        gfx.rect(panel_x, panel_y, panel_w, panel_h, 1)
    end
    
    local is_dir_right = (cfg.director_layout == "right")

    local padding = S(10)
    local btn_h = S(24)
    -- --- AUTO-DETECT CURRENT MARKER ---
    local play_pos = reaper.GetPlayPosition()
    local edit_pos = reaper.GetCursorPosition()
    local cur_time = reaper.GetPlayState() > 0 and play_pos or edit_pos
    
    -- --- CONTEXT DETECTION (Active ASS Actors) ---
    local current_ass_actors = cfg.director_autofill and UTILS.get_ass_actors_at_time(cur_time) or {}
    
    UTILS.update_director_marker_and_autofill(cur_time, current_ass_actors)
    
    -- --- AUTO-ATTACH TIME SELECTION ---
    UTILS.update_corr_time_prefix(calc_only, cur_time)

    local btn_h = S(24) -- Standard button height
    
    local opt_btn_w = S(30)
    local opt_x = panel_x + panel_w - padding - opt_btn_w
    local opt_draw_y = panel_y + ((cfg.director_layout == "right") and S(2) or padding)
    local is_opt_hover = false
    if not calc_only then
        is_opt_hover = UI_STATE.window_focused and
                       (gfx.mouse_x >= opt_x and gfx.mouse_x <= opt_x + opt_btn_w and
                        gfx.mouse_y >= opt_draw_y and gfx.mouse_y <= opt_draw_y + btn_h)
    end

    local function draw_actor_btn_inline(x, y, w, h, text, bg_col, suppress_hover)
        local hover = UI_STATE.window_focused and (gfx.mouse_x >= x and gfx.mouse_x <= x + w and gfx.mouse_y >= y and gfx.mouse_y <= y + h) and not suppress_hover
        local effective_bg = hover and UI.C_BTN_H or (bg_col or UI.C_BTN)
        set_color(effective_bg)
        gfx.rect(x, y, w, h, 1)
        
        set_color(UI.C_TXT)
        
        local str_w, str_h = gfx.measurestr(text)
        gfx.x = x + (w - str_w) / 2
        gfx.y = y + (h - str_h) / 2
        gfx.drawstr(text)
        if hover and is_mouse_clicked() then return true end
        return false
    end

    -- Clipped button: renders the button but crops it to [clip_y_top, clip_y_bot]
    local function draw_actor_btn_clipped(x, y, w, h, text, bg_col, clip_y_top, clip_y_bot)
        local vis_y1 = math.max(y, clip_y_top)
        local vis_y2 = math.min(y + h, clip_y_bot)
        if vis_y1 >= vis_y2 then return false end -- fully outside
        
        local is_fully_visible = (y >= clip_y_top and y + h <= clip_y_bot)
        if is_fully_visible then
            return draw_actor_btn_inline(x, y, w, h, text, bg_col, is_opt_hover)
        end
        
        local buf = OTHER.BUF.DIRECTOR -- Reuse same buffer
        gfx.setimgdim(buf, w, h)
        local prev_dest = gfx.dest
        gfx.dest = buf
        
        local hover = UI_STATE.window_focused and not is_opt_hover and
            (gfx.mouse_x >= x and gfx.mouse_x <= x + w and
             gfx.mouse_y >= vis_y1 and gfx.mouse_y <= vis_y2)
        local effective_bg = hover and UI.C_BTN_H or (bg_col or UI.C_BTN)
        set_color(effective_bg)
        gfx.rect(0, 0, w, h, 1)
        
        set_color(UI.C_TXT)

        local sw, sh = gfx.measurestr(text)
        gfx.x = (w - sw) / 2
        gfx.y = (h - sh) / 2
        gfx.drawstr(text)
        
        gfx.dest = prev_dest
        local src_y = vis_y1 - y
        local slice_h = vis_y2 - vis_y1
        gfx.blit(buf, 1, 0, 0, src_y, w, slice_h, x, vis_y1, w, slice_h)
        
        if hover and not director_resize_drag and is_mouse_clicked() then return true end
        return false
    end

    -- Standard button for other UI elements in this panel
    local function draw_btn_clipped(x, y, w, h, text, bg_col, clip_y_top, clip_y_bot)
        local vis_y1 = math.max(y, clip_y_top)
        local vis_y2 = math.min(y + h, clip_y_bot)
        if vis_y1 >= vis_y2 then return false end -- fully outside
        
        local is_fully_visible = (y >= clip_y_top and y + h <= clip_y_bot)
        
        if is_fully_visible then
            -- Fast path: no clipping needed, use normal draw
            return draw_actor_btn_inline(x, y, w, h, text, bg_col, is_opt_hover)
        end
        
        -- Slow path: render to offscreen buffer and blit only visible slice
        local buf = OTHER.BUF.DIRECTOR
        gfx.setimgdim(buf, w, h)
        local prev_dest = gfx.dest
        gfx.dest = buf
        
        local hover = UI_STATE.window_focused and not is_opt_hover and
            (gfx.mouse_x >= x and gfx.mouse_x <= x + w and
             gfx.mouse_y >= vis_y1 and gfx.mouse_y <= vis_y2)
        local effective_bg = hover and UI.C_BTN_H or (bg_col or UI.C_BTN)
        set_color(effective_bg)
        gfx.rect(0, 0, w, h, 1)
        
        set_color(UI.C_TXT)
        local sw, sh = gfx.measurestr(text)
        gfx.x = (w - sw) / 2
        gfx.y = (h - sh) / 2
        gfx.drawstr(text)
        
        gfx.dest = prev_dest
        
        -- Blit only the visible vertical slice
        local src_y = vis_y1 - y
        local slice_h = vis_y2 - vis_y1
        gfx.blit(buf, 1, 0, 0, src_y, w, slice_h, x, vis_y1, w, slice_h)
        
        if hover and not director_resize_drag and is_mouse_clicked() then return true end
        return false
    end

    -- --- ROW 1: ACTORS ---
    local x = padding
    -- Use smaller top padding for Right layout to save space
    local y = (cfg.director_layout == "right") and S(2) or padding
    
    if not calc_only then
        -- Draw Background
        set_color(UI.C_BG)
        gfx.rect(panel_x, panel_y, panel_w, panel_h, 1)
        
        -- Draw Separator (Left or Top depending on layout? For now basic border)
        set_color(UI.C_MEDIUM_GREY)
        if cfg.director_layout == "right" then
            gfx.line(panel_x, panel_y, panel_x, panel_y + panel_h)
        else
            gfx.rect(panel_x, panel_y, panel_w, 2, 1)
        end
    end
    
    -- Adjust coordinates for drawing
    local draw_x = panel_x + x
    local draw_y = panel_y + y
    
    local _, current_actors_set = get_actors_from_text(director_state.input.text)
    
    local save_btn_w = S(100)
    -- Detect narrow mode (Right layout) for proper input width calculation
    local is_right_layout = (cfg.director_layout == "right")
    local input_w = is_right_layout and (panel_w - padding*2) or (panel_w - padding*2 - save_btn_w - S(10))
    
    -- Options Menu Button (Top-Right)
    local opt_btn_w = S(30)
    local opt_x = panel_x + panel_w - padding - opt_btn_w
    
    -- Actor buttons should wrap before reaching the options button
    local limit_x = opt_x - S(5) -- Leave small gap before options button
    
    local opt_draw_y = draw_y
    local function draw_options_menu()
        if not calc_only and draw_actor_btn_inline(opt_x, opt_draw_y, opt_btn_w, btn_h, "≡", UI.C_ACCENT_N) then
            local dock_check = gfx.dock(-1) > 0 and "!" or ""
            local layout_label = (cfg.director_layout == "right") and T("DOCK_BOTTOM") or T("DOCK_RIGHT")
            local autofill_check = cfg.director_autofill and "• " or ""
            local ignore_green_check = cfg.director_ignore_green and "• " or ""
            local menu_str = T("COPY_ALL_RETAKES_TO_CB") .. "||>" .. T("EXPORT_RETAKES_TO_CSV") .. "|" .. T("EXPORT_DUBBER_MENU") .. "|<|" .. T("IMPORT_ACTOR_NAMES_FROM_SB") .. "||" .. autofill_check .. T("AUTOMATICALLY_SELECT_DUBBER_NAME") .. "|" .. ignore_green_check .. T("IGNORE_COPY_GREEN_RETAKES") .. "|" .. T("CREATE_RETAKES_TRACK") .. "||" .. layout_label .. "|" .. T("CLOSE_WINDOW")
            
            gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
            local ret = gfx.showmenu(menu_str)

            if ret == 1 then
                -- Copy
                ass_markers = capture_project_markers()
                UTILS.copy_markers_to_clipboard(ass_markers)
            elseif ret == 2 then
                -- Просто експорт
                ass_markers = capture_project_markers()
                UTILS.export_markers_to_csv(ass_markers)
            elseif ret == 3 then
                -- Експорт з дедлайном
                DEADLINE.open_picker(nil, function(ts)
                    if not ts then return end
                    local dt = os.date("*t", ts)
                    local d_str = string.format("[%02d.%02d.%02d]", dt.day, dt.month, dt.year % 100)
                    ass_markers = capture_project_markers()
                    UTILS.export_markers_to_csv(ass_markers, d_str)
                end)
            elseif ret == 4 then
                -- Import names
                local existing = {}
                for _, a in ipairs(director_actors) do existing[a] = true end
                
                local names_to_import = {}
                local names_to_update = {}
                local source_label = T("SUBTITLES")
                
                -- Try Dubbers first
                if DUBBERS.data and DUBBERS.data.names and #DUBBERS.data.names > 0 then
                    source_label = T("DB_FROM_DUBBERS_MENU_1")
                    for _, name in ipairs(DUBBERS.data.names) do
                        if name ~= "" and not existing[name] then
                            table.insert(names_to_import, name)
                            existing[name] = true
                        end

                        if name ~= "" then
                            table.insert(names_to_update, name)
                        end
                    end
                else
                    -- Fallback to Subtitles
                    for _, line in ipairs(ass_lines) do
                        if line.actor and line.actor ~= "" and not existing[line.actor] then
                            table.insert(names_to_import, line.actor)
                            existing[line.actor] = true
                        end

                        if line.actor and line.actor ~= "" then
                            table.insert(names_to_update, line.actor)
                        end
                    end
                end
                
                local count = #names_to_import
                if count > 0 then
                    push_undo(T("IMPORT_ACTORS_NAMES_1") .. source_label .. " (" .. count .. ")")
                    for _, name in ipairs(names_to_import) do
                        table.insert(director_actors, name)
                    end

                    if source_label == T("SUBTITLES") then
                        for _, name in ipairs(names_to_update) do
                            director_state.region_actor_to_dubber[name] = name
                        end
                    end
                    
                    -- Sync DUBBERS assignments into the director mapping for newly imported names
                    UTILS.sync_dubbers_to_director(director_state.region_actor_to_dubber)
                    save_project_data(UI_STATE.last_project_id)
                    reaper.MarkProjectDirty(0) -- SAVE ON CHANGE
                    show_snackbar(T("IMPORTED_FROM_DD_EXT_1") .. count .. T("IMPORTED_FROM_DD_EXT_2") .. source_label, "success")
                else
                    show_snackbar(T("NO_NEW_NAMES_FOUND"), "info")
                end
            elseif ret == 5 then
                -- Toggle Autofill
                cfg.director_autofill = not cfg.director_autofill
                save_settings()
            elseif ret == 6 then
                -- Toggle Ignore Green
                cfg.director_ignore_green = not cfg.director_ignore_green
                save_settings()
            elseif ret == 7 then
                -- Integrate Correction Tracks
                UTILS.integrate_correction_tracks()
            elseif ret == 8 then
                -- Toggle Layout
                if cfg.director_layout == "right" then
                    cfg.director_layout = "bottom"
                else
                    cfg.director_layout = "right"
                end
                save_settings() -- Save state immediately
                last_layout_state.state_count = -1 -- Force redraw
            elseif ret == 9 then
                cfg.director_mode = not cfg.director_mode
                save_settings()
            end
        end
    end

    -- Check for recent notes visibility
    local has_recent_notes = false
    for _, m in ipairs(ass_markers) do
        if m.name and m.name:gsub("%s", "") ~= "" then
            has_recent_notes = true
            break
        end
    end
    director_state.has_recent_notes = has_recent_notes

    -- --- DRY RUN for height calculation (Matching draw_editor_panel) ---
    local dry_x = padding
    local dry_y = 0
    local act_row_h = btn_h + S(5)
    
    for _, actor in ipairs(director_actors) do
        local w, _ = gfx.measurestr(actor)
        local b_w = w + S(20)
        if panel_x + dry_x + b_w > limit_x then
            dry_x = padding
            dry_y = dry_y + act_row_h
        end
        dry_x = dry_x + b_w + S(5)
    end
    
    if panel_x + dry_x + S(24) > limit_x then dry_x = padding dry_y = dry_y + act_row_h end
    
    local start_y = is_right_layout and S(8) or S(16)
    local needed_actor_h = start_y + dry_y + btn_h
    local max_actor_h_limit = is_right_layout and (4 * act_row_h + S(2)) or (3 * act_row_h + S(10))
    local actor_area_h = math.min(needed_actor_h, max_actor_h_limit)
    local actor_area_bottom = panel_y + actor_area_h
    
    -- --- SCROLL: handle wheel in actor area ---
    if not calc_only and UI_STATE.window_focused and gfx.mouse_wheel ~= 0 and
       gfx.mouse_x >= panel_x and gfx.mouse_x <= panel_x + panel_w and
       gfx.mouse_y >= panel_y and gfx.mouse_y <= actor_area_bottom then
        local step = btn_h + S(5)
        -- Accumulate the wheel to correctly handle smooth trackpads (macOS)
        director_state.wheel_accum = (director_state.wheel_accum or 0) + gfx.mouse_wheel
        local wheel_sensitivity = 80 -- Threshold per row jump
        
        local new_scroll = director_state.target_scroll_y or 0
        while director_state.wheel_accum >= wheel_sensitivity do
            -- Scroll UP (negative Y): snap to the closest grid point below the current value
            new_scroll = math.floor((new_scroll - 1) / step) * step
            if new_scroll < 0 then new_scroll = 0 end
            director_state.wheel_accum = director_state.wheel_accum - wheel_sensitivity
        end
        while director_state.wheel_accum <= -wheel_sensitivity do
            -- Scroll DOWN (positive Y): snap to the closest grid point above the current value
            new_scroll = math.ceil((new_scroll + 1) / step) * step
            director_state.wheel_accum = director_state.wheel_accum + wheel_sensitivity
        end
        
        director_state.target_scroll_y = new_scroll

        -- Clamp immediately using cached max_scroll from previous frame to prevent overshoot
        local cached_max = director_state.cached_max_scroll or 0
        director_state.target_scroll_y = math.max(0, math.min(cached_max, director_state.target_scroll_y))
        gfx.mouse_wheel = 0
    end
    -- Instant step scroll (no smooth interpolation)
    director_state.scroll_y = director_state.target_scroll_y or 0

    for i, actor in ipairs(director_actors) do
        local label = actor
        local w, _ = gfx.measurestr(label)
        local btn_w = w + S(20)
        
        -- Wrap Check relative to panel start
        if draw_x + btn_w > limit_x then
            x = padding
            y = y + btn_h + S(5)
            draw_x = panel_x + x
            draw_y = panel_y + y
        end
        
        if not calc_only then
            -- Logic drawing ...
            local is_active = current_actors_set[actor]
            local act_col = nil
            if cfg.editor_show_actor_color then
                local native = get_actor_color(actor)
                if native and native ~= 0 then
                    local r, g, b = reaper.ColorFromNative(native & 0xFFFFFF)
                    act_col = {r/255, g/255, b/255}
                end
            end

            local bg_col = is_active and UI.C_ACCENT_G or UI.C_BTN
            local sdraw_y = draw_y - math.floor(director_state.scroll_y or 0) -- scrolled Y
            
            -- Hover Check for Right Click
            -- Adjust hit test to relative coords
            local hover = UI_STATE.window_focused and (gfx.mouse_x >= draw_x and gfx.mouse_x <= draw_x + btn_w and gfx.mouse_y >= sdraw_y and gfx.mouse_y <= sdraw_y + btn_h)
            
            -- Only draw if any part is visible in actor area (draw_btn_clipped handles visual cropping)
            if sdraw_y + btn_h > panel_y and sdraw_y < actor_area_bottom then
                if draw_actor_btn_clipped(draw_x, sdraw_y, btn_w, btn_h, label, bg_col, panel_y, actor_area_bottom) then
                    if not is_opt_hover then
                        -- Toggle Logic
                        local txt = director_state.input.text
                        local list, _ = get_actors_from_text(txt)
                        local clean = txt:gsub("^%[.-%]%s*", "")
                        
                        if is_active then
                            -- Toggle Off (Remove from list)
                            local new_list = {}
                            for _, a in ipairs(list) do
                                if a ~= actor then table.insert(new_list, a) end
                            end
                            if #new_list > 0 then
                                director_state.input.text = "[" .. table.concat(new_list, ", ") .. "] " .. clean
                            else
                                director_state.input.text = clean
                            end
                        else
                            -- Toggle On (Add to list)
                            table.insert(list, actor)
                            director_state.input.text = "[" .. table.concat(list, ", ") .. "] " .. clean
                            
                            -- --- LEARNING (Mapping Update) ---
                            -- Associate only if one actor is speaking clearly
                            if #current_ass_actors == 1 then
                                director_state.region_actor_to_dubber[current_ass_actors[1]] = actor
                                -- Sync all DUBBERS assignments into the mapping
                                UTILS.sync_dubbers_to_director(director_state.region_actor_to_dubber)
                                save_project_data(UI_STATE.last_project_id)
                            end
                        end
                        director_state.input.cursor = #director_state.input.text
                        director_state.input.anchor = director_state.input.cursor
                        director_state.input.focus = true
                        record_field_history(director_state.input)
                    end
                end

            end -- clip
            
            -- Right Click (must be in visible area)
            if not is_opt_hover and hover and sdraw_y >= panel_y and sdraw_y + btn_h <= actor_area_bottom and is_right_mouse_clicked() then
                -- ... (Context Menu Logic) ...
                UI_STATE.mouse_handled = true

                -- Check if multiple actors are currently selected in the input
                local sel_list, sel_set = get_actors_from_text(director_state.input.text)
                local has_multiple_selected = (#sel_list > 1)

                gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
                local menu_str2 = T("COPY_RETAKES_FOR") .. actor .. "||" .. T("CHANGE_NAME") .. "|" .. T("REMOVE_NAME")
                
                if has_multiple_selected then
                    menu_str2 = menu_str2 .. "||" .. T("DELETE_SELECTED_NAMES") .. " (" .. #sel_list .. ")|" .. T("COPY_RETAKES_FOR_SELECTED") .. " (" .. #sel_list .. ")"
                end
                
                local ret2 = gfx.showmenu(menu_str2)
                if ret2 == 1 then
                    -- COPY SINGLE ACTOR
                    UTILS.copy_markers_to_clipboard(ass_markers, {[actor] = true})
                elseif ret2 == 2 then
                    -- RENAME
                    local ok, new_name = reaper.GetUserInputs(T("CHANGE_ACTOR_NAME"), 1, T("NEW_NAME"), actor)
                    if ok then
                        -- Remove variation selector (U+FE0F = \239\184\143) and trim spaces
                        new_name = new_name:gsub("\239\184\143", ""):match("^%s*(.-)%s*$")
                        
                        if new_name ~= "" and new_name ~= actor then
                            -- Merge check
                            local target_exists = false
                            for _, act in ipairs(director_actors) do
                                if act == new_name then target_exists = true break end
                            end
                            
                            if target_exists then
                                push_undo(T("MERGE_EDITOR_U_1") .. actor .. T("MERGE_EDITOR_U_2") .. new_name.. T("MERGE_EDITOR_U_3"))
                                table.remove(director_actors, i)
                                save_project_data(UI_STATE.last_project_id)
                                reaper.MarkProjectDirty(0) -- SAVE ON CHANGE
                                local ops = rename_actor_globally(actor, new_name)

                                -- Force prompter drawer caches to refresh
                                prompter_drawer.marker_cache.count = -1
                                prompter_drawer.filtered_cache.state_count = -1
                                prompter_drawer.has_markers_cache.count = -1
                                
                                -- Update Input if needed
                                local list, set = get_actors_from_text(director_state.input.text)
                                if set[actor] then
                                    local new_list = {}
                                    for _, a in ipairs(list) do
                                        table.insert(new_list, (a == actor) and new_name or a)
                                    end
                                    local clean = director_state.input.text:gsub("^%[.-%]%s*", "")
                                    director_state.input.text = "[" .. table.concat(new_list, ", ") .. "] " .. clean
                                    director_state.input.cursor = #director_state.input.text
                                    director_state.input.anchor = director_state.input.cursor
                                end

                                show_snackbar(T("MERGE_EDITOR_SS_1") .. new_name .. "' (" .. ops .. T("MERGE_EDITOR_SS_2"), "success")
                            else
                                push_undo(T("CHANGE_ACTOR_NAME") .. " " .. actor .. " -> " .. new_name)
                                director_actors[i] = new_name
                                save_project_data(UI_STATE.last_project_id)
                                reaper.MarkProjectDirty(0) -- SAVE ON CHANGE
                                local ops = rename_actor_globally(actor, new_name)

                                -- Force prompter drawer caches to refresh
                                prompter_drawer.marker_cache.count = -1
                                prompter_drawer.filtered_cache.state_count = -1
                                prompter_drawer.has_markers_cache.count = -1
                                
                                -- Update Input if needed
                                local list, set = get_actors_from_text(director_state.input.text)
                                if set[actor] then
                                    local new_list = {}
                                    for _, a in ipairs(list) do
                                        table.insert(new_list, (a == actor) and new_name or a)
                                    end
                                    local clean = director_state.input.text:gsub("^%[.-%]%s*", "")
                                    director_state.input.text = "[" .. table.concat(new_list, ", ") .. "] " .. clean
                                    director_state.input.cursor = #director_state.input.text
                                    director_state.input.anchor = director_state.input.cursor
                                end

                                show_snackbar(T("MERGE_EDITOR_CN_1") .. ops .. T("MERGE_EDITOR_CN_2"), "success")
                            end
                        end
                    end
                elseif ret2 == 3 then
                    -- DELETE
                    local ok = reaper.MB(T("REMOVE_RETAKE_NAME_CM_1") .. actor .. T("REMOVE_RETAKE_NAME_CM_2"), T("CONFIRMATION"), 4)
                    if ok == 6 then
                        push_undo(T("REMOVE_RETAKE_NAME_U_2_1") .. actor .. T("REMOVE_RETAKE_NAME_U_2_2"))
                        table.remove(director_actors, i)
                        save_project_data(UI_STATE.last_project_id)
                        reaper.MarkProjectDirty(0) -- SAVE ON CHANGE
                        local ops = delete_actor_globally(actor)

                        -- Force prompter drawer caches to refresh
                        prompter_drawer.marker_cache.count = -1
                        prompter_drawer.filtered_cache.state_count = -1
                        prompter_drawer.has_markers_cache.count = -1
                        
                        -- Update Input if needed
                        local list, set = get_actors_from_text(director_state.input.text)
                        if set[actor] then
                            local new_list = {}
                            for _, a in ipairs(list) do
                                if a ~= actor then table.insert(new_list, a) end
                            end
                            local clean = director_state.input.text:gsub("^%[.-%]%s*", "")
                            if #new_list > 0 then
                                director_state.input.text = "[" .. table.concat(new_list, ", ") .. "] " .. clean
                            else
                                director_state.input.text = clean
                            end
                            director_state.input.cursor = #director_state.input.text
                            director_state.input.anchor = director_state.input.cursor
                        end
                        
                        show_snackbar(T("REMOVE_RETAKE_NAME_S_2_1") .. ops .. T("REMOVE_RETAKE_NAME_S_2_2"), "info")
                    end
                elseif ret2 == 4 and has_multiple_selected then
                    -- BULK DELETE SELECTED
                    local names_list = table.concat(sel_list, ", ")
                    local ok = reaper.MB(T("REMOVE_AR_SURE_MANY_1") .. #sel_list .. T("REMOVE_AR_SURE_MANY_2") .. names_list .. T("REMOVE_AR_SURE_MANY_3"), T("CONFIRMATION"), 4)
                    if ok == 6 then
                        push_undo(T("REMOVE_SA_PU_1") .. #sel_list .. T("REMOVE_SA_PU_2"))
                        
                        local total_ops = 0
                        local to_remove_indices = {}
                        
                        -- Process all selected actors
                        for _, act_to_del in ipairs(sel_list) do
                            -- Find index in director_actors to remove
                            for idx, d_act in ipairs(director_actors) do
                                if d_act == act_to_del then
                                    table.insert(to_remove_indices, idx)
                                    break
                                end
                            end
                            -- Delete globally
                            local ops = delete_actor_globally(act_to_del)
                            total_ops = total_ops + ops
                        end
                        
                        -- Remove from director_actors (in reverse order to not mess up indices)
                        table.sort(to_remove_indices, function(a, b) return a > b end)
                        for _, idx in ipairs(to_remove_indices) do
                            table.remove(director_actors, idx)
                        end
                        
                        save_project_data(UI_STATE.last_project_id)
                        reaper.MarkProjectDirty(0) -- SAVE ON CHANGE
                        
                        -- Force prompter drawer caches to refresh
                        prompter_drawer.marker_cache.count = -1
                        prompter_drawer.filtered_cache.state_count = -1
                        prompter_drawer.has_markers_cache.count = -1
                        
                        -- Clear them from input
                        local clean = director_state.input.text:gsub("^%[.-%]%s*", "")
                        director_state.input.text = clean
                        director_state.input.cursor = #director_state.input.text
                        director_state.input.anchor = director_state.input.cursor
                        
                        show_snackbar(T("REMOVE_SS_PU_1") .. #sel_list .. T("REMOVE_SS_PU_2") .. total_ops .. T("REMOVE_SS_PU_3"), "info")
                    end
                elseif ret2 == 5 and has_multiple_selected then
                    -- COPY SELECTED ACTORS
                    UTILS.copy_markers_to_clipboard(ass_markers, sel_set)
                end
            end
        end
        x = x + btn_w + S(5)
        draw_x = panel_x + x -- Update draw X
    end

    -- Clamp scroll after layout is known
    if not calc_only then
        local total_actors_h = y + btn_h + S(20) -- total height + bottom padding
        local viewport_h = actor_area_bottom - panel_y
        local max_scroll = math.max(0, total_actors_h - viewport_h)
        
        director_state.cached_max_scroll = max_scroll  -- cache for next frame pre-clamp
        director_state.target_scroll_y = math.max(0, math.min(max_scroll, director_state.target_scroll_y or 0))
        -- Also clamp scroll_y itself to prevent overshoot snap-back
        director_state.scroll_y = math.max(0, math.min(max_scroll, director_state.scroll_y or 0))
        -- Draw scrollbar indicator if needed
        if max_scroll > 0 then
            local bar_h = math.max(S(20), (viewport_h / total_actors_h) * viewport_h)
            local bar_y = panel_y + ((director_state.scroll_y or 0) / total_actors_h) * viewport_h
            set_color(UI.C_TXT_DIM)
            gfx.rect(panel_x + panel_w - S(4), bar_y, S(3), bar_h, 1)
        end
    end

    if not calc_only then
        -- Draw # Button (Recent Notes)

        -- Check wrap for "+" button
        if draw_x + S(24) > limit_x then
            x = padding
            y = y + btn_h + S(5)
            draw_x = panel_x + x
            draw_y = panel_y + y
        end
        local sdraw_y_plus = draw_y - math.floor(director_state.scroll_y or 0)
        if sdraw_y_plus + btn_h > panel_y and sdraw_y_plus < actor_area_bottom then
            if draw_btn_clipped(draw_x, sdraw_y_plus, S(24), btn_h, "+", UI.C_ACCENT_N, panel_y, actor_area_bottom) then
                if not is_opt_hover then
                    local ok, name = reaper.GetUserInputs(T("ADD_AN_ACTOR_DIRECTOR"), 1, T("ACTORS_NAME"), "")
                    if ok then
                        -- Remove variation selector (U+FE0F = \239\184\143) and trim spaces
                        name = name:gsub("\239\184\143", ""):match("^%s*(.-)%s*$")
                        
                        if name ~= "" then
                            -- Check duplication
                            local exists = false
                            for _, act in ipairs(director_actors) do
                                if act == name then exists = true break end
                            end
                            
                            if not exists then
                                push_undo(T("ADD_AN_ACTOR_SS_DIRECTOR_1") .. name .. T("ADD_AN_ACTOR_SS_DIRECTOR_2"))
                                table.insert(director_actors, name)
                                save_project_data(UI_STATE.last_project_id)
                                reaper.MarkProjectDirty(0) -- SAVE ON CHANGE
                            end
                        end
                    end
                end
            end
        end
    end
    
    draw_options_menu()
    
    -- --- ROW 2: PRESETS ---
    local control_row_h = S(28)
    local preset_row_y = actor_area_bottom + padding
    if not calc_only then
        -- Separator line
        set_color(UI.C_MEDIUM_GREY)
        gfx.line(panel_x, actor_area_bottom, panel_x + panel_w, actor_area_bottom)
        
        local cpx = panel_x + padding
        
        -- History Button (#)
        if director_state.has_recent_notes then
            if cpx + S(24) <= (panel_x + panel_w - padding) then
                gfx.setfont(F.std)
                if draw_actor_btn_inline(cpx, preset_row_y, S(24), control_row_h, "#", UI.C_ACCENT_SN) then
                    -- Collect Unique Notes
                    local unique_notes = {}
                    local used_text = {}
                        
                        -- 1. Try Recent Indices First
                    local markers_by_id = {}
                    for _, m in ipairs(ass_markers) do markers_by_id[m.markindex] = m end
                
                    for _, rid in ipairs(director_state.recent_indices) do
                        local m = markers_by_id[rid]
                        if m and m.name and m.name ~= "" and not used_text[m.name] then
                            table.insert(unique_notes, m.name)
                            used_text[m.name] = true
                            if #unique_notes >= 15 then break end
                        end
                    end
                    
                        -- 2. Fill with Newest Markers if space remains
                    if #unique_notes < 15 then
                        for i = #ass_markers, 1, -1 do
                            local m = ass_markers[i]
                            if m and m.name and m.name ~= "" and not used_text[m.name] then
                                table.insert(unique_notes, m.name)
                                used_text[m.name] = true
                                if #unique_notes >= 15 then break end
                            end
                        end
                    end
                    
                    if #unique_notes > 0 then
                        local menu_items = {}
                        for _, note in ipairs(unique_notes) do
                            table.insert(menu_items, (note:gsub("|", "||")))
                        end
                        local menu_str = table.concat(menu_items, "|")
                            
                        gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
                        local ret = gfx.showmenu(menu_str)
                        if ret > 0 and unique_notes[ret] then
                            director_state.input.text = unique_notes[ret]
                            director_state.input.cursor = #director_state.input.text
                            director_state.input.anchor = director_state.input.cursor
                            director_state.input.focus = true
                            record_field_history(director_state.input)
                        end
                    end
                end
                cpx = cpx + S(24) + S(5)
            end
        end

        for i, p in ipairs(cfg.director_presets) do
            local btn_w = S(45)
            if cpx + btn_w <= (panel_x + panel_w - padding) then
                gfx.setfont(F.std)
                if draw_actor_btn_inline(cpx, preset_row_y, btn_w, control_row_h, p.label, UI.C_ROW) then
                    local txt = director_state.input.text
                    local actor_prefix = txt:match("^%[.-%]%s*") or ""
                    local rem = txt:sub(#actor_prefix + 1)
                    local time_prefix = rem:match("^%d+[:%.][%d:%.]*%s*-%s*") or ""
                    
                    local prefix = actor_prefix .. time_prefix
                    director_state.input.text = prefix .. p.val
                    director_state.input.cursor = #director_state.input.text
                    director_state.input.anchor = director_state.input.cursor
                    director_state.input.focus = true
                    record_field_history(director_state.input)
                    UI_STATE.mouse_handled = true
                end
                
                -- Tooltip and Right Click Menu
                local is_h = UI_STATE.window_focused and 
                             gfx.mouse_x >= cpx and gfx.mouse_x <= cpx + btn_w and 
                             gfx.mouse_y >= preset_row_y and gfx.mouse_y <= preset_row_y + control_row_h
                
                if is_h then
                    local tip_id = "dir_preset_" .. i
                    if UI_STATE.tooltip_state.hover_id ~= tip_id then
                        UI_STATE.tooltip_state.hover_id = tip_id
                        UI_STATE.tooltip_state.start_time = reaper.time_precise()
                    end
                    UI_STATE.tooltip_state.text = p.val
                    
                    if is_right_mouse_clicked() then
                        UI_STATE.mouse_handled = true
                        gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
                        local menu_str = T("EDIT_DELETE_PRESET_MENU") .. (i > 1 and "" or "#") .. T("PRESET_MOVE_LEFT_MENU") .. (i < #cfg.director_presets and "" or "#") .. T("PRESET_MOVE_RIGHT_MENU")
                        local sel = gfx.showmenu(menu_str)
                        if sel == 1 then show_panel_preset_dialog("director", i)
                        elseif sel == 2 then table.remove(cfg.director_presets, i) save_settings()
                        elseif sel == 3 then local t = table.remove(cfg.director_presets, i) table.insert(cfg.director_presets, i-1, t) save_settings()
                        elseif sel == 4 then local t = table.remove(cfg.director_presets, i) table.insert(cfg.director_presets, i+1, t) save_settings() end
                    end
                end
                cpx = cpx + btn_w + S(5)
            end
        end
        if cpx + S(24) <= (panel_x + panel_w - padding) then
            gfx.setfont(F.std)
            if draw_actor_btn_inline(cpx, preset_row_y, S(24), control_row_h, "+", UI.C_ACCENT_SN) then
                show_panel_preset_dialog("director")
            end
            
            -- Tooltip for Add Preset
            local is_h = UI_STATE.window_focused and 
                         gfx.mouse_x >= cpx and gfx.mouse_x <= cpx + S(24) and 
                         gfx.mouse_y >= preset_row_y and gfx.mouse_y <= preset_row_y + control_row_h
            if is_h then
                local tip_id = "dir_add_preset"
                if UI_STATE.tooltip_state.hover_id ~= tip_id then
                    UI_STATE.tooltip_state.hover_id = tip_id
                    UI_STATE.tooltip_state.start_time = reaper.time_precise()
                end
                UI_STATE.tooltip_state.text = T("ADD_NEW_PRESET")
            end
        end
    end
    
    -- --- ROW 3: INPUT & SAVE ---
    local min_input_h = S(30)
    local save_btn_space = is_right_layout and (S(30) + S(10)) or 0
    local input_draw_x = panel_x + padding
    
    local input_draw_y = preset_row_y + control_row_h + padding
    local input_h = math.max(min_input_h, (panel_y + panel_h) - input_draw_y - padding - save_btn_space)
    
    if not calc_only then
        local was_focused = director_state.input.focus
        
        -- Force stable "normal" font size for director panel, ignoring reader_mode
        local corr_font = F[cfg.t_corr_size]
        local base_sz = OTHER.FONT_SIZES.normal[cfg.t_corr_size]
        gfx.setfont(corr_font, cfg.p_font, S(base_sz or 18))
        
        ui_text_input("director", input_draw_x, input_draw_y, input_w, input_h, director_state.input, T("ENTER_RETAKE_TEXT"), input_queue, true, true, corr_font)
    
        -- Check for changes to highlight button
        local has_changes = false
        if director_state.last_marker_id then
            if director_state.input.text ~= director_state.original_text then 
                has_changes = true 
            end
        elseif director_state.input.text ~= "" then
            has_changes = true
        end

        local is_empty = (director_state.input.text == "")
        local save_col = has_changes and (director_state.last_marker_id and UI.C_BTN_UPDATE or UI.C_BTN_MEDIUM) or UI.C_BTN
        local save_label = director_state.last_marker_id and T("UPDATE") or T("SAVE")
        
        if director_state.last_marker_id and is_empty then
            save_label = T("DELETE")
            save_col = UI.C_BTN_ERROR
        end
        
        -- Position save button: vertical stack for Right mode, horizontal for Bottom mode
        local save_x = is_right_layout and input_draw_x or (input_draw_x + input_w + S(10))
        local save_y = is_right_layout and (input_draw_y + input_h + S(10)) or input_draw_y
        local save_h = is_right_layout and S(30) or input_h

        if is_right_layout then
            save_btn_w = input_w
        end

        local function save_director_changes()
            local txt = director_state.input.text
            if txt == "" and director_state.last_marker_id then
                push_undo(T("DELETE_RETAKE_UNDO"))
                reaper.DeleteProjectMarker(0, director_state.last_marker_id, false)
                ass_markers = capture_project_markers()
                update_regions_cache()
                
                -- Force table refresh
                table_data_cache.state_count = -1
                last_layout_state.state_count = -1
                prompter_drawer.marker_cache.count = -1
                
                director_state.last_marker_id = nil
                director_state.input.text = ""
                show_snackbar(T("RETAKE_HB_DELETED"), "error")
                return
            end
            if txt ~= "" then
                -- --- LEARNING (Mapping Update on Save) ---
                if #current_ass_actors == 1 then
                    local speaker = current_ass_actors[1]
                    local list, _ = get_actors_from_text(txt)
                    if #list > 0 then
                        -- Check if the first actor in prefix is in director_actors
                        local first_act = list[1]
                        local is_valid = false
                        for _, act in ipairs(director_actors) do
                            if act == first_act then is_valid = true break end
                        end
                        if is_valid then
                            -- Direct mapping: current speaker -> dubber
                            director_state.region_actor_to_dubber[speaker] = first_act
                            -- Sync all DUBBERS assignments into the mapping
                            UTILS.sync_dubbers_to_director(director_state.region_actor_to_dubber)
                        end
                    end
                end
                
                push_undo(save_label .. T("POST_RETAKE_ACTION_TXT"))
                if director_state.last_marker_id then
                    reaper.SetProjectMarker4(0, director_state.last_marker_id, false, cur_time, 0, txt, 0, 0)
                    director_state.pending_scroll_id = director_state.last_marker_id
                else
                    local new_idx = reaper.AddProjectMarker(0, false, cur_time, 0, txt, -1)
                    director_state.pending_scroll_id = new_idx
                end
                ass_markers = capture_project_markers()
                update_regions_cache()
                
                -- Force table refresh
                table_data_cache.state_count = -1
                last_layout_state.state_count = -1
                prompter_drawer.marker_cache.count = -1
                
                -- Update Recent Indices
                local mid = director_state.pending_scroll_id
                if mid then
                    local new_indices = {mid}
                    for _, old_mid in ipairs(director_state.recent_indices) do
                        if old_mid ~= mid then table.insert(new_indices, old_mid) end
                    end
                    director_state.recent_indices = new_indices
                end
                
                director_state.last_marker_id = nil
                director_state.input.text = ""
                -- Force auto-fill re-evaluation on next frame by invalidating the time cache
                director_state.last_time = -1
                director_state.last_ass_actor = nil
                
                -- Persist learning if we learned something
                save_project_data(UI_STATE.last_project_id)
                
                show_snackbar(T("SAVED"), "success")

                -- Adjust playhead/cursor position +150ms
                reaper.SetEditCurPos(cur_time + 0.15, true, false)
            end
        end
        
        gfx.setfont(F.std)
        if draw_actor_btn_inline(save_x, save_y, save_btn_w, save_h, save_label, save_col) then
            save_director_changes()
        end

        -- HOTKEY: Enter (Save/Update)
        if input_queue then
            local is_shift = (gfx.mouse_cap & 8 == 8)
            for _, char in ipairs(input_queue) do
                if char == 13 and not is_shift and was_focused then
                    save_director_changes()
                end
            end
        end
    end
    
    -- Return fixed height = actor viewport + presets row + input area
    local input_area_h = (preset_row_y + control_row_h + padding + input_h + padding + save_btn_space) - actor_area_bottom
    return (actor_area_bottom - panel_y) + input_area_h
end

function UTILS.delete_logic()
    -- Separate ASS lines and markers
    local selected_ass_entries = {}
    local selected_marker_indices = {}
    
    -- Collect selected ASS lines
    for p, l in ipairs(ass_lines) do
        if table_selection[l.index or p] then
            table.insert(selected_ass_entries, {line = l, pos = p})
        end
    end
    
    -- Collect selected markers (string indices like "M12")
    for idx in pairs(table_selection) do
        if type(idx) == "string" and idx:sub(1,1) == "M" then
            local markindex = tonumber(idx:sub(2))
            if markindex then
                table.insert(selected_marker_indices, markindex)
            end
        end
    end
    
    local total_deleted = 0
    
    -- Delete markers (Robust Method)
    if #selected_marker_indices > 0 then
        if #selected_ass_entries > 0 then
            push_undo(T("DELETING_RETAKES_AND_LINES"))
        else
            push_undo(T("DELETING_RETAKES"))
        end
        
        -- Build a lookup set of IDs to delete
        local markers_to_delete = {}
        for _, id in ipairs(selected_marker_indices) do markers_to_delete[id] = true end
        
        -- 1. Sync internal ass_markers table (Prevent resurrection by rebuild_regions)
        local new_ass_markers = {}
        for _, m in ipairs(ass_markers) do
            if not markers_to_delete[m.markindex] then
                table.insert(new_ass_markers, m)
            end
        end
        ass_markers = new_ass_markers
        
        -- 2. Delete from Project
        local i = reaper.CountProjectMarkers(0) - 1
        while i >= 0 do
            local _, isrgn, _, _, _, mark_id = reaper.EnumProjectMarkers3(0, i)
            if not isrgn and markers_to_delete[mark_id] then
                reaper.DeleteProjectMarkerByIndex(0, i)
                total_deleted = total_deleted + 1
            end
            i = i - 1
        end
    end
    
    -- Delete ASS lines
    if #selected_ass_entries > 0 then
        if #selected_marker_indices == 0 then
            push_undo(T("DELETING_LINES"))
        end
        -- Optimized removal: One pass O(N)
        local new_lines = {}
        local to_delete = {}
        for _, ent in ipairs(selected_ass_entries) do to_delete[ent.pos] = true end
        
        for p, l in ipairs(ass_lines) do
            if not to_delete[p] then
                table.insert(new_lines, l)
            else
                total_deleted = total_deleted + 1
            end
        end
        ass_lines = new_lines
        cleanup_actors()
        rebuild_regions()
        save_project_data(UI_STATE.last_project_id)
        reaper.MarkProjectDirty(0) -- SAVE ON CHANGE
    end
    
    if total_deleted > 0 then
        table_selection = {}
        last_selected_row = nil
        table_data_cache.state_count = -1
        last_layout_state.state_count = -1
        prompter_drawer.marker_cache.count = -1
        show_snackbar(T("REMOVED_TABLE_LINES_EX") .. total_deleted, "error")
    end
end

function UTILS.duplicate_logic(target_id)
    local original_pos = nil
    for p, l in ipairs(ass_lines) do
        if (l.index or p) == target_id then
            original_pos = p
            break
        end
    end

    if original_pos then
        local source = ass_lines[original_pos]
        push_undo(T("REPEAT_THE_LINE"))
        
        -- Create copy
        local new_replica = {}
        for k, v in pairs(source) do new_replica[k] = v end
        
        -- Generate new unique index
        local max_idx = 0
        for _, l in ipairs(ass_lines) do
            if type(l.index) == "number" and l.index > max_idx then
                max_idx = l.index
            end
        end
        new_replica.index = max_idx + 1
        
        -- Insert after original
        table.insert(ass_lines, original_pos + 1, new_replica)
        
        cleanup_actors()
        rebuild_regions()
        save_project_data(UI_STATE.last_project_id)
        reaper.MarkProjectDirty(0) -- SAVE ON CHANGE
        
        table_selection = {}
        table_selection[new_replica.index] = true
        table_data_cache.state_count = -1
        last_layout_state.state_count = -1
        show_snackbar(T("LINE_IS_SUCC_DUP"), "success")
        return true
    end
    return false
end

function DRAW_WINDOW.draw_editor_panel(panel_x, panel_y, panel_w, panel_h, input_queue, calc_only)
    gfx.setfont(F.std)
    if not calc_only then
        set_color(UI.C_BG)
        gfx.rect(panel_x, panel_y, panel_w, panel_h, 1)
    end
    
    local is_editor_right = (cfg.editor_layout == "right")
    local padding = S(10)
    local btn_h = S(24)

    -- --- AUTO-DETECT CURRENT STATE ---
    local cur_time = reaper.GetPlayState() > 0 and reaper.GetPlayPosition() or reaper.GetCursorPosition()
    
    local start_ts, end_ts = reaper.GetSet_LoopTimeRange(false, false, 0, 0, false)
    
    -- Find all regions at cur_time using existing utility
    local overlapping_lines = UTILS.get_ass_lines_at_time(cur_time, 0.001)
    local current_region = nil

    -- Filter out disabled regions
    local filtered_lines = {}
    for _, line in ipairs(overlapping_lines) do
        if line.enabled ~= false then
            table.insert(filtered_lines, line)
        end
    end
    overlapping_lines = filtered_lines
    
    -- --- АВТО-ПЕРЕМИКАННЯ НА НОВОСТВОРЕНІ РЕГІОНИ ---
    local state_count = reaper.GetProjectStateChangeCount(0)
    if not editor_state.last_state_count or state_count ~= editor_state.last_state_count then
        local last_undo = reaper.Undo_CanUndo2(0) or ""
        local _, num_markers, num_regions = reaper.CountProjectMarkers(0)
        local m_count = num_markers + num_regions
        
        -- Запускаємо логіку тільки якщо реально змінився Undo-стек або кількість маркерів
        if last_undo ~= editor_state.last_processed_undo or m_count ~= editor_state.last_marker_count then
            if last_undo == "Add region" then
                local max_id = -1
                local found_new_id = nil
                
                -- Шукаємо серед усіх маркерів той, що під курсором і має найбільший ID
                for i = 0, m_count - 1 do
                    local _, isr, pos, r_end, _, _, id = reaper.EnumProjectMarkers3(0, i)
                    if isr and cur_time >= (pos - 0.01) and cur_time <= (r_end + 0.01) then
                        if id > max_id then
                            max_id = id
                            found_new_id = id
                        end
                    end
                end

                if found_new_id then
                    editor_state.last_region_id = found_new_id
                    editor_state.needs_sync = true
                    
                    -- Миттєво оновлюємо дані плагіна
                    rebuild_regions()
                    overlapping_lines = UTILS.get_ass_lines_at_time(cur_time, 0.001)
                    local updated_filtered = {}
                    for _, line in ipairs(overlapping_lines) do
                        if line.enabled ~= false then table.insert(updated_filtered, line) end
                    end
                    overlapping_lines = updated_filtered
                end
            end
            -- Запам'ятовуємо стан, щоб не перевіряти повторно при кліках
            editor_state.last_processed_undo = last_undo
            editor_state.last_marker_count = m_count
        end
        editor_state.last_state_count = state_count
    end
    
    if #overlapping_lines > 0 then
        -- --- ВЗАЄМОДІЯ З REAPER (Ruler/Timeline Hit) ---
        -- Вибираємо конкретний регіон серед накладених через клік по його хедеру
        local mouse_state = 0
        if reaper.JS_Mouse_GetState then mouse_state = reaper.JS_Mouse_GetState(1) & 1 end

        if (mouse_state == 1 and not editor_state.mouse_was_down) then
            if reaper.BR_GetMouseCursorContext then 
                local context = reaper.BR_GetMouseCursorContext()
                if context == "ruler" or context == "timeline" then
                local mouse_time = reaper.BR_GetMouseCursorContext_Position()
                    if mouse_time and mouse_time >= 0 then
                        local best_hit = nil
                        local max_dist = 1000000
                        
                        -- Шукаємо серед накладених регіонів той, чий хедер найближче до кліку
                        for _, line in ipairs(overlapping_lines) do
                            local dist = math.abs(mouse_time - line.t1)
                            
                            -- Пріоритет зміни: додаємо мікро-штраф поточному регіону
                            local effective_dist = dist
                            if line.rgn_idx == editor_state.last_region_id then
                                effective_dist = dist + 0.001
                            end
                            
                            -- Якщо клік в межах 1 секунди від хедера будь-якого з накладених регіонів
                            if effective_dist < max_dist and dist < 1.0 then 
                                max_dist = effective_dist
                                best_hit = line
                            end
                        end

                        if best_hit and best_hit.rgn_idx ~= editor_state.last_region_id then
                            editor_state.last_region_id = best_hit.rgn_idx
                            editor_state.needs_sync = true
                        end
                    end
                end
            end
        end

        editor_state.mouse_was_down = (mouse_state == 1)
        -- Pick the best matching line
        local best_line = nil
        
        -- Priority 1: The one manually selected by user
        if editor_state.last_region_id ~= nil then
            for _, line in ipairs(overlapping_lines) do
                if line.rgn_idx == editor_state.last_region_id then
                    best_line = line
                    break
                end
            end
        end
        
        -- Priority 2: Fallback to the one that started latest (closest to current time)
        if not best_line then
            -- Якщо текст змінено, використовуємо збережені дані попереднього регіону (Sticky Focus)
            if editor_state.input.text ~= editor_state.original_text and not editor_state.needs_sync and editor_state.last_line_data then
                best_line = editor_state.last_line_data
            end
            
            -- Якщо все ще не знайшли (не dirty) — беремо те, що під курсором
            if not best_line then
                best_line = overlapping_lines[#overlapping_lines]
            end
        end
        
        if best_line then
            -- Note: markindex is returned by EnumProjectMarkers3, which is rgn_idx in ass_lines
            current_region = {
                idx = -1, -- We'll find real index if needed, but ID is enough for sync
                start_pos = best_line.t1, 
                end_pos = best_line.t2, 
                name = best_line.text, 
                id = best_line.rgn_idx, 
                col = 0, -- Not used for logic
                actor = best_line.actor or ""
            }
            
            -- SYNC Logic: Check if we need to update the editor content
            local needs_sync = (editor_state.last_region_id ~= current_region.id) or 
                               editor_state.needs_sync
            
            if needs_sync then
                editor_state.needs_sync = false -- Reset flag
                editor_state.last_region_id = current_region.id
                editor_state.last_line_data = best_line -- Запам'ятовуємо дані для sticky-режиму
                editor_state.input.text = current_region.name
                editor_state.original_text = current_region.name
                editor_state.current_actor = current_region.actor
                editor_state.input.cursor = #current_region.name
                editor_state.input.anchor = #current_region.name
                editor_state.input.history = nil -- Очищаємо історію при зміні регіону
                ai_modal.show = false
                if cfg.editor_auto_scroll then
                    editor_state.scroll_to_actor = current_region.actor
                end
            end
        end
    end
    
    if not current_region then
        -- Очищаємо інпут ТІЛЬКИ якщо текст НЕ змінено
        if editor_state.input.text == editor_state.original_text then
            if editor_state.last_region_id ~= nil then
                editor_state.input.text = ""
                editor_state.original_text = ""
                editor_state.current_actor = ""
                editor_state.input.focus = false
                editor_state.input.history = nil -- Очищаємо історію
            end
            editor_state.last_region_id = nil
            editor_state.last_line_data = nil
        end
    end

    local is_editing = (current_region ~= nil)
    local is_creating = (not is_editing and ((end_ts > start_ts) and cur_time >= start_ts and cur_time <= end_ts))
    local is_disabled = (not is_editing and not is_creating)
    
    local opt_btn_w = S(30)
    local opt_x = panel_x + panel_w - padding - opt_btn_w
    local opt_draw_y = panel_y + (is_editor_right and S(2) or padding)
    local is_opt_hover = false
    if not calc_only then
        is_opt_hover = UI_STATE.window_focused and
                       (gfx.mouse_x >= opt_x and gfx.mouse_x <= opt_x + opt_btn_w and
                        gfx.mouse_y >= opt_draw_y and gfx.mouse_y <= opt_draw_y + btn_h)
    end

    local function draw_actor_btn_inline(x, y, w, h, text, bg_col, stripe_col, suppress_hover)
        local hover = UI_STATE.window_focused and (gfx.mouse_x >= x and gfx.mouse_x <= x + w and gfx.mouse_y >= y and gfx.mouse_y <= y + h) and not suppress_hover
        local effective_bg = hover and UI.C_BTN_H or (bg_col or UI.C_BTN)
        set_color(effective_bg)
        gfx.rect(x, y, w, h, 1)
        
        if stripe_col then
            set_color(stripe_col)
            local sw = S(1)
            gfx.rect(x, y + h - sw, w, sw, 1)
        end
        
        set_color(UI.C_TXT)
        
        local str_w, str_h = gfx.measurestr(text)
        gfx.x = x + (w - str_w) / 2
        gfx.y = y + (h - str_h) / 2
        gfx.drawstr(text)
        if hover and is_mouse_clicked() then return true end
        return false
    end

    -- Clipped button: renders the button but crops it to [clip_y_top, clip_y_bot]
    local function draw_actor_btn_clipped(x, y, w, h, text, bg_col, clip_y_top, clip_y_bot, stripe_col)
        local vis_y1 = math.max(y, clip_y_top)
        local vis_y2 = math.min(y + h, clip_y_bot)
        if vis_y1 >= vis_y2 then return false end -- fully outside
        
        local is_fully_visible = (y >= clip_y_top and y + h <= clip_y_bot)
        if is_fully_visible then
            return draw_actor_btn_inline(x, y, w, h, text, bg_col, stripe_col, is_opt_hover)
        end
        
        local buf = OTHER.BUF.DIRECTOR -- Reuse same buffer
        gfx.setimgdim(buf, w, h)
        local prev_dest = gfx.dest
        gfx.dest = buf
        
        local hover = UI_STATE.window_focused and not is_opt_hover and
            (gfx.mouse_x >= x and gfx.mouse_x <= x + w and
             gfx.mouse_y >= vis_y1 and gfx.mouse_y <= vis_y2)
        local effective_bg = hover and UI.C_BTN_H or (bg_col or UI.C_BTN)
        set_color(effective_bg)
        gfx.rect(0, 0, w, h, 1)
        
        if stripe_col then
            set_color(stripe_col)
            local sw = S(1)
            gfx.rect(0, h - sw, w, sw, 1)
        end
        
        set_color(UI.C_TXT)

        local sw, sh = gfx.measurestr(text)
        gfx.x = (w - sw) / 2
        gfx.y = (h - sh) / 2
        gfx.drawstr(text)
        
        gfx.dest = prev_dest
        local src_y = vis_y1 - y
        local slice_h = vis_y2 - vis_y1
        gfx.blit(buf, 1, 0, 0, src_y, w, slice_h, x, vis_y1, w, slice_h)
        
        if hover and not director_resize_drag and is_mouse_clicked() then return true end
        return false
    end

    -- Standard button for other UI elements in this panel
    local function draw_btn_clipped(x, y, w, h, text, bg_col, clip_y_top, clip_y_bot)
        local vis_y1 = math.max(y, clip_y_top)
        local vis_y2 = math.min(y + h, clip_y_bot)
        if vis_y1 >= vis_y2 then return false end
        if y >= clip_y_top and y + h <= clip_y_bot then
            return draw_actor_btn_inline(x, y, w, h, text, bg_col, is_opt_hover)
        end
        local buf = OTHER.BUF.DIRECTOR
        gfx.setimgdim(buf, w, h)
        local prev_dest = gfx.dest
        gfx.dest = buf
        local hover = UI_STATE.window_focused and not is_opt_hover and (gfx.mouse_x >= x and gfx.mouse_x <= x+w and gfx.mouse_y >= vis_y1 and gfx.mouse_y <= vis_y2)
        local effective_bg = hover and UI.C_BTN_H or (bg_col or UI.C_BTN)
        set_color(effective_bg)
        gfx.rect(0, 0, w, h, 1)
        
        set_color(UI.C_TXT)
        local sw, sh = gfx.measurestr(text)
        gfx.x, gfx.y = (w-sw)/2, (h-sh)/2
        gfx.drawstr(text)
        gfx.dest = prev_dest
        gfx.blit(buf, 1, 0, 0, vis_y1-y, w, vis_y2-vis_y1, x, vis_y1, w, vis_y2-vis_y1)
        if hover and not director_resize_drag and is_mouse_clicked() then return true end
        return false
    end

    -- --- ROW 1: ACTORS ---
    local x = padding
    local y = is_editor_right and S(2) or padding
    
    gfx.setfont(F.std)
    if not calc_only then
        set_color(UI.C_BG)
        gfx.rect(panel_x, panel_y, panel_w, panel_h, 1)
        set_color(UI.C_MEDIUM_GREY)
        if is_editor_right then
            gfx.line(panel_x, panel_y, panel_x, panel_y + panel_h)
        else
            gfx.rect(panel_x, panel_y, panel_w, 2, 1)
        end
    end
    
    local draw_x = panel_x + x
    local draw_y = panel_y + y
    local _, current_actors_set = get_actors_from_text(editor_state.input.text)
    local save_btn_w = S(100)
    local input_w = is_editor_right and (panel_w - padding*2) or (panel_w - padding*2 - save_btn_w - S(10))
    local limit_x = opt_x - S(5)

    local function draw_options_menu()
        if not calc_only and draw_actor_btn_inline(opt_x, opt_draw_y, opt_btn_w, btn_h, "≡", UI.C_ACCENT_N) then
            local layout_label = is_editor_right and T("DOCK_BOTTOM") or T("DOCK_RIGHT")
            
            local alpha_mark = (cfg.editor_actor_sort == "alpha" or not cfg.editor_actor_sort) and "• " or ""
            local count_mark = (cfg.editor_actor_sort == "count") and "• " or ""
            local recent_mark = (cfg.editor_actor_sort == "recent") and "• " or ""
            local fast_jump_mark = cfg.editor_fast_jump and "• " or ""
            local auto_scroll_mark = cfg.editor_auto_scroll and "• " or ""
            local show_color_mark = cfg.editor_show_actor_color and "• " or ""
            
            local menu_str = "|>" .. T("SORTING_ACTORS") .. "|" .. alpha_mark .. T("SORTING_ACTORS_AB") .. "|" .. count_mark .. T("SORTING_ACTORS_NL") .. "|<" .. recent_mark .. T("SORTING_ACTORS_LS") .. "|" .. fast_jump_mark .. T("QUICK_JUMP") .. "|" .. auto_scroll_mark .. T("AUTO_SCROLL_TO_ACTOR") .. "|" .. show_color_mark .. T("DISPLAY_ACTOR_COLOR") .. "||" .. T("DELETE_ALL_HIDDEN_COMMENTS") .. "||" .. layout_label .. "|" .. T("CLOSE_WINDOW")
            
            gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
            local ret = gfx.showmenu(menu_str)
            if ret == 1 then
                cfg.editor_actor_sort = "alpha"
                editor_state.sort_cache.valid = false
                save_settings()
            elseif ret == 2 then
                cfg.editor_actor_sort = "count"
                editor_state.sort_cache.valid = false
                save_settings()
            elseif ret == 3 then
                cfg.editor_actor_sort = "recent"
                editor_state.sort_cache.valid = false
                save_settings()
            elseif ret == 4 then
                cfg.editor_fast_jump = not cfg.editor_fast_jump
                save_settings()
            elseif ret == 5 then
                cfg.editor_auto_scroll = not cfg.editor_auto_scroll
                save_settings()
            elseif ret == 6 then
                cfg.editor_show_actor_color = not cfg.editor_show_actor_color
                save_settings()
            elseif ret == 7 then
                -- Delete all hidden comments from all lines
                local count = 0
                push_undo(T("DELETE_ALL_HIDDEN_COMMENTS"))
                for _, line in ipairs(ass_lines or {}) do
                    local old = line.text or ""
                    line.text = old:gsub("%s*\n\n{{+.-}}+", ""):gsub("%s*{{+.-}}+", "")
                    if line.text ~= old then
                        count = count + 1
                    end
                end

                editor_state.last_region_id = -1

                if count > 0 then
                    UI_STATE._markers_is_dirty = true
                    cleanup_actors()
                    rebuild_regions()
                    show_snackbar(T("HIDDEN_COMMENTS_REMOVE_1") .. count .. T("HIDDEN_COMMENTS_REMOVE_2"), "success")
                else
                    show_snackbar(T("NO_HIDDEN_COMMENTS"), "info")
                end
            elseif ret == 8 then
                if cfg.editor_layout == "right" then cfg.editor_layout = "bottom" else cfg.editor_layout = "right" end
                save_settings()
                last_layout_state.state_count = -1
            elseif ret == 9 then
                cfg.editor_mode = false
                save_settings()
            end
        end
    end

    -- Sourcing actors from ass_actors
    local actors_list = {}
    local current_actor_count = 0
    for act, _ in pairs(ass_actors) do
        if act and act ~= "" then 
            table.insert(actors_list, act) 
            current_actor_count = current_actor_count + 1
        end
    end
    
    local sort_mode = cfg.editor_actor_sort or "alpha"
    
    -- Check cache validity
    if editor_state.sort_cache.valid and 
       editor_state.sort_cache.method == sort_mode and 
       #editor_state.sort_cache.list == current_actor_count then
        actors_list = editor_state.sort_cache.list
    else
        if sort_mode == "alpha" then
            table.sort(actors_list)
        elseif sort_mode == "recent" then
            local last_clicks = editor_state.actor_last_clicked or {}
            table.sort(actors_list, function(a, b)
                local ta = last_clicks[a] or 0
                local tb = last_clicks[b] or 0
                if ta ~= tb then return ta > tb end
                return a < b
            end)
        else
            -- Count replicas
            local counts = {}
            for _, line in ipairs(ass_lines) do
                if line.actor and line.actor ~= "" then
                    counts[line.actor] = (counts[line.actor] or 0) + 1
                end
            end
            table.sort(actors_list, function(a, b)
                local ca = counts[a] or 0
                local cb = counts[b] or 0
                if ca ~= cb then return ca > cb end
                return a < b
            end)
        end
        editor_state.sort_cache.list = actors_list
        editor_state.sort_cache.method = sort_mode
        editor_state.sort_cache.valid = true
    end

    -- --- DYNAMIC LAYOUT CALCULATION ---
    local act_row_h = btn_h + S(5)
    local max_actor_h_limit = is_editor_right and (4 * act_row_h + S(2)) or (3 * act_row_h + S(10))

    -- 1. Calculate how much height actors ACTUALLY need (simulating wrap)
    local cur_x = padding
    local cur_y = 0
    for _, actor in ipairs(actors_list) do
        local w, _ = gfx.measurestr(actor)
        local b_w = w + S(20)
        if panel_x + cur_x + b_w > limit_x then
            cur_x = padding
            cur_y = cur_y + act_row_h
        end
        cur_x = cur_x + b_w + S(5)
    end
    
    -- Add wrap check for "+" button in height calculation
    local plus_btn_w = S(24)
    if panel_x + cur_x + plus_btn_w > limit_x then
        cur_x = padding
        cur_y = cur_y + act_row_h
    end
    
    local start_y = is_editor_right and S(8) or S(16)
    local needed_actor_h = start_y + cur_y + btn_h
    
    -- 2. Determine Actor Area Height (clamped to 3 rows)
    local control_row_h = S(28)
    local actor_area_h = math.min(needed_actor_h, max_actor_h_limit)
    local actor_area_bottom = panel_y + actor_area_h
    
    -- 3. Input Row takes ALL remaining space
    local input_row_h = panel_h - actor_area_h - control_row_h - padding*3
    if input_row_h < S(40) then input_row_h = S(40) end -- Safety minimum
    
    local input_area_h = control_row_h + input_row_h + padding*3
    if not calc_only and UI_STATE.window_focused and gfx.mouse_wheel ~= 0 and
       gfx.mouse_x >= panel_x and gfx.mouse_x <= panel_x + panel_w and
       gfx.mouse_y >= panel_y and gfx.mouse_y <= actor_area_bottom then
        local step = btn_h + S(5)
        editor_state.wheel_accum = (editor_state.wheel_accum or 0) + gfx.mouse_wheel
        local wheel_sensitivity = 80
        local new_scroll = editor_state.target_scroll_y or 0
        while editor_state.wheel_accum >= wheel_sensitivity do
            new_scroll = math.floor((new_scroll - 1) / step) * step
            if new_scroll < 0 then new_scroll = 0 end
            editor_state.wheel_accum = editor_state.wheel_accum - wheel_sensitivity
        end
        while editor_state.wheel_accum <= -wheel_sensitivity do
            new_scroll = math.ceil((new_scroll + 1) / step) * step
            editor_state.wheel_accum = editor_state.wheel_accum + wheel_sensitivity
        end
        editor_state.target_scroll_y = new_scroll
        local cached_max = editor_state.cached_max_scroll or 0
        editor_state.target_scroll_y = math.max(0, math.min(cached_max, editor_state.target_scroll_y))
        gfx.mouse_wheel = 0
    end
    editor_state.scroll_y = editor_state.target_scroll_y or 0

    for i, actor in ipairs(actors_list) do
        local label = actor
        local w, _ = gfx.measurestr(label)
        local btn_w = w + S(20)
        
        if draw_x + btn_w > limit_x then
            x = padding
            y = y + btn_h + S(5)
            draw_x = panel_x + x
            draw_y = panel_y + y
        end
        
        if editor_state.scroll_to_actor == actor then
            local cur_scroll = editor_state.scroll_y or 0
            local is_visible = (y >= cur_scroll) and (y + btn_h <= cur_scroll + actor_area_h)
            
            if not is_visible then
                if y < cur_scroll then
                    -- Actor is above the visible area, scroll to its top
                    editor_state.target_scroll_y = y - (is_editor_right and S(2) or padding)
                else
                    -- Actor is below the visible area, scroll to its bottom
                    editor_state.target_scroll_y = y + btn_h - actor_area_h + S(5)
                end
                
                -- Clamp target scroll
                if editor_state.target_scroll_y < 0 then editor_state.target_scroll_y = 0 end
                local cached_max = editor_state.cached_max_scroll or 0
                if editor_state.target_scroll_y > cached_max then editor_state.target_scroll_y = cached_max end
            end
            editor_state.scroll_to_actor = nil
        end
        
        if not calc_only then
            local is_active = (actor == editor_state.current_actor)
            local act_col = nil
            if cfg.editor_show_actor_color then
                local native = get_actor_color(actor)
                if native and native ~= 0 then
                    local r, g, b = reaper.ColorFromNative(native & 0xFFFFFF)
                    act_col = {r/255, g/255, b/255}
                end
            end
            
            local bg_col = is_active and UI.C_ACCENT_G or UI.C_BTN
            local stripe_col = (not is_active) and act_col or nil
            
            local sdraw_y = draw_y - math.floor(editor_state.scroll_y or 0)
            
            if sdraw_y + btn_h > panel_y and sdraw_y < actor_area_bottom then
                local clicked = draw_actor_btn_clipped(draw_x, sdraw_y, btn_w, btn_h, label, bg_col, panel_y, actor_area_bottom, stripe_col)

                if clicked then
                    if not is_opt_hover then
                        editor_state.current_actor = actor
                        
                        -- Update recent click tracking
                        if not editor_state.actor_last_clicked then editor_state.actor_last_clicked = {} end
                        editor_state.actor_last_clicked[actor] = reaper.time_precise()
                        if cfg.editor_actor_sort == "recent" then
                            editor_state.sort_cache.valid = false
                        end
                        
                        -- Immediate sync if editing
                        if current_region and current_region.id then
                            local new_col = get_actor_color(actor)
                            -- Use existing color if get_actor_color returns 0 (default/not found)
                            if not new_col or new_col == 0 then new_col = current_region.col end

                            -- Update REAPER marker immediately (including color!)
                            push_undo(T("CHANGE_OF_ACTOR"))
                            reaper.SetProjectMarker3(0, current_region.id, true, current_region.start_pos, current_region.end_pos, current_region.name, new_col)
                            current_region.col = new_col -- Update local state for immediate feedback
                            
                            for _, line in ipairs(ass_lines) do
                                if line.rgn_idx == current_region.id then
                                    line.actor = actor
                                    break
                                end
                            end

                            UI_STATE._markers_is_dirty = true
                            save_project_data()
                            reaper.MarkProjectDirty(0)
                        end
                    end
                end
                
                -- Right-click Context Menu
                local vis_y1 = math.max(sdraw_y, panel_y)
                local vis_y2 = math.min(sdraw_y + btn_h, actor_area_bottom)
                local hover = UI_STATE.window_focused and not is_opt_hover and
                    (gfx.mouse_x >= draw_x and gfx.mouse_x <= draw_x + btn_w and
                     gfx.mouse_y >= vis_y1 and gfx.mouse_y <= vis_y2)
                     
                if hover and is_right_mouse_clicked() then
                    gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
                    local act = actor
                    local replicas_count = 0
                    for _, l in ipairs(ass_lines) do
                        if l.actor == act then
                            replicas_count = replicas_count + 1
                        end
                    end
                    local is_visible = (ass_actors[act] ~= false)
                    local vis_opt_str = is_visible and T("HIDE_ACTORS_LINES") or T("SHOW_ACTORS_LINES")
                    
                    local ret = gfx.showmenu(T("N_OF_LINES") .. replicas_count .. "||" .. vis_opt_str .. "|" .. T("CHANGE_COLOR") .. "|" .. T("CHANGE_ACTOR_NAME") .. "||" .. T("DELETE_ACTOR"))
                    if ret == 2 then
                        local new_state = not is_visible
                        ass_actors[act] = new_state
                        for _, l in ipairs(ass_lines) do
                            if l.actor == act then l.enabled = new_state end
                        end
                        push_undo(T("TAB_FILE_ACTOR_VISIBILITY") .. act)
                        UI_STATE._markers_is_dirty = true
                        rebuild_regions()
                        save_project_data()
                        reaper.MarkProjectDirty(0)
                    elseif ret == 3 then
                        local current_native = get_actor_color(act)
                        if current_native == 0 then current_native = 2500134 end
                        local retval, color = reaper.GR_SelectColor(reaper.GetMainHwnd(), current_native)
                        if retval > 0 then
                            local final_color = color | 0x1000000
                            ASS.actor_colors[act] = final_color
                            OTHER.update_global_actor_color(act, final_color)
                            
                            cfg.random_color_actors = true
                            rebuild_regions()
                            save_project_data()
                            reaper.MarkProjectDirty(0)
                        end
                    elseif ret == 4 then
                        local ok, new_name = reaper.GetUserInputs(T("TAB_FILE_C_ACTOR_NAME"), 1, T("TAB_FILE_C_ACTOR_NAME_EXT"), act)
                        if ok then
                            new_name = new_name:gsub("\239\184\143", ""):match("^%s*(.-)%s*$")
                            if new_name ~= "" then
                                push_undo(T("TAB_FILE_C_ACTOR_NAME"))
                                for _, l in ipairs(ass_lines) do
                                    if l.actor == act then l.actor = new_name end
                                end
                                local state = ass_actors[act]
                                ass_actors[act] = nil
                                if state ~= nil then ass_actors[new_name] = state else ass_actors[new_name] = true end
                                
                                local current_color = get_actor_color(act)
                                if current_color and current_color ~= 0 then ASS.actor_colors[new_name] = current_color end
                                ASS.actor_colors[act] = nil
                                
                                if editor_state.current_actor == act then
                                    editor_state.current_actor = new_name
                                end
                                
                                cleanup_actors()
                                editor_state.sort_cache.valid = false
                                UI_STATE._markers_is_dirty = true
                                rebuild_regions()
                                save_project_data()
                                reaper.MarkProjectDirty(0)
                            end
                        end
                    elseif ret == 5 then
                        local confirm = reaper.MB(T("DELETE_ACTOR") .. " '" .. act .. "' " .. T("AND_ALL_HIS_LINES"), T("CONFIRMATION"), 4)
                        if confirm == 6 then
                            push_undo(T("REMOVING_AN_ACTOR") .. act)
                            ass_actors[act] = nil
                            ASS.actor_colors[act] = nil
                            local new_lines = {}
                            for _, line in ipairs(ass_lines) do
                                if line.actor ~= act then table.insert(new_lines, line) end
                            end
                            ass_lines = new_lines
                            
                            if editor_state.current_actor == act then
                                editor_state.current_actor = ""
                            end
                            
                            cleanup_actors()
                            editor_state.sort_cache.valid = false
                            UI_STATE._markers_is_dirty = true
                            rebuild_regions()
                            save_project_data()
                            reaper.MarkProjectDirty(0)
                        end
                    end
                    UI_STATE.mouse_handled = true
                end
            end
        end
        x = x + btn_w + S(5)
        draw_x = panel_x + x
    end
    
    -- 5. Draw "+" button
    local plus_w = S(24)
    if draw_x + plus_w > limit_x then
        x = padding
        y = y + btn_h + S(5)
        draw_x = panel_x + x
        draw_y = panel_y + y
    end
    
    if not calc_only then
        local sdraw_y_plus = draw_y - math.floor(editor_state.scroll_y or 0)
        if sdraw_y_plus + btn_h > panel_y and sdraw_y_plus < actor_area_bottom then
            if draw_btn_clipped(draw_x, sdraw_y_plus, plus_w, btn_h, "+", UI.C_ACCENT_N, panel_y, actor_area_bottom) then
                if not is_opt_hover then
                    local ok, name = reaper.GetUserInputs(T("ADD_ACTOR_EDITOR"), 1, T("ACTORS_NAME"), "")
                    if ok then
                        -- Remove variation selector and trim spaces
                        name = name:gsub("\239\184\143", ""):match("^%s*(.-)%s*$")
                        if name ~= "" then
                            if not ass_actors[name] then
                                ass_actors[name] = true
                            end
                            editor_state.current_actor = name
                            
                            -- Immediate sync if editing an existing region
                            if current_region and current_region.id then
                                local new_col = get_actor_color(name)
                                if not new_col or new_col == 0 then new_col = current_region.col end
                                
                                push_undo(T("ADD_AND_EDIT_ACTOR"))
                                reaper.SetProjectMarker3(0, current_region.id, true, current_region.start_pos, current_region.end_pos, current_region.name, new_col)
                                current_region.col = new_col
                                
                                for _, line in ipairs(ass_lines) do
                                    if line.rgn_idx == current_region.id then
                                        line.actor = name
                                        break
                                    end
                                end
                            end

                            UI_STATE._markers_is_dirty = true
                        end
                    end
                end
            end
        end
    end

    if not calc_only then
        local total_actors_h = y + btn_h + S(20)
        local viewport_h = actor_area_bottom - panel_y
        local max_scroll = math.max(0, total_actors_h - viewport_h)
        editor_state.cached_max_scroll = max_scroll
        editor_state.target_scroll_y = math.max(0, math.min(max_scroll, editor_state.target_scroll_y or 0))
        editor_state.scroll_y = math.max(0, math.min(max_scroll, editor_state.scroll_y or 0))
        if max_scroll > 0 then
            local bar_h = math.max(S(20), (viewport_h / total_actors_h) * viewport_h)
            local bar_y = panel_y + ((editor_state.scroll_y or 0) / total_actors_h) * viewport_h
            set_color(UI.C_TXT_DIM)
            gfx.rect(panel_x + panel_w - S(4), bar_y, S(3), bar_h, 1)
        end
    end

    draw_options_menu()
    
    -- Separator Line
    if not calc_only then
        set_color(UI.C_MEDIUM_GREY)
        gfx.line(panel_x, actor_area_bottom, panel_x + panel_w, actor_area_bottom)
    end

    -- --- ROW 2 & 3: CONTROLS & INPUT ---
    local control_draw_y = actor_area_bottom + padding
    local input_draw_y = control_draw_y + control_row_h + padding
    local input_draw_x = panel_x + padding
    local full_w = panel_w - padding*2
    if not calc_only then
        local function save_editor_changes()
            local txt = editor_state.input.text
            
            if is_editing and current_region then
                if txt == "" then
                    push_undo(T("DELETING_LINES"))
                    local to_delete_id = current_region.id
                    local new_lines = {}
                    for _, line in ipairs(ass_lines or {}) do
                        if line.rgn_idx ~= to_delete_id then
                            table.insert(new_lines, line)
                        end
                    end
                    ass_lines = new_lines
                    editor_state.last_region_id = -1
                    editor_state.last_state_count = -1
                    UI_STATE._markers_is_dirty = true
                    editor_state.needs_sync = true
                    cleanup_actors()
                    rebuild_regions()
                    show_snackbar(T("LINE_HB_DELETED"), "error")
                    return
                end
                if not current_region.id then
                    show_snackbar(T("LINE_HB_DELETED_ERROR"), "error")
                    return
                end
                -- Region name is ONLY text, no actor brackets
                push_undo(T("REGION_UPDATE"))
                reaper.SetProjectMarker3(0, current_region.id, true, current_region.start_pos, current_region.end_pos, txt, current_region.col)
                
                -- Sync with ass_lines
                for _, line in ipairs(ass_lines) do
                    if line.rgn_idx == current_region.id then
                        line.actor = editor_state.current_actor
                        line.text = txt
                        break
                    end
                end

                editor_state.original_text = txt
                show_snackbar(T("REGION_UPDATED"), "success")
            elseif is_creating then
                push_undo(T("REGION_CREATION"))
                local actor = editor_state.current_actor
                if not actor or actor == "" then
                    actor = "REAPER"
                    editor_state.current_actor = "REAPER"
                end
                local col = get_actor_color(actor)
                -- If color is 0 (not found/black), use -1 for REAPER's default region color
                if not col or col == 0 then col = -1 end
                local r_idx = reaper.AddProjectMarker2(0, true, start_ts, end_ts, txt, -1, col)
                local _, _, _, _, _, r_id = reaper.EnumProjectMarkers3(0, r_idx)
                
                -- Ensure new region is also in ass_lines for immediate selection/editing
                table.insert(ass_lines, {
                    t1 = start_ts,
                    t2 = end_ts,
                    text = txt,
                    actor = actor,
                    rgn_idx = r_id
                })

                show_snackbar(T("REGION_CREATED"), "success")
            end

            if is_editing or is_creating then 
                cleanup_actors()
                rebuild_regions()
                ACHIEVEMENTS.add_stat("ach_28_count", 1)

                if cfg.editor_fast_jump then
                    local base_pos = is_editing and current_region.start_pos or start_ts
                    local next_r_start = math.huge
                    local retval, num_markers, num_regions = reaper.CountProjectMarkers(0)
                    for i = 0, num_markers + num_regions - 1 do
                        local _, isr, pos, r_end, _, _, _ = reaper.EnumProjectMarkers3(0, i)
                        if isr and pos > base_pos + 0.001 then
                            if pos < next_r_start then
                                next_r_start = pos
                            end
                        end
                    end
                    if next_r_start < math.huge then
                        editor_state.needs_sync = true
                        editor_state.last_region_id = -1
                        reaper.SetEditCurPos(next_r_start, true, false)
                        -- editor_state.input.focus = true
                    end
                end

                UI_STATE._markers_is_dirty = true
            end
        end

        -- 1. CONTROL ROW (Formatting + Save)
        local fmt_btn_w = S(28)
        local fmt_gap = S(4)
        local fmt_btns = {"B", "I", "U", "S", "{/}", "{x}"}
        local fmt_tags = {"b", "i", "u", "s", "c", "x"}
        local fmt_tips = {
            T("FMT_BOLD"),
            T("FMT_ITALIC"),
            T("FMT_UNDERLINE"),
            T("FMT_CROSSLINE"),
            T("FMT_COMMENT"),
            T("FMT_REMOVE_HIDDEN")
        }
        
        local function apply_fmt(tag)
            if is_disabled then return end
            local inp = editor_state.input
            local s_idx = math.min(inp.cursor, inp.anchor)
            local e_idx = math.max(inp.cursor, inp.anchor)
            local txt = inp.text
            
            if tag == "c" then
                if s_idx ~= e_idx then
                    -- Wrap selection in braces
                    local selected = txt:sub(s_idx + 1, e_idx)
                    local new_txt = txt:sub(1, s_idx) .. "{" .. selected .. "}" .. txt:sub(e_idx + 1)
                    inp.text = new_txt
                    inp.cursor = s_idx + 1 + #selected + 1
                    inp.anchor = inp.cursor
                else
                    -- Insert empty braces and place cursor inside
                    local new_txt = txt:sub(1, s_idx) .. "{}" .. txt:sub(s_idx + 1)
                    inp.text = new_txt
                    inp.cursor = s_idx + 1
                    inp.anchor = inp.cursor
                end
            elseif tag == "x" then
                -- Remove {{}} block (supports 2 or more braces) and preceding whitespace/newlines
                local new_txt = txt:gsub("%s*\n\n{{+.-}}+", "")
                if new_txt == txt then
                    -- Fallback: try removing without double newline if the first pattern didn't match
                    new_txt = txt:gsub("%s*{{+.-}}+", "")
                end
                
                if new_txt ~= txt then
                    inp.text = new_txt
                    -- Adjust cursor if it was inside or after the removed block
                    if inp.cursor > #new_txt then inp.cursor = #new_txt end
                    if inp.anchor > #new_txt then inp.anchor = #new_txt end
                else
                    show_snackbar(T("NO_HIDDEN_COMMENTS_TO_DELETE"), "warning")
                end
            else
                if s_idx ~= e_idx then
                    -- Wrap selection in both tags
                    local selected = txt:sub(s_idx + 1, e_idx)
                    local open_tag = "{\\" .. tag .. "1}"
                    local close_tag = "{\\" .. tag .. "0}"
                    local new_txt = txt:sub(1, s_idx) .. open_tag .. selected .. close_tag .. txt:sub(e_idx + 1)
                    inp.text = new_txt
                    inp.cursor = s_idx + #open_tag + #selected + #close_tag
                    inp.anchor = inp.cursor
                else
                    -- Insert both tags and place cursor between them
                    local open_tag = "{\\" .. tag .. "1}"
                    local close_tag = "{\\" .. tag .. "0}"
                    local new_txt = txt:sub(1, s_idx) .. open_tag .. close_tag .. txt:sub(s_idx + 1)
                    inp.text = new_txt
                    inp.cursor = s_idx + #open_tag
                    inp.anchor = inp.cursor
                end
            end
            inp.focus = true
            inp.needs_focus_nudge = 3 -- Nudge focus for several frames
            inp.suppress_auto_scroll_until = 0 -- Force scroll to cursor if needed
            record_field_history(inp)
            UI_STATE.mouse_handled = true
        end

        local function apply_custom_fmt(val)
            if is_disabled then return end
            local inp = editor_state.input
            local s_idx = math.min(inp.cursor, inp.anchor)
            local e_idx = math.max(inp.cursor, inp.anchor)
            local txt = inp.text
            
            local p1, p2 = val:match("^(.-)%.%.%.(.-)$")
            
            if p1 and p2 then
                local selected = txt:sub(s_idx + 1, e_idx)
                local new_txt = txt:sub(1, s_idx) .. p1 .. selected .. p2 .. txt:sub(e_idx + 1)
                inp.text = new_txt
                if s_idx ~= e_idx then
                    inp.cursor = s_idx + #p1 + #selected + #p2
                else
                    inp.cursor = s_idx + #p1
                end
                inp.anchor = inp.cursor
            else
                local new_txt = txt:sub(1, s_idx) .. val .. txt:sub(e_idx + 1)
                inp.text = new_txt
                inp.cursor = s_idx + #val
                inp.anchor = inp.cursor
            end
            inp.focus = true
            inp.needs_focus_nudge = 3
            inp.suppress_auto_scroll_until = 0
            record_field_history(inp)
            UI_STATE.mouse_handled = true
        end

        local save_btn_w = is_editor_right and S(80) or S(110)
        local left_w = full_w - save_btn_w - padding

        -- Calculate AI Button position first
        local provider_name = (cfg.ai_provider == "mistral") and "Mistral" or (cfg.ai_provider == "groq" and "Groq" or "Gemini")
        local ai_btn_text = T("ASK_NAME") .. provider_name
        local ai_btn_w = cfg.lng == "ua" and S(130) or S(90)
        local ai_btn_x = input_draw_x + left_w - ai_btn_w
        local ai_b_col = is_disabled and UI.C_TAB_INA or UI.C_ROW

        for i, label in ipairs(fmt_btns) do
            local bx = input_draw_x + (i-1) * (fmt_btn_w + fmt_gap)
            
            -- Only draw if it does not overlap with the AI button
            if bx + fmt_btn_w <= ai_btn_x then
                local b_col = is_disabled and UI.C_TAB_INA or UI.C_ROW
                
                -- Apply styling for preview
                if label == "B" then gfx.setfont(F.bld)
                elseif label == "I" then gfx.setfont(F.ital)
                else gfx.setfont(F.std) end

                if draw_actor_btn_inline(bx, control_draw_y, fmt_btn_w, control_row_h, label, b_col) then
                    apply_fmt(fmt_tags[i])
                end
                
                local is_hover = UI_STATE.window_focused and 
                                 (gfx.mouse_x >= bx and gfx.mouse_x <= bx + fmt_btn_w and 
                                  gfx.mouse_y >= control_draw_y and gfx.mouse_y <= control_draw_y + control_row_h)
                if is_hover then 
                    local tip_id = "fmt_" .. i
                    if UI_STATE.tooltip_state.hover_id ~= tip_id then
                        UI_STATE.tooltip_state.hover_id = tip_id
                        UI_STATE.tooltip_state.start_time = reaper.time_precise()
                    end
                    UI_STATE.tooltip_state.text = fmt_tips[i]
                end

                -- Draw extra lines for U and S
                local str_w, str_h = gfx.measurestr(label)
                local tx = bx + (fmt_btn_w - str_w) / 2
                local ty = control_draw_y + (control_row_h - str_h) / 2
                local s1 = S(1)
                local s2 = S(2)

                if label == "U" then
                    set_color(UI.C_TXT)
                    gfx.line(tx, ty + str_h - s1, tx + str_w, ty + str_h - s1)
                elseif label == "S" then
                    set_color(UI.C_TXT)
                    gfx.line(tx - s2, ty + str_h/2 - s2, tx + str_w + s2, ty + str_h/2 - s2)
                end
            end
        end

        -- Separator and Presets
        local last_x = input_draw_x + (#fmt_btns) * (fmt_btn_w + fmt_gap)
        if last_x + S(10) <= ai_btn_x then
            -- Vertical Separator
            set_color(UI.C_MEDIUM_GREY, 0.5)
            gfx.rect(last_x + S(3), control_draw_y + S(4), S(1), control_row_h - S(8), 1)
            last_x = last_x + S(10)
            
            -- Custom Presets
            local preset_btn_w = S(36)
            for i, p in ipairs(cfg.fmt_presets) do
                if last_x + preset_btn_w <= ai_btn_x then
                    local b_col = is_disabled and UI.C_TAB_INA or UI.C_ROW
                    gfx.setfont(F.std)
                    if draw_actor_btn_inline(last_x, control_draw_y, preset_btn_w, control_row_h, p.label, b_col) then
                        UI_STATE.mouse_handled = true
                        apply_custom_fmt(p.val)
                    end
                    
                    local is_h = UI_STATE.window_focused and 
                                 (gfx.mouse_x >= last_x and gfx.mouse_x <= last_x + preset_btn_w and 
                                  gfx.mouse_y >= control_draw_y and gfx.mouse_y <= control_draw_y + control_row_h)
                    
                    if is_h then
                        local tip_id = "preset_" .. i
                        if UI_STATE.tooltip_state.hover_id ~= tip_id then
                            UI_STATE.tooltip_state.hover_id = tip_id
                            UI_STATE.tooltip_state.start_time = reaper.time_precise()
                        end
                        UI_STATE.tooltip_state.text = p.val
                        
                        if is_mouse_clicked(2) then
                            UI_STATE.mouse_handled = true
                            gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
                            local move_up_tag = (i > 1) and "" or "#"
                            local move_down_tag = (i < #cfg.fmt_presets) and "" or "#"
                            local sel = gfx.showmenu(T("EDIT_DELETE_PRESET_MENU") .. move_up_tag .. T("PRESET_MOVE_LEFT_MENU") .. move_down_tag .. T("PRESET_MOVE_RIGHT_MENU"))
                            
                            if sel == 1 then show_panel_preset_dialog("editor", i)
                            elseif sel == 2 then 
                                if reaper.MB(T("DELETE_PRESET_MB_1") .. (p.label or "") .. T("DELETE_PRESET_MB_2"), T("DELETION_THE_PRESET"), 1) == 1 then
                                    table.remove(cfg.fmt_presets, i)
                                    save_settings()
                                end
                            elseif sel == 3 then
                                local p = table.remove(cfg.fmt_presets, i)
                                table.insert(cfg.fmt_presets, i - 1, p)
                                save_settings()
                            elseif sel == 4 then
                                local p = table.remove(cfg.fmt_presets, i)
                                table.insert(cfg.fmt_presets, i + 1, p)
                                save_settings()
                            end
                        end
                    end
                    
                    last_x = last_x + preset_btn_w + fmt_gap
                end
            end
            
            -- Plus Button
            if last_x + fmt_btn_w <= ai_btn_x then
                local b_col = is_disabled and UI.C_TAB_INA or UI.C_ACCENT_SN
                gfx.setfont(F.std)
                if draw_actor_btn_inline(last_x, control_draw_y, fmt_btn_w, control_row_h, "+", b_col) then
                    UI_STATE.mouse_handled = true
                    show_panel_preset_dialog("editor")
                end
                
                local is_h = UI_STATE.window_focused and 
                             (gfx.mouse_x >= last_x and gfx.mouse_x <= last_x + fmt_btn_w and 
                              gfx.mouse_y >= control_draw_y and gfx.mouse_y <= control_draw_y + control_row_h)
                if is_h then
                    local tip_id = "preset_add"
                    if UI_STATE.tooltip_state.hover_id ~= tip_id then
                        UI_STATE.tooltip_state.hover_id = tip_id
                        UI_STATE.tooltip_state.start_time = reaper.time_precise()
                    end
                    UI_STATE.tooltip_state.text = T("ADD_NEW_PRESET")
                end
            end
        end
        
        gfx.setfont(F.std)

        if ai_btn_x >= input_draw_x then
            if draw_actor_btn_inline(ai_btn_x, control_draw_y, ai_btn_w, control_row_h, ai_btn_text, ai_b_col) and not is_disabled then
                trigger_ai_modal(editor_state.input, ai_btn_x + ai_btn_w - S(30), control_draw_y + control_row_h, provider_name)
            end

            local ai_hover = (gfx.mouse_x >= ai_btn_x and gfx.mouse_x <= ai_btn_x + ai_btn_w and gfx.mouse_y >= control_draw_y and gfx.mouse_y <= control_draw_y + control_row_h)
            if ai_hover and is_right_mouse_clicked() then
                local menu_str = (cfg.ai_provider == "gemini" and "!" or "") .. "Gemini AI|" .. 
                                 (cfg.ai_provider == "mistral" and "!" or "") .. "Mistral AI|" ..
                                 (cfg.ai_provider == "groq" and "!" or "") .. "Groq AI"
                gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
                local ret = gfx.showmenu(menu_str)
                if ret == 1 then
                    cfg.ai_provider = "gemini"
                    save_settings()
                elseif ret == 2 then
                    cfg.ai_provider = "mistral"
                    save_settings()
                elseif ret == 3 then
                    cfg.ai_provider = "groq"
                    save_settings()
                end
                UI_STATE.mouse_handled = true
            end
        end

        -- 2. INPUT & ACTION AREA (2 Columns)
        local was_focused = editor_state.input.focus
        local corr_font = F[cfg.t_corr_size]
        local base_sz = OTHER.FONT_SIZES.normal[cfg.t_corr_size]
        gfx.setfont(corr_font, cfg.p_font, S(base_sz or 18))
        
        if ai_modal.show and ai_modal.target_state == editor_state.input then
            if DRAW_WINDOW.draw_ai_modal(true) then
                editor_state.input.focus = true
            end
        end
        
        local has_changes = (editor_state.input.text ~= editor_state.original_text)
        local is_empty = (editor_state.input.text == "")
        local save_col = is_disabled and UI.C_TAB_INA or (is_creating and UI.C_ACCENT_G or (has_changes and UI.C_BTN_UPDATE or UI.C_BTN))
        local save_label = is_editing and T("UPDATE") or (is_disabled and T("NOT_IN_REGION") or T("CREATE"))

        if is_editing and is_empty then
            save_label = T("DELETE")
            save_col = UI.C_BTN_ERROR
        end

        -- Column 1: Row 2 (Input)
        ui_text_input("editor_panel", input_draw_x, input_draw_y, left_w, input_row_h, editor_state.input, is_disabled and T("SELECT_AND_GO_REGION") or T("EDITION_THE_LINE"), input_queue, true, false, corr_font)

        -- Column 2: Large Action Button (Spans both rows)
        local save_x = input_draw_x + left_w + padding
        local save_y = control_draw_y
        local save_h = (input_draw_y + input_row_h) - control_draw_y

        gfx.setfont(F.std)
        if draw_actor_btn_inline(save_x, save_y, save_btn_w, save_h, save_label, save_col) then
            if not is_disabled then save_editor_changes() end
        end

        if input_queue and not is_disabled then
            local is_shift = (gfx.mouse_cap & 8 == 8)
            for _, char in ipairs(input_queue) do
                if char == 13 and not is_shift and was_focused then
                    save_editor_changes()
                end
            end
        end

        -- --- RIGHT CLICK ON PANEL CONTEXT MENU ---
        if is_mouse_clicked(2) and editor_state.last_line_data and not UI_STATE.mouse_handled then
            local is_hover_panel = gfx.mouse_x >= panel_x and gfx.mouse_x <= panel_x + panel_w and
                                   gfx.mouse_y >= panel_y and gfx.mouse_y <= panel_y + panel_h
            
            if is_hover_panel then
                gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
                local menu_str = T("UNDO_T_EDITOR_CHANGE") .. "|" .. T("REPEAT_THE_LINE") .. "||" .. T("DELETE_LINE")
                local ret = gfx.showmenu(menu_str)
                local c_index = ass_lines[editor_state.last_line_data._i].index
                if ret == 1 then
                    editor_state.last_region_id = -1
                elseif ret == 2 then
                    UTILS.duplicate_logic(c_index)
                elseif ret == 3 then
                    table_selection = {}
                    table_selection[c_index] = true
                    UTILS.delete_logic()
                end
                UI_STATE.mouse_handled = true
            end
        end
    end
    
    return (actor_area_bottom - panel_y) + input_area_h
end

function OTHER.AI_generate_prompt(is_dub)
    if not ass_lines or #ass_lines == 0 then 
        show_snackbar(T("AI_GENERATE_NO_LINES"), "error")
        return 
    end
    
    local selected_lines = {}
    -- Determine which items to include based on table selection
    for i, line in ipairs(ass_lines) do
        local sel_idx = line.index or i
        if table_selection[sel_idx] then
            local id = sel_idx
            local start_t = format_timestamp(line.t1 or 0)
            local end_t = format_timestamp(line.t2 or 0)
            local actor = line.actor or "Unknown"
            -- Replace newlines with spaces to keep each line in the prompt as a single unit
            local text = (line.text or ""):gsub("\n", " "):gsub("\r", "")
            
            table.insert(selected_lines, string.format("id:%s,start:%s,end:%s,actor:%s,text:%s", id, start_t, end_t, actor, text))
        end
    end
    
    if #selected_lines == 0 then
        show_snackbar(T("AI_GENERATE_SELECT_LINES"), "warning")
        return
    end

    local prompt = ""

    if is_dub then
        prompt = cfg.lng == "ua" and [[Ти — професійний перекладач та лінійний продюсер дубляжу. Твоє завдання: адаптувати наданий текст **{{language}}** мовою для максимально точного візуального та змістовного потрапляння в персонажа.
1. **Ліпсінк (Артикуляція)**: Переклад має максимально відповідати довжині оригіналу та ритміці губ (кількість складів має бути приблизно рівною оригіналу). Звертай особливу увагу на відкриті голосні в кінці фраз та вибухові приголосні, щоб артикуляція виглядала природно. Особливо критичні білабіальні (М, Б, П) — вони мають збігатися з оригіналом за можливості.
2. **Логіка та Контекст**: Пріоритет — жива розмовна мова. Уникай буквалізму. Переклад має передавати той самий емоційний підтекст, що і в оригіналі, зберігаючи логічний зв'язок між репліками. Зберігай соціолект персонажа: якщо герой говорить грубо, просторічно або навпаки — офіційно, відтворюй це.
3. **Сталість звертань та термінології**: Витримуй єдиний стиль звертання (Ти/Ви) між конкретними героями протягом усього фрагмента. Зберігай єдині переклади власних назв, термінів та прізвиськ протягом усього фрагмента.
4. **Формат даних**: Поверни результат виключно у тому ж форматі, який надано в оригіналі (id:...,start:...,end:...,actor:...,text:...). Не змінюй ID, таймкоди чи імена персонажів.
5. **Контекстуальна цілісність**: Забезпеч логічний зв'язок між репліками. Враховуй, що попередня фраза (id:1) визначає тон та зміст наступної (id:2).
6. **Суворі обмеження**: Не додавай жодних вступних чи підсумкових фраз.
