function OTHER.AI_insert_result()
    local clipboard = get_clipboard()
    if not clipboard or clipboard == "" then
        show_snackbar(T("CLIPBOARD_IS_EMPTY"), "error")
        return
    end

    if not ass_lines or #ass_lines == 0 then
        show_snackbar(T("AI_GENERATE_NO_LINES"), "error")
        return
    end

    -- Create a quick lookup map for lines by their ID
    local id_to_line = {}
    for i, line in ipairs(ass_lines) do
        local id = tostring(line.index or i)
        id_to_line[id] = line
    end

    local update_count = 0
    push_undo(T("AI_INSERT_RESULT"))

    -- Parse lines from clipboard
    for line_text in clipboard:gmatch("[^\r\n]+") do
        -- Pattern matches 'id:<id>' and 'text:<text>'
        -- We use a more flexible pattern to handle possible variations in AI output
        local id = line_text:match("id:(%w+)")
        local translated = line_text:match("text:(.*)$")

        if id and translated and id_to_line[id] then
            local target = id_to_line[id]
            local original_old = target.text
            
            -- Strip potential whitespace from translated text
            translated = translated:match("^%s*(.-)%s*$")
            
            -- Format: <translated text>\n\n{{ <original old text> }}
            target.text = string.format("%s\n\n{{ %s }}", translated, original_old)
            update_count = update_count + 1
        end
    end

    if update_count > 0 then
        UI_STATE._markers_is_dirty = true

        -- Sync changes
        cleanup_actors()
        rebuild_regions()
        save_project_data(UI_STATE.last_project_id)
        reaper.MarkProjectDirty(0)

        editor_state.last_region_id = -1
        table_data_cache.state_count = -1 -- Force table refresh

        ACHIEVEMENTS.add_stat("ach_29_count", 1)
        ACHIEVEMENTS.add_stat("ach_29_import_count", update_count)

        show_snackbar(string.format(T("D_LINES_UPDATED"), update_count), "success")
    else
        show_snackbar(T("AI_NO_ID_FOUND"), "warning")
    end
end

OTHER.last_progress_check_time = 0

function OTHER.update_whisper_progress()
    if not OTHER.whisper_state or not OTHER.whisper_state.active then return end
    
    local now = os.clock()
    if now - OTHER.last_progress_check_time < 0.3 then return end -- check every 0.3 seconds
    OTHER.last_progress_check_time = now
    
    local state = OTHER.whisper_state
    local f = io.open(state.out_file, "r")
    if not f then return end
    
    local content = f:read("*a")
    f:close()
    
    local last_end_time = 0
    local last_text = ""
    
    -- Match lines like: [00:00.000 --> 00:05.000] text
    -- We take the last printed progress line in the output stream as the current progress.
    for m1, s1, ms1, m2, s2, ms2, txt in content:gmatch("%[(%d+):(%d+)[%.%:](%d+)%s*%-%->%s*(%d+):(%d+)[%.%:](%d+)%]%s*(.-)[\r\n]") do
        last_end_time = tonumber(m2) * 60 + tonumber(s2) + tonumber(ms2) / 1000
        last_text = txt
    end
    
    if last_end_time > 0 and state.effective_dur > 0 then
        local progress = last_end_time / state.effective_dur
        if progress > 1.0 then progress = 1.0 end
        state.progress = progress
        state.text = last_text:gsub("^%s*(.-)%s*$", "%1")
    else
        -- No timestamps yet, look for the last non-empty line of the file (initialization messages)
        local last_line = ""
        for line in content:gmatch("[^\r\n]+") do
            line = line:gsub("^%s*(.-)%s*$", "%1")
            if line ~= "" then
                last_line = line
            end
        end
        if last_line ~= "" then
            state.text = last_line
        end
    end
end

function OTHER.cancel_whisper_task()
    if not OTHER.whisper_state or not OTHER.whisper_state.active then return end
    
    local state = OTHER.whisper_state
    state.active = false
    
    -- Kill the underlying process
    local pid_str = nil
    if state.pid_file then
        local f = io.open(state.pid_file, "r")
        if f then
            pid_str = f:read("*a"):gsub("%s+", "")
            f:close()
        end
    end
    
    if pid_str and pid_str ~= "" then
        if reaper.GetOS():match("Win") then
            -- taskkill /F /T kills the process AND all its children (e.g. ffmpeg)
            -- reaper.ExecProcess runs this completely silently (no console window flashing)
            reaper.ExecProcess("taskkill /F /T /PID " .. pid_str, 1000)
        else
            -- Kill children first (e.g. ffmpeg spawned by whisper), then the process itself
            reaper.ExecProcess("pkill -KILL -P " .. pid_str, 1000)
            reaper.ExecProcess("kill -9 " .. pid_str, 1000)
        end
    end
    
    -- Remove the task from global_async_pool
    for i = #global_async_pool, 1, -1 do
        local task = global_async_pool[i]
        if task.id == state.id then
            table.remove(global_async_pool, i)
            break
        end
    end
    
    -- Clean up files
    if state.pid_file  then os.remove(state.pid_file)  end
    if state.ps1_file  then os.remove(state.ps1_file)  end
    if state.out_file  then os.remove(state.out_file)  end
    if state.done_file then os.remove(state.done_file) end
    if state.temp_srt  then os.remove(state.temp_srt)  end
    
    show_snackbar(T("WHISPER_CANCELED_ACT"), "info")
end

function OTHER.import_whisper_srt(file_path, timeline_offset, play_rate)
    local f = io.open(file_path, "r")
    if not f then return end
    
    local content = fix_encoding(f:read("*all"))
    f:close()
    content = content:gsub("\r\n", "\n")
    if not content:match("\n\n$") then
        content = content .. "\n\n"
    end
    
    if not ass_lines then ass_lines = {} end
    if not ass_actors then ass_actors = {} end
    
    push_undo("Whisper Speech-to-Text")
    
    local line_idx_counter = get_next_line_index()
    local default_actor = "Whisper"
    ass_actors[default_actor] = true
    
    local function parse_srt_timestamp(str)
        local h, m, s, ms = str:match("(%d+):(%d+):(%d+)[%,%.](%d+)")
        if not h then return 0 end
        return (tonumber(h) * 3600) + (tonumber(m) * 60) + tonumber(s) + (tonumber(ms) / 1000)
    end
    
    for s_start, s_end, text in content:gmatch("(%d+:%d+:%d+[,.]%d+)%s*%-%->%s*(%d+:%d+:%d+[,.]%d+)%s*\n(.-)\n%s*\n") do
        local t1 = parse_srt_timestamp(s_start)
        local t2 = parse_srt_timestamp(s_end)
        
        -- Adjust for play rate and shift by timeline_offset
        local adjusted_t1 = timeline_offset + (t1 / play_rate)
        local adjusted_t2 = timeline_offset + (t2 / play_rate)
        
        local clean_text = text:gsub("\r", ""):gsub("\n", " "):match("^%s*(.-)%s*$")
        if clean_text ~= "" then
            local actor = default_actor
            local speaker_prefix, rest_text = clean_text:match("^%[(SPEAKER_%d+)%]%:%s*(.*)$")
            if speaker_prefix then
                local num = tonumber(speaker_prefix:match("SPEAKER_(%d+)"))
                actor = num and string.format("Whisper-%02d", num + 1) or "Whisper"
                clean_text = rest_text:match("^%s*(.-)%s*$")
            end
            
            ass_actors[actor] = true

            local found = false
            for _, existing in ipairs(ass_lines) do
                if math.abs(existing.t1 - adjusted_t1) < 0.001 and
                   math.abs(existing.t2 - adjusted_t2) < 0.001 and
                   existing.text == clean_text then
                    found = true
                    if not existing.enabled then
                        existing.enabled = true
                    end
                    break
                end
            end
            
            if not found then
                table.insert(ass_lines, {
                    t1 = adjusted_t1,
                    t2 = adjusted_t2,
                    text = clean_text,
                    actor = actor,
                    enabled = true,
                    index = line_idx_counter
                })
                line_idx_counter = line_idx_counter + 1
            end
        end
    end

    rebuild_regions()
end

--- Speech to Text: перевіряє встановлення Whisper і запускає транскрипцію вибраного Item
function OTHER.speech_to_text_from_item()
    if OTHER.whisper_state and OTHER.whisper_state.active then
        show_snackbar(T("WHISPER_ALREADY_RUN"), "warning")
        return
    end

    -- Перевірка збереженості проєкту
    local _, proj_fn = reaper.EnumProjects(-1)
    if not proj_fn or proj_fn == "" then
        show_snackbar(T("WHISPER_PLEASE_SAVE_PROJ"), "error")
        return
    end

    -- 1. Перевірка вибраного Item
    local sel_count = reaper.CountSelectedMediaItems(0)
    if sel_count == 0 then
        show_snackbar(T("WHISPER_SELECT_ONE_ITEM"), "error")
        return
    end
    if sel_count > 1 then
        show_snackbar(T("WHISPER_SELECT_ONLY_ONE_ITEM"), "warning")
        return
    end

    local item = reaper.GetSelectedMediaItem(0, 0)
    local take = reaper.GetActiveTake(item)
    if not take or reaper.TakeIsMIDI(take) then
        show_snackbar(T("WHISPER_ITEM_NO_AUDIO"), "error")
        return
    end

    local source = reaper.GetMediaItemTake_Source(take)
    if not source then
        show_snackbar(T("WHISPER_ITEM_AUDIO_NO_SOURCE"), "error")
        return
    end

    local source_file = reaper.GetMediaSourceFileName(source, "")
    if not source_file or source_file == "" then
        show_snackbar(T("WHISPER_ITEM_AUDIO_NO_FOUND"), "error")
        return
    end

    -- 2. Параметри Item (враховуємо підрізання та зсув)
    --    D_STARTOFFS — зсув у вихідному файлі (секунди)
    --    D_PLAYRATE  — швидкість відтворення
    --    D_LENGTH    — видима довжина item на таймлайні
    local item_len   = reaper.GetMediaItemInfo_Value(item, "D_LENGTH")
    local start_offs = reaper.GetMediaItemTakeInfo_Value(take, "D_STARTOFFS")
    local play_rate  = reaper.GetMediaItemTakeInfo_Value(take, "D_PLAYRATE")
    if not play_rate or play_rate == 0 then play_rate = 1.0 end

    -- Фактичні секунди у вихідному файлі
    local effective_start = start_offs           -- старт у source-файлі
    local effective_dur   = item_len * play_rate -- тривалість у source-файлі

    -- 3. Обираємо мову оригіналу (gfx menu)
    local menu_str = T("WHISPER_SELECT_LNG")
    gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
    local ret = gfx.showmenu(menu_str)
    if ret <= 0 then
        return
    end

    local lang_map = {
        [2] = "auto",
        [3] = "uk",
        [4] = "en",
        [5] = "ja",
        [6] = "pl",
        [7] = "de",
        [8] = "fr",
        [9] = "es",
        [10] = "it",
        [11] = "pt",
        [12] = "zh",
        [13] = "ko"
    }
    
    local selected_lang = lang_map[ret]
    if not selected_lang then return end

    -- 4. Перевіряємо чи встановлений Whisper (без відкриття вікна консолі)
    local is_win = reaper.GetOS():match("Win")
    local py_exe
    if is_win then
        py_exe = UTILS.get_win_py_exe(
            (OTHER.rec_state and OTHER.rec_state.python and OTHER.rec_state.python.executable) or "py -3"
        )
    else
        py_exe = (OTHER.rec_state and OTHER.rec_state.python and OTHER.rec_state.python.executable) or "python3"
        -- For macOS/Linux, if the command is a simple relative executable (no slashes),
        -- prepend standard PATH to find Homebrew or other user Python installations.
        if not py_exe:find("/") then
            py_exe = "PATH=/usr/local/bin:/usr/bin:/bin:/usr/sbin:/sbin:/opt/homebrew/bin " .. py_exe
        end
    end

    local check_cmd
    if is_win then
        -- На Windows ExecProcess запускає процес повністю приховано (без вікна cmd.exe)
        -- Використовуємо find_spec для миттєвої перевірки за 50мс (запобігає таймауту у 3 секунди)
        -- та ASCII-коди символів chr(), щоб уникнути будь-яких вкладених лапок на Windows.
        check_cmd = py_exe .. ' -c "import importlib.util; print(chr(79)+chr(75) if importlib.util.find_spec(chr(119)+chr(104)+chr(105)+chr(115)+chr(112)+chr(101)+chr(114)+chr(120)) else chr(101)+chr(114)+chr(114))"'
    else
        -- На macOS/Linux запускаємо python напряму без обгортки /bin/sh -c, оскільки
        -- reaper.ExecProcess на macOS не вміє парсити екрановані подвійні лапки всередині інших лапок.
        -- Використовуємо простий рядок з одинарними лапками всередині подвійних.
        local clean_py = py_exe
        if clean_py:find("PATH=") then
            clean_py = clean_py:match(" ([^ ]+)$") or "python3"
        end
        check_cmd = clean_py .. ' -c "import sys; sys.stderr = sys.stdout; import importlib.util; print(\'OK\' if importlib.util.find_spec(\'whisperx\') else \'not found\')"'
    end

    local r1 = reaper.ExecProcess(check_cmd, 3000)
    local check_out = r1 or ""
    local whisper_installed = (check_out:find("OK") ~= nil)

    -- 5. Whisper не встановлений -- пропонуємо користувачеві встановити
    if not whisper_installed then
        local msg = T("WHISPER_INSTALL_MSG")
        local res = reaper.MB(msg, "Install", 4) -- 4 = Yes/No
        if res ~= 6 then -- 6 = Yes
            show_snackbar(T("WHISPER_INSTALL_CANCELED"), "info")
            return
        end

        local src_info = debug.getinfo(1, 'S').source
        local script_dir = src_info:match([[^@?(.*[\/])]]) or ""
        local py_script = script_dir .. "stats/subass_whisper.py"

        local install_cmd
        if is_win then
            local py_exe_win = UTILS.get_win_py_exe(
                (OTHER.rec_state and OTHER.rec_state.python and OTHER.rec_state.python.executable) or "py -3"
            )
            install_cmd = py_exe_win .. ' "' .. py_script .. '" --install-check'
        else
            local py_exe_unix = (OTHER.rec_state and OTHER.rec_state.python and OTHER.rec_state.python.executable) or "python3"
            install_cmd = 'PATH=/usr/local/bin:/usr/bin:/bin:/usr/sbin:/sbin:/opt/homebrew/bin:$PATH ' .. py_exe_unix .. ' "' .. py_script .. '" --install-check'
        end

        run_async_command(install_cmd, nil, true, nil, true)
        show_snackbar(T("WHISPER_INSTALL_START"), "info")
        return
    end

    local item_pos = reaper.GetMediaItemInfo_Value(item, "D_POSITION")
    local src_info = debug.getinfo(1, 'S').source
    local script_dir = src_info:match([[^@?(.*[\/])]]) or ""
    local py_script = script_dir .. "stats/subass_whisper.py"
    
    local source_proj, filename = reaper.EnumProjects(-1)
    local id_fname = (not filename or filename == "") and "unsaved" or filename
    local source_project_id = source_proj and (tostring(source_proj) .. "_" .. id_fname) or "none"
    
    local id = tostring(os.clock()):gsub("%.", "") .. "_" .. math.random(1000, 9999)
    local path = reaper.GetResourcePath() .. "/Scripts/"
    local temp_srt = path .. "whisper_temp_" .. id .. ".srt"
    local out_file = path .. "async_out_" .. id .. ".tmp"
    local done_file = path .. "async_done_" .. id .. ".marker"
    local pid_file = path .. "async_pid_" .. id .. ".tmp"
    
    local py_script_arg = py_script
    local source_arg = source_file
    local srt_arg = temp_srt
    if is_win then
        py_script_arg = py_script_arg:gsub("/", "\\")
        source_arg = source_arg:gsub("/", "\\")
        srt_arg = srt_arg:gsub("/", "\\")
    end
    
    local stt_args = ""
    if cfg.hf_token and cfg.hf_token ~= "" then
        stt_args = stt_args .. " --hf-token " .. '"' .. cfg.hf_token .. '"'
    end
    if cfg.stt_diarization then
        stt_args = stt_args .. " --diarize"
    end
    if cfg.stt_split_segments then
        stt_args = stt_args .. string.format(" --split-segments --max-duration %.2f --max-gap %.2f", cfg.stt_max_duration or 4.0, cfg.stt_max_gap or 0.4)
    end
    if cfg.stt_add_offset then
        stt_args = stt_args .. string.format(" --offset-start %.2f --offset-end %.2f", cfg.stt_offset_start or 0.1, cfg.stt_offset_end or 0.1)
    end

    local cmd
    local ps1_file
    if is_win then
        -- On Windows: create a .ps1 wrapper that records PowerShell's own $PID into pid_file,
        -- then runs Python synchronously as a child process.
        -- run_async_command wraps this in its own bat as usual — no changes needed there.
        -- On cancel: taskkill /F /T /PID <ps_pid> kills PowerShell + python + any children (e.g. ffmpeg).
        local pid_file_win = pid_file:gsub("/", "\\")
        ps1_file = (path .. "whisper_wrap_" .. id .. ".ps1"):gsub("/", "\\")
        
        -- Build the PowerShell call expression for py_exe
        -- py_exe can be: "py -3", "python", or a quoted full path like "\"C:\...\python.exe\""
        local py_exe_raw = py_exe:gsub('^"', ''):gsub('"$', '')  -- strip outer quotes
        local ps_invoke
        if py_exe_raw:find("[/\\]") then
            -- Full path — re-quote with double quotes for PowerShell
            ps_invoke = '& "' .. py_exe_raw .. '"'
        else
            -- Short form like "py -3" or "python" — no extra quoting needed
            ps_invoke = '& ' .. py_exe_raw
        end
        
        local f_ps1 = io.open(ps1_file, "wb")
        if f_ps1 then
            -- Write UTF-8 BOM so PowerShell parses non-ASCII characters correctly
            f_ps1:write(string.char(0xEF, 0xBB, 0xBF))
            -- Write PowerShell's own PID; python runs as its child, so taskkill /T covers all
            f_ps1:write('$PID | Out-File -FilePath "' .. pid_file_win .. '" -Encoding ASCII\r\n')
            f_ps1:write('$env:PYTHONUTF8 = "1"\r\n')
            f_ps1:write(string.format(
                '%s -u "%s" "%s" "%s" --lang %s --start %f --duration %f%s\r\n',
                ps_invoke, py_script_arg, source_arg, srt_arg,
                selected_lang, effective_start, effective_dur, stt_args
            ))
            f_ps1:close()
        end
        
        -- Pass the ps1 invocation as cmd; run_async_command will wrap it in a bat normally
        cmd = 'powershell -NoProfile -ExecutionPolicy Bypass -File "' .. ps1_file .. '"'
    else
        cmd = string.format('( PATH=/usr/local/bin:/usr/bin:/bin:/usr/sbin:/sbin:/opt/homebrew/bin:$PATH %s -u "%s" "%s" "%s" --lang %s --start %f --duration %f%s & echo $!>"%s" ; wait )',
            py_exe, py_script_arg, source_arg, srt_arg, selected_lang, effective_start, effective_dur, stt_args, pid_file)
    end
    
    local proj_basename = "Unsaved"
    if filename and filename ~= "" then
        proj_basename = filename:match("[^/\\]+$") or filename
        proj_basename = proj_basename:gsub("%.rpp$", ""):gsub("%.RPP$", "")
    end
    
    OTHER.whisper_state = {
        active = true,
        progress = 0.0,
        text = "Init...",
        id = id,
        project_name = proj_basename,
        out_file = out_file,
        done_file = done_file,
        pid_file = pid_file,  -- used on both platforms for kill
        ps1_file = is_win and ps1_file or nil,
        temp_srt = temp_srt,
        effective_dur = effective_dur,
        item_pos = item_pos,
        play_rate = play_rate
    }
    
    run_async_command(cmd, function(output)
        if not OTHER.whisper_state or OTHER.whisper_state.id ~= id or not OTHER.whisper_state.active then
            return
        end
        
        OTHER.whisper_state.active = false
        
        if is_win and ps1_file then os.remove(ps1_file) end

        if output and (output:find("Warning:") or output:find("Error:") or output:find("CRITICAL")) then
            reaper.ShowConsoleMsg("--- WhisperX Pipeline Messages ---\n" .. tostring(output) .. "\n----------------------------------\n")
        end
        
        local f = io.open(temp_srt, "r")
        if not f then
            show_snackbar(T("WHISPER_ERROR_1"), "error")
            reaper.ClearConsole()
            reaper.ShowConsoleMsg("--- WHISPER ERROR LOG ---\n" .. tostring(output) .. "\n-------------------------\n")
            if pid_file then os.remove(pid_file) end
            if out_file then os.remove(out_file) end
            if done_file then os.remove(done_file) end
            if temp_srt then os.remove(temp_srt) end
            return
        end
        f:close()
        
        local active_proj = reaper.EnumProjects(-1)
        if active_proj == source_proj then
            -- Still on the same project — import immediately
            OTHER.import_whisper_srt(temp_srt, item_pos, play_rate)
            show_snackbar(T("WHISPER_SUCC_DONE_1"), "success")
            if pid_file then os.remove(pid_file) end
            if out_file then os.remove(out_file) end
            if done_file then os.remove(done_file) end
            if temp_srt then os.remove(temp_srt) end
        else
            -- User switched tabs — keep the SRT and wait for them to come back
            OTHER.pending_whisper = {
                temp_srt   = temp_srt,
                item_pos   = item_pos,
                play_rate  = play_rate,
                proj       = source_proj,
                proj_name  = proj_basename,
                pid_file   = pid_file,
                out_file   = out_file,
                done_file  = done_file,
            }
            show_snackbar(T("WHISPER_SUCC_DONE_2") .. proj_basename .. T("WHISPER_SUCC_DONE_3"), "info", 8)
        end
    end, true, nil, false, out_file, done_file)
    
    show_snackbar(T("WHISPER_RUN_START"), "info")
end

function DRAW_TABS.draw_table(input_queue)
    local show_actor = UI_STATE.ass_file_loaded
    local start_y = S(65)
    OTHER.col_vis_menu.handled = false -- Reset per frame
    
    local h_header = cfg.reader_mode and 0 or S(25)
    local row_h = cfg.reader_mode and S(80) or S(24)

    -- DO NOT modify F.std/F.bld globally
    -- Table Specific Font Logic from shared structure
    local tr_set = cfg.reader_mode and OTHER.FONT_SIZES.reader or OTHER.FONT_SIZES.normal
    local use_sz = tr_set[cfg.t_r_size] or 16
    
    gfx.setfont(F[cfg.t_r_size], cfg.p_font, S(use_sz))

    -- --- FILTER INPUT ---
    gfx.setfont(F.std) -- Use the (possibly locally scaled) standard font for global elements
    local filter_y = S(35)
    local filter_h = S(25)
    -- LAYOUT INITIALIZATION (Calculate avail sizes first)
    local w_panel = (cfg.editor_mode and cfg.w_editor or cfg.w_director) or S(300)
    local is_panel_right = (cfg.editor_mode and cfg.editor_layout == "right") or (cfg.director_mode and cfg.director_layout == "right")
    
    if (cfg.director_mode or cfg.editor_mode) and is_panel_right then 
        -- Prevent overlapping the main list (leaving at least S(150) for the left side)
        local max_allowed_w = math.max(S(120), gfx.w - S(150))
        if w_panel > max_allowed_w then
            w_panel = max_allowed_w
            if not director_resize_drag then 
                if cfg.editor_mode then cfg.w_editor = w_panel else cfg.w_director = w_panel end
            end
        end
    end
    
    local h_panel = ((cfg.director_mode or cfg.editor_mode) and not is_panel_right) and (cfg.editor_mode and (cfg.h_editor or dynamic_editor_h) or (cfg.h_director or dynamic_director_h) or S(150)) or 0
    if (cfg.director_mode or cfg.editor_mode) and is_panel_right then h_panel = 0 end
    
    local avail_w = gfx.w
    if (cfg.director_mode or cfg.editor_mode) and is_panel_right then avail_w = gfx.w - w_panel end

    local filter_x = S(10)
    local opt_btn_w = S(30)
    local chk_w = S(25)
    local gap = S(5)
    
    local filter_w = avail_w - S(20) - opt_btn_w - chk_w - (gap * 2)
    
    -- Reserve space for results counter when filter has text
    local counter_reserve = S(0)
    if table_filter_state.text ~= "" and table_data_cache.list then
        local count = #table_data_cache.list
        local count_text = tostring(count)
        gfx.setfont(F.std)
        counter_reserve = gfx.measurestr(count_text) + S(16) -- text width + padding
    end
    
    local prev_text = table_filter_state.text
    local filter_placeholder = OTHER.find_replace_state.show 
        and T("TABLE_FILTER_PLACEHOLDER_1") 
        or T("TABLE_FILTER_PLACEHOLDER_2")
    ui_text_input("table_filter", filter_x, filter_y, filter_w - counter_reserve, filter_h, table_filter_state, filter_placeholder, input_queue)
    gfx.setfont(F.std)
    -- Display results count in the top-right corner of filter input
    if counter_reserve > 0 then
        local count = #table_data_cache.list
        local count_text = tostring(count)
        gfx.setfont(F.std)
        local count_w = gfx.measurestr(count_text)
        local count_x = filter_x + filter_w - count_w - S(8)
        local count_y = filter_y + (filter_h - gfx.texth) / 2
        
        set_color(UI.C_TXT_DIM) -- Subtle gray color
        gfx.x, gfx.y = count_x, count_y
        gfx.drawstr(count_text)
    end

    -- Case Sensitive Toggle (Aa) - Always visible
    local chk_x = filter_x + filter_w + gap
    local case_col = OTHER.find_replace_state.case_sensitive and UI.C_ACCENT_G or UI.C_BTN
    if draw_btn_inline(chk_x, filter_y, chk_w, filter_h, "Aa", case_col) then
        OTHER.find_replace_state.case_sensitive = not OTHER.find_replace_state.case_sensitive
    end

    -- Options / Close Toggle Button
    local btn_x = chk_x + chk_w + gap
    
    local mouse_in_menu = false
    if OTHER.col_vis_menu.show then
        local m_h = 4 * S(24) + S(10) -- 4 items * 24h
        mouse_in_menu = gfx.mouse_x >= OTHER.col_vis_menu.x and gfx.mouse_x <= OTHER.col_vis_menu.x + OTHER.col_vis_menu.w and
                        gfx.mouse_y >= OTHER.col_vis_menu.y and gfx.mouse_y <= OTHER.col_vis_menu.y + m_h
    elseif OTHER.time_shift_menu.show then
        local m_h = S(125) -- Matches the visual height
        mouse_in_menu = gfx.mouse_x >= OTHER.time_shift_menu.x and gfx.mouse_x <= OTHER.time_shift_menu.x + OTHER.time_shift_menu.w and
                        gfx.mouse_y >= OTHER.time_shift_menu.y and gfx.mouse_y <= OTHER.time_shift_menu.y + m_h
    elseif cfg.director_mode or cfg.editor_mode then
        -- Also block clicks if mouse is inside Director/Editor Panel
        if is_panel_right then
            if gfx.mouse_x >= avail_w and gfx.mouse_y >= S(35) then mouse_in_menu = true end
        else
            if gfx.mouse_y >= (gfx.h - h_panel) then mouse_in_menu = true end
        end
    end

    if OTHER.find_replace_state.show then
        -- CLOSE BUTTON (Reddish)
        if draw_btn_inline(btn_x, filter_y, opt_btn_w, filter_h, "X", UI.C_BTN_ERROR) then
            OTHER.find_replace_state.show = false
        end
    else
        -- MENU BUTTON (Standard)
        if draw_btn_inline(btn_x, filter_y, opt_btn_w, filter_h, "≡", UI.C_BTN) then
            -- Clear input focus on menu click
            director_state.input.focus = false
            editor_state.input.focus = false
            table_filter_state.focus = false
            OTHER.find_replace_state.find.focus = false
            OTHER.find_replace_state.replace.focus = false
            
            if OTHER.col_vis_menu.show or OTHER.time_shift_menu.show then
                OTHER.col_vis_menu.show = false
                OTHER.time_shift_menu.show = false
            else
                local any_hidden = not (cfg.col_table_index and cfg.col_table_start and cfg.col_table_end and cfg.col_table_cps and cfg.col_table_actor)
                local col_label = (any_hidden and "• " or "") .. T("TABLE_MENU_COLUMNS")
                local reader_label = (cfg.reader_mode and "• " or "") .. T("TABLE_MENU_READER_MODE")
                local markers_label = (cfg.show_markers_in_table and "• " or "") .. T("TABLE_MENU_SHOW_RETAKES")
                local director_label = (cfg.director_mode and "• " or "") .. T("TABLE_MENU_SHOW_DIRECTOR")
                local editor_label = (cfg.editor_mode and "• " or "") .. T("TABLE_MENU_SHOW_EDITOR")
                
                gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
                local menu_str = T("TABLE_MENU_FIND_REPLACE") .. "|" .. reader_label .. "|" .. col_label .. "|" .. T("TABLE_MENU_TIME_SHIFT") .. "||" .. markers_label .. "|" .. director_label .. "||" .. T("SPLIT_BY_DUBBERS") .. "|" .. editor_label .. "||>" .. T("TABLE_MENU_ACTIONS_ON_ITEM") .. "|" .. T("TABLE_MENU_COLOR_BY_ACTOR") .. "|" .. T("TABLE_MENU_REMOVE_COLORING") .. "||" .. T("TABLE_MENU_REMOVE_ITEM_DUP") .. " (Waveform Match)|" .. T("TABLE_MENU_STT") .. "||" .. T("TABLE_MENU_VN") .. "||<|>" .. T("TABLE_MENU_AI_TRANSLATE") .. "|" .. T("TABLE_MENU_AI_TRANSLATE_P1") .. "|" .. T("TABLE_MENU_AI_TRANSLATE_P2") .. "||" .. T("TABLE_MENU_AI_TRANSLATE_INSERT") .. "|<"
                local ret = gfx.showmenu(menu_str)
                if ret == 1 then
                    OTHER.find_replace_state.show = true
                    show_snackbar(T("TABLE_MENU_FIND_REPLACE_TT"), "info")
                elseif ret == 2 then
                    cfg.reader_mode = not cfg.reader_mode
                    if cfg.reader_mode then
                        table_sort.col = "start"
                        table_sort.dir = 1
                    end
                    save_settings()
                    UTILS.update_prompter_fonts()
                elseif ret == 3 then
                    OTHER.col_vis_menu.show = true
                    OTHER.col_vis_menu.x = (btn_x + opt_btn_w) - S(180)
                    OTHER.col_vis_menu.y = filter_y + filter_h + gap
                elseif ret == 4 then
                    OTHER.time_shift_menu.show = true
                    OTHER.time_shift_menu.x = (btn_x + opt_btn_w) - S(280)
                    OTHER.time_shift_menu.y = filter_y + filter_h + gap
                elseif ret == 5 then
                    cfg.show_markers_in_table = not cfg.show_markers_in_table
                    save_settings()
                elseif ret == 6 then
                    cfg.director_mode = not cfg.director_mode
                    if cfg.director_mode then
                        cfg.editor_mode = false -- Mutual exclusion
                        cfg.show_markers_in_table = true
                    end
                    save_settings()
                elseif ret == 7 then
                    DUBBERS.show_dashboard = true
                    DUBBERS.load()
                elseif ret == 8 then
                    cfg.editor_mode = not cfg.editor_mode
                    if cfg.editor_mode then
                        cfg.director_mode = false -- Mutual exclusion
                        cfg.show_markers_in_table = true
                    end
                    save_settings()
                elseif ret == 9 then
                    apply_item_coloring(false) -- Colorize
                elseif ret == 10 then
                    apply_item_coloring(true) -- Reset
                elseif ret == 11 then
                    filter_unique_item_replicas()
                elseif ret == 12 then
                    OTHER.speech_to_text_from_item()
                elseif ret == 13 then
                    ebu_r128_replicas_normalize()
                elseif ret == 14 then
                    OTHER.AI_generate_prompt(true)
                elseif ret == 15 then
                    OTHER.AI_generate_prompt(false)
                elseif ret == 16 then
                    OTHER.AI_insert_result()
                end
            end
        end

        -- Red Dot indicator for hidden columns or enabled markers
        local any_hidden = cfg.reader_mode or cfg.show_markers_in_table or not (cfg.col_table_index and cfg.col_table_start and cfg.col_table_end and cfg.col_table_cps and cfg.col_table_actor)
        if any_hidden then
            set_color(UI.C_RED) -- Red
            gfx.circle(btn_x + opt_btn_w - 4, filter_y + 4, 3, 1)
        end
    end
    
    if table_filter_state.text ~= prev_text then
        UI_STATE.scroll_y = 0
    end
    
    -- INLINE FIND/REPLACE UI
    if OTHER.find_replace_state.show then
        local fr_y = filter_y + filter_h + S(5)
        local fr_h = S(25)
        
        -- Replace Input
        local btn_apply_w = S(80)
        local rep_w = gfx.w - S(20) - btn_apply_w - gap
        
        ui_text_input("replace_field", filter_x, fr_y, rep_w, fr_h, OTHER.find_replace_state.replace, T("TABLE_FILTER_REPLACE_WITH"), input_queue)
        gfx.setfont(F.std)
        -- Apply Button
        local apply_x = filter_x + rep_w + gap
        if draw_btn_inline(apply_x, fr_y, btn_apply_w, fr_h, T("REPLACE"), UI.C_BTN) then
            local search = table_filter_state.text -- Use filter as search text
            local replace = OTHER.find_replace_state.replace.text
            local case = OTHER.find_replace_state.case_sensitive
            
            if #search > 0 then
                push_undo(T("TABLE_MENU_FIND_REPLACE"))
                local count = 0
                
                for _, line in ipairs(ass_lines) do
                    local txt = line.text or ""
                    local new_txt = ""
                    local matches = 0
                    
                    if case then
                        -- Escape magic chars for literal search if needed
                        local s_pat = search:gsub("([%%%^%$%(%)%.%[%]%*%+%-%?])", "%%%1")
                        new_txt, matches = txt:gsub(s_pat, function() return replace end)
                    else
                        local res_tbl = {}
                        local last_pos = 1
                        
                        local start_idx, end_idx = utf8_find_accent_blind(txt, search)
                        while start_idx do
                            table.insert(res_tbl, txt:sub(last_pos, start_idx - 1))
                            table.insert(res_tbl, replace)
                            last_pos = end_idx + 1
                            count = count + 1 
                            
                            local remaining = txt:sub(last_pos)
                            local next_s, next_e = utf8_find_accent_blind(remaining, search)
                            if next_s then
                                start_idx = last_pos + next_s - 1
                                end_idx = last_pos + next_e - 1
                            else
                                start_idx = nil
                            end
                        end
                        table.insert(res_tbl, txt:sub(last_pos))
                        new_txt = table.concat(res_tbl)
                        if new_txt ~= txt then matches = 1 else matches = 0 end
                    end
                    
                    if new_txt ~= txt then
                        line.text = new_txt
                        if case then count = count + matches end 
                    end
                end
                
                rebuild_regions()
                show_snackbar(T("TABLE_FILTER_REPLACE_INFO_1") .. count .. T("TABLE_FILTER_REPLACE_INFO_2"), "success")
                
                -- Clear inputs after successful replacement
                table_filter_state.text = ""
                table_filter_state.cursor = 0
                table_filter_state.anchor = 0
                OTHER.find_replace_state.replace.text = ""
                OTHER.find_replace_state.replace.cursor = 0
                OTHER.find_replace_state.replace.anchor = 0
                table_data_cache.state_count = -1
                last_layout_state.state_count = -1
            else
                show_snackbar(T("TABLE_FILTER_REPLACE_ENTER_TEXT"), "error")
            end
        end
        
        start_y = start_y + S(35) -- Shift content down
    end
    
    -- UPDATE WHISPER PROGRESS
    OTHER.update_whisper_progress()

    -- WHISPER PROGRESS BAR UI
    if OTHER.whisper_state and OTHER.whisper_state.active then
        local progress_y = start_y
        local progress_h = S(25)
        
        -- Draw background
        set_color(UI.C_PANEL_BG or {0.15, 0.15, 0.15, 1})
        gfx.rect(filter_x, progress_y, filter_w, progress_h, 1)
        
        -- Draw border
        set_color(UI.C_FR_BORDER or {0.3, 0.3, 0.3, 1})
        gfx.rect(filter_x, progress_y, filter_w, progress_h, 0)
        
        -- Cancel Button
        local cancel_w = S(80)
        local cancel_x = filter_x + filter_w - cancel_w
        if draw_btn_inline(cancel_x, progress_y, cancel_w, progress_h, T("CANCEL"), UI.C_BTN_ERROR) then
            OTHER.cancel_whisper_task()
        end
        
        -- Draw active progress fill
        local max_progress_w = cancel_x - filter_x - S(10)
        local progress_w = math.floor(max_progress_w * (OTHER.whisper_state.progress or 0))
        if progress_w > 0 then
            set_color(UI.C_ACCENT or {0.2, 0.6, 0.8, 0.3})
            gfx.rect(filter_x + 1, progress_y + 1, progress_w, progress_h - 2, 1)
        end
        
        -- Draw text info (e.g. "WhisperX: 45% [text snippet]")
        set_color(UI.C_TXT or {0.9, 0.9, 0.9, 1})
        local info_str = "WhisperX"
        if OTHER.whisper_state.text and OTHER.whisper_state.text ~= "" then
            info_str = info_str .. " | " .. OTHER.whisper_state.text
        end
        
        gfx.setfont(F.std)
        -- Limit text to fit
        local max_txt_w = max_progress_w - S(15)
        info_str = fit_text_width(info_str, max_txt_w)
        
        gfx.x, gfx.y = filter_x + S(8), progress_y + (progress_h - gfx.texth)/2
        gfx.drawstr(info_str)
        
        start_y = start_y + S(30) -- Shift content down
    end

    -- Keyboard Shortcuts
    if input_queue then
        for _, key in ipairs(input_queue) do
            -- Verify we are not typing in a text field
            if not table_filter_state.focus and not OTHER.find_replace_state.find.focus and 
               not OTHER.find_replace_state.replace.focus and not director_state.input.focus
               and not editor_state.input.focus then
                -- Ctrl+A (Select All Filtered)
                if key == 1 then
                    table_selection = {}
                    local current_data = table_data_cache.list or {}
                    for _, line in ipairs(current_data) do
                        table_selection[line.index] = true
                    end
                    last_selected_row = nil
                end

                -- Delete (6579564) or Backspace (8)
                if key == 6579564 or key == 8 then
                    UTILS.delete_logic()
                end

                -- Ctrl+D (Duplicate or Deselect All)
                if key == 4 then
                    local sel_count = 0
                    local target_id = nil
                    for idx, _ in pairs(table_selection) do
                        sel_count = sel_count + 1
                        target_id = idx
                    end
                    
                    if sel_count == 1 and type(target_id) == "number" then
                        UTILS.duplicate_logic(target_id)
                    else
                        table_selection = {}
                        last_selected_row = nil
                        show_snackbar(T("HIGHLIGHTING_REMOVED"), "info")
                    end
                end

                -- Navigation: Up (30064), Down (1685026670)
                if key == 30064 or key == 1685026670 then
                    local ds = ass_lines
                    local curr_idx = 0
                    
                    -- Find last selected index
                    for i, l in ipairs(ds) do
                        if table_selection[l.index or i] then curr_idx = i end
                    end
                    
                    if curr_idx == 0 and #ds > 0 then curr_idx = 1 end
                    
                    local new_idx = curr_idx
                    if key == 30064 then new_idx = new_idx - 1 else new_idx = new_idx + 1 end
                    
                    -- Clamp
                    if new_idx < 1 then new_idx = 1 end
                    if new_idx > #ds then new_idx = #ds end
                    
                    -- Apply Selection
                    local item = ds[new_idx]
                    if item then
                        table_selection = {}
                        table_selection[item.index or new_idx] = true
                        last_selected_row = new_idx
                        
                        -- Auto-Scroll (Dynamic)
                        local layout = table_layout_cache[new_idx]
                        if layout then
                            local item_y = layout.y
                            local row_h_local = layout.h
                            local view_h = gfx.h - S(110) -- Approximate available height
                            
                            if item_y < UI_STATE.target_scroll_y then
                                UI_STATE.target_scroll_y = item_y
                            elseif item_y + row_h_local > UI_STATE.target_scroll_y + view_h then
                                UI_STATE.target_scroll_y = item_y + row_h_local - view_h
                            end
                        end
                    end
                end
            end
        end
    end

    -- --- DATA SOURCE PREPARATION (CACHED) ---
    local current_state_count = reaper.GetProjectStateChangeCount(0)
    local current_proj_id = UI_STATE.last_project_id
    local cache_invalid = ((table_data_cache.state_count ~= current_state_count and UTILS.is_markers_regions_changed()) or
                           table_data_cache.project_id ~= current_proj_id or
                           table_data_cache.filter ~= table_filter_state.text or
                           table_data_cache.state_count == -1 or
                           table_data_cache.sort_col ~= table_sort.col or
                           table_data_cache.sort_dir ~= table_sort.dir or
                           table_data_cache.show_markers ~= cfg.show_markers_in_table or
                           table_data_cache.case_sensitive ~= OTHER.find_replace_state.case_sensitive or
                           table_data_cache.is_replace_mode ~= OTHER.find_replace_state.show or
                           table_data_cache.fr_show ~= OTHER.find_replace_state.show or
                           table_data_cache.dubbers_version ~= DUBBERS.version)

    
    if table_data_cache.state_count ~= current_state_count then
        table_data_cache.state_count = current_state_count
    end

    if cache_invalid then
        local raw_data = {}
        for i, line in ipairs(ass_lines) do
            raw_data[i] = line
            if not line.index then line.index = i end
        end
        
        if cfg.show_markers_in_table then
            update_marker_cache() -- Reuse shared prompter cache
            for _, m in ipairs(prompter_drawer.marker_cache.markers) do
                table.insert(raw_data, {
                    t1 = m.pos, t2 = m.pos, text = m.name, actor = T("TABLE_RETAKE"),
                    -- Add redundant fields for robust filtering/sorting in Regions mode
                    pos = m.pos, rgnend = m.pos, name = m.name,
                    is_marker = true, marker_color = m.color, markindex = m.markindex,
                    index = "M" .. m.markindex
                })
            end
        end

        local act_to_dub = {}
        if DUBBERS and DUBBERS.data and DUBBERS.data.assignments then
            for d_name, assigned in pairs(DUBBERS.data.assignments) do
                for actor_name, is_on in pairs(assigned) do
                    if is_on then 
                        if not act_to_dub[actor_name] then act_to_dub[actor_name] = {} end
                        table.insert(act_to_dub[actor_name], d_name)
                    end
                end
            end
            -- Join with commas
            for actor_name, dubbers in pairs(act_to_dub) do
                table.sort(dubbers)
                act_to_dub[actor_name] = table.concat(dubbers, ", ")
            end
        end

        local filtered = {}
        local query = table_filter_state.text
        local use_case = OTHER.find_replace_state.case_sensitive
        local is_replace_mode = OTHER.find_replace_state.show
        
        -- Split query by "|" for multi-filter (OR groups)
        local or_groups = {}
        if not is_replace_mode and query:find("|", 1, true) then
            for part in query:gmatch("[^|]+") do
                local trimmed = part:match("^%s*(.-)%s*$")
                if trimmed ~= "" then table.insert(or_groups, trimmed) end
            end
        elseif query ~= "" then
            table.insert(or_groups, query)
        end

        -- Parse each OR group into sub-queries (AND logic)
        local queries = {} -- Table of tables: { {and_term1, and_term2}, {or_term2_alone} }
        for _, group in ipairs(or_groups) do
            local and_terms = {}
            if group:find("&", 1, true) then
                for part in group:gmatch("[^&]+") do
                    local trimmed = part:match("^%s*(.-)%s*$")
                    if trimmed ~= "" then table.insert(and_terms, trimmed) end
                end
            else
                table.insert(and_terms, group)
            end
            if #and_terms > 0 then table.insert(queries, and_terms) end
        end

        for _, line in ipairs(raw_data) do
            local target_text = line.text or line.name or ""
            local any_match = false
            local h_text, h_actor, h_index, h_dubber
            
            if #queries == 0 then
                any_match = true
            else
                -- Check each OR group
                for _, and_group in ipairs(queries) do
                    local all_and_matched = true
                    
                    -- All terms in this group must match (AND logic)
                    for _, q in ipairs(and_group) do
                        local q_lower = utf8_lower(q)
                        local q_clean = strip_accents(q_lower)
                        local text_match, actor_match, index_match, dubber_match = false, false, false, false
                        
                        -- Special Command: {%UPPER} - All Uppercase (Caps Lock filter)
                        if q == "{%UPPER}" and not is_replace_mode then
                            local visible = target_text:gsub("{{+.-}}+", ""):gsub("{.-}", ""):gsub("\\N", "")
                            -- Remove spaces, punctuation and digits to check only actual letters
                            local letters_only = visible:gsub("%s+", ""):gsub("[%p%d]", "")
                            if #letters_only > 0 and letters_only == utf8_upper(letters_only) then
                                text_match = true
                            end
                        elseif use_case then
                            text_match = target_text:find(q, 1, true)
                            if text_match and not h_text then h_text = {target_text:find(q, 1, true)} end
                            if show_actor and line.actor then
                                actor_match = line.actor:find(q, 1, true)
                                if actor_match and not h_actor then h_actor = {line.actor:find(q, 1, true)} end
                            end
                            
                            local dubber_str = act_to_dub[line.actor or ""] or ""
                            if cfg.col_table_dubber and dubber_str ~= "" then
                                dubber_match = dubber_str:find(q, 1, true)
                                if dubber_match and not h_dubber then h_dubber = {dubber_str:find(q, 1, true)} end
                            end
                            
                            index_match = tostring(line.index or ""):find(q, 1, true)
                            if index_match and not h_index then h_index = {tostring(line.index or ""):find(q, 1, true)} end
                        else
                            local clean_text = strip_accents(utf8_lower((target_text or ""):gsub("\\N", " "):gsub("\\n", " ")))
                            text_match = clean_text:find(q_clean, 1, true)

                            if text_match and not h_text then 
                                local s, e = utf8_find_accent_blind(target_text, q)
                                if s then h_text = {s, e} end
                            end
                            if show_actor and line.actor then
                                local clean_actor = strip_accents(utf8_lower(line.actor))
                                actor_match = clean_actor:find(q_clean, 1, true)
                                if actor_match and not h_actor then
                                    local s, e = utf8_find_accent_blind(line.actor, q)
                                    if s then h_actor = {s, e} end
                                end
                            end
                            
                            local dubber_str = act_to_dub[line.actor or ""] or ""
                            if cfg.col_table_dubber and dubber_str ~= "" then
                                local clean_dubber = strip_accents(utf8_lower(dubber_str))
                                dubber_match = clean_dubber:find(q_clean, 1, true)
                                if dubber_match and not h_dubber then
                                    local s, e = utf8_find_accent_blind(dubber_str, q)
                                    if s then h_dubber = {s, e} end
                                end
                            end
                            local idx_str = tostring(line.index or "")
                            index_match = idx_str:lower():find(q_clean, 1, true)
                            if index_match and not h_index then
                                local s, e = idx_str:lower():find(q_clean, 1, true)
                                if s then h_index = {s, e} end
                            end
                        end
                        
                        if not (text_match or (not is_replace_mode and (actor_match or index_match or dubber_match))) then
                            all_and_matched = false
                            break -- This AND group failed
                        end
                    end
                    
                    if all_and_matched then
                        any_match = true
                        break -- Found a matching OR group
                    end
                end
            end

            if any_match then
                line.h_text = h_text -- Store pre-calculated highlight
                line.h_actor = h_actor
                line.h_index = h_index
                line.h_dubber = h_dubber
                
                -- Pre-calculate CPS and strings for table view
                local duration = (line.t2 or 0) - (line.t1 or 0)
                local clean_txt = (line.text or ""):gsub("{{+.-}}+", ""):gsub("{.-}", ""):gsub("\\N", ""):gsub("%s+", ""):gsub(acute, "")
                local char_count = utf8.len(clean_txt) or #clean_txt
                line.cps = duration > 0 and (char_count / duration) or 0
                line.cps_str = line.is_marker and "" or string.format("%.1f", line.cps)
                line.cps_color = UTILS.get_cps_color(line.cps)
                
                line.t1_str = reaper.format_timestr(line.t1 or 0, "")
                line.t2_str = line.is_marker and "" or reaper.format_timestr(line.t2 or 0, "")
                line.idx_str = tostring(line.index or "")
                line.dubber = act_to_dub[line.actor or ""] or ""
                
                table.insert(filtered, line)
            end
        end

        -- Sorting
        if table_sort.col ~= "#" or table_sort.dir ~= 1 then
            local temp = {}
            for i, item in ipairs(filtered) do
                temp[i] = { item = item, val = get_sort_value(item, table_sort.col, show_actor) }
            end
            table.sort(temp, function(a, b)
                if a.val == b.val then
                    if (table_sort.col == T("TABLE_COLUMN_ACTIVE") or table_sort.col == "enabled") then
                        local t1_a = a.item.t1 or 0; local t1_b = b.item.t1 or 0
                        if t1_a ~= t1_b then return t1_a < t1_b end
                    end
                    local idx_a, idx_b = a.item.index or 0, b.item.index or 0
                    if type(idx_a) ~= type(idx_b) then return type(idx_a) == "number" end
                    return idx_a < idx_b
                end
                if type(a.val) ~= type(b.val) then
                    return (table_sort.dir == 1) == (type(a.val) == "number")
                end
                if table_sort.dir == 1 then
                    return a.val < b.val
                else
                    return a.val > b.val
                end
            end)
            filtered = {}
            for i, t in ipairs(temp) do filtered[i] = t.item end
        end

        table_data_cache.list = filtered
        table_data_cache.state_count = current_state_count
        table_data_cache.project_id = current_proj_id
        table_data_cache.filter = table_filter_state.text
        table_data_cache.sort_col = table_sort.col
        table_data_cache.sort_dir = table_sort.dir
        table_data_cache.show_markers = cfg.show_markers_in_table
        table_data_cache.case_sensitive = use_case
        table_data_cache.is_replace_mode = is_replace_mode
        table_data_cache.fr_show = OTHER.find_replace_state.show
        table_data_cache.dubbers_version = DUBBERS.version
        
        -- Cleanup selection of stale marker indices (only those not in current raw_data)
        -- We do NOT cleanup based on 'filtered' as that would wipe selection during search
        local project_indices = {}
        for _, line in ipairs(raw_data) do
            project_indices[line.index] = true
        end
        for idx in pairs(table_selection) do
            if not project_indices[idx] then
                table_selection[idx] = nil
            end
        end

        DUBBERS.refresh_conflicts()
    end

    local data_source = table_data_cache.list

    -- Column layout: Build x_off based on visible columns only (CACHED)
    local raw_data_count = #ass_lines + (cfg.show_markers_in_table and #prompter_drawer.marker_cache.markers or 0)
    local layout_changed = (last_layout_state.w ~= gfx.w or 
                            last_layout_state.count ~= raw_data_count or 
                            last_layout_state.mode ~= cfg.reader_mode or
                            last_layout_state.filter ~= table_filter_state.text or
                            last_layout_state.sort_col ~= table_sort.col or
                            last_layout_state.sort_dir ~= table_sort.dir or
                            last_layout_state.show_markers ~= cfg.show_markers_in_table or
                            last_layout_state.gui_scale ~= cfg.gui_scale or
                            last_layout_state.state_count ~= current_state_count or
                            last_layout_state.dubbers_version ~= DUBBERS.version or
                            last_layout_state.col_vis_index ~= cfg.col_table_index or
                            last_layout_state.col_vis_start ~= cfg.col_table_start or
                            last_layout_state.col_vis_end ~= cfg.col_table_end or
                            last_layout_state.col_vis_dubber ~= cfg.col_table_dubber or
                            last_layout_state.col_vis_cps ~= cfg.col_table_cps or
                            last_layout_state.col_vis_actor ~= cfg.col_table_actor or
                            OTHER.col_resize.dragging or
                            last_layout_state.col_w_enabled ~= cfg.col_w_enabled or
                            last_layout_state.col_w_index ~= cfg.col_w_index or
                            last_layout_state.col_w_start ~= cfg.col_w_start or
                            last_layout_state.col_w_end ~= cfg.col_w_end or
                            last_layout_state.col_w_dubber ~= cfg.col_w_dubber or
                            last_layout_state.col_w_cps ~= cfg.col_w_cps or
                            last_layout_state.col_w_actor ~= cfg.col_w_actor or
                            last_layout_state.fr_show ~= OTHER.find_replace_state.show or
                            last_layout_state.t_r_size ~= cfg.t_r_size)

    local x_off = last_layout_state.x_off or {S(10)}
    local col_keys = last_layout_state.col_keys or {}
    if layout_changed then
        x_off = {S(10)}
        col_keys = {}
        local function add_col(w, key) 
            table.insert(x_off, x_off[#x_off] + w) 
            table.insert(col_keys, key)
        end
        if not cfg.reader_mode then
            add_col(S(cfg.col_w_enabled), "col_w_enabled")
            if cfg.col_table_index then add_col(S(cfg.col_w_index), "col_w_index") end
            if cfg.col_table_start then add_col(S(cfg.col_w_start), "col_w_start") end
            if cfg.col_table_end then add_col(S(cfg.col_w_end), "col_w_end") end
            if cfg.col_table_dubber then add_col(S(cfg.col_w_dubber), "col_w_dubber") end
            if cfg.col_table_cps then add_col(S(cfg.col_w_cps), "col_w_cps") end
            if cfg.col_table_actor then add_col(S(cfg.col_w_actor), "col_w_actor") end
        end
    end

    if layout_changed then
        table_layout_cache = {}
        local current_y_offset = 0
        
        -- Calculate height for each row using the already prepared data_source
        local content_x_start = x_off[#x_off] or S(10)
        local max_w = avail_w - content_x_start - 30 -- padding + scrollbar (updated to use avail_w)
        
        -- Ensure font is set to the correct size for the NEW mode
        local tr_set_layout = cfg.reader_mode and OTHER.FONT_SIZES.reader or OTHER.FONT_SIZES.normal
        local use_sz_layout = tr_set_layout[cfg.t_r_size] or 16
        gfx.setfont(F[cfg.t_r_size], cfg.p_font, S(use_sz_layout))
        local line_h = gfx.texth
        
        -- Dynamic min_row_h based on font
        local extra_pad = S(6)
        if cfg.t_r_size == "tr_XXXL" then extra_pad = S(11)
        elseif cfg.t_r_size == "tr_XXL" then extra_pad = S(10)
        elseif cfg.t_r_size == "tr_XL" then extra_pad = S(9)
        elseif cfg.t_r_size == "tr_L" then extra_pad = S(8)
        elseif cfg.t_r_size == "tr_M" then extra_pad = S(8)
        else extra_pad = S(8) end

        local min_row_h = cfg.reader_mode and S(60) or (line_h + extra_pad)
        local padding_v = cfg.reader_mode and 20 or 8

        for i, line in ipairs(data_source) do
            local h = min_row_h
            local cached_lines = nil
            if cfg.reader_mode then
                local display_txt = (line.text or ""):gsub("[\n\r]", " ")
                if line.is_marker and line.markindex then
                    display_txt = "(M" .. line.markindex .. ") - " .. display_txt
                end
                cached_lines = wrap_text_manual(display_txt, max_w)
                h = math.max(min_row_h, #cached_lines * line_h + padding_v)
            end
            table.insert(table_layout_cache, {y = current_y_offset, h = h, lines = cached_lines})
            current_y_offset = current_y_offset + h
        end
        
        last_layout_state = {
            w = gfx.w, count = raw_data_count, mode = cfg.reader_mode, 
            filter = table_filter_state.text, sort_col = table_sort.col, 
            sort_dir = table_sort.dir, gui_scale = cfg.gui_scale,
            show_markers = cfg.show_markers_in_table,
            state_count = current_state_count,
            dubbers_version = DUBBERS.version,
            x_off = x_off,
            col_keys = col_keys,
            col_w_enabled = cfg.col_w_enabled,
            col_w_index = cfg.col_w_index,
            col_w_start = cfg.col_w_start,
            col_w_end = cfg.col_w_end,
            col_w_dubber = cfg.col_w_dubber,
            col_w_cps = cfg.col_w_cps,
            col_w_actor = cfg.col_w_actor,
            col_vis_index = cfg.col_table_index,
            col_vis_start = cfg.col_table_start,
            col_vis_end = cfg.col_table_end,
            col_vis_dubber = cfg.col_table_dubber,
            col_vis_cps = cfg.col_table_cps,
            col_vis_actor = cfg.col_table_actor,
            fr_show = OTHER.find_replace_state.show,
            t_r_size = cfg.t_r_size
        }
    end

    local total_h = #table_layout_cache > 0 and (table_layout_cache[#table_layout_cache].y + table_layout_cache[#table_layout_cache].h) or 0
    local min_panel_h = S(128)
    if cfg.editor_mode then min_panel_h = S(188) end 

    -- Safeguard: auto-close bottom panels if window is too small
    if not is_panel_right and gfx.h < min_panel_h + S(60) then
        if cfg.editor_mode or cfg.director_mode then
            cfg.editor_mode = false
            cfg.director_mode = false
            save_settings()
        end
    end

    -- Layout Adjustments (Calculated at top, but validated here for overlap)
    local content_y = start_y + h_header
    local max_allowed_h = math.max(min_panel_h, gfx.h - content_y - S(40))
    if h_panel > max_allowed_h then
        h_panel = max_allowed_h
        if not director_resize_drag then 
            if cfg.editor_mode then cfg.h_editor = h_panel else cfg.h_director = h_panel end
        end
    end
    
    local avail_h = gfx.h - content_y - h_panel
    if avail_h < 0 then avail_h = 0 end

    local max_scroll = math.max(0, total_h - avail_h)
    
    -- Auto-scroll to specific marker (e.g. after Save/Update in Director Panel)
    if director_state.pending_scroll_id then
        for i, line in ipairs(data_source) do
            if line.is_marker and line.markindex == director_state.pending_scroll_id then
                -- 1. Update Selection
                table_selection = {}
                table_selection[line.index] = true 
                last_selected_row = i

                -- 2. Scroll
                if table_layout_cache[i] then
                    local layout = table_layout_cache[i]
                    UI_STATE.target_scroll_y = math.max(0, math.min(max_scroll, layout.y - (avail_h / 2) + (layout.h / 2)))
                end
                
                director_state.pending_scroll_id = nil
                break
            end
        end
    end
    
    -- Auto-scroll to current playback position (only when position changes)
    local play_pos = reaper.GetPlayPosition()
    local edit_pos = reaper.GetCursorPosition()
    local current_pos = reaper.GetPlayState() > 0 and play_pos or edit_pos
    
    -- Only auto-scroll if position changed significantly (user jumped) OR line changed
    local pos_changed = math.abs(current_pos - UI_STATE.last_tracked_pos) > 0.5
    
    -- Find which line corresponds to current position
    local active_line_idx = nil
    for i, line in ipairs(data_source) do
        if current_pos >= line.t1 and current_pos < line.t2 then
            active_line_idx = i
            break
        end
    end

    -- Trigger auto-scroll if:
    -- 1. Playhead jumped significantly (>0.5s)
    -- 2. OR the active line index changed (progression)
    -- 3. AND not suppressed by manual interaction
    
    -- Suppress auto-scroll immediately if user just clicked in the table area
    if (gfx.mouse_cap & 1 == 1) and (UI_STATE.last_mouse_cap & 1 == 0) and gfx.mouse_y >= content_y and gfx.mouse_y < content_y + avail_h then
        suppress_auto_scroll_frames = 5
    end
    
    if suppress_auto_scroll_frames > 0 then
        suppress_auto_scroll_frames = suppress_auto_scroll_frames - 1
    end
    
    local line_changed = (active_line_idx ~= last_auto_scroll_idx)
    if (pos_changed or line_changed) and not UI_STATE.skip_auto_scroll and suppress_auto_scroll_frames == 0 then
        UI_STATE.last_tracked_pos = current_pos
        last_auto_scroll_idx = active_line_idx
        
        if active_line_idx and table_layout_cache[active_line_idx] then
            local layout = table_layout_cache[active_line_idx]
            -- Center the line
            UI_STATE.target_scroll_y = math.max(0, math.min(max_scroll, layout.y - (avail_h / 2) + (layout.h / 2)))
        end
    end
    
    -- Smooth Scroll Logic
    local mouse_in_panel = (cfg.director_mode or cfg.editor_mode) and (
        (not is_panel_right and gfx.mouse_y >= gfx.h - h_panel) or
        (is_panel_right and gfx.mouse_x >= (gfx.w - w_panel))
    )
    if gfx.mouse_wheel ~= 0 and not mouse_in_panel and not mouse_in_menu then
        UI_STATE.target_scroll_y = UI_STATE.target_scroll_y - (gfx.mouse_wheel * 0.25)
        if UI_STATE.target_scroll_y < 0 then UI_STATE.target_scroll_y = 0 end
        if UI_STATE.target_scroll_y > max_scroll then UI_STATE.target_scroll_y = max_scroll end
        gfx.mouse_wheel = 0
    end

    local diff = UI_STATE.target_scroll_y - UI_STATE.scroll_y
    if math.abs(diff) > 0.5 then
        UI_STATE.scroll_y = UI_STATE.scroll_y + (diff * 0.8)
    else
        UI_STATE.scroll_y = UI_STATE.target_scroll_y
    end

    -- Prepare Buffer for Rows (Clipping)
    local prev_dest = gfx.dest
    gfx.dest = OTHER.BUF.TABLE
    gfx.setimgdim(OTHER.BUF.TABLE, gfx.w, math.max(1, avail_h))
    set_color(UI.C_BG)
    gfx.rect(0, 0, avail_w, avail_h, 1)
    
    -- Find starting index based on UI_STATE.scroll_y and layout cache
    local start_idx = 1
    for i, layout in ipairs(table_layout_cache) do
        if layout.y + layout.h > UI_STATE.scroll_y then
            start_idx = i
            break
        end
    end
    
    for i = start_idx, #data_source do
        local layout = table_layout_cache[i]
        if not layout then break end
        
        local screen_y = content_y + (layout.y - UI_STATE.scroll_y)
        local row_h_dynamic = layout.h
        
        -- Stop if we are below visible area
        if screen_y > content_y + avail_h then break end
        
        local buf_y = layout.y - UI_STATE.scroll_y

        -- ASS mode: show all lines with checkbox
        local line = data_source[i]
        
        -- Special background for markers
        if line.is_marker then
            set_color(UI.C_MARKER_BG) -- Dark reddish background for markers
            gfx.rect(0, buf_y, avail_w, row_h_dynamic, 1)
        else
            -- zebra
            if i % 2 == 0 then set_color(UI.C_ROW) else set_color(UI.C_ROW_ALT) end
            gfx.rect(0, buf_y, avail_w, row_h_dynamic, 1)
        end
            local actor = line.actor or ""
            local is_enabled = (line.enabled ~= false) -- Per-line enabled state
            
            -- Determine original index for selection tracking
            local original_idx = line.index or i
            local is_selected = table_selection[original_idx]
            
            -- Highlight if current time is within this line's range (Active)
            local play_pos = reaper.GetPlayPosition()
            local edit_pos = reaper.GetCursorPosition()
            local current_time = reaper.GetPlayState() > 0 and play_pos or edit_pos
            local is_active_row = (current_time >= line.t1 and current_time < line.t2)
            
            if is_selected then
                if line.is_marker then
                    set_color(UI.C_MARKER_SEL) -- Dark Orange Selection for markers
                else
                    set_color(UI.C_HILI_GREEN) -- Darker Green Selection
                end
                gfx.rect(0, buf_y, avail_w, row_h_dynamic, 1)
            end
            
            -- Hover Effect
            local row_hover = UI_STATE.window_focused and (gfx.mouse_x >= 0 and gfx.mouse_x < avail_w and
                                 gfx.mouse_y >= screen_y and gfx.mouse_y < screen_y + row_h_dynamic and
                                 gfx.mouse_y >= content_y and gfx.mouse_y < content_y + avail_h)
            
            if row_hover then
                set_color(UI.C_HILI_WHITE)
                gfx.rect(0, buf_y, avail_w, row_h_dynamic, 1)
            end

            if is_active_row then
                set_color(UI.GET_T_AR_COLOR(1)) -- Bright Green Border
                gfx.rect(0, buf_y, 5, row_h_dynamic, 1)

                set_color(UI.GET_T_AR_COLOR(cfg.t_ar_alpha))
                gfx.rect(0, buf_y, avail_w, row_h_dynamic, 1)
            end
            
            local chk_sz = S(16)
            local chk_x = x_off[1]
            if not cfg.reader_mode and not line.is_marker then
                -- Checkbox column (skip for markers)
                local chk_y = buf_y + (row_h_dynamic - chk_sz)/2
                
                set_color(UI.C_ED_GUTTER)
                gfx.rect(chk_x, chk_y, chk_sz, chk_sz, 0)
                
                if line.enabled ~= false then
                    set_color(UI.C_TXT)
                    -- Checkmark
                    gfx.line(chk_x + S(3), chk_y + S(8), chk_x + S(7), chk_y + S(12))
                    gfx.line(chk_x + S(4), chk_y + S(8), chk_x + S(8), chk_y + S(12))
                    gfx.line(chk_x + S(7), chk_y + S(12), chk_x + S(13), chk_y + S(4))
                    gfx.line(chk_x + S(8), chk_y + S(12), chk_x + S(14), chk_y + S(4))
                end
            end
            
            local row_base_color = UI.C_TXT
            if cfg.reader_mode then
                if is_enabled then
                    row_base_color = UI.C_TXT -- Enabled = White
                else
                    row_base_color = {0.5, 0.5, 0.5, 1} -- Disabled = Gray
                end
            end
            set_color(row_base_color)
            local buf_y_text = buf_y + (cfg.reader_mode and 10 or 4)
            gfx.setfont(F[cfg.t_r_size]) -- Always use our dedicated slot for row content
            
            -- Use original index if possible
            -- Helper to draw truncated text in cell
            -- Helper for highlighting and wrapping
            local function draw_highlighted_text(txt, x, y, max_w, row_h_passed, h_range, cached_lines)
                set_color(row_base_color)
                
                if not cfg.reader_mode then
                    -- Standard Mode: Truncate and draw single line
                    local display_txt = txt:gsub("[\n\r]", " ")
                    display_txt = fit_text_width(display_txt, max_w)
                    
                    if h_range then
                        local s_start, s_end = h_range[1], h_range[2]
                        -- Ensure highlight is within visible/truncated text
                        if s_start <= #display_txt then
                            local pre_match = display_txt:sub(1, s_start - 1)
                            local match_str = display_txt:sub(s_start, math.min(s_end, #display_txt))
                            local pre_w = gfx.measurestr(pre_match)
                            local match_w = gfx.measurestr(match_str)
                            set_color(UI.C_HILI_YELLOW, 0.4)
                            gfx.rect(x + pre_w, y, match_w, gfx.texth, 1)
                            set_color(row_base_color)
                        end
                    end
                    gfx.x, gfx.y = x, y
                    gfx.drawstr(display_txt)
                elseif cached_lines then
                    -- Reader Mode: Use cached wrapped lines
                    local total_text_h = #cached_lines * gfx.texth
                    local cur_y = buf_y + (row_h_passed - total_text_h) / 2
                    local query = table_filter_state.text
                    local first_match_done = false

                    for _, line_str in ipairs(cached_lines) do
                        local line_h = gfx.texth
                        if cur_y + line_h > buf_y + row_h_passed then break end
                        
                        if #query > 0 and not first_match_done then
                            local s_start, s_end
                            if OTHER.find_replace_state.case_sensitive then
                                s_start, s_end = line_str:find(query, 1, true)
                            else
                                s_start, s_end = utf8_find_accent_blind(line_str, query)
                            end
                            if s_start then
                                local pre_match = line_str:sub(1, s_start - 1)
                                local match_str = line_str:sub(s_start, s_end)
                                local pre_w = gfx.measurestr(pre_match)
                                local match_w = gfx.measurestr(match_str)
                                set_color(UI.C_HILI_YELLOW, 0.4)
                                gfx.rect(x + pre_w, cur_y, match_w, line_h, 1)
                                set_color(row_base_color)
                                first_match_done = true 
                            end
                        end
                        
                        gfx.x, gfx.y = x, cur_y
                        gfx.drawstr(line_str)
                        cur_y = cur_y + line_h
                    end
                end
            end

            local col_ptr = cfg.reader_mode and 1 or 2
            local function draw_cell_txt(txt, idx)
                if not idx or not x_off[idx] then return end
                local x = x_off[idx]
                local next_x = x_off[idx + 1] or gfx.w
                local w = next_x - x - S(4) -- padding
                if w > S(5) then
                    gfx.x = x; gfx.y = buf_y_text
                    gfx.drawstr(fit_text_width(txt, w))
                end
            end

            if not cfg.reader_mode then
                if cfg.col_table_index then
                    draw_highlighted_text(line.idx_str, x_off[col_ptr], buf_y_text, x_off[col_ptr+1] - x_off[col_ptr] - 4, row_h_dynamic, line.h_index)
                    col_ptr = col_ptr + 1
                end

                if cfg.col_table_start then
                    draw_cell_txt(line.t1_str, col_ptr); col_ptr = col_ptr + 1
                end

                if cfg.col_table_end then
                    draw_cell_txt(line.t2_str, col_ptr); col_ptr = col_ptr + 1
                end

                if cfg.col_table_dubber then
                    local dx, dw = x_off[col_ptr], x_off[col_ptr+1] - x_off[col_ptr]
                    local conflict = cfg.show_dubber_conflicts and DUBBERS.conflicts[original_idx] or nil
                    if conflict then
                        local alpha = 0.25 -- Subtle tint
                        set_color({1, 0.8, 0}, alpha) -- Unified Yellow/Orange tint for all conflicts
                        gfx.rect(dx, buf_y, dw, row_h_dynamic, 1)
                        
                        -- Tooltip on hover
                        if row_hover and gfx.mouse_x >= dx and gfx.mouse_x < dx + dw then
                            local tip_id = "dub_conf_" .. original_idx
                            if UI_STATE.tooltip_state.hover_id ~= tip_id then
                                UI_STATE.tooltip_state.hover_id = tip_id
                                UI_STATE.tooltip_state.start_time = reaper.time_precise()
                            end
                            UI_STATE.tooltip_state.text = conflict.msg
                            UI_STATE.tooltip_state.immediate = true
                            
                            -- Click to Jump
                            if is_mouse_clicked(1) then
                                for j, l in ipairs(data_source) do
                                    if (l.index or j) == conflict.partner_id then
                                        local target_layout = table_layout_cache[j]
                                        if target_layout then
                                            UI_STATE.target_scroll_y = math.max(0, math.min(max_scroll, target_layout.y - (avail_h / 2) + (target_layout.h / 2)))
                                            table_selection = {[conflict.partner_id] = true} -- Select partner
                                            show_snackbar(T("TABLE_GO_TO_CONFLICT") .. tostring(conflict.partner_id), "info")
                                            UI_STATE.mouse_handled = true -- Prevent other actions
                                        end
                                        break
                                    end
                                end
                            end
                        end
                    end
                    draw_highlighted_text(line.dubber or "", dx, buf_y_text, dw - 4, row_h_dynamic, line.h_dubber)
                    col_ptr = col_ptr + 1
                end
            end

            if not cfg.reader_mode and cfg.col_table_cps then
                set_color(line.cps_color)
                draw_cell_txt(line.cps_str, col_ptr); col_ptr = col_ptr + 1
            end

            if not cfg.reader_mode and cfg.col_table_actor then
                gfx.x = x_off[col_ptr]; gfx.y = buf_y_text; 
                draw_highlighted_text(actor, x_off[col_ptr], buf_y_text, x_off[col_ptr+1] - x_off[col_ptr] - 10, row_h_dynamic, line.h_actor)
                col_ptr = col_ptr + 1
            end
            
            draw_highlighted_text(line.text or "", x_off[col_ptr], buf_y_text, gfx.w - x_off[col_ptr] - 10, row_h_dynamic, line.h_text, layout.lines)
            
            -- Click logic
            -- FIX: Check bit 1 (Left Mouse) regardless of other flags
            if (gfx.mouse_cap & 1 == 1) and (UI_STATE.last_mouse_cap & 1 == 0) and not mouse_in_menu and not OTHER.col_vis_menu.handled then
                -- Safety check: click must be within both the visible content area AND the row itself
                -- Also check horizontal bounds to prevent clicks in Director Panel (when docked right)
                if gfx.mouse_x < avail_w and
                   gfx.mouse_y >= content_y and gfx.mouse_y < content_y + avail_h and
                   gfx.mouse_y >= screen_y and gfx.mouse_y < screen_y + row_h_dynamic then
                    -- Checkbox click? (Only if visible and not a marker)
                    if not cfg.reader_mode and not line.is_marker and chk_x and gfx.mouse_x >= chk_x - S(5) and gfx.mouse_x <= chk_x + chk_sz + S(10) then
                        -- BULK CHECKBOX LOGIC
                        push_undo(T("TABLE_TOGGLE_VISIBILITY"))
                        
                        -- Clear input focus on checkbox click
                        director_state.input.focus = false
                        editor_state.input.focus = false
                        table_filter_state.focus = false
                        OTHER.find_replace_state.find.focus = false
                        OTHER.find_replace_state.replace.focus = false
                        local new_state = not is_enabled
                        
                        if is_selected then
                            -- Apply to all selected
                            local count = 0
                             for k, l in ipairs(ass_lines) do
                                  if table_selection[l.index or k] then
                                      l.enabled = new_state
                                      count = count + 1
                                  end
                             end
                            if count == 0 then line.enabled = new_state end
                        else
                            -- Just toggle self
                            line.enabled = new_state
                        end
                        UI_STATE._markers_is_dirty = true
                        rebuild_regions() 
                    else
                        -- CLICK ON ROW (Selection Logic)
                        local cap = gfx.mouse_cap
                        local is_ctrl = (cap & 4 == 4) or (cap & 32 == 32) -- Ctrl or Cmd
                        local is_shift = (cap & 8 == 8)
                        
                        if is_ctrl then
                            -- Toggle Selection ONLY (No navigation)
                            if table_selection[original_idx] then
                                table_selection[original_idx] = nil
                            else
                                table_selection[original_idx] = true
                                last_selected_row = i -- Update anchor to current visual index
                            end
                        elseif is_shift and last_selected_row then
                            -- Range Selection ONLY (No navigation)
                            local start_v = math.min(last_selected_row, i)
                            local end_v = math.max(last_selected_row, i)
                            
                            table_selection = {}
                            for k = start_v, end_v do
                                local d_line = data_source[k]
                                if d_line then
                                    table_selection[d_line.index or k] = true
                                end
                            end
                        else
                            -- Single Click (Standard) -> Navigate & Clear Selection
                            table_selection = {}
                            table_selection[original_idx] = true
                            last_selected_row = i 
                            UI_STATE.last_tracked_pos = line.t1 -- Always sync position on click
                            last_auto_scroll_idx = i -- Sync to prevent auto-centering immediately after click
                            
                            if line.enabled then
                                editor_state.last_region_id = line.rgn_idx
                                editor_state.needs_sync = true
                            end
                            
                            -- Clear input focus on row click
                            director_state.input.focus = false
                            editor_state.input.focus = false
                            table_filter_state.focus = false
                            OTHER.find_replace_state.find.focus = false
                            OTHER.find_replace_state.replace.focus = false
                            
                            -- Navigate logic
                            local replica_x_start = cfg.reader_mode and 0 or x_off[#x_off]
                            if gfx.mouse_x >= replica_x_start then
                                local now = reaper.time_precise()
                                if UI_STATE.last_click_row == i and (now - UI_STATE.last_click_time) < 0.5 then
                                    -- Double-click on text
                                    if line.is_marker then
                                        -- Edit marker name
                                        local edit_marker = line
                                        open_text_editor(line.text, function(new_text)
                                            push_undo(T("EDIT_RETAKE"))
                                            -- Find marker index
                                            local target_idx = -1
                                            local m_count = reaper.CountProjectMarkers(0)
                                            for j = 0, m_count - 1 do
                                                local _, isrgn, pos, _, _, markindex = reaper.EnumProjectMarkers3(0, j)
                                                if not isrgn and (markindex == edit_marker.markindex or math.abs(pos - edit_marker.t1) < 0.001) then
                                                    target_idx = j
                                                    break
                                                end
                                            end
                                            if target_idx ~= -1 then
                                                reaper.SetProjectMarkerByIndex(0, target_idx, false, edit_marker.t1, 0, edit_marker.markindex, new_text, edit_marker.marker_color or 0)
                                            end
                                            
                                            ass_markers = capture_project_markers()
                                            table_data_cache.state_count = -1 -- FORCE UPDATE TABLE
                                            last_layout_state.state_count = -1 -- FORCE UPDATE LAYOUT
                                            prompter_drawer.marker_cache.count = -1 -- FORCE UPDATE MARKERS
                                        end, original_idx, nil, true)
                                    else
                                        -- Edit ASS line
                                        local edit_line = line
                                        open_text_editor(line.text, function(new_text)
                                            push_undo(T("EDIT_LINE"))
                                            edit_line.text = new_text
                                            UI_STATE._markers_is_dirty = true
                                            rebuild_regions()
                                            table_data_cache.state_count = -1 -- FORCE UPDATE TABLE
                                            last_layout_state.state_count = -1 -- FORCE UPDATE LAYOUT
                                        end, original_idx, ass_lines)
                                    end
                                    UI_STATE.last_click_row = 0
                                else
                                    UI_STATE.last_click_time = now
                                    UI_STATE.last_click_row = i
                                    reaper.SetEditCurPos(line.t1, true, false)
                                end
                            else
                                -- Just Navigate
                                reaper.SetEditCurPos(line.t1, true, false)
                            end
                        end
                    end
                end     
            elseif (gfx.mouse_cap & 2 == 2) and (UI_STATE.last_mouse_cap & 2 == 0) and not mouse_in_menu then
                -- Right Click on Row (with safety check)
                if gfx.mouse_x < avail_w and
                   gfx.mouse_y >= content_y and gfx.mouse_y < content_y + avail_h and
                   gfx.mouse_y >= screen_y and gfx.mouse_y < screen_y + row_h_dynamic then
                    UI_STATE.mouse_handled = true -- Suppress global menu
                    
                    -- If right-clicked on non-selected row (marker or line), select it first
                    if not table_selection[original_idx] then
                        table_selection = {}
                        table_selection[original_idx] = true
                        last_selected_row = i
                    end
                    
                    -- Count selected
                    local sel_indices = {}
                    local marker_count = 0
                    local ass_count = 0
                    
                    for idx, _ in pairs(table_selection) do
                        if type(idx) == "number" then
                            table.insert(sel_indices, idx)
                            ass_count = ass_count + 1
                        elseif type(idx) == "string" and idx:sub(1,1) == "M" then
                            marker_count = marker_count + 1
                        end
                    end
                    table.sort(sel_indices)
                    
                    local menu_str = ""
                    
                    -- If only markers are selected
                    if ass_count == 0 and marker_count > 0 then
                        if marker_count == 1 then
                            menu_str = T("COPY_START_TIME") .. "||" .. T("DELETE_RETAKE")
                        else
                            menu_str = T("DELETE_RETAKES")
                        end
                        
                        gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
                        local ret = gfx.showmenu(menu_str)
                        if marker_count == 1 then
                            if ret == 1 then
                                set_clipboard(line.t1_str)
                                show_snackbar(T("COPIED") .. ": " .. line.t1_str, "info")
                            elseif ret == 2 then
                                UTILS.delete_logic()
                            end
                        else
                            if ret == 1 then
                                UTILS.delete_logic()
                            end
                        end

                    -- Mixed Selection (Markers + ASS lines)
                    elseif ass_count > 0 and marker_count > 0 then
                        menu_str = T("DELETE_SELECTED_L_AND_R")
                        
                        gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
                        local ret = gfx.showmenu(menu_str)
                        if ret == 1 then
                            UTILS.delete_logic()
                        end

                    -- Only ASS lines selected
                    else
                        local sorted_actors = {}
                        for a in pairs(ass_actors) do
                            table.insert(sorted_actors, a)
                        end
                        table.sort(sorted_actors)
                        
                        -- Unique actors in selection for Dubber assignment
                        local selected_actors_map = {}
                        for p, l in ipairs(ass_lines) do
                            if table_selection[l.index or p] then
                                if l.actor and l.actor ~= "" then
                                    selected_actors_map[l.actor] = true
                                end
                            end
                        end
                        local selected_actors = {}
                        for a in pairs(selected_actors_map) do table.insert(selected_actors, a) end

                        -- Re-calculate prefixes
                        local menu_items = { ">" .. T("CHANGE_ACTOR_NAME"), T("NEW_NAME_MENU") }
                        for _, a in ipairs(sorted_actors) do
                            table.insert(menu_items, (a:gsub("|", "||")))
                        end
                        table.insert(menu_items, "<")

                        if cfg.col_table_dubber then
                            table.insert(menu_items, "|>" .. T("ASSING_DUBBER"))
                            table.insert(menu_items, "-  " .. T("NEW_DUBBER") .. "  -")
                            for _, d_name in ipairs(DUBBERS.data.names) do
                                local is_assigned_to_any = false
                                for _, actor in ipairs(selected_actors) do
                                    if DUBBERS.data.assignments[d_name] and DUBBERS.data.assignments[d_name][actor] then
                                        is_assigned_to_any = true
                                        break
                                    end
                                end
                                local prefix = is_assigned_to_any and "!" or ""
                                table.insert(menu_items, prefix .. d_name:gsub("|", "||"))
                            end
                            table.insert(menu_items, "<")
                        end
                        
                        local has_merge = #sel_indices > 1 and #sel_indices <= 50
                        local has_single = #sel_indices == 1
                        
                        if has_merge then
                            table.insert(menu_items, T("COMBINE_LINES"))
                        end
                        
                        if has_single then
                            table.insert(menu_items, T("COPY_START_TIME"))
                            table.insert(menu_items, T("REPEAT_THE_LINE"))
                            table.insert(menu_items, "|" .. T("DELETE_LINE"))
                        else
                            table.insert(menu_items, "|" .. T("DELETE_SELECTED_LINES"))
                        end
                        
                        local menu_str = table.concat(menu_items, "|")
                        gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
                        local ret = gfx.showmenu(menu_str)
                        
                        local actor_count = #sorted_actors
                        local rename_end_idx = 1 + actor_count
                        local dubber_start_idx = rename_end_idx + 1
                        local dubber_end_idx = cfg.col_table_dubber and (dubber_start_idx + #DUBBERS.data.names) or rename_end_idx
                        
                        if ret >= 1 and ret <= rename_end_idx then
                            -- Change Actor Name
                            local selected_entries = {}
                            for p, l in ipairs(ass_lines) do
                                if table_selection[l.index or p] then
                                    table.insert(selected_entries, l)
                                end
                            end
                            
                            if #selected_entries > 0 then
                                local ok, new_actor
                                if ret == 1 then
                                    local first_actor = selected_entries[1].actor or ""
                                    ok, new_actor = reaper.GetUserInputs(T("TAB_FILE_C_ACTOR_NAME"), 1, T("TAB_FILE_C_ACTOR_NAME_EXT"), first_actor)
                                else
                                    new_actor = sorted_actors[ret - 1]
                                    ok = true
                                end
                                
                                if ok and new_actor then
                                    -- Remove variation selector (U+FE0F = \239\184\143) and trim spaces
                                    new_actor = new_actor:gsub("\239\184\143", ""):match("^%s*(.-)%s*$")
                                    
                                    push_undo(T("TAB_FILE_C_ACTOR_NAME"))
                                    if ass_actors[new_actor] == nil then ass_actors[new_actor] = true end
                                    for _, l in ipairs(selected_entries) do
                                        l.actor = new_actor
                                        -- Sync editor state if we're renaming the active region
                                        if editor_state.last_region_id and l.rgn_idx == editor_state.last_region_id then
                                            editor_state.current_actor = new_actor
                                        end
                                    end
                                    cleanup_actors()
                                    rebuild_regions()
                                    show_snackbar(T("ACTOR_NAME_HB_CHANGED") .. #selected_entries .. ")", "success")
                                end
                            end
                        elseif cfg.col_table_dubber and ret >= dubber_start_idx and ret <= dubber_end_idx then
                            -- Assign Dubber
                            local d_idx = ret - dubber_start_idx
                            local selected_dubber
                            local is_new = (d_idx == 0)
                            
                            if is_new then
                                local ok, name = reaper.GetUserInputs(T("NEW_DUBBER"), 1, T("NAME_DUBBER"), "")
                                if ok then
                                    local is_valid, res = DUBBERS.validate_name(name)
                                    if not is_valid then
                                        if res then show_snackbar(res, "error") end
                                    else
                                        table.insert(DUBBERS.data.names, res)
                                        selected_dubber = res
                                    end
                                end
                            else
                                selected_dubber = DUBBERS.data.names[d_idx]
                            end
                            
                            if selected_dubber and #selected_actors > 0 then
                                push_undo(T("ASSING_THE_DUBBER") .. selected_dubber)
                                if not DUBBERS.data.assignments[selected_dubber] then DUBBERS.data.assignments[selected_dubber] = {} end
                                
                                local all_assigned = true
                                for _, actor in ipairs(selected_actors) do
                                    if not DUBBERS.data.assignments[selected_dubber][actor] then
                                        all_assigned = false
                                        break
                                    end
                                end
                                
                                local target_val = not all_assigned
                                for _, actor in ipairs(selected_actors) do
                                    DUBBERS.data.assignments[selected_dubber][actor] = target_val
                                    DUBBERS.version = DUBBERS.version + 1
                                end
                                
                                DUBBERS.save()
                                show_snackbar(T("TABLE_DUBBER_A_1") .. selected_dubber .. (target_val and T("TABLE_DUBBER_A_2") or T("TABLE_DUBBER_A_3")), "success")
                            end
                        elseif has_merge and ret == dubber_end_idx + 1 then
                            -- Merge Replicas logic
                            local selected_entries = {}
                            for p, l in ipairs(ass_lines) do
                                if table_selection[l.index or p] then
                                    table.insert(selected_entries, {line = l, pos = p})
                                end
                            end
                            table.sort(selected_entries, function(a,b) return a.pos < b.pos end)
                            
                            if #selected_entries > 1 then
                                push_undo(T("COMBINING_LINES"))
                                local merged_text = ""
                                local t1_min = math.huge
                                local t2_max = -math.huge
                                local base_pos = selected_entries[1].pos
                                local base_id = selected_entries[1].line.index or base_pos
                                
                                for _, ent in ipairs(selected_entries) do
                                    local l = ent.line
                                    merged_text = (merged_text == "") and (l.text or "") or (merged_text .. "\n" .. (l.text or ""))
                                    if l.t1 < t1_min then t1_min = l.t1 end
                                    if l.t2 > t2_max then t2_max = l.t2 end
                                end
                                
                                ass_lines[base_pos].text = merged_text
                                ass_lines[base_pos].t1 = t1_min
                                ass_lines[base_pos].t2 = t2_max
                                
                                for i = #selected_entries, 2, -1 do
                                    table.remove(ass_lines, selected_entries[i].pos)
                                end
                                
                                table_selection = {}
                                table_selection[base_id] = true
                                cleanup_actors()
                                rebuild_regions()

                                prompter_drawer.marker_cache.count = -1
                                prompter_drawer.filtered_cache.state_count = -1
                                prompter_drawer.has_markers_cache.count = -1
                                table_data_cache.state_count = -1
                                last_layout_state.state_count = -1
                                UI_STATE._markers_is_dirty = true

                                show_snackbar(T("LINES_HB_COMBINED") .. #selected_entries .. ")", "success")
                            end
                        elseif has_single then
                            if ret == dubber_end_idx + 1 then
                                set_clipboard(line.t1_str)
                                show_snackbar(T("COPIED") .. ": " .. line.t1_str, "info")
                            elseif ret == dubber_end_idx + 2 then
                                UTILS.duplicate_logic(sel_indices[1])
                            elseif ret == dubber_end_idx + 3 then
                                UTILS.delete_logic()
                            end
                        elseif (has_merge and ret == dubber_end_idx + 2) or (not has_merge and ret == dubber_end_idx + 1) then
                            UTILS.delete_logic()
                        end
                    end -- End of selection type check
                end
            end
        ::continue::
    end
    
    -- Blit back to screen
    gfx.dest = prev_dest
    -- Blit table canvas to available area
    -- If Right Layout: blit to 0..avail_w
    gfx.blit(OTHER.BUF.TABLE, 1, 0, 0, 0, avail_w, avail_h, 0, content_y)
    
    gfx.setfont(F.std) -- RESTORE standard font for menus and bars
    
    -- Scrollbar
    UI_STATE.target_scroll_y = draw_scrollbar(gfx.w - 10, content_y, 10, avail_h, total_h, avail_h, UI_STATE.target_scroll_y)

    -- Draw Header LAST (always on top)
    if not cfg.reader_mode then
        set_color(UI.C_SNACK_INFO)
        gfx.rect(0, start_y, avail_w, h_header, 1)
    end
    
    local function draw_header_cell(idx, label, x, y, col_name, tooltip)
        -- Clamp next_x to avail_w to prevent overlap with Director Panel
        local next_start = x_off[idx + 1] or avail_w
        local next_x = math.min(next_start, avail_w)
        local cell_w = next_x - x
        local arrow_w = S(12)
        local text_padding = S(5)
        local resize_key = col_keys[idx]
        
        -- Header cells should only draw if they have space
        if cell_w <= 0 then return end

        -- Use (locally scaled) F.bld for headers
        gfx.setfont(F.bld)
        
        local max_text_w = cell_w - text_padding
        if table_sort.col == col_name then max_text_w = max_text_w - arrow_w end
        
        local display_label = label
        if not cfg.reader_mode then
            display_label = fit_text_width(label, max_text_w)
        end
        
        -- Hover & Click detection
        local is_hover = false
        local is_resize_hover = false
        
        if UI_STATE.window_focused and not mouse_in_menu and gfx.mouse_y >= y and gfx.mouse_y < y + h_header then
            if gfx.mouse_x >= x and gfx.mouse_x < next_x then
                is_hover = true
            end
            
            -- Detect resize handle (right edge)
            if resize_key and math.abs(gfx.mouse_x - next_x) < S(5) then
                is_resize_hover = true
                is_hover = false -- Prioritize resize
            end
        end

        -- Handle Resizing
        if OTHER.col_resize.dragging and OTHER.col_resize.key == resize_key then
            local delta = gfx.mouse_x - OTHER.col_resize.start_x
            local new_w = OTHER.col_resize.start_w + delta
            if new_w < S(25) then new_w = S(25) end -- Minimum width (S(25) like 1st col)
            
            -- Store unscaled
            cfg[resize_key] = math.floor(new_w / cfg.gui_scale)
            
            -- Force refresh next frame? (implicit via loop)
        elseif is_resize_hover and is_mouse_clicked() then
            OTHER.col_resize.dragging = true
            OTHER.col_resize.key = resize_key
            OTHER.col_resize.start_x = gfx.mouse_x
            OTHER.col_resize.start_w = cell_w
        end
        
        -- Stop dragging
        if OTHER.col_resize.dragging and gfx.mouse_cap & 1 == 0 then
            OTHER.col_resize.dragging = false
            OTHER.col_resize.key = nil
            save_settings()
        end

        if is_hover then
            if not mouse_in_menu and not OTHER.col_resize.dragging then -- Checks if custom menus are open
                set_color(UI.C_HILI_HEADER)
                gfx.rect(x, y, cell_w, h_header, 1)
                
                if is_mouse_clicked() then
                    if table_sort.col == col_name then
                        table_sort.dir = table_sort.dir * -1
                    else
                        table_sort.col = col_name
                        table_sort.dir = 1
                    end
                end
            end
            
            if tooltip then
                local tip_id = "hdr_" .. col_name
                if UI_STATE.tooltip_state.hover_id ~= tip_id then
                    UI_STATE.tooltip_state.hover_id = tip_id
                    UI_STATE.tooltip_state.start_time = reaper.time_precise()
                end
                UI_STATE.tooltip_state.text = tooltip
                UI_STATE.tooltip_state.immediate = true
            end
        end
        
        -- Draw resize handle highlight
        if is_resize_hover or (OTHER.col_resize.dragging and OTHER.col_resize.key == resize_key) then
            set_color(UI.C_RESIZE_HDL)
            gfx.rect(next_x - S(2), y, S(4), h_header, 1)
        end

        gfx.setfont(F.bld)

        set_color(UI.C_TXT)
        gfx.x = x + text_padding; 
        gfx.y = y + (h_header - gfx.texth) / 2; 
        
        if cfg.reader_mode then
            gfx.drawstr(display_label, 4, x + max_text_w, y + h_header)
        else
            gfx.drawstr(display_label)
        end
        local dspt_w, dspt_h = gfx.measurestr(display_label)
        
        -- Draw vector arrow if sorted
        if table_sort.col == col_name then
            local ax = x + dspt_w + text_padding + S(2)
            local ay = y + (h_header - S(10)) / 2 -- Center arrow
            set_color(UI.C_TXT)
            if table_sort.dir == 1 then
                -- Up arrow
                gfx.line(ax + S(2), ay + S(6), ax + S(5), ay + S(2))
                gfx.line(ax + S(5), ay + S(2), ax + S(8), ay + S(6))
                gfx.line(ax + S(3), ay + S(6), ax + S(7), ay + S(6))
            else
                -- Down arrow
                gfx.line(ax + S(2), ay + S(2), ax + S(5), ay + S(6))
                gfx.line(ax + S(5), ay + S(6), ax + S(8), ay + S(2))
                gfx.line(ax + S(3), ay + S(2), ax + S(7), ay + S(2))
            end
        end
    end

    local col_ptr = 1
    if not cfg.reader_mode then
        draw_header_cell(col_ptr, T("TABLE_COLUMN_ACTIVE"), x_off[col_ptr], start_y, "enabled"); col_ptr = col_ptr + 1
        if cfg.col_table_index then draw_header_cell(col_ptr, "#", x_off[col_ptr], start_y, "index"); col_ptr = col_ptr + 1 end
        if cfg.col_table_start then draw_header_cell(col_ptr, T("START"), x_off[col_ptr], start_y, "start"); col_ptr = col_ptr + 1 end
        if cfg.col_table_end then draw_header_cell(col_ptr, T("END"), x_off[col_ptr], start_y, "end"); col_ptr = col_ptr + 1 end
        
        if cfg.col_table_dubber then 
            local conflict_count = 0
            if DUBBERS and DUBBERS.conflicts then
                for _ in pairs(DUBBERS.conflicts) do conflict_count = conflict_count + 1 end
                conflict_count = math.floor(conflict_count / 2) -- Pairs
            end
            local tip = conflict_count > 0 and (T("TOTAL_N_CONFLICTS") .. conflict_count) or T("NO_CONFLICTS")
            draw_header_cell(col_ptr, T("DUBBER"), x_off[col_ptr], start_y, "dubber", tip)
            col_ptr = col_ptr + 1 
        end
        
        if cfg.col_table_cps then draw_header_cell(col_ptr, "CPS", x_off[col_ptr], start_y, "cps"); col_ptr = col_ptr + 1 end
        if cfg.col_table_actor then draw_header_cell(col_ptr, T("ACTOR"), x_off[col_ptr], start_y, "actor"); col_ptr = col_ptr + 1 end
        draw_header_cell(col_ptr, T("LINE"), x_off[col_ptr], start_y, "text")
    end

    -- --- COLUMN VISIBILITY FLOATING MENU ---
    if OTHER.col_vis_menu.show then
        local m_w = S(180)
        local m_x, m_y = OTHER.col_vis_menu.x, OTHER.col_vis_menu.y
        local item_h = S(24)
        local items = {
            {label = "#", key = "col_table_index"},
            {label = T("START"), key = "col_table_start"},
            {label = T("END"), key = "col_table_end"},
            {label = T("DUBBER"), key = "col_table_dubber"},
            {label = "CPS", key = "col_table_cps"},
            {label = T("ACTOR"), key = "col_table_actor"}
        }
        local m_h = #items * item_h + S(10)
        
        -- Background with shadow
        set_color(UI.C_SHADOW); gfx.rect(m_x+S(2), m_y+S(2), m_w, m_h, 1) -- Shadow
        set_color(UI.C_BG); gfx.rect(m_x, m_y, m_w, m_h, 1)
        set_color(UI.C_BTN_H); gfx.rect(m_x, m_y, m_w, m_h, 0)
        
        for idx, item in ipairs(items) do
            if item.separator then
                set_color(UI.C_HILI_GREY_LOW)
                gfx.line(m_x + S(5), m_y + S(5) + (idx-1) * item_h + item_h/2, m_x + m_w - S(5), m_y + S(5) + (idx-1) * item_h + item_h/2)
            else
                local iy = m_y + S(5) + (idx-1) * item_h
                local hover = UI_STATE.window_focused and (gfx.mouse_x >= m_x and gfx.mouse_x <= m_x + m_w and gfx.mouse_y >= iy and gfx.mouse_y < iy + item_h)
                
                if hover then
                    set_color(UI.C_HILI_WHITE)
                    gfx.rect(m_x, iy, m_w, item_h, 1)
                end
                
                -- Checkbox
                local chk_sz = S(14)
                local chk_x = m_x + S(8)
                local chk_y = iy + (item_h - chk_sz)/2
                set_color(UI.C_ED_GUTTER)
                gfx.rect(chk_x, chk_y, chk_sz, chk_sz, 0)
                
                if cfg[item.key] then
                    set_color(UI.C_TXT)
                    if item.key == "reader_mode" then
                        gfx.circle(chk_x + chk_sz/2, chk_y + chk_sz/2, S(4), 1) -- Bullet point
                    else
                        gfx.line(chk_x+S(3), chk_y+S(7), chk_x+S(6), chk_y+S(10))
                        gfx.line(chk_x+S(6), chk_y+S(10), chk_x+S(11), chk_y+S(3))
                    end
                end
                
                set_color(UI.C_TXT)
                gfx.x = m_x + S(30)
                gfx.y = iy + (item_h - gfx.texth) / 2
                local label = item.label
                if cfg[item.key] and item.key == "reader_mode" then label = "• " .. label end
                gfx.drawstr(label)
                
                if hover and is_mouse_clicked() then
                    OTHER.col_vis_menu.handled = true
                    if item.action then
                        item.action()
                        UTILS.update_prompter_fonts()
                    else
                        cfg[item.key] = not cfg[item.key]
                        save_settings()
                        UTILS.update_prompter_fonts()
                        
                        -- Fallback sorting to # if hidden
                        if not cfg[item.key] and tostring(table_sort.col) == tostring(item.label) then
                            table_sort.col = "#"
                            table_sort.dir = 1
                        end
                    end
                end
            end
        end
        
        -- Close if clicked outside
        if is_mouse_clicked() and not (gfx.mouse_x >= m_x and gfx.mouse_x <= m_x + m_w and gfx.mouse_y >= m_y and gfx.mouse_y <= m_y + m_h) then
            -- BUT check if it was the menu button itself (to avoid immediate close-reopen)
            if not (gfx.mouse_x >= btn_x and gfx.mouse_x <= btn_x + opt_btn_w and 
                    gfx.mouse_y >= filter_y and gfx.mouse_y <= filter_y + filter_h) then
                OTHER.col_vis_menu.show = false
            end
        end
    end

    -- Draw Director/Editor Panel
    if cfg.director_mode or cfg.editor_mode then
        local draw_func = cfg.director_mode and DRAW_WINDOW.draw_director_panel or DRAW_WINDOW.draw_editor_panel
        if is_panel_right then
            -- Right Layout (Align with filters: S(35))
            local dir_y = S(35)
            draw_func(avail_w, dir_y, w_panel, gfx.h - dir_y, input_queue, false)
        else
            -- Bottom Layout
            local draw_y = gfx.h - h_panel
            
            -- Draw
            draw_func(0, draw_y, gfx.w, h_panel, input_queue, false)
            
            -- Recalculate height for NEXT frame to ensure smooth resizing
            local needed = draw_func(0, draw_y, gfx.w, h_panel, nil, true)
            if needed < min_panel_h then needed = min_panel_h end
            
            -- Auto-expand logic: Only expand if content needs more than current setting AND we are not resizing
            -- AND only if the panel is currently at its "natural" state or we haven't manually shrunk it too much
            local max_allowed_dynamic = math.max(min_panel_h, gfx.h - content_y - S(40))
            if not director_resize_drag and needed > h_panel and h_panel < max_allowed_dynamic then
                -- Only auto-expand if we haven't manually set a height that is already large enough
                local current_cfg_h = cfg.editor_mode and cfg.h_editor or cfg.h_director
                if h_panel <= current_cfg_h + 5 then
                    if cfg.editor_mode then cfg.h_editor = math.min(needed, max_allowed_dynamic) else cfg.h_director = math.min(needed, max_allowed_dynamic) end
                end
            end
            if cfg.editor_mode then dynamic_editor_h = needed else dynamic_director_h = needed end
        end
        
        -- RESIZE HANDLE LOGIC (Moved to end for Z-order)
        local resize_zone = S(8)
        local strip_sz = S(2)
        local grab_long = S(40)
        local grab_thick = S(12)
        local handle_x, handle_y, handle_w, handle_h
        local is_hover = false
        
        -- Helper: Check if mouse is strictly inside window
        if is_panel_right then
            local dir_y = S(35)
            local border_x = avail_w
            handle_w = grab_thick
            handle_h = grab_long
            handle_x = border_x - (handle_w / 2)
            handle_y = dir_y + (gfx.h - dir_y - handle_h) / 2
            
            -- Draw Separator
            is_hover = UI_STATE.inside_window and UI_STATE.window_focused and math.abs(gfx.mouse_x - border_x) <= resize_zone and (gfx.mouse_y >= dir_y)
            set_color(is_hover and UI.C_HILI_WHITE_MID or UI.C_HILI_WHITE)
            gfx.rect(border_x, dir_y, strip_sz, gfx.h - dir_y, 1)

            -- Logic
            if is_hover or director_resize_drag then
                reaper.SetCursorContext(2, 0)
                if is_hover and gfx.mouse_cap == 1 and not OTHER.col_resize.dragging then
                    director_resize_drag = true
                    OTHER.col_resize.key = nil
                end
            end
            
            if director_resize_drag and gfx.mouse_cap == 1 then
                local new_w = gfx.w - gfx.mouse_x
                if new_w < S(120) then new_w = S(120) end
                local max_w = gfx.w - S(150)
                if new_w > max_w then new_w = max_w end
                if cfg.editor_mode then cfg.w_editor = new_w else cfg.w_director = new_w end
            elseif director_resize_drag then
                director_resize_drag = false
                save_settings()
                reaper.SetCursorContext(0, 0)
            end
        else
            -- Bottom
            local border_y = gfx.h - h_panel
            handle_w = grab_long
            handle_h = grab_thick
            handle_x = (gfx.w - handle_w) / 2
            handle_y = border_y - (handle_h / 2)

            is_hover = UI_STATE.inside_window and UI_STATE.window_focused and math.abs(gfx.mouse_y - border_y) <= resize_zone
            set_color(is_hover and UI.C_HILI_WHITE_MID or UI.C_HILI_WHITE)
            gfx.rect(0, border_y, gfx.w, strip_sz, 1)

            if is_hover or director_resize_drag then
                reaper.SetCursorContext(1, 0)
                if is_hover and gfx.mouse_cap == 1 and not OTHER.col_resize.dragging then
                    director_resize_drag = true
                end
            end
            
            if director_resize_drag and gfx.mouse_cap == 1 then
                local new_h = gfx.h - gfx.mouse_y
                if new_h < min_panel_h then new_h = min_panel_h end
                local max_h = gfx.h - content_y - S(40)
                if new_h > max_h then new_h = max_h end
                if cfg.editor_mode then cfg.h_editor = new_h else cfg.h_director = new_h end
            elseif director_resize_drag then
                director_resize_drag = false
                save_settings()
                reaper.SetCursorContext(0, 0)
            end
        end

        -- Draw Handle Pill (Only on hover or drag)
        if is_hover or director_resize_drag then
            set_color(UI.C_WHITE, 0.8)
            gfx.rect(handle_x, handle_y, handle_w, handle_h, 1)
            set_color(UI.C_BLACK_OVERLAY)
            gfx.rect(handle_x, handle_y, handle_w, handle_h, 0)
        end
    end

    -- --- TIME SHIFT FLOATING MENU ---
    if OTHER.time_shift_menu.show then
        local m_w = S(280)
        local m_x, m_y = OTHER.time_shift_menu.x, OTHER.time_shift_menu.y
        local m_h = S(125)
        
        -- Background with shadow
        set_color(UI.C_SHADOW); gfx.rect(m_x+S(2), m_y+S(2), m_w, m_h, 1) -- Shadow
        set_color(UI.C_BG); gfx.rect(m_x, m_y, m_w, m_h, 1)
        set_color(UI.C_BTN_H); gfx.rect(m_x, m_y, m_w, m_h, 0)
        
        -- Header/Checkbox Row
        local iy = m_y + S(10)
        local chk_sz = S(14)
        local chk_x = m_x + S(10)
        local hover_chk = UI_STATE.window_focused and (gfx.mouse_x >= m_x and gfx.mouse_x <= m_x + m_w and gfx.mouse_y >= iy and gfx.mouse_y < iy + S(24))
        
        if hover_chk then
            set_color(UI.C_HILI_WHITE_LOW)
            gfx.rect(m_x, iy-S(4), m_w, S(24), 1)
        end
        
        set_color(UI.C_ED_GUTTER)
        gfx.rect(chk_x, iy + S(4), chk_sz, chk_sz, 0)
        if OTHER.time_shift_menu.only_selected then
            set_color(UI.C_TXT)
            gfx.line(chk_x+S(3), iy+S(11), chk_x+S(6), iy+S(14))
            gfx.line(chk_x+S(6), iy+S(14), chk_x+S(11), iy+S(7))
        end
        
        set_color(UI.C_TXT)
        gfx.x, gfx.y = chk_x + chk_sz + S(8), iy + S(4)
        gfx.drawstr(T("FOR_SELECTED_ONLY"))
        
        if hover_chk and is_mouse_clicked() then
            OTHER.time_shift_menu.only_selected = not OTHER.time_shift_menu.only_selected
        end
        
        -- Buttons Grid (2 Rows)
        local btn_w = (m_w - S(20) - S(5)*4) / 6
        local btn_h = S(24)
        local neg_offsets = {-5, -2, -1, -0.5, -0.25, -0.1}
        local pos_offsets = {5, 2, 1, 0.5, 0.25, 0.1}
        
        local function draw_row(offsets, start_y)
            for i, off in ipairs(offsets) do
                local bx = m_x + S(10) + (i-1) * (btn_w + S(4))
                local by = start_y
                
                local label = (off > 0 and "+" or "") .. off .. "s"
                if math.abs(off) < 1 then
                    label = (off < 0 and "-" or "+") .. tostring(math.abs(off)):gsub("^0", "") .. "s"
                end
                
                if draw_btn_inline(bx, by, btn_w, btn_h, label, UI.C_BTN) then
                    push_undo(T("TABLE_MENU_TIME_SHIFT") .. " (" .. off .. "s)")
                    local affected = 0
                    for _, line in ipairs(ass_lines) do
                        if not OTHER.time_shift_menu.only_selected or table_selection[line.index or 0] then
                            line.t1 = line.t1 + off
                            line.t2 = line.t2 + off
                            affected = affected + 1
                        end
                    end
                    rebuild_regions()
                    show_snackbar(T("SHIFTER_BY") .. label .. " (" .. affected .. ")", "success")
                end
            end
        end

        draw_row(neg_offsets, m_y + S(42))
        
        -- Separator
        set_color(UI.C_HILI_WHITE)
        gfx.line(m_x + S(10), m_y + S(76), m_x + m_w - S(10), m_y + S(76))
        
        draw_row(pos_offsets, m_y + S(90))
        
        -- Close if clicked outside
        if is_mouse_clicked() and not (gfx.mouse_x >= m_x and gfx.mouse_x <= m_x + m_w and gfx.mouse_y >= m_y and gfx.mouse_y <= m_y + m_h) then
            if not (gfx.mouse_x >= btn_x and gfx.mouse_x <= btn_x + opt_btn_w and 
                    gfx.mouse_y >= filter_y and gfx.mouse_y <= filter_y + filter_h) then
                OTHER.time_shift_menu.show = false
            end
        end
    end

    -- --- FINAL FONT RESET ---
    -- Ensure F.std and F.bld are returned to standard 14px size for other UI elements (Tabs etc.)
    gfx.setfont(F.std, "Arial", S(14))
    gfx.setfont(F.bld, "Arial", S(14), string.byte('b'))
end

-- --- Main Loop ---
reaper.gmem_attach("SubassSync")

function OTHER.show_auto_startup_suggestion()
    -- Check for auto-startup suggestion with delay (approx 3 seconds)
    if not UI_STATE.auto_startup_checked and reaper.time_precise() - UI_STATE.script_start_time > 3.0 then
        UI_STATE.auto_startup_checked = true
        local has_offered_startup = reaper.GetExtState(section_name, "offered_auto_startup_for_user") == "1"

        -- re-trigger auto start file
        if cfg.auto_startup then
            toggle_reaper_startup(true)
        end

        if not cfg.auto_startup and not has_offered_startup then
            local title = T("AUTO_RUN_1")
            local msg = T("AUTO_RUN_2")
            
            local ret = reaper.MB(msg, title, 4) -- 4 = Yes/No
            if ret == 6 then -- 6 = Yes
                cfg.auto_startup = true
                reaper.SetExtState(section_name, "auto_startup", "1", true)
                toggle_reaper_startup(true)
                show_snackbar(T("AUTO_RUN_3"), "success")
            end
            reaper.SetExtState(section_name, "offered_auto_startup_for_user", "1", true)
        end
    end
end

function OTHER.focus_plugin_window()
    if reaper.JS_Window_Find then
        -- Non-exact match (false) is more robust
        local hwnd = reaper.JS_Window_Find(GL.script_title, false)
        if hwnd then
            reaper.JS_Window_SetForeground(hwnd) -- Grab OS focus
            reaper.JS_Window_SetFocus(hwnd) -- Set internal focus
        end
    end
end

function OTHER.handle_remote_commands()
    local cmd_id = reaper.gmem_read(0)
    if cmd_id == 0 then return end
    
    -- Clear command immediately
    reaper.gmem_write(0, 0)
    
    if cmd_id == 1 then -- EDIT
        local play_state = reaper.GetPlayState()
        local pos = (play_state & 1) == 1 and reaper.GetPlayPosition() or reaper.GetCursorPosition()
        update_regions_cache()
        
        for _, r in ipairs(regions) do
            if pos >= r.pos and pos < r.rgnend then
                for i, line in ipairs(ass_lines) do
                    if math.abs(line.t1 - r.pos) < 0.01 and math.abs(line.t2 - r.rgnend) < 0.01 then
                        OTHER.focus_plugin_window()
                        open_text_editor(line.text, function(new_text)
                            push_undo(T("TEXT_EDIT_REMOTE"))
                            line.text = new_text
                            UI_STATE._markers_is_dirty = true
                            rebuild_regions()
                        end, i, ass_lines)
                        return
                    end
                end
            end
        end
    elseif cmd_id == 3 then -- EDIT_NEXT
        local play_state = reaper.GetPlayState()
        local pos = (play_state & 1) == 1 and reaper.GetPlayPosition() or reaper.GetCursorPosition()
        update_regions_cache()
        
        local current_rgn_idx = nil
        -- Find current region index
        for idx, r in ipairs(regions) do
            if pos >= r.pos and pos < r.rgnend then
                current_rgn_idx = idx
                break
            end
        end
        
        -- If current found, try to get next
        if current_rgn_idx and regions[current_rgn_idx + 1] then
            local next_rgn = regions[current_rgn_idx + 1]
             for i, line in ipairs(ass_lines) do
                if math.abs(line.t1 - next_rgn.pos) < 0.01 and math.abs(line.t2 - next_rgn.rgnend) < 0.01 then
                    OTHER.focus_plugin_window()
                    open_text_editor(line.text, function(new_text)
                        push_undo(T("TEXT_EDIT_REMOTE"))
                        line.text = new_text
                        UI_STATE._markers_is_dirty = true
                        rebuild_regions()
                    end, i, ass_lines)
                    return
                end
            end
        end
    elseif cmd_id == 2 then -- DICT
        local word = reaper.GetExtState("SubassSync", "WORD")
        if word ~= "" then
            trigger_dictionary_lookup(word)
        end
    elseif cmd_id == 4 then -- EDIT_SPECIFIC (with exact times)
        local t1 = reaper.gmem_read(1)
        local t2 = reaper.gmem_read(2)
        local target_id = reaper.gmem_read(3)
        local is_marker_cmd = reaper.gmem_read(4) == 1
        
        -- NEW: Prioritize Marker lookup if it's explicitly a marker or smells like one
        local looks_like_marker = is_marker_cmd or (math.abs(t1 - t2) < 0.001)
        
        if looks_like_marker then
            local m_count = reaper.CountProjectMarkers(0)
            local found_match = false
            for i = 0, m_count - 1 do
                local retval, isrgn, m_pos, _, m_name, markindex = reaper.EnumProjectMarkers3(0, i)
                local matches = false
                if not isrgn then
                    if target_id and target_id ~= -1 then
                        matches = (markindex == target_id)
                    else
                        matches = (math.abs(m_pos - t1) < 0.005) -- Slightly higher tolerance for rounded T1
                    end
                end

                if matches then
                    found_match = true
                    OTHER.focus_plugin_window()
                    open_text_editor(m_name, function(new_text)
                        push_undo(T("RETAKE_EDIT_REMOTE"))
                        -- Знаходимо індекс знову (бо він міг змінитись)
                        local find_idx = -1
                        for j = 0, reaper.CountProjectMarkers(0) - 1 do
                            local _, cur_isrgn, _, _, _, cur_idx = reaper.EnumProjectMarkers3(0, j)
                            if not cur_isrgn and cur_idx == markindex then find_idx = j break end
                        end
                        
                        if find_idx ~= -1 then
                            local _, _, _, _, _, _, m_col = reaper.EnumProjectMarkers3(0, find_idx)
                            reaper.SetProjectMarkerByIndex(0, find_idx, false, m_pos, 0, markindex, new_text, m_col)
                        else
                            -- Fallback за позицією
                            reaper.SetProjectMarker(markindex, false, m_pos, 0, new_text)
                        end
                        
                        -- ПОВНЕ ОНОВЛЕННЯ ВСІХ КЕШІВ
                        ass_markers = capture_project_markers()
                        update_regions_cache()
                        table_data_cache.state_count = -1
                        last_layout_state.state_count = -1
                        prompter_drawer.marker_cache.count = -1
                        prompter_drawer.filtered_cache.state_count = -1
                        
                        rebuild_regions() -- Оновлення решти
                    end, nil, nil, true)
                    return
                end
            end
            if not found_match then
                show_snackbar(string.format(T("NO_FOUND_MARKER_REMOTE"), target_id, t1), "error")
            end
        end

        -- 1. Спроба знайти збіг серед реплік (ass_lines)
        -- Prioritize target_id matching ONLY IF NOT A MARKER to avoid collisions
        if not looks_like_marker and target_id and target_id ~= -1 then
            for i, line in ipairs(ass_lines) do
                if line.rgn_idx == target_id then
                    OTHER.focus_plugin_window()
                    open_text_editor(line.text, function(new_text)
                        push_undo(T("TEXT_EDIT_REMOTE"))
                        line.text = new_text
                        UI_STATE._markers_is_dirty = true
                        rebuild_regions()
                    end, i, ass_lines)
                    return
                end
            end
        end
        
        -- Fallback to time-based matching (safe because t1==t2 vs t1<t2)
        for i, line in ipairs(ass_lines) do
            if not looks_like_marker and math.abs(line.t1 - t1) < 0.01 and math.abs(line.t2 - t2) < 0.01 then
                OTHER.focus_plugin_window()
                open_text_editor(line.text, function(new_text)
                    push_undo(T("TEXT_EDIT_REMOTE"))
                    line.text = new_text
                    UI_STATE._markers_is_dirty = true
                    rebuild_regions()
                end, i, ass_lines)
                return
            end
        end

        -- 2. Якщо не знайдено серед реплік — шукаємо серед маркерів (якщо не знайшли раніше)
        if not looks_like_marker then
            local m_count = reaper.CountProjectMarkers(0)
            for i = 0, m_count - 1 do
                local retval, isrgn, m_pos, _, m_name, markindex = reaper.EnumProjectMarkers3(0, i)
                
                local matches = false
                if target_id and target_id ~= -1 then
                    matches = (not isrgn and markindex == target_id)
                else
                    matches = (not isrgn and math.abs(m_pos - t1) < 0.001)
                end

                if matches then
                    OTHER.focus_plugin_window()
                    open_text_editor(m_name, function(new_text)
                        push_undo(T("RETAKE_EDIT_REMOTE"))
                        -- Знаходимо індекс знову (бо він міг змінитись)
                        local find_idx = -1
                        for j = 0, reaper.CountProjectMarkers(0) - 1 do
                            local _, _, cur_pos, _, _, cur_idx = reaper.EnumProjectMarkers3(0, j)
                            if cur_idx == markindex then find_idx = j break end
                        end
                        
                        if find_idx ~= -1 then
                            local _, _, _, _, _, _, m_col = reaper.EnumProjectMarkers3(0, find_idx)
                            reaper.SetProjectMarkerByIndex(0, find_idx, false, m_pos, 0, markindex, new_text, m_col)
                        else
                            -- Fallback за позицією
                            reaper.SetProjectMarker(markindex, false, m_pos, 0, new_text)
                        end
                        
                        -- ПОВНЕ ОНОВЛЕННЯ ВСІХ КЕШІВ
                        ass_markers = capture_project_markers()
                        update_regions_cache()
                        table_data_cache.state_count = -1
                        last_layout_state.state_count = -1
                        prompter_drawer.marker_cache.count = -1
                        prompter_drawer.filtered_cache.state_count = -1
                        
                        rebuild_regions() -- Оновлення решти
                    end, nil, nil, true)
                    return
                end
            end
        end
    end
end

function OTHER.highlight_marker_with_end_time()
    -- --- GLOBAL: Auto-set time selection from active marker's timestamp ---
    -- Only trigger when the EDIT CURSOR moves (ignore playback to save CPU)
    local cur_time = reaper.GetCursorPosition()
    
    global_marker_sel_state = global_marker_sel_state or {}
    
    -- Only run if the cursor position has changed
    if cur_time ~= global_marker_sel_state.last_cursor_pos then
        global_marker_sel_state.last_cursor_pos = cur_time
        
        local g_found = nil
        for _, m in ipairs(ass_markers) do
            if UTILS.is_near(m.pos, cur_time) then
                g_found = m
                break
            end
        end

        if g_found then
            if g_found.markindex ~= global_marker_sel_state.last_id then
                global_marker_sel_state.last_id = g_found.markindex

                -- Parse time from marker text (after optional [actor] prefix)
                local m_rest = g_found.name:match("^%[.-%]%s*(.*)") or g_found.name
                local ts_str = m_rest:match("^(%d+[:%.][%d:%.]*)%s*-")
                if ts_str then
                    local end_secs = parse_notes_timestamp(ts_str)
                    if end_secs then
                        reaper.GetSet_LoopTimeRange2(0, true, false, g_found.pos, end_secs, false)
                    end
                end
            end
        else
            -- No marker here, clear ID so next marker interaction triggers
            global_marker_sel_state.last_id = nil
        end
    end
end

--- Automatically trim start/end and check for clipping of newly recorded items
function OTHER.process_post_recording()
    local play_state = reaper.GetPlayState()
    local is_recording = (play_state & 4) == 4
    
    -- Track duration sessions
    if not UI_STATE.last_is_recording and is_recording then
        -- Recording just started
        local proj = STATS.get_project()
        if proj then
            local now = os.time()
            if #proj.duration == 0 or (now - proj.duration[#proj.duration]["end"] > 600) then
                -- New session (more than 10 mins gap or first session)
                table.insert(proj.duration, { start = now, ["end"] = now })
            else
                -- Continue existing session (update end to start time of recording)
                proj.duration[#proj.duration]["end"] = now
            end
            STATS.dirty = true
        end
    elseif UI_STATE.last_is_recording and not is_recording then
        -- Recording just stopped
        local proj = STATS.get_project()
        if proj and #proj.duration > 0 then
            proj.duration[#proj.duration]["end"] = os.time()
            STATS.update_cache()
            
            -- Update ETC (Estimated Time to Completion) buffer
            local _, cur_rec = UTILS.get_recording_progress()
            if cur_rec then
                -- Initialization on first Stop (cache is warm, regions are loaded).
                -- Seed the buffer so the NEXT stop immediately shows speed.
                if not STATS.etc.initialized then
                    local now = os.time()
                    STATS.etc.last_activity_time = now
                    STATS.etc.initialized = true
                    table.insert(STATS.etc.buffer, {time = now, count = cur_rec})
                end

                -- Detect backward jump: pop invalidated buffer entries (e.g. user deleted items).
                while #STATS.etc.buffer > 0 and cur_rec < STATS.etc.buffer[#STATS.etc.buffer].count do
                    table.remove(STATS.etc.buffer)
                end
                
                -- If backward jump cleared the entire buffer, re-seed at current state
                -- so the very next stop can immediately show speed again.
                -- Use os.time() to avoid stale timestamps contaminating calculation.
                if #STATS.etc.buffer == 0 then
                    table.insert(STATS.etc.buffer, {time = os.time(), count = cur_rec})
                end

                local last_valid_count = STATS.etc.buffer[#STATS.etc.buffer].count
                local now = os.time()

                -- Pause detection: ANY stop updates activity time, correctly isolating breaks
                -- from periods with many bad takes.
                if now - STATS.etc.last_activity_time > STATS.etc.PAUSE_THRESHOLD then
                    -- Re-seed using the real moment when Record was pressed (session_start).
                    -- math.min(..., now-1) ensures diff_time >= 1s even if Record+Stop
                    -- happened within the same second (session_start == now edge case).
                    local session_start = math.min(proj.duration[#proj.duration].start, now - 1)
                    STATS.etc.buffer = {{time = session_start, count = last_valid_count}}
                end

                STATS.etc.last_activity_time = now

                if cur_rec > last_valid_count then
                    -- Prevent duplicate timestamps (stops within same second): update in-place.
                    if #STATS.etc.buffer > 0 and now == STATS.etc.buffer[#STATS.etc.buffer].time then
                        STATS.etc.buffer[#STATS.etc.buffer].count = cur_rec
                    else
                        table.insert(STATS.etc.buffer, {time = now, count = cur_rec})
                        if #STATS.etc.buffer > 100 then
                            table.remove(STATS.etc.buffer, 1)
                        end
                    end
                end
            end
            
            STATS.dirty = true
            STATS.save()
        end

        -- Recording just stopped (Existing items processing)
        local item_count = reaper.CountSelectedMediaItems(0)
        if item_count > 0 then
            -- Track statistics: count recorded items and get actor names
            -- Track statistics for ach_11
            local total_words = 0
            local total_duration = 0
            local recorded_actors = {}
            local max_take_len = 0
            local unique_replica_indices = {}
            
            for i = 0, item_count - 1 do
                local item = reaper.GetSelectedMediaItem(0, i)
                if item then
                    local item_len = reaper.GetMediaItemInfo_Value(item, "D_LENGTH")
                    if item_len > max_take_len then max_take_len = item_len end
                    total_duration = total_duration + item_len
                    
                    -- Find actor by matching item position to ass_lines
                    local item_pos = reaper.GetMediaItemInfo_Value(item, "D_POSITION")
                    local item_end = item_pos + item_len
                    local found_actor = false
                    -- Use range-based search to find ALL overlapped regions
                    local matched_lines = UTILS.get_ass_lines_in_range(item_pos, item_end)
                    local actor_accounted_for = false
                    
                    for _, entry in ipairs(matched_lines) do
                        -- Only process ENABLED (visible) lines for statistics and achievements
                        if entry.enabled then
                            unique_replica_indices[entry._i] = true
                            
                            -- Count words (using identical logic to UTILS.calculate_lines_stats)
                            if entry.text then
                                local clean = entry.text:gsub("{{+.-}}+", ""):gsub("{.-}", ""):gsub("\\[Nnh]", " ")
                                local _, count = clean:gsub("%S+", "")
                                total_words = total_words + count
                            end

                            if entry.text and (entry.text:lower():find("секс") or entry.text:lower():find("sex")) then
                                ACHIEVEMENTS.add_stat("ach_15_count", 1)
                            end
                            
                            -- Achievement: Parseltongue (ach_19: > 8 hissing sounds)
                            if entry.text then
                                local t_low = entry.text:lower()
                                
                                -- 1. Рахуємо комбінації та видаляємо їх з рядка, щоб не порахувати повторно
                                local sh_count = select(2, t_low:gsub("sh", ""))
                                t_low = t_low:gsub("sh", "")
                                
                                local ch_count = select(2, t_low:gsub("ch", ""))
                                t_low = t_low:gsub("ch", "")
                                
                                local hiss_count = sh_count + ch_count
                                
                                -- 2. Рахуємо решту сибілянтів у "очищеному" рядку
                                for c in t_low:gmatch("[%z\1-\127\194-\244][\128-\191]*") do
                                    if c == "ш" or c == "ж" or c == "ч" or c == "щ" or c == "с" or 
                                    c == "s" or c == "z" or c == "j" then
                                        hiss_count = hiss_count + 1
                                    end
                                end
                                
                                if hiss_count > 8 then
                                    ACHIEVEMENTS.add_stat("ach_19_count", 1)
                                end
                            end

                            -- Achievement: Magic Sync (ach_21: length matches region length exactly)
                            if entry.t1 and entry.t2 then
                                local region_len = entry.t2 - entry.t1
                                if math.abs(item_len - region_len) < 0.001 then
                                    ACHIEVEMENTS.add_stat("ach_21_count", 1)
                                end
                            end

                            if entry.actor and entry.actor ~= "" then
                                -- Only count the FIRST matched actor for the 'recorded_actors' global take count
                                -- to avoid duplicating stats for the same duration.
                                if not actor_accounted_for then
                                    recorded_actors[entry.actor] = (recorded_actors[entry.actor] or 0) + 1
                                    found_actor = true
                                    actor_accounted_for = true
                                end
                            end
                        end
                    end

                    -- Achievement: Thousand Spells (ach_20: 1000+ takes)
                    ACHIEVEMENTS.check_high_take_count_ach_20()

                    -- Achievement: Blessing of Artemis (ach_23: accuracy >= 50 lines, ratio <= 1.1)
                    ACHIEVEMENTS.check_perfect_accuracy_ach_23()

                    -- Achievement: Lightness of a Feather (ach_24: 5s+ absolute silence)
                    if item_len >= 5.0 then
                        ACHIEVEMENTS.check_feather_silence_ach_24(item, item_len)
                    end

                    -- Achievement: Midnight Vigil (ach_22: Record between 00:00 and 04:00 once per day)
                    ACHIEVEMENTS.check_midnight_vigil_ach_22()
                    
                    -- If no actor found, count as "outside" recording
                    if not found_actor then
                        recorded_actors["_OUTSIDE_"] = (recorded_actors["_OUTSIDE_"] or 0) + 1
                    end
                end
            end
            
            -- Track takes per replica (ach_12: King of the Hill)
            for idx, _ in pairs(unique_replica_indices) do
                STATS.etc.replica_takes[idx] = (STATS.etc.replica_takes[idx] or 0) + 1
                if STATS.etc.replica_takes[idx] == 21 then
                    ACHIEVEMENTS.add_stat("ach_12_count", 1)
                end
            end

            -- Achievement for long take (ach_9: Siren)
            if max_take_len > 30 then
                ACHIEVEMENTS.add_stat("ach_9_count", 1)
            end
            
            -- Increment stats for each actor
            for actor, count in pairs(recorded_actors) do
                for _ = 1, count do
                    if actor == "_OUTSIDE_" then
                        STATS.increment_outside()
                    else
                        STATS.increment_recorded(actor)
                    end
                end
            end

            ACHIEVEMENTS.add_stat("ach_11_count", 1)
            ACHIEVEMENTS.add_stat("ach_11_word_count", total_words)
            ACHIEVEMENTS.add_stat("ach_11_total_duration", total_duration)
            STATS.save()
            
            -- Only proceed with trim/clipping if enabled
            if not cfg.auto_trim and not cfg.check_clipping then
                UI_STATE.last_is_recording = is_recording
                return
            end
            
            -- 1. Auto Trim
            if cfg.auto_trim then
                reaper.Undo_BeginBlock()
                local trimmed_count = 0
                for i = 0, item_count - 1 do
                    local item = reaper.GetSelectedMediaItem(0, i)
                    if item then
                        local item_pos = reaper.GetMediaItemInfo_Value(item, "D_POSITION")
                        local item_len = reaper.GetMediaItemInfo_Value(item, "D_LENGTH")
                        
                        local trim_start_sec = cfg.trim_start / 1000
                        local trim_end_sec = cfg.trim_end / 1000
                        
                        if item_len > (trim_start_sec + trim_end_sec) then
                            -- Trim start
                            local take = reaper.GetActiveTake(item)
                            if take then
                                -- Adjust source offset to keep content aligned
                                local offset = reaper.GetMediaItemTakeInfo_Value(take, "D_STARTOFFS")
                                reaper.SetMediaItemTakeInfo_Value(take, "D_STARTOFFS", offset + trim_start_sec)
                            end
                            reaper.SetMediaItemInfo_Value(item, "D_POSITION", item_pos + trim_start_sec)
                            -- Adjust length (minus both start and end trims)
                            reaper.SetMediaItemInfo_Value(item, "D_LENGTH", item_len - trim_start_sec - trim_end_sec)
                            trimmed_count = trimmed_count + 1
                        end
                    end
                end
                
                if trimmed_count > 0 then
                    reaper.UpdateArrange()
                    reaper.Undo_EndBlock(T("AUTOMATIC_TRIM"), -1)
                    show_snackbar(T("AUTOMATIC_SN_1") .. trimmed_count .. T("CLIPPING_WARN_2"), "info")
                else
                    reaper.Undo_EndBlock(T("AUTOMATIC_TRIM"), -1)
                end
            end

            -- 2. Clipping Check
            if cfg.check_clipping then
                local clipped_count = 0
                local max_peak_warning = 0.85
                -- Small defer to let audio buffer/files finalize? usually fine immediately after stop
                for i = 0, item_count - 1 do
                    local item = reaper.GetSelectedMediaItem(0, i)
                    if item then
                        local take = reaper.GetActiveTake(item)
                        if take and not reaper.TakeIsMIDI(take) then
                            local accessor = reaper.CreateTakeAudioAccessor(take)
                            local src = reaper.GetMediaItemTake_Source(take)
                            local start_offs = reaper.GetMediaItemTakeInfo_Value(take, "D_STARTOFFS")
                            local len = reaper.GetMediaItemInfo_Value(item, "D_LENGTH")
                            
                            -- Get source properties
                            local samplerate = 44100
                            if src then samplerate = reaper.GetMediaSourceSampleRate(src) end
                             if samplerate == 0 then samplerate = 44100 end -- Safety

                            local channels = reaper.GetMediaItemTakeInfo_Value(take, "I_CHANMODE")
                            if channels <= 0 then 
                                if src then channels = reaper.GetMediaSourceNumChannels(src) else channels = 1 end
                            end
                            if channels < 1 then channels = 1 end
                            
                            -- Volume Compensation logic
                            local item_vol = reaper.GetMediaItemInfo_Value(item, "D_VOL")
                            local take_vol = reaper.GetMediaItemTakeInfo_Value(take, "D_VOL")
                            local total_gain = item_vol * take_vol
                            
                            local block_size = 4096 -- Smaller chunks for UI responsiveness
                            local buffer = reaper.new_array(block_size * channels)
                            local max_peak = 0
                            
                            local pos = 0
                            while pos < len do
                                local chunk_len = math.min(len - pos, block_size / samplerate)
                                local retval = reaper.GetAudioAccessorSamples(accessor, samplerate, channels, start_offs + pos, math.ceil(chunk_len * samplerate), buffer)
                                
                                if retval > 0 then
                                    local size = retval * channels
                                    for j = 1, size do
                                        -- Compensate for gain
                                        local val = math.abs(buffer[j]) / total_gain
                                        
                                        if val > max_peak then max_peak = val end
                                        
                                        -- Optimization: If we found a peak that triggers RED, we can stop early 
                                        -- unless we wanted to count HOW MANY samples clipped (not needed now)
                                        if max_peak >= 0.99 then 
                                            break -- Exit inner loop
                                        end
                                    end
                                end
                                
                                if max_peak >= 0.99 then break end -- Exit outer loop
                                
                                pos = pos + chunk_len
                            end
                            
                            reaper.DestroyAudioAccessor(accessor)
                            
                            if max_peak >= max_peak_warning then
                                local r, g, b
                                
                                if max_peak >= 0.99 then
                                    -- Pure RED
                                    r, g, b = 255, 0, 0
                                    clipped_count = clipped_count + 1
                                    ACHIEVEMENTS.add_stat("ach_13_count", 1)
                                else
                                    -- Gradient from Yellow (255,255,0) at max_peak_warning to Red (255,0,0) at 0.99
                                    local t = (max_peak - max_peak_warning) / (0.99 - max_peak_warning) -- 0.0 at max_peak_warning, 1.0 at 0.99
                                    r = 255
                                    g = math.floor(255 * (1 - t)) -- 255 at max_peak_warning, 0 at 0.99
                                    b = 0
                                end
                                
                                reaper.SetMediaItemInfo_Value(item, "I_CUSTOMCOLOR", reaper.ColorToNative(r, g, b)|0x1000000)
                            end
                        end
                    end
                end

                if clipped_count > 0 then
                    reaper.UpdateArrange()
                    show_snackbar(T("CLIPPING_WARN_1") .. clipped_count .. T("CLIPPING_WARN_2"), "error")
                end
            end
        end
    end
    UI_STATE.last_is_recording = is_recording
end

local function main()
    if UI_STATE.is_restarting then return end

    OTHER.show_auto_startup_suggestion()
    ACHIEVEMENTS.sync_stats()
    
    -- Initial project state load (if first run)
    if UI_STATE.last_project_id == "" then
        proj_change_count = -1
        prompter_drawer.marker_cache.count = -1
        prompter_drawer.filtered_cache.state_count = -1
        table_data_cache.state_count = -1
        prompter_slider_cache.state_count = -1
        prompter_drawer.has_markers_cache.count = -1
        reaper.Undo_OnStateChangeEx2(0, "Subass: Init marker", -1, -1) 

        local proj, filename = reaper.EnumProjects(-1)
        local id_fname = (not filename or filename == "") and "unsaved" or filename
        UI_STATE.last_project_id = proj and (tostring(proj) .. "_" .. id_fname) or "none"
        DEADLINE.sync_project() -- Restore deadline from global storage if needed
        DEADLINE.project_deadline = DEADLINE.get()
        
        -- Trigger achievement check for the initial project context
        ACHIEVEMENTS.check_deadline_failure()
        ACHIEVEMENTS.check_project_architect_ach_10()
        ACHIEVEMENTS.check_epic_saga_ach_18()
        ACHIEVEMENTS.check_big_track_count_ach_16()
        ACHIEVEMENTS.check_high_actor_count_ach_17()
        ACHIEVEMENTS.check_high_take_count_ach_20()
        ACHIEVEMENTS.check_perfect_accuracy_ach_23()
        DUBBERS.load() -- Load dubber data for initial project
        UI_STATE.confetti_particles = nil

        DUBBERS.last_project_id = UI_STATE.last_project_id
    end
    
    -- Heartbeat for Lionzz
    reaper.gmem_write(100, reaper.time_precise())
    OTHER.handle_remote_commands()
    
    -- Save statistics every 1 minute
    local now = reaper.time_precise()
    if now - STATS.last_save_time > 60 then -- 1 minute
        STATS.save()
    end

    -- Persistently nudge focus if requested (to overcome OS race conditions)
    if text_editor_state.needs_focus_nudge and text_editor_state.needs_focus_nudge > 0 then
        OTHER.focus_plugin_window()
        text_editor_state.needs_focus_nudge = text_editor_state.needs_focus_nudge - 1
    end

    UI_STATE.tooltip_state.text = ""
    UI_STATE.tooltip_state.immediate = false
    UI_STATE.mouse_handled = false
    -- Check if project changed (tab switch)
    local proj, filename = reaper.EnumProjects(-1)
    local id_fname = (not filename or filename == "") and "unsaved" or filename
    local current_project_id = proj and (tostring(proj) .. "_" .. id_fname) or "none"
    if current_project_id ~= UI_STATE.last_project_id then
        proj_change_count = -1
        prompter_drawer.marker_cache.count = -1
        prompter_drawer.filtered_cache.state_count = -1
        table_data_cache.state_count = -1
        prompter_slider_cache.state_count = -1
        prompter_drawer.has_markers_cache.count = -1
        reaper.Undo_OnStateChangeEx2(0, "Subass: Init marker", -1, -1) 
        save_session_state(UI_STATE.last_project_id)
        UI_STATE.last_project_id = current_project_id
        
        -- Reset and load
        load_project_data()
        load_session_state(current_project_id)
        DICT.reload_if_project_changed() -- Reload dict selection for this project
        DEADLINE.project_deadline = nil -- Reset before sync
        DEADLINE.sync_project() -- Synchronize local state with global registry
        DEADLINE.project_deadline = DEADLINE.get()

        -- Trigger achievement check for the new project context
        ACHIEVEMENTS.check_deadline_failure()
        ACHIEVEMENTS.check_project_architect_ach_10()
        ACHIEVEMENTS.check_epic_saga_ach_18()
        ACHIEVEMENTS.check_big_track_count_ach_16()
        ACHIEVEMENTS.check_high_actor_count_ach_17()
        ACHIEVEMENTS.check_high_take_count_ach_20()
        ACHIEVEMENTS.check_perfect_accuracy_ach_23()

        DUBBERS.load() -- Reload dubber data for this project
        DUBBERS.last_project_id = current_project_id
        DUBBERS.conflicts = {} 
        DUBBERS.dashboard_initialized = false
        UI_STATE.confetti_particles = nil
        
        -- Immediate cache update after loading
        update_regions_cache()
        load_director_actors_from_state()
        
        -- Auto-import pending Whisper result if we just switched to the correct project
        if OTHER.pending_whisper and reaper.EnumProjects(-1) == OTHER.pending_whisper.proj then
            local pw = OTHER.pending_whisper
            OTHER.pending_whisper = nil
            local pf = io.open(pw.temp_srt, "r")
            if pf then
                pf:close()
                OTHER.import_whisper_srt(pw.temp_srt, pw.item_pos, pw.play_rate)
                show_snackbar(T("WHISPER_RESULT_IMPORTED"), "success")
            end
            if pw.pid_file  then os.remove(pw.pid_file)  end
            if pw.out_file  then os.remove(pw.out_file)  end
            if pw.done_file then os.remove(pw.done_file) end
            if pw.temp_srt  then os.remove(pw.temp_srt)  end
        end
    end
    
    local curs_state = reaper.GetProjectStateChangeCount(0)
    if curs_state ~= proj_change_count then
        if UTILS.is_markers_regions_changed() then
            update_regions_cache()
            load_director_actors_from_state()
        end

        local last_action = reaper.Undo_CanUndo2(0)

        if last_action == "Add new track" or last_action == "Paste tracks" then
            ACHIEVEMENTS.check_big_track_count_ach_16()
        end

        proj_change_count = curs_state
    end

    -- --- WINDOW FOCUS & INTERACTION DETECTION ---
    UI_STATE.inside_window = (gfx.mouse_x >= 0 and gfx.mouse_x < gfx.w and 
                              gfx.mouse_y >= 0 and gfx.mouse_y < gfx.h)
    
    local has_focus = UI_STATE.inside_window

    -- If JS_API is available, we can check if REAPER or our window is actually in foreground
    if reaper.JS_Window_GetForeground then
        local fg_hwnd = reaper.JS_Window_GetForeground()
        -- Cache my_hwnd: JS_Window_Find searches ALL OS windows every call (expensive on macOS).
        -- Invalidate only when gfx handle changes (dock/undock/restart).
        local cur_gfx_hwnd = reaper.GetMainHwnd and gfx.dock(-1) -- use dock state as proxy
        if not GL._my_hwnd_cache or GL._my_hwnd_dock_state ~= cur_gfx_hwnd then
            GL._my_hwnd_cache = reaper.JS_Window_Find(GL.script_title, true)
            GL._my_hwnd_dock_state = cur_gfx_hwnd
        end
        local my_hwnd = GL._my_hwnd_cache
        local main_hwnd = reaper.GetMainHwnd()
        
        if fg_hwnd then
            -- We are focused if foreground is our window OR the main REAPER window
            if fg_hwnd ~= my_hwnd and fg_hwnd ~= main_hwnd then
                -- One extra check: is it another REAPER window (like MIDI editor)?
                local title = reaper.JS_Window_GetTitle(fg_hwnd) or ""
                if not title:match("REAPER") and not title:match(GL.script_title) then
                    has_focus = false
                end
            end
        else
            has_focus = false
        end
    end
    UI_STATE.window_focused = has_focus

    -- --- INPUT GATHERING ---
    local input_queue = {}
    local char = gfx.getchar()
    while char ~= 0 do
        if char == -1 then return -- EXIT on window close
        else
            table.insert(input_queue, char)
        end
        char = gfx.getchar() -- Consume next
    end

    -- --- INPUT HANDLING (GLOBAL & HOTKEYS) ---
    if not text_editor_state.active then
        -- 1. Hotkey Assignment Capture
        if UI_STATE.hotkey_capture_idx and #input_queue > 0 then
            local char_cap = input_queue[1]
            local key_str = nil
            if char_cap >= 48 and char_cap <= 57 then key_str = string.char(char_cap)
            elseif char_cap == 45 then key_str = "-"
            elseif char_cap == 61 then key_str = "="
            end
            
            if key_str then
                local keys = {}
                -- Reliable split for "1,,3"
                for k in (cfg.hotkeys .. ","):gmatch("(.-),") do table.insert(keys, k) end
                while #keys < UI_STATE.hotkey_capture_idx do table.insert(keys, "") end
                
                local old_key = keys[UI_STATE.hotkey_capture_idx] or ""
                local swap_idx = nil
                for idx, k in ipairs(keys) do
                    if k ~= "" and k == key_str and idx ~= UI_STATE.hotkey_capture_idx then
                        swap_idx = idx
                        break
                    end
                end
                
                if swap_idx then
                    keys[swap_idx] = old_key
                    keys[UI_STATE.hotkey_capture_idx] = key_str
                    cfg.hotkeys = table.concat(keys, ",")
                    save_settings()
                    show_snackbar(T("KEYS_SWAPPED_1") .. key_str .. "] <-> [" .. (old_key ~= "" and old_key or T("NOTHING")) .. "]", "info")
                else
                    keys[UI_STATE.hotkey_capture_idx] = key_str
                    cfg.hotkeys = table.concat(keys, ",")
                    save_settings()
                    show_snackbar(T("KEYS_SWAPPED_2") .. key_str .. "]", "success")
                end
                UI_STATE.hotkey_capture_idx = nil
            else
                show_snackbar(T("KEYS_SWAPPED_ERROR"), "error")
            end
            UI_STATE.hotkey_capture_idx = nil
            for i=1, #input_queue do input_queue[i] = 0 end -- Clear queue
        end

        -- 2. Global Hotkeys & Standard Shortcuts
        for i, c in ipairs(input_queue) do
            if c == 0 then goto next_char end -- Skip consumed

            -- --- A. High-Priority Global Pass-Through (Save, Record) ---
            -- These should work even if a text field is focused
            if c == 19 then -- Ctrl+S (Save)
                reaper.Main_OnCommand(40026, 0)
                input_queue[i] = 0
                goto next_char
            elseif c == 18 then -- Ctrl+R (Record)
                reaper.Main_OnCommand(1013, 0)
                input_queue[i] = 0
                -- Don't return focus, keep script active for prompter/search
                goto next_char
            end

            if c == 26 then -- Ctrl+Z / Cmd+Z
                if not is_any_text_input_focused() then
                    if gfx.mouse_cap & 8 ~= 0 then -- Shift is held
                        redo_action()
                    else
                        undo_action()
                    end
                    input_queue[i] = 0
                    goto next_char
                end
            elseif not text_editor_state.active then
                if not is_any_text_input_focused() then
                -- Space: Play/Stop
                if c == 32 then
                    reaper.Main_OnCommand(40044, 0)
                    input_queue[i] = 0
                    return_focus_to_reaper(true)
                    goto next_char
                end

                -- Custom REAPER 'R' for Record (added by user request)
                if c == 82 or c == 114 then -- R / r
                    reaper.Main_OnCommand(1013, 0)
                    input_queue[i] = 0
                    goto next_char
                end

                -- Check User Hotkeys (0-9, -, =)
                local char_str = nil
                if c >= 48 and c <= 57 then char_str = string.char(c)
                elseif c == 45 then char_str = "-"
                elseif c == 61 then char_str = "="
                end

                if char_str then
                    local keys = {}
                    for k in (cfg.hotkeys .. ","):gmatch("(.-),") do table.insert(keys, k) end
                    for idx, k in ipairs(keys) do
                        if k == char_str then
                            UTILS.execute_hotkey_action(idx)
                                input_queue[i] = 0
                                goto next_char
                            end
                        end
                    end
                end
            end
            ::next_char::
        end
    end

    set_color(UI.C_BG)
    gfx.rect(0, 0, gfx.w, gfx.h, 1)
    
    if not OTHER.rec_state.show then
        if UI_STATE.inside_window then handle_drag_drop() end
    
        -- Main Drawing Logic
        if DEADLINE.modal.show then 
            DEADLINE.draw_picker(input_queue)
        elseif DUBBERS.show_dashboard then
            DUBBERS.draw_dashboard(input_queue)
        elseif DEADLINE.dashboard_show then
            DEADLINE.draw_dashboard(input_queue)
        elseif UI_STATE.show_edit_profile then
            DRAW_WINDOW.draw_edit_profile(input_queue)
        elseif UI_STATE.show_profile_view then
            DRAW_WINDOW.draw_remote_profile(input_queue)
        elseif UI_STATE.show_talent_search then
            DRAW_WINDOW.draw_talent_search(input_queue)
        elseif SEARCH_ITEM.show then
            if SEARCH_ITEM.draw_window then SEARCH_ITEM.draw_window(input_queue) end
        elseif ACHIEVEMENTS.show then
            if ACHIEVEMENTS.draw_window then ACHIEVEMENTS.draw_window(input_queue) end
        elseif dict_modal.show then
            DRAW_WINDOW.draw_dictionary_modal(input_queue)
        elseif text_editor_state.active then
            DRAW_WINDOW.draw_text_editor(input_queue)
        elseif UI_STATE.text_items_style and UI_STATE.text_items_style.show then
            DRAW_WINDOW.draw_text_items_style_editor(input_queue)
        else
            if UI_STATE.current_tab == 1 then 
                if UI_STATE.last_tab ~= 1 then
                    DICT.load()
                end
                DRAW_TABS.draw_file()
            elseif UI_STATE.current_tab == 2 then DRAW_TABS.draw_table(input_queue)
            elseif UI_STATE.current_tab == 3 then DRAW_TABS.draw_prompter(input_queue) 
            elseif UI_STATE.current_tab == 4 then DRAW_TABS.draw_settings() end
            
            UI_STATE.last_tab = UI_STATE.current_tab
            
            -- Draw Tabs LAST (Z-Index top)
            DRAW_TABS.draw_tabs()
            
            -- Draw AI modal over panels if active outside text editor
            if not text_editor_state.active and ai_modal.show then
                DRAW_WINDOW.draw_ai_modal(false)
            end
    
            -- Context Menu logic (Right-click on tab bar / empty space)
            -- Must strictly check UI_STATE.mouse_handled AND window bounds to avoid global capture.
            if UI_STATE.inside_window and gfx.mouse_cap == 2 and UI_STATE.last_mouse_cap == 0 and not UI_STATE.mouse_handled then
                gfx.x, gfx.y = gfx.mouse_x, gfx.mouse_y
                local dock_state = gfx.dock(-1)
                local check = (dock_state > 0) and "!" or ""
                local ret = gfx.showmenu(check .. T("DOCK_THE_WINDOW"))
                if ret == 1 then
                    local target_dock = dock_state > 0 and 0 or (GL.last_dock_id or 1)
                    gfx.dock(target_dock)
                    GL.last_dock_state = gfx.dock(-1) -- Get the actual new index
                    save_settings()
                end
            end
        end
    end

    DRAW_WINDOW.draw_snackbar()
    ACHIEVEMENTS.draw_ach_snackbar()
    DRAW_WINDOW.draw_tooltip()
    
    -- Draw Requirements Overlay (top-most priority, but below snackbar/tooltip)
    DRAW_WINDOW.draw_requirements_window()

    local cur_dock = gfx.dock(-1)
    if cur_dock > 0 then
        if cur_dock ~= GL.last_dock_state then
            GL.last_dock_state = cur_dock
            reaper.SetExtState(section_name, "dock", tostring(GL.last_dock_state), true)
        end
        if cur_dock ~= GL.last_dock_id then
            GL.last_dock_id = cur_dock
            reaper.SetExtState(section_name, "dock_id", tostring(GL.last_dock_id), true)
        end
    elseif cur_dock == 0 and GL.last_dock_state ~= 0 then
        -- Only set to 0 if the window is actually floating (manual undock)
        GL.last_dock_state = 0
        reaper.SetExtState(section_name, "dock", "0", true)
    end

    -- Async handling and Loader must be drawn BEFORE gfx.update
    check_async_pool()

    -- Handle subtitle import request from Subass_Dictionary (throttled: once per second)
    if not UI_STATE.last_import_check_t or (reaper.time_precise() - UI_STATE.last_import_check_t) >= 1.0 then
        UI_STATE.last_import_check_t = reaper.time_precise()
        local import_req = reaper.GetExtState("Subass_Notes", "import_request")
        if import_req ~= "" then
            reaper.SetExtState("Subass_Notes", "import_request", "", false) -- clear immediately
            local low_req = import_req:lower()
            local ext = ""
            if low_req:match("%.ass") or low_req:match("%.ssa") then
                ext = "ass"
            elseif low_req:match("%.vtt") then
                ext = "vtt"
            elseif low_req:match("%.srt") then
                ext = "srt"
            else
                ext = low_req:match("%.([^%.]+)$") or ""
            end

            if ext == "ass" then
                import_ass(import_req)
            elseif ext == "vtt" then
                import_vtt(import_req)
            else
                import_srt(import_req) -- default/srt
            end
        end
    end
    
    -- Periodic Update Check
    if reaper.time_precise() - UI_STATE.last_update_check_time > UI_STATE.AUTO_UPDATE_INTERVAL then
        -- Only check if we are not already doing something async AND python detection finished AND is OK
        if not UI_STATE.script_loading_state.active and not OTHER.rec_state.checking and OTHER.rec_state.python.ok then
            UI_STATE.last_update_check_time = reaper.time_precise()
            check_for_updates(true) -- Silent check
        end
    end

    -- Periodic Update User Stats
    if reaper.time_precise() - UI_STATE.last_registry_update_time > UI_STATE.AUTO_UPDATE_STATS_INTERVAL then
        -- Only check if we are not already doing something async AND python detection finished AND is OK
        if not UI_STATE.script_loading_state.active and not OTHER.rec_state.checking and OTHER.rec_state.python.ok then
            UI_STATE.last_registry_update_time = reaper.time_precise()
            STATS.register_plugin_usage()
        end
    end

    draw_loader()
    
    OTHER.process_post_recording()
    OTHER.highlight_marker_with_end_time()

    gfx.update()

    -- Coroutine Handling (for heavy sync tasks like Dictionary scan)
    if global_coroutine then
        local status = coroutine.status(global_coroutine)
        if status == "suspended" then
            local ok, err = coroutine.resume(global_coroutine)
            if not ok then
                reaper.ShowConsoleMsg("Coroutine Error: " .. tostring(err) .. "\n")
                global_coroutine = nil
                UI_STATE.script_loading_state.active = false
            end
        elseif status == "dead" then
            global_coroutine = nil
            -- Only turn off loader if no other async tasks are pending
            if #global_async_pool == 0 then
                UI_STATE.script_loading_state.active = false
            end
        end
    end

    UI_STATE.last_mouse_cap = gfx.mouse_cap
    
    -- Sync dictionaries periodically (every frames or when switching tabs)
    if UI_STATE.current_tab ~= UI_STATE.last_tab then
        DICT.check_sync()
    end

    reaper.defer(main)
end

ACHIEVEMENTS.global_deadline_sweep()
update_regions_cache()

reaper.atexit(function()
    save_settings()
    STATS.save()
end)

main()
